              initial={{ opacity: 0, y: -50 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -50 }}
              transition={{ duration: 0.2 }}
              className="absolute top-0 left-0 w-full bg-background/95 backdrop-blur-sm p-4 sm:p-6 border-b z-50"
              style={{
                backgroundColor: theme === 'dark' ? '#1F2937' : '#FFFFFF',
                borderColor: theme === 'dark' ? '#3F3F3F' : '#E5E7EB'
              }}>

                <div className="flex items-center gap-3">
                  <Input
                  type="text"
                  placeholder="Cari tugas, catatan, atau workspace..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="flex-1"
                  style={{
                    backgroundColor: theme === 'dark' ? '#3F3F3F' : '#F8F8F8',
                    borderColor: theme === 'dark' ? '#4B5563' : '#E5E7EB',
                    color: theme === 'dark' ? '#FFFFFF' : '#111827'
                  }} />

                  {isSearchLoading ?
                <Loader2 className="w-5 h-5 animate-spin text-primary" /> :

                <Button variant="ghost" size="icon" onClick={() => {setIsSearchOpen(false);setSearchQuery('');setSearchResults([]);}} style={{ color: theme === 'dark' ? '#D1D5DB' : '#4B5563' }}>
                      <X className="w-5 h-5" />
                    </Button>
                }
                </div>

                {searchQuery.length > 0 &&
              <div className="mt-4 max-h-[calc(100vh-180px)] overflow-y-auto custom-scrollbar pr-2">
                    {searchResults.length > 0 ?
                <div className="space-y-2">
                        {searchResults.map((item) =>
                  <div
                    key={`${item.type}-${item.id}`}
                    onClick={() => handleItemClick(item)}
                    className="flex items-center gap-3 p-3 rounded-lg cursor-pointer hover:bg-muted/50 transition-colors"
                    style={{
                      backgroundColor: theme === 'dark' ? '#262626' : '#F8F8F8',
                      color: theme === 'dark' ? '#E5E7EB' : '#1F2937'
                    }}>

                            {item.type === 'Tugas' && <CheckSquare className="w-5 h-5 text-green-500" />}
                            {item.type === 'Catatan' && <FileText className="w-5 h-5 text-blue-500" />}
                            {item.type === 'Workspace' && <Users className="w-5 h-5 text-purple-500" />}
                            <div className="flex-1 min-w-0">
                              <p className="font-medium truncate">{item.title || item.name}</p>
                              <p className="text-xs text-muted-foreground truncate">{item.type} {item.company_name ? `di ${item.company_name}` : ''}</p>
                            </div>
                          </div>
                  )}
                      </div> :

                !isSearchLoading &&
                <p className="text-center text-muted-foreground py-8">Tidak ada hasil ditemukan.</p>

                }
                  </div>
              }
              </motion.div>
            }
          </AnimatePresence>

          <header className="border-b px-3 sm:px-6 py-3 sm:py-4 flex items-center justify-between gap-2 sm:gap-4 sticky top-0 instant-render" style={{
            backgroundColor: theme === 'dark' ? '#1F2937' : '#FFFFFF',
            borderColor: theme === 'dark' ? '#3F3F3F' : '#E5E7EB',
            zIndex: 60,
            paddingTop: 'calc(12px + var(--safe-area-inset-top))',
            paddingLeft: 'calc(12px + var(--safe-area-inset-left))',
            paddingRight: 'calc(12px + var(--safe-area-inset-right))'
          }}>
            <div className="flex items-center gap-2 sm:gap-4 flex-1 min-w-0">
              {isMobile && <Button ref={hamburgerRef} variant="ghost" size="icon" onClick={(e) => {
                e.preventDefault();
                e.stopPropagation();
                justToggledRef.current = true;
                const newState = !isSidebarOpen;
                setIsSidebarOpen(newState);
                setTimeout(() => {
                  justToggledRef.current = false;
                }, 2000);
              }} onTouchStart={(e) => {
                e.stopPropagation();
              }} className="mr-2 ml-2 text-sm font-medium rounded-md inline-flex items-center justify-center gap-2 whitespace-nowrap transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0 hover:bg-accent hover:text-accent-foreground h-9 w-9 flex-shrink-0" style={{
                color: theme === 'dark' ? '#E5E7EB' : '#374151'
              }} data-sidebar-trigger>
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M3 12h18M3 6h18M3 18h18" />
                </svg>
              </Button>}


              <div className="flex-1 min-w-0 max-w-[200px] sm:max-w-none">
                {user && <CompanySwitcher currentUser={user} selectedCompany={selectedCompany} onCompanyChange={handleCompanyChange} />}
              </div>
            </div>

            <div className="flex items-center gap-2 sm:gap-3 flex-shrink-0">
              {user && <ShoppingCartIcon user={user} />}

              <Button variant="ghost" size="icon" onClick={toggleTheme} className="h-9 w-9 rounded-lg transition-all hover:scale-105" style={{
                color: theme === 'dark' ? '#D1D5DB' : '#4B5563',
                backgroundColor: theme === 'dark' ? 'rgba(55, 65, 81, 0.3)' : 'rgba(229, 231, 235, 0.5)'
              }} title={theme === 'dark' ? 'Ganti ke Tema Terang' : 'Ganti ke Tema Gelap'}>
                {theme === 'dark' ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
              </Button>

              {user && <NotificationBell user={user} />}

              {user && <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="ghost" className="h-8 w-8 sm:h-10 sm:w-10 rounded-full p-0 mobile-safe">
                    <Avatar className="h-8 w-8 sm:h-10 sm:w-10">
                      <AvatarImage src={user.avatar_url} />
                      <AvatarFallback className="bg-blue-600 text-white text-xs sm:text-sm">
                        {(user.full_name || user.email || 'U').charAt(0).toUpperCase()}
                      </AvatarFallback>
                    </Avatar>
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent className="w-56 sm:w-64" align="end" style={{
                  backgroundColor: theme === 'dark' ? '#1F2937' : '#FFFFFF',
                  borderColor: theme === 'dark' ? '#4B5563' : '#E5E7EB'
                }}>
                  <DropdownMenuLabel style={{
                    color: theme === 'dark' ? '#FFFFFF' : '#111827'
                  }}>
                    <div className="flex flex-col space-y-1">
                      <p className="text-xs sm:text-sm font-medium truncate">{user.full_name || user.email}</p>
                      <p className="text-xs truncate" style={{
                        color: theme === 'dark' ? '#9CA3AF' : '#6B7280'
                      }}>{user.email}</p>
                    </div>
                  </DropdownMenuLabel>
                  <DropdownMenuSeparator style={{
                    backgroundColor: theme === 'dark' ? '#4B5563' : '#E5E7EB'
                  }} />
                  <DropdownMenuItem asChild>
                    <Link to={createPageUrl('Settings')} onClick={closeSidebar} className="cursor-pointer mobile-safe" style={{
                      color: theme === 'dark' ? '#FFFFFF' : '#111827'
                    }}>
                      <Settings className="mr-2 h-4 w-4" />Pengaturan
                    </Link>
                  </DropdownMenuItem>
                  <DropdownMenuItem asChild>
                    <Link to={createPageUrl('Pricing')} onClick={closeSidebar} className="cursor-pointer mobile-safe" style={{
                      color: theme === 'dark' ? '#FFFFFF' : '#111827'
                    }}>
                      <Crown className="mr-2 h-4 w-4" />Upgrade
                    </Link>
                  </DropdownMenuItem>
                  <DropdownMenuSeparator style={{
                    backgroundColor: theme === 'dark' ? '#4B5563' : '#E5E7EB'
                  }} />
                  <DropdownMenuSeparator style={{
                    backgroundColor: theme === 'dark' ? '#4B5563' : '#E5E7EB'
                  }} />
                  <DropdownMenuItem
                    onClick={async () => {
                      if (confirm('ΓÜá∩╕Å PERINGATAN: Hapus akun akan menghapus SEMUA data Anda secara permanen. Lanjutkan?')) {
                        try {
                          await base44.entities.User.delete(user.id);
                          toast.success('Akun berhasil dihapus');
                          await handleLogout();
                        } catch (error) {
                          toast.error('Gagal menghapus akun: ' + error.message);
                        }
                      }
                    }}
                    className="text-red-600 cursor-pointer mobile-safe font-bold">
                    <X className="mr-2 h-4 w-4" />Hapus Akun
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={handleLogout} className="text-red-400 cursor-pointer mobile-safe">
                    <LogOut className="mr-2 h-4 w-4" />Keluar
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>}
            </div>
          </header>

          <main className="flex-1 overflow-auto instant-render" style={{
            backgroundColor: theme === 'dark' ? '#171717' : '#FFFFFF',
            scrollBehavior: 'auto',
            paddingBottom: isMobile ? 'calc(64px + var(--safe-area-inset-bottom))' : '0'
          }}>
            





            {React.cloneElement(children, {
              selectedCompany,
              currentUser: user
            })}
          </main>
        </div>

        {user && <ExpiryNotificationModal currentUser={user} onClose={() => {}} />}
        {user && <AddonPurchaseModal isOpen={showAddonModal} onClose={() => setShowAddonModal(false)} user={user} />}
        {user && <ReferralCodeModal isOpen={showReferralPopup} onClose={() => setShowReferralPopup(false)} user={user} onSuccess={(updatedUser) => {
          setUser(updatedUser);
          setShowReferralPopup(false);
        }} />}

        {/* Γ£à FIXED BOTTOM NAVIGATION - Google Play Requirement */}
        {isMobile && user &&
        <nav
          className="fixed bottom-0 left-0 right-0 border-t flex justify-around items-center z-50"
          style={{
            backgroundColor: theme === 'dark' ? '#1F2937' : '#FFFFFF',
            borderColor: theme === 'dark' ? '#3F3F3F' : '#E5E7EB',
            height: 'calc(64px + var(--safe-area-inset-bottom))',
            paddingBottom: 'var(--safe-area-inset-bottom)',
            paddingLeft: 'var(--safe-area-inset-left)',
            paddingRight: 'var(--safe-area-inset-right)'
          }}>

            {/* Home - Always Same */}
            <Link
            to={createPageUrl("Dashboard")}
            className="flex flex-col items-center justify-center flex-1 py-2 mobile-safe"
            style={{ color: currentPageName === 'Dashboard' ? '#3B82F6' : theme === 'dark' ? '#9CA3AF' : '#6B7280' }}>

              <LayoutDashboard className="w-5 h-5" />
              <span className="text-xs mt-1">Home</span>
            </Link>

            {/* Second Button: Tasks (Personal) or Absen (Company) */}
            {selectedCompany ?
          <Link
            to={createPageUrl("CompanyAttendance")}
            className="flex flex-col items-center justify-center flex-1 py-2 mobile-safe"
            style={{ color: currentPageName === 'CompanyAttendance' ? '#3B82F6' : theme === 'dark' ? '#9CA3AF' : '#6B7280' }}>

                <Clock className="w-5 h-5" />
                <span className="text-xs mt-1">Absen</span>
              </Link> :

          <Link
            to={createPageUrl("Tasks")}
            className="flex flex-col items-center justify-center flex-1 py-2 mobile-safe"
            style={{ color: currentPageName === 'Tasks' ? '#3B82F6' : theme === 'dark' ? '#9CA3AF' : '#6B7280' }}>

                <CheckSquare className="w-5 h-5" />
                <span className="text-xs mt-1">Tasks</span>
              </Link>
          }

            {/* Third Button: Shop (Personal) or Kasir (Company) */}
            {selectedCompany ?
          <Link
            to={createPageUrl("CompanyPOSCashier")}
            className="flex flex-col items-center justify-center flex-1 py-2 mobile-safe"
            style={{ color: currentPageName === 'CompanyPOSCashier' ? '#3B82F6' : theme === 'dark' ? '#9CA3AF' : '#6B7280' }}>

                <CreditCard className="w-5 h-5" />
                <span className="text-xs mt-1">Kasir</span>
              </Link> :

          <Link
            to={createPageUrl("Shop")}
            className="flex flex-col items-center justify-center flex-1 py-2 mobile-safe"
            style={{ color: currentPageName === 'Shop' ? '#3B82F6' : theme === 'dark' ? '#9CA3AF' : '#6B7280' }}>

                <ShoppingCart className="w-5 h-5" />
                <span className="text-xs mt-1">Shop</span>
              </Link>
          }

            {/* Finance - Always Same */}
            <Link
            to={createPageUrl("Finance")}
            className="flex flex-col items-center justify-center flex-1 py-2 mobile-safe"
            style={{ color: currentPageName === 'Finance' ? '#3B82F6' : theme === 'dark' ? '#9CA3AF' : '#6B7280' }}>

              <Wallet className="w-5 h-5" />
              <span className="text-xs mt-1">Finance</span>
            </Link>

            {/* Settings - Always Same */}
            <Link
            to={createPageUrl("Settings")}
            className="flex flex-col items-center justify-center flex-1 py-2 mobile-safe"
            style={{ color: currentPageName === 'Settings' ? '#3B82F6' : theme === 'dark' ? '#9CA3AF' : '#6B7280' }}>

              <Settings className="w-5 h-5" />
              <span className="text-xs mt-1">Settings</span>
            </Link>
          </nav>
        }

      </div>
    </ErrorBoundary>);


}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';

// Bypass entities.js completely to fix export errors
const User = base44.auth;
const {
  ProductOrder,
  WithdrawalRequest,
  Task
} = base44.entities;
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { TrendingUp, Award, Target, Zap, Trophy } from 'lucide-react';
import { toast } from 'sonner';
import { motion } from 'framer-motion';

const formatCurrency = (amount) => `Rp ${Number(amount || 0).toLocaleString('id-ID')}`;

export default function AdminBasicDashboard({ user }) {
  const [stats, setStats] = useState({
    totalOrders: 0,
    completedOrders: 0,
    totalEarnings: 0,
    withdrawableBalance: 0,
    thisMonthEarnings: 0,
    rank: 0,
    topAdmins: [],
    assignedTasks: []
  });
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    loadStats();

    // Auto refresh tasks every 15s
    const interval = setInterval(loadStats, 15000);
    return () => clearInterval(interval);
  }, [user]);

  const loadStats = async () => {
    try {
      // Get orders processed by this admin
      const allOrders = await ProductOrder.filter({ processed_by_admin: user.email });
      const completedOrders = allOrders.filter(o => o.status === 'completed');

      // Calculate earnings
      const totalEarnings = completedOrders.reduce((sum, o) => sum + (o.admin_commission_amount || 0), 0);
      const unpaidEarnings = completedOrders.filter(o => !o.admin_commission_paid).reduce((sum, o) => sum + (o.admin_commission_amount || 0), 0);

      // This month earnings
      const thisMonthStart = new Date(new Date().getFullYear(), new Date().getMonth(), 1);
      const thisMonthOrders = completedOrders.filter(o => new Date(o.completed_at) >= thisMonthStart);
      const thisMonthEarnings = thisMonthOrders.reduce((sum, o) => sum + (o.admin_commission_amount || 0), 0);

      // Get all admins for ranking
      const allUsers = await User.filter({ admin_type: 'basic' });
      const adminStats = await Promise.all(
        allUsers.map(async (admin) => {
          const adminOrders = await ProductOrder.filter({ processed_by_admin: admin.email, status: 'completed' });
          return {
            name: admin.full_name || admin.email,
            email: admin.email,
            orders: adminOrders.length,
            earnings: adminOrders.reduce((sum, o) => sum + (o.admin_commission_amount || 0), 0)
          };
        })
      );

      adminStats.sort((a, b) => b.earnings - a.earnings);
      const myRank = adminStats.findIndex(a => a.email === user.email) + 1;

      // Γ£à FETCH ASSIGNED TASKS (POS) - ROBUST
      let myTasks = [];
      try {
        console.log('≡ƒöì Checking tasks for User ID:', user.id);
        const allTasks = await Task.filter({ status: 'todo' }); // Fetch 'todo' tasks first

        // Filter client-side for robust ID matching
        myTasks = allTasks.filter(t => String(t.assigned_to) === String(user.id));

        console.log(`Γ£à Found ${myTasks.length} tasks for user.`);
      } catch (e) {
        console.warn('Error fetching tasks:', e);
        myTasks = [];
      }

      setStats({
        totalOrders: allOrders.length,
        completedOrders: completedOrders.length,
        totalEarnings,
        withdrawableBalance: user.admin_commission_balance || 0,
        thisMonthEarnings,
        rank: myRank,
        topAdmins: adminStats.slice(0, 5),
        assignedTasks: myTasks || []
      });
    } catch (error) {
      console.error("Error loading admin stats:", error);
      toast.error("Gagal memuat statistik");
    } finally {
      setIsLoading(false);
    }
  };

  const handleWithdraw = async () => {
    if (stats.withdrawableBalance < 50000) {
      toast.error("Minimum penarikan Rp 50.000");
      return;
    }

    try {
      await WithdrawalRequest.create({
        user_id: user.id,
        user_email: user.email,
        amount: stats.withdrawableBalance,
        bank_account_id: 'admin_commission', // Special type
        bank_account_details: { note: 'Withdrawal komisi admin basic' },
        status: 'pending'
      });

      toast.success("Permintaan penarikan berhasil diajukan!");
      loadStats();
    } catch (error) {
      toast.error("Gagal mengajukan penarikan");
    }
  };

  const handleTaskComplete = async (task) => {
    try {
      await Task.update(task.id, { status: 'completed' });
      toast.success('Γ£à Tugas selesai!');
      loadStats();
    } catch (e) {
      toast.error('Gagal update tugas');
    }
  };

  if (isLoading) {
    return <div className="text-center py-12">Memuat data...</div>;
  }

  return (
    <div className="space-y-6">
      {/* CTA Banner */}
      <Card className="bg-gradient-to-r from-blue-500 to-purple-600 text-white border-0">
        <CardContent className="p-6">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-2xl font-bold mb-2">Selamat Datang, Admin! ≡ƒÄë</h2>
              <p className="opacity-90">Proses lebih banyak transaksi untuk mendapatkan komisi lebih besar!</p>
            </div>
            <Trophy className="w-16 h-16 opacity-50" />
          </div>
        </CardContent>
      </Card>

      {/* ≡ƒöö POS TASKS NOTIFICATION AREA */}
      {stats.assignedTasks?.length > 0 && (
        <Card className="border-l-4 border-l-orange-500 shadow-md">
          <CardHeader className="pb-2">
            <CardTitle className="flex items-center gap-2 text-lg text-orange-700 dark:text-orange-400">
              <Zap className="w-5 h-5" />
              Tugas Masuk (POS)
              <Badge className="bg-orange-600 hover:bg-orange-700 text-white">{stats.assignedTasks.length}</Badge>
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid gap-3">
              {stats.assignedTasks.map((task) => (
                <div key={task.id} className="flex flex-col sm:flex-row sm:items-center justify-between p-3 bg-white dark:bg-gray-800 rounded-lg border border-gray-100 dark:border-gray-700 shadow-sm">
                  <div className="mb-3 sm:mb-0">
                    <h4 className="font-bold text-gray-800 dark:text-gray-200">{task.title}</h4>
                    <p className="text-sm text-gray-500 whitespace-pre-wrap mt-1">{task.description}</p>
                    <p className="text-xs text-gray-400 mt-2">≡ƒòÆ {new Date(task.created_date).toLocaleString('id-ID')}</p>
                  </div>
                  <Button
                    size="sm"
                    className="bg-green-600 hover:bg-green-700 text-white shrink-0"
                    onClick={() => handleTaskComplete(task)}>
                    <Target className="w-4 h-4 mr-2" />
                    Selesai
                  </Button>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Stats Grid */}
      <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
        >
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-gray-600 dark:text-gray-400">
                Total Pesanan Diproses
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{stats.totalOrders}</div>
              <p className="text-xs text-green-600 mt-1">
                {stats.completedOrders} selesai
              </p>
            </CardContent>
          </Card>
        </motion.div>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
        >
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-gray-600 dark:text-gray-400">
                Total Penghasilan
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-green-600">
                {formatCurrency(stats.totalEarnings)}
              </div>
              <p className="text-xs text-gray-500 mt-1">
                Akumulasi dari awal
              </p>
            </CardContent>
          </Card>
        </motion.div>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3 }}
        >
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-gray-600 dark:text-gray-400">
                Saldo Dapat Ditarik
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-blue-600">
                {formatCurrency(stats.withdrawableBalance)}
              </div>
              <Button
                size="sm"
                onClick={handleWithdraw}
                disabled={stats.withdrawableBalance < 50000}
                className="mt-2 w-full"
              >
                Tarik Saldo
              </Button>
            </CardContent>
          </Card>
        </motion.div>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.4 }}
        >
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium text-gray-600 dark:text-gray-400">
                Penghasilan Bulan Ini
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-purple-600">
                {formatCurrency(stats.thisMonthEarnings)}
              </div>
              <div className="flex items-center gap-1 text-xs text-green-600 mt-1">
                <TrendingUp className="w-3 h-3" />
                Terus tingkatkan!
              </div>
            </CardContent>
          </Card>
        </motion.div>
      </div>

      {/* Ranking */}
      <div className="grid md:grid-cols-2 gap-6">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Award className="w-5 h-5 text-yellow-500" />
              Peringkat Anda
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-center py-6">
              <div className="text-6xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-orange-500">
                #{stats.rank}
              </div>
              <p className="text-sm text-gray-600 dark:text-gray-400 mt-2">
                dari {stats.topAdmins.length} Admin
              </p>
              <div className="mt-4 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg">
                <p className="text-sm font-medium">
                  ≡ƒÆí Proses lebih banyak transaksi untuk naik peringkat!
                </p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Trophy className="w-5 h-5 text-yellow-500" />
              Top 5 Admin
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {stats.topAdmins.map((admin, idx) => (
                <div key={idx} className="flex items-center justify-between p-3 bg-gray-50 dark:bg-gray-800 rounded-lg">
                  <div className="flex items-center gap-3">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold ${idx === 0 ? 'bg-yellow-400 text-white' :
                      idx === 1 ? 'bg-gray-300 text-gray-800' :
                        idx === 2 ? 'bg-orange-400 text-white' :
                          'bg-blue-100 text-blue-800'
                      }`}>
                      {idx + 1}
                    </div>
                    <div>
                      <p className="font-medium text-sm">{admin.name}</p>
                      <p className="text-xs text-gray-500">{admin.orders} transaksi</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="font-bold text-sm text-green-600">
                      {formatCurrency(admin.earnings)}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Motivational CTA */}
      <Card className="bg-gradient-to-r from-green-500 to-teal-600 text-white border-0">
        <CardContent className="p-6">
          <div className="flex items-center gap-4">
            <Zap className="w-12 h-12" />
            <div className="flex-1">
              <h3 className="text-xl font-bold mb-1">Tingkatkan Performa Anda!</h3>
              <p className="opacity-90 text-sm">
                Setiap transaksi yang diselesaikan = Komisi untuk Anda. Admin terbaik mendapat bonus bulanan!
              </p>
            </div>
            <Button className="bg-white text-green-600 hover:bg-gray-100">
              Lihat Pesanan
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { 
  Sparkles, Eye, Save, Loader2, Plus, Edit, Trash2, 
  Newspaper
} from 'lucide-react';
import { toast } from 'sonner';
import ReactQuill from 'react-quill';
import 'react-quill/dist/quill.snow.css';

export default function BlogContentTab() {
  const [articles, setArticles] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showArticleDialog, setShowArticleDialog] = useState(false);
  const [editingArticle, setEditingArticle] = useState(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiTheme, setAiTheme] = useState('');

  const [articleForm, setArticleForm] = useState({
    title: '',
    slug: '',
    excerpt: '',
    content: '',
    category: 'Bisnis',
    author: 'SNISHOP Team',
    cover_image: '',
    featured: false,
    read_time: 5,
    tags: [],
    published: false,
    seo_title: '',
    seo_description: ''
  });

  const [tagInput, setTagInput] = useState('');

  useEffect(() => {
    loadArticles();
  }, []);

  const loadArticles = async () => {
    try {
      setIsLoading(true);
      const data = await base44.entities.BlogContent.list('-created_date');
      setArticles(data || []);
    } catch (error) {
      toast.error('Gagal memuat artikel');
    } finally {
      setIsLoading(false);
    }
  };

  const generateSlug = (title) => {
    return title
      .toLowerCase()
      .replace(/[^a-z0-9\s-]/g, '')
      .replace(/\s+/g, '-')
      .replace(/-+/g, '-');
  };

  const handleGenerateWithAI = async () => {
    if (!aiTheme.trim()) {
      toast.error('Masukkan tema artikel');
      return;
    }

    try {
      setIsGenerating(true);
      
      const schema = {
        type: "object",
        properties: {
          title: { type: "string" },
          excerpt: { type: "string" },
          content: { type: "string" },
          category: { 
            type: "string",
            enum: ["Bisnis", "Teknologi", "Tips & Trik", "Case Study", "Product Update", "Tutorial"]
          },
          tags: { type: "array", items: { type: "string" } },
          seo_title: { type: "string" },
          seo_description: { type: "string" }
        }
      };

      const prompt = `
        Generate artikel blog professional dalam Bahasa Indonesia untuk SNISHOP dengan tema:
        "${aiTheme}"

        INSTRUKSI:
        - Title: Menarik, SEO-friendly, maksimal 60 karakter
        - Excerpt: Ringkasan menarik 150-200 karakter
        - Content: Artikel lengkap 500-800 kata dalam format HTML
          * Gunakan tag <h2>, <h3>, <p>, <ul>, <li>, <strong>
          * Struktur: intro, 3-5 poin utama, conclusion
          * Tone: Professional namun friendly
          * Sertakan contoh praktis dan actionable tips
        - Category: Pilih yang paling sesuai
        - Tags: 3-5 tags relevan
        - SEO Title: Optimal untuk search engine
        - SEO Description: Meta description 150-160 karakter

        Tema: ${aiTheme}
      `;

      const result = await base44.integrations.Core.InvokeLLM({
        prompt,
        response_json_schema: schema
      });

      const generatedArticle = {
        ...result,
        slug: generateSlug(result.title),
        author: 'SNISHOP Team',
        read_time: Math.ceil(result.content.split(' ').length / 200),
        featured: false,
        published: false,
        cover_image: ''
      };

      setArticleForm(generatedArticle);
      setShowArticleDialog(true);
      toast.success('Γ£à Artikel berhasil di-generate! Silakan review dan edit jika perlu.');
      setAiTheme('');
    } catch (error) {
      console.error('Error:', error);
      toast.error('Gagal generate artikel');
    } finally {
      setIsGenerating(false);
    }
  };

  const openAddArticleDialog = () => {
    setEditingArticle(null);
    setArticleForm({
      title: '',
      slug: '',
      excerpt: '',
      content: '',
      category: 'Bisnis',
      author: 'SNISHOP Team',
      cover_image: '',
      featured: false,
      read_time: 5,
      tags: [],
      published: false,
      seo_title: '',
      seo_description: ''
    });
    setTagInput('');
    setShowArticleDialog(true);
  };

  const openEditArticleDialog = (article) => {
    setEditingArticle(article);
    setArticleForm(article);
    setTagInput('');
    setShowArticleDialog(true);
  };

  const saveArticle = async () => {
    if (!articleForm.title || !articleForm.content) {
      toast.error('Title dan Content wajib diisi!');
      return;
    }

    try {
      const articleData = {
        ...articleForm,
        slug: articleForm.slug || generateSlug(articleForm.title),
        published_date: articleForm.published ? new Date().toISOString() : null
      };

      if (editingArticle) {
        await base44.entities.BlogContent.update(editingArticle.id, articleData);
        toast.success('Γ£à Artikel berhasil diupdate!');
      } else {
        await base44.entities.BlogContent.create(articleData);
        toast.success('Γ£à Artikel baru berhasil ditambahkan!');
      }

      loadArticles();
      setShowArticleDialog(false);
    } catch (error) {
      toast.error('Gagal menyimpan artikel');
    }
  };

  const deleteArticle = async (id) => {
    if (!confirm('Yakin ingin hapus artikel ini?')) return;
    
    try {
      await base44.entities.BlogContent.delete(id);
      toast.success('Γ£à Artikel berhasil dihapus!');
      loadArticles();
    } catch (error) {
      toast.error('Gagal hapus artikel');
    }
  };

  const addTag = () => {
    if (!tagInput.trim()) return;
    if (articleForm.tags.includes(tagInput.trim())) {
      toast.error('Tag sudah ada');
      return;
    }
    setArticleForm({
      ...articleForm,
      tags: [...articleForm.tags, tagInput.trim()]
    });
    setTagInput('');
  };

  const removeTag = (index) => {
    setArticleForm({
      ...articleForm,
      tags: articleForm.tags.filter((_, i) => i !== index)
    });
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center p-12">
        <Loader2 className="w-8 h-8 animate-spin text-orange-600" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-white flex items-center gap-2">
            <Newspaper className="w-6 h-6 text-orange-500" />
            Kelola Artikel Blog
          </h2>
          <p className="text-gray-400 text-sm mt-1">
            {articles.length} total artikel
          </p>
        </div>
        <div className="flex gap-2">
          <Button
            onClick={() => window.open('/bloglist', '_blank')}
            variant="outline"
            className="border-gray-700"
          >
            <Eye className="w-4 h-4 mr-2" />
            Preview
          </Button>
          <Button
            onClick={openAddArticleDialog}
            className="bg-orange-600 hover:bg-orange-700"
          >
            <Plus className="w-4 h-4 mr-2" />
            Tambah Manual
          </Button>
        </div>
      </div>

      {/* AI Generator */}
      <Card className="bg-gradient-to-br from-purple-900/40 to-indigo-900/40 border-purple-700">
        <CardHeader>
          <CardTitle className="text-white flex items-center gap-2">
            <Sparkles className="w-5 h-5 text-purple-400" />
            Generate Artikel dengan AI
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <Input
            value={aiTheme}
            onChange={(e) => setAiTheme(e.target.value)}
            placeholder="Contoh: 10 Tips Meningkatkan Penjualan untuk UKM Indonesia"
            className="bg-gray-800 border-gray-700 text-white"
          />
          <Button
            onClick={handleGenerateWithAI}
            disabled={isGenerating}
            className="w-full bg-purple-600 hover:bg-purple-700"
          >
            {isGenerating ? (
              <Loader2 className="w-4 h-4 mr-2 animate-spin" />
            ) : (
              <Sparkles className="w-4 h-4 mr-2" />
            )}
            Generate Artikel
          </Button>
        </CardContent>
      </Card>

      {/* Articles List */}
      <Card className="bg-gray-900 border-gray-700">
        <CardHeader>
          <CardTitle className="text-white">Daftar Artikel</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          {articles.length > 0 ? (
            articles.map((article) => (
              <Card key={article.id} className="bg-gray-800 border-gray-700">
                <CardContent className="p-6">
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-2">
                        <h4 className="text-lg font-bold text-white">{article.title}</h4>
                        {article.featured && <Badge className="bg-yellow-600">Featured</Badge>}
                        {article.published ? 
                          <Badge className="bg-green-600">Published</Badge> : 
                          <Badge className="bg-gray-600">Draft</Badge>
                        }
                      </div>
                      <p className="text-gray-400 text-sm mb-3">{article.excerpt}</p>
                      <div className="flex flex-wrap gap-2">
                        <Badge variant="outline" className="border-orange-600 text-orange-400">
                          {article.category}
                        </Badge>
                        <Badge variant="outline" className="border-gray-600 text-gray-400">
                          {article.read_time} min read
                        </Badge>
                        <Badge variant="outline" className="border-gray-600 text-gray-400">
                          {article.views || 0} views
                        </Badge>
                      </div>
                    </div>
                    <div className="flex gap-2 ml-4">
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => openEditArticleDialog(article)}
                        className="border-blue-600 text-blue-400"
                      >
                        <Edit className="w-4 h-4" />
                      </Button>
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => deleteArticle(article.id)}
                        className="border-red-600 text-red-400"
                      >
                        <Trash2 className="w-4 h-4" />
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))
          ) : (
            <div className="text-center py-8">
              <Newspaper className="w-12 h-12 text-gray-600 mx-auto mb-3" />
              <p className="text-gray-400 mb-4">Belum ada artikel</p>
              <Button onClick={openAddArticleDialog} className="bg-orange-600">
                <Plus className="w-4 h-4 mr-2" />
                Buat Artikel Pertama
              </Button>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Article Dialog */}
      <Dialog open={showArticleDialog} onOpenChange={setShowArticleDialog}>
        <DialogContent className="bg-gray-900 text-white max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>
              {editingArticle ? 'Edit Artikel' : 'Tambah Artikel Baru'}
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label className="text-gray-300">Judul Artikel *</Label>
              <Input
                value={articleForm.title}
                onChange={(e) => {
                  const newTitle = e.target.value;
                  setArticleForm({ 
                    ...articleForm, 
                    title: newTitle,
                    slug: generateSlug(newTitle)
                  });
                }}
                placeholder="10 Tips Meningkatkan Penjualan untuk UKM"
                className="bg-gray-800 border-gray-700 text-white mt-2"
              />
            </div>

            <div>
              <Label className="text-gray-300">Slug (URL)</Label>
              <Input
                value={articleForm.slug}
                onChange={(e) => setArticleForm({ ...articleForm, slug: e.target.value })}
                className="bg-gray-800 border-gray-700 text-white mt-2"
              />
            </div>

            <div>
              <Label className="text-gray-300">Excerpt (Ringkasan) *</Label>
              <Textarea
                value={articleForm.excerpt}
                onChange={(e) => setArticleForm({ ...articleForm, excerpt: e.target.value })}
                placeholder="Ringkasan singkat artikel..."
                className="bg-gray-800 border-gray-700 text-white mt-2"
              />
            </div>

            <div>
              <Label className="text-gray-300">Konten Artikel (HTML) *</Label>
              <div className="mt-2 bg-white rounded">
                <ReactQuill
                  value={articleForm.content}
                  onChange={(value) => setArticleForm({ ...articleForm, content: value })}
                  theme="snow"
                  className="text-gray-900"
                  modules={{
                    toolbar: [
                      [{ 'header': [1, 2, 3, false] }],
                      ['bold', 'italic', 'underline', 'strike'],
                      [{ 'list': 'ordered'}, { 'list': 'bullet' }],
                      ['link', 'image'],
                      ['clean']
                    ]
                  }}
                />
              </div>
            </div>

            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <Label className="text-gray-300">Category</Label>
                <select
                  value={articleForm.category}
                  onChange={(e) => setArticleForm({ ...articleForm, category: e.target.value })}
                  className="w-full mt-2 px-3 py-2 bg-gray-800 border border-gray-700 text-white rounded-lg"
                >
                  <option value="Bisnis">Bisnis</option>
                  <option value="Teknologi">Teknologi</option>
                  <option value="Tips & Trik">Tips & Trik</option>
                  <option value="Case Study">Case Study</option>
                  <option value="Product Update">Product Update</option>
                  <option value="Tutorial">Tutorial</option>
                </select>
              </div>

              <div>
                <Label className="text-gray-300">Read Time (menit)</Label>
                <Input
                  type="number"
                  value={articleForm.read_time}
                  onChange={(e) => setArticleForm({ ...articleForm, read_time: parseInt(e.target.value) })}
                  className="bg-gray-800 border-gray-700 text-white mt-2"
                />
              </div>
            </div>

            <div>
              <Label className="text-gray-300">Cover Image URL (Optional)</Label>
              <Input
                value={articleForm.cover_image}
                onChange={(e) => setArticleForm({ ...articleForm, cover_image: e.target.value })}
                placeholder="https://images.unsplash.com/..."
                className="bg-gray-800 border-gray-700 text-white mt-2"
              />
            </div>

            <div>
              <Label className="text-gray-300">Tags</Label>
              <div className="flex gap-2 mt-2">
                <Input
                  value={tagInput}
                  onChange={(e) => setTagInput(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && addTag()}
                  placeholder="productivity, ukm, digital"
                  className="bg-gray-800 border-gray-700 text-white flex-1"
                />
                <Button onClick={addTag} variant="outline">
                  <Plus className="w-4 h-4" />
                </Button>
              </div>
              <div className="flex flex-wrap gap-2 mt-3">
                {articleForm.tags.map((tag, idx) => (
                  <Badge key={idx} className="bg-orange-600">
                    {tag}
                    <button onClick={() => removeTag(idx)} className="ml-2 hover:text-red-400">├ù</button>
                  </Badge>
                ))}
              </div>
            </div>

            <div className="flex items-center gap-4">
              <label className="flex items-center gap-2 text-gray-300 cursor-pointer">
                <input
                  type="checkbox"
                  checked={articleForm.featured}
                  onChange={(e) => setArticleForm({ ...articleForm, featured: e.target.checked })}
                  className="w-4 h-4"
                />
                <span>Featured Article</span>
              </label>
              <label className="flex items-center gap-2 text-gray-300 cursor-pointer">
                <input
                  type="checkbox"
                  checked={articleForm.published}
                  onChange={(e) => setArticleForm({ ...articleForm, published: e.target.checked })}
                  className="w-4 h-4"
                />
                <span>Publish Article</span>
              </label>
            </div>

            <div className="flex gap-3 pt-4">
              <Button
                variant="outline"
                onClick={() => setShowArticleDialog(false)}
                className="flex-1"
              >
                Batal
              </Button>
              <Button
                onClick={saveArticle}
                className="flex-1 bg-orange-600 hover:bg-orange-700"
              >
                <Save className="w-4 h-4 mr-2" />
                {editingArticle ? 'Update Artikel' : 'Tambah Artikel'}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import React, { useState } from 'react';
import { User } from '@/entities/User';
import { Notification as NotificationEntity } from '@/entities/Notification'; // FIX: Rename import to avoid conflict
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
