export default function BroadcastTab() {
    const [title, setTitle] = useState('');
    const [message, setMessage] = useState('');
    const [url, setUrl] = useState('');
    const [isBroadcasting, setIsBroadcasting] = useState(false);
    const [totalUsers, setTotalUsers] = useState(0);

    React.useEffect(() => {
        const fetchUserCount = async () => {
            const users = await User.list();
            setTotalUsers(users.length);
        };
        fetchUserCount();
    }, []);

    const handleUseTemplate = (template) => {
        setTitle(template.title);
        setMessage(template.message);
    };

    const handleBroadcast = async () => {
        if (!title.trim() || !message.trim()) {
            toast.error("Judul dan Pesan tidak boleh kosong.");
            return;
        }

        if (!confirm(`Anda akan mengirim notifikasi ini ke ${totalUsers} pengguna. Lanjutkan?`)) {
            return;
        }

        setIsBroadcasting(true);
        toast.info("Memulai proses broadcast...", {
            description: `Mengirim ke ${totalUsers} pengguna.`,
        });

        try {
            const allUsers = await User.list();
            
            // Batch creation for performance
            const notificationPromises = allUsers.map(user => {
                const personalizedMessage = message.replace('{nama_pengguna}', user.full_name || 'Pengguna');
                return NotificationEntity.create({ // FIX: Use the renamed entity
                    user_id: user.email,
                    title: title,
                    message: personalizedMessage,
                    url: url || '/dashboard',
                });
            });

            await Promise.all(notificationPromises);

            toast.success("Broadcast berhasil terkirim!", {
                description: `Notifikasi telah dikirim ke ${allUsers.length} pengguna.`,
            });

            // Reset form
            setTitle('');
            setMessage('');
            setUrl('');

        } catch (error) {
            toast.error("Gagal mengirim broadcast.", {
                description: "Terjadi kesalahan pada server. Silakan coba lagi.",
            });
            console.error("Broadcast failed:", error);
        } finally {
            setIsBroadcasting(false);
        }
    };

    const handleTestNotification = () => {
        // FIX: Use window.Notification explicitly to refer to the browser's Notification API
        if (!('Notification' in window)) {
            toast.error("Browser ini tidak mendukung notifikasi desktop.");
            return;
        }

        const sendTestNotification = () => {
            const notification = new window.Notification('≡ƒöö Tes Notifikasi TODOIT', {
                body: 'Jika Anda melihat ini, notifikasi berhasil dikonfigurasi!',
                icon: 'https://qtrypzzcjebvfcihiynt.supabase.co/storage/v1/object/public/base44-prod/public/688a42916670b89e7b51038c/bf4ff089b_TODOITLOGO.png'
            });
            
            // Play sound
            const sound = new Audio('https://cdn.jsdelivr.net/gh/scottschiller/SoundManager2@master/demo/_mp3/blip.mp3');
            sound.play().catch(e => console.error("Error playing sound for test notification:", e));
        };

        if (window.Notification.permission === 'granted') {
            sendTestNotification();
        } else if (window.Notification.permission !== 'denied') {
            window.Notification.requestPermission().then(permission => {
                if (permission === 'granted') {
                    sendTestNotification();
                } else {
                    toast.warning("Anda telah menolak izin notifikasi.");
                }
            });
        } else {
            toast.error("Izin notifikasi telah ditolak. Harap aktifkan dari pengaturan browser Anda.");
        }
    };


    return (
        <div className="space-y-6">
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Megaphone /> Kirim Broadcast Notifikasi
                    </CardTitle>
                    <CardDescription>
                        Kirim pemberitahuan penting, promosi, atau update ke seluruh pengguna. ({totalUsers} pengguna aktif)
                    </CardDescription>
                </CardHeader>
                <CardContent className="space-y-6">
                    <div>
                        <Label className="font-semibold">Gunakan Template Cepat</Label>
                        <div className="flex flex-wrap gap-2 mt-2">
                            {templates.map(template => (
                                <Button key={template.id} variant="outline" size="sm" onClick={() => handleUseTemplate(template)}>
                                    <template.icon className="w-4 h-4 mr-2" />
                                    {template.label}
                                </Button>
                            ))}
                        </div>
                        <p className="text-xs text-muted-foreground mt-2">Gunakan `&#123;nama_pengguna&#125;` untuk personalisasi pesan.</p>
                    </div>
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <Label htmlFor="broadcast-title">Judul Notifikasi</Label>
                            <Input 
                                id="broadcast-title" 
                                value={title} 
                                onChange={(e) => setTitle(e.target.value)}
                                placeholder="Contoh: Γ£¿ Fitur Baru: Laporan Keuangan!"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="broadcast-message">Pesan Notifikasi</Label>
                            <Textarea 
                                id="broadcast-message" 
                                value={message} 
                                onChange={(e) => setMessage(e.target.value)}
                                placeholder="Jelaskan detail pengumuman Anda di sini..."
                                rows={6}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="broadcast-url">URL Tujuan (Opsional)</Label>
                            <Input 
                                id="broadcast-url" 
                                type="url"
                                value={url} 
                                onChange={(e) => setUrl(e.target.value)}
                                placeholder="Contoh: /pricing atau https://blog.anda.com/..."
                            />
                        </div>
                    </div>
                    <Button onClick={handleBroadcast} disabled={isBroadcasting} size="lg" className="w-full">
                        {isBroadcasting ? (
                            <>
                                <Loader2 className="w-5 h-5 mr-2 animate-spin" />
                                Mengirim...
                            </>
                        ) : (
                            <>
                                <Send className="w-5 h-5 mr-2" />
                                Kirim Broadcast ke {totalUsers} Pengguna
                            </>
                        )}
                    </Button>
                </CardContent>
            </Card>

            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <BellRing /> Uji Coba Notifikasi
                    </CardTitle>
                    <CardDescription>
                        Kirim notifikasi tes ke browser Anda untuk memastikan sistem berfungsi dengan benar.
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <Button onClick={handleTestNotification}>
                        <Send className="w-5 h-5 mr-2" />
                        Kirim Notifikasi Tes
                    </Button>
                </CardContent>
            </Card>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Changelog } from '@/lib/changelog';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Switch } from '@/components/ui/switch';
import { toast } from 'sonner';
import { PlusCircle, Edit, Trash2, Loader2 } from 'lucide-react';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';
import ReactQuill from 'react-quill';
import 'react-quill/dist/quill.snow.css';

export default function ChangelogTab() {
    const [changelogs, setChangelogs] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingEntry, setEditingEntry] = useState(null);

    const fetchChangelogs = async () => {
        setIsLoading(true);
        try {
            const data = await Changelog.list('-release_date');
            setChangelogs(data);
        } catch (error) {
            toast.error("Gagal memuat data changelog.");
            console.error(error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchChangelogs();
    }, []);

    const handleOpenDialog = (entry = null) => {
        setEditingEntry(entry || {
            version: '',
            title: '',
            description: '',
            release_date: new Date().toISOString(),
            tags: [],
            is_published: true,
            type: 'manual'
        });
        setIsDialogOpen(true);
    };

    const handleSave = async (e) => {
        e.preventDefault();
        setIsLoading(true);
        try {
            const dataToSave = {
                ...editingEntry,
                tags: typeof editingEntry.tags === 'string' ? editingEntry.tags.split(',').map(t => t.trim()) : editingEntry.tags,
                release_date: new Date(editingEntry.release_date).toISOString()
            };

            if (editingEntry.id) {
                await Changelog.update(editingEntry.id, dataToSave);
                toast.success("Catatan pembaruan berhasil diperbarui.");
            } else {
                await Changelog.create(dataToSave);
                toast.success("Catatan pembaruan berhasil ditambahkan.");
            }
            setIsDialogOpen(false);
            setEditingEntry(null);
            fetchChangelogs();
        } catch (error) {
            toast.error("Gagal menyimpan catatan pembaruan.");
            console.error(error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDelete = async (entryId) => {
        if (confirm("Apakah Anda yakin ingin menghapus entri ini?")) {
            setIsLoading(true);
            try {
                await Changelog.delete(entryId);
                toast.success("Entri berhasil dihapus.");
                fetchChangelogs();
            } catch (error) {
                toast.error("Gagal menghapus entri.");
            } finally {
                setIsLoading(false);
            }
        }
    };

    const modules = {
        toolbar: [
            [{ 'header': [1, 2, 3, false] }],
            ['bold', 'italic', 'underline', 'strike', 'blockquote'],
            [{ 'list': 'ordered' }, { 'list': 'bullet' }, { 'indent': '-1' }, { 'indent': '+1' }],
            ['link', 'image'],
            ['clean']
        ],
    };

    return (
        <Card>
            <CardHeader className="flex flex-row items-center justify-between">
                <CardTitle>Kelola Pembaruan Aplikasi (Changelog)</CardTitle>
                <Button size="sm" onClick={() => handleOpenDialog()}>
                    <PlusCircle className="mr-2 h-4 w-4" /> Tambah Manual
                </Button>
            </CardHeader>
            <CardContent>
                {isLoading && !isDialogOpen ? (
                    <Loader2 className="animate-spin" />
                ) : (
                    <div className="space-y-4">
                        {changelogs.map(entry => (
                            <div key={entry.id} className="p-4 border rounded-lg flex justify-between items-start">
                                <div>
                                    <h4 className="font-bold">{entry.title}</h4>
                                    <p className="text-sm text-muted-foreground">
                                        {format(new Date(entry.release_date), 'dd MMMM yyyy, HH:mm', { locale: id })}
                                        <Badge variant={entry.type === 'automatic' ? 'secondary' : 'outline'} className="ml-2">{entry.type}</Badge>
                                    </p>
                                    <div className="prose prose-sm dark:prose-invert max-w-none" dangerouslySetInnerHTML={{ __html: entry.description }} />
                                    <div className="mt-2 flex gap-2">
                                        {(entry.tags || []).map(tag => <Badge key={tag}>{tag}</Badge>)}
                                    </div>
                                </div>
                                <div className="flex gap-2">
                                    <Button variant="ghost" size="icon" onClick={() => handleOpenDialog(entry)}><Edit className="h-4 w-4" /></Button>
                                    <Button variant="ghost" size="icon" className="text-red-500 hover:text-red-600" onClick={() => handleDelete(entry.id)}><Trash2 className="h-4 w-4" /></Button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </CardContent>

            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                <DialogContent className="max-w-3xl">
                    <DialogHeader>
                        <DialogTitle>{editingEntry?.id ? 'Edit' : 'Tambah'} Catatan Pembaruan</DialogTitle>
                    </DialogHeader>
                    <form onSubmit={handleSave} className="space-y-4 max-h-[70vh] overflow-y-auto pr-2">
                        <div><Label>Judul</Label><Input value={editingEntry?.title || ''} onChange={e => setEditingEntry({ ...editingEntry, title: e.target.value })} required /></div>
                        <div><Label>Versi (Opsional)</Label><Input value={editingEntry?.version || ''} onChange={e => setEditingEntry({ ...editingEntry, version: e.target.value })} /></div>
                        <div>
                            <Label>Deskripsi</Label>
                            <ReactQuill
                                theme="snow"
                                value={editingEntry?.description || ''}
                                onChange={val => setEditingEntry({ ...editingEntry, description: val })}
                                modules={modules}
                                className="bg-white dark:bg-gray-800"
                            />
                        </div>
                        <div><Label>Tanggal Rilis</Label><Input type="datetime-local" value={editingEntry?.release_date ? format(new Date(editingEntry.release_date), "yyyy-MM-dd'T'HH:mm") : ''} onChange={e => setEditingEntry({ ...editingEntry, release_date: e.target.value })} required /></div>
                        <div><Label>Tags (pisahkan dengan koma)</Label><Input value={(editingEntry?.tags || []).join(', ')} onChange={e => setEditingEntry({ ...editingEntry, tags: e.target.value })} /></div>
                        <div className="flex items-center space-x-2"><Switch checked={editingEntry?.is_published || false} onCheckedChange={c => setEditingEntry({ ...editingEntry, is_published: c })} /> <Label>Publikasikan</Label></div>
                        <DialogFooter>
                            <Button variant="ghost" type="button" onClick={() => setIsDialogOpen(false)}>Batal</Button>
                            <Button type="submit" disabled={isLoading}>{isLoading ? <Loader2 className="animate-spin" /> : 'Simpan'}</Button>
                        </DialogFooter>
                    </form>
                </DialogContent>
            </Dialog>
        </Card>
    );
}

import { useState, useEffect } from 'react';
import { HomeSettings } from '@/entities/HomeSettings';
import { UploadFile } from '@/integrations/Core';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Home, Plus, Trash } from 'lucide-react';
import { toast } from 'sonner';

export default function HomeSettingsTab() {
  const [settings, setSettings] = useState({
    setting_key: 'main',
    hero_title: '',
    hero_subtitle: '',
    hero_cta_text: '',
    hero_image_url: '',
    features: [],
    testimonials: [],
    stats: { users: 0, tasks: 0, workspaces: 0 },
    contact_email: 'snishopsolusinetwork@gmail.com',
    contact_whatsapp: '081532168812',
    social_links: {}
  });
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  const iconOptions = ['CheckSquare', 'Users', 'Zap', 'Clock', 'FileText', 'Briefcase', 'Target', 'Shield', 'Globe'];

  useEffect(() => {
    loadSettings();
  }, []);

  const loadSettings = async () => {
    try {
      const data = await HomeSettings.filter({ setting_key: 'main' });
      if (data.length > 0) {
        setSettings(data[0]);
      }
    } catch (error) {
      console.error("Error loading settings:", error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageUpload = async (file) => {
    try {
      toast.info("Mengunggah gambar...");
      const { file_url } = await UploadFile({ file });
      setSettings(prev => ({ ...prev, hero_image_url: file_url }));
      toast.success("Gambar berhasil diunggah");
    } catch (error) {
      toast.error("Gagal mengunggah gambar");
    }
  };

  const addFeature = () => {
    setSettings(prev => ({
      ...prev,
      features: [...prev.features, { title: '', description: '', icon: 'CheckSquare' }]
    }));
  };

  const updateFeature = (index, field, value) => {
    setSettings(prev => ({
      ...prev,
      features: prev.features.map((f, i) => i === index ? { ...f, [field]: value } : f)
    }));
  };

  const removeFeature = (index) => {
    setSettings(prev => ({
      ...prev,
      features: prev.features.filter((_, i) => i !== index)
    }));
  };

  const addTestimonial = () => {
    setSettings(prev => ({
      ...prev,
      testimonials: [...prev.testimonials, { name: '', role: '', content: '', avatar_url: '' }]
    }));
  };

  const updateTestimonial = (index, field, value) => {
    setSettings(prev => ({
      ...prev,
      testimonials: prev.testimonials.map((t, i) => i === index ? { ...t, [field]: value } : t)
    }));
  };

  const removeTestimonial = (index) => {
    setSettings(prev => ({
      ...prev,
      testimonials: prev.testimonials.filter((_, i) => i !== index)
    }));
  };

  const handleSave = async () => {
    setIsSaving(true);
    try {
      if (settings.id) {
        await HomeSettings.update(settings.id, settings);
        toast.success("Pengaturan homepage berhasil diperbarui");
      } else {
        await HomeSettings.create(settings);
        toast.success("Pengaturan homepage berhasil dibuat");
      }
      loadSettings();
    } catch (error) {
      toast.error("Gagal menyimpan pengaturan");
      console.error(error);
    } finally {
      setIsSaving(false);
    }
  };

  if (isLoading) {
    return <div className="flex items-center justify-center p-12">Loading...</div>;
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Home className="w-5 h-5" />
          Pengaturan Halaman Home
        </CardTitle>
      </CardHeader>
      <CardContent>
        <Tabs defaultValue="hero" className="w-full">
          <TabsList className="grid w-full grid-cols-4">
            <TabsTrigger value="hero">Hero Section</TabsTrigger>
            <TabsTrigger value="features">Fitur</TabsTrigger>
            <TabsTrigger value="testimonials">Testimoni</TabsTrigger>
            <TabsTrigger value="contact">Kontak</TabsTrigger>
          </TabsList>

          <TabsContent value="hero" className="space-y-4">
            <div>
              <Label>Judul Utama</Label>
              <Input
                value={settings.hero_title}
                onChange={(e) => setSettings({ ...settings, hero_title: e.target.value })}
                placeholder="Kelola Tugas & Produktivitas dengan Mudah"
              />
            </div>
            <div>
              <Label>Subtitle</Label>
              <Textarea
                value={settings.hero_subtitle}
                onChange={(e) => setSettings({ ...settings, hero_subtitle: e.target.value })}
                placeholder="Platform all-in-one untuk manajemen tugas..."
              />
            </div>
            <div>
              <Label>Teks Tombol CTA</Label>
              <Input
                value={settings.hero_cta_text}
                onChange={(e) => setSettings({ ...settings, hero_cta_text: e.target.value })}
                placeholder="Mulai Gratis Sekarang"
              />
            </div>
            <div>
              <Label>Gambar Hero</Label>
              <Input
                type="file"
                accept="image/*"
                onChange={(e) => {
                  const file = e.target.files[0];
                  if (file) handleImageUpload(file);
                }}
              />
              {settings.hero_image_url && (
                <img
                  src={settings.hero_image_url}
                  alt="Hero Preview"
                  className="mt-3 w-full max-w-md rounded-lg border"
                />
              )}
            </div>
            <div className="grid md:grid-cols-3 gap-4">
              <div>
                <Label>Jumlah Users</Label>
                <Input
                  type="number"
                  value={settings.stats.users}
                  onChange={(e) => setSettings({
                    ...settings,
                    stats: { ...settings.stats, users: Number(e.target.value) }
                  })}
                />
              </div>
              <div>
                <Label>Jumlah Tasks</Label>
                <Input
                  type="number"
                  value={settings.stats.tasks}
                  onChange={(e) => setSettings({
                    ...settings,
                    stats: { ...settings.stats, tasks: Number(e.target.value) }
                  })}
                />
              </div>
              <div>
                <Label>Jumlah Workspace</Label>
                <Input
                  type="number"
                  value={settings.stats.workspaces}
                  onChange={(e) => setSettings({
                    ...settings,
                    stats: { ...settings.stats, workspaces: Number(e.target.value) }
                  })}
                />
              </div>
            </div>
          </TabsContent>

          <TabsContent value="features" className="space-y-4">
            <Button onClick={addFeature} size="sm">
              <Plus className="w-4 h-4 mr-1" />
              Tambah Fitur
            </Button>
            {settings.features.map((feature, index) => (
              <Card key={index}>
                <CardContent className="p-4 space-y-3">
                  <div className="flex justify-between items-center">
                    <Label>Fitur #{index + 1}</Label>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => removeFeature(index)}
                    >
                      <Trash className="w-4 h-4 text-red-500" />
                    </Button>
                  </div>
                  <div>
                    <Label>Judul</Label>
                    <Input
                      value={feature.title}
                      onChange={(e) => updateFeature(index, 'title', e.target.value)}
                      placeholder="Task Management"
                    />
                  </div>
                  <div>
                    <Label>Deskripsi</Label>
                    <Textarea
                      value={feature.description}
                      onChange={(e) => updateFeature(index, 'description', e.target.value)}
                      placeholder="Kelola tugas dengan sistem yang powerful"
                    />
                  </div>
                  <div>
                    <Label>Icon</Label>
                    <select
                      className="w-full border rounded p-2"
                      value={feature.icon}
                      onChange={(e) => updateFeature(index, 'icon', e.target.value)}
                    >
                      {iconOptions.map(icon => (
                        <option key={icon} value={icon}>{icon}</option>
                      ))}
                    </select>
                  </div>
                </CardContent>
              </Card>
            ))}
          </TabsContent>

          <TabsContent value="testimonials" className="space-y-4">
            <Button onClick={addTestimonial} size="sm">
              <Plus className="w-4 h-4 mr-1" />
              Tambah Testimoni
            </Button>
            {settings.testimonials.map((testimonial, index) => (
              <Card key={index}>
                <CardContent className="p-4 space-y-3">
                  <div className="flex justify-between items-center">
                    <Label>Testimoni #{index + 1}</Label>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => removeTestimonial(index)}
                    >
                      <Trash className="w-4 h-4 text-red-500" />
                    </Button>
                  </div>
                  <div className="grid md:grid-cols-2 gap-3">
                    <div>
                      <Label>Nama</Label>
                      <Input
                        value={testimonial.name}
                        onChange={(e) => updateTestimonial(index, 'name', e.target.value)}
                        placeholder="Ahmad Rizki"
                      />
                    </div>
                    <div>
                      <Label>Role/Jabatan</Label>
                      <Input
                        value={testimonial.role}
                        onChange={(e) => updateTestimonial(index, 'role', e.target.value)}
                        placeholder="Project Manager"
                      />
                    </div>
                  </div>
                  <div>
                    <Label>Konten Testimoni</Label>
                    <Textarea
                      value={testimonial.content}
                      onChange={(e) => updateTestimonial(index, 'content', e.target.value)}
                      placeholder="TODOIT membantu tim kami lebih produktif..."
                    />
                  </div>
                </CardContent>
              </Card>
            ))}
          </TabsContent>

          <TabsContent value="contact" className="space-y-4">
            <div>
              <Label>Email Kontak</Label>
              <Input
                value={settings.contact_email}
                onChange={(e) => setSettings({ ...settings, contact_email: e.target.value })}
                placeholder="snishopsolusinetwork@gmail.com"
              />
            </div>
            <div>
              <Label>WhatsApp</Label>
              <Input
                value={settings.contact_whatsapp}
                onChange={(e) => setSettings({ ...settings, contact_whatsapp: e.target.value })}
                placeholder="081532168812"
              />
            </div>
          </TabsContent>
        </Tabs>

        <div className="mt-6">
          <Button onClick={handleSave} disabled={isSaving} className="w-full">
            {isSaving ? "Menyimpan..." : "Simpan Pengaturan Home"}
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Mail, Loader2, Download } from 'lucide-react';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';

export default function NewsletterTab() {
  const [subscribers, setSubscribers] = useState([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    loadSubscribers();
  }, []);

  const loadSubscribers = async () => {
    try {
      setIsLoading(true);
      const data = await base44.entities.NewsletterSubscriber.list('-created_date');
      setSubscribers(data || []);
    } catch (error) {
      toast.error('Gagal memuat subscribers');
    } finally {
      setIsLoading(false);
    }
  };

  const exportEmails = () => {
    const emails = subscribers.filter(s => s.is_active).map(s => s.email).join(', ');
    navigator.clipboard.writeText(emails);
    toast.success('Γ£à Email list disalin ke clipboard!');
  };

  const activeSubscribers = subscribers.filter(s => s.is_active);
  const inactiveSubscribers = subscribers.filter(s => !s.is_active);

  if (isLoading) {
    return <div className="flex items-center justify-center p-12">
      <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
    </div>;
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-white flex items-center gap-2">
            <Mail className="w-6 h-6 text-blue-500" />
            Newsletter Subscribers
          </h2>
          <p className="text-gray-400 text-sm mt-1">
            {activeSubscribers.length} active subscribers
          </p>
        </div>
        <Button onClick={exportEmails} variant="outline" className="border-gray-700">
          <Download className="w-4 h-4 mr-2" />
          Export Emails
        </Button>
      </div>

      <div className="grid md:grid-cols-2 gap-4">
        <Card className="bg-gray-900 border-gray-700">
          <CardContent className="p-4">
            <div className="text-2xl font-bold text-white mb-1">{activeSubscribers.length}</div>
            <div className="text-sm text-gray-400">Active Subscribers</div>
          </CardContent>
        </Card>
        <Card className="bg-gray-900 border-gray-700">
          <CardContent className="p-4">
            <div className="text-2xl font-bold text-white mb-1">{inactiveSubscribers.length}</div>
            <div className="text-sm text-gray-400">Unsubscribed</div>
          </CardContent>
        </Card>
      </div>

      <Card className="bg-gray-900 border-gray-700">
        <CardHeader>
          <CardTitle className="text-white">Subscriber List</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-2">
            {subscribers.map((sub) => (
              <div key={sub.id} className="flex items-center justify-between p-3 bg-gray-800 rounded-lg">
                <div className="flex-1">
                  <p className="text-white font-medium">{sub.email}</p>
                  {sub.name && <p className="text-gray-400 text-sm">{sub.name}</p>}
                  <p className="text-gray-500 text-xs mt-1">
                    Subscribed: {format(new Date(sub.created_date), 'dd MMM yyyy', { locale: id })}
                    {' ΓÇó '}From: {sub.subscribed_from || 'website'}
                  </p>
                </div>
                <Badge className={sub.is_active ? 'bg-green-600' : 'bg-gray-600'}>
                  {sub.is_active ? 'Active' : 'Unsubscribed'}
                </Badge>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { ProductOrder } from '@/entities/ProductOrder';
import { User } from '@/entities/User';
import { Notification } from '@/entities/Notification';
import { UploadFile } from '@/integrations/Core';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Badge } from '@/components/ui/badge';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { ShoppingCart, Eye, Trash2, Download, DollarSign, CheckCircle, Clock, Package, Bell, RefreshCw } from 'lucide-react';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';
import { motion, AnimatePresence } from 'framer-motion';

const formatCurrency = (amount) => `Rp ${Number(amount || 0).toLocaleString('id-ID')}`;

export default function OrdersTab({ orders, onUpdate }) {
    const [currentUser, setCurrentUser] = useState(null);
    const [selectedOrder, setSelectedOrder] = useState(null);
    const [isDetailModalOpen, setIsDetailModalOpen] = useState(false);
    const [isProcessing, setIsProcessing] = useState(false);
    const [status, setStatus] = useState('');
    const [adminNotes, setAdminNotes] = useState('');
    const [resultFiles, setResultFiles] = useState([]);
    const [filterStatus, setFilterStatus] = useState('all');
    const [newOrdersCount, setNewOrdersCount] = useState(0);
    const [lastOrderCount, setLastOrderCount] = useState(0);
    const [isRefreshing, setIsRefreshing] = useState(false);

    useEffect(() => {
        loadCurrentUser();
        
        // Request notification permission
        if ('Notification' in window && Notification.permission === 'default') {
            Notification.requestPermission();
        }
    }, []);

    useEffect(() => {
        checkNewOrders();
    }, [orders, currentUser]);

    const loadCurrentUser = async () => {
        try {
            const user = await User.me();
            setCurrentUser(user);
        } catch (error) {
            console.error('Error loading user:', error);
        }
    };

    const checkNewOrders = () => {
        if (!currentUser) return;

        // Count unassigned pending orders
        const unassignedOrders = orders.filter(o => 
            o.status === 'pending' && 
            !o.assigned_to_admin
        );

        const currentCount = unassignedOrders.length;
        
        // If there are new orders since last check and it's not the initial load
        if (currentCount > lastOrderCount && lastOrderCount > 0) {
            showNewOrderNotification();
        }
        
        setNewOrdersCount(currentCount);
        setLastOrderCount(currentCount);
    };

    const showNewOrderNotification = () => {
        // Browser notification
        if ('Notification' in window && Notification.permission === 'granted') {
            new Notification('≡ƒÄë Ada Order Baru!', {
                body: 'Hallo admin, ada pesanan baru! Yuk diproses.',
                icon: '/favicon.ico',
                tag: 'new-order',
                requireInteraction: true
            });
        }

        // Toast notification
        toast.success('≡ƒÄë Ada Order Baru!', {
            description: 'Pesanan baru masuk, yuk diproses!',
            duration: 10000,
            action: {
                label: 'Lihat',
                onClick: () => setFilterStatus('pending')
            }
        });

        // Play notification sound - LOUD ALERT
        try {
            // Create audio context for better sound control
            const audioContext = new (window.AudioContext || window.webkitAudioContext)();
            const oscillator = audioContext.createOscillator();
            const gainNode = audioContext.createGain();
            
            oscillator.connect(gainNode);
            gainNode.connect(audioContext.destination);
            
            // Set frequency and volume
            oscillator.frequency.value = 800; // Higher pitch for attention
            gainNode.gain.value = 0.3; // 30% volume
            
            oscillator.type = 'sine';
            oscillator.start(audioContext.currentTime);
            oscillator.stop(audioContext.currentTime + 0.2);
            
            // Second beep
            setTimeout(() => {
                const osc2 = audioContext.createOscillator();
                const gain2 = audioContext.createGain();
                osc2.connect(gain2);
                gain2.connect(audioContext.destination);
                osc2.frequency.value = 1000;
                gain2.gain.value = 0.3;
                osc2.start(audioContext.currentTime);
                osc2.stop(audioContext.currentTime + 0.2);
            }, 250);
        } catch (e) {
            console.log('Audio notification failed:', e);
        }
    };

    const handleManualRefresh = async () => {
        setIsRefreshing(true);
        try {
            await onUpdate();
            toast.success('Data pesanan diperbarui!');
        } catch (error) {
            toast.error('Gagal memperbarui data');
        } finally {
            setIsRefreshing(false);
        }
    };

    const handleClaimOrder = async (order) => {
        if (!currentUser || currentUser.admin_type !== 'basic') {
            toast.error('Hanya Admin Basic yang bisa mengambil order');
            return;
        }

        setIsProcessing(true);
        try {
            await ProductOrder.update(order.id, {
                assigned_to_admin: currentUser.email,
                assigned_at: new Date().toISOString(),
                status: 'processing'
            });

            toast.success('Order berhasil diambil! Silakan proses.');
            onUpdate();
            
            // Open detail modal
            const updatedOrder = await ProductOrder.get(order.id);
            handleViewDetail(updatedOrder);
        } catch (error) {
            toast.error('Gagal mengambil order');
            console.error(error);
        } finally {
            setIsProcessing(false);
        }
    };

    const handleViewDetail = (order) => {
        // Calculate commission for preview
        const commissionAmount = order.final_price * (order.product_commission_rate || 0);
        
        setSelectedOrder({ ...order, preview_commission: commissionAmount });
        setStatus(order.status);
        setAdminNotes(order.admin_notes || '');
        setResultFiles(order.result_files || []);
        setIsDetailModalOpen(true);
    };

    const handleFileUpload = async (file) => {
        try {
            toast.info("Mengunggah file...");
            const { file_url } = await UploadFile({ file });
            setResultFiles(prev => [...prev, file_url]);
            toast.success("File berhasil diunggah");
        } catch (error) {
            toast.error("Gagal mengunggah file");
            console.error(error);
        }
    };

    const handleRemoveFile = (index) => {
        setResultFiles(prev => prev.filter((_, i) => i !== index));
        toast.info("File dihapus dari daftar");
    };

    const handleUpdateOrder = async () => {
        if (!selectedOrder) return;

        setIsProcessing(true);
        try {
            const updateData = {
                status,
                admin_notes: adminNotes,
                result_files: resultFiles,
                processed_by_admin: currentUser.email
            };
            
            // Calculate and add commission when completing order
            if (status === 'completed' && !selectedOrder.admin_commission_paid) {
                const commissionRate = selectedOrder.product_commission_rate || 0;
                const commissionAmount = selectedOrder.final_price * commissionRate;
                
                updateData.admin_commission_amount = commissionAmount;
                updateData.admin_commission_paid = false;
                updateData.completed_at = new Date().toISOString();
                
                // Update admin's commission balance
                if (currentUser.admin_type === 'basic' && commissionAmount > 0) {
                    const currentBalance = currentUser.admin_commission_balance || 0;
                    await User.update(currentUser.id, {
                        admin_commission_balance: currentBalance + commissionAmount
                    });

                    toast.success(`Order selesai! Komisi Anda: ${formatCurrency(commissionAmount)}`);
                }
            }

            await ProductOrder.update(selectedOrder.id, updateData);

            // Send notification to customer
            let notifTitle = "";
            let notifMessage = "";

            if (status === 'processing') {
                notifTitle = "≡ƒöä Pesanan Sedang Diproses";
                notifMessage = `Pesanan Anda "${selectedOrder.product_name}" sedang diproses oleh admin.`;
            } else if (status === 'completed') {
                notifTitle = "Γ£à Pesanan Selesai!";
                notifMessage = `Pesanan Anda "${selectedOrder.product_name}" telah selesai. Silakan cek detail pesanan untuk mengunduh hasil.`;
            } else if (status === 'cancelled') {
                notifTitle = "Γ¥î Pesanan Dibatalkan";
                notifMessage = `Pesanan Anda "${selectedOrder.product_name}" dibatalkan. ${adminNotes ? 'Alasan: ' + adminNotes : ''}`;
            }

            if (notifTitle) {
                await Notification.create({
                    user_id: selectedOrder.customer_email,
                    title: notifTitle,
                    message: notifMessage,
                    url: '/my-orders'
                });
            }

            toast.success("Pesanan berhasil diperbarui dan notifikasi terkirim!");
            setIsDetailModalOpen(false);
            onUpdate();
        } catch (error) {
            toast.error("Gagal memperbarui pesanan");
            console.error(error);
        } finally {
            setIsProcessing(false);
        }
    };

    const getStatusBadge = (orderStatus) => {
        const config = {
            pending: { label: "Menunggu", color: "bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200", icon: Clock },
            processing: { label: "Diproses", color: "bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200", icon: Package },
            completed: { label: "Selesai", color: "bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200", icon: CheckCircle },
            cancelled: { label: "Dibatalkan", color: "bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200", icon: Download }
        };
        return config[orderStatus] || config.pending;
    };

    const isBasicAdmin = currentUser?.admin_type === 'basic';
    
    // Filter orders based on role and status
    const filteredOrders = orders.filter(order => {
        // Status filter
        if (filterStatus !== 'all' && order.status !== filterStatus) return false;

        // For basic admin: only show unassigned orders or orders assigned to them
        if (isBasicAdmin) {
            return !order.assigned_to_admin || order.assigned_to_admin === currentUser.email;
        }

        // For owner admin: show all
        return true;
    });

    return (
        <>
            <Card>
                <CardHeader>
                    <div className="flex items-center justify-between">
                        <div>
                            <CardTitle>Manajemen Pesanan ({filteredOrders.length})</CardTitle>
                            {newOrdersCount > 0 && (
                                <motion.p 
                                    initial={{ scale: 0 }}
                                    animate={{ scale: 1 }}
                                    className="text-sm text-orange-600 font-semibold mt-1 flex items-center gap-2"
                                >
                                    <Bell className="w-4 h-4 animate-bounce" />
                                    ≡ƒöÑ {newOrdersCount} pesanan baru menunggu!
                                </motion.p>
                            )}
                        </div>
                        <div className="flex items-center gap-2">
                            <Button
                                variant="outline"
                                size="sm"
                                onClick={handleManualRefresh}
                                disabled={isRefreshing}
                                className="flex items-center gap-2"
                            >
                                <RefreshCw className={`w-4 h-4 ${isRefreshing ? 'animate-spin' : ''}`} />
                                Refresh
                            </Button>
                            <Select value={filterStatus} onValueChange={setFilterStatus}>
                                <SelectTrigger className="w-40">
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">Semua Status</SelectItem>
                                    <SelectItem value="pending">Menunggu</SelectItem>
                                    <SelectItem value="processing">Diproses</SelectItem>
                                    <SelectItem value="completed">Selesai</SelectItem>
                                    <SelectItem value="cancelled">Dibatalkan</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    <div className="overflow-x-auto">
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Tanggal</TableHead>
                                    <TableHead>Customer</TableHead>
                                    <TableHead>Produk</TableHead>
                                    <TableHead>Harga</TableHead>
                                    {isBasicAdmin && <TableHead>Komisi</TableHead>}
                                    <TableHead>Status</TableHead>
                                    <TableHead>Aksi</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                <AnimatePresence>
                                    {filteredOrders.map(order => {
                                        const statusConfig = getStatusBadge(order.status);
                                        const StatusIcon = statusConfig.icon;
                                        const commission = order.final_price * (order.product_commission_rate || 0);
                                        const isUnassigned = !order.assigned_to_admin;

                                        return (
                                            <motion.tr 
                                                key={order.id}
                                                initial={{ opacity: 0, x: -20 }}
                                                animate={{ opacity: 1, x: 0 }}
                                                exit={{ opacity: 0, x: 20 }}
                                                transition={{ duration: 0.2 }}
                                            >
                                                <TableCell>
                                                    {format(new Date(order.created_date), 'dd MMM yyyy HH:mm', { locale: id })}
                                                </TableCell>
                                                <TableCell>
                                                    <div>
                                                        <p className="font-medium">{order.customer_name}</p>
                                                        <p className="text-xs text-gray-500 dark:text-gray-400">{order.customer_email}</p>
                                                    </div>
                                                </TableCell>
                                                <TableCell>{order.product_name}</TableCell>
                                                <TableCell className="font-semibold">{formatCurrency(order.final_price)}</TableCell>
                                                {isBasicAdmin && (
                                                    <TableCell>
                                                        <div className="flex items-center gap-1 text-green-600 font-semibold">
                                                            <DollarSign className="w-4 h-4" />
                                                            {formatCurrency(commission)}
                                                        </div>
                                                    </TableCell>
                                                )}
                                                <TableCell>
                                                    <Badge className={statusConfig.color}>
                                                        <StatusIcon className="w-3 h-3 mr-1" />
                                                        {statusConfig.label}
                                                    </Badge>
                                                </TableCell>
                                                <TableCell>
                                                    {isBasicAdmin && isUnassigned && order.status === 'pending' ? (
                                                        <Button
                                                            size="sm"
                                                            onClick={() => handleClaimOrder(order)}
                                                            disabled={isProcessing}
                                                            className="bg-green-600 hover:bg-green-700"
                                                        >
                                                            <CheckCircle className="w-4 h-4 mr-1" />
                                                            Ambil Order
                                                        </Button>
                                                    ) : (
                                                        <Button
                                                            size="sm"
                                                            variant="outline"
                                                            onClick={() => handleViewDetail(order)}
                                                        >
                                                            <Eye className="w-4 h-4 mr-1" />
                                                            Detail
                                                        </Button>
                                                    )}
                                                </TableCell>
                                            </motion.tr>
                                        );
                                    })}
                                </AnimatePresence>
                            </TableBody>
                        </Table>
                    </div>

                    {filteredOrders.length === 0 && (
                        <div className="text-center py-12">
                            <ShoppingCart className="w-16 h-16 mx-auto text-gray-400 mb-4" />
                            <p className="text-gray-600 dark:text-gray-400">
                                {filterStatus === 'all' ? 'Belum ada pesanan' : `Tidak ada pesanan dengan status "${getStatusBadge(filterStatus).label}"`}
                            </p>
                        </div>
                    )}
                </CardContent>
            </Card>

            {/* Order Detail Modal */}
            <Dialog open={isDetailModalOpen} onOpenChange={setIsDetailModalOpen}>
                <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle>Detail Pesanan #{selectedOrder?.id?.slice(0, 8)}</DialogTitle>
                    </DialogHeader>

                    {selectedOrder && (
                        <div className="space-y-6">
                            {/* Commission Preview for Basic Admin */}
                            {isBasicAdmin && selectedOrder.preview_commission > 0 && (
                                <Alert className="bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800">
                                    <DollarSign className="w-4 h-4 text-green-600" />
                                    <AlertDescription>
                                        <p className="font-semibold text-green-800 dark:text-green-200">
                                            Komisi Anda: {formatCurrency(selectedOrder.preview_commission)}
                                        </p>
                                        <p className="text-xs text-green-700 dark:text-green-300 mt-1">
                                            Anda akan mendapat komisi ini setelah menyelesaikan pesanan
                                        </p>
                                    </AlertDescription>
                                </Alert>
                            )}

                            {/* Customer Info */}
                            <div className="grid md:grid-cols-2 gap-4 p-4 bg-gray-50 dark:bg-gray-800 rounded-lg">
                                <div>
                                    <Label className="text-xs text-gray-500">Customer</Label>
                                    <p className="font-medium">{selectedOrder.customer_name}</p>
                                    <p className="text-sm text-gray-500">{selectedOrder.customer_email}</p>
                                </div>
                                <div>
                                    <Label className="text-xs text-gray-500">Produk</Label>
                                    <p className="font-medium">{selectedOrder.product_name}</p>
                                    <p className="text-lg font-bold text-blue-600">{formatCurrency(selectedOrder.final_price)}</p>
                                </div>
                            </div>

                            {/* Order Data from Customer */}
                            <div className="border rounded-lg p-4 bg-white dark:bg-gray-900">
                                <h4 className="font-semibold mb-3 flex items-center gap-2">
                                    ≡ƒôï Data Pesanan Customer
                                </h4>
                                {selectedOrder.order_data && Object.entries(selectedOrder.order_data).length > 0 ? (
                                    <div className="space-y-3">
                                        {Object.entries(selectedOrder.order_data).map(([key, value]) => (
                                            <div key={key} className="pb-2 border-b last:border-0">
                                                <Label className="text-xs text-gray-500 uppercase">{key.replace(/_/g, ' ')}</Label>
                                                {typeof value === 'string' && (value.startsWith('http://') || value.startsWith('https://')) ? (
                                                    <a 
                                                        href={value} 
                                                        target="_blank" 
                                                        rel="noopener noreferrer" 
                                                        className="text-blue-600 hover:underline flex items-center gap-1 text-sm mt-1"
                                                    >
                                                        <Download className="w-3 h-3" />
                                                        Lihat/Download File
                                                    </a>
                                                ) : (
                                                    <p className="text-sm mt-1 whitespace-pre-wrap">{value}</p>
                                                )}
                                            </div>
                                        ))}
                                    </div>
                                ) : (
                                    <p className="text-sm text-gray-500">Tidak ada data pesanan tambahan</p>
                                )}
                            </div>

                            {/* Admin Section - Update Status */}
                            {(isBasicAdmin && selectedOrder.assigned_to_admin === currentUser.email) || !isBasicAdmin ? (
                                <div className="space-y-4">
                                    <div>
                                        <Label>Status Pesanan</Label>
                                        <Select value={status} onValueChange={setStatus}>
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="pending">Menunggu</SelectItem>
                                                <SelectItem value="processing">Diproses</SelectItem>
                                                <SelectItem value="completed">Selesai</SelectItem>
                                                <SelectItem value="cancelled">Dibatalkan</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    <div>
                                        <Label>Catatan Admin untuk Customer</Label>
                                        <Textarea 
                                            value={adminNotes} 
                                            onChange={(e) => setAdminNotes(e.target.value)} 
                                            placeholder="Tambahkan catatan atau instruksi untuk customer..."
                                            rows={3}
                                        />
                                    </div>

                                    <div>
                                        <Label>Upload File Hasil Pekerjaan</Label>
                                        <Input 
                                            type="file" 
                                            onChange={(e) => {
                                                const file = e.target.files[0];
                                                if (file) handleFileUpload(file);
                                            }}
                                            className="mb-2"
                                        />
                                        {resultFiles.length > 0 && (
                                            <div className="space-y-2 mt-3">
                                                <p className="text-sm font-medium">File yang akan dikirim:</p>
                                                {resultFiles.map((url, idx) => (
                                                    <div key={idx} className="flex items-center justify-between p-2 bg-gray-50 dark:bg-gray-800 rounded">
                                                        <a href={url} target="_blank" rel="noopener noreferrer" className="text-sm text-blue-600 hover:underline flex items-center gap-1">
                                                            <Download className="w-3 h-3" />
                                                            File {idx + 1}
                                                        </a>
                                                        <Button 
                                                            size="sm" 
                                                            variant="ghost" 
                                                            onClick={() => handleRemoveFile(idx)}
                                                            className="h-6 w-6 p-0"
                                                        >
                                                            <Trash2 className="w-3 h-3 text-red-500" />
                                                        </Button>
                                                    </div>
                                                ))}
                                            </div>
                                        )}
                                    </div>

                                    <Button 
                                        onClick={handleUpdateOrder} 
                                        disabled={isProcessing} 
                                        className="w-full"
                                    >
                                        {isProcessing ? "Menyimpan..." : "Simpan & Kirim Notifikasi"}
                                    </Button>
                                </div>
                            ) : (
                                <Alert>
                                    <AlertDescription>
                                        Pesanan ini sedang diproses oleh admin lain.
                                    </AlertDescription>
                                </Alert>
                            )}
                        </div>
                    )}
                </DialogContent>
            </Dialog>
        </>
    );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { 
  Handshake, Eye, CheckCircle, XCircle, Mail, Phone, 
  ExternalLink, Loader2, Send, MessageSquare
} from 'lucide-react';
import { toast } from 'sonner';
import { format } from 'date-fns';

export default function PartnershipApplicationsTab() {
  const [applications, setApplications] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedApp, setSelectedApp] = useState(null);
  const [showDialog, setShowDialog] = useState(false);
  const [meetingForm, setMeetingForm] = useState({ meeting_link: '', meeting_date: '', admin_notes: '' });

  useEffect(() => {
    loadApplications();
  }, []);

  const loadApplications = async () => {
    try {
      setIsLoading(true);
      const data = await base44.entities.PartnershipApplication.list('-created_date');
      setApplications(data || []);
    } catch (error) {
      toast.error('Gagal memuat aplikasi');
    } finally {
      setIsLoading(false);
    }
  };

  const updateStatus = async (id, status, additionalData = {}) => {
    try {
      await base44.entities.PartnershipApplication.update(id, {
        status,
        reviewed_by: (await base44.auth.me()).email,
        reviewed_date: new Date().toISOString(),
        ...additionalData
      });

      const app = applications.find(a => a.id === id);
      if (app) {
        let subject = '';
        let body = '';

        if (status === 'negotiation') {
          subject = `≡ƒñ¥ Partnership Discussion - ${app.partnership_type}`;
          body = `
            <h2>Halo, ${app.contact_name}!</h2>
            <p>Terima kasih atas aplikasi partnership Anda untuk <strong>${app.company_name}</strong>.</p>
            <p>Kami tertarik untuk diskusi lebih lanjut!</p>
            <p><strong>Detail Meeting:</strong></p>
            <ul>
              <li>Tanggal: ${additionalData.meeting_date ? format(new Date(additionalData.meeting_date), 'dd MMMM yyyy HH:mm', { locale: id }) : 'TBA'}</li>
              <li>Link: <a href="${additionalData.meeting_link}">${additionalData.meeting_link}</a></li>
            </ul>
            <p>Catatan: ${additionalData.admin_notes || ''}</p>
            <br/><p><strong>Tim Partnership SNISHOP</strong></p>
          `;
        } else if (status === 'approved') {
          subject = `Γ£à Partnership Approved - Welcome to SNISHOP!`;
          body = `
            <h2>Selamat, ${app.contact_name}!</h2>
            <p>Partnership application untuk <strong>${app.company_name}</strong> telah disetujui!</p>
            <p>Selamat bergabung sebagai partner resmi SNISHOP.</p>
            <p>Tim kami akan menghubungi Anda untuk proses onboarding.</p>
            <br/><p><strong>Tim Partnership SNISHOP</strong></p>
          `;
        }

        if (subject && body) {
          await base44.integrations.Core.SendEmail({ to: app.contact_email, subject, body });
          toast.success('Email terkirim!');
        }
      }

      toast.success('Status diupdate!');
      loadApplications();
      setShowDialog(false);
    } catch (error) {
      toast.error('Gagal update');
    }
  };

  const statusConfig = {
    submitted: { label: 'Baru', color: 'bg-blue-600' },
    reviewing: { label: 'Review', color: 'bg-yellow-600' },
    negotiation: { label: 'Negosiasi', color: 'bg-purple-600' },
    approved: { label: 'Approved', color: 'bg-green-600' },
    rejected: { label: 'Rejected', color: 'bg-red-600' }
  };

  if (isLoading) return <div className="flex items-center justify-center p-12"><Loader2 className="w-8 h-8 animate-spin" /></div>;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <Handshake className="w-6 h-6 text-cyan-500" />
          Aplikasi Partnership ({applications.length})
        </h2>
        <Button onClick={loadApplications} variant="outline"><Eye className="w-4 h-4 mr-2" />Refresh</Button>
      </div>

      <div className="grid gap-4">
        {applications.map((app) => (
          <Card key={app.id} className="bg-gray-900 border-gray-700 hover:border-cyan-600 transition-all cursor-pointer" onClick={() => { setSelectedApp(app); setShowDialog(true); }}>
            <CardContent className="p-6">
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <h4 className="text-lg font-bold text-white mb-2">{app.company_name}</h4>
                  <p className="text-gray-400 mb-3">Type: {app.partnership_type} | Contact: {app.contact_name}</p>
                  <div className="flex flex-wrap gap-4 text-sm text-gray-400">
                    <span className="flex items-center gap-1"><Mail className="w-4 h-4" />{app.contact_email}</span>
                    <span className="flex items-center gap-1"><Phone className="w-4 h-4" />{app.contact_phone}</span>
                  </div>
                </div>
                <Badge className={statusConfig[app.status].color}>{statusConfig[app.status].label}</Badge>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      <Dialog open={showDialog} onOpenChange={setShowDialog}>
        <DialogContent className="bg-gray-900 text-white max-w-3xl max-h-[90vh] overflow-y-auto">
          <DialogHeader><DialogTitle>Partnership Application Detail</DialogTitle></DialogHeader>
          {selectedApp && (
            <div className="space-y-6">
              <div className="p-4 bg-gray-800 rounded-lg">
                <h3 className="text-2xl font-bold text-white mb-2">{selectedApp.company_name}</h3>
                <p className="text-gray-400">Contact: {selectedApp.contact_name}</p>
                <Badge className={`${statusConfig[selectedApp.status].color} mt-2`}>{statusConfig[selectedApp.status].label}</Badge>
              </div>

              <div>
                <Label className="text-gray-300">Business Description</Label>
                <p className="text-white mt-2">{selectedApp.business_description}</p>
              </div>

              {selectedApp.proposal_url && (
                <Button variant="outline" onClick={() => window.open(selectedApp.proposal_url, '_blank')}>
                  <ExternalLink className="w-4 h-4 mr-2" />View Proposal
                </Button>
              )}

              {selectedApp.status === 'reviewing' && (
                <Card className="bg-purple-900/30 border-purple-700">
                  <CardContent className="p-4 space-y-4">
                    <Label className="text-white">Schedule Meeting</Label>
                    <Input value={meetingForm.meeting_link} onChange={(e) => setMeetingForm({ ...meetingForm, meeting_link: e.target.value })} placeholder="Meeting link..." className="bg-gray-800 border-gray-700 text-white" />
                    <Input type="datetime-local" value={meetingForm.meeting_date} onChange={(e) => setMeetingForm({ ...meetingForm, meeting_date: e.target.value })} className="bg-gray-800 border-gray-700 text-white" />
                    <Button onClick={() => updateStatus(selectedApp.id, 'negotiation', meetingForm)} className="w-full bg-purple-600">
                      <Send className="w-4 h-4 mr-2" />Send Meeting Invite
                    </Button>
                  </CardContent>
                </Card>
              )}

              <div className="flex gap-3">
                {selectedApp.status === 'submitted' && (
                  <Button onClick={() => updateStatus(selectedApp.id, 'reviewing')} className="bg-yellow-600">Start Review</Button>
                )}
                {(selectedApp.status === 'negotiation' || selectedApp.status === 'reviewing') && (
                  <>
                    <Button onClick={() => updateStatus(selectedApp.id, 'approved')} className="bg-green-600"><CheckCircle className="w-4 h-4 mr-2" />Approve</Button>
                    <Button onClick={() => updateStatus(selectedApp.id, 'rejected')} variant="outline" className="border-red-600 text-red-400"><XCircle className="w-4 h-4 mr-2" />Reject</Button>
                  </>
                )}
                <Button variant="outline" onClick={() => window.open(`https://wa.me/${selectedApp.contact_phone.replace(/[^0-9]/g, '')}`, '_blank')}>
                  <MessageSquare className="w-4 h-4 mr-2" />WhatsApp
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Save, Loader2, Sparkles, Eye, Shield } from 'lucide-react';
import { toast } from 'sonner';

export default function PrivacyContentTab() {
  const [content, setContent] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isAiProcessing, setIsAiProcessing] = useState(false);

  useEffect(() => {
    loadContent();
  }, []);

  const loadContent = async () => {
    try {
      setIsLoading(true);
      const data = await base44.entities.PrivacyContent.list();
      if (data && data.length > 0) {
        setContent(data[0]);
      } else {
        const defaultContent = await base44.entities.PrivacyContent.create({
          title: "Kebijakan Privasi",
          last_updated: new Date().toISOString().split('T')[0],
          is_active: true
        });
        setContent(defaultContent);
      }
    } catch (error) {
      toast.error('Gagal memuat');
    } finally {
      setIsLoading(false);
    }
  };

  const handleSave = async () => {
    try {
      setIsSaving(true);
      await base44.entities.PrivacyContent.update(content.id, content);
      toast.success('Γ£à Berhasil diperbarui!');
    } catch (error) {
      toast.error('Gagal menyimpan');
    } finally {
      setIsSaving(false);
    }
  };

  const handleAiUpdate = async () => {
    if (!aiPrompt.trim()) return;
    try {
      setIsAiProcessing(true);
      const response = await base44.integrations.Core.InvokeLLM({
        prompt: `Update Privacy Policy SNISHOP. ${aiPrompt}. Return JSON.`,
        response_json_schema: {
          type: "object",
          properties: {
            title: { type: "string" },
            intro: { type: "string" },
            contact_email: { type: "string" },
            contact_whatsapp: { type: "string" }
          }
        }
      });
      setContent({ ...content, ...response });
      toast.success('Γ£à Update berhasil!');
      setAiPrompt('');
    } catch (error) {
      toast.error('Gagal AI');
    } finally {
      setIsAiProcessing(false);
    }
  };

  if (isLoading) return <div className="flex items-center justify-center p-12"><Loader2 className="w-8 h-8 animate-spin" /></div>;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <Shield className="w-6 h-6 text-blue-500" />
          Kelola "Kebijakan Privasi"
        </h2>
        <div className="flex gap-3">
          <Button onClick={() => window.open('/privacy', '_blank')} variant="outline"><Eye className="w-4 h-4 mr-2" />Preview</Button>
          <Button onClick={handleSave} disabled={isSaving} className="bg-blue-600">
            {isSaving ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}Simpan
          </Button>
        </div>
      </div>

      <Card className="bg-gradient-to-br from-purple-900/30 to-indigo-900/30 border-purple-700 border-2">
        <CardHeader><CardTitle className="text-white flex items-center gap-2"><Sparkles className="w-5 h-5 text-purple-400" />AI Assistant</CardTitle></CardHeader>
        <CardContent className="space-y-4">
          <Input value={aiPrompt} onChange={(e) => setAiPrompt(e.target.value)} placeholder="Update intro atau kontak" className="bg-gray-800 border-gray-700 text-white" />
          <Button onClick={handleAiUpdate} disabled={isAiProcessing} className="w-full bg-gradient-to-r from-purple-600 to-indigo-600">
            {isAiProcessing ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Sparkles className="w-4 h-4 mr-2" />}Update AI
          </Button>
        </CardContent>
      </Card>

      <Card className="bg-gray-900 border-gray-700">
        <CardHeader><CardTitle className="text-white">Content</CardTitle></CardHeader>
        <CardContent className="space-y-4">
          <div>
            <Label className="text-gray-300">Title</Label>
            <Input value={content?.title || ''} onChange={(e) => setContent({...content, title: e.target.value})} className="bg-gray-800 border-gray-700 text-white mt-2" />
          </div>
          <div>
            <Label className="text-gray-300">Intro</Label>
            <Textarea value={content?.intro || ''} onChange={(e) => setContent({...content, intro: e.target.value})} className="bg-gray-800 border-gray-700 text-white mt-2 min-h-[100px]" />
          </div>
          <div>
            <Label className="text-gray-300">Last Updated</Label>
            <Input type="date" value={content?.last_updated || ''} onChange={(e) => setContent({...content, last_updated: e.target.value})} className="bg-gray-800 border-gray-700 text-white mt-2" />
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { ProductVoucher } from '@/entities/ProductVoucher';
import { DigitalProduct } from '@/entities/DigitalProduct';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Badge } from '@/components/ui/badge';
import { Switch } from '@/components/ui/switch';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Plus, Edit, Trash } from 'lucide-react';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';

export default function ProductVoucherTab() {
  const [vouchers, setVouchers] = useState([]);
  const [products, setProducts] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingVoucher, setEditingVoucher] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [formData, setFormData] = useState({
    code: '',
    name: '',
    discount_type: 'percentage',
    discount_value: 0,
    min_purchase: 0,
    max_discount: 0,
    usage_limit: null,
    valid_from: new Date().toISOString().split('T')[0],
    valid_until: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    applicable_products: [],
    applicable_categories: [],
    is_active: true
  });

  const categoryLabels = {
    zoom: "Zoom Meeting",
    design: "Design Tools",
    plagiarism_check: "Plagiarism Check",
    streaming: "Streaming",
    video_editing: "Video Editing",
    other: "Lainnya"
  };

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [vouchersData, productsData] = await Promise.all([
        ProductVoucher.list('-created_date'),
        DigitalProduct.list()
      ]);
      setVouchers(vouchersData);
      setProducts(productsData);
    } catch (error) {
      toast.error("Gagal memuat data voucher");
    }
  };

  const handleCreate = () => {
    setEditingVoucher(null);
    setFormData({
      code: '',
      name: '',
      discount_type: 'percentage',
      discount_value: 0,
      min_purchase: 0,
      max_discount: 0,
      usage_limit: null,
      valid_from: new Date().toISOString().split('T')[0],
      valid_until: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      applicable_products: [],
      applicable_categories: [],
      is_active: true
    });
    setIsModalOpen(true);
  };

  const handleEdit = (voucher) => {
    setEditingVoucher(voucher);
    setFormData({
      ...voucher,
      valid_from: voucher.valid_from?.split('T')[0] || '',
      valid_until: voucher.valid_until?.split('T')[0] || ''
    });
    setIsModalOpen(true);
  };

  const handleDelete = async (id) => {
    if (confirm('Hapus voucher ini?')) {
      try {
        await ProductVoucher.delete(id);
        toast.success("Voucher berhasil dihapus");
        loadData();
      } catch (error) {
        toast.error("Gagal menghapus voucher");
      }
    }
  };

  const handleSubmit = async () => {
    if (!formData.code || !formData.name) {
      toast.error("Kode dan nama voucher wajib diisi");
      return;
    }

    setIsProcessing(true);
    try {
      const dataToSave = {
        ...formData,
        code: formData.code.toUpperCase(),
        usage_limit: formData.usage_limit || null
      };

      if (editingVoucher) {
        await ProductVoucher.update(editingVoucher.id, dataToSave);
        toast.success("Voucher berhasil diperbarui");
      } else {
        await ProductVoucher.create(dataToSave);
        toast.success("Voucher berhasil ditambahkan");
      }
      setIsModalOpen(false);
      loadData();
    } catch (error) {
      toast.error("Gagal menyimpan voucher");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <>
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold">Voucher Produk</h2>
          <p className="text-gray-600 dark:text-gray-400">Kelola voucher discount untuk produk</p>
        </div>
        <Button onClick={handleCreate}>
          <Plus className="w-4 h-4 mr-2" />
          Tambah Voucher
        </Button>
      </div>

      <Card>
        <CardContent className="p-0">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Kode</TableHead>
                <TableHead>Nama</TableHead>
                <TableHead>Discount</TableHead>
                <TableHead>Min. Pembelian</TableHead>
                <TableHead>Masa Berlaku</TableHead>
                <TableHead>Penggunaan</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Aksi</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {vouchers.map((voucher) => (
                <TableRow key={voucher.id}>
                  <TableCell>
                    <Badge variant="outline" className="font-mono">
                      {voucher.code}
                    </Badge>
                  </TableCell>
                  <TableCell>{voucher.name}</TableCell>
                  <TableCell>
                    {voucher.discount_type === 'percentage' 
                      ? `${voucher.discount_value}%`
                      : `Rp ${voucher.discount_value.toLocaleString('id-ID')}`
                    }
                  </TableCell>
                  <TableCell>Rp {(voucher.min_purchase || 0).toLocaleString('id-ID')}</TableCell>
                  <TableCell className="text-sm">
                    {format(new Date(voucher.valid_from), 'dd MMM', { locale: id })} - 
                    {format(new Date(voucher.valid_until), 'dd MMM yyyy', { locale: id })}
                  </TableCell>
                  <TableCell>
                    {voucher.usage_count || 0} / {voucher.usage_limit || 'Γê₧'}
                  </TableCell>
                  <TableCell>
                    <Badge variant={voucher.is_active ? 'default' : 'secondary'}>
                      {voucher.is_active ? 'Aktif' : 'Nonaktif'}
                    </Badge>
                  </TableCell>
                  <TableCell>
                    <div className="flex gap-2">
                      <Button size="sm" variant="outline" onClick={() => handleEdit(voucher)}>
                        <Edit className="w-4 h-4" />
                      </Button>
                      <Button size="sm" variant="destructive" onClick={() => handleDelete(voucher.id)}>
                        <Trash className="w-4 h-4" />
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
              {vouchers.length === 0 && (
                <TableRow>
                  <TableCell colSpan={8} className="text-center py-8 text-gray-500">
                    Belum ada voucher. Klik "Tambah Voucher" untuk membuat.
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      {/* Voucher Form Modal */}
      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{editingVoucher ? 'Edit Voucher' : 'Tambah Voucher Baru'}</DialogTitle>
          </DialogHeader>

          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Kode Voucher *</Label>
                <Input
                  value={formData.code}
                  onChange={(e) => setFormData({ ...formData, code: e.target.value.toUpperCase() })}
                  placeholder="DISC50K"
                  className="font-mono"
                />
              </div>
              <div>
                <Label>Nama Voucher *</Label>
                <Input
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  placeholder="Diskon 50rb"
                />
              </div>
            </div>

            <div className="grid grid-cols-3 gap-4">
              <div>
                <Label>Tipe Discount</Label>
                <Select value={formData.discount_type} onValueChange={(v) => setFormData({ ...formData, discount_type: v })}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="percentage">Persentase (%)</SelectItem>
                    <SelectItem value="fixed_amount">Jumlah Tetap (Rp)</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label>Nilai Discount *</Label>
                <Input
                  type="number"
                  value={formData.discount_value}
                  onChange={(e) => setFormData({ ...formData, discount_value: Number(e.target.value) })}
                  placeholder={formData.discount_type === 'percentage' ? '10' : '50000'}
                />
              </div>
              {formData.discount_type === 'percentage' && (
                <div>
                  <Label>Max Potongan (Rp)</Label>
                  <Input
                    type="number"
                    value={formData.max_discount || ''}
                    onChange={(e) => setFormData({ ...formData, max_discount: Number(e.target.value) || 0 })}
                    placeholder="100000"
                  />
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Min. Pembelian (Rp)</Label>
                <Input
                  type="number"
                  value={formData.min_purchase}
                  onChange={(e) => setFormData({ ...formData, min_purchase: Number(e.target.value) })}
                  placeholder="0"
                />
              </div>
              <div>
                <Label>Batas Penggunaan</Label>
                <Input
                  type="number"
                  value={formData.usage_limit || ''}
                  onChange={(e) => setFormData({ ...formData, usage_limit: e.target.value ? Number(e.target.value) : null })}
                  placeholder="Unlimited"
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Berlaku Dari *</Label>
                <Input
                  type="date"
                  value={formData.valid_from}
                  onChange={(e) => setFormData({ ...formData, valid_from: e.target.value })}
                />
              </div>
              <div>
                <Label>Berlaku Sampai *</Label>
                <Input
                  type="date"
                  value={formData.valid_until}
                  onChange={(e) => setFormData({ ...formData, valid_until: e.target.value })}
                />
              </div>
            </div>

            <div>
              <Label>Berlaku untuk Kategori (Kosong = Semua)</Label>
              <div className="grid grid-cols-2 gap-2 mt-2">
                {Object.entries(categoryLabels).map(([key, label]) => (
                  <label key={key} className="flex items-center gap-2 p-2 border rounded cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-800">
                    <input
                      type="checkbox"
                      checked={formData.applicable_categories.includes(key)}
                      onChange={(e) => {
                        const cats = e.target.checked 
                          ? [...formData.applicable_categories, key]
                          : formData.applicable_categories.filter(c => c !== key);
                        setFormData({ ...formData, applicable_categories: cats });
                      }}
                    />
                    <span className="text-sm">{label}</span>
                  </label>
                ))}
              </div>
            </div>

            <div className="flex items-center gap-2">
              <Switch
                checked={formData.is_active}
                onCheckedChange={(v) => setFormData({ ...formData, is_active: v })}
              />
              <Label>Voucher Aktif</Label>
            </div>
          </div>

          <div className="flex justify-end gap-3 mt-6 pt-6 border-t">
            <Button onClick={() => setIsModalOpen(false)} variant="outline">
              Batal
            </Button>
            <Button onClick={handleSubmit} disabled={isProcessing}>
              {isProcessing ? 'Menyimpan...' : 'Simpan Voucher'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

import { useState } from 'react';
import { DigitalProduct } from '@/entities/DigitalProduct';
import { UploadFile } from '@/integrations/Core';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Badge } from '@/components/ui/badge';
import { Switch } from '@/components/ui/switch';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Plus, Edit, Trash, X, Image as ImageIcon } from 'lucide-react';
import { toast } from 'sonner';

