    features: [],
    is_active: true,
    stock_available: true,
    commission_rate: 0,
    variants: [],
    order_form_fields: []
  });

  const categoryLabels = {
    zoom: "Zoom Meeting",
    design: "Design Tools (Canva)",
    plagiarism_check: "Plagiarism Check (Turnitin)",
    streaming: "Streaming (Netflix, etc)",
    video_editing: "Video Editing (Capcut, etc)",
    other: "Lainnya"
  };

  const handleCreate = () => {
    setEditingProduct(null);
    setFormData({
      name: '',
      description: '',
      category: 'other',
      price: 0,
      images: [],
      delivery_time: '',
      features: [],
      is_active: true,
      stock_available: true,
      commission_rate: 0,
      variants: [],
      order_form_fields: []
    });
    setIsModalOpen(true);
  };

  const handleEdit = (product) => {
    setEditingProduct(product);
    setFormData({
      ...product,
      images: product.images || [product.image_url].filter(Boolean),
      variants: product.variants || [],
      order_form_fields: product.order_form_fields || []
    });
    setIsModalOpen(true);
  };

  const handleDelete = async (productId) => {
    if (confirm('Hapus produk ini?')) {
      try {
        await DigitalProduct.delete(productId);
        toast.success("Produk berhasil dihapus");
        onUpdate();
      } catch (error) {
        toast.error("Gagal menghapus produk");
      }
    }
  };

  const handleImageUpload = async (file) => {
    try {
      toast.info("Mengunggah gambar...");
      const { file_url } = await UploadFile({ file });
      setFormData((prev) => ({
        ...prev,
        images: [...(prev.images || []), file_url]
      }));
      toast.success("Gambar berhasil diunggah");
    } catch (error) {
      toast.error("Gagal mengunggah gambar");
    }
  };

  const removeImage = (index) => {
    setFormData((prev) => ({
      ...prev,
      images: prev.images.filter((_, i) => i !== index)
    }));
  };

  const handleSubmit = async () => {
    if (!formData.name || !formData.description || formData.price <= 0) {
      toast.error("Isi semua field yang diperlukan");
      return;
    }

    if (!formData.images || formData.images.length === 0) {
      toast.error("Upload minimal 1 gambar produk");
      return;
    }

    setIsProcessing(true);
    try {
      const dataToSave = {
        ...formData,
        image_url: formData.images[0],
        features: formData.features.filter((f) => f.trim() !== ''),
        order_form_fields: formData.order_form_fields.map((field) => ({
          ...field,
          options: field.options || []
        }))
      };

      if (editingProduct) {
        await DigitalProduct.update(editingProduct.id, dataToSave);
        toast.success("Produk berhasil diperbarui");
      } else {
        await DigitalProduct.create(dataToSave);
        toast.success("Produk berhasil ditambahkan");
      }
      setIsModalOpen(false);
      onUpdate();
    } catch (error) {
      toast.error("Gagal menyimpan produk");
      console.error(error);
    } finally {
      setIsProcessing(false);
    }
  };

  const addVariant = () => {
    const newVariant = {
      name: '',
      price: 0,
      description: '',
      is_active: true,
      attributes: {}
    };

    if (formData.category === 'zoom') {
      newVariant.attributes = {
        participant_capacity: '',
        duration: '',
        package_type: 'standard'
      };
    } else if (formData.category === 'design') {
      newVariant.attributes = {
        duration_months: 1,
        account_type: 'pro'
      };
    } else if (formData.category === 'plagiarism_check') {
      newVariant.attributes = {
        check_type: 'regular',
        quota: 1
      };
    } else if (formData.category === 'streaming') {
      newVariant.attributes = {
        duration_months: 1,
        quality: 'hd',
        device_count: 1
      };
    } else if (formData.category === 'video_editing') {
      newVariant.attributes = {
        duration_months: 1,
        features_included: []
      };
    }

    setFormData((prev) => ({
      ...prev,
      variants: [...(prev.variants || []), newVariant]
    }));
  };

  const updateVariant = (index, updates) => {
    setFormData((prev) => ({
      ...prev,
      variants: prev.variants.map((v, i) => i === index ? { ...v, ...updates } : v)
    }));
  };

  const updateVariantAttribute = (index, attrKey, value) => {
    setFormData((prev) => ({
      ...prev,
      variants: prev.variants.map((v, i) =>
      i === index ? { ...v, attributes: { ...v.attributes, [attrKey]: value } } : v
      )
    }));
  };

  const removeVariant = (index) => {
    setFormData((prev) => ({
      ...prev,
      variants: prev.variants.filter((_, i) => i !== index)
    }));
  };

  const addFormField = () => {
    setFormData((prev) => ({
      ...prev,
      order_form_fields: [
      ...prev.order_form_fields,
      {
        field_id: `field_${Date.now()}`,
        field_type: 'text',
        field_label: '',
        field_placeholder: '',
        is_required: false,
        is_enabled: true,
        options: []
      }]

    }));
  };

  const updateFormField = (index, updates) => {
    setFormData((prev) => ({
      ...prev,
      order_form_fields: prev.order_form_fields.map((field, i) =>
      i === index ? { ...field, ...updates } : field
      )
    }));
  };

  const removeFormField = (index) => {
    setFormData((prev) => ({
      ...prev,
      order_form_fields: prev.order_form_fields.filter((_, i) => i !== index)
    }));
  };

  return (
    <>
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold">Manajemen Produk Digital</h2>
        <Button onClick={handleCreate}>
          <Plus className="w-4 h-4 mr-2" />
          Tambah Produk
        </Button>
      </div>

      <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
        {products.map((product) =>
        <Card key={product.id}>
            <CardHeader>
              <div className="aspect-square rounded-lg overflow-hidden bg-gray-100 dark:bg-gray-800 mb-4">
                <img
                src={product.images?.[0] || product.image_url || 'https://via.placeholder.com/400'}
                alt={product.name}
                className="w-full h-full object-cover" />

              </div>
              <CardTitle className="text-lg">{product.name}</CardTitle>
              <div className="flex gap-2 mt-2">
                <Badge>{categoryLabels[product.category]}</Badge>
                <Badge variant={product.is_active ? 'default' : 'secondary'}>
                  {product.is_active ? 'Aktif' : 'Nonaktif'}
                </Badge>
              </div>
            </CardHeader>
            <CardContent>
              <p className="text-sm text-gray-600 dark:text-gray-400 mb-3 line-clamp-2">
                {product.description}
              </p>
              <p className="text-xl font-bold text-blue-600 mb-2">
                Rp {(product.price || 0).toLocaleString('id-ID')}
              </p>
              {product.variants && product.variants.length > 0 &&
            <p className="text-sm text-gray-500 mb-4">
                  {product.variants.length} varian tersedia
                </p>
            }
              <div className="flex gap-2">
                <Button onClick={() => handleEdit(product)} size="sm" variant="outline" className="flex-1">
                  <Edit className="w-4 h-4 mr-1" />
                  Edit
                </Button>
                <Button onClick={() => handleDelete(product.id)} size="sm" variant="destructive">
                  <Trash className="w-4 h-4" />
                </Button>
              </div>
            </CardContent>
          </Card>
        )}
      </div>

      {/* Product Form Modal */}
      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="bg-slate-900 p-6 fixed left-[50%] top-[50%] z-50 grid w-full translate-x-[-50%] translate-y-[-50%] gap-4 border shadow-lg duration-200 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 data-[state=closed]:slide-out-to-left-1/2 data-[state=closed]:slide-out-to-top-[48%] data-[state=open]:slide-in-from-left-1/2 data-[state=open]:slide-in-from-top-[48%] sm:rounded-lg max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{editingProduct ? 'Edit Produk' : 'Tambah Produk Baru'}</DialogTitle>
          </DialogHeader>

          <Tabs defaultValue="basic" className="w-full">
            <TabsList className="bg-slate-950 text-muted-foreground p-1 h-10 items-center justify-center rounded-md grid w-full grid-cols-4">
              <TabsTrigger value="basic">Info Dasar</TabsTrigger>
              <TabsTrigger value="images">Gambar</TabsTrigger>
              <TabsTrigger value="variants">Varian</TabsTrigger>
              <TabsTrigger value="form">Form Tambahan</TabsTrigger>
            </TabsList>

            {/* Basic Info Tab */}
            <TabsContent value="basic" className="space-y-4">
              <div>
                <Label>Nama Produk *</Label>
                <Input
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  placeholder="Zoom Meeting Premium" />

              </div>

              <div>
                <Label>Deskripsi *</Label>
                <Textarea
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  placeholder="Deskripsi lengkap produk"
                  rows={4} />

              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Kategori *</Label>
                  <Select value={formData.category} onValueChange={(v) => setFormData({ ...formData, category: v })}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {Object.entries(categoryLabels).map(([key, label]) =>
                      <SelectItem key={key} value={key}>{label}</SelectItem>
                      )}
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label>Harga Dasar (Rp) *</Label>
                  <Input
                    type="number"
                    value={formData.price}
                    onChange={(e) => setFormData({ ...formData, price: Number(e.target.value) })}
                    placeholder="50000" />

                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Estimasi Pengerjaan</Label>
                  <Input
                    value={formData.delivery_time}
                    onChange={(e) => setFormData({ ...formData, delivery_time: e.target.value })}
                    placeholder="1-2 hari kerja" />

                </div>

                <div>
                  <Label>Komisi Admin (%)</Label>
                  <Input
                    type="number"
                    step="0.01"
                    min="0"
                    max="1"
                    value={(formData.commission_rate || 0) * 100}
                    onChange={(e) => setFormData({ ...formData, commission_rate: Number(e.target.value) / 100 })}
                    placeholder="10" />

                  <p className="text-xs text-gray-500 mt-1">Contoh: 10 = 10%</p>
                </div>
              </div>

              <div>
                <Label>Fitur Produk (Enter untuk menambah)</Label>
                <Textarea
                  value={(formData.features || []).join('\n')}
                  onChange={(e) => setFormData({ ...formData, features: e.target.value.split('\n') })}
                  placeholder="Zoom Premium dengan kapasitas besar&#10;Unlimited meeting time&#10;Recording tersedia"
                  rows={4} />

              </div>

              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Switch
                    checked={formData.is_active}
                    onCheckedChange={(v) => setFormData({ ...formData, is_active: v })} />

                  <Label>Produk Aktif</Label>
                </div>

                <div className="flex items-center gap-2">
                  <Switch
                    checked={formData.stock_available}
                    onCheckedChange={(v) => setFormData({ ...formData, stock_available: v })} />

                  <Label>Stok Tersedia</Label>
                </div>
              </div>
            </TabsContent>

            {/* Images Tab */}
            <TabsContent value="images" className="space-y-4">
              <div>
                <Label>Upload Gambar Produk (Ratio 1:1 / Square) *</Label>
                <div className="mt-2 space-y-4">
                  <div className="border-2 border-dashed rounded-lg p-6 text-center">
                    <ImageIcon className="w-12 h-12 mx-auto mb-3 text-gray-400" />
                    <Input
                      type="file"
                      accept="image/*"
                      onChange={(e) => {
                        if (e.target.files[0]) {
                          handleImageUpload(e.target.files[0]);
                        }
                      }}
                      className="hidden"
                      id="product-image-upload" />

                    <Label htmlFor="product-image-upload" className="cursor-pointer text-blue-600 hover:text-blue-700">
                      Klik untuk upload gambar
                    </Label>
                    <p className="text-xs text-gray-500 mt-1">Rekomendasi: 800x800px</p>
                  </div>

                  {formData.images && formData.images.length > 0 &&
                  <div className="grid grid-cols-3 gap-4">
                      {formData.images.map((img, idx) =>
                    <div key={idx} className="relative aspect-square rounded-lg overflow-hidden bg-gray-100 dark:bg-gray-800 group">
                          <img src={img} alt={`Product ${idx + 1}`} className="w-full h-full object-cover" />
                          <button
                        onClick={() => removeImage(idx)}
                        className="absolute top-2 right-2 bg-red-500 text-white p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">

                            <X className="w-4 h-4" />
                          </button>
                          {idx === 0 &&
                      <Badge className="absolute bottom-2 left-2 bg-blue-600">
                              Gambar Utama
                            </Badge>
                      }
                        </div>
                    )}
                    </div>
                  }
                </div>
              </div>
            </TabsContent>

            {/* Variants Tab */}
            <TabsContent value="variants" className="space-y-4">
              <div className="flex justify-between items-center">
                <div>
                  <Label>Varian Produk</Label>
                  <p className="text-sm text-gray-500">
                    {formData.category === 'zoom' && 'Atur kapasitas peserta, durasi, dan harga'}
                    {formData.category === 'design' && 'Atur durasi akun dan harga'}
                    {formData.category === 'plagiarism_check' && 'Atur tipe cek, kuota, dan harga'}
                    {formData.category === 'streaming' && 'Atur durasi, kualitas, dan harga'}
                    {formData.category === 'video_editing' && 'Atur durasi dan fitur'}
                    {!['zoom', 'design', 'plagiarism_check', 'streaming', 'video_editing'].includes(formData.category) && 'Tambahkan varian produk dengan harga berbeda'}
                  </p>
                </div>
                <Button onClick={addVariant} size="sm" variant="outline">
                  <Plus className="w-4 h-4 mr-1" />
                  Tambah Varian
                </Button>
              </div>

              {formData.variants && formData.variants.length > 0 ?
              <div className="space-y-3">
                  {formData.variants.map((variant, idx) =>
                <Card key={idx}>
                      <CardContent className="pt-6">
                        <div className="flex justify-between items-start mb-3">
                          <h4 className="font-medium">Varian {idx + 1}</h4>
                          <Button
                        onClick={() => removeVariant(idx)}
                        size="sm"
                        variant="ghost">

                            <X className="w-4 h-4" />
                          </Button>
                        </div>
                        
                        <div className="space-y-3">
                          <div className="grid grid-cols-2 gap-3">
                            <div>
                              <Label>Nama Varian</Label>
                              <Input
                            value={variant.name}
                            onChange={(e) => updateVariant(idx, { name: e.target.value })}
                            placeholder="Paket Premium" />

                            </div>
                            <div>
                              <Label>Harga (Rp)</Label>
                              <Input
                            type="number"
                            value={variant.price}
                            onChange={(e) => updateVariant(idx, { price: Number(e.target.value) })}
                            placeholder="100000" />

                            </div>
                          </div>

                          {/* Zoom specific attributes */}
                          {formData.category === 'zoom' &&
                      <div className="grid grid-cols-3 gap-3">
                              <div>
                                <Label>Kapasitas Peserta</Label>
                                <Input
                            value={variant.attributes?.participant_capacity || ''}
                            onChange={(e) => updateVariantAttribute(idx, 'participant_capacity', e.target.value)}
                            placeholder="50-100" />

                              </div>
                              <div>
                                <Label>Durasi</Label>
                                <Input
                            value={variant.attributes?.duration || ''}
                            onChange={(e) => updateVariantAttribute(idx, 'duration', e.target.value)}
                            placeholder="1 jam" />

                              </div>
                              <div>
                                <Label>Jenis Paket</Label>
                                <Select
                            value={variant.attributes?.package_type || 'standard'}
                            onValueChange={(v) => updateVariantAttribute(idx, 'package_type', v)}>

                                  <SelectTrigger>
                                    <SelectValue />
                                  </SelectTrigger>
                                  <SelectContent>
                                    <SelectItem value="standard">Standard</SelectItem>
                                    <SelectItem value="bundling">Bundling Harian</SelectItem>
                                  </SelectContent>
                                </Select>
                              </div>
                            </div>
                      }

                          {/* Canva specific attributes */}
                          {formData.category === 'design' &&
                      <div className="grid grid-cols-2 gap-3">
                              <div>
                                <Label>Durasi (Bulan)</Label>
                                <Input
                            type="number"
                            value={variant.attributes?.duration_months || 1}
                            onChange={(e) => updateVariantAttribute(idx, 'duration_months', Number(e.target.value))}
                            placeholder="1" />

                              </div>
                              <div>
                                <Label>Tipe Akun</Label>
                                <Select
                            value={variant.attributes?.account_type || 'pro'}
                            onValueChange={(v) => updateVariantAttribute(idx, 'account_type', v)}>

                                  <SelectTrigger>
                                    <SelectValue />
                                  </SelectTrigger>
                                  <SelectContent>
                                    <SelectItem value="pro">Pro</SelectItem>
                                    <SelectItem value="team">Team</SelectItem>
                                    <SelectItem value="enterprise">Enterprise</SelectItem>
                                  </SelectContent>
                                </Select>
                              </div>
                            </div>
                      }

                          {/* Turnitin specific attributes */}
                          {formData.category === 'plagiarism_check' &&
                      <div className="grid grid-cols-2 gap-3">
                              <div>
                                <Label>Tipe Cek</Label>
                                <Select
                            value={variant.attributes?.check_type || 'regular'}
                            onValueChange={(v) => updateVariantAttribute(idx, 'check_type', v)}>

                                  <SelectTrigger>
                                    <SelectValue />
                                  </SelectTrigger>
                                  <SelectContent>
                                    <SelectItem value="regular">Regular</SelectItem>
                                    <SelectItem value="priority">Priority</SelectItem>
                                    <SelectItem value="ai">AI Detection</SelectItem>
                                  </SelectContent>
                                </Select>
                              </div>
                              <div>
                                <Label>Kuota Cek</Label>
                                <Select
                            value={String(variant.attributes?.quota || 1)}
                            onValueChange={(v) => updateVariantAttribute(idx, 'quota', Number(v))}>

                                  <SelectTrigger>
                                    <SelectValue />
                                  </SelectTrigger>
                                  <SelectContent>
                                    <SelectItem value="1">1x Cek</SelectItem>
                                    <SelectItem value="3">3x Cek</SelectItem>
                                    <SelectItem value="6">6x Cek</SelectItem>
                                    <SelectItem value="10">10x Cek</SelectItem>
                                  </SelectContent>
                                </Select>
                              </div>
                            </div>
                      }

                          {/* Netflix/Streaming specific attributes */}
                          {formData.category === 'streaming' &&
                      <div className="grid grid-cols-3 gap-3">
                              <div>
                                <Label>Durasi (Bulan)</Label>
                                <Input
                            type="number"
                            value={variant.attributes?.duration_months || 1}
                            onChange={(e) => updateVariantAttribute(idx, 'duration_months', Number(e.target.value))} />

                              </div>
                              <div>
                                <Label>Kualitas</Label>
                                <Select
                            value={variant.attributes?.quality || 'hd'}
                            onValueChange={(v) => updateVariantAttribute(idx, 'quality', v)}>

                                  <SelectTrigger>
                                    <SelectValue />
                                  </SelectTrigger>
                                  <SelectContent>
                                    <SelectItem value="sd">SD</SelectItem>
                                    <SelectItem value="hd">HD</SelectItem>
                                    <SelectItem value="4k">4K</SelectItem>
                                  </SelectContent>
                                </Select>
                              </div>
                              <div>
                                <Label>Jumlah Device</Label>
                                <Input
                            type="number"
                            value={variant.attributes?.device_count || 1}
                            onChange={(e) => updateVariantAttribute(idx, 'device_count', Number(e.target.value))} />

                              </div>
                            </div>
                      }

                          {/* Capcut/Video Editing specific attributes */}
                          {formData.category === 'video_editing' &&
                      <div className="grid grid-cols-2 gap-3">
                              <div>
                                <Label>Durasi (Bulan)</Label>
                                <Input
                            type="number"
                            value={variant.attributes?.duration_months || 1}
                            onChange={(e) => updateVariantAttribute(idx, 'duration_months', Number(e.target.value))} />

                              </div>
                              <div>
                                <Label>Fitur</Label>
                                <Input
                            value={variant.attributes?.features_included?.join(', ') || ''}
                            onChange={(e) => updateVariantAttribute(idx, 'features_included', e.target.value.split(',').map((s) => s.trim()))}
                            placeholder="Premium templates, AI tools" />

                              </div>
                            </div>
                      }

                          <div>
                            <Label>Deskripsi Varian</Label>
                            <Textarea
                          value={variant.description}
                          onChange={(e) => updateVariant(idx, { description: e.target.value })}
                          placeholder="Penjelasan varian ini"
                          rows={2} />

                          </div>

                          <div className="flex items-center gap-2">
                            <Switch
                          checked={variant.is_active}
                          onCheckedChange={(v) => updateVariant(idx, { is_active: v })} />

                            <Label>Varian Aktif</Label>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                )}
                </div> :

              <p className="text-sm text-gray-500 text-center py-8">
                  Belum ada varian. Klik "Tambah Varian" untuk menambahkan.
                </p>
              }
            </TabsContent>

            {/* Form Fields Tab */}
            <TabsContent value="form" className="space-y-4">
              <div className="flex justify-between items-center">
                <div>
                  <Label>Field Form Tambahan (Opsional)</Label>
                  <p className="text-sm text-gray-500">Field tambahan selain varian (e.g., email, notes)</p>
                </div>
                <Button onClick={addFormField} size="sm" variant="outline">
                  <Plus className="w-4 h-4 mr-1" />
                  Tambah Field
                </Button>
              </div>

              {formData.order_form_fields && formData.order_form_fields.length > 0 ?
              <div className="space-y-3">
                  {formData.order_form_fields.map((field, idx) =>
                <Card key={idx}>
                      <CardContent className="pt-6">
                        <div className="flex justify-between items-start mb-3">
                          <h4 className="font-medium">Field {idx + 1}</h4>
                          <div className="flex gap-2">
                            <Switch
                          checked={field.is_enabled}
                          onCheckedChange={(v) => updateFormField(idx, { is_enabled: v })} />

                            <Button onClick={() => removeFormField(idx)} size="sm" variant="ghost">
                              <X className="w-4 h-4" />
                            </Button>
                          </div>
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                          <div>
                            <Label>ID Field</Label>
                            <Input
                          value={field.field_id}
                          onChange={(e) => updateFormField(idx, { field_id: e.target.value })} />

                          </div>
                          <div>
                            <Label>Tipe Field</Label>
                            <Select
                          value={field.field_type}
                          onValueChange={(v) => updateFormField(idx, { field_type: v })}>

                              <SelectTrigger>
                                <SelectValue />
                              </SelectTrigger>
                              <SelectContent>
                                <SelectItem value="text">Text</SelectItem>
                                <SelectItem value="email">Email</SelectItem>
                                <SelectItem value="textarea">Textarea</SelectItem>
                                <SelectItem value="file">File Upload</SelectItem>
                                <SelectItem value="date">Date</SelectItem>
                                <SelectItem value="checkbox">Checkbox</SelectItem>
                              </SelectContent>
                            </Select>
                          </div>
                          <div>
                            <Label>Label</Label>
                            <Input
                          value={field.field_label}
                          onChange={(e) => updateFormField(idx, { field_label: e.target.value })} />

                          </div>
                          <div>
                            <Label>Placeholder</Label>
                            <Input
                          value={field.field_placeholder}
                          onChange={(e) => updateFormField(idx, { field_placeholder: e.target.value })} />

                          </div>
                        </div>

                        <div className="flex items-center gap-2 mt-3">
                          <Switch
                        checked={field.is_required}
                        onCheckedChange={(v) => updateFormField(idx, { is_required: v })} />

                          <Label>Field Wajib Diisi</Label>
                        </div>
                      </CardContent>
                    </Card>
                )}
                </div> :

              <p className="text-sm text-gray-500 text-center py-8">
                  Belum ada field tambahan. Varian sudah mencakup field utama.
                </p>
              }
            </TabsContent>
          </Tabs>

          <div className="flex justify-end gap-3 mt-6 pt-6 border-t">
            <Button onClick={() => setIsModalOpen(false)} variant="outline">
              Batal
            </Button>
            <Button onClick={handleSubmit} disabled={isProcessing} className="inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0 bg-primary text-primary-foreground hover:bg-primary/90 h-10 px-4 py-2">
              {isProcessing ? 'Menyimpan...' : 'Simpan Produk'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </>);

}

import { useState, useEffect } from 'react';
import { UpgradeRequest } from '@/entities/UpgradeRequest';
import { Commission } from '@/entities/Commission';
import { AddonRequest } from '@/entities/AddonRequest';
import { ProductOrder } from '@/entities/ProductOrder';
import { User } from '@/entities/User';
import { DigitalProduct } from '@/entities/DigitalProduct';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { DollarSign, TrendingUp, Award, ShoppingCart, Trophy, Package, Target } from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { format, startOfMonth, endOfMonth, startOfYear, endOfYear, subMonths } from 'date-fns';
import { id } from 'date-fns/locale';

const COLORS = ['#3b82f6', '#8b5cf6', '#10b981', '#f59e0b', '#ef4444', '#06b6d4'];

const formatCurrency = (amount) => `Rp ${Number(amount || 0).toLocaleString('id-ID')}`;

export default function RevenueAnalyticsTab({ upgradeRequests, orders }) { // Modified component signature
  const [period, setPeriod] = useState('all');
  const [analytics, setAnalytics] = useState({
    totalRevenue: 0,
    shopRevenue: 0,
    membershipRevenue: 0,
    totalCommissions: 0,
    adminCommissions: 0,
    netRevenue: 0,
    totalOrders: 0,
    transactions: [],
    monthlyRevenue: [],
    topAdmins: [],
    topProducts: [],
    worstProducts: []
  });
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    loadAnalytics();
  }, [period]);

  const loadAnalytics = async () => {
    setIsLoading(true);
    try {
      const [
        allUpgrades,
        allAddons,
        allCommissions,
        allOrders,
        allAdmins,
        allProducts] =
        await Promise.all([
          UpgradeRequest.filter({ status: 'approved' }),
          AddonRequest.filter({ status: 'approved' }),
          Commission.filter({ status: 'paid_to_balance' }),
          ProductOrder.filter({ status: 'completed' }),
          User.filter({ admin_type: 'basic' }),
          DigitalProduct.list()]
        );

      let filteredUpgrades = allUpgrades;
      let filteredAddons = allAddons;
      let filteredCommissions = allCommissions;
      let filteredOrders = allOrders;

      const now = new Date();
      if (period === 'month') {
        const startDate = startOfMonth(now);
        const endDate = endOfMonth(now);
        filteredUpgrades = allUpgrades.filter((u) => {
          const date = new Date(u.created_date);
          return date >= startDate && date <= endDate;
        });
        filteredAddons = allAddons.filter((a) => {
          const date = new Date(a.created_date);
          return date >= startDate && date <= endDate;
        });
        filteredCommissions = allCommissions.filter((c) => {
          const date = new Date(c.created_date);
          return date >= startDate && date <= endDate;
        });
        filteredOrders = allOrders.filter((o) => {
          const date = new Date(o.completed_at);
          return date >= startDate && date <= endDate;
        });
      } else if (period === 'year') {
        const startDate = startOfYear(now);
        const endDate = endOfYear(now);
        filteredUpgrades = allUpgrades.filter((u) => {
          const date = new Date(u.created_date);
          return date >= startDate && date <= endDate;
        });
        filteredAddons = allAddons.filter((a) => {
          const date = new Date(a.created_date);
          return date >= startDate && date <= endDate;
        });
        filteredCommissions = allCommissions.filter((c) => {
          const date = new Date(c.created_date);
          return date >= startDate && date <= endDate;
        });
        filteredOrders = allOrders.filter((o) => {
          const date = new Date(o.completed_at);
          return date >= startDate && date <= endDate;
        });
      }

      // Calculate revenues
      const membershipRevenue = filteredUpgrades.reduce((sum, u) => sum + (u.price_paid || 0), 0) +
        filteredAddons.reduce((sum, a) => sum + (a.price_paid || 0), 0);

      const shopRevenue = filteredOrders.reduce((sum, o) => sum + (o.final_price || 0), 0);

      const totalRevenue = membershipRevenue + shopRevenue;

      const totalCommissions = filteredCommissions.reduce((sum, c) => sum + (c.commission_amount || 0), 0);

      const adminCommissions = filteredOrders.reduce((sum, o) => sum + (o.admin_commission_amount || 0), 0);

      const netRevenue = totalRevenue - totalCommissions - adminCommissions;

      // Monthly revenue for last 6 months
      const monthlyData = [];
      for (let i = 5; i >= 0; i--) {
        const monthStart = startOfMonth(subMonths(now, i));
        const monthEnd = endOfMonth(subMonths(now, i));

        const monthUpgrades = allUpgrades.filter((u) => {
          const date = new Date(u.created_date);
          return date >= monthStart && date <= monthEnd;
        });

        const monthAddons = allAddons.filter((a) => {
          const date = new Date(a.created_date);
          return date >= monthStart && date <= monthEnd;
        });

        const monthOrders = allOrders.filter((o) => {
          const date = new Date(o.completed_at);
          return date >= monthStart && date <= monthEnd;
        });

        const revenue = monthUpgrades.reduce((sum, u) => sum + (u.price_paid || 0), 0) +
          monthAddons.reduce((sum, a) => sum + (a.price_paid || 0), 0) +
          monthOrders.reduce((sum, o) => sum + (o.final_price || 0), 0);

        monthlyData.push({
          month: format(monthStart, 'MMM', { locale: id }),
          revenue: revenue
        });
      }

      // Top Admins Stats
      const adminStats = await Promise.all(
        allAdmins.map(async (admin) => {
          const adminOrders = filteredOrders.filter((o) => o.processed_by_admin === admin.email);
          const earnings = adminOrders.reduce((sum, o) => sum + (o.admin_commission_amount || 0), 0);
          return {
            name: admin.full_name || admin.email,
            email: admin.email,
            orders: adminOrders.length,
            commission: earnings // Renamed earnings to commission
          };
        })
      );

      const topAdmins = adminStats.
        filter((a) => a.orders > 0).
        sort((a, b) => b.commission - a.commission). // Sorted by commission
        slice(0, 10);

      // Product Statistics
      const productStats = allProducts.map((product) => {
        const productOrders = filteredOrders.filter((o) => o.product_id === product.id);
        const revenue = productOrders.reduce((sum, o) => sum + (o.final_price || 0), 0);
        return {
          id: product.id,
          name: product.name,
          category: product.category,
          orders: productOrders.length,
          revenue: revenue
        };
      });

      const topProducts = productStats.
        filter((p) => p.orders > 0).
        sort((a, b) => b.revenue - a.revenue).
        slice(0, 10);

      const worstProducts = productStats.
        filter((p) => p.orders === 0 || p.revenue < 100000).
        sort((a, b) => a.orders - b.orders).
        slice(0, 10);

      // Combine all transactions
      const transactions = [
        ...filteredUpgrades.map((u) => ({
          type: 'membership',
          date: u.created_date,
          user: u.user_full_name || 'Unknown',
          item: u.requested_plan || 'unknown',
          amount: u.price_paid || 0
        })),
        ...filteredOrders.map((o) => ({
          type: 'shop',
          date: o.completed_at,
          user: o.customer_name || 'Unknown',
          item: o.product_name || 'unknown',
          amount: o.final_price || 0
        }))].
        sort((a, b) => new Date(b.date) - new Date(a.date));

      setAnalytics({
        totalRevenue,
        shopRevenue,
        membershipRevenue,
        totalCommissions,
        adminCommissions,
        netRevenue,
        totalOrders: filteredOrders.length,
        transactions,
        monthlyRevenue: monthlyData,
        topAdmins,
        topProducts,
        worstProducts
      });

    } catch (error) {
      console.error('Error loading analytics:', error);
    } finally {
      setIsLoading(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center p-12">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>);
  }

  return (
    <div className="space-y-6">
      {/* Period Selector */}
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold">Analisa Pendapatan</h2>
        <Select value={period} onValueChange={setPeriod}>
          <SelectTrigger className="w-48">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">Semua Waktu</SelectItem>
            <SelectItem value="month">Bulan Ini</SelectItem>
            <SelectItem value="year">Tahun Ini</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Key Metrics */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <Card className="bg-gradient-to-br from-blue-600/20 to-blue-700/20 border-blue-500/50">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Pendapatan Kotor</CardTitle>
            <DollarSign className="h-5 w-5 text-blue-400" />
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">
              {formatCurrency(analytics.totalRevenue || 0)}
            </div>
            <p className="text-xs text-gray-600 dark:text-gray-400 mt-1">
              Membership: {formatCurrency(analytics.membershipRevenue || 0)}
            </p>
            <p className="text-xs text-gray-600 dark:text-gray-400">
              Toko: {formatCurrency(analytics.shopRevenue || 0)}
            </p>
          </CardContent>
        </Card>

        <Card className="bg-gradient-to-br from-red-600/20 to-red-700/20 border-red-500/50">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Komisi Dibayarkan</CardTitle>
            <Award className="h-5 w-5 text-red-400" />
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">
              {formatCurrency((analytics.totalCommissions || 0) + (analytics.adminCommissions || 0))}
            </div>
            <p className="text-xs text-gray-600 dark:text-gray-400 mt-1">
              Komisi Referral: {formatCurrency(analytics.totalCommissions || 0)}
            </p>
            <p className="text-xs text-gray-600 dark:text-gray-400">
              Komisi Admin: {formatCurrency(analytics.adminCommissions || 0)}
            </p>
          </CardContent>
        </Card>

        <Card className="bg-gradient-to-br from-green-600/20 to-green-700/20 border-green-500/50">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Pendapatan Bersih</CardTitle>
            <TrendingUp className="h-5 w-5 text-green-400" />
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">
              {formatCurrency(analytics.netRevenue || 0)}
            </div>
            <p className="text-xs text-gray-600 dark:text-gray-400 mt-1">
              Margin: {(analytics.netRevenue / (analytics.totalRevenue || 1) * 100).toFixed(1)}%
            </p>
          </CardContent>
        </Card>

        <Card className="bg-gradient-to-br from-purple-600/20 to-purple-700/20 border-purple-500/50">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Order Toko</CardTitle>
            <ShoppingCart className="h-5 w-5 text-purple-400" />
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">
              {analytics.totalOrders || 0}
            </div>
            <p className="text-xs text-gray-600 dark:text-gray-400 mt-1">
              Pesanan selesai
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Monthly Revenue Chart */}
      <Card>
        <CardHeader>
          <CardTitle>Tren Pendapatan 6 Bulan Terakhir</CardTitle>
        </CardHeader>
        <CardContent>
          <ResponsiveContainer width="100%" height={300}>
            <LineChart data={analytics.monthlyRevenue}>
              <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
              <XAxis dataKey="month" stroke="#9ca3af" />
              <YAxis stroke="#9ca3af" />
              <Tooltip
                contentStyle={{ backgroundColor: '#1f2937', border: '1px solid #374151' }}
                labelStyle={{ color: '#fff' }} />

              <Legend />
              <Line type="monotone" dataKey="revenue" stroke="#3b82f6" name="Pendapatan" strokeWidth={2} />
            </LineChart>
          </ResponsiveContainer>
        </CardContent>
      </Card>

      {/* Top Admins & Products */}
      <div className="grid md:grid-cols-2 gap-6">
        {/* Top Admins */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2"> {/* Added flex for icon */}
              <Trophy className="w-5 h-5 text-yellow-500" />
              Top Admin (Berdasarkan Komisi) {/* Modified title */}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {analytics.topAdmins.map((admin, idx) =>
                <div key={idx} className="bg-slate-900 p-3 flex items-center justify-between rounded-lg"> {/* Modified bg class */}
                  <div className="flex items-center gap-3">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm ${
                      idx === 0 ? 'bg-yellow-400 text-white' :
                        idx === 1 ? 'bg-gray-300 text-gray-800' :
                          idx === 2 ? 'bg-orange-400 text-white' : 'bg-gray-100 text-gray-600'}`}> {/* Modified default color class */}
                      {idx + 1}
                    </div>
                    <div>
                      <p className="font-medium">{admin.name}</p> {/* Removed text-sm */}
                      <p className="text-xs text-gray-500">{admin.email}</p> {/* Added admin email */}
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="font-semibold text-green-600">{formatCurrency(admin.commission)}</p> {/* Modified to commission, font-semibold */}
                    <p className="text-xs text-gray-500">{admin.orders} pesanan</p> {/* Modified text from 'transaksi' to 'pesanan' */}
                  </div>
                </div>
              )}
              {analytics.topAdmins.length === 0 &&
                <p className="text-center text-gray-500 py-8">Belum ada data admin</p>
              }
            </div>
          </CardContent>
        </Card>

        {/* Top Products */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2"> {/* Added flex for icon */}
              <Package className="w-5 h-5 text-green-500" />
              Produk Terlaris {/* Modified title */}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {analytics.topProducts.map((product, idx) =>
                <div key={idx} className="bg-slate-900 p-3 flex items-center justify-between rounded-lg"> {/* Modified bg class */}
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-green-100 text-green-800 flex items-center justify-center font-bold text-sm">
                      {idx + 1}
                    </div>
                    <div>
                      <p className="font-medium">{product.name}</p> {/* Removed text-sm */}
                      <p className="text-xs text-gray-500">{product.orders} pesanan</p> {/* Modified text from 'terjual' to 'pesanan' */}
                    </div>
                  </div>
                  <p className="font-semibold text-green-600">{formatCurrency(product.revenue)}</p> {/* Modified font-bold to font-semibold */}
                </div>
              )}
              {analytics.topProducts.length === 0 &&
                <p className="text-center text-gray-500 py-8">Belum ada data produk</p>
              }
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Worst Products */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Target className="w-5 h-5 text-red-500" />
            Produk Kurang Laku (Perlu Perhatian)
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid md:grid-cols-2 gap-3">
            {analytics.worstProducts.map((product, idx) =>
              <div key={idx} className="bg-slate-950 p-3 flex items-center justify-between dark:bg-gray-800 rounded-lg">
                <div>
                  <p className="font-medium text-sm">{product.name}</p>
                  <p className="text-xs text-gray-500">
                    {product.orders} terjual ΓÇó {formatCurrency(product.revenue)}
                  </p>
                </div>
                <Badge variant="destructive" className="text-xs">
                  {product.orders === 0 ? 'Belum Terjual' : 'Kurang Laku'}
                </Badge>
              </div>
            )}
            {analytics.worstProducts.length === 0 &&
              <p className="text-center text-gray-500 py-8 col-span-2">Semua produk laris!</p>
            }
          </div>
        </CardContent>
      </Card>

      {/* Recent Transactions */}
      <Card>
        <CardHeader>
          <CardTitle>Transaksi Terbaru</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Tanggal</TableHead>
                  <TableHead>User</TableHead>
                  <TableHead>Tipe</TableHead>
                  <TableHead>Item</TableHead>
                  <TableHead>Jumlah</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {analytics.transactions.slice(0, 20).map((transaction, index) =>
                  <TableRow key={index}>
                    <TableCell>
                      {format(new Date(transaction.date), 'dd MMM yyyy HH:mm', { locale: id })}
                    </TableCell>
                    <TableCell>{transaction.user}</TableCell>
                    <TableCell>
                      <Badge className={transaction.type === 'membership' ? 'bg-blue-600' : 'bg-green-600'}>
                        {transaction.type === 'membership' ? 'Membership' : 'Toko'}
                      </Badge>
                    </TableCell>
                    <TableCell>{transaction.item}</TableCell>
                    <TableCell className="text-green-600 font-semibold">
                      {formatCurrency(transaction.amount || 0)}
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>
    </div>);
}

import { useState, useEffect } from 'react';
import { ShopSettings } from '@/entities/ShopSettings';
import { UploadFile } from '@/integrations/Core';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Switch } from '@/components/ui/switch';
import { toast } from 'sonner';
import { Store, Image as ImageIcon, Tag, Percent } from 'lucide-react';

export default function ShopSettingsTab() {
    const [settings, setSettings] = useState({
        setting_key: 'main',
        banner_image_url: '',
        banner_title: 'Digital Store TODOIT',
        banner_subtitle: 'Produk digital berkualitas dengan harga terjangkau',
        promo_banner: {
            active: false,
            title: 'Promo Spesial!',
            description: 'Dapatkan discount untuk semua produk',
            discount_percentage: 10,
            valid_until: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString()
        },
        reseller_discounts: {
            free: 0,
            pro: 0.05,
            business: 0.1,
            advanced: 0.15,
            enterprise: 0.2
        }
    });
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        loadSettings();
    }, []);

    const loadSettings = async () => {
        try {
            const data = await ShopSettings.filter({ setting_key: 'main' });
            if (data.length > 0) {
                setSettings(data[0]);
            }
        } catch (error) {
            console.error("Error loading shop settings:", error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleBannerUpload = async (file) => {
        try {
            toast.info("Mengunggah banner...");
            const { file_url } = await UploadFile({ file });
            setSettings(prev => ({ ...prev, banner_image_url: file_url }));
            toast.success("Banner berhasil diunggah");
        } catch (error) {
            toast.error("Gagal mengunggah banner");
        }
    };

    const handleSave = async () => {
        setIsSaving(true);
        try {
            if (settings.id) {
                await ShopSettings.update(settings.id, settings);
                toast.success("Pengaturan toko berhasil diperbarui");
            } else {
                await ShopSettings.create(settings);
                toast.success("Pengaturan toko berhasil dibuat");
            }
            loadSettings();
        } catch (error) {
            toast.error("Gagal menyimpan pengaturan");
            console.error(error);
        } finally {
            setIsSaving(false);
        }
    };

    if (isLoading) {
        return <div className="flex items-center justify-center p-12">Loading...</div>;
    }

    return (
        <div className="space-y-6">
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Store className="w-5 h-5" />
                        Pengaturan Toko Digital
                    </CardTitle>
                </CardHeader>
                <CardContent className="space-y-6">
                    {/* Banner Settings */}
                    <div className="space-y-4">
                        <h3 className="text-lg font-semibold flex items-center gap-2">
                            <ImageIcon className="w-5 h-5" />
                            Banner Toko
                        </h3>
                        <div className="grid md:grid-cols-2 gap-4">
                            <div>
                                <Label>Judul Banner</Label>
                                <Input
                                    value={settings.banner_title}
                                    onChange={(e) => setSettings({ ...settings, banner_title: e.target.value })}
                                    placeholder="Digital Store TODOIT"
                                />
                            </div>
                            <div>
                                <Label>Subtitle Banner</Label>
                                <Input
                                    value={settings.banner_subtitle}
                                    onChange={(e) => setSettings({ ...settings, banner_subtitle: e.target.value })}
