  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubscribe = async (e) => {
    e.preventDefault();
    
    if (!email) {
      toast.error('Email wajib diisi');
      return;
    }

    try {
      setIsSubmitting(true);

      // Check if already subscribed
      const existing = await base44.entities.NewsletterSubscriber.filter({ email });
      if (existing && existing.length > 0) {
        toast.error('Email sudah terdaftar untuk newsletter');
        return;
      }

      await base44.entities.NewsletterSubscriber.create({
        email,
        name: name || null,
        subscribed_from: source,
        is_active: true
      });

      toast.success('Γ£à Berhasil subscribe newsletter! Terima kasih.');
      setEmail('');
      setName('');
    } catch (error) {
      toast.error('Gagal subscribe newsletter');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card className="bg-gradient-to-br from-blue-900/40 to-indigo-900/40 border-blue-700">
      <CardContent className="p-8">
        <div className="text-center mb-6">
          <Mail className="w-12 h-12 text-blue-400 mx-auto mb-4" />
          <h3 className="text-2xl font-bold text-white mb-2">
            Subscribe Newsletter
          </h3>
          <p className="text-gray-300">
            Dapatkan update artikel terbaru dan tips bisnis langsung ke email Anda
          </p>
        </div>
        <form onSubmit={handleSubscribe} className="space-y-4">
          <Input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="Nama Anda (optional)"
            className="bg-gray-800 border-gray-700 text-white"
          />
          <Input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="Email Anda"
            className="bg-gray-800 border-gray-700 text-white"
            required
          />
          <Button
            type="submit"
            disabled={isSubmitting}
            className="w-full bg-blue-600 hover:bg-blue-700"
          >
            {isSubmitting ? (
              <Loader2 className="w-4 h-4 mr-2 animate-spin" />
            ) : (
              <Send className="w-4 h-4 mr-2" />
            )}
            Subscribe
          </Button>
        </form>
      </CardContent>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Badge } from '@/components/ui/badge';
import { MapPin, Clock, Settings as SettingsIcon, Save, Loader2, Plus, Trash2, Edit2 } from 'lucide-react';
import { toast } from 'sonner';

export default function AttendanceSettingsForm({ company, onSuccess }) {
  const [settings, setSettings] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isSettingLocation, setIsSettingLocation] = useState(false);
  const [editingShift, setEditingShift] = useState(null);
  const [showShiftDialog, setShowShiftDialog] = useState(false);

  useEffect(() => {
    if (company?.id) {
      loadSettings();
    }
  }, [company?.id]); // Only reload when company ID changes

  const loadSettings = async () => {
    try {
      setIsLoading(true);
      console.log('≡ƒöä Loading settings for company:', company.id);
      
      const data = await base44.entities.CompanyAttendanceSettings.filter({
        company_id: company.id
      });

      console.log('≡ƒôª Loaded data from DB:', data);

      if (data && data.length > 0) {
        const loadedSettings = data[0];
        console.log('Γ£à Settings loaded, shifts count:', loadedSettings.shifts?.length || 0);
        setSettings(loadedSettings);
      } else {
        console.log('ΓÜá∩╕Å No settings found, using defaults');
        // Default settings
        setSettings({
          company_id: company.id,
          office_location: null,
          office_radius_meters: 100,
          require_office_location: false,
          use_multiple_shifts: false,
          working_hours: {
            start_time: '09:00',
            end_time: '17:00',
            break_duration_minutes: 60
          },
          shifts: [],
          overtime_settings: {
            enabled: true,
            start_after_hours: 8,
            max_overtime_hours_per_day: 4
          },
          late_tolerance_minutes: 15,
          working_days: [1, 2, 3, 4, 5],
          auto_clock_out_enabled: false,
          auto_clock_out_time: '18:00',
          require_photo: true,
          require_notes: false
        });
      }
    } catch (error) {
      console.error('Γ¥î Error loading settings:', error);
      toast.error('Gagal memuat pengaturan');
    } finally {
      setIsLoading(false);
    }
  };

  const handleSetCurrentLocation = async () => {
    try {
      setIsSettingLocation(true);

      const position = await new Promise((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, {
          enableHighAccuracy: true,
          timeout: 10000
        });
      });

      const location = {
        latitude: position.coords.latitude,
        longitude: position.coords.longitude,
        address: 'Lokasi kantor'
      };

      setSettings({
        ...settings,
        office_location: location
      });

      toast.success('≡ƒôì Lokasi kantor berhasil diset!');
    } catch (error) {
      console.error('Error getting location:', error);
      toast.error('Γ¥î Gagal mendapatkan lokasi. Aktifkan GPS dan izinkan akses lokasi.');
    } finally {
      setIsSettingLocation(false);
    }
  };

  const handleSave = async () => {
    try {
      setIsSaving(true);
      
      // Γ£à CRITICAL: Ensure shifts are preserved
      const settingsToSave = {
        ...settings,
        shifts: settings.shifts || [] // Ensure shifts array exists
      };
      
      console.log('≡ƒÆ╛ Saving ALL settings to database...');
      console.log('≡ƒôè Current shifts in state:', settingsToSave.shifts?.length || 0);
      console.log('≡ƒôª Full settings object:', settingsToSave);

      let savedSettings;
      if (settings.id) {
        console.log('≡ƒöä Updating existing settings with ID:', settings.id);
        savedSettings = await base44.entities.CompanyAttendanceSettings.update(settings.id, settingsToSave);
        console.log('Γ£à Settings updated successfully');
        console.log('Γ£à Saved shifts count:', savedSettings.shifts?.length || 0);
      } else {
        console.log('Γ₧ò Creating new settings...');
        savedSettings = await base44.entities.CompanyAttendanceSettings.create(settingsToSave);
        console.log('Γ£à Settings created successfully');
        // Update state with new ID
        setSettings({ ...settingsToSave, id: savedSettings.id });
      }

      // Γ£à BROADCAST: Notify all attendance pages
      try {
        const channel = new BroadcastChannel('snishop_attendance_settings_updates');
        channel.postMessage({
          type: 'SETTINGS_UPDATED',
          companyId: company.id,
          shifts: settingsToSave.shifts,
          timestamp: Date.now()
        });
        channel.close();
        console.log('≡ƒôí Settings broadcasted to all pages');
      } catch (e) {
        console.warn('Broadcast error:', e);
      }

      toast.success('Γ£à Pengaturan berhasil disimpan!', {
        description: `${settingsToSave.shifts?.length || 0} shift tersimpan`
      });
      
      if (onSuccess) onSuccess();
    } catch (error) {
      console.error('Γ¥î Error saving settings:', error);
      toast.error(`Gagal menyimpan pengaturan: ${error.message}`);
    } finally {
      setIsSaving(false);
    }
  };

  // Show loading spinner
  if (isLoading || !settings) {
    return (
      <div className="flex items-center justify-center p-12">
        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Office Location */}
      <Card className="bg-gray-900 border-gray-700">
        <CardHeader>
          <CardTitle className="text-white flex items-center gap-2">
            <MapPin className="w-5 h-5" />
            Lokasi Kantor & Radius
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div>
            <Label className="text-white">Lokasi Kantor</Label>
            {settings.office_location ? (
              <div className="mt-2 p-3 bg-gray-800 rounded-lg">
                <p className="text-sm text-gray-300">
                  ≡ƒôì Lat: {settings.office_location.latitude?.toFixed(6)},
                  Lng: {settings.office_location.longitude?.toFixed(6)}
                </p>
                <a
                  href={`https://www.google.com/maps?q=${settings.office_location.latitude},${settings.office_location.longitude}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-400 hover:underline text-sm mt-1 block"
                >
                  Lihat di Google Maps ΓåÆ
                </a>
              </div>
            ) : (
              <p className="text-sm text-gray-400 mt-2">Belum diset</p>
            )}
            <Button
              onClick={handleSetCurrentLocation}
              disabled={isSettingLocation}
              className="mt-3 bg-blue-600 hover:bg-blue-700"
            >
              {isSettingLocation ? (
                <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Getting...</>
              ) : (
                <><MapPin className="w-4 h-4 mr-2" /> Set Lokasi Saat Ini</>
              )}
            </Button>
          </div>

          <div>
            <Label className="text-white">Radius Kantor (meter)</Label>
            <Input
              type="number"
              value={settings.office_radius_meters}
              onChange={(e) => setSettings({
                ...settings,
                office_radius_meters: Number(e.target.value)
              })}
              className="mt-2 bg-gray-800 border-gray-700 text-white"
            />
            <p className="text-xs text-gray-400 mt-1">
              Karyawan harus dalam radius {settings.office_radius_meters}m dari kantor untuk absen
            </p>
          </div>

          <div className="flex items-center justify-between">
            <div>
              <Label className="text-white">Wajib Absen dari Kantor</Label>
              <p className="text-xs text-gray-400">Validasi lokasi saat absen</p>
            </div>
            <Switch
              checked={settings.require_office_location}
              onCheckedChange={(checked) => setSettings({
                ...settings,
                require_office_location: checked
              })}
            />
          </div>
        </CardContent>
      </Card>

      {/* Working Hours / Shift System Selection */}
      <Card className="bg-gray-900 border-gray-700">
        <CardHeader>
          <CardTitle className="text-white flex items-center gap-2">
            <Clock className="w-5 h-5" />
            Sistem Jam Kerja
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          {/* Toggle Multi-Shift */}
          <div className="flex items-center justify-between p-4 bg-gray-800 rounded-lg">
            <div>
              <Label className="text-white text-base">Gunakan Sistem Multi-Shift</Label>
              <p className="text-xs text-gray-400 mt-1">
                Aktifkan jika perusahaan memiliki beberapa shift kerja (Pagi, Siang, Malam, dll)
              </p>
            </div>
            <Switch
              checked={settings.use_multiple_shifts || false}
              onCheckedChange={(checked) => setSettings({
                ...settings,
                use_multiple_shifts: checked
              })}
            />
          </div>

          {/* Single Working Hours (if multi-shift is OFF) */}
          {!settings.use_multiple_shifts && (
            <>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label className="text-white">Jam Mulai</Label>
                  <Input
                    type="time"
                    value={settings.working_hours.start_time}
                    onChange={(e) => setSettings({
                      ...settings,
                      working_hours: {
                        ...settings.working_hours,
                        start_time: e.target.value
                      }
                    })}
                    className="mt-2 bg-gray-800 border-gray-700 text-white"
                  />
                </div>
                <div>
                  <Label className="text-white">Jam Selesai</Label>
                  <Input
                    type="time"
                    value={settings.working_hours.end_time}
                    onChange={(e) => setSettings({
                      ...settings,
                      working_hours: {
                        ...settings.working_hours,
                        end_time: e.target.value
                      }
                    })}
                    className="mt-2 bg-gray-800 border-gray-700 text-white"
                  />
                </div>
              </div>

              <div>
                <Label className="text-white">Durasi Istirahat (menit)</Label>
                <Input
                  type="number"
                  value={settings.working_hours.break_duration_minutes}
                  onChange={(e) => setSettings({
                    ...settings,
                    working_hours: {
                      ...settings.working_hours,
                      break_duration_minutes: Number(e.target.value)
                    }
                  })}
                  className="mt-2 bg-gray-800 border-gray-700 text-white"
                />
              </div>
            </>
          )}

          <div>
            <Label className="text-white">Toleransi Terlambat (menit)</Label>
            <Input
              type="number"
              value={settings.late_tolerance_minutes}
              onChange={(e) => setSettings({
                ...settings,
                late_tolerance_minutes: Number(e.target.value)
              })}
              className="mt-2 bg-gray-800 border-gray-700 text-white"
            />
            <p className="text-xs text-gray-400 mt-1">
              Karyawan dianggap terlambat jika clock in lebih dari {settings.late_tolerance_minutes} menit
            </p>
          </div>
        </CardContent>
      </Card>

      {/* Overtime Settings */}
      <Card className="bg-gray-900 border-gray-700">
        <CardHeader>
          <CardTitle className="text-white flex items-center gap-2">
            <SettingsIcon className="w-5 h-5" />
            Pengaturan Lembur
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between">
            <div>
              <Label className="text-white">Aktifkan Lembur</Label>
              <p className="text-xs text-gray-400">Hitung jam lembur otomatis</p>
            </div>
            <Switch
              checked={settings.overtime_settings.enabled}
              onCheckedChange={(checked) => setSettings({
                ...settings,
                overtime_settings: {
                  ...settings.overtime_settings,
                  enabled: checked
                }
              })}
            />
          </div>

          {settings.overtime_settings.enabled && (
            <>
              <div>
                <Label className="text-white">Lembur Dimulai Setelah (jam kerja)</Label>
                <Input
                  type="number"
                  value={settings.overtime_settings.start_after_hours}
                  onChange={(e) => setSettings({
                    ...settings,
                    overtime_settings: {
                      ...settings.overtime_settings,
                      start_after_hours: Number(e.target.value)
                    }
                  })}
                  className="mt-2 bg-gray-800 border-gray-700 text-white"
                />
                <p className="text-xs text-gray-400 mt-1">
                  Lembur dihitung setelah {settings.overtime_settings.start_after_hours} jam kerja
                </p>
              </div>

              <div>
                <Label className="text-white">Maksimal Lembur per Hari (jam)</Label>
                <Input
                  type="number"
                  value={settings.overtime_settings.max_overtime_hours_per_day}
                  onChange={(e) => setSettings({
                    ...settings,
                    overtime_settings: {
                      ...settings.overtime_settings,
                      max_overtime_hours_per_day: Number(e.target.value)
                    }
                  })}
                  className="mt-2 bg-gray-800 border-gray-700 text-white"
                />
              </div>
            </>
          )}
        </CardContent>
      </Card>

      {/* Shift Management (only show if multi-shift is enabled) */}
      {settings.use_multiple_shifts && (
        <Card className="bg-gray-900 border-gray-700">
          <CardHeader>
            <div className="flex justify-between items-center">
              <CardTitle className="text-white flex items-center gap-2">
                <Clock className="w-5 h-5" />
                Pengaturan Shift Kerja
              </CardTitle>
              <Button
                onClick={() => {
                  setEditingShift({
                    id: `shift_${Date.now()}`,
                    name: '',
                    start_time: '07:00',
                    end_time: '15:00',
                    break_duration_minutes: 60,
                    is_active: true
                  });
                  setShowShiftDialog(true);
                }}
                className="bg-blue-600 hover:bg-blue-700"
                size="sm"
              >
                <Plus className="w-4 h-4 mr-2" />
                Tambah Shift
              </Button>
            </div>
          </CardHeader>
          <CardContent className="space-y-3">
            {settings.shifts && settings.shifts.length > 0 ? (
              settings.shifts.map((shift, index) => (
              <div key={shift.id} className="flex items-center justify-between p-3 bg-gray-800 rounded-lg border border-gray-700">
                <div className="flex-1">
                  <div className="flex items-center gap-2">
                    <p className="text-white font-semibold">{shift.name}</p>
                    <Badge className={shift.is_active ? 'bg-green-600' : 'bg-gray-600'}>
                      {shift.is_active ? 'Aktif' : 'Non-aktif'}
                    </Badge>
                  </div>
                  <p className="text-sm text-gray-400 mt-1">
                    {shift.start_time} - {shift.end_time} ΓÇó Istirahat: {shift.break_duration_minutes} menit
                  </p>
                </div>
                <div className="flex gap-2">
                  <Button
                    size="sm"
                    variant="ghost"
                    onClick={() => {
                      setEditingShift(shift);
                      setShowShiftDialog(true);
                    }}
                    className="text-blue-400 hover:text-blue-300"
                  >
                    <Edit2 className="w-4 h-4" />
                  </Button>
                  <Button
                    size="sm"
                    variant="ghost"
                    onClick={async () => {
                      if (confirm(`Hapus shift "${shift.name}"?`)) {
                        const updatedSettings = {
                          ...settings,
                          shifts: settings.shifts.filter(s => s.id !== shift.id)
                        };
                        setSettings(updatedSettings);
                        
                        // Auto-save deletion
                        try {
                          setIsSaving(true);
                          if (updatedSettings.id) {
                            await base44.entities.CompanyAttendanceSettings.update(updatedSettings.id, updatedSettings);
                          } else {
                            const created = await base44.entities.CompanyAttendanceSettings.create(updatedSettings);
                            setSettings({ ...updatedSettings, id: created.id });
                          }
                          
                          // Broadcast
                          try {
                            const channel = new BroadcastChannel('snishop_attendance_settings_updates');
                            channel.postMessage({
                              type: 'SETTINGS_UPDATED',
                              companyId: company.id,
                              shifts: updatedSettings.shifts || [],
                              timestamp: Date.now()
                            });
                            channel.close();
                          } catch (e) {}
                          
                          toast.success('Γ£à Shift berhasil dihapus!');
                          // Γ¥î REMOVED: await loadSettings() - no need to reload
                        } catch (error) {
                          console.error('Error deleting shift:', error);
                          toast.error('Gagal menghapus shift');
                        } finally {
                          setIsSaving(false);
                        }
                      }
                    }}
                    className="text-red-400 hover:text-red-300"
                  >
                    <Trash2 className="w-4 h-4" />
                  </Button>
                </div>
              </div>
            ))
            ) : (
              <p className="text-gray-400 text-sm">Belum ada shift. Klik "Tambah Shift" untuk membuat shift baru.</p>
            )}
          </CardContent>
        </Card>
      )}

      {/* Additional Settings */}
      <Card className="bg-gray-900 border-gray-700">
        <CardHeader>
          <CardTitle className="text-white">Pengaturan Tambahan</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between">
            <div>
              <Label className="text-white">Wajib Foto Selfie</Label>
              <p className="text-xs text-gray-400">Karyawan harus foto saat absen</p>
            </div>
            <Switch
              checked={settings.require_photo}
              onCheckedChange={(checked) => setSettings({
                ...settings,
                require_photo: checked
              })}
            />
          </div>

          <div className="flex items-center justify-between">
            <div>
              <Label className="text-white">Auto Clock Out</Label>
              <p className="text-xs text-gray-400">Otomatis clock out jika lupa</p>
            </div>
            <Switch
              checked={settings.auto_clock_out_enabled}
              onCheckedChange={(checked) => setSettings({
                ...settings,
                auto_clock_out_enabled: checked
              })}
            />
          </div>

          {settings.auto_clock_out_enabled && (
            <div>
              <Label className="text-white">Jam Auto Clock Out</Label>
              <Input
                type="time"
                value={settings.auto_clock_out_time}
                onChange={(e) => setSettings({
                  ...settings,
                  auto_clock_out_time: e.target.value
                })}
                className="mt-2 bg-gray-800 border-gray-700 text-white"
              />
            </div>
          )}
        </CardContent>
      </Card>

      {/* Save Button */}
      <div className="flex justify-end">
        <Button
          onClick={handleSave}
          disabled={isSaving}
          className="bg-green-600 hover:bg-green-700"
        >
          {isSaving ? (
            <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Menyimpan...</>
          ) : (
            <><Save className="w-4 h-4 mr-2" /> Simpan Pengaturan</>
          )}
        </Button>
      </div>

      {/* Shift Dialog */}
      {showShiftDialog && (
        <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
          <Card className="bg-gray-900 border-gray-700 max-w-md w-full">
            <CardHeader>
              <CardTitle className="text-white">{editingShift?.name ? 'Edit Shift' : 'Tambah Shift Baru'}</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div>
                <Label className="text-white">Nama Shift</Label>
                <Input
                  value={editingShift?.name || ''}
                  onChange={(e) => setEditingShift({ ...editingShift, name: e.target.value })}
                  placeholder="Contoh: Shift Pagi, Shift Siang"
                  className="mt-2 bg-gray-800 border-gray-700 text-white"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label className="text-white">Jam Mulai</Label>
                  <Input
                    type="time"
                    value={editingShift?.start_time || '07:00'}
                    onChange={(e) => setEditingShift({ ...editingShift, start_time: e.target.value })}
                    className="mt-2 bg-gray-800 border-gray-700 text-white"
                  />
                </div>
                <div>
                  <Label className="text-white">Jam Selesai</Label>
                  <Input
                    type="time"
                    value={editingShift?.end_time || '15:00'}
                    onChange={(e) => setEditingShift({ ...editingShift, end_time: e.target.value })}
                    className="mt-2 bg-gray-800 border-gray-700 text-white"
                  />
                </div>
              </div>
              <div>
                <Label className="text-white">Durasi Istirahat (menit)</Label>
                <Input
                  type="number"
                  value={editingShift?.break_duration_minutes || 60}
                  onChange={(e) => setEditingShift({ ...editingShift, break_duration_minutes: Number(e.target.value) })}
                  className="mt-2 bg-gray-800 border-gray-700 text-white"
                />
              </div>
              <div className="flex items-center justify-between">
                <Label className="text-white">Status Aktif</Label>
                <Switch
                  checked={editingShift?.is_active !== false}
                  onCheckedChange={(checked) => setEditingShift({ ...editingShift, is_active: checked })}
                />
              </div>
              <div className="flex gap-2 justify-end">
                <Button
                  variant="outline"
                  onClick={() => {
                    setShowShiftDialog(false);
                    setEditingShift(null);
                  }}
                  className="border-gray-600 text-white"
                >
                  Batal
                </Button>
                <Button
                  onClick={async () => {
                    if (!editingShift?.name) {
                      toast.error('Nama shift wajib diisi');
                      return;
                    }
                    
                    try {
                      setIsSaving(true);
                      console.log('≡ƒÆ╛ SAVING SHIFT:', editingShift);
                      console.log('≡ƒôª Current settings:', settings);
                      
                      // Prepare shifts array
                      const currentShifts = settings.shifts || [];
                      const existingIndex = currentShifts.findIndex(s => s.id === editingShift.id);
                      
                      let updatedShifts;
                      if (existingIndex >= 0) {
                        updatedShifts = [...currentShifts];
                        updatedShifts[existingIndex] = editingShift;
                        console.log('≡ƒöä Updating existing shift at index', existingIndex);
                      } else {
                        updatedShifts = [...currentShifts, editingShift];
                        console.log('Γ₧ò Adding new shift');
                      }
                      
                      console.log('≡ƒôï Updated shifts array:', updatedShifts);
                      
                      // Prepare full settings object
                      const settingsToSave = {
                        company_id: company.id,
                        office_location: settings.office_location,
                        office_radius_meters: settings.office_radius_meters || 100,
                        require_office_location: settings.require_office_location || false,
                        use_multiple_shifts: settings.use_multiple_shifts || false,
                        working_hours: settings.working_hours || {
                          start_time: '09:00',
                          end_time: '17:00',
                          break_duration_minutes: 60
                        },
                        shifts: updatedShifts,
                        overtime_settings: settings.overtime_settings || {
                          enabled: true,
                          start_after_hours: 8,
                          max_overtime_hours_per_day: 4
                        },
                        late_tolerance_minutes: settings.late_tolerance_minutes || 15,
                        working_days: settings.working_days || [1, 2, 3, 4, 5],
                        auto_clock_out_enabled: settings.auto_clock_out_enabled || false,
                        auto_clock_out_time: settings.auto_clock_out_time || '18:00',
                        require_photo: settings.require_photo !== false,
                        require_notes: settings.require_notes || false
                      };
                      
                      let savedData;
                      if (settings.id) {
                        console.log('≡ƒöä Updating settings with ID:', settings.id);
                        savedData = await base44.entities.CompanyAttendanceSettings.update(settings.id, settingsToSave);
                        console.log('Γ£à Update response:', savedData);
                      } else {
                        console.log('Γ₧ò Creating new settings...');
                        savedData = await base44.entities.CompanyAttendanceSettings.create(settingsToSave);
                        console.log('Γ£à Create response:', savedData);
                      }
                      
                      // Γ£à Update local state immediately (no reload needed)
                      const finalSettings = { 
                        ...settingsToSave, 
                        id: savedData.id || settings.id 
                      };
                      setSettings(finalSettings);
                      console.log('Γ£à Local state updated:', finalSettings);
                      
                      // Close dialog FIRST
                      setShowShiftDialog(false);
                      setEditingShift(null);
                      
                      // Broadcast to all pages
                      try {
                        const channel = new BroadcastChannel('snishop_attendance_settings_updates');
                        channel.postMessage({
                          type: 'SETTINGS_UPDATED',
                          companyId: company.id,
                          shifts: updatedShifts,
                          timestamp: Date.now()
                        });
                        channel.close();
                        console.log('≡ƒôí Broadcast sent successfully');
                      } catch (e) {
                        console.warn('Broadcast error:', e);
                      }
                      
                      toast.success('Γ£à Shift berhasil disimpan!', {
                        description: `Total: ${updatedShifts.length} shift aktif`
                      });
                      
                    } catch (error) {
                      console.error('Γ¥î ERROR saving shift:', error);
                      toast.error(`Gagal menyimpan: ${error.message}`);
                    } finally {
                      setIsSaving(false);
                    }
                  }}
                  className="bg-blue-600 hover:bg-blue-700"
                  disabled={isSaving}
                >
                  {isSaving ? (
                    <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Menyimpan...</>
                  ) : (
                    '≡ƒÆ╛ Simpan Shift'
                  )}
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { base44 } from '@/api/base44Client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Edit, Trash2, Plus, X, Save, Loader2, Tag } from 'lucide-react';
import { toast } from 'sonner';

export default function CategoryManager({ categories, companyId, onCategoriesUpdated }) {
  const [editingCategory, setEditingCategory] = useState(null);
  const [newCategory, setNewCategory] = useState({ name: '', icon: '≡ƒÅ╖∩╕Å', color: '#3b82f6' });
  const [showAddForm, setShowAddForm] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isDeleting, setIsDeleting] = useState(null);

  const handleCreateCategory = async () => {
    if (!newCategory.name.trim()) {
      toast.error('Nama kategori wajib diisi');
      return;
    }

    try {
      setIsSaving(true);
      await base44.entities.CompanyPOSCategory.create({
        company_id: companyId,
        name: newCategory.name.trim(),
        icon: newCategory.icon || '≡ƒÅ╖∩╕Å',
        color: newCategory.color || '#3b82f6'
      });

      toast.success('Γ£à Kategori berhasil ditambahkan!');
      setNewCategory({ name: '', icon: '≡ƒÅ╖∩╕Å', color: '#3b82f6' });
      setShowAddForm(false);

      // Γ£à BROADCAST
      try {
        const channel = new BroadcastChannel('snishop_product_updates');
        channel.postMessage({
          type: 'CATEGORY_CREATED',
          companyId: companyId,
          timestamp: Date.now()
        });
        channel.close();
      } catch (e) {}

      if (onCategoriesUpdated) onCategoriesUpdated();
    } catch (error) {
      console.error('Error creating category:', error);
      toast.error('Gagal membuat kategori');
    } finally {
      setIsSaving(false);
    }
  };

  const handleUpdateCategory = async (categoryId) => {
    if (!editingCategory?.name.trim()) {
      toast.error('Nama kategori wajib diisi');
      return;
    }

    const oldCategory = categories.find(c => c.id === categoryId);
    const oldName = oldCategory?.name;
    const newName = editingCategory.name.trim();

    try {
      setIsSaving(true);
      
      // Γ£à SYNC: Jika nama berubah, update produk yang menggunakan kategori ini
      if (oldName && oldName !== newName) {
        console.log(`≡ƒöä Syncing category rename: "${oldName}" -> "${newName}"`);
        try {
          const productsToUpdate = await base44.entities.CompanyPOSProduct.filter({
            company_id: companyId,
            category: oldName
          });

          if (productsToUpdate && productsToUpdate.length > 0) {
            toast.info(`≡ƒöä Mengupdate ${productsToUpdate.length} produk ke kategori baru...`);
            // Update products sequentially or in small batches to avoid rate limits
            for (const product of productsToUpdate) {
              await base44.entities.CompanyPOSProduct.update(product.id, {
                category: newName
              });
            }
            console.log(`Γ£à Successfully synced ${productsToUpdate.length} products`);
          }
        } catch (syncError) {
          console.error('Γ¥î Sync Rename Failed:', syncError);
          // Kita lanjut saja ke update kategori, tapi beri peringatan
          toast.warning('ΓÜá∩╕Å Kategori diupdate, tapi beberapa produk mungkin gagal sinkronisasi.');
        }
      }

      await base44.entities.CompanyPOSCategory.update(categoryId, {
        name: newName,
        icon: editingCategory.icon || '≡ƒÅ╖∩╕Å',
        color: editingCategory.color || '#3b82f6'
      });

      toast.success('Γ£à Kategori berhasil diupdate!');
      setEditingCategory(null);

      // Γ£à BROADCAST
      try {
        const channel = new BroadcastChannel('snishop_product_updates');
        channel.postMessage({
          type: 'CATEGORY_UPDATED',
          companyId: companyId,
          timestamp: Date.now()
        });
        channel.close();
      } catch (e) {}

      if (onCategoriesUpdated) onCategoriesUpdated();
    } catch (error) {
      console.error('Error updating category:', error);
      toast.error('Gagal mengupdate kategori');
    } finally {
      setIsSaving(false);
    }
  };

  const handleDeleteCategory = async (category) => {
    // Γ£à CHECK: Apakah kategori sedang digunakan produk?
    try {
      setIsDeleting(category.id);
      const productsUsingCategory = await base44.entities.CompanyPOSProduct.filter({
        company_id: companyId,
        category: category.name
      });

      if (productsUsingCategory && productsUsingCategory.length > 0) {
        const proceed = confirm(`ΓÜá∩╕Å Kategori "${category.name}" masih digunakan oleh ${productsUsingCategory.length} produk.\n\nJika dihapus, produk tersebut akan menjadi "Tanpa Kategori".\n\nTetap hapus kategori ini?`);
        if (!proceed) {
          setIsDeleting(null);
          return;
        }
      } else {
        if (!confirm(`Yakin ingin menghapus kategori "${category.name}"?`)) {
          setIsDeleting(null);
          return;
        }
      }
    } catch (error) {
      console.error('Error checking category usage:', error);
      // Jika error saat check, tetap tanya user untuk hapus sebagai fallback
      if (!confirm(`Gagal memeriksa penggunaan produk. Yakin ingin mencoba menghapus kategori "${category.name}"?`)) {
        setIsDeleting(null);
        return;
      }
    }

    try {
      await base44.entities.CompanyPOSCategory.delete(category.id);
      toast.success('Γ£à Kategori berhasil dihapus!');

      // Γ£à BROADCAST
      try {
        const channel = new BroadcastChannel('snishop_product_updates');
        channel.postMessage({
          type: 'CATEGORY_DELETED',
          companyId: companyId,
          timestamp: Date.now()
        });
        channel.close();
      } catch (e) {}

      if (onCategoriesUpdated) onCategoriesUpdated();
    } catch (error) {
      console.error('Error deleting category:', error);
      toast.error('Gagal menghapus kategori: ' + (error.message || 'Error server'));
    } finally {
      setIsDeleting(null);
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold text-gray-900 dark:text-white flex items-center gap-2">
          <Tag className="w-5 h-5 text-blue-600" />
          Kategori Produk
        </h3>
        <Button
          onClick={() => setShowAddForm(!showAddForm)}
          className="bg-blue-600 hover:bg-blue-700"
          size="sm"
        >
          <Plus className="w-4 h-4 mr-2" />
          Tambah Kategori
        </Button>
      </div>

      {/* Add Form */}
      {showAddForm && (
        <Card className="bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-700">
          <CardContent className="p-4 space-y-3">
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
              <div className="sm:col-span-2">
                <Label className="text-xs text-gray-700 dark:text-gray-300">Nama Kategori *</Label>
                <Input
                  value={newCategory.name}
                  onChange={(e) => setNewCategory({ ...newCategory, name: e.target.value })}
                  placeholder="Contoh: Makanan, Minuman, Jasa Spa..."
                  className="bg-white dark:bg-gray-800 border-gray-300 dark:border-gray-700 mt-1"
                />
              </div>
              <div>
                <Label className="text-xs text-gray-700 dark:text-gray-300">Icon Emoji</Label>
                <Input
                  value={newCategory.icon}
                  onChange={(e) => setNewCategory({ ...newCategory, icon: e.target.value })}
                  placeholder="≡ƒÅ╖∩╕Å"
                  className="bg-white dark:bg-gray-800 border-gray-300 dark:border-gray-700 mt-1"
                  maxLength={2}
                />
              </div>
            </div>
            <div className="flex gap-2">
              <Button
                onClick={handleCreateCategory}
                disabled={isSaving || !newCategory.name.trim()}
                className="flex-1 bg-green-600 hover:bg-green-700"
              >
                {isSaving ? (
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                ) : (
                  <Save className="w-4 h-4 mr-2" />
                )}
                Simpan
              </Button>
              <Button
                variant="outline"
                onClick={() => {
                  setShowAddForm(false);
                  setNewCategory({ name: '', icon: '≡ƒÅ╖∩╕Å', color: '#3b82f6' });
                }}
                className="border-gray-300 dark:border-gray-700"
              >
                <X className="w-4 h-4" />
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Categories List */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
        {categories?.length === 0 ? (
          <div className="col-span-full text-center py-8">
            <Tag className="w-12 h-12 text-gray-400 dark:text-gray-600 mx-auto mb-3" />
            <p className="text-gray-600 dark:text-gray-400 text-sm">Belum ada kategori</p>
            <p className="text-xs text-gray-500 dark:text-gray-500 mt-1">Klik "Tambah Kategori" untuk mulai</p>
          </div>
        ) : (
          categories.map((category) => (
            <Card
              key={category.id}
              className="bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 hover:shadow-lg transition-all"
            >
              <CardContent className="p-4">
                {editingCategory?.id === category.id ? (
                  <div className="space-y-3">
                    <div>
                      <Label className="text-xs text-gray-700 dark:text-gray-300">Nama</Label>
                      <Input
                        value={editingCategory.name}
                        onChange={(e) => setEditingCategory({ ...editingCategory, name: e.target.value })}
                        className="bg-gray-100 dark:bg-gray-900 border-gray-300 dark:border-gray-600 mt-1"
                      />
                    </div>
                    <div>
                      <Label className="text-xs text-gray-700 dark:text-gray-300">Icon</Label>
                      <Input
                        value={editingCategory.icon}
                        onChange={(e) => setEditingCategory({ ...editingCategory, icon: e.target.value })}
                        className="bg-gray-100 dark:bg-gray-900 border-gray-300 dark:border-gray-600 mt-1"
                        maxLength={2}
                      />
                    </div>
                    <div className="flex gap-2">
                      <Button
                        size="sm"
                        onClick={() => handleUpdateCategory(category.id)}
                        disabled={isSaving}
                        className="flex-1 bg-green-600 hover:bg-green-700"
                      >
                        {isSaving ? <Loader2 className="w-3 h-3 animate-spin" /> : <Save className="w-3 h-3 mr-1" />}
                        Simpan
                      </Button>
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => setEditingCategory(null)}
                        className="border-gray-300 dark:border-gray-700"
                      >
                        <X className="w-3 h-3" />
                      </Button>
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="flex items-center justify-between mb-3">
                      <div className="flex items-center gap-2">
                        <span className="text-2xl">{category.icon || '≡ƒÅ╖∩╕Å'}</span>
                        <h4 className="font-semibold text-gray-900 dark:text-white">{category.name}</h4>
                      </div>
                      <Badge
                        style={{ backgroundColor: category.color || '#3b82f6' }}
                        className="text-white text-xs"
                      >
                        Aktif
                      </Badge>
                    </div>
                    <div className="flex gap-2">
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => setEditingCategory({ ...category })}
                        className="flex-1 border-gray-300 dark:border-gray-700"
                      >
                        <Edit className="w-3 h-3 mr-1" />
                        Edit
                      </Button>
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => handleDeleteCategory(category)}
                        disabled={isDeleting === category.id}
                        className="border-red-300 dark:border-red-700 text-red-600 dark:text-red-400 hover:bg-red-100 dark:hover:bg-red-900/20"
                      >
                        {isDeleting === category.id ? (
                          <Loader2 className="w-3 h-3 animate-spin" />
                        ) : (
                          <Trash2 className="w-3 h-3" />
                        )}
                      </Button>
                    </div>
                  </>
                )}
              </CardContent>
            </Card>
          ))
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import {
  Download,
  Database,
  Shield,
  CheckCircle,
  Loader2,
  FileJson,
  HardDrive,
  Calendar,
  RefreshCw
} from 'lucide-react';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';

export default function CompanyBackupManager({ company, currentUser }) {
  const [backupHistory, setBackupHistory] = useState([]);
  const [isLoading, setIsLoading] = useState(false); // Γ£à Changed to false - no auto-load
  const [isExporting, setIsExporting] = useState(false);
  const [showConfirmDialog, setShowConfirmDialog] = useState(false);
  const [lastBackupDate, setLastBackupDate] = useState(null);

  // Γ£à MANUAL LOAD ONLY - No auto-load on mount
  const loadBackupHistory = async () => {
    if (!company) return;

    try {
      setIsLoading(true);
      const history = await base44.entities.CompanyBackup.filter({
        company_id: company.id
      }, '-backup_date', 10);

      setBackupHistory(history || []);

      if (history && history.length > 0) {
        setLastBackupDate(new Date(history[0].backup_date));
      }
    } catch (error) {
      console.error('Error loading backup history:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const exportCompanyData = async (createBackupRecord = true) => {
    if (!company) return;

    setIsExporting(true);

    try {
      console.log('≡ƒôª Starting comprehensive company backup...');

      // Γ£à FETCH ALL COMPANY DATA - COMPREHENSIVE
      const [
        members,
        tasks,
        notes,
        workspaces,
        posTransactions,
        posProducts,
        posCategories,
        customers,
        membershipLevels,
        employees,
        attendance,
        leaves,
        payrolls,
        projects,
        assets,
        inventory,
        locations,
        financeRecords,
        invoices,
        appointments,
        goals,
        kpis,
        documents,
        teamChats,
        chatChannels
      ] = await Promise.all([
        base44.entities.CompanyMember.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Task.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Note.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Workspace.filter({ company_id: company.id }).catch(() => []),
        base44.entities.CompanyPOSTransaction.filter({ company_id: company.id }).catch(() => []),
        base44.entities.CompanyPOSProduct.filter({ company_id: company.id }).catch(() => []),
        base44.entities.CompanyPOSCategory.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Customer.filter({ company_id: company.id }).catch(() => []),
        base44.entities.CustomerMembership.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Employee.filter({ company_id: company.id }).catch(() => []),
        base44.entities.CompanyAttendance.filter({ company_id: company.id }).catch(() => []),
        base44.entities.CompanyLeave.filter({ company_id: company.id }).catch(() => []),
        base44.entities.CompanyPayroll.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Project.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Asset.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Inventory.filter({ company_id: company.id }).catch(() => []),
        base44.entities.WarehouseLocation.filter({ company_id: company.id }).catch(() => []),
        base44.entities.FinancialRecord.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Invoice.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Appointment.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Goal.filter({ company_id: company.id }).catch(() => []),
        base44.entities.CompanyKPI.filter({ company_id: company.id }).catch(() => []),
        base44.entities.Document.filter({ company_id: company.id }).catch(() => []),
        base44.entities.TeamChat.filter({ company_id: company.id }).catch(() => []),
        base44.entities.ChatChannel.filter({ company_id: company.id }).catch(() => [])
      ]);

      console.log('Γ£à All company data fetched');

      // Γ£à CREATE COMPREHENSIVE BACKUP OBJECT
      const backupData = {
        backup_metadata: {
          company_id: company.id,
          company_name: company.name,
          backup_date: new Date().toISOString(),
          created_by: currentUser.email,
          created_by_name: currentUser.full_name || currentUser.email,
          version: '1.0',
          platform: 'SNISHOP - Smart Business Operating System'
        },
        company_info: company,
        data: {
          members: members || [],
          tasks: tasks || [],
          notes: notes || [],
          workspaces: workspaces || [],
          pos: {
            transactions: posTransactions || [],
            products: posProducts || [],
            categories: posCategories || []
          },
          crm: {
            customers: customers || [],
            membership_levels: membershipLevels || []
          },
          hr: {
            employees: employees || [],
            attendance: attendance || [],
            leaves: leaves || [],
            payrolls: payrolls || []
          },
          projects: projects || [],
          assets: assets || [],
          inventory: {
            items: inventory || [],
            locations: locations || []
          },
          finance: financeRecords || [],
          invoices: invoices || [],
          appointments: appointments || [],
          goals: goals || [],
          kpis: kpis || [],
          documents: documents || [],
          communications: {
            chats: teamChats || [],
            channels: chatChannels || []
          }
        },
        summary: {
          total_members: members?.length || 0,
          total_tasks: tasks?.length || 0,
          total_notes: notes?.length || 0,
          total_transactions: posTransactions?.length || 0,
          total_inventory: inventory?.length || 0,
          total_customers: customers?.length || 0,
          total_employees: employees?.length || 0,
          total_projects: projects?.length || 0,
          total_assets: assets?.length || 0
        }
      };

      // Γ£à Calculate file size
      const jsonString = JSON.stringify(backupData, null, 2);
      const sizeInBytes = new Blob([jsonString]).size;
      const sizeInMB = (sizeInBytes / (1024 * 1024)).toFixed(2);

      backupData.summary.total_size_mb = parseFloat(sizeInMB);

      console.log('≡ƒôè Backup size:', sizeInMB, 'MB');
      console.log('≡ƒôè Summary:', backupData.summary);

      // Γ£à DOWNLOAD BACKUP FILE
      const blob = new Blob([jsonString], { type: 'application/json' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `BACKUP_${company.name.replace(/\s/g, '_')}_${format(new Date(), 'yyyyMMdd_HHmmss')}.json`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      a.remove();

      toast.success('Γ£à Backup berhasil diunduh!', {
        description: `File size: ${sizeInMB} MB | ${backupData.summary.total_members + backupData.summary.total_tasks + backupData.summary.total_notes} records`,
        duration: 5000
      });

      // Γ£à CREATE BACKUP RECORD (if requested)
      if (createBackupRecord) {
        await base44.entities.CompanyBackup.create({
          company_id: company.id,
          company_name: company.name,
          backup_type: 'manual',
          backup_scope: 'full',
          backup_date: new Date().toISOString(),
          created_by_email: currentUser.email,
          created_by_name: currentUser.full_name || currentUser.email,
          data_summary: backupData.summary,
          file_size_mb: parseFloat(sizeInMB),
          status: 'completed',
          notes: 'Manual backup oleh owner'
        });

        console.log('Γ£à Backup record created');
        
        // Γ£à CLEAR OLD REMINDER - Allow new reminder after new backup
        const reminderKeys = Object.keys(localStorage).filter(key => 
          key.startsWith(`backup_reminder_shown_${company.id}`)
        );
        reminderKeys.forEach(key => localStorage.removeItem(key));
        
        // Reload history
        loadBackupHistory();
      }

    } catch (error) {
      console.error('Error exporting company data:', error);
      toast.error('Gagal membuat backup', {
        description: error.message || 'Terjadi kesalahan saat export data',
        duration: 5000
      });
    } finally {
      setIsExporting(false);
      setShowConfirmDialog(false);
    }
  };

  const shouldShowBackupReminder = () => {
    if (!lastBackupDate) return true;
    const hoursSinceLastBackup = (new Date() - lastBackupDate) / (1000 * 60 * 60);
    return hoursSinceLastBackup >= 24;
  };

  return (
    <div className="space-y-6">
      {/* Γ£à BACKUP INFO CARD */}
      <Card className="bg-gradient-to-br from-green-900/30 to-emerald-900/30 border-2 border-green-600">
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-white">
            <Shield className="w-6 h-6 text-green-400" />
            Backup & Keamanan Data Perusahaan
          </CardTitle>
          <CardDescription className="text-gray-300">
            {company.name} - Backup manual untuk keamanan data
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {/* Γ£à DATA SAFETY GUARANTEE */}
          <div className="p-4 bg-green-900/40 border-2 border-green-500 rounded-lg">
            <div className="flex items-start gap-3">
              <CheckCircle className="w-6 h-6 text-green-400 flex-shrink-0 mt-1" />
              <div className="flex-1">
                <p className="text-base text-green-300 font-bold mb-2">
                  ≡ƒöÆ JAMINAN 100% DATA AMAN
                </p>
                <div className="text-sm text-gray-200 space-y-1">
                  <p>Γ£à <strong>Semua data perusahaan AMAN</strong> - tidak akan dihapus</p>
                  <p>Γ£à Members, Tasks, Notes, POS, Finance, HR, Inventory - <strong>semua tersimpan</strong></p>
                  <p>Γ£à Saat membership expired: <strong>Hanya lock akses fitur</strong>, data tetap ada</p>
                  <p>Γ£à Setelah perpanjang: <strong>Langsung akses kembali</strong> semua data</p>
                  <p>≡ƒÆí <strong>Backup manual tersedia</strong> untuk keamanan ekstra kapan saja</p>
                </div>
              </div>
            </div>
          </div>

          {/* Γ£à BACKUP ACTIONS - Load history on demand */}
          <div className="flex flex-col sm:flex-row gap-3">
            <Button
              onClick={() => setShowConfirmDialog(true)}
              disabled={isExporting}
              className="flex-1 bg-green-600 hover:bg-green-700 text-white font-bold"
            >
              {isExporting ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  Memproses Backup...
                </>
              ) : (
                <>
                  <Download className="w-4 h-4 mr-2" />
                  Backup Sekarang (Full Export)
                </>
              )}
            </Button>

            <Button
              onClick={loadBackupHistory}
              variant="outline"
              className="border-gray-600 text-gray-300"
              disabled={isLoading}
            >
              {isLoading ? (
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
              ) : (
                <RefreshCw className="w-4 h-4 mr-2" />
              )}
              Lihat Riwayat
            </Button>
          </div>

          {/* Γ£à INFO: Manual backup recommendation */}
          <div className="p-3 bg-blue-900/30 border border-blue-600 rounded-lg">
            <div className="flex items-start gap-2 text-xs text-blue-300">
              <Database className="w-4 h-4 flex-shrink-0 mt-0.5" />
              <div>
                <p className="font-bold mb-1">≡ƒÆí Rekomendasi Backup</p>
                <p className="opacity-90">
                  Backup data perusahaan secara berkala (minimal setiap minggu) untuk keamanan ekstra.
                  Data tetap aman di sistem, backup adalah proteksi tambahan.
                </p>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Γ£à BACKUP HISTORY - Only show if loaded */}
      {backupHistory.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Calendar className="w-5 h-5 text-blue-400" />
              Riwayat Backup
            </CardTitle>
            <CardDescription>
              10 backup terakhir perusahaan {company.name}
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {backupHistory.map((backup) => (
                <div
                  key={backup.id}
                  className="p-4 bg-gray-800 border border-gray-700 rounded-lg hover:bg-gray-700/50 transition-all"
                >
                  <div className="flex items-start justify-between gap-4">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-2">
                        <FileJson className="w-4 h-4 text-green-400" />
                        <p className="font-semibold text-white text-sm">
                          {format(new Date(backup.backup_date), 'dd MMMM yyyy HH:mm', { locale: id })}
                        </p>
                        <Badge className="text-xs bg-blue-600">
                          Manual
                        </Badge>
                      </div>

                      <div className="flex flex-wrap gap-2 text-xs text-gray-400">
                        <span>≡ƒæÑ {backup.data_summary?.total_members || 0} members</span>
                        <span>≡ƒô¥ {backup.data_summary?.total_tasks || 0} tasks</span>
                        <span>≡ƒùÆ∩╕Å {backup.data_summary?.total_notes || 0} notes</span>
                        <span>≡ƒÆ│ {backup.data_summary?.total_transactions || 0} trx</span>
                        <span>≡ƒôª {backup.data_summary?.total_inventory || 0} items</span>
                      </div>

                      {backup.data_summary?.total_size_mb && (
                        <p className="text-xs text-gray-500 mt-1">
                          <HardDrive className="w-3 h-3 inline mr-1" />
                          Size: {backup.data_summary.total_size_mb} MB
                        </p>
                      )}

                      <p className="text-xs text-gray-500 mt-1">
                        Oleh: {backup.created_by_name}
                      </p>
                    </div>

                    <Badge className="bg-green-600 text-white flex-shrink-0">
                      <CheckCircle className="w-3 h-3 mr-1" />
                      {backup.status || 'completed'}
                    </Badge>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Γ£à BACKUP CONFIRMATION DIALOG */}
      <Dialog open={showConfirmDialog} onOpenChange={setShowConfirmDialog}>
        <DialogContent className="bg-gray-900 text-white">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Download className="w-5 h-5 text-green-400" />
              Backup Data Perusahaan
            </DialogTitle>
            <DialogDescription className="text-gray-400">
              Backup lengkap semua data {company.name}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 py-4">
            <div className="p-4 bg-blue-900/30 border border-blue-600 rounded-lg">
              <p className="text-sm text-blue-300 font-semibold mb-2">
                ≡ƒôª Yang Akan Di-Backup:
              </p>
              <div className="grid grid-cols-2 gap-2 text-xs text-gray-300">
                <div>Γ£à Members & Permissions</div>
                <div>Γ£à Tasks & Notes</div>
                <div>Γ£à POS Transactions</div>
                <div>Γ£à Products & Inventory</div>
                <div>Γ£à Customers & CRM</div>
                <div>Γ£à HR & Payroll</div>
                <div>Γ£à Finance Records</div>
                <div>Γ£à Projects & Assets</div>
                <div>Γ£à Invoices & Appointments</div>
                <div>Γ£à Goals & KPIs</div>
                <div>Γ£à Documents</div>
                <div>Γ£à Team Communications</div>
              </div>
            </div>

            <div className="p-3 bg-green-900/30 border border-green-600 rounded-lg">
              <p className="text-xs text-green-300">
                Γ£à File akan diunduh dalam format <strong>JSON</strong> yang dapat di-import kembali kapan saja
              </p>
            </div>

            <div className="flex gap-3">
              <Button
                variant="outline"
                onClick={() => setShowConfirmDialog(false)}
                className="flex-1"
                disabled={isExporting}
              >
                Batal
              </Button>
              <Button
                onClick={() => exportCompanyData(true)}
                className="flex-1 bg-green-600 hover:bg-green-700"
                disabled={isExporting}
              >
                {isExporting ? (
                  <>
                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    Processing...
                  </>
                ) : (
                  <>
                    <Download className="w-4 h-4 mr-2" />
                    Backup & Download
                  </>
                )}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

// CompanyProductForm - existing file, no changes needed
import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { X, Loader2, Save, MapPin, Plus, Package, Scan, AlertTriangle, Eye, EyeOff } from 'lucide-react';
import { toast } from 'sonner';

import BarcodeScanner from '@/components/pos/BarcodeScanner';
import { UploadFile } from '@/api/integrations';

export default function CompanyProductForm({ product, onSave, onClose, categories, companyId, onCategoryCreated }) {
  const [formData, setFormData] = useState({
    name: '',
    sku: '',
    category: '',
    description: '',
    price: 0,
    cost: 0,
    stock: 0,
    min_stock: 5,
    unit: 'pcs',
    supplier: '',
    tax_rate: 0,
    image_url: '',
    is_active: true,
    is_unlimited_stock: false,
    ...product
  });

  const [locations, setLocations] = useState([]);
  const [locationStocks, setLocationStocks] = useState([]);
  const [isUploading, setIsUploading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isLoadingLocations, setIsLoadingLocations] = useState(true);
  const [locationLoadError, setLocationLoadError] = useState(false);

  // Γ£à SCANNER & VALIDATION STATE
  const [showScanner, setShowScanner] = useState(false);
  const [skuError, setSkuError] = useState(null);
  const [isCheckingSku, setIsCheckingSku] = useState(false);

  // Γ£à Category creation states
  const [showNewCategoryInput, setShowNewCategoryInput] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');
  const [isSavingCategory, setIsSavingCategory] = useState(false);

  useEffect(() => {
    console.log('≡ƒöº CompanyProductForm mounted with companyId:', companyId);

    if (companyId) {
      loadLocations();
    } else {
      console.warn('ΓÜá∩╕Å No companyId provided!');
      setLocations([]);
      setLocationStocks([]);
      setIsLoadingLocations(false);
      toast.error('Company ID tidak tersedia. Tutup dan buka form kembali.');
    }
  }, [companyId]);

  // Γ£à ORACLE-STYLE: Proactive Duplicate SKU Check
  const checkDuplicateSku = async (skuToCheck) => {
    if (!skuToCheck || !companyId) return;

    // Ignore if same SKU as original product (editing)
    if (product && product.sku === skuToCheck) {
      setSkuError(null);
      return;
    }

    try {
      setIsCheckingSku(true);
      const existing = await base44.entities.CompanyPOSProduct.filter({
        company_id: companyId,
        sku: skuToCheck
      });

      // Validasi ketat: Jika ada produk lain dengan SKU sama
      const duplicate = existing?.find(p => p.id !== product?.id);

      if (duplicate) {
        setSkuError(`Γ¢ö SKU "${skuToCheck}" sudah digunakan oleh produk: ${duplicate.name}`);
        toast.error(`ΓÜá∩╕Å SKU DUPLIKAT! Sudah digunakan oleh: ${duplicate.name}`);
      } else {
        setSkuError(null); // Clear error if unique
      }
    } catch (error) {
      console.error('Error checking SKU:', error);
    } finally {
      setIsCheckingSku(false);
    }
  };

  const loadLocations = async () => {
    // ... (rest of loadLocations stays same)
    const startTime = Date.now();
    console.log('≡ƒôª Starting location load for company:', companyId);

    try {
      setIsLoadingLocations(true);
      setLocationLoadError(false);

      // Γ£à FETCH LOCATIONS dengan timeout 3 detik (lebih cepat!)
      const locationsPromise = base44.entities.WarehouseLocation.filter({
        company_id: companyId,
        is_active: true
      });

      const timeoutPromise = new Promise((_, reject) =>
        setTimeout(() => reject(new Error('Timeout after 3 seconds')), 3000)
      );

      const locationsData = await Promise.race([locationsPromise, timeoutPromise]);

      const loadTime = Date.now() - startTime;
      console.log(`Γ£à Loaded ${locationsData?.length || 0} locations in ${loadTime}ms`);

      setLocations(locationsData || []);

      // Γ£à LOAD EXISTING INVENTORY if editing (with timeout)
      if (product && product.id) {
        console.log('≡ƒô¥ Loading existing inventory for product:', product.id);

        try {
          const inventoryPromise = base44.entities.Inventory.filter({
            company_id: companyId,
            product_id: product.id
          });

          const inventoryTimeoutPromise = new Promise((_, reject) =>
            setTimeout(() => reject(new Error('Inventory timeout')), 3000)
          );

          const inventoryData = await Promise.race([inventoryPromise, inventoryTimeoutPromise]);
          console.log(`Γ£à Loaded inventory: ${inventoryData?.length || 0} records`);

          const stocksByLocation = (locationsData || []).map(location => {
            const inv = inventoryData.find(i => i.location_id === location.id);
            return {
              location_id: location.id,
              location_name: location.location_name,
              quantity: inv?.quantity || 0,
              min_stock: inv?.min_stock || formData.min_stock || 5,
              unit_cost: inv?.unit_cost || formData.cost || 0,
              selling_price: inv?.selling_price || formData.price || 0
            };
          });

          setLocationStocks(stocksByLocation);
        } catch (invError) {
          console.warn('ΓÜá∩╕Å Inventory load failed, using defaults:', invError.message);
          const defaultStocks = (locationsData || []).map(location => ({
            location_id: location.id,
            location_name: location.location_name,
            quantity: 0,
            min_stock: formData.min_stock || 5,
            unit_cost: formData.cost || 0,
            selling_price: formData.price || 0
          }));
          setLocationStocks(defaultStocks);
        }
      } else {
        // Γ£à NEW PRODUCT - Initialize dengan 0
        const defaultStocks = (locationsData || []).map(location => ({
          location_id: location.id,
          location_name: location.location_name,
          quantity: 0,
          min_stock: formData.min_stock || 5,
          unit_cost: formData.cost || 0,
          selling_price: formData.price || 0
        }));

        setLocationStocks(defaultStocks);
        console.log('Γ£à Initialized default stocks for', defaultStocks.length, 'locations');
      }

    } catch (error) {
      const loadTime = Date.now() - startTime;
      console.error(`Γ¥î Location load failed after ${loadTime}ms:`, error.message);

      setLocationLoadError(true);

      if (error.message.includes('Timeout')) {
        toast.error('ΓÅ▒∩╕Å Loading lokasi timeout (>3 detik). Klik "Coba Lagi" atau "Lewati".');
      } else {
        toast.error('Gagal memuat lokasi: ' + error.message);
      }

      setLocations([]);
      setLocationStocks([]);
    } finally {
      setIsLoadingLocations(false);
    }
  };

  const updateLocationStock = (locationId, field, value) => {
    setLocationStocks(prev => prev.map(stock =>
      stock.location_id === locationId
        ? { ...stock, [field]: (field === 'quantity' || field === 'min_stock') ? (parseInt(value) || 0) : (parseFloat(value) || 0) }
        : stock
    ));
  };

  const handleImageUpload = async (file) => {
    try {
      setIsUploading(true);
      const { file_url } = await UploadFile({ file });
      setFormData({ ...formData, image_url: file_url });
      toast.success('Gambar berhasil diunggah');
    } catch (error) {
      console.error('Error uploading image:', error);
      toast.error('Gagal mengunggah gambar');
    } finally {
      setIsUploading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Γ£à STRICT BLOCKING: Oracle-style prevent save on duplicate
    if (skuError) {
      toast.error('Gagal Simpan: SKU sudah terdaftar pada produk lain. Harap ganti SKU.');
      return;
    }

    // Trigger check again just to be safe if user clicked save immediately after typing
    // (Optional, but adds robustness)

    if (!formData.name || !formData.sku || formData.price <= 0) {
      toast.error('Nama, SKU, dan Harga wajib diisi dengan benar');
      return;
    }

    if (!companyId) {
      toast.error('Company ID tidak tersedia. Refresh halaman dan coba lagi.');
      return;
    }

    try {
      setIsSaving(true);

      const totalStock = locationStocks.reduce((sum, loc) => sum + (loc.quantity || 0), 0);

      const productData = {
        ...formData,
        stock: totalStock
      };

      console.log('≡ƒÆ╛ Saving product with', locationStocks.length, 'location stocks');
      await onSave(productData, locationStocks);
    } catch (error) {
      console.error('Error in form submit:', error);
      toast.error('Gagal menyimpan produk');
    } finally {
      setIsSaving(false);
    }
  };

  // Γ£à Handle creating new category inline
  const handleCreateCategory = async () => {
    if (!newCategoryName.trim() || !companyId) {
      toast.error('Nama kategori tidak boleh kosong');
      return;
    }

    try {
      setIsSavingCategory(true);
      await base44.entities.CompanyPOSCategory.create({
        company_id: companyId,
        name: newCategoryName.trim(),
        is_active: true
      });
      toast.success('Γ£à Kategori berhasil ditambahkan!');
      setFormData({ ...formData, category: newCategoryName.trim() });
      setNewCategoryName('');
      setShowNewCategoryInput(false);

      // Γ£à BROADCAST to sync with POS Cashier and other pages
      try {
        const productChannel = new BroadcastChannel('snishop_product_updates');
        productChannel.postMessage({
          type: 'CATEGORY_CREATED',
          companyId: companyId,
          categoryName: newCategoryName.trim(),
          timestamp: Date.now()
        });
        productChannel.close();
        console.log('Γ£à Category broadcast sent');
      } catch (e) { }

      if (onCategoryCreated) onCategoryCreated();
    } catch (error) {
      console.error('Error creating category:', error);
      toast.error('Gagal membuat kategori: ' + error.message);
    } finally {
      setIsSavingCategory(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-3 sm:p-4 overflow-y-auto">
      <Card className="bg-gray-900 border-gray-700 max-w-4xl w-full max-h-[95vh] overflow-y-auto my-4 mx-3 sm:mx-0">
        <CardHeader className="border-b border-gray-800 p-4 sm:p-6 sticky top-0 bg-gray-900 z-10">
          <div className="flex items-start justify-between gap-3">
            <CardTitle className="text-white text-base sm:text-xl">
              {product ? 'Edit Produk' : 'Tambah Produk Baru'}
            </CardTitle>
            <Button variant="ghost" size="icon" onClick={onClose} className="flex-shrink-0">
              <X className="w-4 h-4 sm:w-5 sm:h-5" />
            </Button>
          </div>
        </CardHeader>

        <CardContent className="p-4 sm:p-6">
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Image Upload */}
            <div>
              <Label className="text-gray-300 text-xs sm:text-sm">Gambar Produk</Label>
              <div className="mt-2">
                {formData.image_url ? (
                  <div className="relative inline-block">
                    <img
                      src={formData.image_url}
                      alt="Product"
                      className="w-32 h-32 object-cover rounded-lg border-2 border-gray-700"
                    />
                    <Button
                      type="button"
                      size="icon"
                      variant="destructive"
                      className="absolute -top-2 -right-2 h-6 w-6"
                      onClick={() => setFormData({ ...formData, image_url: '' })}
                    >
                      <X className="w-3 h-3" />
                    </Button>
                  </div>
                ) : (
                  <div className="flex items-center gap-2">
                    <Input
                      type="file"
                      accept="image/*"
                      onChange={(e) => {
                        const file = e.target.files[0];
                        if (file) handleImageUpload(file);
                      }}
                      disabled={isUploading}
                      className="bg-gray-800 border-gray-700 text-white"
                    />
                    {isUploading && <Loader2 className="w-4 h-4 animate-spin text-blue-400" />}
                  </div>
                )}
              </div>
            </div>

            {/* Basic Info */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <Label className="text-gray-300 text-xs sm:text-sm">Nama Produk *</Label>
                <Input
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  className="bg-gray-800 border-gray-700 text-white mt-1"
                  required
                />
              </div>

              <div>
                <Label className="text-gray-300 text-xs sm:text-sm">SKU/Barcode *</Label>
                <div className="flex gap-2">
                  <Input
                    value={formData.sku}
                    onChange={(e) => {
                      setFormData({ ...formData, sku: e.target.value.toUpperCase() });
                      setSkuError(null); // Reset visual error temporarily
                    }}
                    onBlur={() => checkDuplicateSku(formData.sku)} // Γ£à CHECK ON BLUR
                    className={`bg-gray-800 border-gray-700 text-white mt-1 uppercase ${skuError ? 'border-red-500 ring-1 ring-red-500' : ''
                      }`}
                    required
                    placeholder="Scan atau ketik SKU"
                  />
                  <Button
                    type="button"
                    variant="secondary"
                    onClick={() => setShowScanner(true)}
                    className="mt-1 bg-blue-700 hover:bg-blue-600 text-white border-blue-600"
                    title="Scan Barcode (Camera)"
                  >
                    <Scan className="w-4 h-4" />
                  </Button>
                </div>
                {/* Γ£à ERROR MESSAGE UI */}
                {isCheckingSku && <p className="text-xs text-blue-400 mt-1 animate-pulse">Memeriksa ketersediaan SKU...</p>}
                {skuError && (
                  <div className="flex items-center gap-2 mt-1 text-red-400 bg-red-900/20 p-2 rounded border border-red-800">
                    <AlertTriangle className="w-4 h-4 flex-shrink-0" />
                    <p className="text-xs font-bold">{skuError}</p>
                  </div>
                )}
              </div>

              {/* Γ£à SCANNER MODAL */}
              {showScanner && (
                <BarcodeScanner
                  scanMode="raw" // Γ£à Use RAW mode to get string directly
                  onScan={(code) => {
                    setFormData(prev => ({ ...prev, sku: code }));
                    checkDuplicateSku(code); // Γ£à Check immediately after scan
                    setShowScanner(false);
                    // toast handled by scanner
                  }}
                  onClose={() => setShowScanner(false)}
                />
              )}

              <div>
                <Label className="text-gray-300 text-xs sm:text-sm">Kategori</Label>
                <select
                  value={showNewCategoryInput ? '__new__' : formData.category}
                  onChange={(e) => {
                    if (e.target.value === '__new__') {
                      setShowNewCategoryInput(true);
                    } else {
                      setShowNewCategoryInput(false);
                      setFormData({ ...formData, category: e.target.value });
                    }
                  }}
                  className="w-full px-3 py-2 bg-gray-800 border border-gray-700 text-white rounded-md mt-1"
                >
                  <option value="">Pilih Kategori</option>
                  <option value="__new__">Γ₧ò Tambah Kategori Baru...</option>
                  {categories?.map((cat) => (
                    <option key={cat.id} value={cat.name}>
                      {cat.name}
                    </option>
                  ))}
                </select>

                {/* Inline new category creation */}
                {showNewCategoryInput && (
