                    className="mt-2 w-full p-2 border rounded-lg bg-gray-50 dark:bg-gray-800 text-sm"
                  >
                    <option value="58mm">58mm (Kecil)</option>
                    <option value="80mm">80mm (Standard)</option>
                  </select>
                </div>

                <div>
                  <Label htmlFor="font_size">Ukuran Font</Label>
                  <select
                    id="font_size"
