      can_edit_projects: false,
      can_view_pos: false,
      can_use_pos: false,
      can_edit_pos_transactions: false,
      can_view_reports: false,
      can_manage_members: false,
      can_manage_roles: false,
      can_view_settings: false,
      can_edit_settings: false
    }
  }
};

const PERMISSION_GROUPS = {
  'Dashboard & Tasks': [
    { key: 'can_view_dashboard', label: 'Lihat Dashboard' },
    { key: 'can_view_tasks', label: 'Lihat Tugas' },
    { key: 'can_create_tasks', label: 'Buat Tugas' },
    { key: 'can_edit_tasks', label: 'Edit Tugas' },
    { key: 'can_delete_tasks', label: 'Hapus Tugas' }],

  'Notes': [
    { key: 'can_view_notes', label: 'Lihat Catatan' },
    { key: 'can_create_notes', label: 'Buat Catatan' },
    { key: 'can_edit_notes', label: 'Edit Catatan' },
    { key: 'can_delete_notes', label: 'Hapus Catatan' }],

  'HR & Payroll': [
    { key: 'can_view_hr', label: 'Lihat HR' },
    { key: 'can_edit_hr', label: 'Kelola HR' }],

  'Finance': [
    { key: 'can_view_finance', label: 'Lihat Keuangan' },
    { key: 'can_edit_finance', label: 'Kelola Keuangan' }],

  'Inventory': [
    { key: 'can_view_inventory', label: 'Lihat Inventory' },
    { key: 'can_edit_inventory', label: 'Kelola Inventory' }],

  'Projects': [
    { key: 'can_view_projects', label: 'Lihat Projects' },
    { key: 'can_edit_projects', label: 'Kelola Projects' }],

  'POS / Kasir': [
    { key: 'can_view_pos', label: 'Lihat POS' },
    { key: 'can_use_pos', label: 'Gunakan Kasir' },
    { key: 'can_edit_pos_transactions', label: 'Edit Transaksi POS' }],

  'Reports & Management': [
    { key: 'can_view_reports', label: 'Lihat Laporan' },
    { key: 'can_manage_members', label: 'Kelola Anggota' },
    { key: 'can_manage_roles', label: 'Kelola Role' },
    { key: 'can_view_settings', label: 'Lihat Pengaturan' },
    { key: 'can_edit_settings', label: 'Edit Pengaturan' }]

};

export default function RoleManager({ selectedCompany, currentUser }) {
  const [members, setMembers] = useState([]);
  const [invitations, setInvitations] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showInviteForm, setShowInviteForm] = useState(false);
  const [showEditForm, setShowEditForm] = useState(false);
  const [editingMember, setEditingMember] = useState(null);

  // Invite form state
  const [inviteEmail, setInviteEmail] = useState('');
  const [inviteRole, setInviteRole] = useState('employee');
  const [inviteDepartment, setInviteDepartment] = useState('');
  const [invitePosition, setInvitePosition] = useState('');
  const [inviteMessage, setInviteMessage] = useState('');
  const [invitePermissions, setInvitePermissions] = useState(ROLE_TEMPLATES.employee.permissions);
  const [customPermissions, setCustomPermissions] = useState(false);

  // Γ£à FIX: Check both original owner AND invited owner role
  const isOriginalOwner = selectedCompany && currentUser && selectedCompany.owner_email === currentUser.email;

  // Γ£à NEW: State for member permission check (for invited owners/admins)
  const [currentUserRole, setCurrentUserRole] = useState(null);
  const [canManageMembers, setCanManageMembers] = useState(false);

  // Γ£à FIX: Check user's role in company on mount
  useEffect(() => {
    const checkUserRole = async () => {
      if (!selectedCompany?.id || !currentUser?.email) {
        setCanManageMembers(isOriginalOwner);
        return;
      }

      // Original owner always has full access
      if (isOriginalOwner) {
        setCurrentUserRole('owner');
        setCanManageMembers(true);
        console.log('Γ£à User is original owner - full access');
        return;
      }

      // Check if user is a member with owner/admin role
      try {
        console.log('≡ƒöì Checking user role in company...');
        let memberData = null;

        // Try to get user's membership
        try {
          const members = await base44.entities.CompanyMember.filter({
            company_id: selectedCompany.id,
            user_email: currentUser.email
          });
          memberData = members?.[0];
        } catch (e) {
          // Fallback to service role
          try {
            const members = await base44.asServiceRole.entities.CompanyMember.filter({
              company_id: selectedCompany.id,
              user_email: currentUser.email
            });
            memberData = members?.[0];
          } catch (e2) {
            console.warn('Could not check membership:', e2);
          }
        }

        if (memberData) {
          setCurrentUserRole(memberData.role);

          // Γ£à CRITICAL: Check if role is owner OR has can_manage_members permission
          const hasOwnerRole = memberData.role === 'owner';
          const hasAdminRole = memberData.role === 'admin';
          const hasManagePermission = memberData.permissions?.can_manage_members === true;

          const canManage = hasOwnerRole || hasAdminRole || hasManagePermission;
          setCanManageMembers(canManage);

          console.log('Γ£à User role:', memberData.role);
          console.log('Γ£à Can manage members:', canManage);
        } else {
          console.log('ΓÜá∩╕Å User is not a member of this company');
          setCanManageMembers(false);
        }
      } catch (error) {
        console.error('Error checking user role:', error);
        setCanManageMembers(isOriginalOwner);
      }
    };

    checkUserRole();
  }, [selectedCompany?.id, currentUser?.email, isOriginalOwner]);

  // Γ£à Backward compatibility: isOwner now includes invited owners
  const isOwner = canManageMembers;

  useEffect(() => {
    if (selectedCompany) {
      loadData();
    }
  }, [selectedCompany]);

  // ROBUST MEMBER LOADING - Multiple fallback strategies
  const loadMembers = async () => {
    if (!selectedCompany) return;

    console.log('');
    console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
    console.log('≡ƒæÑ ROLE MANAGER - LOADING MEMBERS');
    console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
    console.log('≡ƒÅó Company:', selectedCompany.name);
    console.log('≡ƒåö Company ID:', selectedCompany.id);
    console.log('');

    try {
      let membersData = [];
      let loadSuccess = false;

      // STRATEGY 1: Direct filter dengan base44.entities (fresh, no cache)
      console.log('≡ƒö╣ Strategy 1: Direct filter...');
      try {
        membersData = await base44.entities.CompanyMember.filter({
          company_id: selectedCompany.id
        });

        console.log(`Γ£à Strategy 1 SUCCESS - Found ${membersData?.length || 0} members`);
        loadSuccess = true;
      } catch (e) {
        console.warn(`Γ¥î Strategy 1 failed:`, e.message);
      }

      // STRATEGY 2: Service role filter (admin privileges)
      if (!loadSuccess || !membersData || membersData.length === 0) {
        console.log('');
        console.log('≡ƒö╣ Strategy 2: Service role filter...');
        try {
          membersData = await base44.asServiceRole.entities.CompanyMember.filter({
            company_id: selectedCompany.id
          });

          console.log(`Γ£à Strategy 2 SUCCESS - Found ${membersData?.length || 0} members`);
          loadSuccess = true;
        } catch (e) {
          console.warn(`Γ¥î Strategy 2 failed:`, e.message);
        }
      }

      // STRATEGY 3: List all + manual filter (last resort)
      if (!loadSuccess || !membersData || membersData.length === 0) {
        console.log('');
        console.log('≡ƒö╣ Strategy 3: List all + manual filter...');
        try {
          const allMembers = await base44.asServiceRole.entities.CompanyMember.list();
          console.log(`   - Total members in DB: ${allMembers?.length || 0}`);

          membersData = (allMembers || []).filter(m =>
            m && m.company_id === selectedCompany.id
          );

          console.log(`Γ£à Strategy 3 SUCCESS - Found ${membersData.length} members after filter`);
          loadSuccess = true;
        } catch (e) {
          console.warn(`Γ¥î Strategy 3 failed:`, e.message);
        }
      }

      // Final result
      if (!loadSuccess) {
        console.error('Γ¥îΓ¥îΓ¥î ALL STRATEGIES FAILED - No members loaded');
        membersData = [];
      }

      console.log('');
      console.log('≡ƒôè FINAL RESULT:');
      console.log(`   - Members loaded: ${membersData?.length || 0}`);

      if (membersData && membersData.length > 0) {
        membersData.forEach((m, i) => {
          console.log(`   ${i + 1}. ${m.user_name || m.user_email} (${m.role})`);
        });
      } else {
        console.log('   ΓÜá∩╕Å No members found for this company');
      }

      console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
      console.log('');

      setMembers(membersData || []);

    } catch (error) {
      console.error('Γ¥î Critical error loading members:', error);
      toast.error('Gagal memuat daftar anggota');
      setMembers([]);
    }
  };

  const loadInvitations = async () => {
    if (!selectedCompany || !currentUser) return;
    try {
      const data = await base44.entities.CompanyInvitation.filter({
        company_id: selectedCompany.id,
        invited_by: currentUser.email
      });
      const pendingInvitations = (data || []).filter((inv) => inv.status === 'pending');
      setInvitations(pendingInvitations);
    } catch (error) {
      console.error('Error loading invitations:', error);
      setInvitations([]);
    }
  };

  const loadData = async () => {
    if (!selectedCompany) return;
    setIsLoading(true);
    try {
      await loadMembers();
      if (isOwner) {
        await loadInvitations();
      }
    } catch (error) {
      console.error('Error loading company data:', error);
      toast.error('Gagal memuat data perusahaan');
    } finally {
      setIsLoading(false);
    }
  };

  const handleRoleChange = (role) => {
    setInviteRole(role);
    if (!customPermissions && ROLE_TEMPLATES[role]) {
      setInvitePermissions(ROLE_TEMPLATES[role].permissions);
    }
  };

  const togglePermission = (key) => {
    setInvitePermissions((prev) => ({
      ...prev,
      [key]: !prev[key]
    }));
  };

  const handleInvite = async (e) => {
    e.preventDefault();

    if (!inviteEmail || !inviteRole) {
      toast.error('Email dan role harus diisi');
      return;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(inviteEmail)) {
      toast.error('Format email tidak valid');
      return;
    }

    try {
      setIsLoading(true);
      toast.loading('Memeriksa undangan...', { id: 'invite-check' });

      // Γ£à STEP 1: Check existing invitations
      const existingInvites = await base44.entities.CompanyInvitation.filter({
        company_id: selectedCompany.id,
        invited_email: inviteEmail,
        status: 'pending'
      });

      if (existingInvites && existingInvites.length > 0) {
        toast.error('User ini sudah memiliki undangan pending', { id: 'invite-check' });
        setIsLoading(false);
        return;
      }

      // Γ£à STEP 2: Check existing members
      const existingMembers = await base44.entities.CompanyMember.filter({
        company_id: selectedCompany.id,
        user_email: inviteEmail
      });

      if (existingMembers && existingMembers.length > 0) {
        toast.error('User ini sudah menjadi anggota perusahaan', { id: 'invite-check' });
        setIsLoading(false);
        return;
      }

      toast.loading('Mengirim undangan...', { id: 'invite-check' });

      // Γ£à STEP 3: Create invitation with expiry (30 days)
      const expiresAt = new Date();
      expiresAt.setDate(expiresAt.getDate() + 30);

      const invitationData = {
        company_id: selectedCompany.id,
        company_name: selectedCompany.name,
        invited_email: inviteEmail,
        invited_by: currentUser.email,
        invited_by_name: currentUser.full_name || currentUser.email,
        role: inviteRole,
        department: inviteDepartment || '',
        position: invitePosition || '',
        permissions: invitePermissions,
        message: inviteMessage || `Bergabunglah dengan ${selectedCompany.name} sebagai ${inviteRole}`,
        status: 'pending',
        expires_at: expiresAt.toISOString()
      };

      const newInvitation = await base44.entities.CompanyInvitation.create(invitationData);

      // Γ£à STEP 4: Create notification
      try {
        await base44.entities.Notification.create({
          user_id: inviteEmail,
          title: `Undangan Bergabung dengan ${selectedCompany.name}`,
          message: `${currentUser.full_name || currentUser.email} mengundang Anda untuk bergabung dengan ${selectedCompany.name} sebagai ${inviteRole}`,
          url: '/dashboard',
          is_read: false
        });
      } catch (error) {
        console.log('ΓÜá∩╕Å Could not create notification:', error);
      }

      // Γ£à STEP 5: Broadcast
      try {
        const channel = new BroadcastChannel('snishop_invitation_updates');
        channel.postMessage({
          type: 'INVITATION_CREATED',
          invitedEmail: inviteEmail,
          invitation: {
            id: newInvitation.id,
            company_id: selectedCompany.id,
            company_name: selectedCompany.name,
            invited_by: currentUser.email,
            invited_by_name: currentUser.full_name || currentUser.email,
            role: inviteRole,
            department: inviteDepartment,
            position: invitePosition,
            permissions: invitePermissions,
            message: inviteMessage
          },
          timestamp: Date.now()
        });
        channel.close();
      } catch (e) {
        console.warn('BroadcastChannel error:', e);
      }

      toast.success(`Γ£à Undangan berhasil dikirim ke ${inviteEmail}!`, { id: 'invite-check' });

      // Γ£à STEP 6: Reset form
      setInviteEmail('');
      setInviteRole('employee');
      setInviteDepartment('');
      setInvitePosition('');
      setInviteMessage('');
      setInvitePermissions(ROLE_TEMPLATES.employee.permissions);
      setCustomPermissions(false);
      setShowInviteForm(false);

      // Γ£à STEP 7: Reload invitations
      invalidateCache(/CompanyInvitation/);
      await loadInvitations();

    } catch (error) {
      console.error('Γ¥î Error sending invitation:', error);
      toast.error(`Gagal mengirim undangan: ${error.message}`, { id: 'invite-check' });
    } finally {
      setIsLoading(false);
    }
  };

  const handleCancelInvitation = async (invitationId) => {
    if (!confirm('Apakah Anda yakin ingin membatalkan undangan ini?')) return;

    try {
      setIsLoading(true);
      await base44.entities.CompanyInvitation.update(invitationId, {
        status: 'expired'
      });

      toast.success('Undangan dibatalkan');
      invalidateCache(/CompanyInvitation/);
      await loadInvitations();

    } catch (error) {
      console.error('Error canceling invitation:', error);
      toast.error('Gagal membatalkan undangan');
    } finally {
      setIsLoading(false);
    }
  };

  const handleResendInvitation = async (invitation) => {
    try {
      setIsLoading(true);

      // Re-create notification
      try {
        await base44.entities.Notification.create({
          user_id: invitation.invited_email,
          title: `≡ƒöö Reminder: Undangan Bergabung dengan ${invitation.company_name}`,
          message: `${invitation.invited_by_name} mengirim ulang undangan untuk bergabung dengan ${invitation.company_name} sebagai ${invitation.role}`,
          url: '/dashboard',
          is_read: false
        });
      } catch (error) {
        console.log('ΓÜá∩╕Å Could not create notification:', error);
      }

      // Re-broadcast
      try {
        const channel = new BroadcastChannel('snishop_invitation_updates');
        channel.postMessage({
          type: 'INVITATION_CREATED',
          invitedEmail: invitation.invited_email,
          invitation: {
            id: invitation.id,
            company_id: invitation.company_id,
            company_name: invitation.company_name,
            invited_by: invitation.invited_by,
            invited_by_name: invitation.invited_by_name,
            role: invitation.role,
            department: invitation.department,
            position: invitation.position,
            permissions: invitation.permissions,
            message: invitation.message
          },
          timestamp: Date.now()
        });
        channel.close();
      } catch (e) {
        console.warn('BroadcastChannel error:', e);
      }

      toast.success(`Γ£à Undangan berhasil dikirim ulang ke ${invitation.invited_email}!`);

    } catch (error) {
      console.error('Γ¥î Error resending invitation:', error);
      toast.error('Gagal mengirim ulang undangan');
    } finally {
      setIsLoading(false);
    }
  };

  const handleEditMember = (member) => {
    setEditingMember({
      ...member,
      selectedRole: member.role,
      customPermissions: { ...(member.permissions || {}) }
    });
    setShowEditForm(true);
  };

  const handleUpdateMember = async () => {
    if (!editingMember) return;

    try {
      setIsLoading(true);

      const updateData = {
        role: editingMember.selectedRole,
        permissions: editingMember.customPermissions,
        department: editingMember.department,
        position: editingMember.position
      };

      await base44.entities.CompanyMember.update(editingMember.id, updateData);
      invalidateCache(/CompanyMember/);

      // Broadcast
      try {
        const channel = new BroadcastChannel('snishop_member_updates');
        channel.postMessage({
          type: 'PERMISSIONS_UPDATED',
          memberId: editingMember.id,
          memberEmail: editingMember.user_email,
          companyId: selectedCompany.id,
          timestamp: Date.now()
        });
        channel.close();
      } catch (e) {
        console.warn('BroadcastChannel error:', e);
      }

      toast.success('Γ£à Anggota berhasil diperbarui!');

      setShowEditForm(false);
      setEditingMember(null);
      await loadData();

    } catch (error) {
      console.error('Error updating member:', error);
      toast.error('Gagal memperbarui anggota');
    } finally {
      setIsLoading(false);
    }
  };

  const handleRoleChangeForEdit = (role) => {
    if (!editingMember) return;

    const template = ROLE_TEMPLATES[role];

    // Γ£à FIX: When changing to owner role, ensure ALL permissions are true
    const newPermissions = template?.permissions || {};

    console.log(`≡ƒöä Role changed to ${role} - syncing permissions:`, newPermissions);

    setEditingMember({
      ...editingMember,
      selectedRole: role,
      customPermissions: { ...newPermissions }
    });
  };

  const handlePermissionToggleForEdit = (permissionKey) => {
    if (!editingMember) return;

    setEditingMember({
      ...editingMember,
      customPermissions: {
        ...editingMember.customPermissions,
        [permissionKey]: !editingMember.customPermissions[permissionKey]
      }
    });
  };

  const handleDeleteMember = async (memberId) => {
    if (!confirm('Yakin ingin menghapus anggota ini?')) return;

    try {
      setIsLoading(true);
      await base44.entities.CompanyMember.delete(memberId);
      invalidateCache(/CompanyMember/);
      toast.success('Anggota berhasil dihapus');
      await loadData();
    } catch (error) {
      console.error('Error deleting member:', error);
      toast.error('Gagal menghapus anggota');
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOwner) {
    return (
      <div className="text-center py-8">
        <p className="text-gray-500 text-sm">
          Anda tidak memiliki akses untuk mengelola anggota perusahaan.
        </p>
        <p className="text-gray-400 text-xs mt-2">
          Hanya Owner, Admin, atau user dengan izin "Kelola Anggota" yang dapat mengundang anggota baru.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-4 sm:space-y-6 w-full overflow-hidden">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
        <div className="min-w-0 flex-1">
          <h3 className="text-base sm:text-lg font-semibold truncate">Anggota Tim</h3>
          <p className="text-xs sm:text-sm text-gray-500 truncate">Kelola anggota dan izin akses</p>
        </div>
        <div className="flex gap-2 flex-shrink-0">
          <Button
            variant="outline"
            size="sm"
            onClick={() => {
              toast.info('Memuat ulang data member...');
              loadData();
            }}
            className="min-h-[44px]"
          >
            <RefreshCw className="w-4 h-4" />
          </Button>
          <Button onClick={() => setShowInviteForm(true)} className="w-full sm:w-auto min-h-[44px] flex-shrink-0">
            <UserPlus className="w-4 h-4 mr-2" />
            Undang Anggota
          </Button>
        </div>
      </div>

      <Tabs defaultValue="members" className="w-full">
        <div className="w-full overflow-x-auto -mx-3 sm:mx-0 px-3 sm:px-0 pb-2 sm:pb-0">
          <TabsList className="inline-flex sm:grid sm:grid-cols-2 w-auto sm:w-full min-w-max">
            <TabsTrigger value="members" className="text-xs sm:text-sm px-3 sm:px-4 whitespace-nowrap">
              Anggota Aktif ({members.length})
            </TabsTrigger>
            <TabsTrigger value="invitations" className="text-xs sm:text-sm px-3 sm:px-4 whitespace-nowrap">
              Undangan Pending ({invitations.length})
            </TabsTrigger>
          </TabsList>
        </div>

        <TabsContent value="members" className="space-y-3 sm:space-y-4 mt-3 sm:mt-4">
          <Card>
            <CardHeader className="p-3 sm:p-4">
              <CardTitle className="text-sm sm:text-base">Daftar Anggota Aktif</CardTitle>
            </CardHeader>
            <CardContent className="p-3 sm:p-4">
              {isLoading ? (
                <div className="flex justify-center items-center py-8">
                  <Loader2 className="w-6 h-6 animate-spin text-gray-500" />
                </div>
              ) : members.length === 0 ? (
                <div className="text-center py-8">
                  <p className="text-gray-500 text-sm mb-4">Belum ada anggota. Undang anggota baru untuk memulai.</p>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => {
                      console.log('≡ƒöä Manual refresh clicked');
                      loadData();
                    }}
                  >
                    <RefreshCw className="w-4 h-4 mr-2" />
                    Refresh Data
                  </Button>
                </div>
              ) : (
                <div className="space-y-2 sm:space-y-3">
                  {members.map((member) => (
                    <div
                      key={member.id}
                      className="bg-gray-950 dark:bg-gray-800 p-3 sm:p-4 rounded-lg"
                    >
                      <div className="flex flex-col sm:flex-row sm:items-center gap-3">
                        <div className="flex-1 min-w-0">
                          <div className="font-medium text-sm sm:text-base truncate">{member.user_name || member.user_email}</div>
                          <div className="text-xs sm:text-sm text-gray-500 truncate">{member.user_email}</div>
                          <div className="flex flex-wrap gap-1 sm:gap-2 mt-2">
                            <Badge className="bg-purple-600 text-white text-xs">{member.role}</Badge>
                            {member.department && (
                              <Badge variant="secondary" className="text-xs">{member.department}</Badge>
                            )}
                            {member.position && (
                              <Badge variant="outline" className="text-xs">{member.position}</Badge>
                            )}
                          </div>
                        </div>
                        <div className="flex gap-2 w-full sm:w-auto flex-shrink-0">
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => handleEditMember(member)}
                            className="flex-1 sm:flex-none min-h-[36px] text-xs sm:text-sm"
                          >
                            <Settings className="w-3 h-3 sm:w-4 sm:h-4 mr-1" />
                            Edit
                          </Button>
                          {member.role !== 'owner' && (
                            <Button
                              variant="outline"
                              size="sm"
                              onClick={() => handleDeleteMember(member.id)}
                              className="text-red-600 hover:text-red-700 min-h-[36px]"
                            >
                              <XCircle className="w-3 h-3 sm:w-4 sm:h-4" />
                            </Button>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="invitations" className="space-y-3 sm:space-y-4 mt-3 sm:mt-4">
          <h3 className="text-base sm:text-lg font-semibold">Undangan Pending</h3>

          {isLoading ? (
            <div className="flex justify-center items-center py-8">
              <Loader2 className="w-6 h-6 animate-spin text-gray-500" />
            </div>
          ) : invitations.length === 0 ? (
            <Card>
              <CardContent className="p-6 sm:p-8 text-center text-gray-500">
                <p className="text-sm">Tidak ada undangan pending</p>
              </CardContent>
            </Card>
          ) : (
            <div className="grid gap-3 sm:gap-4">
              {invitations.map((invitation) => (
                <Card key={invitation.id} className="border-blue-200">
                  <CardContent className="p-3 sm:p-4">
                    <div className="flex flex-col sm:flex-row sm:items-start gap-3">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-2">
                          <Mail className="w-4 h-4 sm:w-5 sm:h-5 text-blue-600 flex-shrink-0" />
                          <h4 className="font-semibold text-sm sm:text-base truncate">{invitation.invited_email}</h4>
                        </div>

                        <div className="flex flex-wrap gap-1 sm:gap-2 mb-2">
                          <Badge className="bg-purple-600 text-white text-xs">
                            {invitation.role}
                          </Badge>
                          {invitation.department && (
                            <Badge variant="secondary" className="text-xs">{invitation.department}</Badge>
                          )}
                          {invitation.position && (
                            <Badge variant="outline" className="text-xs">{invitation.position}</Badge>
                          )}
                          <Badge variant="outline" className="text-orange-600 text-xs">
                            Pending
                          </Badge>
                        </div>

                        {invitation.message && (
                          <p className="text-xs sm:text-sm text-gray-600 mt-2 line-clamp-2">"{invitation.message}"</p>
                        )}
                      </div>

                      <div className="flex gap-2 flex-shrink-0">
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => handleResendInvitation(invitation)}
                          disabled={isLoading}
                          className="w-full sm:w-auto min-h-[36px] text-xs sm:text-sm bg-green-600 hover:bg-green-700 text-white border-green-600"
                        >
                          <Mail className="w-3 h-3 sm:w-4 sm:h-4 mr-1" />
                          Kirim Ulang
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => handleCancelInvitation(invitation.id)}
                          disabled={isLoading}
                          className="w-full sm:w-auto min-h-[36px] text-xs sm:text-sm"
                        >
                          <XCircle className="w-3 h-3 sm:w-4 sm:h-4 mr-1" />
                          Batalkan
                        </Button>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </TabsContent>
      </Tabs>

      {/* Invite Modal */}
      <Dialog open={showInviteForm} onOpenChange={setShowInviteForm}>
        <DialogContent className="bg-slate-950 p-4 sm:p-6 max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Undang Anggota Baru</DialogTitle>
          </DialogHeader>

          <form onSubmit={handleInvite} className="space-y-4">
            <div>
              <Label htmlFor="inviteEmail">Email *</Label>
              <Input
                id="inviteEmail"
                type="email"
                value={inviteEmail}
                onChange={(e) => setInviteEmail(e.target.value)}
                placeholder="user@example.com"
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label htmlFor="inviteRole">Role *</Label>
                <Select value={inviteRole} onValueChange={handleRoleChange}>
                  <SelectTrigger id="inviteRole">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {Object.entries(ROLE_TEMPLATES).map(([key, template]) => (
                      <SelectItem key={key} value={key}>
                        {template.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                {ROLE_TEMPLATES[inviteRole] && (
                  <p className="text-xs text-gray-500 mt-1">
                    {ROLE_TEMPLATES[inviteRole].description}
                  </p>
                )}
              </div>

              <div>
                <Label htmlFor="inviteDepartment">Department</Label>
                <Input
                  id="inviteDepartment"
                  value={inviteDepartment}
                  onChange={(e) => setInviteDepartment(e.target.value)}
                  placeholder="Engineering, Sales, etc"
                />
              </div>
            </div>

            <div>
              <Label htmlFor="invitePosition">Position</Label>
              <Input
                id="invitePosition"
                value={invitePosition}
                onChange={(e) => setInvitePosition(e.target.value)}
                placeholder="Software Engineer, Sales Manager, etc"
              />
            </div>

            <div>
              <Label htmlFor="inviteMessage">Pesan (Optional)</Label>
              <Input
                id="inviteMessage"
                value={inviteMessage}
                onChange={(e) => setInviteMessage(e.target.value)}
                placeholder="Pesan untuk yang diundang..."
              />
            </div>

            <div className="bg-gray-950 p-4 rounded-lg flex items-center gap-2">
              <Switch
                id="customPermissionsToggle"
                checked={customPermissions}
                onCheckedChange={setCustomPermissions}
              />
              <div>
                <Label htmlFor="customPermissionsToggle" className="cursor-pointer">Custom Permissions</Label>
                <p className="text-xs text-gray-500">
                  Aktifkan untuk mengatur hak akses secara manual
                </p>
              </div>
            </div>

            {customPermissions && (
              <Card>
                <CardHeader>
                  <CardTitle className="text-lg flex items-center gap-2">
                    <Settings className="w-5 h-5" />
                    Atur Hak Akses
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <Accordion type="multiple" className="w-full">
                    {Object.entries(PERMISSION_GROUPS).map(([groupName, permissions]) => (
                      <AccordionItem key={groupName} value={groupName}>
                        <AccordionTrigger>{groupName}</AccordionTrigger>
                        <AccordionContent>
                          <div className="space-y-3 p-2">
                            {permissions.map((perm) => (
                              <div key={perm.key} className="flex items-center justify-between">
                                <Label htmlFor={perm.key} className="cursor-pointer">
                                  {perm.label}
                                </Label>
                                <Switch
                                  id={perm.key}
                                  checked={invitePermissions[perm.key]}
                                  onCheckedChange={() => togglePermission(perm.key)}
                                />
                              </div>
                            ))}
                          </div>
                        </AccordionContent>
                      </AccordionItem>
                    ))}
                  </Accordion>
                </CardContent>
              </Card>
            )}

            <div className="flex justify-end gap-2">
              <Button type="button" variant="outline" onClick={() => setShowInviteForm(false)}>
                Batal
              </Button>
              <Button type="submit" disabled={isLoading}>
                {isLoading ? (
                  <>
                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    Mengirim...
                  </>
                ) : (
                  <>
                    <Mail className="w-4 h-4 mr-2" />
                    Kirim Undangan
                  </>
                )}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>

      {/* Edit Member Modal */}
      {showEditForm && editingMember && (
        <Dialog open={showEditForm} onOpenChange={setShowEditForm}>
          <DialogContent className="bg-gray-950 p-4 sm:p-6 max-w-4xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Edit Anggota - {editingMember.user_name || editingMember.user_email}</DialogTitle>
            </DialogHeader>

            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="editDepartment">Department</Label>
                  <Input
                    id="editDepartment"
                    value={editingMember.department || ''}
                    onChange={(e) => setEditingMember({ ...editingMember, department: e.target.value })}
                    placeholder="Department"
                  />
                </div>

                <div>
                  <Label htmlFor="editPosition">Position</Label>
                  <Input
                    id="editPosition"
                    value={editingMember.position || ''}
                    onChange={(e) => setEditingMember({ ...editingMember, position: e.target.value })}
                    placeholder="Position"
                  />
                </div>
              </div>

              <div>
                <Label htmlFor="editRole">Role Template</Label>
                <Select value={editingMember.selectedRole} onValueChange={handleRoleChangeForEdit}>
                  <SelectTrigger id="editRole">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {Object.entries(ROLE_TEMPLATES).map(([key, template]) => (
                      <SelectItem key={key} value={key}>
                        <div>
                          <div className="font-medium">{template.label}</div>
                          <div className="text-xs text-gray-500">{template.description}</div>
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <Card>
                <CardHeader>
                  <CardTitle className="text-sm">Custom Permissions</CardTitle>
                </CardHeader>
                <CardContent>
                  <Accordion type="multiple" className="w-full">
                    {Object.entries(PERMISSION_GROUPS).map(([groupName, permissions]) => (
                      <AccordionItem key={groupName} value={groupName}>
                        <AccordionTrigger className="text-sm font-medium">
                          {groupName}
                        </AccordionTrigger>
                        <AccordionContent>
                          <div className="space-y-2 pl-4">
                            {permissions.map((perm) => (
                              <div key={perm.key} className="flex items-center justify-between py-2">
                                <Label htmlFor={`edit-${perm.key}`} className="text-sm">
                                  {perm.label}
                                </Label>
                                <Switch
                                  id={`edit-${perm.key}`}
                                  checked={editingMember.customPermissions[perm.key] || false}
                                  onCheckedChange={() => handlePermissionToggleForEdit(perm.key)}
                                />
                              </div>
                            ))}
                          </div>
                        </AccordionContent>
                      </AccordionItem>
                    ))}
                  </Accordion>
                </CardContent>
              </Card>

              <div className="flex justify-end gap-2">
                <Button variant="outline" onClick={() => { setShowEditForm(false); setEditingMember(null); }}>
                  Batal
                </Button>
                <Button onClick={handleUpdateMember} disabled={isLoading}>
                  {isLoading && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                  Simpan Perubahan
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Switch } from '@/components/ui/switch';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import {
  Plus, Edit, Trash2, Save, Store, Smartphone,
  Globe, RefreshCw, GripVertical, CheckCircle
} from 'lucide-react';
import { toast } from 'sonner';

// Default channels yang sudah ada di sistem
const SYSTEM_CHANNELS = [
  { value: 'OFFLINE', label: 'Offline / Toko Langsung', icon: '≡ƒÅ¬', category: 'offline' },
  { value: 'SHOPEE', label: 'Shopee', icon: '≡ƒ¢Æ', category: 'marketplace' },
  { value: 'TOKOPEDIA', label: 'Tokopedia', icon: '≡ƒƒó', category: 'marketplace' },
  { value: 'TIKTOK', label: 'TikTok Shop', icon: '≡ƒÄ╡', category: 'marketplace' },
  { value: 'GRAB', label: 'GrabFood/Mart', icon: '≡ƒƒ⌐', category: 'delivery' },
  { value: 'GOJEK', label: 'GoFood/Mart', icon: '≡ƒƒó', category: 'delivery' },
  { value: 'WHATSAPP', label: 'WhatsApp', icon: '≡ƒÆ¼', category: 'social' },
  { value: 'WEBSITE', label: 'Website', icon: '≡ƒîÉ', category: 'online' },
  { value: 'ONLINE_DALAM_KOTA', label: 'Online Dalam Kota', icon: '≡ƒÅÖ∩╕Å', category: 'online' },
  { value: 'ONLINE_LUAR_KOTA', label: 'Online Luar Kota', icon: '≡ƒÅÿ∩╕Å', category: 'online' },
  { value: 'ONLINE_LUAR_PROVINSI', label: 'Online Luar Provinsi', icon: '≡ƒù╛', category: 'online' },
  { value: 'OTHER', label: 'Lainnya', icon: '≡ƒôª', category: 'other' },
];

const CATEGORY_CONFIG = {
  offline: { label: 'Offline', color: 'bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-300' },
  marketplace: { label: 'Marketplace', color: 'bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-300' },
  delivery: { label: 'Delivery', color: 'bg-green-100 text-green-700 dark:bg-green-900/40 dark:text-green-300' },
  social: { label: 'Social Media', color: 'bg-purple-100 text-purple-700 dark:bg-purple-900/40 dark:text-purple-300' },
  online: { label: 'Online', color: 'bg-teal-100 text-teal-700 dark:bg-teal-900/40 dark:text-teal-300' },
  whatsapp_custom: { label: 'WhatsApp Custom', color: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-300' },
  other: { label: 'Lainnya', color: 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/40 dark:text-yellow-300' },
};

export default function SalesChannelManager({ companyId, companyName }) {
  const [settings, setSettings] = useState(null);
  const [customChannels, setCustomChannels] = useState([]);
  const [systemChannelLabels, setSystemChannelLabels] = useState({});
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingChannel, setEditingChannel] = useState(null);
  const [newChannel, setNewChannel] = useState({
    value: '', label: '', icon: '≡ƒôª', category: 'other', is_active: true, description: ''
  });

  useEffect(() => {
    if (companyId) loadSettings();
  }, [companyId]);

  const loadSettings = async () => {
    setIsLoading(true);
    try {
      const result = await base44.entities.CompanyPOSSettings.filter({ company_id: companyId });
      const existingSettings = result?.[0];

      if (existingSettings) {
        setSettings(existingSettings);
        const channels = existingSettings.sales_channels_config?.custom_channels || [];
        const labels = existingSettings.sales_channels_config?.system_channel_labels || {};
        setCustomChannels(channels);
        setSystemChannelLabels(labels);
      } else {
        // Create default settings
        const defaultSettings = await base44.entities.CompanyPOSSettings.create({
          company_id: companyId,
          sales_channels_config: {
            custom_channels: [
              // Default custom WA channels sesuai permintaan user
              { value: 'WA_DALAM_KOTA', label: 'WA - Online Dalam Kota', icon: '≡ƒÆ¼', category: 'whatsapp_custom', is_active: true, description: 'Orderan WA area dalam kota' },
              { value: 'WA_LUAR_KOTA', label: 'WA - Online Luar Kota', icon: '≡ƒÆ¼', category: 'whatsapp_custom', is_active: true, description: 'Orderan WA area luar kota' },
              { value: 'WA_LUAR_PROVINSI', label: 'WA - Online Luar Provinsi', icon: '≡ƒÆ¼', category: 'whatsapp_custom', is_active: true, description: 'Orderan WA antar provinsi' },
              { value: 'ONLINE_DALAM_KOTA', label: 'Online Dalam Kota', icon: '≡ƒÅÖ∩╕Å', category: 'online', is_active: true, description: 'Orderan Online area dalam kota' },
              { value: 'ONLINE_LUAR_KOTA', label: 'Online Luar Kota', icon: '≡ƒÅÿ∩╕Å', category: 'online', is_active: true, description: 'Orderan Online area luar kota' },
              { value: 'ONLINE_LUAR_PROVINSI', label: 'Online Luar Provinsi', icon: '≡ƒù╛', category: 'online', is_active: true, description: 'Orderan Online antar provinsi' },
            ],
            system_channel_labels: {}
          }
        });
        setSettings(defaultSettings);
        setCustomChannels(defaultSettings.sales_channels_config?.custom_channels || []);
        setSystemChannelLabels({});
      }
    } catch (e) {
      console.error('Load settings error:', e);
      toast.error('Gagal memuat pengaturan channel');
    } finally {
      setIsLoading(false);
    }
  };

  const saveSettings = async (updatedChannels, updatedLabels) => {
    setIsSaving(true);
    try {
      const newConfig = {
        sales_channels_config: {
          custom_channels: updatedChannels ?? customChannels,
          system_channel_labels: updatedLabels ?? systemChannelLabels
        }
      };

      if (settings?.id) {
        await base44.entities.CompanyPOSSettings.update(settings.id, newConfig);
        setSettings({ ...settings, ...newConfig });
      } else {
        const created = await base44.entities.CompanyPOSSettings.create({
          company_id: companyId,
          ...newConfig
        });
        setSettings(created);
      }

      // Broadcast perubahan ke POS
      try {
        const ch = new BroadcastChannel('snishop_pos_updates');
        ch.postMessage({ type: 'SALES_CHANNELS_UPDATED', companyId, timestamp: Date.now() });
        ch.close();
      } catch (e) {}

      toast.success('Γ£à Pengaturan channel berhasil disimpan!');
    } catch (e) {
      toast.error('Gagal menyimpan: ' + e.message);
    } finally {
      setIsSaving(false);
    }
  };

  const handleAddChannel = async () => {
    if (!newChannel.value.trim() || !newChannel.label.trim()) {
      toast.error('Kode dan nama channel wajib diisi');
      return;
    }

    // Validasi: value harus uppercase, no space
    const channelValue = newChannel.value.toUpperCase().replace(/\s+/g, '_');

    // Cek duplikat
    const allValues = [
      ...SYSTEM_CHANNELS.map(c => c.value),
      ...customChannels.map(c => c.value)
    ];
    if (allValues.includes(channelValue)) {
      toast.error(`Kode "${channelValue}" sudah digunakan`);
      return;
    }

    const channelToAdd = {
      ...newChannel,
      value: channelValue,
      created_at: new Date().toISOString()
    };

    const updated = [...customChannels, channelToAdd];
    setCustomChannels(updated);
    await saveSettings(updated, systemChannelLabels);
    setNewChannel({ value: '', label: '', icon: '≡ƒôª', category: 'other', is_active: true, description: '' });
    setShowAddForm(false);
  };

  const handleEditChannel = async (index, updatedData) => {
    const updated = [...customChannels];
    updated[index] = { ...updated[index], ...updatedData };
    setCustomChannels(updated);
    await saveSettings(updated, systemChannelLabels);
    setEditingChannel(null);
  };

  const handleToggleChannel = async (index) => {
    const updated = [...customChannels];
    updated[index] = { ...updated[index], is_active: !updated[index].is_active };
    setCustomChannels(updated);
    await saveSettings(updated, systemChannelLabels);
  };

  const handleDeleteChannel = async (index) => {
    if (!confirm(`Hapus channel "${customChannels[index].label}"? Ini akan mempengaruhi laporan POS.`)) return;
    const updated = customChannels.filter((_, i) => i !== index);
    setCustomChannels(updated);
    await saveSettings(updated, systemChannelLabels);
    toast.success('Channel dihapus');
  };

  const handleUpdateSystemLabel = async (channelValue, newLabel) => {
    const updated = { ...systemChannelLabels, [channelValue]: newLabel };
    setSystemChannelLabels(updated);
    await saveSettings(customChannels, updated);
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <RefreshCw className="w-6 h-6 animate-spin text-blue-500 mr-2" />
        <span className="text-gray-500">Memuat pengaturan channel...</span>
      </div>
    );
  }

  const allChannels = [
    ...SYSTEM_CHANNELS.map(c => ({ ...c, isSystem: true, is_active: true })),
    ...customChannels
  ];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h3 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <Store className="w-5 h-5 text-blue-500" />
            Manajemen Channel Penjualan
          </h3>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-0.5">
            {allChannels.length} channel tersedia untuk {companyName}
          </p>
        </div>
        <Button onClick={() => setShowAddForm(true)} className="bg-blue-600 hover:bg-blue-700 gap-2">
          <Plus className="w-4 h-4" />
          Tambah Channel
        </Button>
      </div>

      {/* Info Banner */}
      <div className="p-3 bg-blue-50 dark:bg-blue-950/30 rounded-xl border border-blue-200 dark:border-blue-800 flex items-start gap-3">
        <CheckCircle className="w-5 h-5 text-blue-500 flex-shrink-0 mt-0.5" />
        <div className="text-sm text-blue-800 dark:text-blue-300">
          <p className="font-semibold mb-1">Channel terintegrasi dengan POS & Laporan</p>
          <p className="text-xs opacity-80">
            Channel bawaan sistem tidak bisa dihapus, tapi bisa diubah labelnya. Channel custom bisa ditambah, edit, dan hapus sesuai kebutuhan bisnis Anda.
          </p>
        </div>
      </div>

      {/* Add Form */}
      {showAddForm && (
        <Card className="border-2 border-blue-200 dark:border-blue-800 shadow-md">
          <CardHeader className="pb-3 bg-blue-50 dark:bg-blue-950/30 border-b border-blue-100 dark:border-blue-900">
            <CardTitle className="text-base text-blue-900 dark:text-blue-100 flex items-center gap-2">
              <Plus className="w-4 h-4" /> Tambah Channel Baru
            </CardTitle>
          </CardHeader>
          <CardContent className="pt-4 space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <Label className="text-sm">Kode Channel <span className="text-red-500">*</span></Label>
                <Input
                  placeholder="Contoh: WA_DALAM_KOTA"
                  value={newChannel.value}
                  onChange={(e) => setNewChannel({ ...newChannel, value: e.target.value.toUpperCase().replace(/\s/g, '_') })}
                  className="font-mono uppercase"
                />
                <p className="text-xs text-gray-400">Huruf kapital, pisahkan dengan underscore _</p>
              </div>
              <div className="space-y-1.5">
                <Label className="text-sm">Nama Tampilan <span className="text-red-500">*</span></Label>
                <Input
                  placeholder="Contoh: WA - Online Dalam Kota"
                  value={newChannel.label}
                  onChange={(e) => setNewChannel({ ...newChannel, label: e.target.value })}
                />
              </div>
              <div className="space-y-1.5">
                <Label className="text-sm">Ikon (Emoji)</Label>
                <Input
                  placeholder="≡ƒÆ¼"
                  value={newChannel.icon}
                  onChange={(e) => setNewChannel({ ...newChannel, icon: e.target.value })}
                  className="text-2xl text-center"
                  maxLength={4}
                />
              </div>
              <div className="space-y-1.5">
                <Label className="text-sm">Kategori</Label>
                <Select value={newChannel.category} onValueChange={(val) => setNewChannel({ ...newChannel, category: val })}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {Object.entries(CATEGORY_CONFIG).map(([val, cfg]) => (
                      <SelectItem key={val} value={val}>{cfg.label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-1.5 md:col-span-2">
                <Label className="text-sm">Deskripsi (Opsional)</Label>
                <Input
                  placeholder="Keterangan channel ini..."
                  value={newChannel.description}
                  onChange={(e) => setNewChannel({ ...newChannel, description: e.target.value })}
                />
              </div>
            </div>
            <div className="flex justify-end gap-2">
              <Button variant="outline" size="sm" onClick={() => { setShowAddForm(false); setNewChannel({ value: '', label: '', icon: '≡ƒôª', category: 'other', is_active: true, description: '' }); }}>
                Batal
              </Button>
              <Button size="sm" onClick={handleAddChannel} disabled={isSaving} className="bg-blue-600 hover:bg-blue-700">
                {isSaving ? <RefreshCw className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
                Simpan Channel
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* System Channels */}
      <Card className="border dark:border-gray-700">
        <CardHeader className="pb-3">
          <CardTitle className="text-sm font-semibold flex items-center gap-2">
            <Globe className="w-4 h-4 text-gray-500" />
            Channel Bawaan Sistem
            <Badge variant="outline" className="ml-auto text-xs">{SYSTEM_CHANNELS.length} channel</Badge>
          </CardTitle>
          <CardDescription className="text-xs">Ubah nama tampilan sesuai branding bisnis Anda</CardDescription>
        </CardHeader>
        <CardContent className="p-0">
          <div className="divide-y divide-gray-100 dark:divide-gray-800">
            {SYSTEM_CHANNELS.map((channel) => (
              <div key={channel.value} className="flex items-center gap-3 px-4 py-3 hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors">
                <span className="text-xl w-8 text-center flex-shrink-0">{channel.icon}</span>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap">
                    <p className="font-medium text-sm text-gray-900 dark:text-gray-100">
                      {systemChannelLabels[channel.value] || channel.label}
                    </p>
                    <span className="text-xs font-mono text-gray-400 dark:text-gray-500 bg-gray-100 dark:bg-gray-800 px-1.5 py-0.5 rounded">
                      {channel.value}
                    </span>
                    <Badge className={`text-xs ${CATEGORY_CONFIG[channel.category]?.color}`}>
                      {CATEGORY_CONFIG[channel.category]?.label}
                    </Badge>
                  </div>
                </div>
                <div className="flex-shrink-0 w-48">
                  <Input
                    size="sm"
                    placeholder={`Label: ${channel.label}`}
                    value={systemChannelLabels[channel.value] || ''}
                    onChange={(e) => {
                      const updated = { ...systemChannelLabels, [channel.value]: e.target.value };
                      setSystemChannelLabels(updated);
                    }}
                    onBlur={(e) => {
                      if (e.target.value !== (systemChannelLabels[channel.value] || '')) {
                        handleUpdateSystemLabel(channel.value, e.target.value);
                      }
                    }}
                    className="text-xs h-8"
                  />
                </div>
                <Badge className="bg-gray-100 text-gray-500 dark:bg-gray-800 dark:text-gray-400 text-xs flex-shrink-0">System</Badge>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Custom Channels */}
      <Card className="border dark:border-gray-700">
        <CardHeader className="pb-3">
          <CardTitle className="text-sm font-semibold flex items-center gap-2">
            <Smartphone className="w-4 h-4 text-purple-500" />
            Channel Custom
            <Badge variant="outline" className="ml-auto text-xs">{customChannels.length} channel</Badge>
          </CardTitle>
          <CardDescription className="text-xs">Channel yang Anda buat sendiri, termasuk variasi WhatsApp</CardDescription>
        </CardHeader>
        <CardContent className="p-0">
          {customChannels.length === 0 ? (
            <div className="text-center py-10 px-4">
              <Smartphone className="w-10 h-10 mx-auto mb-2 text-gray-300 dark:text-gray-600" />
              <p className="text-sm text-gray-500 dark:text-gray-400 mb-3">Belum ada channel custom</p>
              <Button size="sm" onClick={() => setShowAddForm(true)} variant="outline">
                <Plus className="w-4 h-4 mr-1" /> Tambah Channel
              </Button>
            </div>
          ) : (
            <div className="divide-y divide-gray-100 dark:divide-gray-800">
              {customChannels.map((channel, index) => (
                <div key={channel.value} className={`px-4 py-3 hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors ${!channel.is_active ? 'opacity-50' : ''}`}>
                  {editingChannel === index ? (
                    <EditChannelForm
                      channel={channel}
                      onSave={(data) => handleEditChannel(index, data)}
                      onCancel={() => setEditingChannel(null)}
                      isSaving={isSaving}
                    />
                  ) : (
                    <div className="flex items-center gap-3">
                      <GripVertical className="w-4 h-4 text-gray-300 dark:text-gray-600 cursor-grab flex-shrink-0" />
                      <span className="text-xl w-8 text-center flex-shrink-0">{channel.icon}</span>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap">
                          <p className="font-semibold text-sm text-gray-900 dark:text-gray-100">{channel.label}</p>
                          <span className="text-xs font-mono text-gray-400 bg-gray-100 dark:bg-gray-800 px-1.5 py-0.5 rounded">{channel.value}</span>
                          <Badge className={`text-xs ${CATEGORY_CONFIG[channel.category]?.color || CATEGORY_CONFIG.other.color}`}>
                            {CATEGORY_CONFIG[channel.category]?.label || channel.category}
                          </Badge>
                          {!channel.is_active && <Badge className="text-xs bg-gray-200 text-gray-500">Nonaktif</Badge>}
                        </div>
                        {channel.description && (
                          <p className="text-xs text-gray-400 mt-0.5 truncate">{channel.description}</p>
                        )}
                      </div>
                      <div className="flex items-center gap-2 flex-shrink-0">
                        <Switch
                          checked={channel.is_active !== false}
                          onCheckedChange={() => handleToggleChannel(index)}
                          className="scale-75"
                        />
                        <Button size="icon" variant="ghost" className="h-7 w-7" onClick={() => setEditingChannel(index)}>
                          <Edit className="w-3.5 h-3.5 text-gray-500" />
                        </Button>
                        <Button size="icon" variant="ghost" className="h-7 w-7" onClick={() => handleDeleteChannel(index)}>
                          <Trash2 className="w-3.5 h-3.5 text-red-500" />
                        </Button>
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Preview - Semua channel aktif */}
      <Card className="border dark:border-gray-700 bg-gray-50 dark:bg-gray-900/50">
        <CardHeader className="pb-2">
          <CardTitle className="text-sm font-semibold">Preview Channel di POS</CardTitle>
          <CardDescription className="text-xs">Channel aktif yang akan muncul saat transaksi</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex flex-wrap gap-2">
            {[
              ...SYSTEM_CHANNELS.map(c => ({ ...c, customLabel: systemChannelLabels[c.value] })),
              ...customChannels.filter(c => c.is_active !== false)
            ].map(channel => (
              <div key={channel.value} className="flex items-center gap-1.5 px-3 py-1.5 rounded-full border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm">
                <span>{channel.icon}</span>
                <span className="font-medium text-gray-800 dark:text-gray-200">
                  {channel.customLabel || channel.label}
                </span>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

function EditChannelForm({ channel, onSave, onCancel, isSaving }) {
  const [formData, setFormData] = useState({ ...channel });

  return (
    <div className="bg-blue-50 dark:bg-blue-950/30 rounded-xl p-3 space-y-3">
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        <div className="space-y-1">
          <Label className="text-xs">Ikon</Label>
          <Input value={formData.icon} onChange={(e) => setFormData({ ...formData, icon: e.target.value })} className="text-center text-xl h-8 text-sm" maxLength={4} />
        </div>
        <div className="md:col-span-2 space-y-1">
          <Label className="text-xs">Nama Tampilan</Label>
          <Input value={formData.label} onChange={(e) => setFormData({ ...formData, label: e.target.value })} className="h-8 text-sm" />
        </div>
        <div className="space-y-1">
          <Label className="text-xs">Kategori</Label>
          <Select value={formData.category} onValueChange={(val) => setFormData({ ...formData, category: val })}>
            <SelectTrigger className="h-8 text-xs"><SelectValue /></SelectTrigger>
            <SelectContent>
              {Object.entries(CATEGORY_CONFIG).map(([val, cfg]) => (
                <SelectItem key={val} value={val} className="text-xs">{cfg.label}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <div className="md:col-span-4 space-y-1">
          <Label className="text-xs">Deskripsi</Label>
          <Input value={formData.description || ''} onChange={(e) => setFormData({ ...formData, description: e.target.value })} className="h-8 text-sm" placeholder="Keterangan channel..." />
        </div>
      </div>
      <div className="flex justify-end gap-2">
        <Button variant="outline" size="sm" onClick={onCancel} className="h-7 text-xs">Batal</Button>
        <Button size="sm" onClick={() => onSave(formData)} disabled={isSaving} className="h-7 text-xs bg-blue-600 hover:bg-blue-700">
          {isSaving ? <RefreshCw className="w-3 h-3 mr-1 animate-spin" /> : <Save className="w-3 h-3 mr-1" />}
          Simpan
        </Button>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Smartphone, Save, Loader2, CheckCircle2, ExternalLink, Eye, EyeOff } from 'lucide-react';
import { toast } from 'sonner';

export default function WablasSettingsForm({ selectedCompany }) {
  const [settings, setSettings] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [showApiKey, setShowApiKey] = useState(false);
  const [showSecretKey, setShowSecretKey] = useState(false);

  // Γ£à PERSISTENT DEFAULT - Load from localStorage first
  const STORAGE_KEY = `SNISHOP_WABLAS_SETTINGS_${selectedCompany?.id}`;
  
  const [formData, setFormData] = useState(() => {
    // Try to load from localStorage for instant state
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (stored) {
        return JSON.parse(stored);
      }
    } catch (e) {}
    
    return {
      use_system_api: true,
      wablas_api_key: '',
      wablas_secret_key: '',
      wablas_domain: 'jogja.wablas.com',
      auto_send_receipt: false,
      receipt_message_template: 'Terima kasih telah berbelanja di {company_name}!\n\n≡ƒôï *Detail Transaksi*\nNo: {transaction_id}\nTanggal: {date}\nTotal: {total}\n\nKami tunggu kunjungan berikutnya! ≡ƒÖÅ'
    };
  });

  useEffect(() => {
    if (selectedCompany) {
      loadSettings();
    }
  }, [selectedCompany]);

  const loadSettings = async () => {
    try {
      setIsLoading(true);
      const settingsData = await base44.entities.CompanyWablasSettings.filter({
        company_id: selectedCompany.id
      });

      if (settingsData && settingsData.length > 0) {
        const setting = settingsData[0];
        setSettings(setting);
        const loadedData = {
          use_system_api: setting.use_system_api !== undefined ? setting.use_system_api : true,
          wablas_api_key: setting.wablas_api_key || '',
          wablas_secret_key: setting.wablas_secret_key || '',
          wablas_domain: setting.wablas_domain || 'jogja.wablas.com',
          auto_send_receipt: setting.auto_send_receipt || false,
          receipt_message_template: setting.receipt_message_template || 'Terima kasih telah berbelanja di {company_name}!\n\n≡ƒôï *Detail Transaksi*\nNo: {transaction_id}\nTanggal: {date}\nTotal: {total}\n\nKami tunggu kunjungan berikutnya! ≡ƒÖÅ'
        };
        setFormData(loadedData);
        
        // Γ£à PERSIST to localStorage for instant load next time
        try {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(loadedData));
        } catch (e) {}
      }
    } catch (error) {
      console.error('Load settings error:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSave = async (e) => {
    e.preventDefault();

    if (!formData.use_system_api && !formData.wablas_api_key.trim()) {
      toast.error('Wablas API Key wajib diisi jika tidak menggunakan API sistem');
      return;
    }

    try {
      setIsSaving(true);

      if (settings) {
        await base44.entities.CompanyWablasSettings.update(settings.id, {
          ...formData,
          company_id: selectedCompany.id,
          is_active: true
        });
        toast.success('Γ£à Settings berhasil diupdate!');
      } else {
        await base44.entities.CompanyWablasSettings.create({
          ...formData,
          company_id: selectedCompany.id,
          is_active: true
        });
        toast.success('Γ£à Settings berhasil disimpan!');
      }

      // Γ£à PERSIST to localStorage immediately
      try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
      } catch (e) {}

      loadSettings();
    } catch (error) {
      console.error('Save error:', error);
      toast.error('Gagal menyimpan: ' + error.message);
    } finally {
      setIsSaving(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-8">
        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
      </div>
    );
  }

  return (
    <Card className="bg-white dark:bg-gray-900 border-gray-200 dark:border-gray-700">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Smartphone className="w-5 h-5 text-green-600" />
          Integrasi Wablas WhatsApp
        </CardTitle>
        <CardDescription>
          Input API Key & Secret Key Wablas Anda untuk mengaktifkan fitur WhatsApp
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        
        {settings && (
          <Alert className="bg-green-50 dark:bg-green-900/20 border-green-200">
            <CheckCircle2 className="w-4 h-4 text-green-600" />
            <AlertDescription className="text-green-800 dark:text-green-300">
              Γ£à Wablas sudah terkonfigurasi! Anda bisa langsung connect device.
            </AlertDescription>
          </Alert>
        )}

        <form onSubmit={handleSave} className="space-y-4">
          <div className="flex items-center justify-between p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg mb-4">
            <div>
              <p className="text-sm font-medium text-gray-900 dark:text-white">Gunakan API Default Sistem</p>
              <p className="text-xs text-gray-600 dark:text-gray-400">API Wablas yang dikonfigurasi oleh Admin Owner</p>
            </div>
            <label className="relative inline-flex items-center cursor-pointer">
              <input
                type="checkbox"
                checked={formData.use_system_api}
                onChange={(e) => setFormData({ ...formData, use_system_api: e.target.checked })}
                className="sr-only peer"
              />
              <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none peer-focus:ring-4 peer-focus:ring-blue-300 dark:peer-focus:ring-blue-800 rounded-full peer dark:bg-gray-700 peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all dark:border-gray-600 peer-checked:bg-blue-600"></div>
            </label>
          </div>

          {!formData.use_system_api && (
            <>
              <div>
                <label className="text-sm font-medium mb-2 block">
                  Wablas API Key Sendiri *
                </label>
            <div className="relative">
              <Input
                type={showApiKey ? "text" : "password"}
                value={formData.wablas_api_key}
                onChange={(e) => setFormData({ ...formData, wablas_api_key: e.target.value })}
                placeholder="Masukkan API Key dari dashboard Wablas"
                className="pr-10"
                required
              />
              <button
                type="button"
                onClick={() => setShowApiKey(!showApiKey)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                {showApiKey ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
            <p className="text-xs text-gray-500 mt-1">
              Dapatkan di: <a href="https://solo.wablas.com/setting" target="_blank" className="text-blue-600 hover:underline inline-flex items-center gap-1">
                Wablas Dashboard ΓåÆ Settings ΓåÆ API Keys <ExternalLink className="w-3 h-3" />
              </a>
            </p>
          </div>

          <div>
            <label className="text-sm font-medium mb-2 block">
              Wablas Secret Key (Opsional)
            </label>
            <div className="relative">
              <Input
                type={showSecretKey ? "text" : "password"}
                value={formData.wablas_secret_key}
                onChange={(e) => setFormData({ ...formData, wablas_secret_key: e.target.value })}
                placeholder="Masukkan Secret Key (jika ada)"
                className="pr-10"
              />
              <button
                type="button"
                onClick={() => setShowSecretKey(!showSecretKey)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                {showSecretKey ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
          </div>

          <div>
            <label className="text-sm font-medium mb-2 block">
              Domain Wablas Server
            </label>
            <Input
              value={formData.wablas_domain}
              onChange={(e) => setFormData({ ...formData, wablas_domain: e.target.value })}
              placeholder="solo.wablas.com"
            />
            <p className="text-xs text-gray-500 mt-1">
              Default: jogja.wablas.com
            </p>
          </div>
            </>
          )}

          <div className="border-t border-gray-200 dark:border-gray-700 pt-4 mt-4">
            <h3 className="text-sm font-semibold mb-3 text-gray-900 dark:text-white">≡ƒöö Auto Blast Struk</h3>
            
            <div className="flex items-center justify-between p-3 bg-gray-50 dark:bg-gray-800 rounded-lg mb-3">
              <div>
                <p className="text-sm font-medium text-gray-900 dark:text-white">Kirim Struk Otomatis</p>
                <p className="text-xs text-gray-600 dark:text-gray-400">Kirim detail transaksi ke customer via WhatsApp</p>
              </div>
              <label className="relative inline-flex items-center cursor-pointer">
                <input
                  type="checkbox"
                  checked={formData.auto_send_receipt}
                  onChange={(e) => setFormData({ ...formData, auto_send_receipt: e.target.checked })}
                  className="sr-only peer"
                />
                <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none peer-focus:ring-4 peer-focus:ring-green-300 dark:peer-focus:ring-green-800 rounded-full peer dark:bg-gray-700 peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all dark:border-gray-600 peer-checked:bg-green-600"></div>
              </label>
            </div>

            {formData.auto_send_receipt && (
              <div>
                <label className="text-sm font-medium mb-2 block">
                  Template Pesan Struk
                </label>
                <textarea
                  value={formData.receipt_message_template}
                  onChange={(e) => setFormData({ ...formData, receipt_message_template: e.target.value })}
                  rows={6}
                  className="w-full px-3 py-2 border border-gray-300 dark:border-gray-700 rounded-lg bg-white dark:bg-gray-800 text-gray-900 dark:text-white text-sm"
                  placeholder="Template pesan..."
                />
                <p className="text-xs text-gray-500 mt-2">
                  Variabel tersedia: {'{company_name}'}, {'{transaction_id}'}, {'{date}'}, {'{total}'}, {'{items}'}, {'{customer_name}'}
                </p>
              </div>
            )}
          </div>

          <Button
            type="submit"
            disabled={isSaving}
            className="bg-green-600 hover:bg-green-700 w-full"
          >
            {isSaving ? (
              <>
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                Menyimpan...
              </>
            ) : (
              <>
                <Save className="w-4 h-4 mr-2" />
                Simpan Konfigurasi
              </>
            )}
          </Button>
        </form>

        <Alert className="bg-blue-50 dark:bg-blue-900/20 border-blue-200">
          <AlertDescription className="text-sm space-y-2">
            <p className="font-semibold">≡ƒô▒ Cara Setup:</p>
            <ol className="list-decimal list-inside space-y-1 ml-2 text-xs">
              <li>Daftar/Login ke <a href="https://wablas.com" target="_blank" className="text-blue-600 hover:underline">Wablas.com</a></li>
              <li>Buka Dashboard ΓåÆ Settings ΓåÆ API Keys</li>
              <li>Copy API Key Anda dan paste di form ini</li>
              <li>Connect device WhatsApp di dashboard Wablas</li>
              <li>Selesai! Kembali ke halaman WhatsApp Web untuk mulai kirim pesan</li>
            </ol>
          </AlertDescription>
        </Alert>
      </CardContent>
    </Card>
  );
}

import { useState, useRef, useEffect, useMemo } from 'react';
import { Bot, Sparkles, Send, Mic, Loader2, Folder } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { toast } from 'sonner';
import { motion, AnimatePresence } from 'framer-motion';
import ReactMarkdown from 'react-markdown';
import { base44 } from '@/api/base44Client';
import { Task } from '@/entities/Task';
import { Note } from '@/entities/Note';
import { Badge } from '@/components/ui/badge';

