                                Kasir Aktif Hari Ini
                                {activeCashiers.length > 0 && (
                                    <Badge className="ml-auto text-xs bg-indigo-100 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-400 border-0">
