                          >
                            <X className="w-4 h-4 mr-1" />
                            Tolak
                          </Button>
                        </div>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </motion.div>
            ))}
          </AnimatePresence>

          <div className="text-center text-xs text-gray-400 mt-2 pt-2 border-t border-gray-700">
            ≡ƒÆí Undangan juga tersedia di popup & notifikasi
          </div>
        </CardContent>
      </Card>
    </motion.div>
  );
