import { useState } from 'react';
import { base44 } from '@/api/base44Client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { toast } from 'sonner';
import { ArrowRightLeft, AlertTriangle } from 'lucide-react';
import { formatRupiah } from '@/components/utils/currencyFormatter';

export default function AccountTransfer({ accounts, user, mode, companyId = null, onSuccess }) {
  const [showDialog, setShowDialog] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [transferData, setTransferData] = useState({
    from_account_id: '',
    to_account_id: '',
    amount: 0,
    transfer_fee: 0,
    description: '',
    date: new Date().toISOString().split('T')[0]
  });

  const activeAccounts = accounts.filter(a => a.is_active);

  const fromAccount = activeAccounts.find(a => a.id === transferData.from_account_id);
  const toAccount = activeAccounts.find(a => a.id === transferData.to_account_id);

  const handleTransfer = async (e) => {
    e.preventDefault();

    if (!transferData.from_account_id || !transferData.to_account_id) {
      toast.error('Pilih rekening asal dan tujuan');
      return;
    }

    if (transferData.from_account_id === transferData.to_account_id) {
      toast.error('Rekening asal dan tujuan harus berbeda');
      return;
    }

    if (transferData.amount <= 0) {
      toast.error('Jumlah transfer harus lebih dari 0');
      return;
    }

    const totalDeduction = transferData.amount + (transferData.transfer_fee || 0);
    if (fromAccount && fromAccount.calculated_balance < totalDeduction) {
      toast.error(`Saldo ${fromAccount.name} tidak cukup`);
      return;
    }

    setIsLoading(true);
    try {
      // Create transfer record
      await base44.entities.FinancialRecord.create({
        user_id: user.id,
        company_id: companyId,
        account_id: transferData.from_account_id,
        transfer_to_account_id: transferData.to_account_id,
        type: 'transfer',
        amount: transferData.amount,
        transfer_fee: transferData.transfer_fee || 0,
        category: 'Transfer',
        description: transferData.description || `Transfer dari ${fromAccount?.name} ke ${toAccount?.name}`,
        date: new Date(transferData.date).toISOString(),
        mode: mode,
        source: 'manual'
      });

      // Broadcast update
      try {
        const channel = new BroadcastChannel('snishop_finance_updates');
        channel.postMessage({
          type: 'TRANSFER_CREATED',
          companyId: companyId || null,
          mode: mode,
          timestamp: Date.now()
        });
        channel.close();
      } catch (e) {}

      toast.success(`Γ£à Transfer ${formatRupiah(transferData.amount)} berhasil!`);
      setShowDialog(false);
      setTransferData({
        from_account_id: '',
        to_account_id: '',
        amount: 0,
        transfer_fee: 0,
        description: '',
        date: new Date().toISOString().split('T')[0]
      });

      if (onSuccess) onSuccess();
    } catch (error) {
      console.error('Transfer error:', error);
      toast.error('Gagal melakukan transfer');
    }
    setIsLoading(false);
  };

  return (
    <>
      <Button 
        onClick={() => setShowDialog(true)}
        variant="outline"
        className="border-blue-600 text-blue-400 hover:bg-blue-600/10"
      >
        <ArrowRightLeft className="w-4 h-4 mr-2" />
        Transfer Antar Rekening
      </Button>

      <Dialog open={showDialog} onOpenChange={setShowDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <ArrowRightLeft className="w-5 h-5 text-blue-600" />
              Transfer Antar Rekening
            </DialogTitle>
          </DialogHeader>
          <form onSubmit={handleTransfer} className="space-y-4">
            <div>
              <Label htmlFor="fromAccount">Dari Rekening *</Label>
              <Select
                value={transferData.from_account_id}
                onValueChange={(value) => setTransferData({ ...transferData, from_account_id: value })}
              >
                <SelectTrigger id="fromAccount">
                  <SelectValue placeholder="Pilih rekening sumber" />
                </SelectTrigger>
                <SelectContent>
                  {activeAccounts.map(acc => (
                    <SelectItem key={acc.id} value={acc.id}>
                      {acc.icon} {acc.name} - {formatRupiah(acc.calculated_balance || 0)}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label htmlFor="toAccount">Ke Rekening *</Label>
              <Select
                value={transferData.to_account_id}
                onValueChange={(value) => setTransferData({ ...transferData, to_account_id: value })}
              >
                <SelectTrigger id="toAccount">
                  <SelectValue placeholder="Pilih rekening tujuan" />
                </SelectTrigger>
                <SelectContent>
                  {activeAccounts
                    .filter(acc => acc.id !== transferData.from_account_id)
                    .map(acc => (
                      <SelectItem key={acc.id} value={acc.id}>
                        {acc.icon} {acc.name}
                      </SelectItem>
                    ))}
                </SelectContent>
              </Select>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label htmlFor="amount">Jumlah Transfer *</Label>
                <Input
                  id="amount"
                  type="number"
                  value={transferData.amount || ''}
                  onChange={(e) => setTransferData({ ...transferData, amount: Number(e.target.value) })}
                  placeholder="0"
                  required
                />
              </div>
              <div>
                <Label htmlFor="transferFee">Biaya Transfer</Label>
                <Input
                  id="transferFee"
                  type="number"
                  value={transferData.transfer_fee || 0}
                  onChange={(e) => setTransferData({ ...transferData, transfer_fee: Number(e.target.value) })}
                  placeholder="0"
                />
              </div>
            </div>

            <div>
              <Label htmlFor="transferDate">Tanggal</Label>
              <Input
                id="transferDate"
                type="date"
                value={transferData.date}
                onChange={(e) => setTransferData({ ...transferData, date: e.target.value })}
                required
              />
            </div>

            <div>
              <Label htmlFor="description">Keterangan</Label>
              <Input
                id="description"
                value={transferData.description || ''}
                onChange={(e) => setTransferData({ ...transferData, description: e.target.value })}
                placeholder="Keterangan transfer (optional)"
              />
            </div>

            {fromAccount && toAccount && transferData.amount > 0 && (
              <div className="p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-700 rounded-lg space-y-2">
                <p className="font-semibold text-sm">Ringkasan Transfer:</p>
                <div className="text-xs space-y-1">
                  <p>≡ƒôñ Dari: {fromAccount.name} ({formatRupiah(fromAccount.calculated_balance)})</p>
                  <p>≡ƒôÑ Ke: {toAccount.name}</p>
                  <p>≡ƒÆ░ Jumlah: {formatRupiah(transferData.amount)}</p>
                  {transferData.transfer_fee > 0 && (
                    <p>≡ƒÆ│ Biaya: {formatRupiah(transferData.transfer_fee)}</p>
                  )}
                  <p className="font-semibold pt-2 border-t">
                    Total Dipotong: {formatRupiah(transferData.amount + (transferData.transfer_fee || 0))}
                  </p>
                  <p className="text-muted-foreground">
                    Saldo {fromAccount.name} setelah transfer: {formatRupiah(fromAccount.calculated_balance - transferData.amount - (transferData.transfer_fee || 0))}
                  </p>
                </div>
                
                {fromAccount.calculated_balance < (transferData.amount + (transferData.transfer_fee || 0)) && (
                  <div className="flex items-center gap-2 text-red-600 text-xs mt-2">
                    <AlertTriangle className="w-4 h-4" />
                    <span>Saldo tidak cukup!</span>
                  </div>
                )}
              </div>
            )}

            <DialogFooter>
              <Button type="button" variant="outline" onClick={() => setShowDialog(false)}>
                Batal
              </Button>
              <Button 
                onClick={handleTransfer}
                disabled={isLoading || !transferData.from_account_id || !transferData.to_account_id}
              >
                {isLoading ? 'Memproses...' : 'Transfer Sekarang'}
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </>
  );
}

import { useState, useMemo } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Progress } from '@/components/ui/progress';
import { Badge } from '@/components/ui/badge';
import { toast } from 'sonner';
import {
    Plus, Edit, Trash2, TrendingUp, Wallet,
    ArrowUpRight, ArrowDownLeft, Target, Briefcase, Clock
} from 'lucide-react';
import { format, startOfMonth, endOfMonth, startOfYear, endOfYear } from 'date-fns';
import { id } from 'date-fns/locale';
import { withRetry } from '@/components/utils/apiHelpers';
import { formatCurrency } from '@/components/utils/currencyFormatter';

export default function BudgetManager({ budgets, records, allRecords = [], categories, user, mode, companyId = null, onUpdate }) {
    const [editingBudget, setEditingBudget] = useState(null);
    const [showDialog, setShowDialog] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [processingId, setProcessingId] = useState(null);
    const [viewDetail, setViewDetail] = useState(null); // 'receivable', 'debt', 'investment'

    // Γ£à FINANCIAL POSITION METRICS (Using allRecords for historical data)
    const { receivables, debts, investments, totalReceivable, totalDebt, totalInvestment } = useMemo(() => {
        // Unpaid Receivables (Piutang)
        const receivableList = allRecords
            .filter(r => r.type === 'receivable' && r.status === 'unpaid')
            .sort((a, b) => new Date(a.date) - new Date(b.date)); // Oldest first

        // Unpaid Debts (Hutang)
        const debtList = allRecords
            .filter(r => r.type === 'debt' && r.status === 'unpaid')
            .sort((a, b) => new Date(a.date) - new Date(b.date));

        // Total Investments
        const investmentList = allRecords
            .filter(r => r.type === 'investment')
            .sort((a, b) => new Date(b.date) - new Date(a.date)); // Newest first

        return {
            receivables: receivableList,
            debts: debtList,
            investments: investmentList,
            totalReceivable: receivableList.reduce((sum, r) => sum + (r.amount || 0), 0),
            totalDebt: debtList.reduce((sum, r) => sum + (r.amount || 0), 0),
            totalInvestment: investmentList.reduce((sum, r) => sum + (r.amount || 0), 0)
        };
    }, [allRecords]);


    // Γ£à BUDGET LOGIC (Using filtered 'records' prop)
    const expenseCategories = useMemo(() => {
        return (categories || []).filter(c => c.type === 'expense');
    }, [categories]);

    const calculateSpending = (budget) => {
        const now = new Date();
        let startDate, endDate;

        if (budget.period === 'monthly') {
            startDate = startOfMonth(now);
            endDate = endOfMonth(now);
        } else {
            startDate = startOfYear(now);
            endDate = endOfYear(now);
        }

        const spending = records
            .filter(r => {
                if (r.type !== 'expense') return false;
                const categoryMatch = r.category === budget.category ||
                    r.category?.toLowerCase() === budget.category?.toLowerCase();
                if (!categoryMatch) return false;
                const rDate = new Date(r.date);
                return rDate >= startDate && rDate <= endDate;
            })
            .reduce((sum, r) => sum + (r.amount || 0), 0);

        return spending;
    };

    const budgetAnalysis = useMemo(() => {
        return budgets.map(budget => {
            const spent = calculateSpending(budget);
            const percentage = budget.amount > 0 ? (spent / budget.amount) * 100 : 0;
            const remaining = budget.amount - spent;
            const isOverBudget = spent > budget.amount;
            const isNearLimit = percentage >= budget.alert_threshold;

            return {
                ...budget,
                spent,
                percentage: Math.min(percentage, 100),
                remaining,
                isOverBudget,
                isNearLimit
            };
        });
    }, [budgets, records]);

    // Γ£à HANDLERS
    const handleSaveBudget = async (e) => {
        e.preventDefault();
        setIsLoading(true);
        try {
            const dataToSave = { ...editingBudget, user_id: user.id, mode: mode, company_id: companyId };
            if (editingBudget.id) {
                await withRetry(() => base44.entities.Budget.update(editingBudget.id, dataToSave));
            } else {
                await withRetry(() => base44.entities.Budget.create(dataToSave));
            }
            toast.success('Anggaran berhasil disimpan');
            setShowDialog(false);
            setEditingBudget(null);
            if (onUpdate) onUpdate();
        } catch (error) {
            toast.error('Gagal menyimpan anggaran');
            console.error(error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteBudget = async (budgetId) => {
        if (!confirm('Hapus anggaran ini?')) return;
        try {
            await withRetry(() => base44.entities.Budget.delete(budgetId));
            toast.success('Anggaran dihapus');
            if (onUpdate) onUpdate();
        } catch (error) {
            toast.error('Gagal menghapus');
        }
    };

    const handleMarkAsPaid = async (record) => {
        if (!confirm(`Tandai ${record.type === 'debt' ? 'hutang' : 'piutang'} senilai ${formatCurrency(record.amount)} sebagai LUNAS?`)) return;

        setProcessingId(record.id);
        try {
            await withRetry(() => base44.entities.FinancialRecord.update(record.id, {
                status: 'paid',
                updated_at: new Date().toISOString()
            }));
            toast.success('Status berhasil diperbarui! ≡ƒÄë');
            if (onUpdate) onUpdate();
        } catch (error) {
            toast.error('Gagal memperbarui status');
            console.error(error);
        } finally {
            setProcessingId(null);
        }
    };

    // Γ£à SUB-COMPONENTS
    const TransactionList = ({ items, type }) => (
        <div className="space-y-2 mt-2">
            {items.length === 0 ? (
                <p className="text-sm text-gray-500 italic py-2">Tidak ada data {type === 'receivable' ? 'piutang' : type === 'debt' ? 'hutang' : 'investasi'} aktif.</p>
            ) : (
                items.map(item => (
                    <div key={item.id} className="flex items-center justify-between p-3 bg-gray-900 border border-gray-800 rounded-lg hover:border-gray-700 transition-colors">
                        <div className="flex items-center gap-3">
                            <div className={`p-2 rounded-full ${type === 'receivable' ? 'bg-green-900/30 text-green-400' : type === 'debt' ? 'bg-red-900/30 text-red-400' : 'bg-purple-900/30 text-purple-400'}`}>
                                {type === 'receivable' ? <ArrowUpRight className="w-4 h-4" /> :
                                    type === 'debt' ? <ArrowDownLeft className="w-4 h-4" /> :
                                        <TrendingUp className="w-4 h-4" />}
                            </div>
                            <div>
                                <p className="text-sm font-semibold text-white">{item.contact_name || 'Tanpa Nama'}</p>
                                <div className="flex items-center gap-2 text-xs text-gray-400">
                                    <Clock className="w-3 h-3" />
                                    <span>{format(new Date(item.date), 'dd MMM yyyy', { locale: id })}</span>
                                    <span>ΓÇó</span>
                                    <span>{item.description}</span>
                                </div>
                            </div>
                        </div>
                        <div className="flex flex-col items-end gap-1">
                            <span className="text-sm font-bold text-white">{formatCurrency(item.amount)}</span>
                            {type !== 'investment' && (
                                <Button
                                    size="xs"
                                    variant="outline"
                                    disabled={processingId === item.id}
                                    onClick={() => handleMarkAsPaid(item)}
                                    className="h-6 text-[10px] bg-gray-800 border-gray-700 hover:bg-green-900/50 hover:text-green-400 hover:border-green-700"
                                >
                                    {processingId === item.id ? '...' : 'Tandai Lunas'}
                                </Button>
                            )}
                        </div>
                    </div>
                ))
            )}
        </div>
    );

    return (
        <div className="space-y-6">

            {/* === SECTION 1: FINANCIAL POSITION DASHBOARD === */}
            <div>
                <h2 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
                    <Briefcase className="w-5 h-5 text-blue-400" />
                    Posisi Keuangan & Aset
                </h2>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {/* CARD 1: PIUTANG (Receivables) */}
                    <Card className="bg-gray-900 border-gray-800 hover:border-green-800 transition-all cursor-pointer" onClick={() => setViewDetail(viewDetail === 'receivable' ? null : 'receivable')}>
                        <CardHeader className="pb-2">
                            <p className="text-xs font-medium text-gray-400 mb-1">Total Piutang (Belum Lunas)</p>
                            <div className="flex justify-between items-center">
                                <CardTitle className="text-xl text-green-500">{formatCurrency(totalReceivable)}</CardTitle>
                                <ArrowUpRight className="w-5 h-5 text-green-500" />
                            </div>
                        </CardHeader>
                        <CardContent>
                            <div className="flex justify-between text-xs text-gray-500">
                                <span>{receivables.length} Customer</span>
                                <span className="text-blue-400 hover:underline">Lihat Detail {viewDetail === 'receivable' ? 'Γû▓' : 'Γû╝'}</span>
                            </div>
                            {viewDetail === 'receivable' && <TransactionList items={receivables} type="receivable" />}
                        </CardContent>
                    </Card>

                    {/* CARD 2: HUTANG (Debt) */}
                    <Card className="bg-gray-900 border-gray-800 hover:border-red-800 transition-all cursor-pointer" onClick={() => setViewDetail(viewDetail === 'debt' ? null : 'debt')}>
                        <CardHeader className="pb-2">
                            <p className="text-xs font-medium text-gray-400 mb-1">Total Hutang (Belum Lunas)</p>
                            <div className="flex justify-between items-center">
                                <CardTitle className="text-xl text-red-500">{formatCurrency(totalDebt)}</CardTitle>
                                <ArrowDownLeft className="w-5 h-5 text-red-500" />
                            </div>
                        </CardHeader>
                        <CardContent>
                            <div className="flex justify-between text-xs text-gray-500">
                                <span>{debts.length} Invoice</span>
                                <span className="text-blue-400 hover:underline">Lihat Detail {viewDetail === 'debt' ? 'Γû▓' : 'Γû╝'}</span>
                            </div>
                            {viewDetail === 'debt' && <TransactionList items={debts} type="debt" />}
                        </CardContent>
                    </Card>

                    {/* CARD 3: INVESTASI (Investment) */}
                    <Card className="bg-gray-900 border-gray-800 hover:border-purple-800 transition-all cursor-pointer" onClick={() => setViewDetail(viewDetail === 'investment' ? null : 'investment')}>
                        <CardHeader className="pb-2">
                            <p className="text-xs font-medium text-gray-400 mb-1">Total Investasi</p>
                            <div className="flex justify-between items-center">
                                <CardTitle className="text-xl text-purple-500">{formatCurrency(totalInvestment)}</CardTitle>
                                <TrendingUp className="w-5 h-5 text-purple-500" />
                            </div>
                        </CardHeader>
                        <CardContent>
                            <div className="flex justify-between text-xs text-gray-500">
                                <span>{investments.length} Portofolio</span>
                                <span className="text-blue-400 hover:underline">Lihat Detail {viewDetail === 'investment' ? 'Γû▓' : 'Γû╝'}</span>
                            </div>
                            {viewDetail === 'investment' && <TransactionList items={investments} type="investment" />}
                        </CardContent>
                    </Card>
                </div>
            </div>

            <div className="border-t border-gray-800 my-6"></div>

            {/* === SECTION 2: BUDGET MANAGEMENT (Existing) === */}
            <div className="space-y-4">
                <div className="flex justify-between items-center">
                    <h2 className="text-xl font-bold text-white flex items-center gap-2">
                        <Target className="w-5 h-5 text-yellow-400" />
                        Target Anggaran (Budgeting)
                    </h2>
                    <Button
                        size="sm"
                        onClick={() => {
                            setEditingBudget({
                                name: '', category: '', amount: 0, period: 'monthly', alert_threshold: 80
                            });
                            setShowDialog(true);
                        }}
                        className="bg-blue-600 hover:bg-blue-700 text-xs"
                    >
                        <Plus className="w-3 h-3 mr-1" />
                        Buat Anggaran
                    </Button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {budgetAnalysis.map(budget => (
                        <Card key={budget.id} className={`bg-gray-900 border-gray-700 ${budget.isOverBudget ? 'border-red-900/50 bg-red-900/10' : budget.isNearLimit ? 'border-yellow-900/50 bg-yellow-900/10' : ''}`}>
                            <CardHeader className="pb-2 p-3">
                                <div className="flex justify-between items-start">
                                    <div>
                                        <CardTitle className="text-sm font-bold text-white">{budget.name}</CardTitle>
                                        <div className="flex items-center gap-1.5 mt-1">
                                            <Badge variant="outline" className="text-[10px] h-5 px-1 bg-gray-800 border-gray-600 text-gray-300">
                                                {budget.category}
                                            </Badge>
                                            <span className="text-[10px] text-gray-500">{budget.period === 'monthly' ? 'Bulanan' : 'Tahunan'}</span>
                                        </div>
                                    </div>
                                    <div className="flex gap-1">
                                        <Button variant="ghost" size="icon" className="h-6 w-6 text-gray-400 hover:text-white" onClick={() => { setEditingBudget(budget); setShowDialog(true); }}>
                                            <Edit className="w-3 h-3" />
                                        </Button>
                                        <Button variant="ghost" size="icon" className="h-6 w-6 text-red-500 hover:text-red-400" onClick={() => handleDeleteBudget(budget.id)}>
                                            <Trash2 className="w-3 h-3" />
                                        </Button>
                                    </div>
                                </div>
                            </CardHeader>
                            <CardContent className="p-3">
                                <div className="space-y-2">
                                    <div className="flex justify-between text-xs text-gray-300">
                                        <span>Terpakai</span>
                                        <span className="font-semibold">{formatCurrency(budget.spent)} / {formatCurrency(budget.amount)}</span>
                                    </div>
                                    <Progress value={budget.percentage} className={`h-1.5 bg-gray-700 ${budget.isOverBudget ? '[&>div]:bg-red-500' : budget.isNearLimit ? '[&>div]:bg-yellow-500' : '[&>div]:bg-blue-500'}`} />
                                    <div className="flex justify-between items-center pt-1">
                                        <span className="text-[10px] text-gray-500">{budget.percentage.toFixed(0)}% digunakan</span>
                                        <span className={`text-xs font-semibold ${budget.remaining < 0 ? 'text-red-400' : 'text-green-400'}`}>
                                            {budget.remaining < 0 ? 'Over' : 'Sisa'} {formatCurrency(Math.abs(budget.remaining))}
                                        </span>
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    ))}

                    {budgetAnalysis.length === 0 && (
                        <div className="col-span-full text-center py-8 bg-gray-900 border border-gray-800 rounded-lg border-dashed">
                            <Wallet className="w-8 h-8 mx-auto text-gray-600 mb-2" />
                            <p className="text-gray-500 text-sm">Belum ada anggaran yang dibuat.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* === DIALOG EDITOR === */}
            <Dialog open={showDialog} onOpenChange={setShowDialog}>
                <DialogContent className="bg-gray-900 border-gray-700 text-white sm:max-w-md">
                    <DialogHeader>
                        <DialogTitle>{editingBudget?.id ? 'Edit Anggaran' : 'Buat Anggaran Baru'}</DialogTitle>
                        <CardDescription className="text-gray-400">Atur batas pengeluaran untuk kategori tertentu.</CardDescription>
                    </DialogHeader>
                    <form onSubmit={handleSaveBudget} className="space-y-4">
                        <div className="space-y-1">
                            <Label htmlFor="budgetName" className="text-xs">Nama Anggaran</Label>
                            <Input id="budgetName" className="bg-gray-800 border-gray-700" value={editingBudget?.name || ''} onChange={(e) => setEditingBudget({ ...editingBudget, name: e.target.value })} placeholder="Contoh: Operasional Harian" required />
                        </div>
                        <div className="space-y-1">
                            <Label htmlFor="budgetCategory" className="text-xs">Kategori Pengeluaran</Label>
                            <Select value={editingBudget?.category || ''} onValueChange={(value) => setEditingBudget({ ...editingBudget, category: value })}>
                                <SelectTrigger className="bg-gray-800 border-gray-700"><SelectValue placeholder="Pilih Kategori" /></SelectTrigger>
                                <SelectContent className="bg-gray-800 border-gray-700 text-white">
                                    {expenseCategories.map(cat => (
                                        <SelectItem key={cat.id} value={cat.name}>{cat.name}</SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                            <div className="space-y-1">
                                <Label htmlFor="amount" className="text-xs">Nominal (Rp)</Label>
                                <Input id="amount" type="number" className="bg-gray-800 border-gray-700" value={editingBudget?.amount || ''} onChange={(e) => setEditingBudget({ ...editingBudget, amount: Number(e.target.value) })} required />
                            </div>
                            <div className="space-y-1">
                                <Label htmlFor="period" className="text-xs">Periode</Label>
                                <Select value={editingBudget?.period || 'monthly'} onValueChange={(value) => setEditingBudget({ ...editingBudget, period: value })}>
                                    <SelectTrigger className="bg-gray-800 border-gray-700"><SelectValue /></SelectTrigger>
                                    <SelectContent className="bg-gray-800 border-gray-700 text-white">
                                        <SelectItem value="monthly">Bulanan</SelectItem>
                                        <SelectItem value="yearly">Tahunan</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                        </div>
                        <DialogFooter className="pt-2">
                            <Button type="button" variant="ghost" size="sm" onClick={() => setShowDialog(false)} className="text-gray-400">Batal</Button>
                            <Button type="submit" size="sm" className="bg-blue-600 hover:bg-blue-700">Simpan</Button>
                        </DialogFooter>
                    </form>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Plus, Edit, Trash2, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { withRetry } from '@/components/utils/apiHelpers';

const emojiList = ['≡ƒÆ░', '≡ƒÅá', '≡ƒÜù', '≡ƒìö', '≡ƒÄ¼', '≡ƒÅÑ', '≡ƒôÜ', 'Γ£ê∩╕Å', '≡ƒæò', '≡ƒÄ«', 'ΓÜí', '≡ƒô▒', '≡ƒÆ╝', '≡ƒÄô', '≡ƒ¢Æ', '≡ƒìò', '≡ƒÆ│', '≡ƒÅ¬', '≡ƒÄ»', 'Γ¡É'];

export default function CategoryManager({ categories, user, mode, onUpdate, companyId = null }) {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingCategory, setEditingCategory] = useState(null);
  const [isSaving, setIsSaving] = useState(false);
  const [activeMode, setActiveMode] = useState(mode);
  const [showDiagnostic, setShowDiagnostic] = useState(false);
  const [allDbCategories, setAllDbCategories] = useState([]);

  const [formData, setFormData] = useState({
    name: '',
    type: 'expense',
    mode: mode,
    icon: '≡ƒÆ░'
  });

  useEffect(() => {
    setActiveMode(mode);
    console.log('≡ƒôè CategoryManager Props:');
    console.log('  Mode:', mode);
    console.log('  Company ID:', companyId);
    console.log('  Categories received:', categories?.length || 0);
    console.log('  Categories:', categories);
  }, [mode, categories, companyId]);

  // ≡ƒöì DATABASE CHECK FUNCTION
  const checkDatabase = async () => {
    if (!user || !user.id) {
      toast.error('User tidak ditemukan');
      console.error('Γ¥î No user!');
      return;
    }

    console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
    console.log('≡ƒöì DATABASE CHECK - Loading ALL categories');
    console.log('   User ID:', user.id);
    console.log('   Current Mode:', mode);
    console.log('   Current Company ID:', companyId || 'null');
    console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');

    try {
      // Load ALL categories for this user (no company filter)
      const allCats = await base44.entities.TransactionCategory.filter({ user_id: user.id });

      console.log('∩┐╜ TOTAL IN DATABASE:', allCats?.length || 0);

      if (allCats && allCats.length > 0) {
        const personal = allCats.filter(c => c.mode === 'personal' || !c.company_id);
        const business = allCats.filter(c => c.mode === 'business' && c.company_id);
        const orphan = allCats.filter(c => c.mode === 'business' && !c.company_id);
        const forThisCompany = companyId ? allCats.filter(c => c.company_id === companyId) : [];

        console.log('≡ƒôê BREAKDOWN:');
        console.log('   Personal:', personal.length);
        console.log('   Business (with company_id):', business.length);
        console.log('   Orphan (business, no company_id):', orphan.length);
        if (companyId) {
          console.log('   For CURRENT company:', forThisCompany.length);
        }

        console.log('∩┐╜ ALL CATEGORIES LIST:');
        allCats.forEach((cat, i) => {
          const status = !cat.company_id ? 'PERSONAL' :
            cat.company_id === companyId ? 'CURRENT_COMPANY Γ£à' : 'OTHER_COMPANY';
          console.log(`   ${i + 1}. ${cat.name} | mode:${cat.mode} | company_id:${cat.company_id || 'null'} | ${status}`);
        });
      } else {
        console.log('Γ¥î NO CATEGORIES FOUND IN DATABASE!');
      }

      console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');

      setAllDbCategories(allCats || []);
      setShowDiagnostic(true);
      toast.success(`Ditemukan ${allCats?.length || 0} kategori total di database`);
    } catch (error) {
      console.error('Γ¥î Error checking database:', error);
      console.error('Error details:', error.message);
      toast.error('Gagal cek database: ' + error.message);
    }
  };

  const handleCreate = () => {
    setEditingCategory(null);
    setFormData({
      name: '',
      type: 'expense',
      mode: mode, // Use current mode prop directly
      icon: '≡ƒÆ░'
    });
    console.log('≡ƒô¥ Creating new category in mode:', mode);
    setIsModalOpen(true);
  };

  const handleEdit = (category) => {
    setEditingCategory(category);
    setFormData({
      name: category.name,
      type: category.type,
      mode: category.mode,
      icon: category.icon || '≡ƒÆ░'
    });
    setIsModalOpen(true);
  };

  const handleDelete = async (categoryId) => {
    if (!confirm('Yakin hapus kategori ini? Data transaksi dengan kategori ini tidak akan terhapus.')) {
      return;
    }

    try {
      await withRetry(() => base44.entities.TransactionCategory.delete(categoryId));
      toast.success("Kategori berhasil dihapus");
      if (onUpdate) onUpdate(); // INSTANT reload
    } catch (error) {
      toast.error("Gagal menghapus kategori");
      console.error(error);
    }
  };

  const handleSubmit = async () => {
    if (!formData.name.trim()) {
      toast.error("Nama kategori wajib diisi");
      return;
    }

    // Γ£à VALIDATION: Check user
    if (!user || !user.id) {
      console.error('Γ¥î CRITICAL ERROR: No user ID!');
      toast.error("Error: User tidak ditemukan. Coba login ulang.");
      setIsSaving(false);
      return;
    }

    // Γ£à VALIDATION: Check company ID for business mode
    if (mode === 'business' && !companyId) {
      console.error('Γ¥î CRITICAL ERROR: Company mode but no companyId!');
      toast.error("Error: Company ID tidak ditemukan. Refresh halaman dan coba lagi.");
      setIsSaving(false);
      return;
    }

    setIsSaving(true);
    try {
      console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
      console.log('≡ƒöì DEBUG: Checking props BEFORE save');
      console.log('  mode prop:', mode);
      console.log('  companyId prop:', companyId);
      console.log('  user.id:', user.id);
      console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');

      // Γ£à ROBUST FIX: Use companyId existence, NOT mode prop!
      // If companyId exists = Company mode, otherwise = Personal mode
      const isCompanyMode = !!companyId;
      const actualMode = isCompanyMode ? 'business' : 'personal';
      const actualCompanyId = isCompanyMode ? companyId : null;

      console.log('Γ£à COMPUTED VALUES:');
      console.log('  isCompanyMode:', isCompanyMode);
      console.log('  actualMode:', actualMode);
      console.log('  actualCompanyId:', actualCompanyId);

      // Γ£à Build data to save
      const dataToSave = {
        name: formData.name.trim(),
        type: formData.type,
        icon: formData.icon,
        user_id: user.id,
        mode: actualMode,  // Use computed mode!
        company_id: actualCompanyId  // Use computed company_id!
      };

      console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
      console.log('≡ƒÆ╛ SAVING CATEGORY');
      console.log('  Final data to save:', JSON.stringify(dataToSave, null, 2));
      console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');

      let result;
      if (editingCategory) {
        result = await withRetry(() => base44.entities.TransactionCategory.update(editingCategory.id, dataToSave));
        console.log('Γ£à UPDATE Response from base44:', JSON.stringify(result, null, 2));
        toast.success("Γ£à Kategori berhasil diperbarui!");
