import { toast } from 'sonner';
import { formatRupiah } from '@/components/utils/currencyFormatter';

const monthlyLimits = {
  free: 300, pro: 1500, business: 3000, advanced: 6000, enterprise: 9000
};

export default function FinanceAIAssistant({ user, mode = 'personal', companyId = null, accounts = [], onRecordCreated, onUpdateData }) {
  const [messages, setMessages] = useState([
    { role: 'assistant', content: 'Halo! Saya asisten keuangan AI Anda. ≡ƒºá\n\n≡ƒÆ¼ **Chat (OFFLINE, 0 kredit)**:\nΓÇó "makan 10rb" ΓåÆ otomatis tercatat\nΓÇó "gaji 5jt kemarin" ΓåÆ tanggal kemarin\nΓÇó "bensin 50rb dan kopi 15rb" ΓåÆ 2 transaksi\nΓÇó "bayar listrik 200rb kemarin jam 3 siang"\n\n≡ƒôä Upload struk/PDF (butuh kredit AI)\n≡ƒô╖ Foto struk (butuh kredit AI)\n≡ƒÄñ Voice (butuh kredit AI)\n\n≡ƒÆí Pilih rekening di bawah sebelum mencatat!' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [customCategories, setCustomCategories] = useState([]);
  const [budgetCategories, setBudgetCategories] = useState([]); // Γ£à NEW: Store budget categories for AI Priority
  const [progress, setProgress] = useState(0);
  const [selectedAccountId, setSelectedAccountId] = useState('');

  const fileInputRef = useRef(null);
  const cameraInputRef = useRef(null);
  const messagesEndRef = useRef(null);
  const recognitionRef = useRef(null);
  const silenceTimerRef = useRef(null);

  const monthlyUsage = user?.ai_monthly_usage || 0;
  const addonQuota = user?.ai_addon_quota || 0;
  const totalQuota = (monthlyLimits[user?.subscription_plan || 'free'] || 0) + addonQuota;
  const canUseAI = monthlyUsage < totalQuota;

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  useEffect(() => {
    // Update welcome message dynamically based on mode
    if (messages.length === 1) {
      if (mode === 'business') {
        setMessages([{ role: 'assistant', content: `Halo! Saya asisten keuangan AI Anda. ≡ƒºá\n\n≡ƒÆ¼ **Chat (OFFLINE, 0 kredit)**:\nΓÇó "makan 10rb" ΓåÆ otomatis tercatat\nΓÇó "gaji 5jt kemarin" ΓåÆ tanggal kemarin\nΓÇó "bensin 50rb dan kopi 15rb" ΓåÆ 2 transaksi\nΓÇó "bayar listrik 200rb kemarin jam 3 siang"\n\n≡ƒôä Upload struk/PDF (butuh kredit AI)\n≡ƒô╖ Foto struk (butuh kredit AI)\n≡ƒÄñ Voice (butuh kredit AI)\n\n≡ƒÆí Pilih rekening di bawah sebelum mencatat!\n\n≡ƒÅó **Mode Bisnis Aktif:** AI secara otomatis memprioritaskan kategori dari tab Anggaran (Budget) Anda.` }]);
      } else {
        setMessages([{ role: 'assistant', content: `Halo! Saya asisten keuangan AI Anda. ≡ƒºá\n\n≡ƒÆ¼ **Chat (OFFLINE, 0 kredit)**:\nΓÇó "makan 10rb" ΓåÆ otomatis tercatat\nΓÇó "gaji 5jt kemarin" ΓåÆ tanggal kemarin\nΓÇó "bensin 50rb dan kopi 15rb" ΓåÆ 2 transaksi\nΓÇó "bayar listrik 200rb kemarin jam 3 siang"\n\n≡ƒôä Upload struk/PDF (butuh kredit AI)\n≡ƒô╖ Foto struk (butuh kredit AI)\n≡ƒÄñ Voice (butuh kredit AI)\n\n≡ƒÆí Pilih rekening di bawah sebelum mencatat!` }]);
      }
    }
  }, [mode]);

  useEffect(() => {
    const fetchData = async () => {
      if (user) {
        try {
          let query = {};
          if (mode === 'business' && companyId) {
            query = { user_id: user.id, mode: 'business', company_id: companyId };
          } else {
            query = { user_id: user.id, mode: 'personal', company_id: null };
          }

          const [cats, budgs] = await Promise.all([
            base44.entities.TransactionCategory.filter(query),
            base44.entities.Budget.filter(query)
          ]);

          console.log(`≡ƒÅ╖∩╕Å AI Categories loaded for ${mode} mode:`, cats?.length || 0);
          setCustomCategories(cats || []);

          if (budgs) {
            const bCats = budgs.map(b => b.category).filter(Boolean);
            setBudgetCategories([...new Set(bCats)]);
            console.log(`≡ƒÄ» AI Budget Targets loaded:`, bCats?.length || 0);
          } else {
            setBudgetCategories([]);
          }
        } catch (error) {
          console.error('Error fetching data for AI:', error);
          setCustomCategories([]);
          setBudgetCategories([]);
        }
      }
    };
    fetchData();
  }, [user, mode, companyId]);

  const updateUsage = async (credits) => {
    try {
      const newUsage = (user?.ai_monthly_usage || 0) + credits;
      await base44.auth.updateMe({ ai_monthly_usage: newUsage });
    } catch (error) {
      console.error('Error updating usage:', error);
    }
  };

  const processAndCreateRecords = async (transactions, source) => {
    const isImage = source === 'ai_scan';
    let creditsConsumed = isImage ? 5 : transactions.length;
    const currentAvailableQuota = totalQuota - (user?.ai_monthly_usage || 0);

    if (currentAvailableQuota < creditsConsumed) {
      toast.error(`Gagal mencatat. Butuh ${creditsConsumed} kredit, kuota Anda tidak cukup.`);
      setMessages((prev) => [...prev, { role: 'assistant', content: `Analisis berhasil, ditemukan ${transactions.length} transaksi. Namun kuota tidak cukup untuk mencatat (butuh ${creditsConsumed} kredit).` }]);
      return false;
    }

    const recordsToCreate = transactions.map((tx) => ({
      ...tx,
      user_id: user.id,
      source: source,
      mode: mode,
      company_id: companyId || null,
      account_id: selectedAccountId || null
    }));

    console.log('≡ƒÆ╛ Creating records:', recordsToCreate.length, '| Mode:', mode, '| Company:', companyId || 'Personal');

    try {
      setProgress(80);
      await base44.entities.FinancialRecord.bulkCreate(recordsToCreate);
      setProgress(100);
      await updateUsage(creditsConsumed);

      try {
        const channel = new BroadcastChannel('snishop_finance_updates');
        channel.postMessage({
          type: 'RECORDS_CREATED',
          companyId: companyId || null,
          mode: mode,
          count: transactions.length,
          timestamp: Date.now()
        });
        channel.close();
        console.log('≡ƒôí Finance records broadcasted | Mode:', mode, '| Company:', companyId || 'Personal');
      } catch (e) {
        console.warn('BroadcastChannel error:', e);
      }

      toast.success(`Γ£à ${transactions.length} transaksi berhasil dicatat!`, {
        description: `${creditsConsumed} kredit AI telah digunakan.`,
        duration: 3000
      });
      setMessages((prev) => [...prev, { role: 'assistant', content: `Sukses! ${transactions.length} transaksi telah dicatat ke mode ${mode}. Digunakan ${creditsConsumed} kredit.` }]);

      // Γ£à INSTANT OPTIMISTIC UPDATE: Send data back to parent immediately
      if (onRecordCreated) {
        console.log('ΓÜí Sending optimistic update to parent...');
        onRecordCreated(recordsToCreate);
      }

      // Γ£à Trigger data reload via callback - with small delay for DB consistency
      if (onUpdateData) {
        console.log('≡ƒôí Triggering data refresh after DB save...');
        // Small delay to ensure DB has committed the writes
        await new Promise(resolve => setTimeout(resolve, 800)); // Increased slightly to be safe
        console.log('≡ƒôí Calling loadData() now...');
        await onUpdateData();
        console.log('Γ£à Data refresh completed!');
      }

      return true;
    } catch (error) {
      console.error('Error creating records:', error);
      toast.error('Gagal menyimpan transaksi ke database.');
      setMessages((prev) => [...prev, { role: 'assistant', content: 'Maaf, gagal menyimpan ke database. Coba lagi.' }]);
      return false;
    }
  };

  const handleFileUpload = useCallback(async (file) => {
    if (!file) return;

    const currentAvailableQuota = totalQuota - (user?.ai_monthly_usage || 0);
    const isImage = file.type.startsWith('image/');
    const isPdf = file.type === 'application/pdf';
    const isExcel = file.type.includes('spreadsheet') || file.type.includes('excel') || file.name.endsWith('.xlsx') || file.name.endsWith('.xls');

    if (!isImage && !isPdf && !isExcel) {
      toast.error('Hanya file gambar (JPG, PNG), PDF, atau Excel yang didukung.');
      setMessages((prev) => [...prev, { role: 'assistant', content: 'Maaf, hanya file gambar (JPG, PNG), PDF, atau Excel yang didukung.' }]);
      return;
    }

    let requiredCredits = isImage ? 5 : 1;
    if (currentAvailableQuota < requiredCredits) {
      toast.error(`Kuota AI tidak cukup. Memindai ${isImage ? 'gambar' : isPdf ? 'PDF' : 'Excel'} butuh minimal ${requiredCredits} kredit.`);
      setMessages((prev) => [...prev, { role: 'assistant', content: `Kuota AI tidak cukup. Butuh minimal ${requiredCredits} kredit.` }]);
      return;
    }

    setIsLoading(true);
    setProgress(10);
    setMessages((prev) => [...prev, { role: 'assistant', content: `Menganalisis file ${file.name}...` }]);

    try {
      setProgress(20);
      const uploadResult = await UploadFile({ file });
      if (!uploadResult?.file_url) throw new Error('Gagal mengunggah file.');
      setProgress(40);

      const jsonSchema = {
        type: "object",
        properties: {
          transactions: {
            type: "array",
            items: {
              type: "object",
              properties: {
                date: {
                  type: "string",
                  format: "date-time",
                  description: "Date in ISO 8601 format (YYYY-MM-DDTHH:mm:ss). Indonesian date format DD/MM/YYYY"
                },
                description: { type: "string" },
                category: { type: "string" },
                amount: { type: "number" },
                type: { type: "string", enum: ["income", "expense"] }
              },
              required: ["date", "description", "amount", "type"]
            }
          }
        }
      };

      const extractionResult = await ExtractDataFromUploadedFile({
        file_url: uploadResult.file_url,
        json_schema: jsonSchema
      });
      setProgress(70);

      if (extractionResult.status !== 'success' || !extractionResult.output?.transactions) {
        throw new Error(extractionResult.details || 'Gagal mengekstrak data dari dokumen.');
      }

      const transactions = extractionResult.output.transactions;
      if (transactions.length === 0) {
        toast.info('Tidak ada transaksi yang ditemukan di dalam dokumen.');
        setIsLoading(false);
        setMessages((prev) => [...prev, { role: 'assistant', content: 'Analisis selesai, namun tidak ada transaksi yang dapat dicatat.' }]);
        return;
      }

      const validatedTransactions = transactions.map((tx) => {
        try {
          const date = new Date(tx.date);
          if (isNaN(date.getTime())) {
            return { ...tx, date: new Date().toISOString() };
          }
          return tx;
        } catch (error) {
          return { ...tx, date: new Date().toISOString() };
        }
      });

      await processAndCreateRecords(validatedTransactions, isImage ? 'ai_scan' : 'ai_text');

    } catch (error) {
      console.error('Gagal memproses file:', error);
      toast.error(error.message || 'Terjadi kesalahan saat memproses file.');
      setMessages((prev) => [...prev, { role: 'assistant', content: `Maaf, terjadi kesalahan: ${error.message}` }]);
    } finally {
      setIsLoading(false);
      setTimeout(() => setProgress(0), 1000);
    }
  }, [user, totalQuota, mode, companyId, onRecordCreated]);

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // Γ£à SUPER SMART PARSER v2.0 ΓÇö 100% OFFLINE, 0 CREDIT
  // Deep Indonesian NLP: date/time intelligence, category-first matching,
  // multi-transaction, enhanced amount parsing
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ

  // ΓöÇΓöÇ HELPER: Parse Amount (shared by single & multi-transaction) ΓöÇΓöÇ
  const parseAmount = (str) => {
    const original = str;
    let s = str.toLowerCase().trim();

    // Remove "rp" / "rp." prefix
    s = s.replace(/^rp\.?\s*/i, '');

    // Handle decimal juta: "2.5jt", "2,5jt", "1.5 juta", "2,5 juta"
    const decJtMatch = s.match(/(\d+)[.,](\d+)\s*(?:jt|juta)/i);
    if (decJtMatch) return parseFloat(`${decJtMatch[1]}.${decJtMatch[2]}`) * 1_000_000;

    // Handle integer juta: "5jt", "10juta"
    const intJtMatch = s.match(/(\d+)\s*(?:jt|juta)/i);
    if (intJtMatch) return parseInt(intJtMatch[1]) * 1_000_000;

    // Handle decimal ribu: "2.5rb", "7,5 ribu"
    const decRbMatch = s.match(/(\d+)[.,](\d+)\s*(?:rb|ribu|k)/i);
    if (decRbMatch) return parseFloat(`${decRbMatch[1]}.${decRbMatch[2]}`) * 1_000;

    // Handle integer ribu: "50rb", "10ribu", "150k"
    const intRbMatch = s.match(/(\d+)\s*(?:rb|ribu|k)/i);
    if (intRbMatch) return parseInt(intRbMatch[1]) * 1_000;

    // Indonesian word numbers (longest match first)
    const wordNumbers = {
      'sepuluh juta': 10_000_000, 'lima juta': 5_000_000, 'tiga juta': 3_000_000,
      'dua juta': 2_000_000, 'satu juta': 1_000_000, 'sejuta': 1_000_000,
      'lima ratus ribu': 500_000, 'tiga ratus ribu': 300_000, 'dua ratus ribu': 200_000,
      'seratus ribu': 100_000, 'lima puluh ribu': 50_000, 'empat puluh ribu': 40_000,
      'tiga puluh ribu': 30_000, 'dua puluh ribu': 20_000, 'lima belas ribu': 15_000,
      'sepuluh ribu': 10_000, 'sembilan ribu': 9_000, 'delapan ribu': 8_000,
      'tujuh ribu': 7_000, 'enam ribu': 6_000, 'lima ribu': 5_000,
      'empat ribu': 4_000, 'tiga ribu': 3_000, 'dua ribu': 2_000, 'seribu': 1_000
    };
    for (const [word, val] of Object.entries(wordNumbers)) {
      if (s.includes(word)) return val;
    }

    // Handle "X ribu" with space: "10 ribu" ΓåÆ 10000
    const numRibuMatch = s.match(/(\d+)\s+ribu/i);
    if (numRibuMatch) return parseInt(numRibuMatch[1]) * 1_000;

    // Handle "X juta" with space: "5 juta" ΓåÆ 5000000
    const numJutaMatch = s.match(/(\d+)\s+juta/i);
    if (numJutaMatch) return parseInt(numJutaMatch[1]) * 1_000_000;

    // Handle formatted numbers: "50.000", "1.500.000" (Indonesian dot-separator)
    const formattedMatch = s.match(/(\d{1,3}(?:\.\d{3})+)/)
    if (formattedMatch) {
      return parseInt(formattedMatch[1].replace(/\./g, '')) || 0;
    }

    // Plain number (e.g. "10000", "50000")
    const plainNum = s.match(/\d+/);
    if (plainNum) {
      return parseInt(plainNum[0]) || 0;
    }

    return 0;
  };

  // ΓöÇΓöÇ HELPER: Deep Date/Time Intelligence ΓöÇΓöÇ
  const parseDateTime = (text) => {
    const now = new Date();
    const lower = text.toLowerCase();
    let resultDate = new Date(now); // default = now
    let dateModified = false;

    // ΓöÇΓöÇ RELATIVE DATE ΓöÇΓöÇ
    if (lower.includes('kemarin') || lower.includes('kemaren')) {
      resultDate.setDate(resultDate.getDate() - 1);
      dateModified = true;
    } else if (lower.includes('lusa') || lower.match(/2\s*hari\s*(?:yang\s*)?lalu/) || lower.includes('dua hari lalu')) {
      resultDate.setDate(resultDate.getDate() - 2);
      dateModified = true;
    } else if (lower.match(/3\s*hari\s*(?:yang\s*)?lalu/) || lower.includes('tiga hari lalu')) {
      resultDate.setDate(resultDate.getDate() - 3);
      dateModified = true;
    } else {
      // Generic "X hari lalu" / "X hari yang lalu"
      const nDaysAgo = lower.match(/(\d+)\s*hari\s*(?:yang\s*)?lalu/);
      if (nDaysAgo) {
        resultDate.setDate(resultDate.getDate() - parseInt(nDaysAgo[1]));
        dateModified = true;
      }
    }

    // "minggu lalu" / "seminggu lalu"
    if (lower.includes('minggu lalu') || lower.includes('seminggu lalu') || lower.includes('seminggu yang lalu')) {
      resultDate.setDate(resultDate.getDate() - 7);
      dateModified = true;
    }

    // "bulan lalu" / "sebulan lalu"
    if (lower.includes('bulan lalu') || lower.includes('sebulan lalu') || lower.includes('sebulan yang lalu')) {
      resultDate.setMonth(resultDate.getMonth() - 1);
      dateModified = true;
    }

    // "tadi" / "barusan" = today (already default)
    if (lower.includes('tadi') || lower.includes('barusan') || lower.includes('baru saja')) {
      dateModified = true; // keep today
    }

    // ΓöÇΓöÇ ABSOLUTE DATE: "tanggal 15" / "tgl 1" ΓöÇΓöÇ
    const tglMatch = lower.match(/(?:tanggal|tgl|tg)\s*(\d{1,2})/);
    if (tglMatch) {
      const day = parseInt(tglMatch[1]);
      if (day >= 1 && day <= 31) {
        // If "bulan lalu tanggal X", the month is already adjusted
        resultDate.setDate(day);
        dateModified = true;
      }
    }

    // Full date: "20 Februari", "5 Maret 2026"
    const monthNames = {
      'januari': 0, 'jan': 0, 'februari': 1, 'feb': 1, 'maret': 2, 'mar': 2,
      'april': 3, 'apr': 3, 'mei': 4, 'juni': 5, 'jun': 5, 'juli': 6, 'jul': 6,
      'agustus': 7, 'ags': 7, 'agu': 7, 'september': 8, 'sep': 8, 'sept': 8,
      'oktober': 9, 'okt': 9, 'november': 10, 'nov': 10, 'desember': 11, 'des': 11
    };
    for (const [mName, mIdx] of Object.entries(monthNames)) {
      const fullDateMatch = lower.match(new RegExp(`(\\d{1,2})\\s+${mName}(?:\\s+(\\d{4}))?`));
      if (fullDateMatch) {
        const day = parseInt(fullDateMatch[1]);
        const year = fullDateMatch[2] ? parseInt(fullDateMatch[2]) : now.getFullYear();
        resultDate = new Date(year, mIdx, day);
        dateModified = true;
        break;
      }
    }

    // ΓöÇΓöÇ TIME PARSING ΓöÇΓöÇ
    // "jam 3 siang" ΓåÆ 15:00, "jam 10 pagi" ΓåÆ 10:00, "jam 8 malam" ΓåÆ 20:00
    const jamMatch = lower.match(/jam\s*(\d{1,2})(?:\.(\d{1,2}))?\s*(pagi|siang|sore|malam|subuh)?/);
    if (jamMatch) {
      let hour = parseInt(jamMatch[1]);
      const minutes = jamMatch[2] ? parseInt(jamMatch[2]) : 0;
      const period = jamMatch[3];

      if (period === 'siang' && hour < 12) hour += 12; // jam 3 siang ΓåÆ 15
      if (period === 'sore' && hour < 12) hour += 12; // jam 4 sore ΓåÆ 16
      if (period === 'malam' && hour < 12) hour += 12; // jam 8 malam ΓåÆ 20
      if (period === 'pagi' && hour === 12) hour = 0; // jam 12 pagi ΓåÆ 0
      if (period === 'subuh' && hour > 6) hour = hour; // subuh = 3-5

      resultDate.setHours(hour, minutes, 0, 0);
    } else if (!jamMatch) {
      // Contextual time words without "jam"
      if (lower.includes('tadi pagi') || lower.includes('pagi ini') || lower.includes('pagi tadi')) {
        resultDate.setHours(8, 0, 0, 0);
      } else if (lower.includes('tadi siang') || lower.includes('siang ini') || lower.includes('siang tadi')) {
        resultDate.setHours(12, 0, 0, 0);
      } else if (lower.includes('tadi sore') || lower.includes('sore ini') || lower.includes('sore tadi')) {
        resultDate.setHours(16, 0, 0, 0);
      } else if (lower.includes('tadi malam') || lower.includes('malam ini') || lower.includes('malam tadi') || lower.includes('semalam')) {
        resultDate.setHours(20, 0, 0, 0);
      } else if (lower.includes('subuh')) {
        resultDate.setHours(4, 30, 0, 0);
      }
    }

    return resultDate.toISOString();
  };

  // ΓöÇΓöÇ HELPER: Detect Type ΓöÇΓöÇ
  const detectType = (lower) => {
    const incomeKeywords = ['gaji', 'terima', 'dapat', 'masuk', 'pemasukan', 'pendapatan', 'bayaran', 'bonus', 'transfer masuk', 'penjualan', 'laba', 'untung', 'revenue', 'income', 'fee', 'komisi', 'dividen', 'hadiah', 'cashback', 'honor', 'honorarium', 'thr', 'refund'];
    const expenseKeywords = ['beli', 'bayar', 'keluar', 'pengeluaran', 'belanja', 'makan', 'buat', 'sewa', 'biaya', 'ongkos', 'parkir', 'bensin', 'listrik', 'air', 'pulsa', 'internet', 'transport', 'ojol', 'grab', 'gojek', 'laundry', 'langganan', 'cicilan', 'utang', 'kredit', 'tagihan', 'iuran', 'donasi', 'sedekah', 'infaq', 'zakat', 'pajak', 'grocery', 'expense', 'jajan', 'kopi', 'cemilan', 'snack', 'rokok', 'obat', 'dokter', 'rumah sakit', 'rs', 'tiket', 'hotel', 'jalan-jalan', 'wisata', 'top up', 'topup', 'isi ulang', 'service', 'servis'];

    let type = 'expense'; // default
    for (const kw of incomeKeywords) {
      if (lower.includes(kw)) { type = 'income'; break; }
    }
    // Expense keywords override if at start or explicit
    for (const kw of expenseKeywords) {
      if (lower.startsWith(kw) || lower.includes('beli') || lower.includes('bayar')) {
        type = 'expense'; break;
      }
    }
    return type;
  };

  // ΓöÇΓöÇ HELPER: Detect Category ΓöÇΓöÇ
  const detectCategory = (lower, detectedType) => {
    const categoryMap = {
      'Makanan & Minuman': ['makan', 'minum', 'kopi', 'jajan', 'cemilan', 'snack', 'sarapan', 'nasi', 'bakso', 'mie', 'ayam', 'ikan', 'sayur', 'buah', 'resto', 'restaurant', 'warteg', 'warung', 'cafe', 'starbucks', 'kfc', 'mcd', 'pizza', 'burger', 'roti', 'es', 'teh', 'juice', 'susu', 'gorengan', 'sate', 'soto', 'rawon', 'pecel', 'gudeg', 'rendang', 'martabak', 'indomie', 'nongkrong'],
      'Transportasi': ['bensin', 'bbm', 'solar', 'pertalite', 'pertamax', 'transport', 'ojol', 'grab', 'gojek', 'uber', 'taxi', 'taksi', 'bus', 'kereta', 'mrt', 'lrt', 'krl', 'tol', 'parkir', 'angkot', 'ojek', 'tiket pesawat', 'tiket kereta', 'maxim', 'ongkir', 'pengiriman'],
      'Belanja': ['belanja', 'shopping', 'tokopedia', 'shopee', 'lazada', 'bukalapak', 'blibli', 'toko', 'mall', 'pasar', 'minimarket', 'indomaret', 'alfamart', 'supermarket', 'hypermart'],
      'Tagihan & Utilitas': ['listrik', 'air', 'pdam', 'gas', 'pln', 'pulsa', 'paket data', 'internet', 'wifi', 'indihome', 'telkom', 'iuran', 'ipkl', 'sampah', 'keamanan', 'token listrik'],
      'Kesehatan': ['obat', 'dokter', 'rumah sakit', 'rs', 'apotek', 'farmasi', 'vitamin', 'supplement', 'bpjs', 'asuransi kesehatan', 'klinik', 'lab', 'rawat'],
      'Hiburan': ['nonton', 'bioskop', 'film', 'game', 'musik', 'spotify', 'netflix', 'youtube premium', 'disney', 'langganan', 'subscription', 'konser', 'wisata', 'jalan-jalan', 'hotel', 'airbnb', 'liburan', 'piknik', 'rekreasi'],
      'Pendidikan': ['buku', 'kursus', 'les', 'sekolah', 'kuliah', 'spp', 'pelatihan', 'sertifikasi', 'seminar', 'workshop', 'udemy', 'coursera', 'tutor'],
      'Gaji & Pendapatan': ['gaji', 'salary', 'pendapatan', 'pemasukan', 'honor', 'honorarium', 'bonus', 'thr', 'upah', 'fee karyawan', 'insentif', 'pekerja'],
      'Operasional': ['operasional', 'ops', 'opr'],
      'Modal': ['modal', 'investasi awal', 'capex', 'aset'],
      'Transfer': ['transfer', 'kirim', 'tf'],
      'Cicilan & Hutang': ['cicilan', 'kredit', 'utang', 'hutang', 'angsuran', 'pinjaman', 'kpr', 'kta'],
      'Sedekah & Donasi': ['sedekah', 'infaq', 'zakat', 'donasi', 'sumbangan', 'amal', 'infak'],
      'Laundry & Kebersihan': ['laundry', 'cuci', 'dry clean', 'setrika'],
      'Rokok & Lainnya': ['rokok', 'vape']
    };

    let category = 'Lainnya';
    let matchedType = detectedType;

    // PRIORITY 0: Exact Match against Budget Categories (Highest Priority for Company)
    for (const bCatName of budgetCategories) {
      const bCatLower = bCatName.toLowerCase();
      if (lower.includes(bCatLower)) {
        category = bCatName;
        const matchedCustomCat = customCategories.find(c => c.name.toLowerCase() === bCatLower);
        if (matchedCustomCat) matchedType = matchedCustomCat.type;
        return { category, type: matchedType };
      }
    }

    // PRIORITY 0.5: Word-level match against Budget Categories
    for (const bCatName of budgetCategories) {
      const catWords = bCatName.toLowerCase().split(/\s+/);
      for (const word of catWords) {
        if (word.length >= 3 && lower.includes(word)) {
          category = bCatName;
          const matchedCustomCat = customCategories.find(c => c.name.toLowerCase() === bCatName.toLowerCase());
          if (matchedCustomCat) matchedType = matchedCustomCat.type;
          return { category, type: matchedType };
        }
      }
    }

    // PRIORITY 1: Exact match against user's custom categories
    for (const cat of customCategories) {
      const catLower = cat.name.toLowerCase();
      if (lower.includes(catLower)) {
        category = cat.name;
        if (cat.type === 'income' || cat.type === 'expense') matchedType = cat.type;
        return { category, type: matchedType };
      }
    }

    // PRIORITY 2: Word-level fuzzy match against custom categories
    // e.g. user has category "Operasional" and text contains "operasional"
    // or user has "Bahan Baku" and text contains "bahan"
    for (const cat of customCategories) {
      const catWords = cat.name.toLowerCase().split(/\s+/);
      for (const word of catWords) {
        if (word.length >= 3 && lower.includes(word)) {
          category = cat.name;
          if (cat.type === 'income' || cat.type === 'expense') matchedType = cat.type;
          return { category, type: matchedType };
        }
      }
    }

    // PRIORITY 3: Built-in category map
    for (const [catName, keywords] of Object.entries(categoryMap)) {
      for (const kw of keywords) {
        if (lower.includes(kw)) {
          return { category: catName, type: matchedType };
        }
      }
    }

    return { category, type: matchedType };
  };

  // ΓöÇΓöÇ HELPER: Clean Description ΓöÇΓöÇ
  const cleanDescription = (text) => {
    let desc = text
      .replace(/rp\.?\s*/gi, '')
      .replace(/\d+[.,]\d+\s*(?:jt|juta|rb|ribu|k)/gi, '') // "2.5jt"
      .replace(/\d+\s*(?:ribu|rb|k|juta|jt)/gi, '') // "10rb"
      .replace(/\d{1,3}(?:\.\d{3})+/g, '') // "50.000"
      .replace(/\d{4,}/g, '') // "50000"
      .replace(/\b(?:kemarin|kemaren|lusa|tadi|barusan|baru saja|pagi|siang|sore|malam|subuh)\b/gi, '')
      .replace(/\b(?:jam\s*\d+(?:\.\d+)?\s*(?:pagi|siang|sore|malam|subuh)?)\b/gi, '')
      .replace(/\b(?:tanggal|tgl|tg)\s*\d+/gi, '')
      .replace(/\b\d+\s*hari\s*(?:yang\s*)?lalu\b/gi, '')
      .replace(/\b(?:minggu|seminggu|bulan|sebulan)\s*(?:yang\s*)?lalu\b/gi, '')
      .replace(/\b(?:dan|\&|\+)\b/gi, '') // multi-tx delimiters
      .replace(/^\s*(?:beli|bayar|dapat|terima)\s*/i, '')
      .replace(/\s{2,}/g, ' ')
      .trim();

    if (!desc || desc.length < 2) desc = text.trim();
    return desc.charAt(0).toUpperCase() + desc.slice(1);
  };

  // ΓöÇΓöÇ MAIN: superSmartParser with multi-transaction support ΓöÇΓöÇ
  const superSmartParser = (text) => {
    const lower = text.toLowerCase().trim();

    // ΓöÇΓöÇ STEP 1: Check for multi-transaction ΓöÇΓöÇ
    // Split by "dan", "&", "+", "," delimiter when EACH segment has an amount
    const multiDelimiterRegex = /\s+(?:dan|\&)\s+|\s*\+\s*|\s*,\s+/gi;
    const segments = text.split(multiDelimiterRegex).filter(s => s.trim().length > 0);

    // Only treat as multi-transaction if:
    // - More than 1 segment
    // - EACH segment contains a number (amount)
    const isMulti = segments.length > 1 && segments.every(seg => /\d/.test(seg));

    if (isMulti) {
      console.log(`≡ƒºá MULTI-TRANSACTION DETECTED: ${segments.length} segments`);
      const transactions = [];
      // Parse shared date from the full text
      const sharedDate = parseDateTime(text);

      for (const segment of segments) {
        const segLower = segment.toLowerCase().trim();
        const amount = parseAmount(segment);
        if (amount <= 0) continue;

        const detectedType = detectType(segLower);
        const { category, type } = detectCategory(segLower, detectedType);
        const description = cleanDescription(segment);

        transactions.push({
          type,
          amount,
          category,
          description,
          date: sharedDate
        });
      }

      if (transactions.length > 0) {
        console.log(`≡ƒºá MULTI-TX SUCCESS: ${transactions.length} transactions parsed`);
        return { transactions };
      }
    }

    // ΓöÇΓöÇ STEP 2: Single transaction parse ΓöÇΓöÇ
    const amount = parseAmount(text);
    if (amount <= 0) return null; // Cannot parse ΓåÆ fall through to AI

    const detectedType = detectType(lower);
    const { category, type } = detectCategory(lower, detectedType);
    const description = cleanDescription(text);
    const date = parseDateTime(text);

    console.log(`≡ƒºá LOCAL PARSER: type=${type}, amount=${amount}, category=${category}, desc="${description}", date=${date}`);
    return {
      transactions: [{
        type,
        amount,
        category,
        description,
        date
      }]
    };
  };


  const handleSendMessage = async () => {
    const userMessage = input.trim();
    if (!userMessage || isLoading) return;

    setInput('');
    setMessages((prev) => [...prev, { role: 'user', content: userMessage }]);
    setIsLoading(true);

    try {
      setProgress(20);

      // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
      // ≡ƒºá STEP 1: TRY LOCAL PARSER FIRST (0 credits, INSTANT)
      // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
      let parsedResult = null;
      try {
        parsedResult = superSmartParser(userMessage);
        if (parsedResult && parsedResult.transactions?.length > 0 && parsedResult.transactions.every(tx => tx.amount > 0)) {
          console.log(`≡ƒºá LOCAL PARSER SUCCESS (0 credits): ${parsedResult.transactions.length} transaction(s)`, parsedResult);
          setProgress(60);
        } else {
          parsedResult = null; // Reset if parser couldn't extract amount
        }
      } catch (parserError) {
        console.warn('ΓÜá∩╕Å Local parser error:', parserError.message);
        parsedResult = null;
      }

      // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
      // ≡ƒñû STEP 2: IF LOCAL FAILS, TRY AI (uses credits)
      // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
      if (!parsedResult) {
        if (!canUseAI) {
          toast.error('Parser lokal gagal dan kredit AI habis! Coba format: "beli makan 10 ribu" atau "gaji 5jt"');
          setMessages((prev) => [...prev, { role: 'assistant', content: 'ΓÜá∩╕Å Saya gagal parsing otomatis dan kredit AI habis.\n\nCoba format yang lebih jelas:\nΓÇó "beli makan 10 ribu"\nΓÇó "bensin 50rb"\nΓÇó "dapat gaji 5jt"\nΓÇó "bayar listrik 200000"' }]);
          setProgress(0);
          return;
        }

        console.log('≡ƒñû Local parser failed, trying AI...');
        setProgress(40);

        const currentDate = new Date();
        const currentYear = currentDate.getFullYear();
        const currentMonth = currentDate.getMonth() + 1;
        const currentDay = currentDate.getDate();

        const fullPrompt = `Kamu adalah asisten keuangan AI cerdas. Tanggal HARI INI adalah ${currentDay} ${getMonthName(currentMonth)} ${currentYear}.

TUGAS UTAMA:
1. Parse tanggal (HARI INI: ${currentYear}-${String(currentMonth).padStart(2, '0')}-${String(currentDay).padStart(2, '0')})
2. Ekstrak data transaksi: type (income/expense), amount, category, description.
3. KATEGORI ANGGARAN (PRIORITAS): Jika ini pengeluaran, 90% harus menggunakan salah satu kategori anggaran berikut jika sesuai konteks:
   ${budgetCategories.length > 0 ? budgetCategories.map(c => `- ${c}`).join('\n   ') : '(Belum ada anggaran)'}
4. JANGAN buat kategori baru jika ada yang mirip di daftar kategori user.

DAFTAR KATEGORI USER KESELURUHAN:
${customCategories.length > 0 ? customCategories.map(c => `- ${c.name} (${c.type})`).join('\n') : '(Belum ada, gunakan umum)'}

OUTPUT FORMAT (JSON ONLY):
{
  "transactions": [
    {
      "type": "income/expense",
      "amount": number,
      "category": "string (Matches user list if possible)",
      "description": "string",
      "date": "YYYY-MM-DDTHH:mm:ss"
    }
  ]
}

Pesan user: ${userMessage}`;

        try {
          const response = await InvokeLLM({
            prompt: fullPrompt,
            response_json_schema: {
              type: 'object',
              properties: {
                transactions: {
                  type: 'array',
                  items: {
                    type: 'object',
                    properties: {
                      type: { type: 'string', enum: ['income', 'expense'] },
                      amount: { type: 'number' },
                      category: { type: 'string' },
                      description: { type: 'string' },
                      date: { type: 'string' }
                    },
                    required: ['type', 'amount', 'category', 'description', 'date']
                  }
                }
              }
            }
          });
          parsedResult = response;
          console.log('≡ƒñû AI SUCCESS:', parsedResult);
        } catch (aiError) {
          console.error('Γ¥î AI juga gagal:', aiError.message);
          toast.error('Parser lokal & AI gagal. Coba format: "beli makan 10 ribu"');
          setMessages((prev) => [...prev, { role: 'assistant', content: 'Γ¥î Semua layanan gagal. Coba format yang lebih sederhana:\nΓÇó "beli makan 10 ribu"\nΓÇó "bensin 50rb"\nΓÇó "gaji 5jt"' }]);
          setProgress(0);
          return;
        }
      }

      // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
      // Γ£à STEP 3: PROCESS RESULT
      // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
      const transactions = parsedResult?.transactions || [];
      console.log('≡ƒôè Final transactions:', transactions);

      if (transactions.length === 0) {
        setMessages((prev) => [...prev, { role: 'assistant', content: 'Maaf, saya tidak menemukan transaksi dari pesan Anda. Coba sebutkan dengan lebih jelas: jenis transaksi, jumlah, dan tanggalnya.' }]);
        setProgress(0);
        return;
      }

      const validatedTransactions = transactions.map((tx) => {
        let finalDate = tx.date;
        try {
          const parsedDate = new Date(finalDate);
          if (isNaN(parsedDate.getTime())) {
            finalDate = new Date().toISOString();
            console.warn('ΓÜá∩╕Å Invalid date, using today:', finalDate);
          } else {
            finalDate = parsedDate.toISOString();
          }
        } catch (e) {
          finalDate = new Date().toISOString();
        }
        return { ...tx, date: finalDate };
      });

      console.log('Γ£à Validated transactions with dates:', validatedTransactions);
      await processAndCreateRecords(validatedTransactions, 'ai_text');
      setProgress(0);

    } catch (error) {
      console.error('Γ¥î Error in Finance AI handleSendMessage:', error);
      toast.error('Gagal memproses pesan: ' + (error.message || 'Unknown error'));
      setMessages((prev) => [...prev, { role: 'assistant', content: `Maaf, terjadi kesalahan: ${error.message || 'Unknown error'}` }]);
      setProgress(0);
    } finally {
      setIsLoading(false);
    }
  };

  const getMonthName = (month) => {
    const months = [
      'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni',
      'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];

    return months[month - 1] || months[0];
  };

  const handleVoiceInput = () => {
    if (isListening) {
      recognitionRef.current?.stop();
      setIsListening(false);
      if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
      return;
    }

    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      toast.error("Browser tidak mendukung voice recognition.");
      return;
    }

    try {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.lang = 'id-ID';
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;

      recognitionRef.current.onstart = () => {
        setIsListening(true);
        toast.info('≡ƒÄñ Mulai berbicara...', { duration: 2000 });
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
        if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
      };

      recognitionRef.current.onerror = (event) => {
        setIsListening(false);
        const errorMessages = {
          'no-speech': 'Tidak ada suara terdeteksi. Coba lagi.',
          'audio-capture': 'Microphone tidak terdeteksi.',
          'not-allowed': 'Akses microphone ditolak. Aktifkan di browser.'
        };
        toast.error(errorMessages[event.error] || 'Error: ' + event.error);
        if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
      };

      recognitionRef.current.onresult = (event) => {
        const transcript = event.results[0][0].transcript;
        setInput(transcript);
        toast.success('Γ£à Terdeteksi: "' + transcript + '"');

        if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
        silenceTimerRef.current = setTimeout(() => {
          if (transcript.trim()) handleSendMessage();
        }, 2000);
      };

      recognitionRef.current.start();
    } catch (error) {
      toast.error('Gagal memulai voice recognition');
      setIsListening(false);
    }
  };

  const openFileDialog = () => {
    if (isLoading || !canUseAI) {
      if (!canUseAI) toast.error("Kuota AI habis.");
      return;
    }
    fileInputRef.current?.click();
  };

  const openCameraDialog = () => {
    if (isLoading || !canUseAI) {
      if (!canUseAI) toast.error("Kuota AI habis.");
      return;
    }
    cameraInputRef.current?.click();
  };

  const handleFileChange = (e) => {
    if (e.target.files && e.target.files[0]) {
      handleFileUpload(e.target.files[0]);
      e.target.value = null;
    }
  };

  const quotaPercentage = monthlyUsage / totalQuota * 100;

  return (
    <Card className="bg-gray-900/50 border-gray-800 h-full flex flex-col overflow-hidden">
      <CardHeader className="border-b border-gray-800 p-1.5 sm:p-2 flex-shrink-0">
        <div className="flex items-center justify-between gap-2">
          <CardTitle className="text-white flex items-center gap-1.5 text-xs sm:text-sm">
            <FileText className="w-3.5 h-3.5 sm:w-4 sm:h-4 text-purple-400 flex-shrink-0" />
            Asisten Keuangan AI
          </CardTitle>
          <Badge className="bg-blue-600/20 text-blue-400 border-blue-600/30 text-xs h-4 px-1.5">
            {((totalQuota - monthlyUsage) / 1000).toFixed(1)}K / {(totalQuota / 1000).toFixed(1)}K
          </Badge>
        </div>
        <Progress value={quotaPercentage} className="h-0.5 mt-1" />
      </CardHeader>

      <CardContent className="flex-1 flex flex-col p-1.5 sm:p-2 gap-2" style={{ minHeight: 0 }}>
        <div className="flex-1 overflow-y-auto space-y-2 p-2 bg-gray-800/30 rounded-lg" style={{ minHeight: 0, maxHeight: '100%' }}>
          {messages.map((msg, index) =>
            <div key={index} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`rounded-lg px-2.5 py-1.5 max-w-[85%] text-xs ${msg.role === 'user' ?
                'bg-blue-600 text-white' :
                'bg-gray-800 text-gray-200 border border-gray-700'}`
              }>
                <p className="text-xs leading-relaxed whitespace-pre-wrap">{msg.content}</p>
              </div>
            </div>
          )}
          {isLoading &&
            <div className="flex flex-col items-start gap-1.5">
              <div className="rounded-lg px-2.5 py-1.5 bg-gray-800 border border-gray-700">
                <Loader2 className="w-4 h-4 animate-spin text-blue-400" />
              </div>
              {progress > 0 &&
                <div className="w-full">
                  <Progress value={progress} className="h-1" />
                  <p className="text-xs text-center mt-0.5 text-gray-400">{Math.round(progress)}%</p>
                </div>
              }
            </div>
          }
          <div ref={messagesEndRef} />
        </div>

        <div className="flex-shrink-0 space-y-1.5">
          {/* Account Selector */}
          <div className="flex items-center gap-2 p-2 bg-gray-800/50 rounded-lg border border-gray-700">
            <Wallet className="w-4 h-4 text-blue-400 flex-shrink-0" />
            <Select
              value={selectedAccountId}
              onValueChange={setSelectedAccountId}
            >
              <SelectTrigger className="bg-gray-800 border-gray-700 text-white text-xs h-7 flex-1">
                <SelectValue placeholder="Pilih rekening untuk mencatat" />
              </SelectTrigger>
              <SelectContent className="bg-gray-900 border-gray-700">
                {accounts && accounts.length > 0 ? (
                  accounts.filter(a => a.is_active).map(account => (
                    <SelectItem key={account.id} value={account.id} className="text-white text-xs">
                      {account.icon} {account.name} - {formatRupiah(account.calculated_balance || 0)}
                    </SelectItem>
                  ))
                ) : (
                  <SelectItem value="no-account" disabled className="text-gray-400 text-xs">
                    Belum ada rekening. Buat di tab Rekening
                  </SelectItem>
                )}
              </SelectContent>
            </Select>
          </div>

          <div className="relative">
            <Textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSendMessage();
                }
              }}
              placeholder="Ketik: 'makan 10rb' atau 'gaji 5jt kemarin' (OFFLINE, 0 kredit)"
              className="pr-9 bg-gray-800 border-gray-700 text-white resize-none text-xs"
              rows={2}
              disabled={isLoading} />

            <Button
              variant="ghost"
              size="icon"
              onClick={handleSendMessage}
              disabled={isLoading || !input.trim()}
              className="absolute right-0.5 bottom-0.5 text-blue-400 hover:bg-gray-700 h-6 w-6">

              <Send className="w-3 h-3" />
            </Button>
          </div>

          <div className="flex flex-wrap gap-1">
            <Button
              variant="outline"
              size="sm"
              onClick={openFileDialog}
              disabled={isLoading || !canUseAI}
              className="border-gray-700 text-gray-300 text-xs h-6 px-1.5">

              <Paperclip className="w-3 h-3 mr-1" />
              File
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={openCameraDialog}
              disabled={isLoading || !canUseAI}
              className="border-gray-700 text-gray-300 text-xs h-6 px-1.5">

              <Camera className="w-3 h-3 mr-1" />
              Foto
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={handleVoiceInput}
              disabled={isLoading || !canUseAI}
              className={`border-gray-700 text-xs h-6 px-1.5 ${isListening ? 'bg-red-600 text-white animate-pulse' : 'text-gray-300'}`}>

              {isListening ? <MicOff className="w-3 h-3 mr-1" /> : <Mic className="w-3 h-3 mr-1" />}
              Voice
            </Button>
          </div>

          {!canUseAI &&
            <p className="text-yellow-500 text-xs text-center">
              ΓÜí Kredit AI habis. Chat teks tetap bisa (offline, 0 kredit). File/Foto/Voice butuh kredit.
            </p>
          }
        </div>
      </CardContent>

      <input
        ref={fileInputRef}
        type="file"
        onChange={handleFileChange}
        accept="image/*,application/pdf,.xlsx,.xls"
        className="hidden" />

      <input
        ref={cameraInputRef}
        type="file"
        capture="environment"
        onChange={handleFileChange}
        accept="image/*"
        className="hidden" />

    </Card>);

}

import { useState, useMemo, useCallback, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Textarea } from '@/components/ui/textarea';
import { TrendingUp, AlertCircle, Lightbulb, Loader2, RefreshCw, BarChart as BarChartIcon, Send, Sparkles } from 'lucide-react';
import { toast } from 'sonner';
import { BarChart, Bar, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { format, startOfMonth, subMonths, isAfter } from 'date-fns';

// Skema JSON tidak perlu diubah, karena sudah cukup fleksibel
const analysisSchema = {
    type: "object",
    properties: {
        response_title: { type: "string", description: "Judul singkat dan menarik untuk analisis ini, misal: 'Analisis Keuangan 6 Bulan Terakhir'" },
        response_summary: { type: "string", description: "Ringkasan tekstual 2-3 kalimat dari analisis dalam Bahasa Indonesia, berdasarkan data dan metrik yang diberikan." },
        actionable_insights: {
            type: "array",
            items: {
                type: "object",
                properties: {
                    priority: { type: "string", enum: ["high", "medium", "low"] },
                    title: { type: "string", description: "Judul insight yang bisa ditindaklanjuti." },
                    description: { type: "string", description: "Deskripsi detail dari insight." }
                }
            }
        }
    },
    required: ["response_title", "response_summary", "actionable_insights"]
};

export default function FinanceAIRecommendations({ user, records }) {
    const [analysis, setAnalysis] = useState(null);
    const [isLoading, setIsLoading] = useState(true);
    const [query, setQuery] = useState('');
    const [isQuerying, setIsQuerying] = useState(false);
    const [chartType, setChartType] = useState('bar');
    const [timeRange, setTimeRange] = useState('12');

    const processedData = useMemo(() => {
        if (!records || records.length === 0) return [];
        const cutoffDate = subMonths(new Date(), parseInt(timeRange));
        const filteredRecords = records.filter((record) => isAfter(new Date(record.date), cutoffDate));
        const monthlyData = new Map();
        filteredRecords.forEach((record) => {
            const monthKey = format(startOfMonth(new Date(record.date)), 'yyyy-MM');
            if (!monthlyData.has(monthKey)) {
                monthlyData.set(monthKey, { name: format(new Date(monthKey), 'MMM yy'), Pemasukan: 0, Pengeluaran: 0, monthKey: monthKey });
            }
            const data = monthlyData.get(monthKey);
            if (record.type === 'income') data.Pemasukan += record.amount; else data.Pengeluaran += record.amount;
        });
        return Array.from(monthlyData.values()).sort((a, b) => a.monthKey.localeCompare(b.monthKey));
    }, [records, timeRange]);

    const keyMetrics = useMemo(() => {
        if (!processedData || processedData.length === 0) return [];
        const totalIncome = processedData.reduce((sum, data) => sum + data.Pemasukan, 0);
        const totalExpense = processedData.reduce((sum, data) => sum + data.Pengeluaran, 0);
        const netFlow = totalIncome - totalExpense;
        let mostExpensiveMonth = processedData.length > 0 ? processedData.reduce((max, month) => max.Pengeluaran > month.Pengeluaran ? max : month) : null;
        const formatCurrency = (value) => `Rp ${new Intl.NumberFormat('id-ID').format(value)}`;
        return [
            { label: "Total Pemasukan", value: formatCurrency(totalIncome) },
            { label: "Total Pengeluaran", value: formatCurrency(totalExpense) },
            { label: "Arus Kas Bersih", value: formatCurrency(netFlow) },
            { label: "Bulan Terboros", value: mostExpensiveMonth ? mostExpensiveMonth.name : '-' }
        ];
    }, [processedData]);

    // --- BARU: Menyiapkan 20 transaksi mentah terakhir untuk AI ---
    const recentTransactionsForAI = useMemo(() => {
        if (!records || records.length === 0) return [];
        // Mengambil 20 transaksi terakhir dan memformatnya untuk prompt
        return records.slice(-20).map(r =>
            `- Tanggal: ${r.date}, Tipe: ${r.type}, Jumlah: Rp ${r.amount.toLocaleString('id-ID')}, Deskripsi: ${r.description}`
        ).join('\n');
    }, [records]);

    // Γ£à API KEYS & HELPERS (Added for Recommendations)
    const OPENAI_API_KEY = import.meta.env.VITE_OPENAI_API_KEY || "";
    const CLAUDE_API_KEY = import.meta.env.VITE_CLAUDE_API_KEY || "";

    const callOpenAI = async (prompt, schema) => {
        const res = await fetch('https://api.openai.com/v1/chat/completions', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${OPENAI_API_KEY}` },
            body: JSON.stringify({
                model: "gpt-4o",
                messages: [{ role: "system", content: "You are a helpful financial analyst." }, { role: "user", content: prompt }],
                response_format: { type: "json_object" },
                temperature: 0.3
            })
        });
        if (!res.ok) throw new Error(`OpenAI Error: ${res.statusText}`);
        const data = await res.json();
        return JSON.parse(data.choices[0].message.content);
    };

    const callClaude = async (prompt, schema) => {
        // Claude fallback: Force JSON in prompt
        const claudePrompt = prompt + "\n\nCRITICAL: OUTPUT MUST BE VALID JSON matching this schema: " + JSON.stringify(schema);
        const res = await fetch('https://api.anthropic.com/v1/messages', {
            method: 'POST',
            headers: {
                'content-type': 'application/json',
                'x-api-key': CLAUDE_API_KEY,
                'anthropic-version': '2023-06-01',
                'anthropic-dangerously-allow-browser': 'true'
            },
            body: JSON.stringify({
                model: "claude-3-5-sonnet-latest",
                max_tokens: 2000,
                messages: [{ role: "user", content: claudePrompt }]
            })
        });
        if (!res.ok) throw new Error(`Claude Error: ${res.statusText}`);
        const data = await res.json();
        const content = data.content[0].text;
        const jsonMatch = content.match(/\{[\s\S]*\}/);
        return jsonMatch ? JSON.parse(jsonMatch[0]) : JSON.parse(content);
    };

    // --- PERBAIKAN: Fungsi `runAIAnalysis` kini menggunakan prompt yang jauh lebih cerdas ---
    const runAIAnalysis = useCallback(async (userQuery = "", showLoader = true) => {
        if (processedData.length === 0) {
            setIsLoading(false); return;
        }
        if (showLoader) userQuery ? setIsQuerying(true) : setIsLoading(true);

        try {
            const dataForPrompt = JSON.stringify(processedData);
            const metricsForPrompt = JSON.stringify(keyMetrics);

            // --- INI ADALAH BAGIAN UTAMA PENINGKATAN KECERDASAN AI ---
            const prompt = `
                Anda adalah TODOIT AI, seorang penasihat keuangan pribadi yang cerdas, empatik, dan proaktif untuk pengguna bernama ${user.full_name}.
                Tugas Anda adalah menganalisis data keuangan pengguna dan menjawab pertanyaan mereka dengan cara yang kontekstual dan bermanfaat.

                Berikut adalah data yang Anda miliki:
                1.  **Ringkasan Keuangan Bulanan (untuk melihat tren):**
                    ${dataForPrompt}

                2.  **Metrik Kunci Akurat (sebagai sumber kebenaran angka):**
                    ${metricsForPrompt}
                
                3.  **Daftar 20 Transaksi Terbaru (untuk detail spesifik):**
                    ${recentTransactionsForAI}

                ---
                PERMINTAAN PENGGUNA: "${userQuery || "Berikan saya analisis umum dan saran untuk keuangan saya saat ini."}"
                ---

                INSTRUKSI:
                -   Jawab pertanyaan pengguna secara langsung dan akurat berdasarkan data yang ada.
                -   Jika pertanyaannya umum (misal: "bagaimana cara mengelola keuangan"), berikan nasihat umum TAPI selipkan contoh yang diambil dari data keuangan pengguna agar terasa personal (misal: "Anda bisa mulai dengan mengurangi pengeluaran di kategori Makanan & Minuman, yang merupakan pengeluaran terbesar Anda bulan lalu sebesar...").
                -   Jika pertanyaannya spesifik tentang data (misal: "keuangan kemarin"), gunakan daftar transaksi terbaru untuk menjawab.
                -   Selalu berikan jawaban yang mendukung, positif, dan mudah ditindaklanjuti.
                -   Gunakan format JSON yang diminta untuk output Anda. Judul dan ringkasan harus sesuai dengan jawaban Anda.
            `;

            // Kita hapus `key_metrics` dari skema karena kini dihitung lokal, AI hanya fokus pada insight
            const { key_metrics, ...schemaWithoutMetrics } = analysisSchema.properties;
            const newSchema = { ...analysisSchema, properties: schemaWithoutMetrics, required: ["response_title", "response_summary", "actionable_insights"] };

            // Γ£à EXECUTE AI CALL (OpenAI -> Followed by Claude Fallback)
            let result;
            try {
                result = await callOpenAI(prompt, newSchema);
            } catch (e1) {
                console.warn('ΓÜá∩╕Å OpenAI Analysis failed, attempting Claude...', e1);
                try {
                    result = await callClaude(prompt, newSchema);
                } catch (e2) {
                    throw new Error('Semua layanan AI gagal memberikan analisis.');
                }
            }

            // Gabungkan hasil dari AI dengan metrik akurat yang sudah kita hitung
            const finalAnalysis = { ...result, key_metrics: keyMetrics };

            setAnalysis(finalAnalysis);
            localStorage.setItem(`financeAnalysisCache_${timeRange}`, JSON.stringify({ data: processedData, result: finalAnalysis }));
        } catch (error) {
            toast.error("Gagal menghasilkan analisis AI");
            console.error(error);
        } finally {
            if (showLoader) userQuery ? setIsQuerying(false) : setIsLoading(false);
        }
    }, [processedData, keyMetrics, recentTransactionsForAI, timeRange, user.full_name]);

    useEffect(() => {
        const cachedData = localStorage.getItem(`financeAnalysisCache_${timeRange}`);
        if (cachedData) {
            const { data: cachedProcessedData, result } = JSON.parse(cachedData);
            if (JSON.stringify(cachedProcessedData) === JSON.stringify(processedData)) {
                setAnalysis(result);
                setIsLoading(false);
                return;
            }
        }
        runAIAnalysis("", true);
    }, [processedData, timeRange, runAIAnalysis]);

    const handleQuerySubmit = (e) => {
        e.preventDefault();
        if (!query.trim()) return;
        runAIAnalysis(query, true);
        setQuery('');
    };

    // ... Sisa kode (tampilan JSX) tidak ada perubahan sama sekali ...
    if (isLoading) {
        return (
            <div className="flex justify-center items-center py-12">
                <div className="text-center">
                    <Loader2 className="w-8 h-8 animate-spin mx-auto mb-4" />
                    <p className="text-muted-foreground">AI sedang menganalisis keuangan Anda...</p>
                </div>
            </div>
        );
    }

    if (!processedData || processedData.length === 0) {
        return (
            <div className="text-center py-12">
                <AlertCircle className="w-12 h-12 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-semibold mb-2">Belum Ada Data Cukup</h3>
                <p className="text-muted-foreground mb-4">
                    Tambahkan transaksi untuk periode yang dipilih untuk melihat analisis.
                </p>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Sparkles className="text-primary" />
                        Tanyakan Sesuatu Pada AI
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <form onSubmit={handleQuerySubmit} className="flex items-center gap-2">
                        <Textarea value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Contoh: Bagaimana cara saya mengurangi pengeluaran?" rows={1} className="flex-1 resize-none" disabled={isQuerying} />
                        <Button type="submit" size="icon" disabled={!query.trim() || isQuerying}>
                            {isQuerying ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
                        </Button>
                    </form>
                </CardContent>
            </Card>

            <Card>
                <CardHeader>
                    <CardTitle className="flex flex-wrap items-center justify-between gap-4">
                        <span className="flex items-center gap-2">
                            <BarChartIcon className="text-blue-500" />
                            Grafik Keuangan
                        </span>
                        <div className="flex items-center gap-2 flex-wrap">
                            <select value={chartType} onChange={(e) => setChartType(e.target.value)} className="bg-background border rounded-md px-2 py-1 text-sm">
                                <option value="bar">Bar Chart</option>
                                <option value="line">Line Chart</option>
                            </select>
                            <select value={timeRange} onChange={(e) => setTimeRange(e.target.value)} className="bg-background border rounded-md px-2 py-1 text-sm">
                                <option value="6">6 Bulan Terakhir</option>
                                <option value="12">12 Bulan Terakhir</option>
                                <option value="24">24 Bulan Terakhir</option>
                            </select>
                        </div>
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <ResponsiveContainer width="100%" height={300}>
                        {chartType === 'bar' ? (
                            <BarChart data={processedData}>
                                <CartesianGrid strokeDasharray="3 3" />
                                <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} />
                                <YAxis fontSize={12} tickLine={false} axisLine={false} tickFormatter={(val) => new Intl.NumberFormat('id-ID', { notation: 'compact' }).format(val)} />
                                <Tooltip cursor={{ fill: 'rgba(100, 116, 139, 0.1)' }} contentStyle={{ backgroundColor: 'hsl(var(--card))', color: 'hsl(var(--card-foreground))', border: '1px solid hsl(var(--border))', borderRadius: '0.5rem' }} formatter={(val) => `Rp${new Intl.NumberFormat('id-ID').format(val)}`} />
                                <Legend />
                                <Bar dataKey="Pemasukan" fill="#22c55e" radius={[4, 4, 0, 0]} />
                                <Bar dataKey="Pengeluaran" fill="#ef4444" radius={[4, 4, 0, 0]} />
                            </BarChart>
                        ) : (
                            <LineChart data={processedData}>
                                <CartesianGrid strokeDasharray="3 3" />
                                <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} />
                                <YAxis fontSize={12} tickLine={false} axisLine={false} tickFormatter={(val) => new Intl.NumberFormat('id-ID', { notation: 'compact' }).format(val)} />
                                <Tooltip cursor={{ strokeDasharray: '3 3' }} contentStyle={{ backgroundColor: 'hsl(var(--card))', color: 'hsl(var(--card-foreground))', border: '1px solid hsl(var(--border))', borderRadius: '0.5rem' }} formatter={(val) => `Rp${new Intl.NumberFormat('id-ID').format(val)}`} />
                                <Legend />
                                <Line type="monotone" dataKey="Pemasukan" stroke="#22c55e" strokeWidth={2} activeDot={{ r: 8 }} />
                                <Line type="monotone" dataKey="Pengeluaran" stroke="#ef4444" strokeWidth={2} activeDot={{ r: 8 }} />
                            </LineChart>
                        )}
                    </ResponsiveContainer>
                </CardContent>
            </Card>

            {analysis && (
                <>
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center justify-between">
                                <span className="flex items-center gap-2">
                                    <TrendingUp className="text-blue-500" />
                                    {analysis.response_title}
                                </span>
                                <Button variant="outline" size="sm" onClick={() => runAIAnalysis(query || "", true)} disabled={isQuerying || isLoading}>
                                    <RefreshCw className="w-4 h-4 mr-2" />
                                    Analisa Ulang
                                </Button>
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <p className="text-muted-foreground">{analysis.response_summary}</p>
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-center">
                                {analysis.key_metrics?.map((metric, index) => (
                                    <div key={index} className="bg-slate-100 dark:bg-gray-800 p-3 rounded-lg">
                                        <p className="text-sm text-muted-foreground">{metric.label}</p>
                                        <p className="text-lg font-bold">{metric.value}</p>
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-2">
                                <Lightbulb className="text-yellow-500" />
                                Insight & Rekomendasi
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="space-y-4">
                                {analysis.actionable_insights?.map((insight, index) => (
                                    <div key={index} className="border dark:border-gray-700 rounded-lg p-4 space-y-2">
                                        <div className="flex items-center justify-between gap-2">
                                            <h4 className="font-semibold">{insight.title}</h4>
                                            <Badge variant={insight.priority === 'high' ? 'destructive' : insight.priority === 'medium' ? 'secondary' : 'outline'}>
                                                Prioritas {insight.priority}
                                            </Badge>
                                        </div>
                                        <p className="text-sm text-muted-foreground">{insight.description}</p>
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>
                </>
            )}
        </div>
    );
}

import React from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { format, eachDayOfInterval, subDays } from 'date-fns';

export default function FinanceChart({ records, mode }) {
  // Generate chart data from records
  const chartData = React.useMemo(() => {
    if (!records || records.length === 0) return [];

    const last30Days = eachDayOfInterval({
      start: subDays(new Date(), 29),
      end: new Date()
    });

    return last30Days.map(day => {
      const dayStr = format(day, 'yyyy-MM-dd');
      const dayRecords = records.filter(r => {
        const recordDate = format(new Date(r.date), 'yyyy-MM-dd');
        return recordDate === dayStr;
      });

      const income = dayRecords
        .filter(r => r.type === 'income')
        .reduce((sum, r) => sum + (r.amount || 0), 0);
      
      const expense = dayRecords
        .filter(r => r.type === 'expense')
        .reduce((sum, r) => sum + (r.amount || 0), 0);

      return {
        date: format(day, 'dd/MM'),
        income,
        expense
      };
    });
  }, [records]);

  return (
    <Card className="bg-gray-900 border-gray-700">
      <CardHeader className="p-4 sm:p-6">
        <CardTitle className="text-white text-sm sm:text-base">Tren Keuangan (30 Hari Terakhir)</CardTitle>
      </CardHeader>
      <CardContent className="p-3 sm:p-6">
        <div className="w-full overflow-x-auto">
          <div className="min-w-[300px]">
            <ResponsiveContainer width="100%" height={300}>
              <LineChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
                <XAxis dataKey="date" stroke="#9CA3AF" tick={{ fontSize: 10 }} />
                <YAxis stroke="#9CA3AF" tick={{ fontSize: 10 }} />
                <Tooltip 
                  formatter={(value) => `Rp ${Number(value).toLocaleString('id-ID')}`}
                  contentStyle={{ backgroundColor: '#1F2937', border: '1px solid #374151', fontSize: '12px' }}
                  labelStyle={{ color: '#F3F4F6' }}
                />
                <Legend wrapperStyle={{ fontSize: '12px' }} />
                <Line type="monotone" dataKey="income" stroke="#10b981" name="Pemasukan" strokeWidth={2} />
                <Line type="monotone" dataKey="expense" stroke="#ef4444" name="Pengeluaran" strokeWidth={2} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

import { useState, useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Calendar, Search, Filter, Edit, Trash2 } from 'lucide-react';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';
import FinanceExportActions from './FinanceExportActions';

const SALES_CHANNELS = [
  { id: 'OFFLINE', name: 'Offline Store', icon: '≡ƒÅ¬' },
  { id: 'SHOPEE', name: 'Shopee', icon: '≡ƒ¢Æ' },
  { id: 'TOKOPEDIA', name: 'Tokopedia', icon: '≡ƒƒó' },
  { id: 'TIKTOK', name: 'TikTok Shop', icon: '≡ƒÄ╡' },
  { id: 'GRAB', name: 'GrabFood/GrabMart', icon: '≡ƒÜù' },
  { id: 'GOJEK', name: 'GoFood/GoShop', icon: '≡ƒ¢╡' },
  { id: 'WHATSAPP', name: 'WhatsApp Order', icon: '≡ƒô▒' },
  { id: 'WEBSITE', name: 'Website', icon: '≡ƒîÉ' },
  { id: 'ONLINE_DALAM_KOTA', name: 'Online Dalam Kota', icon: '≡ƒÅÖ∩╕Å' },
  { id: 'ONLINE_LUAR_KOTA', name: 'Online Luar Kota', icon: '≡ƒÅÿ∩╕Å' },
  { id: 'ONLINE_LUAR_PROVINSI', name: 'Online Luar Provinsi', icon: '≡ƒù╛' },
  { id: 'OTHER', name: 'Lainnya', icon: '≡ƒö╣' }
];

export default function FinanceHistory({ records, onEdit, onDelete, canEdit = true, canDelete = true }) {
    const [selectedYear, setSelectedYear] = useState('all');
    const [selectedCategory, setSelectedCategory] = useState('all');
    const [selectedType, setSelectedType] = useState('all');
    const [selectedChannel, setSelectedChannel] = useState('all'); // Γ£à NEW: Sales Channel filter
    const [searchQuery, setSearchQuery] = useState('');
    const [customDateRange, setCustomDateRange] = useState({ start: '', end: '' });
    const [dateFilterMode, setDateFilterMode] = useState('year');
    // Γ£à NEW: Bulk recategorization
    const [selectedRecords, setSelectedRecords] = useState(new Set());
    const [showBulkActions, setShowBulkActions] = useState(false);
    const [bulkNewCategory, setBulkNewCategory] = useState('');
    const [bulkNewChannel, setBulkNewChannel] = useState('');
    const [isBulkUpdating, setIsBulkUpdating] = useState(false);

    const availableYears = useMemo(() => {
        const years = new Set();
        records.forEach(record => {
            try {
                const year = new Date(record.date).getFullYear();
                if (!isNaN(year)) {
                    years.add(year.toString());
                }
            } catch (e) {}
        });
        return Array.from(years).sort((a, b) => b - a);
    }, [records]);

    const formatSafeDate = (dateString, formatStr = 'd MMMM yyyy') => {
        try {
            if (!dateString) return '-';
            const date = new Date(dateString);
            if (isNaN(date.getTime())) return '-';
            return format(date, formatStr, { locale: id });
        } catch (error) {
            return '-';
        }
    };

    const categories = useMemo(() => {
        return [...new Set(records.map(r => r.category).filter(Boolean))];
    }, [records]);

    const filteredRecords = useMemo(() => {
        const filtered = records.filter(record => {
            try {
                const recordDate = new Date(record.date);
                const recordYear = recordDate.getFullYear().toString();
                
                let matchesDate = true;
                if (dateFilterMode === 'year') {
                    matchesDate = selectedYear === 'all' || recordYear === selectedYear;
                } else if (dateFilterMode === 'custom' && customDateRange.start && customDateRange.end) {
                    const startDate = new Date(customDateRange.start);
                    startDate.setHours(0, 0, 0, 0);
                    const endDate = new Date(customDateRange.end);
                    endDate.setHours(23, 59, 59, 999);
                    matchesDate = recordDate >= startDate && recordDate <= endDate;
                }
                
                const matchesCategory = selectedCategory === 'all' || record.category === selectedCategory;
                const matchesType = selectedType === 'all' || record.type === selectedType;
                const matchesChannel = selectedChannel === 'all' || (record.sales_channel || 'OFFLINE') === selectedChannel;
                const matchesSearch = !searchQuery || 
                    record.description?.toLowerCase().includes(searchQuery.toLowerCase()) ||
                    record.category?.toLowerCase().includes(searchQuery.toLowerCase());

                return matchesDate && matchesCategory && matchesType && matchesChannel && matchesSearch;
            } catch (e) {
                return false;
            }
        });

        return filtered.sort((a, b) => {
            try {
                const dateA = new Date(a.date || a.created_date);
                const dateB = new Date(b.date || b.created_date);
                return dateB - dateA;
            } catch (e) {
                return 0;
            }
        });
    }, [records, selectedYear, selectedCategory, selectedType, selectedChannel, searchQuery, dateFilterMode, customDateRange]);

    // Γ£à Bulk recategorize handler
    const handleBulkRecategorize = async () => {
        if (selectedRecords.size === 0) return;
        if (!bulkNewCategory && !bulkNewChannel) {
            return;
        }
        setIsBulkUpdating(true);
        try {
            const { base44 } = await import('@/api/base44Client');
            const { toast } = await import('sonner');
            for (const id of selectedRecords) {
                const updateData = {};
                if (bulkNewCategory) updateData.category = bulkNewCategory;
                if (bulkNewChannel) updateData.sales_channel = bulkNewChannel;
                await base44.entities.FinancialRecord.update(id, updateData);
            }
            toast.success(`Γ£à ${selectedRecords.size} transaksi berhasil diperbarui`);
            setSelectedRecords(new Set());
            setBulkNewCategory('');
            setBulkNewChannel('');
            setShowBulkActions(false);
        } catch (e) {
            const { toast } = await import('sonner');
            toast.error('Gagal memperbarui: ' + e.message);
        } finally {
            setIsBulkUpdating(false);
        }
    };

    const toggleSelect = (id) => {
        const next = new Set(selectedRecords);
        next.has(id) ? next.delete(id) : next.add(id);
        setSelectedRecords(next);
    };

    const selectAll = () => {
        if (selectedRecords.size === filteredRecords.length) {
            setSelectedRecords(new Set());
        } else {
            setSelectedRecords(new Set(filteredRecords.map(r => r.id)));
        }
    };

    const stats = useMemo(() => {
        const income = filteredRecords.filter(r => r.type === 'income').reduce((sum, r) => sum + (r.amount || 0), 0);
        const expense = filteredRecords.filter(r => r.type === 'expense').reduce((sum, r) => sum + (r.amount || 0), 0);
        return {
            totalIncome: income,
            totalExpense: expense,
            netAmount: income - expense,
            transactionCount: filteredRecords.length
        };
    }, [filteredRecords]);

    return (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <Card className="bg-gray-900 border-gray-700">
                    <CardContent className="p-4">
                        <div className="text-2xl font-bold text-green-600">
                            Rp {stats.totalIncome.toLocaleString('id-ID')}
                        </div>
                        <p className="text-sm text-gray-400">Total Pemasukan</p>
                    </CardContent>
                </Card>
                <Card className="bg-gray-900 border-gray-700">
                    <CardContent className="p-4">
                        <div className="text-2xl font-bold text-red-600">
                            Rp {stats.totalExpense.toLocaleString('id-ID')}
                        </div>
                        <p className="text-sm text-gray-400">Total Pengeluaran</p>
                    </CardContent>
                </Card>
                <Card className="bg-gray-900 border-gray-700">
                    <CardContent className="p-4">
                        <div className={`text-2xl font-bold ${stats.netAmount >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                            Rp {stats.netAmount.toLocaleString('id-ID')}
                        </div>
                        <p className="text-sm text-gray-400">Selisih Bersih</p>
                    </CardContent>
                </Card>
                <Card className="bg-gray-900 border-gray-700">
                    <CardContent className="p-4">
                        <div className="text-2xl font-bold text-blue-600">
                            {stats.transactionCount}
                        </div>
                        <p className="text-sm text-gray-400">Total Transaksi</p>
                    </CardContent>
                </Card>
            </div>

            <Card className="bg-gray-900 border-gray-700">
                <CardHeader>
                    <CardTitle className="flex items-center gap-2 text-white">
                        <Filter className="text-blue-500" />
                        Filter Riwayat
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                        <div>
                            <label className="text-sm font-medium mb-2 block text-gray-300">Filter Tanggal</label>
                            <Select value={dateFilterMode} onValueChange={(v) => {
                                setDateFilterMode(v);
                                if (v === 'year') {
                                    setCustomDateRange({ start: '', end: '' });
                                }
                            }}>
                                <SelectTrigger className="bg-gray-800 border-gray-700 text-white">
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent className="bg-gray-800 border-gray-700">
                                    <SelectItem value="year">Per Tahun</SelectItem>
                                    <SelectItem value="custom">Custom Range</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        
                        {dateFilterMode === 'year' ? (
                            <div>
                                <label className="text-sm font-medium mb-2 block text-gray-300">Tahun</label>
                                <Select value={selectedYear} onValueChange={setSelectedYear}>
                                    <SelectTrigger className="bg-gray-800 border-gray-700 text-white">
                                        <SelectValue placeholder="Pilih tahun" />
                                    </SelectTrigger>
                                    <SelectContent className="bg-gray-800 border-gray-700">
                                        <SelectItem value="all">Semua Tahun</SelectItem>
                                        {availableYears.map(year => (
                                            <SelectItem key={year} value={year}>{year}</SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>
                        ) : (
                            <>
                                <div>
                                    <label className="text-sm font-medium mb-2 block text-gray-300">Dari Tanggal</label>
                                    <Input
                                        type="date"
                                        value={customDateRange.start}
                                        onChange={(e) => setCustomDateRange({ ...customDateRange, start: e.target.value })}
                                        className="bg-gray-800 border-gray-700 text-white"
                                    />
                                </div>
                                <div>
                                    <label className="text-sm font-medium mb-2 block text-gray-300">Sampai Tanggal</label>
                                    <Input
                                        type="date"
                                        value={customDateRange.end}
                                        onChange={(e) => setCustomDateRange({ ...customDateRange, end: e.target.value })}
                                        className="bg-gray-800 border-gray-700 text-white"
                                    />
                                </div>
                            </>
                        )}
                        
                        <div className={dateFilterMode === 'custom' ? 'md:col-start-1' : ''}>
                            <label className="text-sm font-medium mb-2 block text-gray-300">Kategori</label>
                            <Select value={selectedCategory} onValueChange={setSelectedCategory}>
                                <SelectTrigger className="bg-gray-800 border-gray-700 text-white">
                                    <SelectValue placeholder="Pilih kategori" />
                                </SelectTrigger>
                                <SelectContent className="bg-gray-800 border-gray-700">
                                    <SelectItem value="all">Semua Kategori</SelectItem>
                                    {categories.map(category => (
                                        <SelectItem key={category} value={category}>{category}</SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                        
                        <div className={dateFilterMode === 'custom' ? 'md:col-start-1' : ''}>
                            <label className="text-sm font-medium mb-2 block text-gray-300">Jenis</label>
                            <Select value={selectedType} onValueChange={setSelectedType}>
                                <SelectTrigger className="bg-gray-800 border-gray-700 text-white">
                                    <SelectValue placeholder="Pilih jenis" />
                                </SelectTrigger>
                                <SelectContent className="bg-gray-800 border-gray-700">
                                    <SelectItem value="all">Semua Jenis</SelectItem>
                                    <SelectItem value="income">Pemasukan</SelectItem>
                                    <SelectItem value="expense">Pengeluaran</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        {/* Γ£à NEW: Sales Channel Filter */}
                        <div>
                            <label className="text-sm font-medium mb-2 block text-gray-300">Channel Penjualan</label>
                            <Select value={selectedChannel} onValueChange={setSelectedChannel}>
                                <SelectTrigger className="bg-gray-800 border-gray-700 text-white">
                                    <SelectValue placeholder="Semua Channel" />
                                </SelectTrigger>
                                <SelectContent className="bg-gray-800 border-gray-700">
                                    <SelectItem value="all">Semua Channel</SelectItem>
                                    {SALES_CHANNELS.map(ch => (
                                        <SelectItem key={ch.id} value={ch.id} className="text-white">
                                            {ch.icon} {ch.name}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                        <div>
                            <label className="text-sm font-medium mb-2 block text-gray-300">Cari</label>
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
                                <Input
                                    placeholder="Cari transaksi..."
                                    value={searchQuery}
                                    onChange={(e) => setSearchQuery(e.target.value)}
                                    className="pl-10 bg-gray-800 border-gray-700 text-white"
                                />
                            </div>
                        </div>
                    </div>
                </CardContent>
            </Card>

            {/* Γ£à Bulk Actions Bar */}
            {selectedRecords.size > 0 && (
                <div className="bg-blue-900/50 border border-blue-600 rounded-lg p-3 flex flex-wrap items-center gap-3">
                    <span className="text-blue-300 text-sm font-semibold">{selectedRecords.size} dipilih</span>
                    <div className="flex flex-wrap gap-2 flex-1 items-center">
                        <div>
                            <label className="text-xs text-gray-400 block mb-1">Ganti Kategori</label>
                            <Select value={bulkNewCategory} onValueChange={setBulkNewCategory}>
                                <SelectTrigger className="bg-gray-800 border-gray-600 text-white text-xs h-8 w-44">
                                    <SelectValue placeholder="Pilih kategori" />
                                </SelectTrigger>
                                <SelectContent className="bg-gray-800 border-gray-700">
                                    {[...new Set(records.map(r => r.category).filter(Boolean))].map(cat => (
                                        <SelectItem key={cat} value={cat} className="text-white text-xs">{cat}</SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                        <div>
                            <label className="text-xs text-gray-400 block mb-1">Ganti Channel</label>
                            <Select value={bulkNewChannel} onValueChange={setBulkNewChannel}>
                                <SelectTrigger className="bg-gray-800 border-gray-600 text-white text-xs h-8 w-44">
                                    <SelectValue placeholder="Pilih channel" />
                                </SelectTrigger>
                                <SelectContent className="bg-gray-800 border-gray-700">
                                    {SALES_CHANNELS.map(ch => (
                                        <SelectItem key={ch.id} value={ch.id} className="text-white text-xs">{ch.icon} {ch.name}</SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                        <Button
                            size="sm"
                            onClick={handleBulkRecategorize}
                            disabled={isBulkUpdating || (!bulkNewCategory && !bulkNewChannel)}
                            className="bg-blue-600 hover:bg-blue-700 text-xs h-8 mt-auto">
                            {isBulkUpdating ? '...' : 'Γ£à Terapkan'}
                        </Button>
                        <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => { setSelectedRecords(new Set()); setBulkNewCategory(''); setBulkNewChannel(''); }}
                            className="text-gray-400 text-xs h-8 mt-auto">
                            Γ£ò Batal
                        </Button>
                    </div>
                </div>
            )}

            <Card className="bg-gray-900 border-gray-700">
                <CardHeader>
                    <CardTitle className="flex items-center justify-between flex-wrap gap-2 text-white">
                        <span className="flex items-center gap-2">
                            <Calendar className="text-green-500" />
                            Riwayat Transaksi
                        </span>
                        <div className="flex items-center gap-4">
                            <Button size="sm" variant="outline" onClick={() => setShowBulkActions(!showBulkActions)}
                                className="border-gray-600 text-gray-300 text-xs h-7">
                                Γÿæ∩╕Å Pilih
                            </Button>
                            <Badge variant="outline" className="border-gray-600 text-gray-300">
                                {filteredRecords.length} transaksi
                            </Badge>
                            <FinanceExportActions records={filteredRecords} />
                        </div>
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    {filteredRecords.length > 0 ? (
                        <div className="overflow-x-auto">
                            <table className="w-full min-w-[700px]">
                                <thead>
                                    <tr className="border-b border-gray-700 bg-gray-800">
                                        {showBulkActions && <th className="p-3 w-8">
                                            <input type="checkbox"
                                                checked={selectedRecords.size === filteredRecords.length && filteredRecords.length > 0}
                                                onChange={selectAll}
                                                className="w-4 h-4" />
                                        </th>}
                                        <th className="text-left p-3 text-sm font-semibold text-gray-400">Tanggal</th>
                                        <th className="text-left p-3 text-sm font-semibold text-gray-400">Deskripsi</th>
                                        <th className="text-left p-3 text-sm font-semibold text-gray-400">Kategori</th>
                                        <th className="text-left p-3 text-sm font-semibold text-gray-400">Channel</th>
                                        <th className="text-left p-3 text-sm font-semibold text-gray-400">Tipe</th>
                                        <th className="text-right p-3 text-sm font-semibold text-gray-400">Jumlah</th>
                                        {(canEdit || canDelete) && (
                                            <th className="text-right p-3 text-sm font-semibold text-gray-400">Aksi</th>
                                        )}
                                    </tr>
                                </thead>
                                <tbody>
                                    {filteredRecords.map((record) => {
                                        const ch = SALES_CHANNELS.find(c => c.id === record.sales_channel);
                                        return (
                                        <tr key={record.id} className={`border-b border-gray-800 hover:bg-gray-800 ${selectedRecords.has(record.id) ? 'bg-blue-900/20' : ''}`}>
                                            {showBulkActions && <td className="p-3">
                                                <input type="checkbox"
                                                    checked={selectedRecords.has(record.id)}
                                                    onChange={() => toggleSelect(record.id)}
                                                    className="w-4 h-4" />
                                            </td>}
                                            <td className="p-3 text-sm text-gray-300">
                                                {formatSafeDate(record.date, 'dd MMM yyyy')}
                                            </td>
                                            <td className="p-3 text-sm text-gray-300 max-w-[180px] truncate">
                                                {record.description || '-'}
                                            </td>
                                            <td className="p-3">
                                                <Badge className={record.type === 'income' ? 'bg-green-100 text-green-800 text-xs' : 'bg-red-100 text-red-800 text-xs'}>
                                                    {record.category || '-'}
                                                </Badge>
                                            </td>
                                            <td className="p-3">
                                                {ch ? (
                                                    <span className="text-xs text-gray-400">{ch.icon} {ch.name}</span>
                                                ) : (
                                                    <span className="text-xs text-gray-600">-</span>
                                                )}
                                            </td>
                                            <td className="p-3">
                                                <Badge variant="outline" className="text-xs border-gray-600 text-gray-300">
                                                    {record.type === 'income' ? 'Pemasukan' : 'Pengeluaran'}
                                                </Badge>
                                            </td>
                                            <td className="p-3 text-right">
                                                <span className={`font-semibold ${record.type === 'income' ? 'text-green-600' : 'text-red-600'}`}>
                                                    {record.type === 'income' ? '+' : '-'}Rp {(record.amount || 0).toLocaleString('id-ID')}
                                                </span>
                                            </td>
                                            {(canEdit || canDelete) && (
                                                <td className="p-3 text-right">
                                                    <div className="flex justify-end gap-2">
                                                        {canEdit && onEdit && (
                                                            <Button
                                                                variant="ghost"
                                                                size="sm"
                                                                onClick={() => onEdit(record)}
                                                                className="text-gray-400 hover:text-white hover:bg-gray-700 h-8 w-8 p-0">
                                                                <Edit className="w-4 h-4" />
                                                            </Button>
                                                        )}
                                                        {canDelete && onDelete && (
                                                            <Button
                                                                variant="ghost"
                                                                size="sm"
                                                                onClick={() => onDelete(record.id)}
                                                                className="text-red-500 hover:text-red-400 hover:bg-gray-700 h-8 w-8 p-0">
                                                                <Trash2 className="w-4 h-4" />
                                                            </Button>
                                                        )}
                                                    </div>
                                                </td>
                                            )}
                                        </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    ) : (
                        <div className="text-center py-8">
                            <Calendar className="w-12 h-12 text-gray-400 mx-auto mb-4" />
                            <h3 className="text-lg font-semibold mb-2 text-white">Tidak Ada Data</h3>
                            <p className="text-gray-400">
                                Tidak ditemukan transaksi dengan kriteria yang dipilih.
                            </p>
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}

import React from 'react';
import { Card, CardContent } from '@/components/ui/card';
import { TrendingUp, TrendingDown, DollarSign, Wallet } from 'lucide-react';

export default function FinanceStats({ records, isLoading }) {
  // Γ£à NEW FORMAT: Rp 21.424.000 (full number with thousand separator)
  const formatCurrency = (amount) => {
    return `Rp ${Number(amount || 0).toLocaleString('id-ID')}`;
  };

  // Calculate stats from records
  const stats = React.useMemo(() => {
    if (!records || records.length === 0) {
      return {
        totalIncome: 0,
        totalExpense: 0,
        balance: 0,
        totalTransactions: 0
      };
    }

    const income = records.filter(r => r.type === 'income').reduce((sum, r) => sum + (r.amount || 0), 0);
    const expense = records.filter(r => r.type === 'expense').reduce((sum, r) => sum + (r.amount || 0), 0);

    return {
      totalIncome: income,
      totalExpense: expense,
      balance: income - expense,
      totalTransactions: records.length
    };
  }, [records]);

  return (
    <div className="grid grid-cols-2 lg:grid-cols-4 gap-2 sm:gap-4">
      <Card className="bg-gray-900 border-gray-700">
        <CardContent className="p-3 sm:p-6">
          <div className="flex items-center justify-between">
            <div className="flex-1 min-w-0">
              <p className="text-gray-400 text-xs sm:text-sm truncate">Total Pemasukan</p>
              <p className="text-base sm:text-2xl font-bold text-green-600 mt-1 truncate">
                {formatCurrency(stats.totalIncome)}
              </p>
            </div>
            <TrendingUp className="w-6 h-6 sm:w-10 sm:h-10 text-green-500 flex-shrink-0" />
          </div>
        </CardContent>
      </Card>

      <Card className="bg-gray-900 border-gray-700">
        <CardContent className="p-3 sm:p-6">
          <div className="flex items-center justify-between">
            <div className="flex-1 min-w-0">
              <p className="text-gray-400 text-xs sm:text-sm truncate">Total Pengeluaran</p>
              <p className="text-base sm:text-2xl font-bold text-red-600 mt-1 truncate">
                {formatCurrency(stats.totalExpense)}
              </p>
            </div>
            <TrendingDown className="w-6 h-6 sm:w-10 sm:h-10 text-red-500 flex-shrink-0" />
          </div>
        </CardContent>
      </Card>

      <Card className="bg-gray-900 border-gray-700">
        <CardContent className="p-3 sm:p-6">
          <div className="flex items-center justify-between">
            <div className="flex-1 min-w-0">
              <p className="text-gray-400 text-xs sm:text-sm truncate">Saldo Bersih</p>
              <p className={`text-base sm:text-2xl font-bold mt-1 truncate ${stats.balance >= 0 ? 'text-blue-600' : 'text-red-600'}`}>
                {formatCurrency(stats.balance)}
              </p>
            </div>
            <Wallet className="w-6 h-6 sm:w-10 sm:h-10 text-blue-500 flex-shrink-0" />
          </div>
        </CardContent>
      </Card>

      <Card className="bg-gray-900 border-gray-700">
        <CardContent className="p-3 sm:p-6">
          <div className="flex items-center justify-between">
            <div className="flex-1 min-w-0">
              <p className="text-gray-400 text-xs sm:text-sm truncate">Total Transaksi</p>
              <p className="text-base sm:text-2xl font-bold text-white mt-1">{stats.totalTransactions}</p>
            </div>
            <DollarSign className="w-6 h-6 sm:w-10 sm:h-10 text-purple-500 flex-shrink-0" />
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { Download, FileText } from 'lucide-react';
import { format, startOfMonth, endOfMonth } from 'date-fns';
import { id } from 'date-fns/locale';

export default function FinancialReports({ records, accounts = [], startDate, endDate, companyName, mode }) {
  const [selectedReport, setSelectedReport] = useState('income_statement');

  // Logic filter removed (handled in parent)

  // Safe date handling with fallbacks
  const safeStartDate = useMemo(() => {
    if (startDate && startDate instanceof Date && !isNaN(startDate)) {
      return startDate;
    }
    return startOfMonth(new Date());
  }, [startDate]);

  const safeEndDate = useMemo(() => {
    if (endDate && endDate instanceof Date && !isNaN(endDate)) {
      return endDate;
    }
    return endOfMonth(new Date());
  }, [endDate]);

  const financialData = useMemo(() => {
    if (!records || records.length === 0) {
      return {
        totalIncome: 0,
        totalExpense: 0,
        netProfit: 0,
        profitMargin: 0,
        incomeByCategory: {},
        expenseByCategory: {},
        monthlyData: {},
        cashFlow: [],
        recordCount: 0
      };
    }

    const income = records.filter(r => r.type === 'income');
    const expense = records.filter(r => r.type === 'expense');

    const incomeByCategory = {};
    income.forEach(r => {
      const cat = r.category || 'Lainnya';
      incomeByCategory[cat] = (incomeByCategory[cat] || 0) + r.amount;
    });

    const expenseByCategory = {};
    expense.forEach(r => {
      const cat = r.category || 'Lainnya';
      expenseByCategory[cat] = (expenseByCategory[cat] || 0) + r.amount;
    });

    const totalIncome = income.reduce((sum, r) => sum + r.amount, 0);
    const totalExpense = expense.reduce((sum, r) => sum + r.amount, 0);
    const netProfit = totalIncome - totalExpense;
    const profitMargin = totalIncome > 0 ? (netProfit / totalIncome * 100) : 0;

    const monthlyData = {};
    records.forEach(r => {
      try {
        const month = format(new Date(r.date), 'yyyy-MM');
        if (!monthlyData[month]) {
          monthlyData[month] = { income: 0, expense: 0 };
        }
        if (r.type === 'income') {
          monthlyData[month].income += r.amount;
        } else {
          monthlyData[month].expense += r.amount;
        }
      } catch (err) {
        console.warn('Invalid date in record:', r.date);
      }
    });

    let runningBalance = 0;
    const cashFlow = records
      .sort((a, b) => new Date(a.date) - new Date(b.date))
      .map(r => {
        if (r.type === 'income') {
          runningBalance += r.amount;
        } else {
          runningBalance -= r.amount;
        }
        return {
          date: r.date,
          description: r.description,
          category: r.category,
          type: r.type,
          amount: r.amount,
          balance: runningBalance
        };
      });

    return {
      totalIncome,
      totalExpense,
      netProfit,
      profitMargin,
      incomeByCategory,
      expenseByCategory,
      monthlyData,
      cashFlow,
      recordCount: records.length
    };
  }, [records]);

  const arrayToCSV = (data) => {
    return data.map(row =>
      row.map(cell => {
        if (typeof cell === 'string' && (cell.includes(',') || cell.includes('"'))) {
          return `"${cell.replace(/"/g, '""')}"`;
        }
        return cell;
      }).join(',')
    ).join('\n');
  };

  const downloadCSV = (data, filename) => {
    const csv = arrayToCSV(data);
    const blob = new Blob(['\ufeff' + csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `${filename}_${format(new Date(), 'yyyyMMdd')}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const safeFormatDate = (date, formatStr = 'dd MMMM yyyy') => {
    try {
      if (!date) return '-';
      const dateObj = date instanceof Date ? date : new Date(date);
      if (isNaN(dateObj.getTime())) return '-';
      return format(dateObj, formatStr, { locale: id });
    } catch (err) {
      console.error('Date formatting error:', err);
      return '-';
    }
  };

  const generateIncomeStatement = () => {
    return [
      ['LAPORAN LABA RUGI (INCOME STATEMENT)'],
      [companyName || 'Personal Finance'],
      [`Periode: ${safeFormatDate(safeStartDate)} - ${safeFormatDate(safeEndDate)}`],
      [''],
      ['PENDAPATAN (REVENUE)'],
      ...Object.entries(financialData.incomeByCategory).map(([cat, amount]) => [
        `  ${cat}`, '', `Rp ${amount.toLocaleString('id-ID')}`
      ]),
      ['', 'Total Pendapatan', `Rp ${financialData.totalIncome.toLocaleString('id-ID')}`],
      [''],
      ['BEBAN OPERASIONAL (OPERATING EXPENSES)'],
      ...Object.entries(financialData.expenseByCategory).map(([cat, amount]) => [
        `  ${cat}`, '', `Rp ${amount.toLocaleString('id-ID')}`
      ]),
      ['', 'Total Beban', `Rp ${financialData.totalExpense.toLocaleString('id-ID')}`],
      [''],
      ['LABA/RUGI BERSIH', '', `Rp ${financialData.netProfit.toLocaleString('id-ID')}`],
      ['Margin Laba', '', `${financialData.profitMargin.toFixed(2)}%`],
      ['Status', '', financialData.netProfit >= 0 ? 'SURPLUS' : 'DEFISIT']
    ];
  };

  const generateBalanceSheet = () => {
    return [
      ['NERACA (BALANCE SHEET)'],
      [companyName || 'Personal Finance'],
      [`Per Tanggal: ${safeFormatDate(safeEndDate)}`],
      [''],
      ['ASET (ASSETS)'],
      ['  Kas dan Setara Kas', '', `Rp ${financialData.netProfit.toLocaleString('id-ID')}`],
      ['Total Aset', '', `Rp ${financialData.netProfit.toLocaleString('id-ID')}`],
      [''],
      ['KEWAJIBAN (LIABILITIES)'],
      ['  Hutang Usaha', '', 'Rp 0'],
      ['Total Kewajiban', '', 'Rp 0'],
      [''],
      ['EKUITAS (EQUITY)'],
      ['  Modal', '', `Rp ${financialData.totalIncome.toLocaleString('id-ID')}`],
      ['  Laba Ditahan', '', `Rp ${financialData.netProfit.toLocaleString('id-ID')}`],
      ['Total Ekuitas', '', `Rp ${(financialData.totalIncome + financialData.netProfit).toLocaleString('id-ID')}`]
    ];
  };

  const generateCashFlow = () => {
    return [
      ['LAPORAN ARUS KAS'],
      [companyName || 'Personal Finance'],
      [`Periode: ${safeFormatDate(safeStartDate)} - ${safeFormatDate(safeEndDate)}`],
      [''],
      ['Kas dari Pendapatan', '', `Rp ${financialData.totalIncome.toLocaleString('id-ID')}`],
      ['Kas untuk Beban', '', `Rp (${financialData.totalExpense.toLocaleString('id-ID')})`],
      ['Kas Bersih Operasi', '', `Rp ${financialData.netProfit.toLocaleString('id-ID')}`]
    ];
  };

  const generateTransactionDetail = () => {
    return [
      ['LAPORAN TRANSAKSI DETAIL'],
      [companyName || 'Personal Finance'],
      [`Periode: ${safeFormatDate(safeStartDate)} - ${safeFormatDate(safeEndDate)}`],
      [''],
      ['Tanggal', 'Deskripsi', 'Kategori', 'Tipe', 'Jumlah', 'Saldo'],
      ...financialData.cashFlow.map(cf => [
        safeFormatDate(cf.date, 'dd/MM/yyyy'),
        cf.description || '-',
        cf.category || '-',
        cf.type === 'income' ? 'Pemasukan' : 'Pengeluaran',
        `Rp ${cf.amount.toLocaleString('id-ID')}`,
        `Rp ${cf.balance.toLocaleString('id-ID')}`
      ])
    ];
  };

  const generateCategoryAnalysis = () => {
    return [
      ['ANALISA PER KATEGORI'],
      [companyName || 'Personal Finance'],
      [`Periode: ${safeFormatDate(safeStartDate)} - ${safeFormatDate(safeEndDate)}`],
      [''],
      ['PENDAPATAN PER KATEGORI'],
      ['Kategori', 'Jumlah', 'Persentase'],
      ...Object.entries(financialData.incomeByCategory).map(([cat, amount]) => [
        cat,
        `Rp ${amount.toLocaleString('id-ID')}`,
        `${financialData.totalIncome > 0 ? ((amount / financialData.totalIncome) * 100).toFixed(2) : 0}%`
      ]),
      [''],
      ['PENGELUARAN PER KATEGORI'],
      ['Kategori', 'Jumlah', 'Persentase'],
      ...Object.entries(financialData.expenseByCategory).map(([cat, amount]) => [
        cat,
        `Rp ${amount.toLocaleString('id-ID')}`,
        `${financialData.totalExpense > 0 ? ((amount / financialData.totalExpense) * 100).toFixed(2) : 0}%`
      ])
    ];
  };

  const generateMonthlyReport = () => {
    return [
      ['LAPORAN BULANAN'],
      [companyName || 'Personal Finance'],
      [`Periode: ${safeFormatDate(safeStartDate)} - ${safeFormatDate(safeEndDate)}`],
      [''],
      ['Bulan', 'Pendapatan', 'Pengeluaran', 'Laba/Rugi', 'Margin'],
      ...Object.entries(financialData.monthlyData)
        .sort(([a], [b]) => a.localeCompare(b))
        .map(([month, data]) => {
          const profit = data.income - data.expense;
          const margin = data.income > 0 ? (profit / data.income * 100) : 0;
          return [
            safeFormatDate(new Date(month + '-01'), 'MMMM yyyy'),
            `Rp ${data.income.toLocaleString('id-ID')}`,
            `Rp ${data.expense.toLocaleString('id-ID')}`,
            `Rp ${profit.toLocaleString('id-ID')}`,
            `${margin.toFixed(2)}%`
          ];
        })
    ];
  };

  const generateTaxReport = () => {
    return [
      ['LAPORAN PAJAK SPT'],
      [companyName || 'Personal Finance'],
      [`Tahun: ${safeFormatDate(safeStartDate, 'yyyy')}`],
      [''],
      ['A. PENGHASILAN BRUTO', '', `Rp ${financialData.totalIncome.toLocaleString('id-ID')}`],
      ['B. PENGURANGAN', '', `Rp ${financialData.totalExpense.toLocaleString('id-ID')}`],
      ['C. PENGHASILAN NETO', '', `Rp ${financialData.netProfit.toLocaleString('id-ID')}`],
      ['D. PTKP', '', 'Rp 54.000.000'],
      ['E. PKP', '', `Rp ${Math.max(0, financialData.netProfit - 54000000).toLocaleString('id-ID')}`],
      ['F. PPh 5%', '', `Rp ${(Math.max(0, financialData.netProfit - 54000000) * 0.05).toLocaleString('id-ID')}`]
    ];
  };

  // Γ£à NEW: Calculate movements per account (Income/Expense in selected period)
  const accountMovements = useMemo(() => {
    const movements = {};
    accounts.forEach(acc => {
      movements[acc.id] = { income: 0, expense: 0 };
    });

    records.forEach(record => {
      if (movements[record.account_id]) {
        if (record.type === 'income') {
          movements[record.account_id].income += (record.amount || 0);
        } else if (record.type === 'expense') {
          movements[record.account_id].expense += (record.amount || 0);
        }
      }
    });
    return movements;
  }, [records, accounts]);

  // Γ£à NEW: Generate Account Balance Report with Movements
  const generateAccountBalance = () => {
    const totalBalance = accounts.reduce((sum, acc) => sum + (acc.calculated_balance || 0), 0);
    const totalIncome = Object.values(accountMovements).reduce((sum, m) => sum + m.income, 0);
    const totalExpense = Object.values(accountMovements).reduce((sum, m) => sum + m.expense, 0);

    return [
      ['LAPORAN SALDO REKENING & MUTASI'],
      [companyName || 'Personal Finance'],
      [`Periode: ${safeFormatDate(startDate)} - ${safeFormatDate(safeEndDate)}`],
      [''],
      ['Nama Rekening', 'Jenis', 'No. Rekening', 'Masuk (Periode)', 'Keluar (Periode)', 'Saldo Akhir', 'Status'],
      ...accounts.map(account => [
        account.name || '-',
        account.type === 'cash' ? 'Kas/Tunai' :
          account.type === 'bank' ? 'Bank' :
            account.type === 'e-wallet' ? 'E-Wallet' : 'Lainnya',
        account.account_number || '-',
        `Rp ${(accountMovements[account.id]?.income || 0).toLocaleString('id-ID')}`,
        `Rp ${(accountMovements[account.id]?.expense || 0).toLocaleString('id-ID')}`,
        `Rp ${(account.calculated_balance || 0).toLocaleString('id-ID')}`,
        account.is_active ? 'Aktif' : 'Nonaktif'
      ]),
      [''],
      ['TOTAL', '', '',
        `Rp ${totalIncome.toLocaleString('id-ID')}`,
        `Rp ${totalExpense.toLocaleString('id-ID')}`,
        `Rp ${totalBalance.toLocaleString('id-ID')}`,
        '']
    ];
  };

  const exportReport = (type) => {
    let data, filename;
    switch (type) {
      case 'income_statement':
        data = generateIncomeStatement();
        filename = 'Laporan_Laba_Rugi';
        break;
      case 'balance_sheet':
        data = generateBalanceSheet();
        filename = 'Neraca';
        break;
      case 'cash_flow':
        data = generateCashFlow();
        filename = 'Arus_Kas';
        break;
      case 'transaction_detail':
        data = generateTransactionDetail();
        filename = 'Detail_Transaksi';
        break;
      case 'category_analysis':
        data = generateCategoryAnalysis();
        filename = 'Analisa_Kategori';
        break;
      case 'monthly_report':
        data = generateMonthlyReport();
        filename = 'Laporan_Bulanan';
        break;
      case 'tax_report':
        data = generateTaxReport();
        filename = 'Laporan_Pajak';
        break;
      case 'account_balance': // Γ£à NEW
        data = generateAccountBalance();
        filename = 'Saldo_Rekening';
        break;
      case 'complete':
        const all = [
          ...generateIncomeStatement(), [''], [''],
          ...generateBalanceSheet(), [''], [''],
          ...generateCashFlow(), [''], [''],
          ...generateTransactionDetail(), [''], [''],
          ...generateCategoryAnalysis(), [''], [''],
          ...generateMonthlyReport(), [''], [''],
          ...generateTaxReport(), [''], [''],
          ...generateAccountBalance() // Γ£à NEW: Include account balance in complete export
        ];
        downloadCSV(all, 'Laporan_Lengkap');
        return;
    }
    downloadCSV(data, filename);
  };

  const exportPDF = (type) => {
    const win = window.open('', '', 'height=800,width=1000');
    let data, title;

    switch (type) {
      case 'income_statement':
        data = generateIncomeStatement();
        title = 'LAPORAN LABA RUGI';
        break;
      case 'balance_sheet':
        data = generateBalanceSheet();
        title = 'NERACA';
        break;
      case 'cash_flow':
        data = generateCashFlow();
        title = 'LAPORAN ARUS KAS';
        break;
      case 'transaction_detail': // Added for PDF export
        data = generateTransactionDetail();
        title = 'LAPORAN DETAIL TRANSAKSI';
        break;
      case 'category_analysis': // Added for PDF export
        data = generateCategoryAnalysis();
        title = 'ANALISA PER KATEGORI';
        break;
      case 'monthly_report': // Added for PDF export
        data = generateMonthlyReport();
        title = 'LAPORAN BULANAN';
        break;
      case 'tax_report': // Added for PDF export
        data = generateTaxReport();
        title = 'LAPORAN PAJAK SPT';
        break;
      case 'account_balance': // Γ£à NEW: Account balance PDF
        data = generateAccountBalance();
        title = 'LAPORAN SALDO REKENING';
        break;
      default:
        data = generateIncomeStatement();
        title = 'LAPORAN';
    }

    win.document.write(`
      <html>
        <head>
          <title>${title}</title>
          <style>
            body { font-family: Arial; padding: 40px; font-size: 12px; }
            table { width: 100%; border-collapse: collapse; margin-top: 20px; }
            td { padding: 8px; border-bottom: 1px solid #ddd; }
            th { text-align: left; padding: 8px; border-bottom: 1px solid #ddd; font-weight: bold; }
            .header { text-align: center; margin-bottom: 30px; }
            .title { font-size: 18px; font-weight: bold; }
            .amount { text-align: right; font-weight: bold; }
            .text-right { text-align: right; }
            .text-left { text-align: left; }
            @media print { body { padding: 20px; } }
          </style>
        </head>
        <body>
          <div class="header">
            <div class="title">${title}</div>
            <div>${companyName || 'Personal Finance'}</div>
            <div>${data[2][0]}</div>
          </div>
          <table>
            ${data.slice(4).map(row => {
      if (row.length === 1 && row[0] === '') return ''; // Skip empty rows used for spacing in CSV
      if (row[0].startsWith('PENDAPATAN') || row[0].startsWith('BEBAN') || row[0].startsWith('LABA/RUGI BERSIH') || row[0].startsWith('ASET') || row[0].startsWith('KEWAJIBAN') || row[0].startsWith('EKUITAS') || row[0].startsWith('Kas dari Pendapatan') || row[0].startsWith('Tanggal') || row[0].startsWith('A. PENGHASILAN BRUTO') || row[0].startsWith('B. PENGURANGAN') || row[0].startsWith('C. PENGHASILAN NETO') || row[0].startsWith('D. PKP') || row[0].startsWith('E. PPh 5%') || row[0].startsWith('Bulan') || row[0].startsWith('Nama Rekening')) {
        // This is likely a header row within the report sections or the transaction detail table header
        if (row[0].startsWith('Tanggal') || row[0].startsWith('Kategori') || row[0].startsWith('Bulan') || row[0].startsWith('Nama Rekening')) { // Specific header for transaction detail, category analysis, monthly report, account balance
          return `<thead><tr>${row.map(cell => `<th class="text-left">${cell || ''}</th>`).join('')}</tr></thead><tbody>`;
        }
        return `<tr><td colspan="${row.length}" style="font-weight: bold; padding-top: 15px; padding-bottom: 5px;">${row[0]}</td></tr>`;
      }
      if (row[1] === 'Total Pendapatan' || row[1] === 'Total Beban' || row[1] === 'Total Aset' || row[1] === 'Total Kewajiban' || row[1] === 'Total Ekuitas' || row[1] === 'Total') {
        // For total rows, align the amounts (usually last columns)
        return `<tr>${row.map((cell, idx) => `<td class="${(cell && cell.toString().includes('Rp')) ? 'amount' : ''}" style="border-top: 1px solid black; font-weight: bold;">${cell || ''}</td>`).join('')}</tr>`;
      }
      return `
                <tr>
                  ${row.map((cell, idx) => {
        let className = '';
        if (typeof cell === 'string' && cell.trim().startsWith('Rp')) className = 'amount'; // Auto-align currency
        else if (idx === row.length - 1 && !isNaN(parseFloat(cell))) className = 'amount'; // Fallback for last column logic only if it looks numeric

        if (row[0].startsWith('  ')) className += ' pl-4'; // Indent sub-items
        if (row[0] === 'LABA/RUGI BERSIH' || row[0] === 'Kas Bersih Operasi' || row[0] === 'C. PENGHASILAN NETO' || row[0] === 'E. PKP') className += ' font-bold';
        return `<td class="${className.trim()}">${cell || ''}</td>`;
      }).join('')}
                </tr>
              `;
    }).join('')}
          </table>
          <script>window.onload = function() { window.print(); window.close(); }</script>
        </body>
      </html>
    `);
    win.document.close();
  };

  return (
    <div className="space-y-4 sm:space-y-6">
      {/* Header Card - Mobile Optimized */}
      <Card className="bg-gray-900/50 border-gray-800">
        <CardHeader className="p-4 sm:p-6">
          <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3 sm:gap-4">
            <div className="w-full sm:w-auto">
              <CardTitle className="text-white flex items-center gap-2 text-base sm:text-lg">
                <FileText className="w-4 h-4 sm:w-5 sm:h-5 text-blue-400 flex-shrink-0" />
                <span>Laporan Keuangan Profesional</span>
              </CardTitle>
              <p className="text-xs sm:text-sm text-gray-400 mt-1">
                Format standar akuntansi (CSV/Excel & PDF)
              </p>
            </div>
            <div className="flex gap-2 w-full sm:w-auto">
              {/* Filter removed (in header) */}

              <Button
                onClick={() => exportReport('complete')}
                className="bg-green-600 hover:bg-green-700 w-full sm:w-auto min-h-[44px] text-sm">
                <Download className="w-4 h-4 mr-2" />
                Export Semua
              </Button>
            </div>
          </div>
        </CardHeader>
      </Card>

      {/* Tabs - Mobile Optimized with Horizontal Scroll */}
      <div className="w-full overflow-x-auto -mx-3 sm:mx-0 px-3 sm:px-0">
        <Tabs value={selectedReport} onValueChange={setSelectedReport}>
          <TabsList className="bg-gray-900/50 inline-flex sm:grid sm:grid-cols-8 w-auto sm:w-full min-w-max border-b border-gray-800">
            <TabsTrigger value="income_statement" className="text-xs sm:text-sm px-3 sm:px-4 whitespace-nowrap">
              Laba Rugi
            </TabsTrigger>
            <TabsTrigger value="balance_sheet" className="text-xs sm:text-sm px-3 sm:px-4 whitespace-nowrap">
              Neraca
            </TabsTrigger>
            <TabsTrigger value="cash_flow" className="text-xs sm:text-sm px-3 sm:px-4 whitespace-nowrap">
              Arus Kas
            </TabsTrigger>
            <TabsTrigger value="transaction_detail" className="text-xs sm:text-sm px-3 sm:px-4 whitespace-nowrap">
              Detail
            </TabsTrigger>
            <TabsTrigger value="category_analysis" className="text-xs sm:text-sm px-3 sm:px-4 whitespace-nowrap">
              Kategori
            </TabsTrigger>
            <TabsTrigger value="monthly_report" className="text-xs sm:text-sm px-3 sm:px-4 whitespace-nowrap">
              Bulanan
            </TabsTrigger>
            <TabsTrigger value="tax_report" className="text-xs sm:text-sm px-3 sm:px-4 whitespace-nowrap">
              Pajak
            </TabsTrigger>
            <TabsTrigger value="account_balance" className="text-xs sm:text-sm px-3 sm:px-4 whitespace-nowrap">
              Saldo
            </TabsTrigger>
          </TabsList>

          {/* Income Statement Tab - Mobile Optimized */}
          <TabsContent value="income_statement" className="mt-4">
            <Card className="bg-gray-900/50 border-gray-800">
              <CardHeader className="p-4 sm:p-6">
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
                  <CardTitle className="text-white text-base sm:text-lg">LAPORAN LABA RUGI</CardTitle>
                  <div className="flex gap-2 w-full sm:w-auto">
                    <Button
                      size="sm"
                      onClick={() => exportReport('income_statement')}
                      className="bg-green-600 flex-1 sm:flex-none min-h-[40px] text-xs sm:text-sm">
                      <Download className="w-3 h-3 sm:w-4 sm:h-4 mr-2" />CSV
                    </Button>
                    <Button
                      size="sm"
                      onClick={() => exportPDF('income_statement')}
                      variant="outline"
                      className="border-gray-700 flex-1 sm:flex-none min-h-[40px] text-xs sm:text-sm">
                      <FileText className="w-3 h-3 sm:w-4 sm:h-4 mr-2" />PDF
                    </Button>
                  </div>
                </div>
              </CardHeader>
              <CardContent className="p-4 sm:p-6">
                <div className="space-y-6">
                  <div>
                    <h3 className="text-lg font-semibold text-white mb-3">PENDAPATAN</h3>
                    <div className="space-y-2">
                      {Object.entries(financialData.incomeByCategory).map(([cat, amount]) => (
                        <div key={cat} className="flex justify-between text-gray-300 pl-4">
                          <span>{cat}</span>
                          <span>Rp {amount.toLocaleString('id-ID')}</span>
                        </div>
                      ))}
                      <div className="flex justify-between font-bold text-white border-t border-gray-700 pt-2">
                        <span>Total Pendapatan</span>
                        <span className="text-green-400">Rp {financialData.totalIncome.toLocaleString('id-ID')}</span>
                      </div>
                    </div>
                  </div>

                  <div>
                    <h3 className="text-lg font-semibold text-white mb-3">BEBAN</h3>
                    <div className="space-y-2">
                      {Object.entries(financialData.expenseByCategory).map(([cat, amount]) => (
                        <div key={cat} className="flex justify-between text-gray-300 pl-4">
                          <span>{cat}</span>
                          <span>Rp {amount.toLocaleString('id-ID')}</span>
                        </div>
                      ))}
                      <div className="flex justify-between font-bold text-white border-t border-gray-700 pt-2">
                        <span>Total Beban</span>
                        <span className="text-red-400">Rp {financialData.totalExpense.toLocaleString('id-ID')}</span>
                      </div>
                    </div>
                  </div>

                  <div className="bg-gray-800/50 p-6 rounded-lg border border-gray-700">
                    <div className="space-y-3">
                      <div className="flex justify-between items-center">
                        <span className="text-xl font-bold text-white">LABA/RUGI BERSIH</span>
                        <span className={`text-2xl font-bold ${financialData.netProfit >= 0 ? 'text-green-400' : 'text-red-400'}`}>
                          Rp {financialData.netProfit.toLocaleString('id-ID')}
                        </span>
                      </div>
                      <div className="flex justify-between text-gray-300">
                        <span>Margin</span>
                        <span>{financialData.profitMargin.toFixed(2)}%</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-white font-semibold">Status</span>
                        <Badge className={financialData.netProfit >= 0 ? 'bg-green-600' : 'bg-red-600'}>
                          {financialData.netProfit >= 0 ? 'SURPLUS' : 'DEFISIT'}
                        </Badge>
                      </div>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Balance Sheet Tab - Mobile Optimized */}
          <TabsContent value="balance_sheet" className="mt-4">
            <Card className="bg-gray-900/50 border-gray-800">
              <CardHeader className="p-4 sm:p-6">
                <div className="flex flex-col sm:flex-row justify-between gap-3">
                  <CardTitle className="text-white text-base sm:text-lg">NERACA</CardTitle>
                  <div className="flex gap-2 w-full sm:w-auto">
                    <Button
                      size="sm"
                      onClick={() => exportReport('balance_sheet')}
                      className="bg-green-600 flex-1 sm:flex-none min-h-[40px] text-xs sm:text-sm">
                      <Download className="w-3 h-3 sm:w-4 sm:h-4 mr-2" />CSV
                    </Button>
                    <Button
                      size="sm"
                      onClick={() => exportPDF('balance_sheet')}
                      variant="outline"
                      className="border-gray-700 flex-1 sm:flex-none min-h-[40px] text-xs sm:text-sm">
                      <FileText className="w-3 h-3 sm:w-4 sm:h-4 mr-2" />PDF
                    </Button>
                  </div>
                </div>
              </CardHeader>
              <CardContent className="p-4 sm:p-6">
                <div className="grid md:grid-cols-2 gap-8">
                  <div>
                    <h3 className="text-lg font-semibold text-white mb-4">ASET</h3>
                    <div className="space-y-3">
                      <div className="flex justify-between text-gray-300 pl-4">
                        <span>Kas</span>
                        <span>Rp {financialData.netProfit.toLocaleString('id-ID')}</span>
                      </div>
                      <div className="flex justify-between font-bold text-white border-t border-gray-700 pt-2">
                        <span>Total Aset</span>
                        <span className="text-blue-400">Rp {financialData.netProfit.toLocaleString('id-ID')}</span>
                      </div>
                    </div>
                  </div>
                  <div>
                    <h3 className="text-lg font-semibold text-white mb-4">KEWAJIBAN & EKUITAS</h3>
                    <div className="space-y-4">
                      <div>
                        <div className="text-gray-400 mb-2">Ekuitas</div>
                        <div className="flex justify-between text-gray-300 pl-4">
                          <span>Modal</span>
                          <span>Rp {financialData.totalIncome.toLocaleString('id-ID')}</span>
                        </div>
                        <div className="flex justify-between text-gray-300 pl-4">
                          <span>Laba</span>
                          <span>Rp {financialData.netProfit.toLocaleString('id-ID')}</span>
                        </div>
                      </div>
                      <div className="flex justify-between font-bold text-white border-t border-gray-700 pt-2">
                        <span>Total</span>
                        <span className="text-blue-400">Rp ${(financialData.totalIncome + financialData.netProfit).toLocaleString('id-ID')}</span>
                      </div>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Cash Flow Tab - Mobile Optimized */}
          <TabsContent value="cash_flow" className="mt-4">
            <Card className="bg-gray-900/50 border-gray-800">
              <CardHeader className="p-4 sm:p-6">
                <div className="flex flex-col sm:flex-row justify-between gap-3">
                  <CardTitle className="text-white text-base sm:text-lg">ARUS KAS</CardTitle>
                  <div className="flex gap-2 w-full sm:w-auto">
                    <Button size="sm" onClick={() => exportReport('cash_flow')} className="bg-green-600 flex-1 sm:flex-none min-h-[40px] text-xs sm:text-sm">
                      <Download className="w-3 h-3 sm:w-4 sm:h-4 mr-2" />CSV
                    </Button>
                    <Button size="sm" onClick={() => exportPDF('cash_flow')} variant="outline" className="border-gray-700 flex-1 sm:flex-none min-h-[40px] text-xs sm:text-sm">
                      <FileText className="w-3 h-3 sm:w-4 sm:h-4 mr-2" />PDF
                    </Button>
                  </div>
                </div>
              </CardHeader>
              <CardContent className="p-4 sm:p-6">
                <div className="space-y-4">
                  <div className="flex justify-between text-gray-300 pl-4">
                    <span>Pendapatan</span>
                    <span className="text-green-400">Rp {financialData.totalIncome.toLocaleString('id-ID')}</span>
                  </div>
                  <div className="flex justify-between text-gray-300 pl-4">
                    <span>Beban</span>
                    <span className="text-red-400">Rp ({financialData.totalExpense.toLocaleString('id-ID')})</span>
                  </div>
                  <div className="bg-gray-800/50 p-6 rounded-lg border border-gray-700">
                    <div className="flex justify-between items-center">
                      <span className="text-xl font-bold text-white">Kas Bersih</span>
                      <span className={`text-2xl font-bold ${financialData.netProfit >= 0 ? 'text-green-400' : 'text-red-400'}`}>
                        Rp {financialData.netProfit.toLocaleString('id-ID')}
                      </span>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Transaction Detail Tab - Mobile Optimized */}
          <TabsContent value="transaction_detail" className="mt-4">
            <Card className="bg-gray-900/50 border-gray-800">
              <CardHeader className="p-4 sm:p-6">
                <div className="flex flex-col sm:flex-row justify-between gap-3">
                  <CardTitle className="text-white text-base sm:text-lg">DETAIL TRANSAKSI</CardTitle>
                  <div className="flex gap-2 w-full sm:w-auto">
                    <Button size="sm" onClick={() => exportReport('transaction_detail')} className="bg-green-600 flex-1 sm:flex-none min-h-[40px] text-xs sm:text-sm">
                      <Download className="w-3 h-3 sm:w-4 sm:h-4 mr-2" />CSV
                    </Button>
                    <Button size="sm" onClick={() => exportPDF('transaction_detail')} variant="outline" className="border-gray-700 flex-1 sm:flex-none min-h-[40px] text-xs sm:text-sm">
                      <FileText className="w-3 h-3 sm:w-4 sm:h-4 mr-2" />PDF
                    </Button>
                  </div>
                </div>
              </CardHeader>
              <CardContent className="p-0">
                <div className="overflow-x-auto">
                  <table className="w-full">
                    <thead>
                      <tr className="border-b border-gray-700">
                        <th className="text-left text-gray-400 py-3 px-4">Tanggal</th>
                        <th className="text-left text-gray-400 py-3 px-4">Deskripsi</th>
                        <th className="text-left text-gray-400 py-3 px-4">Kategori</th>
                        <th className="text-right text-gray-400 py-3 px-4">Jumlah</th>
                        <th className="text-right text-gray-400 py-3 px-4">Saldo</th>
                      </tr>
                    </thead>
                    <tbody>
                      {financialData.cashFlow.map((cf, idx) => (
                        <tr key={idx} className="border-b border-gray-800">
                          <td className="py-3 px-4 text-gray-300">{safeFormatDate(cf.date, 'dd/MM/yyyy')}</td>
                          <td className="py-3 px-4 text-gray-300">{cf.description || '-'}</td>
                          <td className="py-3 px-4 text-gray-300">{cf.category || '-'}</td>
                          <td className="py-3 px-4 text-right text-white">Rp {cf.amount.toLocaleString('id-ID')}</td>
                          <td className="py-3 px-4 text-right text-blue-400">Rp {cf.balance.toLocaleString('id-ID')}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Category Analysis Tab - Mobile Optimized */}
          <TabsContent value="category_analysis" className="mt-4">
            <Card className="bg-gray-900/50 border-gray-800">
              <CardHeader className="p-4 sm:p-6">
                <div className="flex flex-col sm:flex-row justify-between gap-3">
                  <CardTitle className="text-white text-base sm:text-lg">ANALISA KATEGORI</CardTitle>
                  <div className="flex gap-2 w-full sm:w-auto">
                    <Button size="sm" onClick={() => exportReport('category_analysis')} className="bg-green-600 flex-1 sm:flex-none min-h-[40px] text-xs sm:text-sm">
                      <Download className="w-3 h-3 sm:w-4 sm:h-4 mr-2" />CSV
                    </Button>
                    <Button size="sm" onClick={() => exportPDF('category_analysis')} variant="outline" className="border-gray-700 flex-1 sm:flex-none min-h-[40px] text-xs sm:text-sm">
                      <FileText className="w-3 h-3 sm:w-4 sm:h-4 mr-2" />PDF
                    </Button>
                  </div>
                </div>
              </CardHeader>
              <CardContent className="p-4 sm:p-6">
                <div className="grid md:grid-cols-2 gap-8">
                  <div>
                    <h3 className="text-lg font-semibold text-white mb-4">Pendapatan</h3>
                    {Object.entries(financialData.incomeByCategory).map(([cat, amount]) => (
                      <div key={cat} className="space-y-2 mb-3">
                        <div className="flex justify-between text-gray-300">
                          <span>{cat}</span>
                          <span>Rp {amount.toLocaleString('id-ID')} ({financialData.totalIncome > 0 ? ((amount / financialData.totalIncome) * 100).toFixed(1) : 0}%)</span>
                        </div>
                        <div className="w-full bg-gray-800 rounded-full h-2">
                          <div className="bg-green-500 h-2 rounded-full" style={{ width: `${financialData.totalIncome > 0 ? (amount / financialData.totalIncome) * 100 : 0}%` }} />
                        </div>
                      </div>
                    ))}
                  </div>
                  <div>
                    <h3 className="text-lg font-semibold text-white mb-4">Pengeluaran</h3>
                    {Object.entries(financialData.expenseByCategory).map(([cat, amount]) => (
                      <div key={cat} className="space-y-2 mb-3">
                        <div className="flex justify-between text-gray-300">
                          <span>{cat}</span>
                          <span>Rp {amount.toLocaleString('id-ID')} ({financialData.totalExpense > 0 ? ((amount / financialData.totalExpense) * 100).toFixed(1) : 0}%)</span>
                        </div>
                        <div className="w-full bg-gray-800 rounded-full h-2">
                          <div className="bg-red-500 h-2 rounded-full" style={{ width: `${financialData.totalExpense > 0 ? (amount / financialData.totalExpense) * 100 : 0}%` }} />
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Monthly Report Tab - Mobile Optimized */}
          <TabsContent value="monthly_report" className="mt-4">
            <Card className="bg-gray-900/50 border-gray-800">
              <CardHeader className="p-4 sm:p-6">
                <div className="flex flex-col sm:flex-row justify-between gap-3">
                  <CardTitle className="text-white text-base sm:text-lg">LAPORAN BULANAN</CardTitle>
                  <div className="flex gap-2 w-full sm:w-auto">
                    <Button size="sm" onClick={() => exportReport('monthly_report')} className="bg-green-600 flex-1 sm:flex-none min-h-[40px] text-xs sm:text-sm">
