              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 sm:gap-4">
                <div className="p-3 sm:p-4 bg-indigo-900/20 border border-indigo-600/30 rounded-lg">
                  <div className="flex items-center justify-between sm:flex-col sm:items-start gap-2 mb-2">
                    <div className="flex items-center gap-2">
                      <Store className="w-3 h-3 sm:w-4 sm:h-4 text-indigo-400" />
                      <span className="text-xs sm:text-sm text-gray-300">Offline Store</span>
                    </div>
                    <p className="text-xl sm:text-2xl font-bold text-white">{totalStats.offline}</p>
                  </div>
                </div>
                <div className="p-3 sm:p-4 bg-cyan-900/20 border border-cyan-600/30 rounded-lg">
                  <div className="flex items-center justify-between sm:flex-col sm:items-start gap-2 mb-2">
                    <div className="flex items-center gap-2">
                      <Globe className="w-3 h-3 sm:w-4 sm:h-4 text-cyan-400" />
                      <span className="text-xs sm:text-sm text-gray-300">Online Store</span>
                    </div>
                    <p className="text-xl sm:text-2xl font-bold text-white">{totalStats.online}</p>
                  </div>
                </div>
                <div className="p-3 sm:p-4 bg-orange-900/20 border border-orange-600/30 rounded-lg">
                  <div className="flex items-center justify-between sm:flex-col sm:items-start gap-2 mb-2">
                    <div className="flex items-center gap-2">
                      <ShoppingCart className="w-3 h-3 sm:w-4 sm:h-4 text-orange-400" />
                      <span className="text-xs sm:text-sm text-gray-300">Marketplace</span>
                    </div>
                    <p className="text-xl sm:text-2xl font-bold text-white">{totalStats.marketplace}</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Geographic Distribution - Mobile Optimized */}
            <div>
              <h3 className="text-white font-semibold mb-3 flex items-center gap-2 text-sm sm:text-base">
                <MapPin className="w-4 h-4 sm:w-5 sm:h-5 text-cyan-400" />
                Geographic Distribution
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
                <div className="p-3 sm:p-4 bg-green-900/20 border border-green-600/30 rounded-lg">
                  <div className="flex items-center justify-between gap-2">
                    <div className="flex-1 min-w-0">
                      <span className="text-xs sm:text-sm text-gray-300">≡ƒôì Dalam Kota</span>
                      <p className="text-xs text-gray-500 mt-1">Same-day delivery</p>
                    </div>
                    <p className="text-xl sm:text-2xl font-bold text-white flex-shrink-0">{totalStats.sameCity}</p>
                  </div>
                </div>
                <div className="p-3 sm:p-4 bg-blue-900/20 border border-blue-600/30 rounded-lg">
                  <div className="flex items-center justify-between gap-2">
                    <div className="flex-1 min-w-0">
                      <span className="text-xs sm:text-sm text-gray-300">≡ƒÜÜ Luar Kota</span>
                      <p className="text-xs text-gray-500 mt-1">1-3 days shipping</p>
                    </div>
                    <p className="text-xl sm:text-2xl font-bold text-white flex-shrink-0">{totalStats.otherCities}</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Per-Location Details - Mobile Optimized */}
            <div>
              <h3 className="text-white font-semibold mb-3 text-sm sm:text-base">Stock by Location</h3>
              {inventoryList.length === 0 ? (
                <div className="text-center py-6 sm:py-8 text-gray-400">
                  <Package className="w-10 h-10 sm:w-12 sm:h-12 mx-auto mb-2 opacity-50" />
                  <p className="text-xs sm:text-sm">Belum ada inventory untuk produk ini</p>
                </div>
              ) : (
                <div className="space-y-2 sm:space-y-3">
                  {inventoryList.map((inv) => (
                    <div key={inv.id} className="p-3 sm:p-4 bg-gray-800/50 rounded-lg border border-gray-700">
                      {/* Mobile Layout - Stacked */}
                      <div className="block sm:hidden space-y-3">
                        <div className="flex items-center justify-between">
                          <div className="flex-1 min-w-0">
                            <p className="text-white font-medium text-sm truncate">{inv.location_name || 'Unknown Location'}</p>
                            <Badge className={
                              inv.stock_status === 'in_stock' ? 'bg-green-600' :
                              inv.stock_status === 'low_stock' ? 'bg-yellow-600' :
                              'bg-red-600'
                            }>
                              {inv.stock_status || 'unknown'}
                            </Badge>
                          </div>
                          <div className="text-right flex-shrink-0">
                            <p className="text-xl font-bold text-white">{inv.quantity || 0}</p>
                            <p className="text-xs text-gray-400">Avail: {inv.available_quantity || 0}</p>
                          </div>
                        </div>

                        {inv.channel_allocations && (
                          <div className="grid grid-cols-3 gap-2 text-xs">
                            <div className="text-center p-2 bg-indigo-900/20 rounded">
                              <p className="text-gray-400">≡ƒÅ¬ Offline</p>
                              <p className="text-white font-semibold">{inv.channel_allocations.offline || 0}</p>
                            </div>
                            <div className="text-center p-2 bg-cyan-900/20 rounded">
                              <p className="text-gray-400">≡ƒÆ╗ Online</p>
                              <p className="text-white font-semibold">{inv.channel_allocations.online || 0}</p>
                            </div>
                            <div className="text-center p-2 bg-orange-900/20 rounded">
                              <p className="text-gray-400">≡ƒ¢Æ Market</p>
                              <p className="text-white font-semibold">{inv.channel_allocations.marketplace || 0}</p>
                            </div>
                          </div>
                        )}

                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => {
                            setSelectedInventory(inv);
                            setShowAllocationForm(true);
                          }}
                          className="border-gray-700 w-full text-xs"
                        >
                          <Edit className="w-3 h-3 mr-2" />
                          Edit Allocation
                        </Button>
                      </div>

                      {/* Desktop Layout - Horizontal */}
                      <div className="hidden sm:block">
                        <div className="flex items-center justify-between mb-3">
                          <div>
                            <p className="text-white font-medium">{inv.location_name || 'Unknown Location'}</p>
                            <div className="flex items-center gap-2 mt-1">
                              <Badge className={
                                inv.stock_status === 'in_stock' ? 'bg-green-600' :
                                inv.stock_status === 'low_stock' ? 'bg-yellow-600' :
                                'bg-red-600'
                              }>
                                {inv.stock_status || 'unknown'}
                              </Badge>
                            </div>
                          </div>
                          <div className="text-right">
                            <p className="text-2xl font-bold text-white">{inv.quantity || 0}</p>
                            <p className="text-xs text-gray-400">Available: {inv.available_quantity || 0}</p>
                          </div>
                        </div>

                        {inv.channel_allocations && (
                          <div className="grid grid-cols-3 gap-2 text-xs mb-3">
                            <div className="text-center p-2 bg-indigo-900/20 rounded">
                              <p className="text-gray-400">≡ƒÅ¬ Offline</p>
                              <p className="text-white font-semibold">{inv.channel_allocations.offline || 0}</p>
                            </div>
                            <div className="text-center p-2 bg-cyan-900/20 rounded">
                              <p className="text-gray-400">≡ƒÆ╗ Online</p>
                              <p className="text-white font-semibold">{inv.channel_allocations.online || 0}</p>
                            </div>
                            <div className="text-center p-2 bg-orange-900/20 rounded">
                              <p className="text-gray-400">≡ƒ¢Æ Market</p>
                              <p className="text-white font-semibold">{inv.channel_allocations.marketplace || 0}</p>
                            </div>
                          </div>
                        )}

                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => {
                            setSelectedInventory(inv);
                            setShowAllocationForm(true);
                          }}
                          className="border-gray-700 w-full"
                        >
                          <Edit className="w-3 h-3 mr-2" />
                          Edit Allocation
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </CardContent>
        </Card>
      </div>

      {showAllocationForm && selectedInventory && (
        <StockAllocationForm
          productId={product.id || inventory?.product_id}
          productName={product.name}
          locationId={selectedInventory.location_id}
          locationName={selectedInventory.location_name}
          currentStock={selectedInventory.quantity || 0}
          companyId={companyId}
          onSuccess={() => {
            setShowAllocationForm(false);
            loadInventoryDetails();
            if (onUpdate) onUpdate();
          }}
          onClose={() => setShowAllocationForm(false)}
        />
      )}
    </>
  );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Store, MapPin, Save, Loader2 } from 'lucide-react';
import { toast } from 'sonner';

export default function StockAllocationForm({ 
  productId, 
  productName,
  locationId,
  locationName,
  currentStock = 0,
  companyId,
  onSuccess, 
  onClose 
}) {
  const [allocations, setAllocations] = useState({
    offline: 0,
    online: 0,
    marketplace: 0,
    b2b: 0,
    reserved: 0
  });

  const [geoZones, setGeoZones] = useState({
    same_city: 0,
    other_cities: 0,
    export: 0
  });

  // New states required for the expanded inventory management logic from the outline
  // Defaulting to 0 as there are no UI elements provided to set these in this form
  const [minStock, setMinStock] = useState(0); 
  const [maxStock, setMaxStock] = useState(0);
  const [reorderPoint, setReorderPoint] = useState(0);
  const [unitCost, setUnitCost] = useState(0);

  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    const defaultOffline = Math.floor(currentStock * 0.5);
    const defaultOnline = Math.floor(currentStock * 0.3);
    const defaultMarketplace = Math.floor(currentStock * 0.2);
    const defaultSameCity = Math.floor(currentStock * 0.7);
    const defaultOtherCities = Math.floor(currentStock * 0.3);

    setAllocations({
      offline: defaultOffline,
      online: defaultOnline,
      marketplace: defaultMarketplace,
      b2b: 0,
      reserved: 0
    });

    setGeoZones({
      same_city: defaultSameCity,
      other_cities: defaultOtherCities,
      export: 0
    });
  }, [currentStock]);

  const totalChannelAllocation = Object.values(allocations).reduce((sum, val) => sum + val, 0);
  const totalGeoAllocation = Object.values(geoZones).reduce((sum, val) => sum + val, 0);

  const handleSave = async () => {
    // Current allocation validation
    if (totalChannelAllocation > currentStock) {
      toast.error('Total alokasi channel melebihi stok yang tersedia!');
      return;
    }

    if (totalGeoAllocation > currentStock) {
      toast.error('Total alokasi geografis melebihi stok yang tersedia!');
      return;
    }

    // New validation from the outline, using currentStock as the primary quantity
    if (currentStock <= 0) {
      toast.error('Stok utama harus lebih dari 0 untuk membuat/mengupdate inventaris.');
      return;
    }
    
    try {
      setIsSaving(true);

      // Mock products and locations data for the `find` method to work
      // In a real application, these would typically be fetched or passed as more complete objects.
      const products = [{ id: productId, name: productName, sku: 'N/A' }]; 
      const locations = [{ id: locationId, location_name: locationName }];

      const product = products.find(p => p.id === productId);
      const location = locations.find(l => l.id === locationId);

      if (!product || !location) {
        toast.error('Data produk atau lokasi tidak ditemukan.');
        return;
      }

      // Check if inventory record already exists
      // Γ£à CRITICAL FIX: Filter dengan company_id untuk cegah data leak!
      let inventoryRecords = await base44.entities.Inventory.filter({
        company_id: companyId,  // Γ£à WAJIB!
        product_id: productId,
        location_id: locationId
      });

      // Calculate stock status (from outline)
      const stockStatus = currentStock === 0 ? 'out_of_stock' :
                         currentStock <= minStock ? 'low_stock' :
                         currentStock >= maxStock ? 'overstock' :
                         'in_stock';

      // Prepare inventory data, combining existing allocation data with new fields from outline
      const inventoryData = {
        company_id: companyId,  // Γ£à WAJIB!
        product_id: productId,
        product_name: productName,
        product_sku: product?.sku || 'N/A', // using mocked product with safe access
        location_id: locationId,
        location_name: locationName,
        quantity: currentStock, // Using currentStock as the main quantity for the record
        // available_quantity: currentStock, // This was from the outline's handleSubmit
        // Retaining existing calculation for available_quantity based on reserved stock
        available_quantity: currentStock - allocations.reserved, 
        min_stock: minStock,
        max_stock: maxStock,
        reorder_point: reorderPoint,
        unit_cost: unitCost,
        total_value: unitCost * currentStock,
        stock_status: stockStatus,
        channel_allocations: allocations, // Existing allocation data
        geographic_zones: geoZones,     // Existing allocation data
        reserved_quantity: allocations.reserved // Existing allocation data
      };

      if (inventoryRecords && inventoryRecords.length > 0) {
        const record = inventoryRecords[0];
        await base44.entities.Inventory.update(record.id, inventoryData);
        toast.success('Γ£à Inventaris dan alokasi stok berhasil diperbarui!');
      } else {
        // Create new record (from outline logic)
        await base44.entities.Inventory.create(inventoryData);
        toast.success('Γ£à Inventaris dan alokasi stok berhasil dibuat!');
      }

      // Broadcast Inventory Change (from outline)
      try {
        const channel = new BroadcastChannel('snishop_inventory_updates');
        channel.postMessage({
          type: 'INVENTORY_UPDATED',
          companyId: companyId,
          productId: productId,
          locationId: locationId,
          timestamp: Date.now()
        });
        channel.close();
      } catch (e) {
        console.warn('Gagal menyiarkan pembaruan inventaris:', e);
      }

      if (onSuccess) onSuccess();
      if (onClose) onClose();

    } catch (error) {
      console.error('Error saving inventory and allocation:', error);
      toast.error('Gagal menyimpan inventaris dan alokasi');
    } finally {
      setIsSaving(false);
    }
  };

  // ============================================================================
  // SIMPLE CONTENT ONLY - NO WRAPPER MODAL, PARENT HANDLE MODAL DISPLAY
  // ============================================================================
  return (
    <div style={{ display: 'block', width: '100%' }}>
      {/* Current Stock Info */}
      <div style={{ padding: '16px', backgroundColor: '#0c4a6e', border: '1px solid #0e7490', borderRadius: '8px', marginBottom: '24px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span style={{ color: '#cbd5e1', fontSize: '14px' }}>Total Stock:</span>
          <span style={{ fontSize: '24px', fontWeight: 'bold', color: 'white' }}>{currentStock} units</span>
        </div>
      </div>

      {/* Channel Allocation */}
      <div style={{ marginBottom: '24px' }}>
        <h3 style={{ color: 'white', fontWeight: '600', marginBottom: '16px', fontSize: '16px', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <Store size={18} style={{ color: '#a78bfa' }} />
          Channel Allocation
        </h3>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '16px', marginBottom: '12px' }}>
          <div>
            <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>≡ƒÅ¬ Offline Store</Label>
            <Input
              type="number"
              value={allocations.offline}
              onChange={(e) => setAllocations({...allocations, offline: parseInt(e.target.value) || 0})}
              style={{ width: '100%', padding: '8px', backgroundColor: '#1f2937', border: '1px solid #374151', color: 'white', borderRadius: '6px', boxSizing: 'border-box' }}
              min="0"
              max={currentStock}
            />
          </div>
          <div>
            <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>≡ƒÆ╗ Online</Label>
            <Input
              type="number"
              value={allocations.online}
              onChange={(e) => setAllocations({...allocations, online: parseInt(e.target.value) || 0})}
              style={{ width: '100%', padding: '8px', backgroundColor: '#1f2937', border: '1px solid #374151', color: 'white', borderRadius: '6px', boxSizing: 'border-box' }}
              min="0"
              max={currentStock}
            />
          </div>
          <div>
            <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>≡ƒ¢Æ Marketplace</Label>
            <Input
              type="number"
              value={allocations.marketplace}
              onChange={(e) => setAllocations({...allocations, marketplace: parseInt(e.target.value) || 0})}
              style={{ width: '100%', padding: '8px', backgroundColor: '#1f2937', border: '1px solid #374151', color: 'white', borderRadius: '6px', boxSizing: 'border-box' }}
              min="0"
              max={currentStock}
            />
          </div>
          <div>
            <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>≡ƒÅó B2B</Label>
            <Input
              type="number"
              value={allocations.b2b}
              onChange={(e) => setAllocations({...allocations, b2b: parseInt(e.target.value) || 0})}
              style={{ width: '100%', padding: '8px', backgroundColor: '#1f2937', border: '1px solid #374151', color: 'white', borderRadius: '6px', boxSizing: 'border-box' }}
              min="0"
              max={currentStock}
            />
          </div>
        </div>
        <div style={{ padding: '12px', backgroundColor: totalChannelAllocation > currentStock ? '#7f1d1d' : '#1b4332', border: `1px solid ${totalChannelAllocation > currentStock ? '#dc2626' : '#2d6a4f'}`, borderRadius: '6px' }}>
          <p style={{ margin: 0, fontSize: '14px', color: 'white' }}>
            Total: <strong>{totalChannelAllocation}</strong> / {currentStock}
          </p>
        </div>
      </div>

      {/* Geographic Distribution */}
      <div style={{ marginBottom: '24px' }}>
        <h3 style={{ color: 'white', fontWeight: '600', marginBottom: '16px', fontSize: '16px', display: 'flex', alignItems: 'center', gap: '8px' }}>
          <MapPin size={18} style={{ color: '#22d3ee' }} />
          Geographic Distribution
        </h3>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '16px', marginBottom: '12px' }}>
          <div>
            <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>≡ƒôì Dalam Kota</Label>
            <Input
              type="number"
              value={geoZones.same_city}
              onChange={(e) => setGeoZones({...geoZones, same_city: parseInt(e.target.value) || 0})}
              style={{ width: '100%', padding: '8px', backgroundColor: '#1f2937', border: '1px solid #374151', color: 'white', borderRadius: '6px', boxSizing: 'border-box' }}
              min="0"
              max={currentStock}
            />
          </div>
          <div>
            <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>≡ƒÜÜ Luar Kota</Label>
            <Input
              type="number"
              value={geoZones.other_cities}
              onChange={(e) => setGeoZones({...geoZones, other_cities: parseInt(e.target.value) || 0})}
              style={{ width: '100%', padding: '8px', backgroundColor: '#1f2937', border: '1px solid #374151', color: 'white', borderRadius: '6px', boxSizing: 'border-box' }}
              min="0"
              max={currentStock}
            />
          </div>
          <div>
            <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>Γ£ê∩╕Å Export</Label>
            <Input
              type="number"
              value={geoZones.export}
              onChange={(e) => setGeoZones({...geoZones, export: parseInt(e.target.value) || 0})}
              style={{ width: '100%', padding: '8px', backgroundColor: '#1f2937', border: '1px solid #374151', color: 'white', borderRadius: '6px', boxSizing: 'border-box' }}
              min="0"
              max={currentStock}
            />
          </div>
        </div>
        <div style={{ padding: '12px', backgroundColor: totalGeoAllocation > currentStock ? '#7f1d1d' : '#1b4332', border: `1px solid ${totalGeoAllocation > currentStock ? '#dc2626' : '#2d6a4f'}`, borderRadius: '6px' }}>
          <p style={{ margin: 0, fontSize: '14px', color: 'white' }}>
            Total: <strong>{totalGeoAllocation}</strong> / {currentStock}
          </p>
        </div>
      </div>

      {/* Action Buttons */}
      <div style={{ paddingTop: '16px', borderTop: '1px solid #1f2937', display: 'flex', gap: '12px', justifyContent: 'flex-end', flexDirection: 'row-reverse' }}>
        <Button 
          onClick={handleSave} 
          disabled={isSaving || totalChannelAllocation > currentStock || totalGeoAllocation > currentStock}
          style={{ 
            backgroundColor: '#2563eb', 
            color: 'white',
            padding: '10px 20px',
            border: 'none',
            borderRadius: '6px',
            cursor: isSaving ? 'not-allowed' : 'pointer',
            opacity: isSaving ? 0.5 : 1,
            fontSize: '14px',
            fontWeight: '500',
            width: '100%'
          }}
        >
          {isSaving ? (
            <>
              <Loader2 style={{ width: '16px', height: '16px', marginRight: '8px', display: 'inline-block' }} />
              Saving...
            </>
          ) : (
            <>
              <Save style={{ width: '16px', height: '16px', marginRight: '8px', display: 'inline-block' }} />
              Save
            </>
          )}
        </Button>
        <Button 
          onClick={onClose}
          style={{ 
            backgroundColor: 'transparent',
            color: '#d1d5db',
            padding: '10px 20px',
            border: '1px solid #374151',
            borderRadius: '6px',
            cursor: 'pointer',
            fontSize: '14px',
            fontWeight: '500',
            width: '100%'
          }}
        >
          Cancel
        </Button>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { ArrowRight, Save, Loader2 } from 'lucide-react';
import { toast } from 'sonner';

export default function StockTransferForm({ companyId, locations, products, onSuccess, onClose, currentUser }) {
  // Refactored state variables
  const [selectedProductId, setSelectedProductId] = useState('');
  const [fromLocationId, setFromLocationId] = useState('');
  const [toLocationId, setToLocationId] = useState('');
  const [transferQuantity, setTransferQuantity] = useState(0);
  const [reason, setReason] = useState('');
  const [notes, setNotes] = useState('');

  const [currentProductData, setCurrentProductData] = useState(null); // Stores the full product object
  const [fromLocationStock, setFromLocationStock] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false); // Renamed from isSaving

  // Effect to load product data when selectedProductId changes
  useEffect(() => {
    if (selectedProductId) {
      const product = products.find(p => p.id === selectedProductId);
      setCurrentProductData(product);
    } else {
      setCurrentProductData(null);
    }
  }, [selectedProductId, products]);

  // Effect to load stock information when product or fromLocation changes
  useEffect(() => {
    if (selectedProductId && fromLocationId) {
      loadStockInfo();
    } else {
      setFromLocationStock(0); // Clear stock if product or location is unselected
    }
  }, [selectedProductId, fromLocationId, companyId]); // Added companyId as a dependency

  const loadStockInfo = async () => {
    try {
      // Γ£à CRITICAL FIX: Filter dengan company_id untuk cegah data leak!
      const inventoryRecords = await base44.entities.Inventory.filter({
        company_id: companyId,  // Γ£à WAJIB!
        product_id: selectedProductId,
        location_id: fromLocationId
      });

      if (inventoryRecords && inventoryRecords.length > 0) {
        setFromLocationStock(inventoryRecords[0].available_quantity || 0);
      } else {
        setFromLocationStock(0);
      }
    } catch (error) {
      console.error('Error loading stock info:', error);
      toast.error('Gagal memuat informasi stok');
    }
  };

  const handleSubmit = async () => {
    if (!selectedProductId || !fromLocationId || !toLocationId || transferQuantity <= 0) {
      toast.error('Lengkapi semua field yang diperlukan dan masukkan kuantitas yang valid.');
      return;
    }

    if (fromLocationId === toLocationId) {
      toast.error('Lokasi asal dan tujuan tidak boleh sama!');
      return;
    }

    if (!currentProductData) {
      toast.error('Produk tidak ditemukan.');
      return;
    }

    try {
      setIsSubmitting(true);

      const product = currentProductData; // Use the product data loaded into state
      const fromLoc = locations.find(l => l.id === fromLocationId);
      const toLoc = locations.find(l => l.id === toLocationId);

      if (!fromLoc || !toLoc) {
        toast.error('Lokasi asal atau tujuan tidak valid.');
        setIsSubmitting(false);
        return;
      }

      // Get source inventory
      // Γ£à CRITICAL FIX: Filter dengan company_id!
      const sourceInv = await base44.entities.Inventory.filter({
        company_id: companyId,  // Γ£à WAJIB!
        product_id: selectedProductId,
        location_id: fromLocationId
      });

      if (!sourceInv || sourceInv.length === 0) {
        toast.error('Stok produk tidak ditemukan di lokasi asal.');
        setIsSubmitting(false);
        return;
      }

      const source = sourceInv[0];

      if (source.available_quantity < transferQuantity) {
        toast.error(`Stok tersedia hanya ${source.available_quantity} unit.`);
        setIsSubmitting(false);
        return;
      }

      // Update source location (reduce stock)
      const newSourceQty = source.quantity - transferQuantity;
      const updatedSourceInventory = await base44.entities.Inventory.update(source.id, {
        quantity: newSourceQty,
        available_quantity: Math.max(0, newSourceQty - (source.reserved_quantity || 0)),
        stock_status: newSourceQty === 0 ? 'out_of_stock' :
                     newSourceQty <= (source.min_stock || 0) ? 'low_stock' :
                     'in_stock',
        last_stock_out: new Date().toISOString(),
        total_value: (source.unit_cost || 0) * newSourceQty
      });

      // Update destination location (add stock)
      // Γ£à CRITICAL FIX: Filter dengan company_id!
      const destInv = await base44.entities.Inventory.filter({
        company_id: companyId,  // Γ£à WAJIB!
        product_id: selectedProductId,
        location_id: toLocationId
      });

      // No need to store destinationInventoryId here, as the StockMovement only tracks origin.
      // If we needed to track both, we would create two movement records.
      if (destInv && destInv.length > 0) {
        const dest = destInv[0];
        const newDestQty = dest.quantity + transferQuantity;

        await base44.entities.Inventory.update(dest.id, {
          quantity: newDestQty,
          available_quantity: Math.max(0, newDestQty - (dest.reserved_quantity || 0)),
          stock_status: newDestQty === 0 ? 'out_of_stock' :
                       newDestQty <= (dest.min_stock || 0) ? 'low_stock' :
                       newDestQty >= (dest.max_stock || 1000) ? 'overstock' :
                       'in_stock',
          last_stock_in: new Date().toISOString(),
          total_value: (dest.unit_cost || 0) * newDestQty
        });
      } else {
        // Create new inventory at destination if it doesn't exist
        await base44.entities.Inventory.create({
          company_id: companyId,
          product_id: selectedProductId,
          product_name: product.name,
          product_sku: product.sku,
          location_id: toLocationId,
          location_name: toLoc.location_name,
          quantity: transferQuantity,
          available_quantity: transferQuantity,
          reserved_quantity: 0,
          min_stock: source.min_stock || 5, // Inherit min_stock from source or default
          max_stock: source.max_stock || 1000, // Inherit max_stock from source or default
          unit_cost: source.unit_cost || 0, // Inherit unit_cost from source or default
          total_value: (source.unit_cost || 0) * transferQuantity,
          stock_status: transferQuantity <= (source.min_stock || 0) ? 'low_stock' : 'in_stock',
          last_stock_in: new Date().toISOString()
        });
      }

      // Create stock movement record
      await base44.entities.StockMovement.create({
        company_id: companyId,
        inventory_id: updatedSourceInventory.id, // Reference the source inventory record
        product_id: selectedProductId,
        product_name: product.name,
        location_id: fromLocationId, // Movement originated from here
        location_name: fromLoc.location_name,
        movement_type: 'transfer',
        quantity: transferQuantity,
        stock_before: source.quantity,
        stock_after: newSourceQty,
        reference_type: 'transfer',
        from_location_id: fromLocationId,
        to_location_id: toLocationId,
        reason: reason || `Transfer to ${toLoc.location_name}`, // Use user-provided reason or default
        unit_cost: source.unit_cost || 0,
        total_value: (source.unit_cost || 0) * transferQuantity,
        performed_by: currentUser?.email || 'system',
        performed_by_name: currentUser?.full_name || 'System',
        notes: notes
      });

      toast.success('Γ£à Transfer stok berhasil!');
      
      // Γ£à TRIPLE BROADCAST - Inventory, POS, Products
      try {
        const channel1 = new BroadcastChannel('snishop_inventory_updates');
        const channel2 = new BroadcastChannel('snishop_pos_updates');
        const channel3 = new BroadcastChannel('snishop_product_updates');
        
        const message = {
          type: 'STOCK_TRANSFERRED',
          companyId: companyId,
          productId: selectedProductId,
          fromLocationId: fromLocationId,
          toLocationId: toLocationId,
          quantity: transferQuantity,
          timestamp: Date.now()
        };
        
        channel1.postMessage(message);
        channel2.postMessage(message);
        channel3.postMessage(message);
        
        channel1.close();
        channel2.close();
        channel3.close();
        
        console.log('Γ£à TRANSFER BROADCAST to ALL channels');
      } catch (e) {
        console.warn('Broadcast failed:', e);
      }
      
      // Γ£à Invalidate global cache
      try {
        const { default: globalCache } = await import('@/components/utils/globalDataCache');
        globalCache.invalidate(`inventory_${companyId}`);
        globalCache.invalidate(`products_${companyId}`);
        globalCache.invalidate(`pos_products_${companyId}`);
      } catch (e) {}

      if (onSuccess) onSuccess();
      if (onClose) onClose();

    } catch (error) {
      console.error('Error transferring stock:', error);
      toast.error('Gagal melakukan transfer stok');
    } finally {
      setIsSubmitting(false);
    }
  };

  // ============================================================================
  // CONTENT ONLY - NO MODAL WRAPPER, PARENT HANDLE DIALOG DISPLAY
  // STRUKTUR LOGIC TRANSFER TETAP SAMA, HANYA TAMPILAN DIPERBAIKI
  // ============================================================================
  return (
    <div style={{ display: 'block', width: '100%' }}>
      {/* Product Selection */}
      <div style={{ marginBottom: '16px' }}>
        <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>
          Product *
        </Label>
        <select
          value={selectedProductId}
          onChange={(e) => setSelectedProductId(e.target.value)}
          style={{
            width: '100%',
            padding: '8px 12px',
            backgroundColor: '#1f2937',
            border: '1px solid #374151',
            color: 'white',
            borderRadius: '6px',
            fontSize: '14px',
            boxSizing: 'border-box',
            cursor: 'pointer'
          }}
        >
          <option value="">Select Product</option>
          {products.map(product => (
            <option key={product.id} value={product.id}>
              {product.name} - {product.sku}
            </option>
          ))}
        </select>
      </div>

      {/* From Location & To Location Grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '16px', marginBottom: '16px' }}>
        <div>
          <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>
            From Location *
          </Label>
          <select
            value={fromLocationId}
            onChange={(e) => setFromLocationId(e.target.value)}
            style={{
              width: '100%',
              padding: '8px 12px',
              backgroundColor: '#1f2937',
              border: '1px solid #374151',
              color: 'white',
              borderRadius: '6px',
              fontSize: '14px',
              boxSizing: 'border-box',
              cursor: 'pointer'
            }}
          >
            <option value="">Select Location</option>
            {locations.map(loc => (
              <option key={loc.id} value={loc.id}>{loc.location_name}</option>
            ))}
          </select>
          {fromLocationStock > 0 && (
            <p style={{ fontSize: '12px', color: '#4ade80', marginTop: '6px', margin: 0 }}>
              Available: {fromLocationStock} units
            </p>
          )}
        </div>

        <div>
          <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>
            To Location *
          </Label>
          <select
            value={toLocationId}
            onChange={(e) => setToLocationId(e.target.value)}
            style={{
              width: '100%',
              padding: '8px 12px',
              backgroundColor: '#1f2937',
              border: '1px solid #374151',
              color: 'white',
              borderRadius: '6px',
              fontSize: '14px',
              boxSizing: 'border-box',
              cursor: 'pointer'
            }}
          >
            <option value="">Select Location</option>
            {locations.filter(l => l.id !== fromLocationId).map(loc => (
              <option key={loc.id} value={loc.id}>{loc.location_name}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Quantity */}
      <div style={{ marginBottom: '16px' }}>
        <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>
          Quantity to Transfer *
        </Label>
        <Input
          type="number"
          value={transferQuantity}
          onChange={(e) => setTransferQuantity(parseInt(e.target.value) || 0)}
          max={fromLocationStock}
          min="0"
          placeholder="0"
          style={{
            width: '100%',
            padding: '8px 12px',
            backgroundColor: '#1f2937',
            border: '1px solid #374151',
            color: 'white',
            borderRadius: '6px',
            fontSize: '14px',
            boxSizing: 'border-box'
          }}
        />
        <p style={{ fontSize: '12px', color: '#9ca3af', marginTop: '6px', margin: 0 }}>
          Max: {fromLocationStock} units
        </p>
      </div>

      {/* Reason */}
      <div style={{ marginBottom: '16px' }}>
        <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>
          Reason
        </Label>
        <Input
          value={reason}
          onChange={(e) => setReason(e.target.value)}
          placeholder="Restock, redistribution, dll"
          style={{
            width: '100%',
            padding: '8px 12px',
            backgroundColor: '#1f2937',
            border: '1px solid #374151',
            color: 'white',
            borderRadius: '6px',
            fontSize: '14px',
            boxSizing: 'border-box'
          }}
        />
      </div>

      {/* Notes */}
      <div style={{ marginBottom: '16px' }}>
        <Label style={{ color: '#d1d5db', fontSize: '14px', display: 'block', marginBottom: '8px' }}>
          Notes (optional)
        </Label>
        <Input
          value={notes}
          onChange={(e) => setNotes(e.target.value)}
          placeholder="Additional notes"
          style={{
            width: '100%',
            padding: '8px 12px',
            backgroundColor: '#1f2937',
            border: '1px solid #374151',
            color: 'white',
            borderRadius: '6px',
            fontSize: '14px',
            boxSizing: 'border-box'
          }}
        />
      </div>

      {/* Transfer Summary */}
      {currentProductData && fromLocationId && toLocationId && transferQuantity > 0 && (
        <div style={{ 
          padding: '14px', 
          backgroundColor: '#0c4a6e', 
          border: '1px solid #0e7490',
          borderRadius: '8px',
          marginBottom: '16px'
        }}>
          <p style={{ color: 'white', fontWeight: '600', fontSize: '14px', marginBottom: '10px', margin: 0 }}>
            Transfer Summary:
          </p>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '13px', marginTop: '10px', flexWrap: 'wrap' }}>
            <span style={{ color: '#cbd5e1', flex: '1 1 auto', minWidth: '80px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
              {locations.find(l => l.id === fromLocationId)?.location_name}
            </span>
            <ArrowRight style={{ color: '#06b6d4', flexShrink: 0, width: '18px', height: '18px' }} />
            <span style={{ color: '#cbd5e1', flex: '1 1 auto', minWidth: '80px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
              {locations.find(l => l.id === toLocationId)?.location_name}
            </span>
          </div>
          <p style={{ color: 'white', marginTop: '10px', fontSize: '13px', margin: 0 }}>
            <strong>{transferQuantity}</strong> x {currentProductData.name}
          </p>
        </div>
      )}

      {/* Action Buttons */}
      <div style={{ paddingTop: '16px', borderTop: '1px solid #1f2937', display: 'flex', gap: '12px', justifyContent: 'flex-end', flexDirection: 'row-reverse', flexWrap: 'wrap' }}>
        <Button 
          onClick={handleSubmit} 
          disabled={isSubmitting || !selectedProductId || !fromLocationId || !toLocationId || transferQuantity <= 0}
          style={{ 
            backgroundColor: '#2563eb',
            color: 'white',
            padding: '10px 20px',
            border: 'none',
            borderRadius: '6px',
            cursor: isSubmitting || !selectedProductId || !fromLocationId || !toLocationId || transferQuantity <= 0 ? 'not-allowed' : 'pointer',
            opacity: isSubmitting || !selectedProductId || !fromLocationId || !toLocationId || transferQuantity <= 0 ? 0.5 : 1,
            fontSize: '14px',
            fontWeight: '500',
            minWidth: '140px'
          }}
        >
          {isSubmitting && (
            <Loader2 style={{ width: '16px', height: '16px', marginRight: '8px', display: 'inline-block', animation: 'spin 1s linear infinite' }} />
          )}
          <Save style={{ width: '16px', height: '16px', marginRight: '8px', display: 'inline-block' }} />
          Transfer Stock
        </Button>
        <Button 
          onClick={onClose}
          style={{ 
            backgroundColor: 'transparent',
            color: '#d1d5db',
            padding: '10px 20px',
            border: '1px solid #374151',
            borderRadius: '6px',
            cursor: 'pointer',
            fontSize: '14px',
            fontWeight: '500',
            minWidth: '100px'
          }}
        >
          Cancel
        </Button>
      </div>

      <style>{`
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Sparkles, Send, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import ReactMarkdown from 'react-markdown';
import { base44 } from '@/api/base44Client';

const { Invoice, FinancialRecord, Customer } = base44.entities;

export default function InvoiceAIAssistant({ selectedCompany, currentUser, onInvoiceCreated, customers }) {
  const [messages, setMessages] = useState([
    {
      role: 'assistant',
      content: `≡ƒæï Halo! Saya AI Assistant untuk Invoice.\n\n**Saya bisa bantu:**\n- Buat invoice otomatis dari deskripsi\n- Catat ke keuangan perusahaan\n- Track pembayaran customer\n- Reminder invoice jatuh tempo\n\n**Contoh:** *"Buatkan invoice untuk PT ABC senilai 5 juta untuk jasa konsultasi website, jatuh tempo 30 hari"*`
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const generateInvoiceNumber = () => {
    const date = new Date();
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const random = Math.floor(Math.random() * 10000).toString().padStart(4, '0');
    return `INV-${year}${month}-${random}`;
  };

  const createFinancialRecord = async (invoice, paymentInfo) => {
    try {
      const record = {
        company_id: selectedCompany.id,
        type: 'income',
        amount: paymentInfo.amount,
        category: 'Penjualan',
        description: `${paymentInfo.memo} - Invoice #${invoice.invoice_number} - ${invoice.customer_name}`,
        date: new Date().toISOString(),
        source: 'ai_invoice',
        mode: 'business'
      };

      await FinancialRecord.create(record);
      return true;
    } catch (error) {
      console.error('Error creating financial record:', error);
      return false;
    }
  };

  const handleSendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = { role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      // Use direct base44 usage
      const InvokeLLM = base44.integrations.Core.InvokeLLM;

      const now = new Date();
      const contextPrompt = `Anda adalah AI Assistant untuk pembuatan invoice profesional.

**KONTEKS:**
- Perusahaan: ${selectedCompany.name}
- User: ${currentUser.full_name}
- Tanggal: ${now.toLocaleDateString('id-ID')}

**PERMINTAAN USER:** "${input}"

**TUGAS ANDA:**
Analisis permintaan dan tentukan apakah user ingin:
1. Membuat invoice baru
2. Update status pembayaran invoice
3. Informasi umum tentang invoice

**JIKA MEMBUAT INVOICE BARU:**
Response JSON:
\`\`\`json
{
  "action": "create_invoice",
  "invoice": {
    "customer_name": "Nama customer",
    "customer_email": "email@customer.com",
    "customer_phone": "081234567890",
    "customer_address": "Alamat lengkap",
    "items": [
      {
        "description": "Deskripsi item/jasa",
        "quantity": 1,
        "unit_price": 5000000,
        "total": 5000000
      }
    ],
    "subtotal": 5000000,
    "tax_percentage": 11,
    "tax_amount": 550000,
    "discount_percentage": 0,
    "discount_amount": 0,
    "total": 5550000,
    "due_days": 30,
    "notes": "Catatan tambahan",
    "terms": "Syarat & ketentuan pembayaran"
  },
  "message": "Konfirmasi pembuatan invoice"
}
\`\`\`

**JIKA UPDATE PEMBAYARAN:**
Response JSON:
\`\`\`json
{
  "action": "record_payment",
  "payment": {
    "invoice_number": "INV-xxx",
    "amount": 2500000,
    "percentage": 50,
    "memo": "Pembayaran DP 50%",
    "payment_date": "2024-01-15"
  },
  "message": "Konfirmasi pencatatan pembayaran"
}
\`\`\`

**JIKA CHAT BIASA:**
\`\`\`json
{
  "action": "chat_response",
  "message": "Jawaban yang membantu"
}
\`\`\`

**ATURAN PENTING:**
- Hitung PPN 11% jika tidak disebutkan
- Default jatuh tempo 30 hari
- Extract semua detail dari permintaan user
- Gunakan format Rupiah untuk harga`;

      const response = await InvokeLLM({
        prompt: contextPrompt,
        add_context_from_internet: false,
        response_json_schema: {
          type: 'object',
          properties: {
            action: { type: 'string' },
            invoice: { type: 'object' },
            payment: { type: 'object' },
            message: { type: 'string' }
          },
          required: ['action', 'message']
        }
      });

      let aiResponse = typeof response === 'string' ? JSON.parse(response) : response;

      if (aiResponse.action === 'create_invoice' && aiResponse.invoice) {
        try {
          const invoiceNumber = generateInvoiceNumber();
          const issueDate = new Date().toISOString();
          const dueDate = new Date();
          dueDate.setDate(dueDate.getDate() + (aiResponse.invoice.due_days || 30));

          const invoiceData = {
            company_id: selectedCompany.id,
            invoice_number: invoiceNumber,
            invoice_type: 'invoice',
            customer_name: aiResponse.invoice.customer_name,
            customer_email: aiResponse.invoice.customer_email || '',
            customer_phone: aiResponse.invoice.customer_phone || '',
            customer_address: aiResponse.invoice.customer_address || '',
            issue_date: issueDate,
            due_date: dueDate.toISOString(),
            items: aiResponse.invoice.items,
            subtotal: aiResponse.invoice.subtotal,
            tax_percentage: aiResponse.invoice.tax_percentage || 11,
            tax_amount: aiResponse.invoice.tax_amount,
            discount_percentage: aiResponse.invoice.discount_percentage || 0,
            discount_amount: aiResponse.invoice.discount_amount || 0,
            total: aiResponse.invoice.total,
            notes: aiResponse.invoice.notes || '',
            terms: aiResponse.invoice.terms || 'Pembayaran dilakukan sesuai tanggal jatuh tempo',
            status: 'sent',
            paid_amount: 0
          };

          const createdInvoice = await Invoice.create(invoiceData);
          const fullInvoiceData = { ...invoiceData, id: createdInvoice?.id || Date.now() };

          setMessages(prev => [...prev, {
            role: 'assistant',
            content: `Γ£à **Invoice berhasil dibuat!**\n\n${aiResponse.message}\n\n≡ƒôä **Invoice #${invoiceNumber}**\n≡ƒÆ░ Total: Rp ${aiResponse.invoice.total.toLocaleString('id-ID')}\n≡ƒôà Jatuh Tempo: ${dueDate.toLocaleDateString('id-ID')}\n\nInvoice telah tersimpan dan siap dikirim ke customer.`
          }]);

          toast.success(`Invoice #${invoiceNumber} berhasil dibuat!`);
          if (onInvoiceCreated) onInvoiceCreated(fullInvoiceData);

        } catch (error) {
          console.error('Error creating invoice:', error);
          setMessages(prev => [...prev, {
            role: 'assistant',
            content: 'Γ¥î Maaf, gagal membuat invoice. Silakan coba lagi atau buat manual.'
          }]);
          toast.error('Gagal membuat invoice');
        }

      } else if (aiResponse.action === 'record_payment' && aiResponse.payment) {
        try {
          // Find invoice
          const invoices = await Invoice.filter({
            company_id: selectedCompany.id,
            invoice_number: aiResponse.payment.invoice_number
          });

          if (invoices.length === 0) {
            throw new Error('Invoice tidak ditemukan');
          }

          const invoice = invoices[0];
          const newPaidAmount = (invoice.paid_amount || 0) + aiResponse.payment.amount;
          const newStatus = newPaidAmount >= invoice.total ? 'paid' : 'sent';

          // Update invoice
          await Invoice.update(invoice.id, {
            paid_amount: newPaidAmount,
            status: newStatus,
            paid_date: newPaidAmount >= invoice.total ? new Date().toISOString() : invoice.paid_date
          });

          // Create financial record
          await createFinancialRecord(invoice, aiResponse.payment);

          setMessages(prev => [...prev, {
            role: 'assistant',
            content: `Γ£à **Pembayaran berhasil dicatat!**\n\n${aiResponse.message}\n\n≡ƒÆ╡ Jumlah: Rp ${aiResponse.payment.amount.toLocaleString('id-ID')}\n≡ƒô¥ Memo: ${aiResponse.payment.memo}\n\n**Status Invoice:**\n- Total: Rp ${invoice.total.toLocaleString('id-ID')}\n- Terbayar: Rp ${newPaidAmount.toLocaleString('id-ID')}\n- Sisa: Rp ${(invoice.total - newPaidAmount).toLocaleString('id-ID')}\n\n${newStatus === 'paid' ? '≡ƒÄë Invoice LUNAS!' : 'ΓÅ│ Menunggu pelunasan'}\n\nΓ£à Transaksi sudah tercatat di keuangan perusahaan.`
          }]);

          toast.success('Pembayaran berhasil dicatat!');
          if (onInvoiceCreated) onInvoiceCreated();

        } catch (error) {
          console.error('Error recording payment:', error);
          setMessages(prev => [...prev, {
            role: 'assistant',
            content: `Γ¥î Gagal mencatat pembayaran: ${error.message}`
          }]);
          toast.error('Gagal mencatat pembayaran');
        }

      } else {
        setMessages(prev => [...prev, {
          role: 'assistant',
          content: aiResponse.message
        }]);
      }

    } catch (error) {
      console.error('AI Error:', error);
      setMessages(prev => [...prev, {
        role: 'assistant',
        content: 'Γ¥î Maaf, terjadi kesalahan. Silakan coba lagi.'
      }]);
      toast.error('Gagal memproses permintaan');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Card className="h-[600px] flex flex-col bg-gray-900 border-gray-700">
      <CardHeader className="border-b border-gray-700">
        <CardTitle className="flex items-center gap-2 text-white">
          <Sparkles className="w-5 h-5 text-purple-400" />
          AI Invoice Assistant
        </CardTitle>
      </CardHeader>

      <CardContent className="flex-1 flex flex-col p-4 overflow-hidden">
        <div className="flex-1 overflow-y-auto space-y-4 mb-4">
          {messages.map((msg, idx) => (
            <div
              key={idx}
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div
                className={`max-w-[80%] rounded-lg px-4 py-2 ${msg.role === 'user'
                  ? 'bg-blue-600 text-white'
                  : 'bg-gray-800 text-gray-200'
                  }`}
              >
                <ReactMarkdown className="prose prose-sm prose-invert max-w-none">
                  {msg.content}
                </ReactMarkdown>
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-gray-800 rounded-lg px-4 py-2 flex items-center gap-2">
                <Loader2 className="w-4 h-4 animate-spin text-purple-400" />
                <span className="text-gray-400 text-sm">AI sedang memproses...</span>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        <div className="flex gap-2">
          <Textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleSendMessage();
              }
            }}
            placeholder="Contoh: Buatkan invoice untuk PT ABC senilai 5 juta..."
            className="bg-gray-800 border-gray-700 text-white resize-none"
            rows={2}
            disabled={isLoading}
          />
          <Button
            onClick={handleSendMessage}
            disabled={isLoading || !input.trim()}
            className="bg-purple-600 hover:bg-purple-700"
          >
            {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

import { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';
import { FileText, Calendar, Mail, Phone, MapPin, Printer, CreditCard, CheckCircle } from 'lucide-react';
import { toast } from 'sonner';
import { base44 } from '@/api/base44Client';

const { Invoice } = base44.entities;

export default function InvoiceDetailDialog({ open, onOpenChange, invoice, company, onUpdate }) {
  const [isPaymentOpen, setIsPaymentOpen] = useState(false);
  const [paymentAmount, setPaymentAmount] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  if (!invoice) return null;

  const handlePayment = async () => {
    if (!paymentAmount || isProcessing) return;

    try {
      setIsProcessing(true);
      const amount = parseFloat(paymentAmount);
      const newPaidAmount = (invoice.paid_amount || 0) + amount;
      const newStatus = newPaidAmount >= invoice.total ? 'paid' : 'sent';

      await Invoice.update(invoice.id, {
        paid_amount: newPaidAmount,
        status: newStatus,
        paid_date: newStatus === 'paid' ? new Date().toISOString() : invoice.paid_date
      });

      toast.success('Pembayaran berhasil dicatat');
      setIsPaymentOpen(false);
      setPaymentAmount('');

      if (onUpdate) {
        onUpdate({
          ...invoice,
          paid_amount: newPaidAmount,
          status: newStatus
        });
      }
    } catch (error) {
      console.error('Error recording payment:', error);
      toast.error('Gagal mencatat pembayaran');
    } finally {
      setIsProcessing(false);
    }
  };

  const formatDateSafe = (dateString) => {
    try {
      if (!dateString) return '-';
      return format(new Date(dateString), 'dd MMM yyyy', { locale: id });
    } catch (e) {
      return '-';
    }
  };

  const formatPrice = (price) => {
    return new Intl.NumberFormat('id-ID', {
      style: 'currency',
      currency: 'IDR',
      minimumFractionDigits: 0
    }).format(price || 0);
  };

  const getStatusColor = (status) => {
    const colors = {
      draft: 'bg-gray-600',
      sent: 'bg-blue-600',
      paid: 'bg-green-600',
      overdue: 'bg-red-600',
      cancelled: 'bg-gray-500'
    };
    return colors[status] || 'bg-gray-600';
  };

  const getTypeColor = (type) => {
    const colors = {
      invoice: 'bg-blue-600',
      quotation: 'bg-purple-600',
      proforma: 'bg-orange-600'
    };
    return colors[type] || 'bg-blue-600';
  };

  const handlePrint = () => {
    const printWindow = window.open('', '', 'width=800,height=600');

    // Create HTML for print
    const htmlContent = `
      <!DOCTYPE html>
      <html>
        <head>
          <title>Invoice #${invoice.invoice_number}</title>
          <style>
            @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');
            
            body { 
              font-family: 'Inter', sans-serif; 
              padding: 40px; 
              color: #1a1a1a; 
              line-height: 1.5;
              max-width: 800px;
              margin: 0 auto;
            }
            .header { 
              display: flex; 
              justify-content: space-between; 
              align-items: flex-start;
              margin-bottom: 50px; 
              border-bottom: 2px solid #f3f4f6; 
              padding-bottom: 30px; 
            }
            .company-info { display: flex; flex-direction: column; gap: 4px; }
            .logo-container { margin-bottom: 12px; }
            .logo-container img { max-height: 60px; max-width: 200px; object-fit: contain; }
            .company-info h1 { margin: 0; color: #111827; font-size: 20px; font-weight: 700; }
            .company-info p { margin: 0; color: #4b5563; font-size: 13px; }
            
            .invoice-details { text-align: right; }
            .invoice-details h2 { margin: 0 0 10px 0; color: #2563eb; font-size: 32px; font-weight: 800; letter-spacing: -0.5px; }
            .invoice-meta { margin-top: 10px; }
            .invoice-meta p { margin: 4px 0; font-size: 14px; color: #374151; }
            
            .bill-to { margin-bottom: 40px; background: #f9fafb; padding: 20px; border-radius: 8px; }
            .bill-to h3 { margin: 0 0 10px 0; color: #6b7280; font-size: 12px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.5px; }
            .bill-to-name { font-size: 16px; font-weight: 700; color: #111827; margin-bottom: 4px; }
            
            table { width: 100%; border-collapse: separate; border-spacing: 0; margin-bottom: 40px; }
            th { text-align: left; padding: 12px 16px; background: #f3f4f6; border-bottom: 1px solid #e5e7eb; text-transform: uppercase; font-size: 11px; font-weight: 600; color: #6b7280; letter-spacing: 0.5px; }
            th:first-child { border-top-left-radius: 6px; border-bottom-left-radius: 6px; }
            th:last-child { border-top-right-radius: 6px; border-bottom-right-radius: 6px; }
            td { padding: 16px; border-bottom: 1px solid #e5e7eb; font-size: 14px; color: #374151; }
            tr:last-child td { border-bottom: none; }
            
            .text-right { text-align: right; }
            .totals { width: 320px; margin-left: auto; }
            .totals-row { display: flex; justify-content: space-between; padding: 8px 0; font-size: 14px; }
            .total-final { font-weight: 700; font-size: 18px; border-top: 2px solid #e5e7eb; padding-top: 16px; margin-top: 8px; color: #111827; }
            
            .status-badge { 
              display: inline-block; padding: 6px 12px; border-radius: 9999px; color: white; font-weight: 600; font-size: 11px; text-transform: uppercase; letter-spacing: 0.5px;
              background: ${invoice.status === 'paid' ? '#059669' : invoice.status === 'overdue' ? '#dc2626' : '#6b7280'};
            }
            
            .footer { margin-top: 60px; padding-top: 30px; border-top: 1px solid #f3f4f6; text-align: center; color: #9ca3af; font-size: 12px; }
          </style>
        </head>
        <body>
          <div class="header">
            <div class="company-info">
              ${company?.logo_url ? `<div class="logo-container"><img src="${company.logo_url}" alt="Logo" /></div>` : ''}
              <h1>${company?.name || ''}</h1>
              <p>${company?.address || ''}</p>
              <p>${company?.phone || ''} ${company?.email ? `ΓÇó ${company?.email}` : ''}</p>
            </div>
            <div class="invoice-details">
              <h2>${invoice.invoice_type?.toUpperCase()}</h2>
              <span class="status-badge">${invoice.status}</span>
              <div class="invoice-meta">
                <p><strong>#${invoice.invoice_number}</strong></p>
                <p>Issue Date: ${format(new Date(invoice.issue_date), 'dd MMM yyyy', { locale: id })}</p>
                <p>Due Date: ${format(new Date(invoice.due_date), 'dd MMM yyyy', { locale: id })}</p>
              </div>
            </div>
          </div>

          <div class="bill-to">
            <h3>Bill To</h3>
            <div class="bill-to-name">${invoice.customer_name}</div>
            ${invoice.customer_address ? `<div style="font-size: 14px; color: #4b5563;">${invoice.customer_address}</div>` : ''}
            ${invoice.customer_phone ? `<div style="font-size: 13px; color: #6b7280; margin-top: 4px;">${invoice.customer_phone}</div>` : ''}
          </div>

          <table>
            <thead>
              <tr>
                <th style="width: 40%">Description</th>
                <th class="text-right" style="width: 15%">Qty</th>
                <th class="text-right" style="width: 20%">Price</th>
                <th class="text-right" style="width: 25%">Total</th>
              </tr>
            </thead>
            <tbody>
              ${invoice.items?.map(item => `
                <tr>
                  <td>
                    <div style="font-weight: 500; color: #111827;">${item.description}</div>
                  </td>
                  <td class="text-right">${item.quantity}</td>
                  <td class="text-right">${formatPrice(item.unit_price)}</td>
                  <td class="text-right" style="font-weight: 500;">${formatPrice(item.total)}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>

          <div class="totals">
            <div class="totals-row">
              <span style="color: #6b7280;">Subtotal</span>
              <span style="font-weight: 500;">${formatPrice(invoice.subtotal)}</span>
            </div>
            ${invoice.tax_amount > 0 ? `
            <div class="totals-row">
              <span style="color: #6b7280;">Tax (${invoice.tax_percentage}%)</span>
              <span style="font-weight: 500;">${formatPrice(invoice.tax_amount)}</span>
            </div>
            ` : ''}
            ${invoice.discount_amount > 0 ? `
            <div class="totals-row" style="color: #ef4444;">
              <span>Discount</span>
              <span>-${formatPrice(invoice.discount_amount)}</span>
            </div>
            ` : ''}
            <div class="totals-row total-final">
              <span>Total Due</span>
              <span>${formatPrice(invoice.total)}</span>
            </div>
            ${invoice.paid_amount > 0 ? `
            <div class="totals-row" style="color: #059669; margin-top: 12px; padding-top: 8px; border-top: 1px dashed #e5e7eb;">
              <span>Amount Paid</span>
              <span>-${formatPrice(invoice.paid_amount)}</span>
            </div>
            <div class="totals-row" style="font-weight: 700; color: #b91c1c;">
              <span>Balance Due</span>
              <span>${formatPrice(invoice.total - invoice.paid_amount)}</span>
            </div>
            ` : ''}
          </div>

          ${(invoice.notes || invoice.terms) ? `
          <div style="margin-top: 60px; display: grid; grid-template-columns: 1fr 1fr; gap: 40px;">
            ${invoice.notes ? `
            <div>
              <h3 style="margin: 0 0 8px 0; font-size: 11px; font-weight: 600; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;">Notes</h3>
              <p style="margin: 0; font-size: 13px; color: #4b5563;">${invoice.notes}</p>
            </div>
            ` : ''}
            ${invoice.terms ? `
            <div>
              <h3 style="margin: 0 0 8px 0; font-size: 11px; font-weight: 600; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;">Terms & Conditions</h3>
              <p style="margin: 0; font-size: 13px; color: #4b5563;">${invoice.terms}</p>
            </div>
            ` : ''}
          </div>
          ` : ''}
          
          <div class="footer">
            <p>Thank you for your business!</p>
            <p style="margin-top: 4px;">Powered by SNISHOP System</p>
          </div>
        </body>
      </html>
    `;

    printWindow.document.write(htmlContent);
    printWindow.document.close();

    // Auto-print after loading
    setTimeout(() => {
      printWindow.print();
    }, 500);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto bg-gray-900 border-gray-700">
        <DialogHeader>
          <div className="flex justify-between items-center">
            <DialogTitle className="text-white flex items-center gap-2">
              <FileText className="w-6 h-6" />
              Invoice Detail - #{invoice.invoice_number}
            </DialogTitle>
            <div className="flex gap-2">
              <Button
                variant="outline"
                className="bg-green-600/10 text-green-500 hover:bg-green-600/20 border-green-600/50"
                onClick={() => setIsPaymentOpen(!isPaymentOpen)}
              >
                <CreditCard className="w-4 h-4 mr-2" />
                Update Pembayaran
              </Button>
              <button
                onClick={handlePrint}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-md text-sm font-medium transition-colors"
              >
                <Printer className="w-4 h-4" />
                Print / Download PDF
              </button>
            </div>
          </div>
        </DialogHeader>

        {isPaymentOpen && (
          <div className="mx-4 p-4 bg-gray-800 rounded-lg border border-gray-700 animate-in slide-in-from-top-2">
            <h3 className="text-white font-medium mb-3 flex items-center gap-2">
              <CheckCircle className="w-4 h-4 text-green-400" />
              Catat Pembayaran Masuk
            </h3>
            <div className="flex gap-3">
              <div className="flex-1">
                <Input
                  type="number"
                  placeholder="Masukkan jumlah pembayaran..."
                  value={paymentAmount}
                  onChange={(e) => setPaymentAmount(e.target.value)}
                  className="bg-gray-900 border-gray-600 text-white"
                />
                <p className="text-xs text-gray-400 mt-1">
                  Sisa tagihan: {formatPrice(invoice.total - (invoice.paid_amount || 0))}
                </p>
              </div>
              <Button onClick={handlePayment} disabled={isProcessing || !paymentAmount}>
                {isProcessing ? 'Menyimpan...' : 'Simpan'}
              </Button>
            </div>
          </div>
        )}

        <div className="space-y-6 p-4">
          {/* Header Info */}
          <div className="flex justify-between items-start">
            <div>
              <h2 className="text-2xl font-bold text-white mb-2">{company?.name}</h2>
              <p className="text-gray-400">{company?.email}</p>
              <p className="text-gray-400">{company?.phone}</p>
              <p className="text-gray-400">{company?.address}</p>
            </div>
            <div className="text-right">
              <div className="flex gap-2 mb-2">
                <Badge className={getTypeColor(invoice.invoice_type)}>
                  {invoice.invoice_type}
                </Badge>
                <Badge className={getStatusColor(invoice.status)}>
                  {invoice.status}
                </Badge>
              </div>
              <p className="text-sm text-gray-400">
                <Calendar className="w-4 h-4 inline mr-1" />
                Issue: {formatDateSafe(invoice.issue_date)}
              </p>
              <p className="text-sm text-gray-400">
                Due: {formatDateSafe(invoice.due_date)}
              </p>
            </div>
          </div>

          {/* Customer Info */}
          <Card className="bg-gray-800 border-gray-700">
            <CardContent className="p-4">
              <h3 className="font-bold text-white mb-3">Bill To:</h3>
              <div className="space-y-1 text-gray-300">
                <p className="font-semibold text-lg">{invoice.customer_name}</p>
                {invoice.customer_email && (
                  <p className="flex items-center gap-2">
                    <Mail className="w-4 h-4" />
                    {invoice.customer_email}
                  </p>
                )}
                {invoice.customer_phone && (
                  <p className="flex items-center gap-2">
                    <Phone className="w-4 h-4" />
                    {invoice.customer_phone}
                  </p>
                )}
                {invoice.customer_address && (
                  <p className="flex items-center gap-2">
                    <MapPin className="w-4 h-4" />
                    {invoice.customer_address}
                  </p>
                )}
              </div>
            </CardContent>
          </Card>

          {/* Items Table */}
          <Card className="bg-gray-800 border-gray-700">
            <CardContent className="p-0">
              <table className="w-full">
                <thead className="bg-gray-700">
                  <tr>
                    <th className="text-left p-3 text-gray-300">Description</th>
                    <th className="text-right p-3 text-gray-300">Qty</th>
                    <th className="text-right p-3 text-gray-300">Unit Price</th>
                    <th className="text-right p-3 text-gray-300">Total</th>
                  </tr>
                </thead>
                <tbody>
                  {invoice.items?.map((item, idx) => (
                    <tr key={idx} className="border-b border-gray-700">
                      <td className="p-3 text-white">{item.description}</td>
                      <td className="p-3 text-right text-white">{item.quantity}</td>
                      <td className="p-3 text-right text-white">{formatPrice(item.unit_price)}</td>
                      <td className="p-3 text-right text-white font-semibold">{formatPrice(item.total)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </CardContent>
          </Card>

          {/* Totals */}
          <Card className="bg-gray-800 border-gray-700">
            <CardContent className="p-4">
              <div className="space-y-2">
                <div className="flex justify-between text-gray-300">
                  <span>Subtotal:</span>
                  <span className="font-semibold">{formatPrice(invoice.subtotal)}</span>
                </div>

                {invoice.tax_amount > 0 && (
                  <div className="flex justify-between text-gray-300">
                    <span>Tax ({invoice.tax_percentage}%):</span>
                    <span className="font-semibold">{formatPrice(invoice.tax_amount)}</span>
                  </div>
                )}

                {invoice.discount_amount > 0 && (
                  <div className="flex justify-between text-red-400">
                    <span>Discount ({invoice.discount_percentage}%):</span>
                    <span className="font-semibold">-{formatPrice(invoice.discount_amount)}</span>
                  </div>
                )}

                <div className="border-t border-gray-700 pt-2 mt-2">
                  <div className="flex justify-between items-center">
                    <span className="text-xl font-bold text-white">Total:</span>
                    <span className="text-2xl font-bold text-green-400">
                      {formatPrice(invoice.total)}
                    </span>
                  </div>
                </div>

                {invoice.paid_amount > 0 && (
                  <>
                    <div className="flex justify-between text-yellow-400">
                      <span>Paid:</span>
                      <span className="font-semibold">{formatPrice(invoice.paid_amount)}</span>
                    </div>
                    <div className="flex justify-between text-red-400">
                      <span className="font-bold">Balance Due:</span>
                      <span className="font-bold">{formatPrice(invoice.total - invoice.paid_amount)}</span>
                    </div>
                  </>
                )}
              </div>
            </CardContent>
          </Card>

          {/* Notes & Terms */}
          {(invoice.notes || invoice.terms) && (
            <div className="grid grid-cols-2 gap-4">
              {invoice.notes && (
                <Card className="bg-gray-800 border-gray-700">
                  <CardContent className="p-4">
                    <h3 className="font-bold text-white mb-2">Notes:</h3>
                    <p className="text-gray-300 text-sm">{invoice.notes}</p>
                  </CardContent>
                </Card>
              )}

              {invoice.terms && (
                <Card className="bg-gray-800 border-gray-700">
                  <CardContent className="p-4">
                    <h3 className="font-bold text-white mb-2">Terms & Conditions:</h3>
                    <p className="text-gray-300 text-sm">{invoice.terms}</p>
                  </CardContent>
                </Card>
              )}
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Card, CardContent } from '@/components/ui/card';
import { base44 } from '@/api/base44Client';
const { Invoice } = base44.entities;
import { Plus, Trash2, Loader2 } from 'lucide-react';
import { toast } from 'sonner';

export default function InvoiceFormDialog({ open, onOpenChange, invoice, company, customers, onSuccess }) {
  const [formData, setFormData] = useState({
    invoice_number: '',
    invoice_type: 'invoice',
    customer_name: '',
    customer_email: '',
    customer_phone: '',
    customer_address: '',
    issue_date: new Date().toISOString().split('T')[0],
    due_date: '',
    items: [{ description: '', quantity: 1, unit_price: 0, total: 0 }],
    subtotal: 0,
    tax_percentage: 0,
    tax_amount: 0,
    discount_percentage: 0,
    discount_amount: 0,
    total: 0,
    notes: '',
    terms: 'Pembayaran dalam 7 hari'
  });

  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (open) {
      if (invoice) {
        setFormData({
          ...invoice,
          items: invoice.items || [{ description: '', quantity: 1, unit_price: 0, total: 0 }]
        });
      } else {
        // Generate invoice number
        generateInvoiceNumber();
      }
    }
  }, [open, invoice]);

  const generateInvoiceNumber = async () => {
    try {
      const existingInvoices = await Invoice.filter({ company_id: company.id });
      const count = existingInvoices.length + 1;
      const invNumber = `INV-${company.name.substring(0, 3).toUpperCase()}-${new Date().getFullYear()}${String(new Date().getMonth() + 1).padStart(2, '0')}${String(count).padStart(4, '0')}`;

      setFormData(prev => ({
        ...prev,
        invoice_number: invNumber
      }));
    } catch (error) {
      console.error('Error generating invoice number:', error);
    }
  };

  const calculateTotals = (items, taxPercentage, discountPercentage) => {
    const subtotal = items.reduce((sum, item) => sum + (item.total || 0), 0);
    const taxAmount = (subtotal * (taxPercentage || 0)) / 100;
    const discountAmount = (subtotal * (discountPercentage || 0)) / 100;
    const total = subtotal + taxAmount - discountAmount;

    setFormData(prev => ({
      ...prev,
      items,
      subtotal,
      tax_amount: taxAmount,
      discount_amount: discountAmount,
      total
    }));
  };

  const handleItemChange = (index, field, value) => {
    const newItems = [...formData.items];
    newItems[index][field] = value;

    if (field === 'quantity' || field === 'unit_price') {
      newItems[index].total = newItems[index].quantity * newItems[index].unit_price;
    }

    calculateTotals(newItems, formData.tax_percentage, formData.discount_percentage);
  };

  const addItem = () => {
    const newItems = [...formData.items, { description: '', quantity: 1, unit_price: 0, total: 0 }];
    calculateTotals(newItems, formData.tax_percentage, formData.discount_percentage);
  };

  const removeItem = (index) => {
    const newItems = formData.items.filter((_, i) => i !== index);
    calculateTotals(newItems, formData.tax_percentage, formData.discount_percentage);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.customer_name || formData.items.length === 0) {
      toast.error('Lengkapi data invoice');
      return;
    }

    setIsLoading(true);

    try {
      const dataToSave = {
        ...formData,
        company_id: company.id
      };

      if (invoice) {
        await Invoice.update(invoice.id, dataToSave);
        toast.success('Invoice berhasil diupdate');
      } else {
        await Invoice.create(dataToSave);
        toast.success('Invoice berhasil dibuat');
      }

      if (onSuccess) {
        onSuccess();
      }

      onOpenChange(false);

    } catch (error) {
      console.error('Error saving invoice:', error);
      toast.error('Gagal menyimpan invoice');
    } finally {
      setIsLoading(false);
    }
  };

  const formatPrice = (price) => {
    return new Intl.NumberFormat('id-ID').format(price);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto bg-gray-900 border-gray-700">
        <DialogHeader>
          <DialogTitle className="text-white">
            {invoice ? 'Edit Invoice' : 'Buat Invoice Baru'}
          </DialogTitle>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Header Info */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label className="text-gray-300">Nomor Invoice</Label>
              <Input
                value={formData.invoice_number}
                onChange={(e) => setFormData({ ...formData, invoice_number: e.target.value })}
                className="bg-gray-800 border-gray-700 text-white"
                required
              />
            </div>

            <div>
              <Label className="text-gray-300">Tipe</Label>
              <Select
                value={formData.invoice_type}
                onValueChange={(value) => setFormData({ ...formData, invoice_type: value })}
              >
                <SelectTrigger className="bg-gray-800 border-gray-700 text-white">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="invoice">Invoice</SelectItem>
                  <SelectItem value="quotation">Quotation</SelectItem>
                  <SelectItem value="proforma">Proforma</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label className="text-gray-300">Tanggal Terbit</Label>
              <Input
                type="date"
                value={formData.issue_date}
                onChange={(e) => setFormData({ ...formData, issue_date: e.target.value })}
                className="bg-gray-800 border-gray-700 text-white"
                required
              />
            </div>

            <div>
              <Label className="text-gray-300">Jatuh Tempo</Label>
              <Input
                type="date"
                value={formData.due_date}
                onChange={(e) => setFormData({ ...formData, due_date: e.target.value })}
                className="bg-gray-800 border-gray-700 text-white"
                required
              />
            </div>
          </div>

          {/* Customer Info */}
          <Card className="bg-gray-800 border-gray-700">
            <CardContent className="p-4 space-y-4">
              <h3 className="font-bold text-white">Informasi Customer</h3>

              <div>
                <Label className="text-gray-300">Nama Customer</Label>
                <Input
                  value={formData.customer_name}
                  onChange={(e) => setFormData({ ...formData, customer_name: e.target.value })}
                  className="bg-gray-700 border-gray-600 text-white"
                  required
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label className="text-gray-300">Email</Label>
                  <Input
                    type="email"
                    value={formData.customer_email}
                    onChange={(e) => setFormData({ ...formData, customer_email: e.target.value })}
                    className="bg-gray-700 border-gray-600 text-white"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Telepon</Label>
                  <Input
                    value={formData.customer_phone}
                    onChange={(e) => setFormData({ ...formData, customer_phone: e.target.value })}
                    className="bg-gray-700 border-gray-600 text-white"
                  />
                </div>
              </div>

              <div>
                <Label className="text-gray-300">Alamat</Label>
                <Textarea
                  value={formData.customer_address}
                  onChange={(e) => setFormData({ ...formData, customer_address: e.target.value })}
                  rows={2}
                  className="bg-gray-700 border-gray-600 text-white"
                />
              </div>
            </CardContent>
          </Card>

          {/* Items */}
          <Card className="bg-gray-800 border-gray-700">
            <CardContent className="p-4 space-y-4">
              <div className="flex justify-between items-center">
                <h3 className="font-bold text-white">Item Invoice</h3>
                <Button type="button" onClick={addItem} size="sm">
                  <Plus className="w-4 h-4 mr-1" />
                  Tambah Item
                </Button>
              </div>

              {formData.items.map((item, index) => (
                <div key={index} className="grid grid-cols-12 gap-2 items-start">
                  <div className="col-span-5">
                    <Input
                      placeholder="Deskripsi"
                      value={item.description}
                      onChange={(e) => handleItemChange(index, 'description', e.target.value)}
                      className="bg-gray-700 border-gray-600 text-white"
                      required
                    />
                  </div>
                  <div className="col-span-2">
                    <Input
                      type="number"
                      placeholder="Qty"
                      value={item.quantity}
                      onChange={(e) => handleItemChange(index, 'quantity', parseFloat(e.target.value) || 0)}
                      className="bg-gray-700 border-gray-600 text-white"
                      required
                    />
                  </div>
                  <div className="col-span-2">
                    <Input
                      type="number"
                      placeholder="Harga"
                      value={item.unit_price}
                      onChange={(e) => handleItemChange(index, 'unit_price', parseFloat(e.target.value) || 0)}
                      className="bg-gray-700 border-gray-600 text-white"
                      required
                    />
                  </div>
                  <div className="col-span-2">
                    <Input
                      value={formatPrice(item.total)}
                      readOnly
                      className="bg-gray-700 border-gray-600 text-white"
                    />
                  </div>
                  <div className="col-span-1">
                    {formData.items.length > 1 && (
                      <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        onClick={() => removeItem(index)}
                      >
                        <Trash2 className="w-4 h-4 text-red-400" />
                      </Button>
                    )}
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>

          {/* Totals */}
          <Card className="bg-gray-800 border-gray-700">
            <CardContent className="p-4 space-y-3">
              <div className="flex justify-between">
                <span className="text-gray-300">Subtotal:</span>
                <span className="text-white font-bold">Rp {formatPrice(formData.subtotal)}</span>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label className="text-gray-300">Pajak (%)</Label>
                  <Input
                    type="number"
                    value={formData.tax_percentage}
                    onChange={(e) => {
                      const taxPercentage = parseFloat(e.target.value) || 0;
                      setFormData({ ...formData, tax_percentage: taxPercentage });
                      calculateTotals(formData.items, taxPercentage, formData.discount_percentage);
                    }}
                    className="bg-gray-700 border-gray-600 text-white"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Diskon (%)</Label>
                  <Input
                    type="number"
                    value={formData.discount_percentage}
                    onChange={(e) => {
                      const discountPercentage = parseFloat(e.target.value) || 0;
                      setFormData({ ...formData, discount_percentage: discountPercentage });
                      calculateTotals(formData.items, formData.tax_percentage, discountPercentage);
                    }}
                    className="bg-gray-700 border-gray-600 text-white"
                  />
                </div>
              </div>

              <div className="flex justify-between text-lg border-t border-gray-700 pt-3">
                <span className="text-white font-bold">TOTAL:</span>
                <span className="text-green-400 font-bold text-2xl">
                  Rp {formatPrice(formData.total)}
                </span>
              </div>
            </CardContent>
          </Card>

          {/* Notes & Terms */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label className="text-gray-300">Catatan</Label>
              <Textarea
                value={formData.notes}
                onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                rows={3}
                className="bg-gray-800 border-gray-700 text-white"
              />
            </div>

            <div>
              <Label className="text-gray-300">Syarat & Ketentuan</Label>
              <Textarea
                value={formData.terms}
                onChange={(e) => setFormData({ ...formData, terms: e.target.value })}
                rows={3}
                className="bg-gray-800 border-gray-700 text-white"
              />
            </div>
          </div>

          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)} className="border-gray-600">
              Batal
            </Button>
            <Button type="submit" disabled={isLoading}>
              {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Simpan Invoice'}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { 
  Eye, 
  Trash2,
  TrendingUp,
  TrendingDown,
  Minus,
  Award
} from 'lucide-react';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';

export default function KPIList({ kpis, employees, companyId, onUpdate }) {
  const [expandedKPI, setExpandedKPI] = useState(null);

  const handleDelete = async (kpiId) => {
    if (!confirm('Yakin ingin menghapus KPI ini?')) return;

    try {
      await base44.entities.CompanyKPI.delete(kpiId);
      toast.success('KPI berhasil dihapus');
      onUpdate();
    } catch (error) {
      console.error('Error deleting KPI:', error);
      toast.error('Gagal menghapus KPI');
    }
  };

  const getRatingBadge = (rating) => {
    const badges = {
      outstanding: { color: 'bg-green-600', label: 'Outstanding' },
      exceeds: { color: 'bg-blue-600', label: 'Exceeds' },
      meets: { color: 'bg-purple-600', label: 'Meets' },
      needs_improvement: { color: 'bg-yellow-600', label: 'Needs Improvement' },
      unsatisfactory: { color: 'bg-red-600', label: 'Unsatisfactory' }
    };
    const badge = badges[rating] || badges.meets;
    return <Badge className={badge.color}>{badge.label}</Badge>;
  };

  const getScoreIcon = (actual, target) => {
    const percentage = (actual / target) * 100;
    if (percentage >= 100) return <TrendingUp className="w-4 h-4 text-green-400" />;
    if (percentage >= 70) return <Minus className="w-4 h-4 text-yellow-400" />;
    return <TrendingDown className="w-4 h-4 text-red-400" />;
  };

  if (kpis.length === 0) {
    return (
      <Card className="bg-gray-900 border-gray-700">
        <CardContent className="p-12 text-center">
          <Award className="w-16 h-16 text-gray-600 mx-auto mb-4" />
          <p className="text-gray-400">Belum ada KPI review</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-4">
      {kpis.map((kpi) => {
        const employee = employees.find(e => e.id === kpi.employee_id);
        const isExpanded = expandedKPI === kpi.id;

        return (
          <Card key={kpi.id} className="bg-gray-900 border-gray-700">
            <CardContent className="p-6">
              <div className="flex items-start justify-between mb-4">
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="text-xl font-bold text-white">{kpi.employee_name}</h3>
                    {getRatingBadge(kpi.rating)}
                  </div>
                  <div className="flex items-center gap-4 text-sm text-gray-400">
                    <span>Period: {format(new Date(kpi.period), 'MMMM yyyy', { locale: id })}</span>
                    <span>ΓÇó</span>
                    <span>Score: <span className="text-white font-bold">{kpi.overall_score?.toFixed(1)}</span>/100</span>
                    {employee && (
                      <>
                        <span>ΓÇó</span>
                        <span>{employee.department} - {employee.position}</span>
                      </>
                    )}
                  </div>
                </div>

                <div className="flex gap-2">
                  <Button
                    size="sm"
                    variant="ghost"
                    onClick={() => setExpandedKPI(isExpanded ? null : kpi.id)}
                    className="text-blue-400 hover:bg-gray-800"
                  >
                    <Eye className="w-4 h-4" />
                  </Button>
                  <Button
                    size="sm"
                    variant="ghost"
                    onClick={() => handleDelete(kpi.id)}
                    className="text-red-400 hover:bg-gray-800"
                  >
                    <Trash2 className="w-4 h-4" />
                  </Button>
                </div>
              </div>

              <Progress value={kpi.overall_score} className="h-3" />

              {isExpanded && (
                <div className="mt-6 space-y-4 pt-6 border-t border-gray-700">
                  <h4 className="text-white font-semibold mb-3">Breakdown Metrics:</h4>
                  {kpi.metrics?.map((metric, idx) => {
                    const achievement = (metric.actual / metric.target) * 100;
                    return (
                      <div key={idx} className="bg-gray-800 p-4 rounded-lg">
                        <div className="flex items-start justify-between mb-2">
                          <div className="flex-1">
                            <div className="flex items-center gap-2">
                              {getScoreIcon(metric.actual, metric.target)}
                              <h5 className="text-white font-semibold">{metric.name}</h5>
                              <Badge variant="outline" className="ml-auto">
                                Weight: {metric.weight}%
                              </Badge>
                            </div>
                            {metric.description && (
                              <p className="text-sm text-gray-400 mt-1">{metric.description}</p>
                            )}
                          </div>
                        </div>

                        <div className="grid grid-cols-3 gap-4 mt-3">
                          <div>
                            <p className="text-xs text-gray-400">Target</p>
                            <p className="text-white font-semibold">{metric.target} {metric.unit}</p>
                          </div>
                          <div>
                            <p className="text-xs text-gray-400">Actual</p>
                            <p className="text-white font-semibold">{metric.actual} {metric.unit}</p>
                          </div>
                          <div>
                            <p className="text-xs text-gray-400">Achievement</p>
                            <p className={`font-bold ${achievement >= 100 ? 'text-green-400' : achievement >= 70 ? 'text-yellow-400' : 'text-red-400'}`}>
                              {achievement.toFixed(1)}%
                            </p>
                          </div>
                        </div>

                        <Progress value={Math.min(100, achievement)} className="mt-3 h-2" />
                      </div>
                    );
                  })}

                  {kpi.reviewer_notes && (
                    <div className="bg-gray-800 p-4 rounded-lg">
                      <p className="text-sm font-semibold text-gray-400 mb-2">Catatan Reviewer:</p>
                      <p className="text-white">{kpi.reviewer_notes}</p>
                    </div>
                  )}
                </div>
              )}
            </CardContent>
          </Card>
        );
      })}
    </div>
  );
}

