function MetricWeightBar({ metrics }) {
  const total = metrics.reduce((s, m) => s + (Number(m.weight) || 0), 0);
  const isValid = Math.abs(total - 100) < 0.1;
  return (
    <div className="space-y-1.5">
      <div className="flex items-center justify-between text-sm">
        <span className="text-gray-400">Total Bobot Metrik</span>
        <div className="flex items-center gap-2">
          {isValid
            ? <CheckCircle className="w-4 h-4 text-green-400" />
            : <AlertCircle className="w-4 h-4 text-red-400" />
          }
          <span className={`font-bold ${isValid ? 'text-green-400' : 'text-red-400'}`}>{total}%</span>
          <span className="text-gray-500 text-xs">/ 100%</span>
        </div>
      </div>
      <div className="h-2.5 bg-gray-700 rounded-full overflow-hidden">
        <div
          className={`h-full rounded-full transition-all ${total > 100 ? 'bg-red-500' : total === 100 ? 'bg-green-500' : 'bg-yellow-500'}`}
          style={{ width: `${Math.min(total, 100)}%` }}
        />
      </div>
      {!isValid && (
        <p className="text-xs text-red-400">
          {total < 100 ? `Kurang ${100 - total}% lagi untuk mencapai 100%` : `Melebihi 100% sebesar ${total - 100}%`}
        </p>
      )}
    </div>
  );
}

export default function KPITemplateManager({ companyId, onTemplateCreated }) {
  const [templates, setTemplates] = useState([]);
  const [isOpen, setIsOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [editingTemplate, setEditingTemplate] = useState(null);
  const [dynamicRoles, setDynamicRoles] = useState([]);

  const freshForm = () => ({
    template_name: '',
    applicable_roles: [],
    applicable_departments: [],
    default_metrics: [
      { metric_name: 'Absensi Harian', description: 'Persentase kehadiran', default_target: 100, unit: '%', weight: 30, calculation_method: 'auto_from_attendance' },
      { metric_name: 'Penyelesaian Tugas', description: 'Tugas workspace diselesaikan', default_target: 100, unit: '%', weight: 40, calculation_method: 'auto_from_tasks' },
      { metric_name: 'Pencapaian Sales', description: 'Total penjualan dari POS', default_target: 5000000, unit: 'Rp', weight: 30, calculation_method: 'auto_from_sales' },
    ],
    auto_calculate: true,
    calculation_frequency: 'daily',
    is_active: true
  });

  const [formData, setFormData] = useState(freshForm());

  useEffect(() => {
    if (companyId) {
      loadTemplates();
      loadDynamicRoles();
    }
  }, [companyId]);

  const loadDynamicRoles = async () => {
    try {
      const members = await base44.entities.CompanyMember.filter({ company_id: companyId, status: 'active' });
      const positions = [...new Set((members || []).map(m => m.position).filter(Boolean))];
      const departments = [...new Set((members || []).map(m => m.department).filter(Boolean))];
      const roles = [...new Set((members || []).map(m => m.role).filter(Boolean))];
      // Combine all unique labels for roles dropdown
      const allRoles = [...new Set([...positions, ...roles, ...departments, 'Terapis', 'Sales', 'Kasir', 'Admin', 'Owner', 'Host', 'Manager', 'Supervisor'])];
      setDynamicRoles(allRoles.filter(r => r && r.trim()));
    } catch (e) {
      console.error('Load dynamic roles error:', e);
      setDynamicRoles(['Terapis', 'Sales', 'Kasir', 'Admin', 'Owner', 'Host', 'Manager', 'Supervisor', 'Employee']);
    }
  };

  const loadTemplates = async () => {
    try {
      setIsLoading(true);
      const data = await base44.entities.KPITemplate.filter({ company_id: companyId });
      setTemplates(data || []);
    } catch (e) {
      console.error('Load templates error:', e);
    } finally {
      setIsLoading(false);
    }
  };

  const addMetric = () => {
    setFormData(f => ({
      ...f,
      default_metrics: [...f.default_metrics, {
        metric_name: '', description: '', default_target: 100, unit: '%', weight: 0, calculation_method: 'manual'
      }]
    }));
  };

  const removeMetric = (i) => setFormData(f => ({ ...f, default_metrics: f.default_metrics.filter((_, idx) => idx !== i) }));
  const updateMetric = (i, field, val) => {
    const updated = [...formData.default_metrics];
    updated[i] = { ...updated[i], [field]: val };
    setFormData(f => ({ ...f, default_metrics: updated }));
  };

  const autoDistributeWeights = () => {
    const n = formData.default_metrics.length;
    if (n === 0) return;
    const base = Math.floor(100 / n);
    const remainder = 100 - base * n;
    const updated = formData.default_metrics.map((m, i) => ({
      ...m, weight: base + (i < remainder ? 1 : 0)
    }));
    setFormData(f => ({ ...f, default_metrics: updated }));
    toast.success('Bobot dibagi rata otomatis');
  };

  const handleSave = async () => {
    if (!formData.template_name.trim()) {
      toast.error('Nama template wajib diisi');
      return;
    }
    if (formData.default_metrics.length === 0) {
      toast.error('Tambahkan minimal 1 metric');
      return;
    }
    // Validate each metric has a name
    const emptyMetric = formData.default_metrics.find(m => !m.metric_name.trim());
    if (emptyMetric) {
      toast.error('Semua metric harus memiliki nama');
      return;
    }

    const totalWeight = formData.default_metrics.reduce((s, m) => s + (Number(m.weight) || 0), 0);
    if (Math.abs(totalWeight - 100) > 0.5) {
      toast.error(`Total bobot harus 100%. Saat ini: ${totalWeight}%`);
      return;
    }

    setIsSaving(true);
    try {
      const payload = {
        company_id: companyId,
        template_name: formData.template_name.trim(),
        applicable_roles: formData.applicable_roles || [],
        applicable_departments: formData.applicable_departments || [],
        default_metrics: formData.default_metrics.map(m => ({
          metric_name: m.metric_name,
          description: m.description || '',
          default_target: Number(m.default_target) || 100,
          unit: m.unit || '%',
          weight: Number(m.weight) || 0,
          calculation_method: m.calculation_method || 'manual'
        })),
        auto_calculate: Boolean(formData.auto_calculate),
        calculation_frequency: formData.calculation_frequency || 'daily',
        is_active: true
      };

      if (editingTemplate) {
        await base44.entities.KPITemplate.update(editingTemplate.id, payload);
        toast.success('Γ£à Template berhasil diperbarui!');
      } else {
        await base44.entities.KPITemplate.create(payload);
        toast.success('Γ£à KPI Template berhasil disimpan!');
      }

      setIsOpen(false);
      setEditingTemplate(null);
      setFormData(freshForm());
      loadTemplates();
      if (onTemplateCreated) onTemplateCreated();
    } catch (e) {
      console.error('Save template error:', e);
      toast.error('Gagal menyimpan template: ' + (e.message || 'Unknown error'));
    } finally {
      setIsSaving(false);
    }
  };

  const handleEdit = (template) => {
    setEditingTemplate(template);
    setFormData({
      template_name: template.template_name,
      applicable_roles: template.applicable_roles || [],
      applicable_departments: template.applicable_departments || [],
      default_metrics: template.default_metrics || [],
      auto_calculate: template.auto_calculate !== false,
      calculation_frequency: template.calculation_frequency || 'daily',
      is_active: template.is_active !== false
    });
    setIsOpen(true);
  };

  const handleDuplicate = async (template) => {
    try {
      await base44.entities.KPITemplate.create({
        ...template,
        id: undefined,
        template_name: template.template_name + ' (Copy)',
        company_id: companyId
      });
      toast.success('Template diduplikat');
      loadTemplates();
    } catch (e) { toast.error('Gagal menduplikat'); }
  };

  const deleteTemplate = async (id) => {
    if (!confirm('Hapus template ini?')) return;
    try {
      await base44.entities.KPITemplate.delete(id);
      toast.success('Template dihapus');
      loadTemplates();
    } catch (e) { toast.error('Gagal menghapus'); }
  };

  const loadPreset = (preset) => {
    setFormData(f => ({
      ...f,
      template_name: preset.template_name,
      applicable_roles: preset.applicable_roles,
      default_metrics: preset.default_metrics
    }));
    toast.success(`Preset "${preset.template_name}" dimuat`);
  };

  const openNew = () => {
    setEditingTemplate(null);
    setFormData(freshForm());
    setIsOpen(true);
  };

  return (
    <div className="space-y-4">
      <Card className="bg-gray-900 border-gray-700">
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle className="text-white flex items-center gap-2">
              <FileText className="w-5 h-5 text-purple-400" />
              KPI Templates
              <Badge className="bg-purple-600">{templates.length}</Badge>
            </CardTitle>
            <Button onClick={openNew} className="bg-purple-600 hover:bg-purple-700">
              <Plus className="w-4 h-4 mr-2" />
              Buat Template
            </Button>
          </div>
          <p className="text-sm text-gray-400 mt-1">
            Template menentukan metrik & bobot KPI karyawan. Terintegrasi otomatis dengan Absensi, POS, dan Workspace.
          </p>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="flex justify-center py-8"><Loader2 className="w-8 h-8 animate-spin text-purple-400" /></div>
          ) : templates.length === 0 ? (
            <div className="text-center py-10 text-gray-400 space-y-3">
              <FileText className="w-12 h-12 mx-auto text-gray-600" />
              <p className="font-medium">Belum ada KPI template</p>
              <p className="text-sm">Buat template atau gunakan preset yang tersedia</p>
              <div className="flex flex-wrap gap-2 justify-center mt-4">
                {PRESET_TEMPLATES.map(p => (
                  <Button key={p.template_name} size="sm" variant="outline" className="border-purple-600 text-purple-400"
                    onClick={() => { openNew(); setTimeout(() => loadPreset(p), 100); }}>
                    <Sparkles className="w-3 h-3 mr-1" /> {p.template_name}
                  </Button>
                ))}
              </div>
            </div>
          ) : (
            <div className="space-y-3">
              {templates.map((t) => (
                <div key={t.id} className="p-4 bg-gray-800 rounded-xl border border-gray-700 hover:border-purple-700 transition-colors">
                  <div className="flex items-start justify-between mb-3">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 flex-wrap mb-1">
                        <h3 className="font-bold text-white">{t.template_name}</h3>
                        {t.is_active !== false
                          ? <Badge className="bg-green-700 text-xs">Aktif</Badge>
                          : <Badge className="bg-gray-600 text-xs">Nonaktif</Badge>
                        }
                        {t.auto_calculate && <Badge className="bg-blue-700 text-xs"><Sparkles className="w-2.5 h-2.5 mr-1" />Auto-Calc</Badge>}
                      </div>
                      <div className="flex gap-1.5 flex-wrap mb-2">
                        {t.applicable_roles?.map((r, i) => <Badge key={i} className="bg-blue-800 text-xs">{r}</Badge>)}
                        {t.applicable_departments?.map((d, i) => <Badge key={i} className="bg-purple-800 text-xs">{d}</Badge>)}
                      </div>
                      <p className="text-xs text-gray-400">{t.default_metrics?.length || 0} metrik ┬╖ {t.calculation_frequency || 'daily'}</p>
                    </div>
                    <div className="flex gap-1 flex-shrink-0 ml-2">
                      <Button size="icon" variant="ghost" className="h-7 w-7 text-blue-400 hover:bg-blue-900/20" onClick={() => handleEdit(t)}>
                        <Edit className="w-3.5 h-3.5" />
                      </Button>
                      <Button size="icon" variant="ghost" className="h-7 w-7 text-gray-400 hover:bg-gray-700" onClick={() => handleDuplicate(t)}>
                        <Copy className="w-3.5 h-3.5" />
                      </Button>
                      <Button size="icon" variant="ghost" className="h-7 w-7 text-red-400 hover:bg-red-900/20" onClick={() => deleteTemplate(t.id)}>
                        <Trash2 className="w-3.5 h-3.5" />
                      </Button>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
                    {t.default_metrics?.slice(0, 6).map((m, i) => {
                      const calcCfg = CALC_METHODS.find(c => c.value === m.calculation_method);
                      return (
                        <div key={i} className="bg-gray-900 p-2 rounded-lg text-xs">
                          <p className="text-gray-300 font-medium truncate">{m.metric_name}</p>
                          <p className="text-gray-500 mt-0.5">{m.default_target} {m.unit} ┬╖ <span className="text-purple-400">{m.weight}%</span></p>
                          {calcCfg && <span className="text-[10px] text-blue-400">{calcCfg.icon} {calcCfg.label}</span>}
                        </div>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Dialog */}
      <Dialog open={isOpen} onOpenChange={(open) => { if (!open) { setIsOpen(false); setEditingTemplate(null); setFormData(freshForm()); } else setIsOpen(true); }}>
        <DialogContent className="max-w-4xl max-h-[92vh] overflow-y-auto bg-gray-900 border-gray-700">
          <DialogHeader>
            <DialogTitle className="text-white flex items-center gap-2">
              <FileText className="w-5 h-5 text-purple-400" />
              {editingTemplate ? 'Edit KPI Template' : 'Buat KPI Template Baru'}
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-5">
            {/* Preset buttons */}
            {!editingTemplate && (
              <div className="bg-gray-800 p-3 rounded-xl">
                <p className="text-xs text-gray-400 mb-2 font-medium">ΓÜí Muat dari Preset:</p>
                <div className="flex flex-wrap gap-2">
                  {PRESET_TEMPLATES.map(p => (
                    <Button key={p.template_name} size="sm" variant="outline" className="border-purple-600 text-purple-300 text-xs h-7"
                      onClick={() => loadPreset(p)}>
                      {p.template_name}
                    </Button>
                  ))}
                </div>
              </div>
            )}

            {/* Nama template */}
            <div>
              <Label className="text-gray-300">Nama Template <span className="text-red-400">*</span></Label>
              <Input
                value={formData.template_name}
                onChange={(e) => setFormData(f => ({ ...f, template_name: e.target.value }))}
                placeholder="Contoh: KPI Terapis Bulanan"
                className="bg-gray-800 border-gray-700 text-white mt-2"
              />
            </div>

            {/* Roles & Departments */}
            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label className="text-gray-300 mb-2 block text-sm">Berlaku untuk Role / Jabatan</Label>
                <div className="bg-gray-800 p-3 rounded-lg space-y-1.5 max-h-40 overflow-y-auto">
                  {(dynamicRoles.length > 0 ? dynamicRoles : ['Terapis', 'Sales', 'Kasir', 'Admin', 'Owner', 'Host', 'Manager', 'Supervisor', 'Employee']).map(role => (
                    <label key={role} className="flex items-center gap-2 cursor-pointer text-sm text-gray-300 hover:text-white">
                      <Checkbox
                        checked={formData.applicable_roles.includes(role)}
                        onCheckedChange={(c) => setFormData(f => ({
                          ...f,
                          applicable_roles: c ? [...f.applicable_roles, role] : f.applicable_roles.filter(r => r !== role)
                        }))}
                      />
                      {role}
                    </label>
                  ))}
                </div>
              </div>
              <div>
                <Label className="text-gray-300 mb-2 block text-sm">Berlaku untuk Departemen</Label>
                <div className="bg-gray-800 p-3 rounded-lg space-y-1.5 max-h-40 overflow-y-auto">
                  {(dynamicRoles.length > 0 ? dynamicRoles : ['Sales', 'Terapis', 'Kasir', 'Admin', 'Marketing', 'Operasional', 'Finance', 'IT', 'HR']).map(dept => (
                    <label key={dept} className="flex items-center gap-2 cursor-pointer text-sm text-gray-300 hover:text-white">
                      <Checkbox
                        checked={formData.applicable_departments.includes(dept)}
                        onCheckedChange={(c) => setFormData(f => ({
                          ...f,
                          applicable_departments: c ? [...f.applicable_departments, dept] : f.applicable_departments.filter(d => d !== dept)
                        }))}
                      />
                      {dept}
                    </label>
                  ))}
                </div>
              </div>
            </div>

            {/* Metrics */}
            <div>
              <div className="flex items-center justify-between mb-3">
                <Label className="text-white text-base font-semibold">Metrik KPI</Label>
                <div className="flex gap-2">
                  <Button type="button" size="sm" variant="outline" onClick={autoDistributeWeights} className="border-yellow-600 text-yellow-400 text-xs h-8">
                    ΓÜû∩╕Å Rata-kan Bobot
                  </Button>
                  <Button type="button" size="sm" onClick={addMetric} className="bg-blue-600 h-8 text-xs">
                    <Plus className="w-3 h-3 mr-1" /> Tambah Metrik
                  </Button>
                </div>
              </div>

              <div className="space-y-3">
                {formData.default_metrics.map((metric, index) => (
                  <Card key={index} className="bg-gray-800 border-gray-700">
                    <CardContent className="p-4">
                      <div className="flex items-center justify-between mb-3">
                        <span className="text-gray-300 text-sm font-semibold">Metrik #{index + 1}</span>
                        {formData.default_metrics.length > 1 && (
                          <Button size="icon" variant="ghost" onClick={() => removeMetric(index)} className="h-7 w-7 text-red-400 hover:bg-red-900/20">
                            <Trash2 className="w-3.5 h-3.5" />
                          </Button>
                        )}
                      </div>
                      <div className="grid grid-cols-2 gap-3">
                        <div className="col-span-2 md:col-span-1 space-y-1">
                          <Label className="text-gray-400 text-xs">Nama Metrik <span className="text-red-400">*</span></Label>
                          <Input value={metric.metric_name} onChange={(e) => updateMetric(index, 'metric_name', e.target.value)}
                            className="bg-gray-900 border-gray-600 text-white h-8 text-sm" placeholder="Contoh: Absensi Harian" />
                        </div>
                        <div className="space-y-1">
                          <Label className="text-gray-400 text-xs">Satuan (Unit)</Label>
                          <Input value={metric.unit} onChange={(e) => updateMetric(index, 'unit', e.target.value)}
                            className="bg-gray-900 border-gray-600 text-white h-8 text-sm" placeholder="%, Rp, sesi" />
                        </div>
                        <div className="space-y-1">
                          <Label className="text-gray-400 text-xs">Target Default</Label>
                          <Input type="number" value={metric.default_target} onChange={(e) => updateMetric(index, 'default_target', Number(e.target.value))}
                            className="bg-gray-900 border-gray-600 text-white h-8 text-sm" />
                        </div>
                        <div className="space-y-1">
                          <Label className="text-gray-400 text-xs">Bobot (%) <span className="text-red-400">*</span></Label>
                          <Input type="number" min="0" max="100" value={metric.weight} onChange={(e) => updateMetric(index, 'weight', Number(e.target.value))}
                            className="bg-gray-900 border-gray-600 text-white h-8 text-sm" />
                        </div>
                        <div className="col-span-2 space-y-1">
                          <Label className="text-gray-400 text-xs">Metode Kalkulasi</Label>
                          <Select value={metric.calculation_method} onValueChange={(v) => updateMetric(index, 'calculation_method', v)}>
                            <SelectTrigger className="bg-gray-900 border-gray-600 text-white h-8 text-sm">
                              <SelectValue />
                            </SelectTrigger>
                            <SelectContent className="bg-gray-900 border-gray-700">
                              {CALC_METHODS.map(c => (
                                <SelectItem key={c.value} value={c.value} className="text-sm">{c.icon} {c.label}</SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          {metric.calculation_method !== 'manual' && (
                            <p className="text-xs text-blue-400">ΓÜí Nilai akan diisi otomatis dari data sistem</p>
                          )}
                        </div>
                        <div className="col-span-2 space-y-1">
                          <Label className="text-gray-400 text-xs">Deskripsi</Label>
                          <Input value={metric.description || ''} onChange={(e) => updateMetric(index, 'description', e.target.value)}
                            className="bg-gray-900 border-gray-600 text-white h-8 text-sm" placeholder="Penjelasan singkat metrik ini" />
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>

              <div className="mt-3">
                <MetricWeightBar metrics={formData.default_metrics} />
              </div>
            </div>

            {/* Auto-calculate settings */}
            <div className="bg-gray-800 p-4 rounded-xl space-y-3">
              <div className="flex items-center justify-between">
                <div>
                  <Label className="text-white text-sm font-semibold">Auto-Calculate KPI</Label>
                  <p className="text-xs text-gray-400 mt-0.5">Otomatis update nilai KPI dari data Absensi, POS, dan Workspace</p>
                </div>
                <Switch checked={formData.auto_calculate} onCheckedChange={(c) => setFormData(f => ({ ...f, auto_calculate: c }))} />
              </div>
              {formData.auto_calculate && (
                <div className="space-y-1">
                  <Label className="text-gray-400 text-xs">Frekuensi Kalkulasi</Label>
                  <Select value={formData.calculation_frequency} onValueChange={(v) => setFormData(f => ({ ...f, calculation_frequency: v }))}>
                    <SelectTrigger className="bg-gray-900 border-gray-700 text-white h-9 text-sm">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className="bg-gray-900 border-gray-700">
                      <SelectItem value="daily">≡ƒîà Daily (Setiap Hari)</SelectItem>
                      <SelectItem value="weekly">≡ƒôà Weekly (Setiap Minggu)</SelectItem>
                      <SelectItem value="monthly">≡ƒùô∩╕Å Monthly (Akhir Bulan)</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              )}
            </div>

            {/* Footer actions */}
            <div className="flex justify-between items-center pt-4 border-t border-gray-700">
              <Button variant="outline" onClick={() => { setIsOpen(false); setEditingTemplate(null); setFormData(freshForm()); }}
                className="border-gray-700 text-gray-300" disabled={isSaving}>
                Batal
              </Button>
              <Button onClick={handleSave} disabled={isSaving} className="bg-green-600 hover:bg-green-700 min-w-[160px]">
                {isSaving
                  ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Menyimpan...</>
                  : <><Save className="w-4 h-4 mr-2" /> {editingTemplate ? 'Update Template' : 'Simpan Template'}</>
                }
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Checkbox } from '@/components/ui/checkbox';
import { Badge } from '@/components/ui/badge';
import { Loader2, CheckSquare, Sparkles, Zap, FileText } from 'lucide-react';
import { toast } from 'sonner';

export default function QuickKPIEntry({ employees, companyId, period, onSuccess }) {
  const [templates, setTemplates] = useState([]);
  const [selectedEmployees, setSelectedEmployees] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);

  useEffect(() => {
    loadTemplates();
  }, [companyId]);

  const loadTemplates = async () => {
    try {
      const templatesData = await base44.entities.KPITemplate.filter({
        company_id: companyId,
        is_active: true
      });
      setTemplates(templatesData || []);
    } catch (error) {
      console.error('Error loading templates:', error);
    }
  };

  const getTemplateForEmployee = (employee) => {
    const normalize = (s) => (s || '').toLowerCase().trim();
    const empPosition = normalize(employee.position);
    const empDept = normalize(employee.department);
    const empRole = normalize(employee.role);

    return templates.find(t => {
      const roles = (t.applicable_roles || []).map(normalize);
      const depts = (t.applicable_departments || []).map(normalize);
      return (
        (empPosition && roles.includes(empPosition)) ||
        (empDept && roles.includes(empDept)) ||
        (empRole && roles.includes(empRole)) ||
        (empDept && depts.includes(empDept)) ||
        (empPosition && depts.includes(empPosition))
      );
    });
  };

  const autoCalculateMetric = async (employee, metric, period) => {
    try {
      if (metric.calculation_method === 'manual') {
        return metric.default_target;
      }

      const currentMonth = period;
      const startDate = `${currentMonth}-01`;
      const endDate = `${currentMonth}-31`;

      if (metric.calculation_method === 'auto_from_attendance') {
        const attendance = await base44.entities.CompanyAttendance.filter({
          company_id: companyId,
          employee_id: employee.id,
          date: { $gte: startDate, $lte: endDate }
        });

        const presentDays = attendance.filter(a => 
          a.status === 'present' || a.status === 'late'
        ).length;
        
        const totalDays = attendance.length;
        const attendanceRate = totalDays > 0 ? (presentDays / totalDays) * 100 : 0;

        return attendanceRate;
      }

      if (metric.calculation_method === 'auto_from_sales') {
        const transactions = await base44.entities.CompanyPOSTransaction.filter({
          company_id: companyId,
          cashier_id: employee.id,
          created_date: { $gte: startDate, $lte: endDate }
        });

        const totalSales = transactions.reduce((sum, t) => sum + (t.total || 0), 0);
        return totalSales;
      }

      if (metric.calculation_method === 'auto_from_projects') {
        const projects = await base44.entities.Project.filter({
          company_id: companyId,
          team_members: { $contains: employee.id }
        });

        const completedProjects = projects.filter(p => p.status === 'completed').length;
        return completedProjects;
      }

      return metric.default_target;

    } catch (error) {
      console.error('Error auto-calculating metric:', error);
      return metric.default_target;
    }
  };

  const generateKPIsFromTemplates = async () => {
    if (selectedEmployees.length === 0) {
      toast.error('Pilih minimal 1 karyawan');
      return;
    }

    try {
      setIsGenerating(true);

      for (const employeeId of selectedEmployees) {
        const employee = employees.find(e => e.id === employeeId);
        const template = getTemplateForEmployee(employee);

        if (!template) {
          console.log(`No template for ${employee.user_name}`);
          continue;
        }

        const calculatedMetrics = await Promise.all(
          template.default_metrics.map(async (metric) => {
            const actualValue = await autoCalculateMetric(employee, metric, period);

            return {
              name: metric.metric_name,
              description: metric.description,
              target: metric.default_target,
              actual: actualValue,
              unit: metric.unit,
              weight: metric.weight
            };
          })
        );

        let overallScore = 0;
        calculatedMetrics.forEach(m => {
          const achievement = (m.actual / m.target) * 100;
          const weightedScore = achievement * (m.weight / 100);
          overallScore += weightedScore;
        });

        const rating = 
          overallScore >= 90 ? 'outstanding' :
          overallScore >= 80 ? 'exceeds' :
          overallScore >= 70 ? 'meets' :
          overallScore >= 50 ? 'needs_improvement' :
          'unsatisfactory';

        await base44.entities.CompanyKPI.create({
          company_id: companyId,
          employee_id: employee.id,
          employee_name: employee.user_name,
          period: period,
          metrics: calculatedMetrics,
          overall_score: Math.min(100, overallScore),
          rating: rating,
          status: 'finalized',
          auto_generated: true,
          template_id: template.id
        });
      }

      toast.success(`Γ£à KPI berhasil di-generate untuk ${selectedEmployees.length} karyawan!`);
      onSuccess();
      setSelectedEmployees([]);

    } catch (error) {
      console.error('Error generating KPIs:', error);
      toast.error('Gagal generate KPI');
    } finally {
      setIsGenerating(false);
    }
  };

  const toggleEmployee = (employeeId) => {
    if (selectedEmployees.includes(employeeId)) {
      setSelectedEmployees(selectedEmployees.filter(id => id !== employeeId));
    } else {
      setSelectedEmployees([...selectedEmployees, employeeId]);
    }
  };

  const selectAll = () => {
    if (selectedEmployees.length === employees.length) {
      setSelectedEmployees([]);
    } else {
      setSelectedEmployees(employees.map(e => e.id));
    }
  };

  return (
    <Card className="bg-gradient-to-br from-purple-900/20 to-blue-900/20 border-purple-700">
      <CardHeader>
        <CardTitle className="text-white flex items-center gap-2">
          <Zap className="w-5 h-5 text-yellow-400" />
          Quick KPI Generation
          <Badge className="ml-2 bg-purple-600">
            Tinggal Centang!
          </Badge>
        </CardTitle>
        <p className="text-sm text-gray-400 mt-2">
          ≡ƒÆí Pilih karyawan dan KPI akan otomatis dihitung berdasarkan template dan data realtime
        </p>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="flex items-center justify-between mb-3">
          <Button
            size="sm"
            variant="outline"
            onClick={selectAll}
            className="border-gray-600"
          >
            <CheckSquare className="w-4 h-4 mr-2" />
            {selectedEmployees.length === employees.length ? 'Unselect All' : 'Select All'}
          </Button>

          <span className="text-sm text-gray-400">
            {selectedEmployees.length} / {employees.length} dipilih
          </span>
        </div>

        <div className="max-h-96 overflow-y-auto space-y-2 bg-gray-800 p-3 rounded-lg">
          {employees.map((employee) => {
            const template = getTemplateForEmployee(employee);
            const hasTemplate = !!template;

            return (
              <div
                key={employee.id}
                className={`flex items-center justify-between p-3 rounded-lg border ${
                  hasTemplate ? 'border-purple-600 bg-purple-900/10' : 'border-gray-700 bg-gray-900'
                }`}
              >
                <div className="flex items-center gap-3 flex-1">
                  <Checkbox
                    checked={selectedEmployees.includes(employee.id)}
                    onCheckedChange={() => toggleEmployee(employee.id)}
                    disabled={!hasTemplate}
                  />
                  <div className="flex-1">
                    <p className="text-white font-medium">{employee.user_name}</p>
                    <div className="flex gap-2 mt-1">
                      <Badge variant="outline" className="text-xs">
                        {employee.position}
                      </Badge>
                      <Badge variant="outline" className="text-xs">
                        {employee.department}
                      </Badge>
                    </div>
                  </div>
                </div>

                {hasTemplate ? (
                  <div className="text-right">
                    <Badge className="bg-green-600 text-xs">
                      <Sparkles className="w-3 h-3 mr-1" />
                      {template.template_name}
                    </Badge>
                    <p className="text-xs text-gray-400 mt-1">
                      {template.default_metrics?.length} metrics
                    </p>
                  </div>
                ) : (
                  <Badge variant="outline" className="text-xs text-gray-500">
                    No Template
                  </Badge>
                )}
              </div>
            );
          })}
        </div>

        <Button
          onClick={generateKPIsFromTemplates}
          disabled={isGenerating || selectedEmployees.length === 0}
          className="w-full bg-green-600 hover:bg-green-700"
        >
          {isGenerating ? (
            <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Generating KPIs...</>
          ) : (
            <><Zap className="w-4 h-4 mr-2" /> Generate KPI untuk {selectedEmployees.length} Karyawan</>
          )}
        </Button>

        {templates.length === 0 && (
          <div className="text-center py-4 text-gray-400 text-sm">
            <FileText className="w-8 h-8 mx-auto mb-2 text-gray-600" />
            <p>Belum ada KPI template.</p>
            <p>Buat template terlebih dahulu di tab "KPI Templates"</p>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Bell } from 'lucide-react';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { Card } from '@/components/ui/card';

export default function NotificationBell({ user }) {
  const [notifications, setNotifications] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [isOpen, setIsOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [hasError, setHasError] = useState(false);

  const loadNotifications = async () => {
    if (!user || !user.email || isLoading) return;

    try {
      setIsLoading(true);
      setHasError(false);
      
      // Γ£à IMPROVED: Add timeout and better error handling
      const data = await Promise.race([
        base44.entities.Notification.filter({
          user_id: user.email,
          is_read: false
        }),
        new Promise((_, reject) => 
          setTimeout(() => reject(new Error('Timeout')), 5000)
        )
      ]);

      setNotifications(data || []);
      setUnreadCount((data || []).length);
    } catch (error) {
      console.log('ΓÜá∩╕Å Could not load notifications:', error?.message || 'Unknown error');
      setHasError(true);
      // Silent fail - don't show error to user
      setNotifications([]);
      setUnreadCount(0);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (user) {
      // Delayed initial load to prevent blocking
      const timer = setTimeout(() => {
        loadNotifications();
      }, 2000);

      // Refresh only when page becomes visible
      const handleVisibilityChange = () => {
        if (document.visibilityState === 'visible' && !isLoading) {
          loadNotifications();
        }
      };

      document.addEventListener('visibilitychange', handleVisibilityChange);

      return () => {
        clearTimeout(timer);
        document.removeEventListener('visibilitychange', handleVisibilityChange);
      };
    }
  }, [user]);

  // Γ£à LISTEN TO BROADCAST - REALTIME NOTIFICATIONS!
  useEffect(() => {
    if (!user?.email) return;

    console.log('≡ƒöö NotificationBell: Setting up realtime listener for', user.email);

    const channel = new BroadcastChannel('snishop_invitation_updates');

    channel.onmessage = (event) => {
      const { type, invitedEmail } = event.data;

      if (type === 'INVITATION_CREATED' && invitedEmail === user.email) {
        console.log('≡ƒöö New invitation notification received!');
        
        // Γ£à RELOAD NOTIFICATIONS INSTANTLY
        setTimeout(() => {
          loadNotifications();
        }, 1000);
      }
    };

    return () => {
      channel.close();
    };
  }, [user, loadNotifications]); // Added loadNotifications to dependencies

  const handleMarkAsRead = async (notificationId) => {
    try {
      await base44.entities.Notification.update(notificationId, { is_read: true });
      setNotifications(prev => prev.filter(n => n.id !== notificationId));
      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch (error) {
      console.log('ΓÜá∩╕Å Could not mark notification as read:', error?.message);
    }
  };

  const handleNotificationClick = async (notification) => {
    await handleMarkAsRead(notification.id);
    if (notification.url) {
      window.location.href = notification.url;
    }
  };

  // Always show bell, even with errors
  return (
    <DropdownMenu onOpenChange={setIsOpen}>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon" className="relative">
          <Bell className="w-5 h-5 text-gray-600 dark:text-gray-400" />
          {unreadCount > 0 && !hasError && (
            <Badge 
              className="absolute -top-1 -right-1 h-5 w-5 flex items-center justify-center p-0 bg-red-500 text-white text-xs"
            >
              {unreadCount > 9 ? '9+' : unreadCount}
            </Badge>
          )}
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-80 max-h-96 overflow-y-auto">
        <div className="p-2">
          <h3 className="font-semibold mb-2">Notifikasi</h3>
          {isLoading ? (
            <p className="text-sm text-gray-500 text-center py-4">
              Memuat notifikasi...
            </p>
          ) : hasError ? (
            <p className="text-sm text-gray-500 text-center py-4">
              Tidak dapat memuat notifikasi
            </p>
          ) : notifications.length === 0 ? (
            <p className="text-sm text-gray-500 text-center py-4">
              Tidak ada notifikasi baru
            </p>
          ) : (
            <div className="space-y-2">
              {notifications.map((notification) => (
                <Card
                  key={notification.id}
                  className="p-3 cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors"
                  onClick={() => handleNotificationClick(notification)}
                >
                  <h4 className="font-medium text-sm">{notification.title}</h4>
                  <p className="text-xs text-gray-600 dark:text-gray-400 mt-1">
                    {notification.message}
                  </p>
                </Card>
              ))}
            </div>
          )}
        </div>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

import { useEffect, useRef, useCallback } from 'react';
import { Task } from '@/entities/Task';
import { Notification } from '@/entities/Notification';

const NotificationService = ({ user }) => {
  const intervalRef = useRef(null);
  const lastCheckRef = useRef(new Date());
  const notifiedTasksRef = useRef(new Set());

  const requestNotificationPermission = useCallback(async () => {
    if ('Notification' in window) {
      if (Notification.permission === 'default') {
        const permission = await Notification.requestPermission();
        if (permission === 'granted') {
          console.log('Notification permission granted');
          // Test notification
          showTestNotification();
        } else {
          console.log('Notification permission denied');
        }
      }
    }
  }, []);

  const showTestNotification = () => {
    if (Notification.permission === 'granted') {
      const notification = new Notification('TODOIT Aktif', {
        body: 'Sistem notifikasi telah diaktifkan. Anda akan menerima pengingat untuk tugas-tugas penting.',
        icon: '/favicon.ico',
        badge: '/favicon.ico',
        tag: 'todoit-activated',
        silent: false
      });

      // Auto close after 4 seconds
      setTimeout(() => notification.close(), 4000);
    }
  };

  const checkForDueTasks = async () => {
    try {
      if (Notification.permission !== 'granted') return;

      const now = new Date();
      const checkTime = new Date(now.getTime() + 60 * 60 * 1000); // Next 1 hour

      // Get all tasks assigned to current user that are due soon
      const tasks = await Task.filter({
        $or: [
          { created_by: user.email },
          { assignee_id: user.email }
        ]
      });

      for (const task of tasks) {
        // Skip if task is completed or cancelled
        if (task.status === 'done' || task.status === 'cancelled') continue;
        
        // Skip if already notified
        if (notifiedTasksRef.current.has(task.id)) continue;

        if (task.due_date) {
          const dueDate = new Date(task.due_date);
          const reminderTime = task.reminder_config?.value || 30;
          const reminderUnit = task.reminder_config?.unit || 'minutes';
          
          let reminderMs = 0;
          switch (reminderUnit) {
            case 'minutes': reminderMs = reminderTime * 60 * 1000; break;
            case 'hours': reminderMs = reminderTime * 60 * 60 * 1000; break;
            case 'days': reminderMs = reminderTime * 24 * 60 * 60 * 1000; break;
          }

          const reminderDateTime = new Date(dueDate.getTime() - reminderMs);

          // Check if it's time to send reminder
          if (now >= reminderDateTime && now < dueDate) {
            await sendTaskNotification(task, dueDate, reminderTime, reminderUnit);
            notifiedTasksRef.current.add(task.id);
            
            // Record notification in database
            await Notification.create({
              user_id: user.email,
              title: `Pengingat: ${task.title}`,
              message: `Tugas Anda akan dimulai dalam ${reminderTime} ${reminderUnit}`,
              url: `/tasks?id=${task.id}`
            });
          }
        }
      }
    } catch (error) {
      console.error('Error checking for due tasks:', error);
    }
  };

  const startNotificationService = useCallback(() => {
    // Check immediately
    checkForDueTasks();
    
    // Then check every 30 seconds
    intervalRef.current = setInterval(() => {
      checkForDueTasks();
    }, 30000); // 30 seconds
  }, []);

  const sendTaskNotification = async (task, dueDate, reminderTime, reminderUnit) => {
    if (Notification.permission !== 'granted') return;

    // Create notification sound
    const audio = new Audio('data:audio/wav;base64,UklGRnoGAABXQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YQoGAACBhYqFbF1fdJivrJBhNjVgodDbq2EcBj+a2/LDciUFLIHO8tiJNwgZaLvt559NEAxQp+PwtmMcBjiR1/LMeSwFJHfH8N2QQAoUXrTp66hVFApGn+DyvmwhBjaG0/DN');
    audio.volume = 0.5;

    const unitText = {
      'minutes': 'menit',
      'hours': 'jam',
      'days': 'hari'
    };

    const notification = new Notification(`≡ƒöö Pengingat Tugas: ${task.title}`, {
      body: `Tugas Anda akan dimulai dalam ${reminderTime} ${unitText[reminderUnit]}!\n\nJadwal: ${dueDate.toLocaleString('id-ID', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      })}`,
      icon: '/favicon.ico',
      badge: '/favicon.ico',
      tag: `task-${task.id}`,
      requireInteraction: true, // Keep notification until user interacts
      silent: false,
      actions: [
        {
          action: 'mark-done',
          title: 'Tandai Selesai'
        },
        {
          action: 'snooze',
          title: 'Tunda 10 Menit'
        }
      ]
    });

    // Play sound
    try {
      await audio.play();
    } catch (e) {
      console.log('Could not play notification sound:', e);
    }

    // Handle notification click
    notification.onclick = () => {
      window.focus();
      window.location.href = `/tasks?id=${task.id}`;
      notification.close();
    };

    // Auto close after 30 seconds if user doesn't interact
    setTimeout(() => {
      if (notification) {
        notification.close();
      }
    }, 30000);
  };

  useEffect(() => {
    if (!user) return;

    requestNotificationPermission();
    startNotificationService();
    
    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
      }
    };
  }, [user, requestNotificationPermission, startNotificationService]);

  // This component doesn't render anything visible
  return null;
};

export default NotificationService;

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Bell, X, CheckCircle, AlertTriangle, AlertCircle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';

const NotificationToast = ({ notification, onClose, onAction }) => {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => {
      handleClose();
    }, 8000); // Auto close after 8 seconds

    return () => clearTimeout(timer);
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(() => onClose(), 300); // Wait for animation to complete
  };

  const getIcon = (type) => {
    switch (type) {
      case 'success':
        return <CheckCircle className="w-5 h-5 text-green-500" />;
      case 'warning':
        return <AlertTriangle className="w-5 h-5 text-yellow-500" />;
      case 'error':
        return <AlertCircle className="w-5 h-5 text-red-500" />;
      default:
        return <Bell className="w-5 h-5 text-blue-500" />;
    }
  };

  const getBgColor = (type) => {
    switch (type) {
      case 'success':
        return 'bg-green-50 border-green-200 dark:bg-green-900/20 dark:border-green-800';
      case 'warning':
        return 'bg-yellow-50 border-yellow-200 dark:bg-yellow-900/20 dark:border-yellow-800';
      case 'error':
        return 'bg-red-50 border-red-200 dark:bg-red-900/20 dark:border-red-800';
      default:
        return 'bg-blue-50 border-blue-200 dark:bg-blue-900/20 dark:border-blue-800';
    }
  };

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          initial={{ opacity: 0, y: -100, scale: 0.95 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          exit={{ opacity: 0, y: -50, scale: 0.95 }}
          transition={{
            type: "spring",
            stiffness: 500,
            damping: 30,
            mass: 0.8
          }}
          className="fixed top-4 right-4 z-[100] max-w-md w-full"
        >
          <Card className={`p-4 shadow-xl border-2 ${getBgColor(notification.type)} backdrop-blur-md`}>
            <div className="flex items-start gap-3">
              <motion.div
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                transition={{ delay: 0.2, type: "spring", stiffness: 400 }}
              >
                {getIcon(notification.type)}
              </motion.div>
              
              <div className="flex-1 min-w-0">
                <motion.h4 
                  className="font-semibold text-gray-900 dark:text-gray-100 text-sm mb-1"
                  initial={{ opacity: 0, x: 20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.1 }}
                >
                  {notification.title}
                </motion.h4>
                <motion.p 
                  className="text-gray-700 dark:text-gray-300 text-xs leading-relaxed"
                  initial={{ opacity: 0, x: 20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.2 }}
                >
                  {notification.message}
                </motion.p>
                
                {notification.url && (
                  <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.3 }}
                    className="mt-3"
                  >
                    <Button 
                      size="sm" 
                      variant="outline"
                      onClick={() => {
                        if (notification.url.startsWith('http')) {
                          window.open(notification.url, '_blank');
                        } else {
                          window.location.href = notification.url;
                        }
                        handleClose();
                      }}
                      className="h-7 text-xs px-3"
                    >
                      Lihat Detail
                    </Button>
                  </motion.div>
                )}
              </div>
              
              <Button
                variant="ghost"
                size="icon"
                onClick={handleClose}
                className="h-6 w-6 text-gray-400 hover:text-gray-600 dark:text-gray-500 dark:hover:text-gray-300 flex-shrink-0"
              >
                <X className="w-4 h-4" />
              </Button>
            </div>
            
            {/* Progress bar */}
            <motion.div
              className="absolute bottom-0 left-0 h-1 bg-blue-500 rounded-bl-lg"
              initial={{ width: "100%" }}
              animate={{ width: "0%" }}
              transition={{ duration: 8, ease: "linear" }}
            />
          </Card>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

