        notes: order.notes || ''
      });
      setMaterialsConsumption(order.materials_consumed || []);
      setQualityCheck(order.quality_check || {
        passed: 0,
        failed: 0,
        inspector: '',
        inspection_date: '',
        notes: ''
      });
    } else {
      // Generate order number
      const orderNum = `PO-${Date.now().toString().slice(-8)}`;
      setFormData(prev => ({ ...prev, order_number: orderNum }));
    }
  }, [order]);

  const loadData = async () => {
    try {
      const [bomsData, productsData, employeesData, materialsData] = await Promise.all([
        base44.entities.BillOfMaterials.filter({ company_id, is_active: true }),
        base44.entities.CompanyPOSProduct.filter({ company_id }),
        base44.entities.CompanyMember.filter({ company_id, status: 'active' }),
        base44.entities.RawMaterial.filter({ company_id, is_active: true })
      ]);

      setBoms(bomsData || []);
      setProducts(productsData || []);
      setEmployees(employeesData || []);
      setRawMaterials(materialsData || []);
    } catch (error) {
      console.error('Error loading data:', error);
      toast.error('Gagal memuat data');
    }
  };

  const handleBOMChange = async (bomId) => {
    const bom = boms.find(b => b.id === bomId);
    if (!bom) return;

    setSelectedBOM(bom);
    setFormData(prev => ({
      ...prev,
      bom_id: bomId,
      product_id: bom.product_id,
      product_name: bom.product_name,
      labor_cost: bom.labor_cost || 0,
      overhead_cost: bom.overhead_cost || 0
    }));

    // Calculate materials needed
    const materials = bom.materials.map(m => ({
      material_id: m.material_id,
      material_name: m.material_name,
      material_code: m.material_code,
      quantity_used: m.quantity_needed * formData.quantity_to_produce,
      unit: m.unit,
      cost: m.unit_cost * m.quantity_needed * formData.quantity_to_produce
    }));

    setMaterialsConsumption(materials);

    // Check material availability
    await checkMaterialAvailability(materials);
  };

  const checkMaterialAvailability = async (materials) => {
    const availability = {};
    
    for (const mat of materials) {
      const rawMat = rawMaterials.find(rm => rm.id === mat.material_id);
      if (rawMat) {
        const available = rawMat.current_stock >= mat.quantity_used;
        availability[mat.material_id] = {
          available,
          currentStock: rawMat.current_stock,
          needed: mat.quantity_used,
          shortage: available ? 0 : mat.quantity_used - rawMat.current_stock
        };
      }
    }

    setMaterialAvailability(availability);
  };

  const handleQuantityChange = (quantity) => {
    setFormData(prev => ({ ...prev, quantity_to_produce: quantity }));

    if (selectedBOM) {
      const materials = selectedBOM.materials.map(m => ({
        material_id: m.material_id,
        material_name: m.material_name,
        material_code: m.material_code,
        quantity_used: m.quantity_needed * quantity,
        unit: m.unit,
        cost: m.unit_cost * m.quantity_needed * quantity
      }));

      setMaterialsConsumption(materials);
      checkMaterialAvailability(materials);
    }
  };

  const handleStatusChange = async (newStatus) => {
    setFormData(prev => ({ ...prev, status: newStatus }));

    // Auto-fill dates based on status
    const now = new Date().toISOString().split('T')[0];
    if (newStatus === 'in_progress' && !formData.actual_start_date) {
      setFormData(prev => ({ ...prev, actual_start_date: now }));
    }
    if (newStatus === 'completed' && !formData.actual_end_date) {
      setFormData(prev => ({ ...prev, actual_end_date: now }));
    }
  };

  const calculateTotalCost = () => {
    const materialCost = materialsConsumption.reduce((sum, m) => sum + (m.cost || 0), 0);
    const totalCost = materialCost + formData.labor_cost + formData.overhead_cost;
    const costPerUnit = formData.quantity_to_produce > 0 ? totalCost / formData.quantity_to_produce : 0;

    return {
      material_cost: materialCost,
      total_production_cost: totalCost,
      cost_per_unit: costPerUnit
    };
  };

  const deductMaterialsFromInventory = async (orderId) => {
    try {
      for (const material of materialsConsumption) {
        // Update raw material stock
        const rawMat = rawMaterials.find(rm => rm.id === material.material_id);
        if (rawMat) {
          const newStock = rawMat.current_stock - material.quantity_used;
          await base44.entities.RawMaterial.update(material.material_id, {
            current_stock: newStock
          });

          // Create stock movement record
          await base44.entities.StockMovement.create({
            company_id,
            inventory_id: material.material_id,
            product_id: material.material_id,
            product_name: material.material_name,
            location_id: 'production',
            location_name: 'Production Floor',
            movement_type: 'out',
            quantity: material.quantity_used,
            stock_before: rawMat.current_stock,
            stock_after: newStock,
            reference_type: 'production',
            reference_id: orderId,
            reason: `Production Order ${formData.order_number}`,
            unit_cost: material.cost / material.quantity_used,
            total_value: material.cost,
            performed_by: company_id,
            notes: `Consumed for production order ${formData.order_number}`
          });
        }
      }
    } catch (error) {
      console.error('Error deducting materials:', error);
      throw error;
    }
  };

  const addToFinishedGoodsInventory = async (orderId) => {
    try {
      // Check if inventory record exists
      const existingInventory = await base44.entities.Inventory.filter({
        company_id,
        product_id: formData.product_id,
        location_id: 'warehouse'
      });

      const quantityProduced = formData.quantity_produced || formData.quantity_to_produce;
      const costs = calculateTotalCost();

      if (existingInventory && existingInventory.length > 0) {
        const inv = existingInventory[0];
        const newQuantity = (inv.quantity || 0) + quantityProduced;
        
        await base44.entities.Inventory.update(inv.id, {
          quantity: newQuantity,
          available_quantity: newQuantity - (inv.reserved_quantity || 0),
          unit_cost: costs.cost_per_unit,
          total_value: newQuantity * costs.cost_per_unit
        });
      } else {
        await base44.entities.Inventory.create({
          company_id,
          product_id: formData.product_id,
          product_name: formData.product_name,
          location_id: 'warehouse',
          location_name: 'Main Warehouse',
          quantity: quantityProduced,
          available_quantity: quantityProduced,
          unit_cost: costs.cost_per_unit,
          total_value: quantityProduced * costs.cost_per_unit,
          stock_status: 'in_stock'
        });
      }

      // Create stock movement for finished goods
      await base44.entities.StockMovement.create({
        company_id,
        product_id: formData.product_id,
        product_name: formData.product_name,
        location_id: 'warehouse',
        location_name: 'Main Warehouse',
        movement_type: 'in',
        quantity: quantityProduced,
        reference_type: 'production',
        reference_id: orderId,
        reason: `Production completed - Order ${formData.order_number}`,
        unit_cost: costs.cost_per_unit,
        total_value: quantityProduced * costs.cost_per_unit,
        performed_by: company_id
      });
    } catch (error) {
      console.error('Error adding to inventory:', error);
      throw error;
    }
  };

  const createLotBatch = async (orderId) => {
    try {
      const costs = calculateTotalCost();
      const quantityProduced = formData.quantity_produced || formData.quantity_to_produce;

      const lotNumber = formData.batch_number || `LOT-${Date.now().toString().slice(-8)}`;
      
      await base44.entities.LotBatch.create({
        company_id,
        lot_number: lotNumber,
        product_id: formData.product_id,
        product_name: formData.product_name,
        production_order_id: orderId,
        quantity: quantityProduced,
        quantity_remaining: quantityProduced,
        manufacture_date: formData.actual_end_date || new Date().toISOString().split('T')[0],
        location_id: 'warehouse',
        location_name: 'Main Warehouse',
        cost_per_unit: costs.cost_per_unit,
        status: 'active',
        quality_status: qualityCheck.passed > 0 ? 'passed' : 'pending'
      });

      toast.success(`Γ£à Lot/Batch ${lotNumber} created`);
    } catch (error) {
      console.error('Error creating lot:', error);
      toast.error('Failed to create lot/batch');
    }
  };

  const handleSave = async () => {
    // Validation
    if (!formData.product_id || !formData.bom_id) {
      toast.error('Pilih produk dan BOM terlebih dahulu');
      return;
    }

    if (!formData.planned_start_date || !formData.planned_end_date) {
      toast.error('Tentukan tanggal mulai dan selesai produksi');
      return;
    }

    // Check material availability
    const hasShortage = Object.values(materialAvailability).some(m => !m.available);
    if (hasShortage && !order) {
      const confirmProceed = confirm(
        'Beberapa bahan baku tidak mencukupi. Lanjutkan membuat production order?'
      );
      if (!confirmProceed) return;
    }

    try {
      setIsSaving(true);

      const costs = calculateTotalCost();

      const productionOrderData = {
        company_id,
        ...formData,
        materials_consumed: materialsConsumption,
        total_production_cost: costs.total_production_cost,
        cost_per_unit: costs.cost_per_unit,
        quality_check: qualityCheck
      };

      let savedOrder;

      if (order) {
        // Update existing order
        await base44.entities.ProductionOrder.update(order.id, productionOrderData);
        savedOrder = { ...order, ...productionOrderData };
        toast.success('Γ£à Production Order berhasil diperbarui');

        // If status changed to completed, process inventory
        if (formData.status === 'completed' && order.status !== 'completed') {
          await deductMaterialsFromInventory(order.id);
          await addToFinishedGoodsInventory(order.id);
          await createLotBatch(order.id);
          toast.success('Γ£à Inventory berhasil diupdate');
        }
      } else {
        // Create new order
        savedOrder = await base44.entities.ProductionOrder.create(productionOrderData);
        toast.success('Γ£à Production Order berhasil dibuat');

        // If starting as in_progress or completed, deduct materials immediately
        if (formData.status === 'in_progress' || formData.status === 'completed') {
          await deductMaterialsFromInventory(savedOrder.id);
          toast.success('Γ£à Material berhasil dikonsumsi dari inventory');
        }

        // If completed, add to finished goods
        if (formData.status === 'completed') {
          await addToFinishedGoodsInventory(savedOrder.id);
          await createLotBatch(savedOrder.id);
        }
      }

      if (onSuccess) onSuccess(savedOrder);
    } catch (error) {
      console.error('Error saving production order:', error);
      toast.error('Gagal menyimpan production order: ' + error.message);
    } finally {
      setIsSaving(false);
    }
  };

  const costs = calculateTotalCost();
  const hasShortage = Object.values(materialAvailability).some(m => !m.available);

  return (
    <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-4 overflow-y-auto">
      <div className="bg-gray-900 border border-gray-700 rounded-lg max-w-6xl w-full max-h-[95vh] overflow-y-auto my-8">
        <div className="flex items-center justify-between p-6 border-b border-gray-800 sticky top-0 bg-gray-900 z-10">
          <h2 className="text-xl font-bold text-white">
            {order ? 'Edit Production Order' : 'Buat Production Order Baru'}
          </h2>
          <Button variant="ghost" size="icon" onClick={onClose}>
            <X className="w-5 h-5" />
          </Button>
        </div>

        <div className="p-6 space-y-6">
          {/* Basic Info */}
          <Card className="bg-gray-900/50 border-gray-800">
            <CardHeader>
              <CardTitle className="text-white">Informasi Dasar</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-3 gap-4">
                <div>
                  <Label className="text-gray-300">Order Number</Label>
                  <Input
                    value={formData.order_number}
                    disabled
                    className="bg-gray-800 border-gray-700 text-white"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">BOM / Product *</Label>
                  <Select value={formData.bom_id} onValueChange={handleBOMChange}>
                    <SelectTrigger className="bg-gray-800 border-gray-700 text-white">
                      <SelectValue placeholder="Pilih BOM" />
                    </SelectTrigger>
                    <SelectContent>
                      {boms.map(bom => (
                        <SelectItem key={bom.id} value={bom.id}>
                          {bom.product_name} - {bom.bom_code}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label className="text-gray-300">Quantity to Produce *</Label>
                  <Input
                    type="number"
                    value={formData.quantity_to_produce}
                    onChange={(e) => handleQuantityChange(parseInt(e.target.value))}
                    className="bg-gray-800 border-gray-700 text-white"
                    min="1"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Planned Start Date *</Label>
                  <Input
                    type="date"
                    value={formData.planned_start_date}
                    onChange={(e) => setFormData({ ...formData, planned_start_date: e.target.value })}
                    className="bg-gray-800 border-gray-700 text-white"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Planned End Date *</Label>
                  <Input
                    type="date"
                    value={formData.planned_end_date}
                    onChange={(e) => setFormData({ ...formData, planned_end_date: e.target.value })}
                    className="bg-gray-800 border-gray-700 text-white"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Priority</Label>
                  <Select value={formData.priority} onValueChange={(val) => setFormData({ ...formData, priority: val })}>
                    <SelectTrigger className="bg-gray-800 border-gray-700 text-white">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">Low</SelectItem>
                      <SelectItem value="normal">Normal</SelectItem>
                      <SelectItem value="high">High</SelectItem>
                      <SelectItem value="urgent">Urgent</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label className="text-gray-300">Status</Label>
                  <Select value={formData.status} onValueChange={handleStatusChange}>
                    <SelectTrigger className="bg-gray-800 border-gray-700 text-white">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="planned">Planned</SelectItem>
                      <SelectItem value="in_progress">In Progress</SelectItem>
                      <SelectItem value="completed">Completed</SelectItem>
                      <SelectItem value="cancelled">Cancelled</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label className="text-gray-300">Batch Number</Label>
                  <Input
                    value={formData.batch_number}
                    onChange={(e) => setFormData({ ...formData, batch_number: e.target.value })}
                    placeholder="Auto-generated"
                    className="bg-gray-800 border-gray-700 text-white"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Quantity Produced</Label>
                  <Input
                    type="number"
                    value={formData.quantity_produced}
                    onChange={(e) => setFormData({ ...formData, quantity_produced: parseInt(e.target.value) })}
                    className="bg-gray-800 border-gray-700 text-white"
                    min="0"
                    max={formData.quantity_to_produce}
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Materials Consumption */}
          {materialsConsumption.length > 0 && (
            <Card className={`${hasShortage ? 'bg-red-900/20 border-red-800' : 'bg-gray-900/50 border-gray-800'}`}>
              <CardHeader>
                <CardTitle className="text-white flex items-center gap-2">
                  Materials Consumption
                  {hasShortage && (
                    <AlertCircle className="w-5 h-5 text-red-400" />
                  )}
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  {materialsConsumption.map((mat, idx) => {
                    const availability = materialAvailability[mat.material_id];
                    return (
                      <div 
                        key={idx} 
                        className={`p-3 rounded-lg border ${
                          availability && !availability.available 
                            ? 'bg-red-900/20 border-red-700' 
                            : 'bg-gray-800/50 border-gray-700'
                        }`}
                      >
                        <div className="flex items-center justify-between">
                          <div className="flex-1">
                            <p className="text-white font-medium">{mat.material_name}</p>
                            <p className="text-sm text-gray-400">
                              Needed: {mat.quantity_used} {mat.unit} ├ù Rp {(mat.cost / mat.quantity_used).toLocaleString('id-ID')}
                            </p>
                          </div>
                          <div className="text-right">
                            {availability && (
                              <>
                                {availability.available ? (
                                  <div className="flex items-center gap-2 text-green-400">
                                    <CheckCircle className="w-4 h-4" />
                                    <span className="text-sm">Available: {availability.currentStock}</span>
                                  </div>
                                ) : (
                                  <div className="flex items-center gap-2 text-red-400">
                                    <AlertCircle className="w-4 h-4" />
                                    <span className="text-sm">
                                      Short: {availability.shortage} {mat.unit}
                                    </span>
                                  </div>
                                )}
                              </>
                            )}
                            <p className="text-white font-semibold">
                              Rp {mat.cost.toLocaleString('id-ID')}
                            </p>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </CardContent>
            </Card>
          )}

          {/* Labor & Costs */}
          <Card className="bg-gray-900/50 border-gray-800">
            <CardHeader>
              <CardTitle className="text-white">Labor & Production Costs</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-3 gap-4">
                <div>
                  <Label className="text-gray-300">Actual Labor Hours</Label>
                  <Input
                    type="number"
                    value={formData.labor_hours}
                    onChange={(e) => setFormData({ ...formData, labor_hours: parseFloat(e.target.value) })}
                    className="bg-gray-800 border-gray-700 text-white"
                    step="0.5"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Labor Cost</Label>
                  <Input
                    type="number"
                    value={formData.labor_cost}
                    onChange={(e) => setFormData({ ...formData, labor_cost: parseFloat(e.target.value) })}
                    className="bg-gray-800 border-gray-700 text-white"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Overhead Cost</Label>
                  <Input
                    type="number"
                    value={formData.overhead_cost}
                    onChange={(e) => setFormData({ ...formData, overhead_cost: parseFloat(e.target.value) })}
                    className="bg-gray-800 border-gray-700 text-white"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Actual Start Date</Label>
                  <Input
                    type="date"
                    value={formData.actual_start_date}
                    onChange={(e) => setFormData({ ...formData, actual_start_date: e.target.value })}
                    className="bg-gray-800 border-gray-700 text-white"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Actual End Date</Label>
                  <Input
                    type="date"
                    value={formData.actual_end_date}
                    onChange={(e) => setFormData({ ...formData, actual_end_date: e.target.value })}
                    className="bg-gray-800 border-gray-700 text-white"
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Assign Employees */}
          <Card className="bg-gray-900/50 border-gray-800">
            <CardHeader>
              <CardTitle className="text-white">Assigned Employees</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-2 gap-2">
                {employees.map(emp => (
                  <div key={emp.id} className="flex items-center gap-2">
                    <input
                      type="checkbox"
                      checked={formData.assigned_to.includes(emp.id)}
                      onChange={(e) => {
                        if (e.target.checked) {
                          setFormData({
                            ...formData,
                            assigned_to: [...formData.assigned_to, emp.id]
                          });
                        } else {
                          setFormData({
                            ...formData,
                            assigned_to: formData.assigned_to.filter(id => id !== emp.id)
                          });
                        }
                      }}
                      className="w-4 h-4"
                    />
                    <Label className="text-gray-300 text-sm">{emp.user_name}</Label>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>

          {/* Quality Check */}
          <Card className="bg-gray-900/50 border-gray-800">
            <CardHeader>
              <CardTitle className="text-white">Quality Control</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-4 gap-4">
                <div>
                  <Label className="text-gray-300">Passed (units)</Label>
                  <Input
                    type="number"
                    value={qualityCheck.passed}
                    onChange={(e) => setQualityCheck({ ...qualityCheck, passed: parseInt(e.target.value) })}
                    className="bg-gray-800 border-gray-700 text-white"
                    min="0"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Failed (units)</Label>
                  <Input
                    type="number"
                    value={qualityCheck.failed}
                    onChange={(e) => setQualityCheck({ ...qualityCheck, failed: parseInt(e.target.value) })}
                    className="bg-gray-800 border-gray-700 text-white"
                    min="0"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Inspector</Label>
                  <Input
                    value={qualityCheck.inspector}
                    onChange={(e) => setQualityCheck({ ...qualityCheck, inspector: e.target.value })}
                    className="bg-gray-800 border-gray-700 text-white"
                  />
                </div>

                <div>
                  <Label className="text-gray-300">Inspection Date</Label>
                  <Input
                    type="date"
                    value={qualityCheck.inspection_date}
                    onChange={(e) => setQualityCheck({ ...qualityCheck, inspection_date: e.target.value })}
                    className="bg-gray-800 border-gray-700 text-white"
                  />
                </div>
              </div>

              <div>
                <Label className="text-gray-300">QC Notes</Label>
                <Textarea
                  value={qualityCheck.notes}
                  onChange={(e) => setQualityCheck({ ...qualityCheck, notes: e.target.value })}
                  className="bg-gray-800 border-gray-700 text-white"
                  rows={2}
                />
              </div>
            </CardContent>
          </Card>

          {/* Notes */}
          <Card className="bg-gray-900/50 border-gray-800">
            <CardHeader>
              <CardTitle className="text-white">Production Notes</CardTitle>
            </CardHeader>
            <CardContent>
              <Textarea
                value={formData.notes}
                onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                className="bg-gray-800 border-gray-700 text-white"
                rows={3}
                placeholder="Catatan produksi..."
              />
            </CardContent>
          </Card>

          {/* Cost Summary */}
          <Card className="bg-gradient-to-br from-green-900/30 to-blue-900/30 border-green-700">
            <CardHeader>
              <CardTitle className="text-white flex items-center gap-2">
                <Calculator className="w-5 h-5 text-green-400" />
                Production Cost Summary
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-3 gap-4">
                <div className="p-4 bg-gray-800/50 rounded-lg">
                  <p className="text-sm text-gray-400">Material Cost</p>
                  <p className="text-2xl font-bold text-white">
                    Rp {costs.material_cost.toLocaleString('id-ID')}
                  </p>
                </div>

                <div className="p-4 bg-gray-800/50 rounded-lg">
                  <p className="text-sm text-gray-400">Total Production Cost</p>
                  <p className="text-2xl font-bold text-green-400">
                    Rp {costs.total_production_cost.toLocaleString('id-ID')}
                  </p>
                </div>

                <div className="p-4 bg-gray-800/50 rounded-lg">
                  <p className="text-sm text-gray-400">Cost Per Unit</p>
                  <p className="text-2xl font-bold text-blue-400">
                    Rp {costs.cost_per_unit.toLocaleString('id-ID', { maximumFractionDigits: 0 })}
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Actions */}
          <div className="flex gap-3 justify-end sticky bottom-0 bg-gray-900 pt-4 border-t border-gray-800">
            <Button onClick={onClose} variant="outline" className="border-gray-700">
              Batal
            </Button>
            <Button
              onClick={handleSave}
              disabled={isSaving}
              className="bg-green-600 hover:bg-green-700"
            >
              {isSaving ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  Menyimpan...
                </>
              ) : (
                <>
                  <Save className="w-4 h-4 mr-2" />
                  Simpan Production Order
                </>
              )}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { X, Save, Loader2 } from 'lucide-react';
import { toast } from 'sonner';

export default function RawMaterialForm({ material, suppliers, onSave, onClose }) {
  const [formData, setFormData] = useState({
    material_code: '',
    material_name: '',
    category: 'raw_material',
    unit_of_measure: 'pcs',
    current_stock: 0,
    min_stock: 10,
    max_stock: 1000,
    reorder_point: 20,
    unit_cost: 0,
    supplier_id: '',
    supplier_name: '',
    lead_time_days: 7,
    storage_location: '',
    notes: '',
    is_active: true,
    ...material
  });

  const [isSaving, setIsSaving] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!formData.material_name || !formData.material_code) {
      toast.error('Nama dan kode bahan baku wajib diisi');
      return;
    }

    setIsSaving(true);
    try {
      await onSave(formData);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-4">
      <div className="bg-gray-900 border border-gray-700 rounded-lg max-w-3xl w-full max-h-[90vh] overflow-y-auto">
        <div className="flex items-center justify-between p-6 border-b border-gray-800">
          <h2 className="text-xl font-bold text-white">
            {material ? 'Edit Bahan Baku' : 'Tambah Bahan Baku Baru'}
          </h2>
          <Button variant="ghost" size="icon" onClick={onClose}>
            <X className="w-5 h-5" />
          </Button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label className="text-white">Kode Bahan Baku *</Label>
              <Input
                value={formData.material_code}
                onChange={(e) => setFormData({...formData, material_code: e.target.value})}
                placeholder="SKU-001"
                className="bg-gray-800 border-gray-700 text-white"
                required
              />
            </div>

            <div>
              <Label className="text-white">Nama Bahan Baku *</Label>
              <Input
                value={formData.material_name}
                onChange={(e) => setFormData({...formData, material_name: e.target.value})}
                placeholder="Tepung Terigu"
                className="bg-gray-800 border-gray-700 text-white"
                required
              />
            </div>

            <div>
              <Label className="text-white">Kategori</Label>
              <select
                value={formData.category}
                onChange={(e) => setFormData({...formData, category: e.target.value})}
                className="w-full px-3 py-2 bg-gray-800 border border-gray-700 text-white rounded-md"
              >
                <option value="raw_material">Bahan Baku</option>
                <option value="packaging">Kemasan</option>
                <option value="ingredient">Bahan Tambahan</option>
                <option value="component">Komponen</option>
                <option value="other">Lainnya</option>
              </select>
            </div>

            <div>
              <Label className="text-white">Satuan</Label>
              <Input
                value={formData.unit_of_measure}
                onChange={(e) => setFormData({...formData, unit_of_measure: e.target.value})}
                placeholder="kg, liter, pcs"
                className="bg-gray-800 border-gray-700 text-white"
              />
            </div>

            <div>
              <Label className="text-white">Stok Saat Ini</Label>
              <Input
                type="number"
                value={formData.current_stock}
                onChange={(e) => setFormData({...formData, current_stock: parseFloat(e.target.value)})}
                className="bg-gray-800 border-gray-700 text-white"
              />
            </div>

            <div>
              <Label className="text-white">Stok Minimum</Label>
              <Input
                type="number"
                value={formData.min_stock}
                onChange={(e) => setFormData({...formData, min_stock: parseFloat(e.target.value)})}
                className="bg-gray-800 border-gray-700 text-white"
              />
            </div>

            <div>
              <Label className="text-white">Stok Maximum</Label>
              <Input
                type="number"
                value={formData.max_stock}
                onChange={(e) => setFormData({...formData, max_stock: parseFloat(e.target.value)})}
                className="bg-gray-800 border-gray-700 text-white"
              />
            </div>

            <div>
              <Label className="text-white">Reorder Point</Label>
              <Input
                type="number"
                value={formData.reorder_point}
                onChange={(e) => setFormData({...formData, reorder_point: parseFloat(e.target.value)})}
                className="bg-gray-800 border-gray-700 text-white"
              />
            </div>

            <div>
              <Label className="text-white">Harga Per Unit</Label>
              <Input
                type="number"
                value={formData.unit_cost}
                onChange={(e) => setFormData({...formData, unit_cost: parseFloat(e.target.value)})}
                placeholder="0"
                className="bg-gray-800 border-gray-700 text-white"
              />
            </div>

            <div>
              <Label className="text-white">Lead Time (hari)</Label>
              <Input
                type="number"
                value={formData.lead_time_days}
                onChange={(e) => setFormData({...formData, lead_time_days: parseInt(e.target.value)})}
                className="bg-gray-800 border-gray-700 text-white"
              />
            </div>

            <div>
              <Label className="text-white">Supplier</Label>
              <Input
                value={formData.supplier_name}
                onChange={(e) => setFormData({...formData, supplier_name: e.target.value})}
                placeholder="Nama Supplier"
                className="bg-gray-800 border-gray-700 text-white"
              />
            </div>

            <div>
              <Label className="text-white">Lokasi Penyimpanan</Label>
              <Input
                value={formData.storage_location}
                onChange={(e) => setFormData({...formData, storage_location: e.target.value})}
                placeholder="Gudang A"
                className="bg-gray-800 border-gray-700 text-white"
              />
            </div>
          </div>

          <div>
            <Label className="text-white">Catatan</Label>
            <Textarea
              value={formData.notes}
              onChange={(e) => setFormData({...formData, notes: e.target.value})}
              placeholder="Catatan tambahan..."
              className="bg-gray-800 border-gray-700 text-white"
              rows={3}
            />
          </div>

          <div className="flex items-center gap-2">
            <input
              type="checkbox"
              checked={formData.is_active}
              onChange={(e) => setFormData({...formData, is_active: e.target.checked})}
              className="w-4 h-4"
            />
            <Label className="text-white">Aktif</Label>
          </div>

          <div className="flex items-center justify-end gap-3 pt-4 border-t border-gray-800">
            <Button type="button" variant="outline" onClick={onClose}>
              Batal
            </Button>
            <Button type="submit" disabled={isSaving} className="bg-blue-600 hover:bg-blue-700">
              {isSaving ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  Menyimpan...
                </>
              ) : (
                <>
                  <Save className="w-4 h-4 mr-2" />
                  Simpan
                </>
              )}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Bot, Send, Loader2, Sparkles } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import ReactMarkdown from 'react-markdown';
import { InvokeLLM } from '@/integrations/Core';
import { User } from '@/entities/User';
import { toast } from 'sonner';

const monthlyLimits = {
  free: 300, pro: 1500, business: 3000, advanced: 6000, enterprise: 9000
};

export default function NoteAIAssistant({ user, workspaces, onNoteCreate, onUserUpdate }) {
  const [messages, setMessages] = useState([{
    role: 'assistant',
    content: "Halo! Saya AI asisten catatan. Saya bisa membantu:\n\nΓÇó Membuat catatan dengan riset mendalam\nΓÇó Mencari informasi dari internet\nΓÇó Menyusun catatan terstruktur dan rapi\n\nContoh: *'Buat catatan tentang React Hooks'* atau *'Tulis catatan tentang tips produktivitas'*"
  }]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef(null);

  const monthlyUsage = user?.ai_monthly_usage || 0;
  const monthlyLimit = monthlyLimits[user?.subscription_plan || 'free'];
  const addonQuota = user?.ai_addon_quota || 0;
  const totalQuota = monthlyLimit + addonQuota;
  const canUseAI = monthlyUsage < totalQuota;

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const createNoteFromAI = async (noteData) => {
    try {
      const personalWorkspace = workspaces.find(w => w.is_personal) || workspaces[0];
      if (!personalWorkspace) {
        throw new Error('No workspace found');
      }

      const newNote = {
        title: noteData.title,
        content: noteData.content,
        workspace_id: personalWorkspace.id,
        icon: noteData.icon || '≡ƒô¥'
      };

      const createdNote = await onNoteCreate(newNote);
      return createdNote;
    } catch (error) {
      console.error('Failed to create note:', error);
      throw error;
    }
  };

  const handleSendMessage = async () => {
    if (!input.trim() || isLoading || !canUseAI) return;

    const messageContent = input.trim();
    const newUserMessage = { role: 'user', content: messageContent };
    setMessages(prev => [...prev, newUserMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const shouldResearch = messageContent.toLowerCase().includes('tentang') || 
                           messageContent.toLowerCase().includes('mengenai') ||
                           messageContent.toLowerCase().includes('jelaskan');

      const contextPrompt = `Anda adalah AI asisten yang sangat ahli dalam membuat catatan informatif dan terstruktur. Anda terintegrasi di dalam halaman "Catatan" pada aplikasi produktivitas TODOIT.

Tugas Anda adalah mengubah permintaan pengguna menjadi sebuah catatan yang kaya konten dan rapi.

Permintaan pengguna: "${messageContent}"

**INSTRUKSI PENUH:**
- **Riset Mendalam:** Jika topik membutuhkan informasi eksternal (misal: "catatan tentang AI", "jelaskan tentang snishop"), gunakan kemampuan browsing internet Anda untuk mengumpulkan data yang akurat, relevan, dan terkini.
- **Struktur Konten:** Hasilkan konten dalam format HTML. Gunakan struktur yang logis dengan heading (<h1>, <h2>), paragraf (<p>), daftar (<ul><li>), dan penekanan (<strong>, <em>).
- **Output JSON Ketat:** Anda **HARUS** memberikan output dalam format JSON yang valid. Jangan sertakan teks lain di luar objek JSON.

**Format Output JSON (WAJIB):**
\`\`\`json
{
  "action": "create_note",
  "note": {
    "title": "Judul catatan yang menarik dan sesuai dengan topik permintaan.",
    "content": "Konten catatan yang sangat informatif, mendalam, dan terstruktur dengan baik dalam format HTML. Jangan takut membuat konten yang panjang jika topik kompleks.",
    "icon": "Satu emoji yang paling mewakili topik catatan."
  },
  "message": "Pesan konfirmasi yang ramah kepada pengguna, beritahu mereka bahwa catatan tentang topik tersebut telah berhasil dibuat dan siap dibaca."
}
\`\`\`
`;

      const response = await InvokeLLM({ 
        prompt: contextPrompt,
        add_context_from_internet: shouldResearch
      });
      
      let aiResponse;
      try {
        aiResponse = JSON.parse(response);
      } catch (e) {
        setMessages(prev => [...prev, { 
          role: 'assistant', 
          content: "Maaf, saya tidak dapat memproses permintaan ini. Bisakah Anda jelaskan lebih spesifik catatan yang ingin dibuat?" 
        }]);
        return;
      }

      if (aiResponse.action === 'create_note') {
        try {
          const note = await createNoteFromAI(aiResponse.note);
          setMessages(prev => [...prev, { 
            role: 'assistant', 
            content: `≡ƒô¥ **Catatan berhasil dibuat!**\n\n${aiResponse.message}\n\n${aiResponse.note.icon} **${aiResponse.note.title}**\n\nCatatan telah disimpan dan siap untuk diedit lebih lanjut.` 
          }]);
          toast.success(`Catatan "${aiResponse.note.title}" berhasil dibuat!`);
        } catch (error) {
          setMessages(prev => [...prev, { 
            role: 'assistant', 
            content: `Γ¥î Maaf, gagal membuat catatan: ${error.message}` 
          }]);
        }
      } else {
        setMessages(prev => [...prev, { 
          role: 'assistant', 
          content: aiResponse.message 
        }]);
      }

      // Update AI usage
      const newUsage = (user?.ai_monthly_usage || 0) + 1;
      await User.updateMyUserData({ ai_monthly_usage: newUsage });
      if (onUserUpdate) onUserUpdate({ ...user, ai_monthly_usage: newUsage });

    } catch (error) {
      console.error("Error calling AI:", error);
      toast.error("Terjadi kesalahan saat menghubungi AI.");
      setMessages(prev => [...prev, { role: 'assistant', content: "Maaf, saya mengalami gangguan." }]);
    } finally {
      setIsLoading(false);
    }
  };

  if (!canUseAI) {
    return (
      <Card className="bg-red-50 border-red-200">
        <CardContent className="p-4 text-center">
          <p className="text-red-700">Kuota AI bulanan telah habis.</p>
          <Button size="sm" className="mt-2" onClick={() => window.location.href = '/pricing'}>
            Upgrade Plan
          </Button>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className="bg-gray-800 border-gray-700 text-white">
      <CardHeader className="pb-3">
        <CardTitle className="flex items-center gap-2 text-base">
          <Sparkles className="w-5 h-5 text-purple-400" />
          AI Asisten Catatan
        </CardTitle>
        <p className="text-xs text-gray-400">
          Sisa kuota: {(totalQuota - monthlyUsage).toLocaleString()}
        </p>
      </CardHeader>
      <CardContent className="p-4">
        <div className="h-64 overflow-y-auto mb-4 space-y-3 pr-2 scrollbar-thin scrollbar-track-gray-700 scrollbar-thumb-gray-600">
          <AnimatePresence>
            {messages.map((msg, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                {msg.role === 'assistant' && <Bot className="w-5 h-5 text-purple-400 mt-1 mr-2 flex-shrink-0" />}
                <div className={`max-w-[85%] rounded-lg px-3 py-2 text-sm ${
                  msg.role === 'user' ? 'bg-purple-600' : 'bg-gray-700'
                }`}>
                  <ReactMarkdown className="prose prose-sm prose-invert max-w-none [&>p]:my-0">
                    {msg.content}
                  </ReactMarkdown>
                </div>
              </motion.div>
            ))}
          </AnimatePresence>
          <div ref={messagesEndRef} />
        </div>
        
        <div className="flex gap-2">
          <Textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleSendMessage();
              }
            }}
            placeholder="Jelaskan catatan yang ingin dibuat..."
            className="bg-gray-700 border-gray-600 text-white placeholder-gray-400 resize-none"
            rows={2}
            disabled={isLoading}
          />
          <Button 
            onClick={handleSendMessage} 
            disabled={isLoading || !input.trim()} 
            size="icon"
            className="bg-purple-600 hover:bg-purple-700"
          >
            {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

import { memo, useState } from 'react';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Pin, Archive, Trash2, Tag, MoreVertical } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import { id } from 'date-fns/locale';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import LabelDialog from './LabelDialog';

const NoteItem = memo(({ note, labels, onSelect, onPinToggle, onArchiveToggle, onDelete, onAddLabel, onRemoveLabel }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [showLabelDialog, setShowLabelDialog] = useState(false);

  const handleMenuAction = (e, action) => {
    e.stopPropagation();
    setIsMenuOpen(false);
    action();
  };

  const getFormattedDate = () => {
    try {
      if (!note.updated_date) return 'Baru saja';
      const date = new Date(note.updated_date);
      if (isNaN(date.getTime())) return 'Baru saja';
      return formatDistanceToNow(date, { addSuffix: true, locale: id });
    } catch (error) {
      return 'Baru saja';
    }
  };

  const noteLabels = Array.isArray(note.labels) ? note.labels : [];
  const noteLabelObjects = labels.filter(l => noteLabels.includes(l.id));

  return (
    <>
      <Card 
        onClick={() => onSelect(note)} 
        className="cursor-pointer transition-shadow hover:shadow-lg bg-gray-800 text-white border-gray-700 relative"
      >
        <CardContent className="p-4">
          <div className="absolute top-2 right-2 flex items-center gap-1">
            {note.pinned && <Pin className="w-4 h-4 text-yellow-400 fill-yellow-400" />}
            <DropdownMenu open={isMenuOpen} onOpenChange={setIsMenuOpen}>
              <DropdownMenuTrigger asChild>
                <Button
                  variant="ghost"
                  size="icon"
                  className="h-8 w-8 hover:bg-gray-700"
                  onClick={(e) => e.stopPropagation()}
                >
                  <MoreVertical className="w-4 h-4" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="w-48">
                <DropdownMenuItem onClick={(e) => handleMenuAction(e, () => onPinToggle?.(note.id, !note.pinned))}>
                  <Pin className="w-4 h-4 mr-2" />
                  {note.pinned ? 'Lepas Pin' : 'Pin Catatan'}
                </DropdownMenuItem>
                <DropdownMenuItem onClick={(e) => handleMenuAction(e, () => onArchiveToggle?.(note.id, !note.archived))}>
                  <Archive className="w-4 h-4 mr-2" />
                  {note.archived ? 'Pulihkan' : 'Arsipkan'}
                </DropdownMenuItem>
                <DropdownMenuItem onClick={(e) => {
                  e.stopPropagation();
                  setIsMenuOpen(false);
                  setShowLabelDialog(true);
                }}>
                  <Tag className="w-4 h-4 mr-2" />
                  Kelola Label
                </DropdownMenuItem>
                <DropdownMenuSeparator />
                <DropdownMenuItem 
                  onClick={(e) => handleMenuAction(e, () => onDelete?.(note.id))}
                  className="text-red-600 focus:text-red-600"
                >
                  <Trash2 className="w-4 h-4 mr-2" />
                  Hapus
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>

          <h3 className="font-semibold mb-2 truncate pr-10">{note.title}</h3>
          <div 
            className="text-sm text-gray-300 overflow-hidden max-h-24 note-content-preview line-clamp-3"
            dangerouslySetInnerHTML={{ __html: note.content || '' }} 
          />
          
          {noteLabelObjects.length > 0 && (
            <div className="flex flex-wrap gap-2 mt-4">
              {noteLabelObjects.map((label) => (
                <Badge 
                  key={label.id} 
                  variant="secondary" 
                  className="text-xs"
                  style={{ backgroundColor: label.color || '#9CA3AF', color: '#fff' }}
                >
                  {label.icon} {label.name}
                </Badge>
              ))}
            </div>
          )}
          
          <p className="text-xs text-gray-500 mt-4">
            {getFormattedDate()}
          </p>
        </CardContent>
      </Card>

      <LabelDialog
        open={showLabelDialog}
        onOpenChange={setShowLabelDialog}
        note={note}
        labels={labels}
        onAddLabel={onAddLabel}
        onRemoveLabel={onRemoveLabel}
      />
    </>
  );
});

NoteItem.displayName = 'NoteItem';

export default NoteItem;

import { useState, useEffect, useRef, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Input } from '@/components/ui/input';
import { toast } from 'sonner';

export default function NoteTaker({ workspaces = [], user, onNoteCreated }) {
  const [isFocused, setIsFocused] = useState(false);
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [selectedWorkspace, setSelectedWorkspace] = useState('');
  const wrapperRef = useRef(null);

  useEffect(() => {
    const personalWorkspace = workspaces.find((w) => w.is_personal);
    if (personalWorkspace) {
      setSelectedWorkspace(personalWorkspace.id);
    } else if (workspaces.length > 0) {
      setSelectedWorkspace(workspaces[0].id);
    }
  }, [workspaces]);

  const handleSaveAndOpen = useCallback(() => {
    if (!title.trim() && !content.trim()) return;

    if (!selectedWorkspace) {
      toast.error("Silakan pilih workspace terlebih dahulu.");
      return;
    }

    // The onNoteCreated prop will now handle the creation and navigation
    onNoteCreated({
      title: title || "Tanpa Judul",
      content: content,
      workspace_id: selectedWorkspace
    });

    // Reset fields after initiating creation
    setTitle('');
    setContent('');
    setIsFocused(false);
  }, [title, content, selectedWorkspace, onNoteCreated]);

  const handleClickOutside = useCallback((event) => {
    if (wrapperRef.current && !wrapperRef.current.contains(event.target)) {
      if (title || content) {
        handleSaveAndOpen();
      }
      setIsFocused(false);
    }
  }, [title, content, handleSaveAndOpen]);

  useEffect(() => {
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [handleClickOutside]);

  return (
    <div
      ref={wrapperRef}
      className="max-w-xl mx-auto shadow-lg rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 transition-all duration-300">

      <div className="pt-4 pr-4 pb-4 pl-4">
        {isFocused &&
        <Input
          placeholder="Judul"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          className="text-lg font-semibold border-none focus:ring-0 shadow-none px-2 mb-2 bg-transparent" />

        }
        <Textarea
          placeholder="Buat catatan..."
          value={content}
          onChange={(e) => setContent(e.target.value)}
          onFocus={() => setIsFocused(true)}
          className="border-none focus:ring-0 shadow-none px-2 resize-none bg-transparent"
          rows={isFocused ? 3 : 1} />

        {isFocused &&
        <div className="flex justify-between items-center mt-4">
            <select
            value={selectedWorkspace}
            onChange={(e) => setSelectedWorkspace(e.target.value)} className="bg-slate-800 px-2 py-1 text-sm dark:bg-gray-700 border-none rounded-md focus:ring-2 focus:ring-blue-500">


              {workspaces.map((ws) =>
            <option key={ws.id} value={ws.id}>{ws.icon} {ws.name}</option>
            )}
            </select>
            <Button onClick={handleSaveAndOpen} size="sm">Buat & Buka</Button>
          </div>
        }
      </div>
    </div>);

}

import { useState, useEffect, useCallback, useRef } from 'react';
import { base44 } from '@/api/base44Client';
import { offlineStorage } from './OfflineStorage';
import { toast } from 'sonner';

/**
 * OfflineManager - Background service untuk manage offline/online sync
 * - Deteksi online/offline status
 * - Auto-sync saat online kembali
 * - Maintain company context saat offline
 * - Conflict resolution
 */

export default function OfflineManager({ user, selectedCompany, onStatusChange }) {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [isSyncing, setIsSyncing] = useState(false);
  const [pendingCount, setPendingCount] = useState(0);
  const syncIntervalRef = useRef(null);
  const lastSyncRef = useRef(0);
  const companyContextRef = useRef(selectedCompany);

  // Γ£à UPDATE company context ref when it changes
  useEffect(() => {
