  }, [selectedCompany]);

  // Γ£à MONITOR ONLINE/OFFLINE STATUS
  useEffect(() => {
    const handleOnline = () => {
      console.log('');
      console.log('≡ƒîÉ ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
      console.log('Γ£à INTERNET CONNECTION RESTORED!');
      console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
      console.log('');
      
      setIsOnline(true);
      
      toast.success('≡ƒîÉ Online!', {
        description: 'Koneksi internet tersambung kembali. Memulai sinkronisasi...',
        duration: 3000
      });

      // Γ£à Trigger sync immediately
      setTimeout(() => {
        syncOfflineData();
      }, 1000);
    };

    const handleOffline = () => {
      console.log('');
      console.log('≡ƒô╡ ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
      console.log('ΓÜá∩╕Å INTERNET CONNECTION LOST!');
      console.log('≡ƒôï Current context:', companyContextRef.current ? `Company: ${companyContextRef.current.name}` : 'Personal');
      console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
      console.log('');
      
      setIsOnline(false);
      
      toast.warning('≡ƒô╡ Mode Offline Aktif', {
        description: 'Koneksi terputus. Semua perubahan akan disimpan dan disinkronkan saat online.',
        duration: 5000
      });
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    // Γ£à Check initial status
    if (navigator.onLine) {
      console.log('≡ƒîÉ Initial status: ONLINE');
    } else {
      console.log('≡ƒô╡ Initial status: OFFLINE');
    }

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Γ£à UPDATE PENDING COUNT
  const updatePendingCount = useCallback(async () => {
    try {
      const queue = await offlineStorage.getSyncQueue();
      setPendingCount(queue.length);
      
      if (onStatusChange) {
        onStatusChange({ isOnline, pendingCount: queue.length, isSyncing });
      }
    } catch (error) {
      console.error('Failed to update pending count:', error);
    }
  }, [isOnline, isSyncing, onStatusChange]);

  // Γ£à SYNC OFFLINE DATA TO SERVER
  const syncOfflineData = useCallback(async () => {
    if (!isOnline || isSyncing) {
      console.log('ΓÅ¡∩╕Å Skipping sync (offline or already syncing)');
      return;
    }

    // Γ£à Rate limiting - max 1 sync per 5 seconds
    const now = Date.now();
    if (now - lastSyncRef.current < 5000) {
      console.log('ΓÅ│ Sync rate limit - wait 5 seconds');
      return;
    }
    lastSyncRef.current = now;

    try {
      setIsSyncing(true);

      console.log('');
      console.log('≡ƒöä ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
      console.log('Γ¼å∩╕Å STARTING OFFLINE DATA SYNC');
      console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
      console.log('');

      const queue = await offlineStorage.getSyncQueue();

      if (queue.length === 0) {
        console.log('Γ£à No pending operations to sync');
        setIsSyncing(false);
        return;
      }

      console.log(`≡ƒôï Found ${queue.length} pending operations`);

      let successCount = 0;
      let failCount = 0;

      for (const item of queue) {
        try {
          console.log('');
          console.log(`≡ƒöä Syncing: ${item.operation} ${item.entity} (ID: ${item.queueId})`);

          const entitySDK = base44.entities[item.entity];

          if (!entitySDK) {
            console.error(`Γ¥î Entity SDK not found: ${item.entity}`);
            await offlineStorage.updateSyncQueueItem(item.queueId, { 
              status: 'failed', 
              error: 'Entity SDK not found' 
            });
            failCount++;
            continue;
          }

          let result;

          switch (item.operation) {
            case 'create':
              console.log('   - Creating new record...');
              result = await entitySDK.create(item.data);
              
              // Γ£à Update local with server ID
              if (result && result.id) {
                await offlineStorage.saveToLocal(item.entity, result);
                
                // Γ£à Delete temp offline record
                if (item.originalId && item.originalId.startsWith('offline_')) {
                  await offlineStorage.deleteFromLocal(item.entity, item.originalId);
                }
              }
              break;

            case 'update':
              console.log('   - Updating record:', item.originalId);
              
              // Γ£à Check if record still exists on server
              try {
                await entitySDK.get(item.originalId);
                result = await entitySDK.update(item.originalId, item.data);
              } catch (error) {
                if (error?.message?.includes('not found') || error?.message?.includes('404')) {
                  // Record deleted on server - create new one
                  console.log('   - Record not found, creating new instead');
                  result = await entitySDK.create(item.data);
                } else {
                  throw error;
                }
              }
              
              // Γ£à Update local cache
              if (result) {
                await offlineStorage.saveToLocal(item.entity, result);
              }
              break;

            case 'delete':
              console.log('   - Deleting record:', item.originalId);
              
              try {
                await entitySDK.delete(item.originalId);
              } catch (error) {
                // If already deleted, that's ok
                if (!error?.message?.includes('not found')) {
                  throw error;
                }
              }
              
              // Γ£à Delete from local
              await offlineStorage.deleteFromLocal(item.entity, item.originalId);
              break;

            default:
              console.error('Γ¥î Unknown operation:', item.operation);
              continue;
          }

          // Γ£à Remove from sync queue
          await offlineStorage.deleteSyncQueueItem(item.queueId);
          
          console.log(`Γ£à ${item.operation} ${item.entity} synced successfully`);
          successCount++;

          // Γ£à Small delay to prevent rate limiting
          await new Promise(resolve => setTimeout(resolve, 200));

        } catch (error) {
          console.error(`Γ¥î Failed to sync ${item.operation} ${item.entity}:`, error);

          // Γ£à Update retry count
          const newRetryCount = (item.retryCount || 0) + 1;

          if (newRetryCount >= 3) {
            // Γ£à Mark as failed after 3 retries
            await offlineStorage.updateSyncQueueItem(item.queueId, {
              status: 'failed',
              error: error.message,
              retryCount: newRetryCount
            });
            failCount++;
          } else {
            // Γ£à Retry later
            await offlineStorage.updateSyncQueueItem(item.queueId, {
              retryCount: newRetryCount,
              lastError: error.message
            });
          }
        }
      }

      console.log('');
      console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
      console.log('Γ£à SYNC COMPLETE!');
      console.log(`   - Success: ${successCount}`);
      console.log(`   - Failed: ${failCount}`);
      console.log('ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ');
      console.log('');

      if (successCount > 0) {
        toast.success(`Γ£à ${successCount} perubahan berhasil disinkronkan!`, {
          duration: 3000
        });

        // Γ£à Trigger global refresh
        window.dispatchEvent(new Event('offlineSyncComplete'));
        
        // Γ£à Force reload pages that use synced data
        window.dispatchEvent(new Event('forceReloadTasks'));
        window.dispatchEvent(new Event('forceReloadNotes'));
        
        // Γ£à Broadcast untuk finance
        const channel = new BroadcastChannel('snishop_finance_updates');
        channel.postMessage({
          type: 'SYNC_COMPLETE',
          timestamp: Date.now()
        });
        channel.close();
      }

      if (failCount > 0) {
        toast.error(`ΓÜá∩╕Å ${failCount} perubahan gagal disinkronkan. Akan dicoba lagi nanti.`, {
          duration: 5000
        });
      }

    } catch (error) {
      console.error('Γ¥î Sync process error:', error);
    } finally {
      setIsSyncing(false);
      updatePendingCount();
    }
  }, [isOnline, isSyncing, updatePendingCount]);

  // Γ£à PERIODIC SYNC CHECK
  useEffect(() => {
    if (!user) return;

    updatePendingCount();

    if (isOnline) {
      // Γ£à Check and sync every 15 seconds when online
      syncIntervalRef.current = setInterval(() => {
        syncOfflineData();
      }, 15000);

      // Γ£à Immediate sync when coming online
      syncOfflineData();
    }

    return () => {
      if (syncIntervalRef.current) {
        clearInterval(syncIntervalRef.current);
      }
    };
  }, [isOnline, user, syncOfflineData, updatePendingCount]);

  // Γ£à LISTEN FOR MANUAL SYNC TRIGGER
  useEffect(() => {
    const handleManualSync = () => {
      console.log('≡ƒöä Manual sync triggered');
      syncOfflineData();
    };

    window.addEventListener('triggerOfflineSync', handleManualSync);

    return () => {
      window.removeEventListener('triggerOfflineSync', handleManualSync);
    };
  }, [syncOfflineData]);

  // Γ£à This is a background service - no UI
  return null;
}

