  getBluetoothPrinterStatus
} from '@/components/pos/BluetoothPrinter';

export default function BluetoothPrinterManager({ company, user, onConnectionChange }) {
  const [isScanning, setIsScanning] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [printerStatus, setPrinterStatus] = useState({ connected: false, deviceName: null });
  const [isPrinting, setIsPrinting] = useState(false);
  const [settings, setSettings] = useState({
    paper_width: '80mm',
    encoding: 'UTF-8',
    auto_cut: true,
    beep_on_print: false,
    auto_reconnect: true,
    print_logo: false,
    // Γ£à REMOVED: header_text and footer_text - now managed in Company Settings ΓåÆ Struk/Receipt
    font_size: 'normal'
  });
  const [savedSettings, setSavedSettings] = useState([]);
  const loadAttemptRef = useRef(0);

  useEffect(() => {
    // Γ£à DELAYED LOAD untuk menghindari rate limit
    const timer = setTimeout(() => {
      loadSavedSettings();
    }, 1000); // Delay 1 detik

    // Γ£à CHECK STATUS SAAT MOUNT
    const status = getBluetoothPrinterStatus();
    setPrinterStatus(status);
    if (onConnectionChange) {
      onConnectionChange(status);
    }

    // Γ£à TRY AUTO-RECONNECT ON MOUNT
    setTimeout(async () => {
      try {
        const { autoReconnectPrinter } = await import('@/components/pos/BluetoothPrinter');
        const result = await autoReconnectPrinter();

        if (result && result.success) {
          const newStatus = getBluetoothPrinterStatus();
          setPrinterStatus(newStatus);
          if (onConnectionChange) {
            onConnectionChange(newStatus);
          }

          toast.success(`≡ƒÄë Auto-reconnect berhasil!\n\n${result.deviceName} siap print!`, {
            duration: 5000
          });
        }
      } catch (e) {
        console.log('Auto-reconnect not available or failed:', e);
      }
    }, 2000); // Try auto-reconnect 2s after mount

    // Γ£à AUTO-CHECK SETIAP 5 DETIK (lebih lama untuk hemat API calls)
    const statusInterval = setInterval(() => {
      const currentStatus = getBluetoothPrinterStatus();
      setPrinterStatus(currentStatus);
      if (onConnectionChange) {
        onConnectionChange(currentStatus);
      }
    }, 5000); // Changed from 3000 to 5000

    return () => {
      clearTimeout(timer);
      clearInterval(statusInterval);
    };
  }, [onConnectionChange]);

  // Γ£à IMPROVED loadSavedSettings dengan error handling & retry
  const loadSavedSettings = async (retryCount = 0) => {
    try {
      loadAttemptRef.current++;

      // Max 2 retry attempts
      if (retryCount > 2) {
        console.log('ΓÜá∩╕Å Max retry reached, using empty settings');
        setSavedSettings([]);
        return;
      }

      // Γ£à GUNAKAN CACHED REQUEST untuk menghindari rate limit
      const data = await cachedRequest('PrinterSettings', 'filter', {
        user_id: user.id,
        company_id: company?.id || null
      });

      setSavedSettings(data || []);

      const defaultSetting = data?.find(s => s.is_default);
      if (defaultSetting) {
        setSettings({
          paper_width: defaultSetting.paper_width || '80mm',
          encoding: defaultSetting.encoding || 'UTF-8',
          auto_cut: defaultSetting.auto_cut !== false,
          beep_on_print: defaultSetting.beep_on_print || false,
          auto_reconnect: defaultSetting.auto_reconnect !== false,
          print_logo: defaultSetting.print_logo || false,
          // Γ£à REMOVED: header_text and footer_text - now managed in Company Settings ΓåÆ Struk/Receipt
          font_size: defaultSetting.font_size || 'normal'
        });
      }

      console.log(`Γ£à Loaded ${data?.length || 0} printer settings`);

    } catch (error) {
      console.error('Error loading settings:', error);

      // Γ£à HANDLE SPECIFIC ERRORS
      const errorMsg = error?.message || String(error);

      if (errorMsg.includes('Rate limit') || errorMsg.includes('429')) {
        console.log(`ΓÜá∩╕Å Rate limit hit, retry ${retryCount + 1}/3 in ${(retryCount + 1) * 2} seconds...`);

        // Exponential backoff retry
        setTimeout(() => {
          loadSavedSettings(retryCount + 1);
        }, (retryCount + 1) * 2000); // 2s, 4s, 6s

      } else if (errorMsg.includes('Network')) {
        console.log(`ΓÜá∩╕Å Network error, retry ${retryCount + 1}/3 in ${(retryCount + 1) * 3} seconds...`);

        setTimeout(() => {
          loadSavedSettings(retryCount + 1);
        }, (retryCount + 1) * 3000); // 3s, 6s, 9s

      } else {
        // Other errors - use empty settings
        console.log('ΓÜá∩╕Å Unknown error, using empty settings');
        setSavedSettings([]);
      }
    }
  };

  const handleConnect = async () => {
    setIsConnecting(true);
    setIsScanning(true);

    try {
      // Γ£à CONNECT PRINTER
      const result = await connectBluetoothPrinter();

      const status = getBluetoothPrinterStatus();
      setPrinterStatus(status);

      // Γ£à NOTIFY PARENT COMPONENT
      if (onConnectionChange) {
        onConnectionChange(status);
      }

      // Γ£à SAVE SETTINGS dengan delay untuk avoid rate limit
      setTimeout(async () => {
        try {
          await saveDeviceSettings(result.deviceId, result.deviceName);
        } catch (e) {
          console.error('Failed to save settings:', e);
          // Don't show error to user, settings will be saved next time
        }
      }, 2000);

      toast.success(`≡ƒÄë Printer terhubung!\n\nΓ£à Semua transaksi akan otomatis print ke ${result.deviceName}`, {
        duration: 5000
      });

    } catch (error) {
      if (error.message !== 'CANCELLED') {
        toast.error(error.message, { duration: 5000 });
      }
    } finally {
      setIsConnecting(false);
      setIsScanning(false);
    }
  };

  const handleDisconnect = async () => {
    try {
      await disconnectBluetoothPrinter();

      const status = { connected: false, deviceName: null };
      setPrinterStatus(status);

      if (onConnectionChange) {
        onConnectionChange(status);
      }

      toast.success('Γ£à Printer disconnected');
    } catch (error) {
      toast.error('Gagal disconnect');
    }
  };

  const handleTestPrint = async () => {
    setIsPrinting(true);
    try {
      await testBluetoothPrinter();
      toast.success('Γ£à Test print berhasil!');
    } catch (error) {
      toast.error(error.message);
    } finally {
      setIsPrinting(false);
    }
  };

  // Γ£à IMPROVED saveDeviceSettings dengan error handling
  const saveDeviceSettings = async (deviceId, deviceName) => {
    try {
      const settingData = {
        company_id: company?.id || null,
        user_id: user.id,
        printer_name: deviceName || 'Bluetooth Printer',
        device_id: deviceId,
        device_name: deviceName || 'Unknown',
        paper_width: settings.paper_width,
        encoding: settings.encoding,
        auto_cut: settings.auto_cut,
        beep_on_print: settings.beep_on_print,
        auto_reconnect: settings.auto_reconnect,
        print_logo: settings.print_logo,
        // Γ£à REMOVED: header_text and footer_text - now managed in Company Settings ΓåÆ Struk/Receipt
        font_size: settings.font_size,
        last_connected: new Date().toISOString(),
        connection_count: 1,
        is_default: true
      };

      // Γ£à CHECK EXISTING dengan delay
      await new Promise(resolve => setTimeout(resolve, 500));

      const existing = await cachedRequest('PrinterSettings', 'filter', {
        user_id: user.id,
        company_id: company?.id || null,
        device_id: deviceId
      }, { skipCache: true });

      // Γ£à SAVE dengan delay
      await new Promise(resolve => setTimeout(resolve, 500));

      if (existing && existing.length > 0) {
        await base44.entities.PrinterSettings.update(existing[0].id, {
          ...settingData,
          connection_count: (existing[0].connection_count || 0) + 1
        });
      } else {
        await base44.entities.PrinterSettings.create(settingData);
      }

      // Γ£à INVALIDATE CACHE
      invalidateCache(/PrinterSettings/);

      // Γ£à RELOAD dengan delay
      setTimeout(() => {
        loadSavedSettings();
      }, 1000);

    } catch (error) {
      console.error('Error saving settings:', error);
      // Don't throw - just log
    }
  };

  const handleSaveSettings = async () => {
    try {
      if (!printerStatus.connected) {
        toast.error('Γ¥î Connect printer dulu sebelum save settings');
        return;
      }

      const currentStatus = getBluetoothPrinterStatus();

      if (!currentStatus.connected) {
        toast.error('Γ¥î Printer tidak terhubung');
        return;
      }

      const settingData = {
        company_id: company?.id || null,
        user_id: user.id,
        printer_name: currentStatus.deviceName || 'Bluetooth Printer',
        device_id: currentStatus.deviceId || 'unknown',
        device_name: currentStatus.deviceName || 'Unknown',
        ...settings,
        last_connected: new Date().toISOString(),
        is_default: true
      };

      // Γ£à DELAY sebelum query untuk avoid rate limit
      await new Promise(resolve => setTimeout(resolve, 500));

      const existing = await cachedRequest('PrinterSettings', 'filter', {
        user_id: user.id,
        company_id: company?.id || null,
        is_default: true
      }, { skipCache: true });

      // Γ£à DELAY sebelum save
      await new Promise(resolve => setTimeout(resolve, 500));

      if (existing && existing.length > 0) {
        await base44.entities.PrinterSettings.update(existing[0].id, settingData);
      } else {
        await base44.entities.PrinterSettings.create(settingData);
      }

      // Γ£à INVALIDATE CACHE
      invalidateCache(/PrinterSettings/);

      toast.success('Γ£à Pengaturan tersimpan & sync ke Kasir!');

      // Γ£à RELOAD dengan delay
      setTimeout(() => {
        loadSavedSettings();
      }, 1000);

    } catch (error) {
      console.error('Save error:', error);

      const errorMsg = error?.message || String(error);

      if (errorMsg.includes('Rate limit')) {
        toast.error('ΓÜá∩╕Å Terlalu banyak request. Tunggu sebentar dan coba lagi.', {
          duration: 3000
        });
      } else {
        toast.error('Γ¥î Gagal menyimpan. Coba lagi dalam beberapa detik.', {
          duration: 3000
        });
      }
    }
  };

  return (
    <div className="space-y-6">
      {/* Γ£à PERSISTENT CONNECTION BANNER */}
      {printerStatus.connected && (
        <div className="p-4 bg-gradient-to-r from-green-900/40 to-blue-900/40 border-2 border-green-500 rounded-xl">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-green-600 rounded-full animate-pulse">
              <Zap className="w-8 h-8 text-white" />
            </div>
            <div className="flex-1">
              <p className="text-white font-bold text-lg">≡ƒöÆ Koneksi PERSISTENT Aktif!</p>
              <p className="text-sm text-gray-300 mt-1">
                <strong>{printerStatus.deviceName}</strong>
              </p>
              <div className="mt-2 space-y-1 text-xs text-green-300">
                <p>Γ£à Tetap terhubung walaupun:</p>
                <p className="ml-4">ΓÇó Pindah menu / page</p>
                <p className="ml-4">ΓÇó Refresh halaman</p>
                <p className="ml-4">ΓÇó Close/open browser</p>
                <p className="mt-2 font-semibold text-yellow-300">≡ƒöä Auto-reconnect AKTIF!</p>
              </div>
            </div>
            <Button
              onClick={handleTestPrint}
              disabled={isPrinting}
              className="bg-green-600 hover:bg-green-700 px-6 py-6"
            >
              {isPrinting ? (
                <Loader2 className="w-5 h-5 animate-spin" />
              ) : (
                <>
                  <Printer className="w-5 h-5 mr-2" />
                  <span className="font-semibold">Test Print</span>
                </>
              )}
            </Button>
          </div>
        </div>
      )}

      <Card className="bg-gray-900 border-gray-700">
        <CardHeader>
          <CardTitle className="text-white flex items-center gap-2">
            {printerStatus.connected ? (
              <>
                <BluetoothConnected className="w-5 h-5 text-green-400 animate-pulse" />
                Terhubung & Siap Print
              </>
            ) : (
              <>
                <Bluetooth className="w-5 h-5 text-gray-400" />
                Belum Terhubung
              </>
            )}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          {printerStatus.connected ? (
            <div className="p-4 bg-gray-800 rounded-lg border-2 border-green-500">
              <div className="flex items-center justify-between mb-3">
                <div className="flex items-center gap-3">
                  <Printer className="w-8 h-8 text-green-400" />
                  <div>
                    <p className="font-semibold text-white text-lg">{printerStatus.deviceName}</p>
                    <p className="text-xs text-gray-400">Device ID: {printerStatus.deviceId || 'N/A'}</p>
                  </div>
                </div>
                <Badge className="bg-green-600 text-white px-3 py-1">
                  <Wifi className="w-3 h-3 mr-1" />
                  Connected
                </Badge>
              </div>

              <div className="flex gap-2 flex-wrap">
                <Button
                  onClick={handleDisconnect}
                  variant="outline"
                  className="border-red-600 text-red-400 hover:bg-red-600/10 flex-1 min-h-[48px]"
                >
                  <X className="w-4 h-4 mr-2" />
                  Disconnect
                </Button>
                <Button
                  onClick={handleTestPrint}
                  disabled={isPrinting}
                  className="bg-green-600 hover:bg-green-700 flex-1 min-h-[48px]"
                >
                  {isPrinting ? (
                    <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Printing...</>
                  ) : (
                    <><Printer className="w-4 h-4 mr-2" /> Test Print</>
                  )}
                </Button>
              </div>

              <div className="mt-3 p-3 bg-green-900/20 border border-green-700 rounded">
                <p className="text-xs text-green-300 font-semibold flex items-center gap-2">
                  <CheckCircle className="w-4 h-4" />
                  PERSISTENT CONNECTION AKTIF
                </p>
                <p className="text-xs text-gray-300 mt-2">
                  ΓÇó Tidak perlu connect ulang<br />
                  ΓÇó Print otomatis saat transaksi<br />
                  ΓÇó Tetap terhubung selama tidak disconnect
                </p>
              </div>
            </div>
          ) : (
            <div className="space-y-4">
              <Button
                onClick={handleConnect}
                disabled={isConnecting || isScanning}
                className="w-full bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 py-8 text-lg font-semibold shadow-lg"
              >
                {isScanning || isConnecting ? (
                  <>
                    <BluetoothSearching className="w-6 h-6 mr-3 animate-spin" />
                    <span>{isScanning ? 'Scanning...' : 'Connecting...'}</span>
                  </>
                ) : (
                  <>
                    <Bluetooth className="w-6 h-6 mr-3" />
                    <span>≡ƒöì Scan & Connect Printer</span>
                  </>
                )}
              </Button>

              <div className="p-5 bg-gradient-to-r from-green-900/30 to-blue-900/30 border-2 border-green-600 rounded-xl">
                <p className="text-base text-green-300 font-bold mb-4 flex items-center gap-2">
                  <Zap className="w-5 h-5" />
                  SETUP SEKALI - PRINT SELAMANYA!
                </p>
                <div className="text-sm text-gray-200 space-y-2 mb-4">
                  <p className="font-semibold">Γ£à CARA KERJA SISTEM:</p>
                  <ul className="space-y-1 ml-4">
                    <li>ΓÇó Setup printer SEKALI saja</li>
                    <li>ΓÇó Koneksi TETAP TERHUBUNG selama tidak disconnect</li>
                    <li>ΓÇó Setiap transaksi OTOMATIS print</li>
                    <li>ΓÇó TIDAK PERLU reconnect setiap transaksi!</li>
                    <li>ΓÇó Driver auto-install untuk semua printer thermal</li>
                  </ul>
                </div>
                <ol className="text-sm text-gray-200 space-y-3 list-decimal list-inside">
                  <li className="font-semibold">Γ£à Nyalakan printer thermal Anda</li>
                  <li className="font-semibold">Γ£à Pastikan Bluetooth HP AKTIF di Settings</li>
                  <li className="font-semibold">Γ£à Tekan tombol BT printer 3-5 detik (lampu KEDIP)</li>
                  <li className="font-semibold">Γ£à Klik tombol "Scan & Connect Printer"</li>
                  <li className="font-semibold text-yellow-300">ΓÜá∩╕Å Popup browser muncul ΓåÆ PILIH printer ΓåÆ JANGAN cancel!</li>
                  <li className="font-semibold">Γ£à Sistem auto-detect driver & install...</li>
                  <li className="font-semibold text-green-300">Γ£à Driver installed! Printer terhubung!</li>
                  <li className="font-semibold text-green-300">Γ£à SELESAI! Sekarang bisa print otomatis! ≡ƒÄë</li>
                </ol>
              </div>

              <div className="p-4 bg-yellow-900/30 border-2 border-yellow-600 rounded-lg">
                <p className="text-sm text-yellow-300 font-bold mb-3 flex items-center gap-2">
                  <AlertCircle className="w-5 h-5" />
                  ΓÜá∩╕Å PENTING - BACA INI!
                </p>
                <ul className="text-xs text-gray-200 space-y-2">
                  <li className="font-semibold">ΓÇó Scan akan tampilkan SEMUA device Bluetooth</li>
                  <li className="font-semibold">ΓÇó Pilih printer Anda (JK-xxxx, Zijiang, RPP, dll)</li>
                  <li className="font-semibold">ΓÇó HARUS pakai Chrome browser Android/Desktop</li>
                  <li className="font-semibold">ΓÇó JANGAN cancel popup! Pilih printer dari list!</li>
                  <li className="font-semibold">ΓÇó Koneksi PERSISTEN - tidak perlu connect ulang!</li>
                  <li className="font-semibold">ΓÇó Jarak maksimal 5 meter dari HP ke printer</li>
                </ul>
              </div>

              <div className="p-4 bg-red-900/30 border border-red-600 rounded-lg">
                <p className="text-sm text-red-300 font-bold mb-2">≡ƒÜ½ TROUBLESHOOTING:</p>
                <ul className="text-xs text-gray-200 space-y-1">
                  <li>ΓÇó <strong>Popup kosong:</strong> Pastikan printer ON & mode pairing (lampu kedip)</li>
                  <li>ΓÇó <strong>Connect gagal:</strong> Restart printer & scan ulang</li>
                  <li>ΓÇó <strong>Print gagal:</strong> Check printer status di atas</li>
                  <li>ΓÇó <strong>Disconnect sendiri:</strong> Restart printer & reconnect sekali</li>
                </ul>
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Settings Card */}
      <Card className="bg-gray-900 border-gray-700">
        <CardHeader>
          <CardTitle className="text-white flex items-center gap-2">
            <SettingsIcon className="w-5 h-5" />
            Pengaturan Printer
          </CardTitle>
          <p className="text-xs text-gray-400 mt-1">
            Settings ini berlaku untuk Kasir & Company Settings
          </p>
        </CardHeader>
        <CardContent className="space-y-4">
          <div>
            <Label className="text-gray-300">Lebar Kertas</Label>
            <select
              value={settings.paper_width}
              onChange={(e) => setSettings({ ...settings, paper_width: e.target.value })}
              className="w-full mt-2 px-3 py-2 bg-gray-800 border border-gray-700 text-white rounded-lg"
            >
              <option value="58mm">58mm (Mini)</option>
              <option value="80mm">80mm (Standard)</option>
            </select>
          </div>

          {/* Γ£à REMOVED: Header Struk and Footer Struk inputs */}
          {/* These are now managed in Company Settings ΓåÆ Struk/Receipt tab */}
          <div className="p-3 bg-yellow-900/20 border border-yellow-600 rounded-lg">
            <p className="text-xs text-yellow-300 font-semibold">
              ΓÜá∩╕Å Pengaturan Header & Footer Struk ada di tab <strong>"Struk/Receipt"</strong>
            </p>
            <p className="text-xs text-gray-400 mt-1">
              Klik tab Struk/Receipt di atas untuk mengatur teks Header, Footer, Logo, dll.
            </p>
          </div>

          <div className="space-y-3">
            <div className="flex items-center justify-between p-3 bg-gray-800 rounded-lg">
              <Label className="text-gray-300">Auto Cut Paper</Label>
              <Switch
                checked={settings.auto_cut}
                onCheckedChange={(checked) => setSettings({ ...settings, auto_cut: checked })}
              />
            </div>

            <div className="flex items-center justify-between p-3 bg-gray-800 rounded-lg">
              <Label className="text-gray-300">Beep Sound</Label>
              <Switch
                checked={settings.beep_on_print}
                onCheckedChange={(checked) => setSettings({ ...settings, beep_on_print: checked })}
              />
            </div>

            <div className="flex items-center justify-between p-3 bg-gray-800 rounded-lg">
              <Label className="text-gray-300">Auto Reconnect</Label>
              <Switch
                checked={settings.auto_reconnect}
                onCheckedChange={(checked) => setSettings({ ...settings, auto_reconnect: checked })}
              />
            </div>
          </div>

          <Button
            onClick={handleSaveSettings}
            className="w-full bg-green-600 hover:bg-green-700 py-6"
            disabled={!printerStatus.connected}
          >
            <Save className="w-4 h-4 mr-2" />
            Simpan Pengaturan
          </Button>

          <div className="p-3 bg-blue-900/20 border border-blue-700 rounded-lg">
            <p className="text-xs text-blue-300 font-semibold">
              ≡ƒÆí Settings ini otomatis sync antara Kasir & Company Settings!
            </p>
          </div>
        </CardContent>
      </Card>

      {/* Saved Printers */}
      {savedSettings.length > 0 && (
        <Card className="bg-gray-900 border-gray-700">
          <CardHeader>
            <CardTitle className="text-white flex items-center gap-2">
              <FileText className="w-5 h-5" />
              Printer Tersimpan
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              {savedSettings.map((setting) => (
                <div
                  key={setting.id}
                  className="p-3 bg-gray-800 rounded-lg flex items-center justify-between hover:bg-gray-750 transition-colors"
                >
                  <div className="flex items-center gap-3">
                    <Printer className="w-5 h-5 text-blue-400" />
                    <div>
                      <p className="text-white font-semibold text-sm">{setting.printer_name}</p>
                      <p className="text-xs text-gray-400">{setting.paper_width} | {setting.connection_count || 0}x connected</p>
                    </div>
                  </div>
                  {setting.is_default && (
                    <Badge className="bg-green-600 text-white">Default</Badge>
                  )}
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Browser Compatibility */}
      <Card className="bg-gray-900 border-gray-700">
        <CardHeader>
          <CardTitle className="text-white flex items-center gap-2 text-base">
            <AlertCircle className="w-5 h-5 text-yellow-400" />
            Browser Support
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-3 text-sm">
            <div className="flex items-center gap-2 p-2 bg-green-900/20 rounded">
              <Check className="w-4 h-4 text-green-400" />
              <span className="text-green-300 font-semibold">Γ£à Chrome Android (RECOMMENDED)</span>
            </div>
            <div className="flex items-center gap-2 p-2 bg-green-900/20 rounded">
              <Check className="w-4 h-4 text-green-400" />
              <span className="text-green-300 font-semibold">Γ£à Chrome Desktop</span>
            </div>
            <div className="flex items-center gap-2 p-2 bg-green-900/20 rounded">
              <Check className="w-4 h-4 text-green-400" />
              <span className="text-green-300 font-semibold">Γ£à Edge Desktop</span>
            </div>
            <div className="flex items-center gap-2 p-2 bg-red-900/20 rounded">
              <X className="w-4 h-4 text-red-400" />
              <span className="text-red-400">Γ¥î Safari (tidak support)</span>
            </div>
            <div className="flex items-center gap-2 p-2 bg-red-900/20 rounded">
              <X className="w-4 h-4 text-red-400" />
              <span className="text-red-400">Γ¥î Firefox (tidak support)</span>
            </div>
            <div className="flex items-center gap-2 p-2 bg-red-900/20 rounded">
              <X className="w-4 h-4 text-red-400" />
              <span className="text-red-400">Γ¥î UC Browser / Opera (tidak support)</span>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import {
  Minus, Plus, Trash2, CreditCard, User, Award, X
} from 'lucide-react';
import TransferDropdown from './POSTransferDropdown';
import POSSalesChannel from './POSSalesChannel';

export default function POSCartSection({
  cart,
  selectedCustomer,
  selectedTherapist,
  companyMembers,
  accounts,
  selectedPaymentAccount,
  discount,
  shippingCost,
  otherCost,
  note,
  salesChannel,
  membershipLevels,
  locations,
  selectedLocation,
  getProductStock,
  getStockAtLocation,
  updateQuantity,
  removeFromCart,
  updateCartItemTransferLocation,
  setSelectedCustomer,
  setSelectedTherapist,
  setSelectedPaymentAccount,
  setDiscount,
  setShippingCost,
  setOtherCost,
  setNote,
  setSalesChannel,
  calculateSubtotal,
  calculateTotal,
  getMembershipDiscount,
  calculatePointsEarned,
  calculateStampsEarned,
  handleCheckout,
}) {
  return (
    <Card className="bg-white dark:bg-gray-900 border-gray-200 dark:border-gray-800">
      <CardHeader className="p-3 sm:p-4">
        <CardTitle className="text-gray-900 dark:text-white flex items-center justify-between text-sm sm:text-base">
          <span>Keranjang</span>
          <div className="flex items-center gap-2">
            {selectedCustomer && (
              <Badge variant="outline" className="bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 border-blue-200 dark:border-blue-800 text-[10px] px-1.5 py-0 h-5">
                Poin: {selectedCustomer.membership_points || 0}
              </Badge>
            )}
            <Badge className="bg-green-600 text-white text-xs">{cart.length} item</Badge>
          </div>
        </CardTitle>
        {selectedCustomer && (
          <div className="mt-2 p-2 bg-blue-50 dark:bg-blue-900/10 border border-blue-100 dark:border-blue-900/30 rounded-lg space-y-1.5 animate-in fade-in slide-in-from-top-1 duration-200">
            <div className="flex items-center justify-between">
              <span className="text-[10px] font-bold text-blue-800 dark:text-blue-300 uppercase tracking-wider">Info Pelanggan</span>
              <Badge className="bg-purple-600 hover:bg-purple-700 text-[10px] px-1 h-4">
                {selectedCustomer.membership_level_name || 'Reguler'}
              </Badge>
            </div>
            <div className="grid grid-cols-1 gap-1 text-[11px]">
              <div className="flex items-start gap-1.5 text-gray-700 dark:text-gray-300">
                <Badge variant="ghost" className="p-0 h-auto text-blue-600 dark:text-blue-400"><User className="w-3 h-3" /></Badge>
                <span className="font-medium truncate">{selectedCustomer.name}</span>
                <span className="text-gray-400">({selectedCustomer.whatsapp_number || selectedCustomer.phone || '-'})</span>
              </div>
              <div className="flex items-start gap-1.5 text-gray-600 dark:text-gray-400">
                <Badge variant="ghost" className="p-0 h-auto text-blue-600 dark:text-blue-400"><X className="w-3 h-3 opacity-0" /></Badge>
                <span className="line-clamp-2 italic">{selectedCustomer.address || 'Alamat tidak tersedia'}</span>
              </div>
              {selectedCustomer.maps_url && (
                <button 
                  onClick={() => window.open(selectedCustomer.maps_url, '_blank')}
                  className="flex items-center gap-1.5 text-red-600 dark:text-red-400 hover:underline font-medium mt-0.5"
                >
                  <Badge variant="ghost" className="p-0 h-auto text-red-600 dark:text-red-400">≡ƒôì</Badge>
                  Lihat di Google Maps
                </button>
              )}
              {selectedCustomer.image_url && (
                <div className="mt-1 flex items-center gap-2">
                  <div className="w-10 h-10 rounded border border-blue-200 dark:border-blue-800 overflow-hidden flex-shrink-0 cursor-pointer" onClick={() => window.open(selectedCustomer.image_url, '_blank')}>
                    <img src={selectedCustomer.image_url} alt="House" className="w-full h-full object-cover" />
                  </div>
                  <span className="text-[10px] text-gray-500 italic">Foto Rumah tersedia</span>
                </div>
              )}
            </div>
          </div>
        )}
      </CardHeader>
      <CardContent className="space-y-3 sm:space-y-4 p-3 sm:p-4 pt-0">
        <div className="space-y-2 max-h-48 sm:max-h-64 overflow-y-auto">
          {cart.map((item) => (
            <div key={item.product_id} className="p-2 bg-gray-100 dark:bg-gray-800 rounded space-y-2">
              <div className="flex items-center gap-2">
                <div className="flex-1 min-w-0">
                  <p className="text-gray-900 dark:text-white text-xs sm:text-sm font-medium truncate">
                    {item.product_name}
                  </p>
                  <p className="text-gray-600 dark:text-gray-400 text-xs">Rp {item.price.toLocaleString('id-ID')}</p>
                </div>
                <div className="flex items-center gap-1 sm:gap-2 flex-shrink-0">
                  <Button size="icon" variant="outline" className="h-7 w-7 sm:h-8 sm:w-8"
                    onClick={() => updateQuantity(item.product_id, item.quantity - 1)}>
                    <Minus className="w-3 h-3" />
                  </Button>
                  <Input type="number" value={item.quantity}
                    onChange={(e) => updateQuantity(item.product_id, Math.max(1, parseInt(e.target.value) || 1))}
                    className="w-10 sm:w-12 h-7 sm:h-8 text-center p-0 text-xs sm:text-sm bg-gray-100 dark:bg-gray-800 border-gray-300 dark:border-gray-600"
                    min="1" />
                  <Button size="icon" variant="outline" className="h-7 w-7 sm:h-8 sm:w-8"
                    onClick={() => updateQuantity(item.product_id, item.quantity + 1)}>
                    <Plus className="w-3 h-3" />
                  </Button>
                  <Button size="icon" variant="ghost"
                    className="h-7 w-7 sm:h-8 sm:w-8 text-red-600 dark:text-red-400"
                    onClick={() => removeFromCart(item.product_id)}>
                    <Trash2 className="w-3 h-3" />
                  </Button>
                </div>
              </div>
              <TransferDropdown
                item={item}
                locations={locations}
                selectedLocation={selectedLocation}
                getProductStock={getProductStock}
                getStockAtLocation={getStockAtLocation}
                updateCartItemTransferLocation={updateCartItemTransferLocation}
              />
            </div>
          ))}
        </div>

        <div className="border-t border-gray-200 dark:border-gray-700 pt-3 sm:pt-4 space-y-3 text-xs sm:text-sm">
          {/* Sales Channel */}
          <POSSalesChannel value={salesChannel} onChange={setSalesChannel} />

          {/* Therapist */}
          <div className="space-y-1">
            <Label className="text-xs font-semibold text-gray-700 dark:text-gray-300">Terapis / Penanggung Jawab</Label>
            <div className="relative">
              <User className="absolute left-2 top-2.5 w-3 h-3 text-gray-400" />
              <select value={selectedTherapist ? selectedTherapist.id : ''}
                onChange={(e) => {
                  const id = e.target.value;
                  const member = companyMembers.find(m => m.user_id === id);
                  setSelectedTherapist(member ? { id: member.user_id, full_name: member.user_name || member.email, name: member.user_name || member.email } : null);
                }}
                className="w-full pl-8 pr-3 py-2 bg-gray-100 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-xs">
                <option value="">-- Pilih Terapis --</option>
                {companyMembers && companyMembers.length > 0 ? (
                  companyMembers.map((member) => (
                    <option key={member.id} value={member.user_id}>
                      {member.user_name || member.user_email || member.email} ({member.role})
                    </option>
                  ))
                ) : (
                  <option disabled>Loading members...</option>
                )}
              </select>
            </div>
          </div>

          {/* Payment Account */}
          <div className="space-y-1">
            <Label className="text-xs font-semibold text-gray-700 dark:text-gray-300">Metode Pembayaran / Rekening *</Label>
            <div className="relative">
