            <div className="grid grid-cols-4 gap-1 mb-2">
              {[5, 10, 15, 20].map((pct) => (
                <Button key={pct} size="sm"
                  variant={discount.type === 'percentage' && discount.value === pct ? 'default' : 'outline'}
