                className="flex-1 h-8 text-xs bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600"
                min="0" max={discount.type === 'percentage' ? 100 : undefined} />
              {discount.value && (
                <Button size="sm" variant="ghost" className="h-8 w-8 p-0"
                  onClick={() => setDiscount({ ...discount, value: '' })}>
                  <X className="w-3 h-3" />
                </Button>
              )}
            </div>
            {discount.value && parseFloat(discount.value) > 0 && (
              <p className="text-xs text-green-600 dark:text-green-400 font-semibold">
                Diskon: -Rp {(discount.type === 'percentage'
                  ? calculateSubtotal() * parseFloat(discount.value) / 100
                  : parseFloat(discount.value)).toLocaleString('id-ID')}
              </p>
            )}
          </div>

          {/* Extras */}
          <div className="grid grid-cols-2 gap-2">
            <div className="space-y-1">
              <Label className="text-xs text-gray-600">Ongkos Kirim</Label>
              <Input type="number" value={shippingCost}
                onChange={(e) => setShippingCost(e.target.value)}
                className="h-8 text-xs bg-gray-100 dark:bg-gray-800" placeholder="Rp 0" />
            </div>
            <div className="space-y-1">
              <Label className="text-xs text-gray-600">Biaya Lain</Label>
              <Input type="number" value={otherCost}
                onChange={(e) => setOtherCost(e.target.value)}
                className="h-8 text-xs bg-gray-100 dark:bg-gray-800" placeholder="Rp 0" />
            </div>
          </div>

          {/* Note */}
          <div className="space-y-1">
            <Label className="text-xs text-gray-600">Catatan Transaksi</Label>
            <textarea value={note} onChange={(e) => setNote(e.target.value)}
              className="w-full h-16 px-3 py-2 bg-gray-100 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded text-xs resize-none focus:outline-none focus:ring-1 focus:ring-blue-500"
              placeholder="Tambahkan catatan untuk struk..." />
          </div>

          <div className="flex justify-between text-gray-900 dark:text-white text-base sm:text-lg font-bold">
            <span>Total</span>
            <span>Rp {calculateTotal().toLocaleString('id-ID')}</span>
          </div>
          {selectedCustomer && calculatePointsEarned() > 0 && (
            <div className="flex justify-between text-yellow-600 dark:text-yellow-400 text-xs sm:text-sm">
              <span className="flex items-center gap-1"><Award className="w-3 h-3 sm:w-4 sm:h-4" />Poin yang didapat</span>
              <span>+{calculatePointsEarned()} poin</span>
            </div>
          )}
          {selectedCustomer && calculateStampsEarned() > 0 && (
            <div className="flex justify-between text-purple-600 dark:text-purple-400 text-xs sm:text-sm">
              <span className="flex items-center gap-1">≡ƒÄ½ Stamp yang didapat</span>
              <span className="font-semibold">+{calculateStampsEarned()} stamp</span>
            </div>
          )}
        </div>

        <Button className="w-full bg-blue-600 hover:bg-blue-700 text-sm sm:text-base h-10 sm:h-11"
          onClick={handleCheckout} disabled={cart.length === 0 || !selectedLocation}>
          <CreditCard className="w-4 h-4 mr-2" />
          Bayar
        </Button>
      </CardContent>
    </Card>
  );
}

import { base44 } from '@/api/base44Client';
import { toast } from 'sonner';

export async function updateCustomerMembership({ customerId, currentTotal, membershipLevels, companyId }) {
  if (!customerId) return;
  const Customer = base44.entities.Customer;
  const CustomerMembership = base44.entities.CustomerMembership;

  const customerData = await Customer.filter({ id: customerId });
  const customer = customerData?.[0];
  const allLevels = await CustomerMembership.filter({ company_id: companyId, is_active: true });
  const sortedLevels = allLevels?.sort((a, b) => (a.order || 0) - (b.order || 0)) || [];

  if (!customer || sortedLevels.length === 0) return;

  const baseLevel = sortedLevels[0];
  let currentLevel = null;
  let currentLevelIndex = -1;

  if (customer.membership_level_id) {
    currentLevelIndex = sortedLevels.findIndex(l => String(l.id) === String(customer.membership_level_id));
    if (currentLevelIndex === -1 && customer.membership_level_name) {
      currentLevelIndex = sortedLevels.findIndex(l => l.level_name === customer.membership_level_name);
    }
    if (currentLevelIndex !== -1) currentLevel = sortedLevels[currentLevelIndex];
  }

  if (!customer.membership_level_id && baseLevel) {
    await Customer.update(customer.id, { membership_level_id: baseLevel.id, membership_level_name: baseLevel.level_name, membership_since: new Date().toISOString(), stamps: 0, membership_points: 0 });
    currentLevel = baseLevel; currentLevelIndex = 0;
    toast.success(`≡ƒÄë ${customer.name} bergabung sebagai ${baseLevel.icon} ${baseLevel.level_name}!`, { duration: 4000 });
  }

  const minPurchase = currentLevel?.min_purchase > 0 ? currentLevel.min_purchase : 100000;
  const pointsToAdd = currentTotal >= minPurchase ? 10 : 0;
  const stampsEarned = pointsToAdd > 0 ? 1 : 0;

  let existingStamps = 0;
  if (customer.stamps !== undefined && customer.stamps !== null) existingStamps = Number(customer.stamps);
  else existingStamps = Math.floor(Number(customer.membership_points || 0) / 10);

  const newStamps = existingStamps + stampsEarned;
  const newPoints = newStamps * 10;
  const newVisits = (customer.total_orders || 0) + 1;
  const newLifetimeValue = (customer.lifetime_value || 0) + currentTotal;

  let updatePayload = { total_orders: newVisits, membership_points: newPoints, stamps: newStamps, lifetime_value: newLifetimeValue, last_purchase_date: new Date().toISOString() };

  let upgradedLevel = null;
  if (currentLevelIndex >= 0 && currentLevelIndex < sortedLevels.length - 1) {
    const nextLevel = sortedLevels[currentLevelIndex + 1];
    if (nextLevel && nextLevel.auto_upgrade !== false && (nextLevel.order > (currentLevel?.order || 0))) {
      const stampsReq = Number(nextLevel.stamps_required) > 0 ? Number(nextLevel.stamps_required) : 10;
      const safeThreshold = Math.max(stampsReq, 2);
      const forceStamp = nextLevel.stamps_required > 0;
      const scheme = forceStamp ? 'stamp' : nextLevel.scheme_type;

      let shouldUpgrade = false;
      switch (scheme) {
        case 'stamp': shouldUpgrade = newStamps >= safeThreshold; break;
        case 'visits': shouldUpgrade = newVisits >= (nextLevel.visits_required || 20); break;
        case 'points': shouldUpgrade = newPoints >= (nextLevel.points_required || 1000); break;
        case 'spending': shouldUpgrade = newLifetimeValue >= (nextLevel.min_purchase || 1000000); break;
        default: shouldUpgrade = newLifetimeValue >= (nextLevel.min_purchase || 1000000);
      }

      const gateStamps = Number(nextLevel.stamps_required) > 0 ? Number(nextLevel.stamps_required) : 10;
      if (shouldUpgrade && newStamps < gateStamps) { shouldUpgrade = false; toast.info(`ΓÜá∩╕Å Belum cukup stamp untuk naik level (${newStamps}/${gateStamps})`); }

      if (shouldUpgrade) {
        upgradedLevel = nextLevel;
        updatePayload.membership_level_id = nextLevel.id;
        updatePayload.membership_level_name = nextLevel.level_name;
        updatePayload.membership_points = 0;
        updatePayload.stamps = 0;
      }
    }
  }

  await Customer.update(customer.id, updatePayload);

  if (upgradedLevel) {
    toast.success(`≡ƒÄë ${customer.name} naik level ke ${upgradedLevel.icon} ${upgradedLevel.level_name}!`, { duration: 5000 });
    toast.info(`Mulai mengumpulkan stamp dari awal untuk level ${upgradedLevel.level_name}`);
  } else if (stampsEarned > 0) {
    toast.success(`≡ƒÄ½ +1 Stamp! Total: ${Math.floor(newPoints / 10)} stamp`, { duration: 3000 });
  }
}

import { useState } from 'react';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Input } from '@/components/ui/input';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { FileSpreadsheet, FileText, ShoppingCart, Calendar } from 'lucide-react';
import { format, startOfMonth, endOfMonth, startOfYear, endOfYear, startOfWeek, endOfWeek } from 'date-fns';
import { id } from 'date-fns/locale';
import { toast } from 'sonner';

const SNISHOP_LOGO = 'https://qtrypzzcjebvfcihiynt.supabase.co/storage/v1/object/public/base44-prod/public/68e711957c86e922f92ad49f/a236b74f4_Logosnishopbirupanjang.png';

export default function POSProfessionalExport({
  transactions,
  products,
  customers,
  selectedCompany,
  period,
  salesChannelFilter = 'ALL',
  locationFilter = 'ALL',
  salesChannelConfig = {},
  locations = [] // List of {id, location_name}
}) {
  const [showExportDialog, setShowExportDialog] = useState(false);
  const [exportPeriod, setExportPeriod] = useState(period || 'all');
  const [customDateRange, setCustomDateRange] = useState({ start: '', end: '' });

  const companyName = selectedCompany?.name || 'Toko';
  const companyLogo = selectedCompany?.logo_url || SNISHOP_LOGO;
  const companyAddress = selectedCompany?.address || '';
  const companyPhone = selectedCompany?.phone || '';
  const companyEmail = selectedCompany?.email || '';

  // Helper to resolve Channel Name
  const getChannelName = (id) => {
    if (!id || id === 'OFFLINE') return 'Offline Store';
    const configName = salesChannelConfig[id];
    if (configName) return configName;
    // Fallback to static list if needed, or just ID
    return id;
  };

  // Helper to resolve Location Name
  const getLocationName = (id) => {
    if (!id) return '-';
    const loc = locations.find(l => l.id === id);
    return loc ? loc.location_name : '-';
  };

  const getDateRange = (periodType) => {
    const now = new Date();
    let startDate, endDate;

    switch (periodType) {
      case 'today':
        startDate = new Date(now.setHours(0, 0, 0, 0));
        endDate = new Date();
        break;
      case 'this_week':
        startDate = startOfWeek(now);
        endDate = endOfWeek(now);
        break;
      case 'this_month':
        startDate = startOfMonth(now);
        endDate = endOfMonth(now);
        break;
      case 'last_month':
        const lastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
        startDate = startOfMonth(lastMonth);
        endDate = endOfMonth(lastMonth);
        break;
      case 'this_year':
        startDate = startOfYear(now);
        endDate = endOfYear(now);
        break;
      case 'custom':
        if (customDateRange.start && customDateRange.end) {
          return {
            startDate: new Date(customDateRange.start),
            endDate: new Date(customDateRange.end)
          };
        }
        return { startDate: null, endDate: null };
      case 'all':
      default:
        return { startDate: null, endDate: null };
    }

    return { startDate, endDate };
  };

  const getFilteredTransactions = () => {
    const { startDate, endDate } = getDateRange(exportPeriod);

    // 1. Filter by Status
    let filtered = transactions.filter(t => t.status === 'completed');

    // 2. Filter by Date
    if (startDate && endDate) {
      filtered = filtered.filter(t => {
        const tDate = new Date(t.created_date);
        return tDate >= startDate && tDate <= endDate;
      });
    }

    // 3. Filter by Channel (Strict)
    if (salesChannelFilter !== 'ALL') {
      filtered = filtered.filter(t => (t.sales_channel || 'OFFLINE') === salesChannelFilter);
    }

    // 4. Filter by Location (Strict)
    if (locationFilter !== 'ALL') {
      filtered = filtered.filter(t => {
        const tLocId = t.location_id || t.items?.[0]?.fulfillment_location_id;
        return tLocId === locationFilter;
      });
    }

    return filtered.sort((a, b) => new Date(b.created_date) - new Date(a.created_date));
  };

  const calculatePOSFinancials = (filteredTrx) => {
    const totalRevenue = filteredTrx.reduce((sum, t) => sum + t.total, 0);
    const totalDiscount = filteredTrx.reduce((sum, t) => sum + (t.discount_amount || 0), 0);
    const totalTax = filteredTrx.reduce((sum, t) => sum + (t.tax_amount || 0), 0);
    const subtotalBeforeDiscount = filteredTrx.reduce((sum, t) => sum + t.subtotal, 0);

    // Calculate COGS
    let totalCOGS = 0;
    filteredTrx.forEach(t => {
      (t.items || []).forEach(item => {
        const product = products.find(p => p.id === item.product_id);
        const unitCost = product?.cost || 0;
        totalCOGS += unitCost * item.quantity;
      });
    });

    const grossProfit = totalRevenue - totalCOGS;
    const profitMargin = totalRevenue > 0 ? (grossProfit / totalRevenue * 100) : 0;

    // Sales by payment method
    const byPaymentMethod = {};
    filteredTrx.forEach(t => {
      const method = t.payment_method || 'cash';
      byPaymentMethod[method] = (byPaymentMethod[method] || 0) + t.total;
    });

    // Sales by category
    const byCategory = {};
    const categoryQuantity = {};
    filteredTrx.forEach(t => {
      (t.items || []).forEach(item => {
        const product = products.find(p => p.id === item.product_id);
        const category = product?.category || 'Lainnya';
        byCategory[category] = (byCategory[category] || 0) + item.subtotal;
        categoryQuantity[category] = (categoryQuantity[category] || 0) + item.quantity;
      });
    });

    // Product sales
    const productSales = {};
    filteredTrx.forEach(t => {
      (t.items || []).forEach(item => {
        if (!productSales[item.product_id]) {
          const product = products.find(p => p.id === item.product_id);
          productSales[item.product_id] = {
            name: item.product_name,
            sku: item.sku,
            quantity: 0,
            revenue: 0,
            cogs: 0,
            profit: 0,
            unitCost: product?.cost || 0
          };
        }
        productSales[item.product_id].quantity += item.quantity;
        productSales[item.product_id].revenue += item.subtotal;
        const product = products.find(p => p.id === item.product_id);
        const cogs = (product?.cost || 0) * item.quantity;
        productSales[item.product_id].cogs += cogs;
        productSales[item.product_id].profit += (item.subtotal - cogs);
      });
    });

    const topProducts = Object.values(productSales)
      .sort((a, b) => b.revenue - a.revenue)
      .slice(0, 20);

    // Daily sales
    const dailySales = {};
    filteredTrx.forEach(t => {
      const day = format(new Date(t.created_date), 'yyyy-MM-dd');
      if (!dailySales[day]) {
        dailySales[day] = { revenue: 0, transactions: 0, items: 0 };
      }
      dailySales[day].revenue += t.total;
      dailySales[day].transactions += 1;
      dailySales[day].items += (t.items || []).reduce((sum, item) => sum + item.quantity, 0);
    });

    const productsSold = filteredTrx.reduce((sum, t) => {
      return sum + (t.items || []).reduce((itemSum, item) => itemSum + item.quantity, 0);
    }, 0);

    const uniqueCustomers = new Set(filteredTrx.filter(t => t.customer_id).map(t => t.customer_id)).size;
    const avgTransaction = filteredTrx.length > 0 ? totalRevenue / filteredTrx.length : 0;
    const avgItemsPerTransaction = filteredTrx.length > 0 ? productsSold / filteredTrx.length : 0;

    return {
      totalRevenue,
      totalCOGS,
      grossProfit,
      profitMargin,
      totalDiscount,
      totalTax,
      subtotalBeforeDiscount,
      transactionCount: filteredTrx.length,
      productsSold,
      uniqueCustomers,
      avgTransaction,
      avgItemsPerTransaction,
      byPaymentMethod,
      byCategory,
      categoryQuantity,
      topProducts,
      dailySales,
      transactions: filteredTrx
    };
  };

  const exportProfessionalCSV = () => {
    const filteredTrx = getFilteredTransactions();
    const financials = calculatePOSFinancials(filteredTrx);
    const { startDate, endDate } = getDateRange(exportPeriod);

    const csvData = [
      [`"LAPORAN PENJUALAN POS ENTERPRISE - ${companyName.toUpperCase()}"`],
      [`"Periode: ${startDate && endDate ? `${format(startDate, 'dd MMMM yyyy', { locale: id })} - ${format(endDate, 'dd MMMM yyyy', { locale: id })}` : 'Semua Waktu'}"`],
      [`"Channel: ${salesChannelFilter === 'ALL' ? 'Semua Channel' : getChannelName(salesChannelFilter)}"`],
      [`"Lokasi: ${locationFilter === 'ALL' ? 'Semua Lokasi' : getLocationName(locationFilter)}"`],
      [`"Dicetak: ${format(new Date(), 'dd MMMM yyyy HH:mm', { locale: id })} WIB"`],
      [`"${companyAddress || ''}"`],
      [`"Tel: ${companyPhone || '-'} | Email: ${companyEmail || '-'}"`],
      [`"Powered by SNISHOP.COM - Smart Business Operating System"`],
      [''],
      ['=== RINGKASAN PENJUALAN ==='],
      ['Metrik', 'Nilai', 'Keterangan'],
      ['Total Penjualan (Revenue)', `"Rp ${financials.totalRevenue.toLocaleString('id-ID')}"`, `Omzet kotor`],
      ['Harga Pokok Penjualan (COGS)', `"Rp ${financials.totalCOGS.toLocaleString('id-ID')}"`, `Modal produk terjual`],
      ['Laba Kotor (Gross Profit)', `"Rp ${financials.grossProfit.toLocaleString('id-ID')}"`, `Revenue - COGS`],
      ['Margin Laba Kotor', `${financials.profitMargin.toFixed(2)}%`, `(Gross Profit / Revenue) x 100%`],
      ['Total Diskon Diberikan', `"Rp ${financials.totalDiscount.toLocaleString('id-ID')}"`, `Total potongan harga`],
      ['Total Pajak', `"Rp ${financials.totalTax.toLocaleString('id-ID')}"`, `Pajak terkumpul`],
      ['Total Transaksi', `${financials.transactionCount}`, `Jumlah transaksi completed`],
      ['Total Produk Terjual', `${financials.productsSold}`, `Unit terjual`],
      ['Customer Unik', `${financials.uniqueCustomers}`, `Jumlah customer berbeda`],
      ['Rata-rata Nilai Transaksi', `"Rp ${financials.avgTransaction.toLocaleString('id-ID')}"`, `Revenue / Transaksi`],
      ['Rata-rata Item per Transaksi', `${financials.avgItemsPerTransaction.toFixed(1)}`, `Total items / Transaksi`],
      [''],
      ['=== PENJUALAN PER METODE PEMBAYARAN ==='],
      ['Metode', 'Jumlah Penjualan', 'Persentase (%)', 'Jumlah Transaksi'],
      ...Object.entries(financials.byPaymentMethod)
        .sort(([, a], [, b]) => b - a)
        .map(([method, amount]) => {
          const trxCount = filteredTrx.filter(t => t.payment_method === method).length;
          return [
            method.charAt(0).toUpperCase() + method.slice(1),
            `"Rp ${amount.toLocaleString('id-ID')}"`,
            `${financials.totalRevenue > 0 ? ((amount / financials.totalRevenue) * 100).toFixed(2) : 0}%`,
            trxCount
          ];
        }),
      [''],
      ['=== PENJUALAN PER KATEGORI PRODUK ==='],
      ['Kategori', 'Revenue', 'Persentase (%)', 'Unit Terjual', 'Avg per Unit'],
      ...Object.entries(financials.byCategory)
        .sort(([, a], [, b]) => b - a)
        .map(([cat, amount]) => [
          cat,
          `"Rp ${amount.toLocaleString('id-ID')}"`,
          `${financials.totalRevenue > 0 ? ((amount / financials.totalRevenue) * 100).toFixed(2) : 0}%`,
          financials.categoryQuantity[cat] || 0,
          `"Rp ${(amount / Math.max(1, financials.categoryQuantity[cat] || 1)).toLocaleString('id-ID')}"`
        ]),
      [''],
      ['=== TOP 20 PRODUK TERLARIS ==='],
      ['Ranking', 'SKU', 'Nama Produk', 'Unit Terjual', 'Revenue', 'COGS', 'Laba Kotor', 'Margin (%)'],
      ...financials.topProducts.map((product, idx) => [
        idx + 1,
        product.sku || '-',
        product.name,
        product.quantity,
        `"Rp ${product.revenue.toLocaleString('id-ID')}"`,
        `"Rp ${product.cogs.toLocaleString('id-ID')}"`,
        `"Rp ${product.profit.toLocaleString('id-ID')}"`,
        `${product.revenue > 0 ? ((product.profit / product.revenue) * 100).toFixed(2) : 0}%`
      ]),
      [''],
      ['=== PENJUALAN HARIAN ==='],
      ['Tanggal', 'Revenue', 'Transaksi', 'Items Terjual', 'Avg per Transaksi'],
      ...Object.entries(financials.dailySales)
        .sort(([a], [b]) => b.localeCompare(a))
        .map(([day, data]) => [
          format(new Date(day), 'dd MMMM yyyy (EEEE)', { locale: id }),
          `"Rp ${data.revenue.toLocaleString('id-ID')}"`,
          data.transactions,
          data.items,
          `"Rp ${(data.revenue / data.transactions).toLocaleString('id-ID')}"`
        ]),
      [''],
      ['=== DETAIL TRANSAKSI LENGKAP ==='],
