// Γ£à INSTANT PAGE LOADER - Zero loading time for all pages
// Uses aggressive caching + stale-while-revalidate pattern

import { base44 } from '@/api/base44Client';

const CACHE_PREFIX = 'SNISHOP_PAGE_';
const CACHE_TTL = 5 * 60 * 1000; // 5 minutes

/**
 * Get cached page data instantly, refresh in background
 */
export async function loadPageData(pageKey, loaderFn, options = {}) {
  const {
    ttl = CACHE_TTL,
    forceRefresh = false,
    onStaleData = null,
    dependencies = []
  } = options;

  const cacheKey = `${CACHE_PREFIX}${pageKey}_${dependencies.join('_')}`;

  try {
    // 1. Γ£à INSTANT CACHE HIT - Return immediately if available
    if (!forceRefresh) {
      const cached = sessionStorage.getItem(cacheKey);
      
      if (cached) {
        try {
          const { data, timestamp } = JSON.parse(cached);
          const age = Date.now() - timestamp;
          
          if (data) {
            const isStale = age > ttl;
            
            console.log(`≡ƒôª INSTANT PAGE: ${pageKey} - ${isStale ? 'STALE' : 'FRESH'} cache (${Math.round(age/1000)}s old)`);
            
            if (onStaleData && isStale) {
              onStaleData(data);
            }
            
            // Γ£à Refresh in background if stale
            if (isStale) {
              setTimeout(() => refreshPageData(cacheKey, loaderFn, pageKey), 100);
            }
            
            return data;
          }
        } catch (e) {
          console.warn('Cache parse error:', e);
        }
      }
    }

    // 2. ΓÅ│ No cache - load fresh
    console.log(`ΓÅ│ INSTANT PAGE: ${pageKey} - Loading fresh data...`);
    const freshData = await loaderFn();
    
    // 3. Γ£à Save to cache
    sessionStorage.setItem(cacheKey, JSON.stringify({
      data: freshData,
      timestamp: Date.now()
    }));
    
    console.log(`Γ£à INSTANT PAGE: ${pageKey} - Data loaded and cached`);
    return freshData;

  } catch (error) {
    console.error(`Γ¥î Error loading ${pageKey}:`, error);
    
    // Γ£à Fallback to stale cache on error
    const cached = sessionStorage.getItem(cacheKey);
    if (cached) {
      try {
        const { data } = JSON.parse(cached);
        console.log(`ΓÜá∩╕Å INSTANT PAGE: ${pageKey} - Using stale cache due to error`);
        return data;
      } catch (e) {}
    }
    
    throw error;
  }
}

/**
 * Refresh cache in background
 */
async function refreshPageData(cacheKey, loaderFn, pageKey) {
  try {
    console.log(`≡ƒöä BACKGROUND: Refreshing ${pageKey}...`);
    const freshData = await loaderFn();
    
    sessionStorage.setItem(cacheKey, JSON.stringify({
      data: freshData,
