/**
 * UPDATE STOCK FROM TRANSACTION: Update stok setelah transaksi POS
 * @param {string} companyId
 * @param {array} transactionItems - Array of {product_id, quantity}
 * @param {string} locationId - ID lokasi transaksi
 * @param {string} performedBy
 * @returns {Promise<boolean>}
 */
export async function updateStockFromTransaction(companyId, transactionItems, locationId, performedBy) {
  try {
    console.log('≡ƒöä TRANSACTION SYNC: Processing', transactionItems.length, 'items');

    for (const item of transactionItems) {
      // 1. Get current product
      const product = await base44.entities.CompanyPOSProduct.get(item.product_id);
      if (!product) {
        console.warn(`ΓÜá∩╕Å Product not found: ${item.product_id}`);
        continue;
      }

      // 2. Calculate new stock
      const newStock = Math.max(0, (product.stock || 0) - item.quantity);
      console.log(`≡ƒôª ${product.name}: ${product.stock} ΓåÆ ${newStock} (sold: ${item.quantity})`);

      // 3. Update CompanyPOSProduct
      await base44.entities.CompanyPOSProduct.update(product.id, {
        stock: newStock
      });

      // 4. Update Inventory for this location
      const inventoryItems = await base44.entities.Inventory.filter({
        company_id: companyId,
        product_id: product.id,
        location_id: locationId
      });

      if (inventoryItems && inventoryItems.length > 0) {
        const inv = inventoryItems[0];
        const invNewStock = Math.max(0, (inv.quantity || 0) - item.quantity);
        const stockStatus = invNewStock === 0 ? 'out_of_stock' :
          invNewStock <= (inv.min_stock || 5) ? 'low_stock' : 'in_stock';

        await base44.entities.Inventory.update(inv.id, {
          quantity: invNewStock,
          available_quantity: invNewStock,
          total_value: invNewStock * (inv.unit_cost || 0),
          stock_status: stockStatus,
          last_stock_out: new Date().toISOString()
        });

        // Log stock movement
        await base44.entities.StockMovement.create({
          company_id: companyId,
          inventory_id: inv.id,
          product_id: product.id,
          product_name: product.name,
          location_id: locationId,
          location_name: inv.location_name,
          movement_type: 'out',
          quantity: item.quantity,
          stock_before: inv.quantity || 0,
          stock_after: invNewStock,
          reference_type: 'pos_sale',
          reason: 'POS transaction',
          performed_by: performedBy,
          performed_by_name: performedBy,
          unit_cost: inv.unit_cost || 0,
          total_value: item.quantity * (inv.unit_cost || 0)
        }).catch(err => console.warn('Stock movement log failed:', err));
      }
    }

    // 5. Broadcast update
    try {
      const channel = new BroadcastChannel('snishop_inventory_updates');
      channel.postMessage({
        type: 'TRANSACTION_COMPLETED',
        companyId: companyId,
        timestamp: Date.now()
      });
      channel.close();
      console.log('≡ƒôí TRANSACTION SYNC: Broadcast sent');
    } catch (e) {
      console.warn('BroadcastChannel error:', e);
    }

    return true;
  } catch (error) {
    console.error('Γ¥î TRANSACTION SYNC ERROR:', error);
    throw error;
  }
}

/**
 * ULTIMATE INSTANT APP - ZERO LOADING, EXTREME CACHE
 * Aggressive cache-first strategy for instant UX
 */

class RequestManager {
  constructor() {
    this.cache = new Map();
    this.pendingRequests = new Map();
    this.requestTimestamps = [];
    this.maxRequestsPerSecond = 1; // Γ£à MAXIMUM 1 request per 15 seconds
    this.requestQueue = [];
    this.isProcessingQueue = false;
    this.retryDelays = [120000, 300000, 600000]; // Γ£à 2min, 5min, 10min retry delays
    
    this.loadCacheFromStorage();
    
    setInterval(() => this.saveCacheToStorage(), 60000); // Save every minute
    setInterval(() => this.cleanOldTimestamps(), 2000);
  }

  cleanOldTimestamps() {
    const fifteenSecondsAgo = Date.now() - 15000; // Γ£à 15 second window
    this.requestTimestamps = this.requestTimestamps.filter(t => t > fifteenSecondsAgo);
  }

  async waitForRateLimit() {
    this.cleanOldTimestamps();
    
    while (this.requestTimestamps.length >= this.maxRequestsPerSecond) {
      await new Promise(resolve => setTimeout(resolve, 15000)); // Γ£à Wait 15s
      this.cleanOldTimestamps();
    }
    
    this.requestTimestamps.push(Date.now());
  }

  async queueRequest(fn) {
    return new Promise((resolve, reject) => {
      this.requestQueue.push({ fn, resolve, reject });
      this.processQueue();
    });
  }

  async processQueue() {
    if (this.isProcessingQueue || this.requestQueue.length === 0) return;
    this.isProcessingQueue = true;

    while (this.requestQueue.length > 0) {
      const { fn, resolve, reject } = this.requestQueue.shift();
      try {
        await this.waitForRateLimit();
        const result = await fn();
        resolve(result);
      } catch (error) {
        reject(error);
      }
      await new Promise(r => setTimeout(r, 15000)); // Γ£à 15s gap between requests
    }

    this.isProcessingQueue = false;
  }

  saveCacheToStorage() {
    try {
      const cacheData = {};
      let count = 0;
      
      this.cache.forEach((value, key) => {
        const age = Date.now() - (value.timestamp || Date.now());
        if (age < 604800000) { // Γ£à Keep cache for 7 days
          cacheData[key] = {
            data: value.data,
            timestamp: value.timestamp
          };
          count++;
        }
      });
      
      localStorage.setItem('TODOIT_DATA_CACHE', JSON.stringify(cacheData));
    } catch (e) {}
  }

  loadCacheFromStorage() {
    try {
      const stored = localStorage.getItem('TODOIT_DATA_CACHE');
      if (stored) {
        const cacheData = JSON.parse(stored);
        let count = 0;
        
        Object.entries(cacheData).forEach(([key, value]) => {
          const age = Date.now() - (value.timestamp || Date.now());
          if (age < 604800000) { // Γ£à Keep cache for 7 days
            this.cache.set(key, {
              data: value.data,
              timestamp: value.timestamp
            });
            count++;
          }
        });
        
        console.log(`≡ƒÆ╛ Cache loaded: ${count} items - INSTANT MODE`);
      }
    } catch (e) {}
  }

  getCacheKey(entityName, method, filters = {}) {
    const filterStr = JSON.stringify(filters);
    return `${entityName}:${method}:${filterStr}`;
  }

  getCached(key) {
    const cached = this.cache.get(key);
    if (!cached) return null;

    const age = Date.now() - (cached.timestamp || Date.now());

    return {
      data: cached.data,
      isStale: age > 3600000, // Γ£à 1 hour before stale
      age
    };
  }

  setCache(key, data) {
    this.cache.set(key, {
      data: data,
      timestamp: Date.now()
    });
  }

  invalidateCache(keyOrPattern) {
    if (typeof keyOrPattern === 'string') {
      this.cache.delete(keyOrPattern);
    } else if (keyOrPattern instanceof RegExp) {
      for (const key of this.cache.keys()) {
        if (keyOrPattern.test(key)) {
          this.cache.delete(key);
        }
      }
    }
    setTimeout(() => this.saveCacheToStorage(), 100);
  }

  async retryRequest(entityName, method, filters, attemptNumber = 0) {
    if (attemptNumber >= this.retryDelays.length) {
      console.error(`Γ¥î Max retries exceeded for ${entityName}.${method}`);
      throw new Error('Max retries exceeded');
    }

    try {
      await this.waitForRateLimit();
      return await this.executeRequest(entityName, method, filters);
    } catch (error) {
      const isRateLimit = 
        error?.response?.status === 429 || 
        error?.message?.includes('Rate limit') ||
        error?.message?.includes('429');

      if (isRateLimit && attemptNumber < this.retryDelays.length) {
        const delay = this.retryDelays[attemptNumber];
        console.log(`ΓÅ│ Rate limit hit, retrying in ${delay/1000}s (attempt ${attemptNumber + 1}/${this.retryDelays.length})`);
        
        await new Promise(resolve => setTimeout(resolve, delay));
        return this.retryRequest(entityName, method, filters, attemptNumber + 1);
      }

      throw error;
    }
  }

  async request(entityName, method, filters = {}, options = {}) {
    const { skipCache = false, background = false } = options;
    const cacheKey = this.getCacheKey(entityName, method, filters);

    if (!skipCache) {
      const cached = this.getCached(cacheKey);
      if (cached && cached.data !== null && cached.data !== undefined) {
        console.log(`ΓÜí INSTANT: ${entityName}.${method} (age: ${Math.round(cached.age/1000)}s)`);

        if (cached.isStale && !background && !this.pendingRequests.has(cacheKey)) {
          setTimeout(() => {
            this.request(entityName, method, filters, { skipCache: true, background: true })
              .catch(() => {});
          }, 1000); // Γ£à Refresh stale data after 1 second
        }

        return cached.data;
      }
    }

    if (!skipCache && !this.cache.has(cacheKey)) {
      let placeholder;
      if (method === 'list' || method === 'filter') {
        placeholder = [];
      } else if (method === 'get' || method === 'me') {
        placeholder = null;
      }
      
      console.log(`ΓÜí NO CACHE: ${entityName}.${method} - Placeholder returned`);
      
      if (placeholder !== null) {
        setTimeout(() => {
          this.request(entityName, method, filters, { skipCache: true, background: true })
            .then(data => {
              window.dispatchEvent(new CustomEvent('cacheUpdated', {
                detail: { entityName, method, filters, data }
              }));
            })
            .catch(() => {});
        }, 120000); // Γ£à Delay background load 2 minutes
        
        return placeholder;
      }
    }

    if (this.pendingRequests.has(cacheKey)) {
      return this.pendingRequests.get(cacheKey);
    }

    const requestPromise = this.queueRequest(async () => {
      try {
        const result = await this.retryRequest(entityName, method, filters);
        this.setCache(cacheKey, result);
        
        if (!background) {
          setTimeout(() => this.saveCacheToStorage(), 1000);
        }
        
        return result;
        
      } catch (error) {
        const staleCache = this.cache.get(cacheKey);
        if (staleCache && staleCache.data) {
          console.log(`Γ£à Using STALE cache on error: ${entityName}.${method}`);
          return staleCache.data;
        }
        
        const isRateLimit = 
          error?.response?.status === 429 || 
          error?.message?.includes('Rate limit') ||
          error?.message?.includes('429');
        
        if (isRateLimit) {
          console.error(`Γ¥î RATE LIMIT: ${entityName}.${method}`);
          
          if (method === 'list' || method === 'filter') return [];
          if (method === 'me') return null;
          if (method === 'get') return null;
        }
        
        if (method === 'list' || method === 'filter') return [];
        if (method === 'me') return null;
        if (method === 'get') return null;
        
        throw error;
        
      } finally {
        this.pendingRequests.delete(cacheKey);
      }
    });

    this.pendingRequests.set(cacheKey, requestPromise);
    return requestPromise;
  }

  async executeRequest(entityName, method, filters) {
    try {
      const entityModule = await import(`@/entities/${entityName}`);
      const Entity = entityModule[entityName];
      
      let result;
      switch (method) {
        case 'me':
          result = await Entity.me();
          break;
        case 'list':
          result = await Entity.list();
          break;
        case 'filter':
          result = await Entity.filter(filters);
          break;
        case 'get':
          if (!filters || !filters.id) {
            console.warn(`ΓÜá∩╕Å Invalid get query - missing ID for ${entityName}`);
            return null;
          }
          result = await Entity.get(filters.id);
          break;
        default:
          throw new Error(`Unknown method: ${method}`);
      }
      
      return result;
    } catch (error) {
      const errorMsg = error?.message || String(error);
      const statusCode = error?.response?.status;
      
      if (statusCode === 403 || errorMsg.includes('RLS') || errorMsg.includes('not authorized')) {
        if (method === 'list' || method === 'filter') return [];
        if (method === 'get' || method === 'me') return null;
      }
      
      throw error;
    }
  }

  clearAll() {
    this.cache.clear();
    this.pendingRequests.clear();
    this.requestTimestamps = [];
    localStorage.removeItem('TODOIT_DATA_CACHE');
  }
}

