/**
 * Safely create a company with retry and verification
 * Returns the created company or null on error
 */
export async function safeCreateCompany(data) {
  try {
    console.log('≡ƒö¿ Creating company:', data.name);
    
    // Create the company
    const company = await Company.create(data);
    
    if (!company || !company.id) {
      console.log('Γ¥î Company creation returned no ID');
      return null;
    }
    
    console.log('Γ£à Company created with ID:', company.id);
    
    // Wait a moment for database to sync
    await new Promise(resolve => setTimeout(resolve, 500));
    
    // Try to verify it exists (with retries)
    let verified = null;
    for (let attempt = 1; attempt <= 3; attempt++) {
      try {
        console.log(`≡ƒöì Verification attempt ${attempt}/3...`);
        verified = await Company.get(company.id);
        
        if (verified) {
          console.log('Γ£à Company verified successfully');
          return verified;
        }
      } catch (verifyError) {
        const is404 = verifyError?.response?.status === 404;
        
        if (is404 && attempt < 3) {
          console.log(`ΓÅ│ Not found yet, waiting before retry ${attempt}/3...`);
          await new Promise(resolve => setTimeout(resolve, 1000 * attempt));
        } else if (is404) {
          console.log('Γ¥î Company not found after 3 attempts');
        } else {
          console.log('ΓÜá∩╕Å Verify error:', verifyError.message);
        }
      }
    }
    
    // If verification failed but we have the creation response, return it anyway
    if (company && company.id) {
      console.log('ΓÜá∩╕Å Using unverified company from creation response');
      return company;
    }
    
    return null;
  } catch (error) {
    console.error('Γ¥î Error creating company:', error.message);
    
    // Check if it's a 404 during creation (shouldn't happen but handle it)
    const is404 = error?.response?.status === 404;
    if (is404) {
      console.error('Γ¥î Got 404 during company creation - this is unexpected');
    }
    
    return null;
  }
}

