/**
 * Update user's storage_used field
 */
export async function updateUserStorageUsage(userId, userEmail) {
  try {
    const { total } = await calculateUserStorage(userId, userEmail);
    
    // Γ£à Round to 2 decimal places for display
    const roundedTotal = Math.round(total * 100) / 100;
    
    await base44.auth.updateMe({
      storage_used: roundedTotal
    });

    console.log('Γ£à User storage updated in DB:', roundedTotal.toFixed(2), 'MB');

    // Γ£à Broadcast update to UI
    window.dispatchEvent(new CustomEvent('storageUpdated', {
      detail: { newStorageUsed: roundedTotal }
    }));

    // Γ£à Also update sessionStorage cache
    const cachedUserData = sessionStorage.getItem('TODOIT_USER_CACHE');
    if (cachedUserData) {
      try {
        const { user: cachedUser } = JSON.parse(cachedUserData);
        cachedUser.storage_used = roundedTotal;
        sessionStorage.setItem('TODOIT_USER_CACHE', JSON.stringify({
          user: cachedUser,
          cachedAt: Date.now()
        }));
      } catch (e) {}
    }

    return roundedTotal;
  } catch (error) {
    console.error('Γ¥î Error updating storage:', error);
    return 0;
  }
}

/**
 * Background storage sync - runs periodically
 */
export function startStorageSync(userId, userEmail, intervalMinutes = 5) {
  const intervalMs = intervalMinutes * 60 * 1000;
  
  console.log(`≡ƒöä STORAGE SYNC: Started - every ${intervalMinutes} minutes`);
  console.log(`   User: ${userEmail}`);
  
  // Γ£à Initial sync after 3 seconds
  setTimeout(() => {
    console.log('≡ƒöä STORAGE SYNC: Running initial calculation...');
    updateUserStorageUsage(userId, userEmail);
  }, 3000);

  // Γ£à Periodic sync
  const interval = setInterval(() => {
    console.log('≡ƒöä STORAGE SYNC: Running periodic calculation...');
    updateUserStorageUsage(userId, userEmail);
  }, intervalMs);

  // Γ£à Sync on window focus (tab switch back)
  const handleFocus = () => {
    console.log('≡ƒöä STORAGE SYNC: Tab focused - recalculating...');
    updateUserStorageUsage(userId, userEmail);
  };
  window.addEventListener('focus', handleFocus);

  return () => {
    clearInterval(interval);
    window.removeEventListener('focus', handleFocus);
    console.log('≡ƒ¢æ STORAGE SYNC: Stopped');
  };
}

