      });
      toast.success('Data keluhan berhasil disimpan! ΓÜá∩╕Å', { description: `${formData.customerName} - ${COMPLAINT_TYPES[formData.complaintType]?.label}` });
      setFormData({ customerId: '', customerName: '', phone: '', handledById: '', handledByName: '', complaintType: 'produk', complaintDetail: '', solution: '', status: 'open' });
      setErrors({});
      setUseExistingCustomer(false);
      loadData();
      window.dispatchEvent(new CustomEvent('taskCreated', { detail: { workspaceId: workspace.id } }));
    } catch (error) {
      toast.error('Gagal menyimpan data keluhan');
    } finally { setLoading(false); }
  };

  // Stats
  const statsData = useMemo(() => ({
    total: recentLogs.length,
    open: recentLogs.filter(l => l.status !== 'done' && l.status !== 'in_progress').length,
    inProgress: recentLogs.filter(l => l.status === 'in_progress').length,
    resolved: recentLogs.filter(l => l.status === 'done').length,
  }), [recentLogs]);

  // Filtered logs
  const filteredLogs = useMemo(() => {
    let result = recentLogs;
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      result = result.filter(l => { const p = parseLog(l.content); return (p.pelanggan + l.title).toLowerCase().includes(q); });
    }
    if (filterStatus !== 'all') {
      if (filterStatus === 'open') result = result.filter(l => l.status !== 'done' && l.status !== 'in_progress');
      else if (filterStatus === 'in_progress') result = result.filter(l => l.status === 'in_progress');
      else if (filterStatus === 'resolved') result = result.filter(l => l.status === 'done');
    }
    return result;
  }, [recentLogs, searchQuery, filterStatus]);

  return (
    <div className="max-w-4xl mx-auto space-y-5">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-gradient-to-br from-amber-500 to-orange-600 text-white rounded-xl shadow-md">
            <MessageSquareWarning className="w-5 h-5" />
          </div>
          <div>
            <h2 className="text-lg font-bold text-gray-900 dark:text-white">Keluhan Pelanggan</h2>
            <p className="text-xs text-gray-500 dark:text-gray-400">Catat dan tangani komplain pelanggan</p>
          </div>
        </div>
        <Button variant="outline" size="sm" onClick={loadData} disabled={loadingLogs} className="gap-1.5">
          <RefreshCw className={`w-3.5 h-3.5 ${loadingLogs ? 'animate-spin' : ''}`} />
          Refresh
        </Button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        {[
          { label: 'Total Keluhan', value: statsData.total, icon: MessageSquareWarning, color: 'text-amber-500' },
          { label: 'Open', value: statsData.open, icon: XCircle, color: 'text-red-500' },
          { label: 'Dalam Proses', value: statsData.inProgress, icon: Clock, color: 'text-yellow-500' },
          { label: 'Resolved', value: statsData.resolved, icon: CheckCircle2, color: 'text-green-500' },
        ].map(({ label, value, icon: Icon, color }) => (
          <Card key={label} className={`border dark:border-gray-700 ${value > 0 && label === 'Open' ? 'border-red-200 dark:border-red-900' : ''}`}>
            <CardContent className="p-3 flex items-center gap-3">
              <div className={`p-2 rounded-lg bg-gray-100 dark:bg-gray-800 ${color}`}><Icon className="w-4 h-4" /></div>
              <div><p className="text-xs text-gray-500 dark:text-gray-400">{label}</p><p className="text-xl font-bold text-gray-900 dark:text-white">{value}</p></div>
            </CardContent>
          </Card>
        ))}
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="grid w-full grid-cols-2 mb-4">
          <TabsTrigger value="form" className="gap-2"><Send className="w-4 h-4" /> Catat Keluhan</TabsTrigger>
          <TabsTrigger value="logs" className="gap-2">
            <Eye className="w-4 h-4" /> Riwayat Keluhan
            {statsData.open > 0 && <Badge className="ml-1 bg-red-600 text-white text-xs px-1.5 py-0">{statsData.open} open</Badge>}
          </TabsTrigger>
        </TabsList>

        <TabsContent value="form">
          <Card className="border dark:border-gray-700 shadow-sm">
            <CardContent className="pt-6">
              <form onSubmit={handleSubmit} className="space-y-5">
                {/* Customer Section */}
                <div className="p-4 bg-gray-50 dark:bg-gray-800/50 rounded-xl space-y-3 border border-gray-200 dark:border-gray-700">
                  <div className="flex gap-2">
                    <Button type="button" size="sm" variant={!useExistingCustomer ? 'default' : 'outline'} onClick={() => setUseExistingCustomer(false)} className="gap-1.5">
                      <UserPlus className="w-3.5 h-3.5" /> Pelanggan Baru
                    </Button>
                    <Button type="button" size="sm" variant={useExistingCustomer ? 'default' : 'outline'} onClick={() => setUseExistingCustomer(true)} className="gap-1.5">
                      <Users className="w-3.5 h-3.5" /> Database ({customers.length})
                    </Button>
                  </div>
                  {useExistingCustomer ? (
                    <Select value={formData.customerId} onValueChange={(val) => {
                      const c = customers.find(x => x.id === val);
                      setFormData({ ...formData, customerId: val, customerName: c?.name || '', phone: c?.phone || '' });
                    }}>
                      <SelectTrigger><SelectValue placeholder="-- Pilih Pelanggan --" /></SelectTrigger>
                      <SelectContent>
                        {customers.map(c => <SelectItem key={c.id} value={c.id}>{c.name} ({c.phone})</SelectItem>)}
                      </SelectContent>
                    </Select>
                  ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                      <div className="space-y-1.5">
                        <Label className="text-sm">Nama Pelanggan <span className="text-red-500">*</span></Label>
                        <Input placeholder="Nama pelanggan/pasien" value={formData.customerName} onChange={(e) => { setFormData({ ...formData, customerName: e.target.value }); if (errors.customerName) setErrors({ ...errors, customerName: '' }); }} className={errors.customerName ? 'border-red-500' : ''} />
                        {errors.customerName && <p className="text-xs text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3" />{errors.customerName}</p>}
                      </div>
                      <div className="space-y-1.5">
                        <Label className="text-sm">No. Telepon / WA</Label>
                        <Input placeholder="08xxxxxxxxxx" value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value })} />
                      </div>
                    </div>
                  )}
                </div>

                {/* Handler */}
                <div className="space-y-1.5">
                  <Label className="text-sm">Ditangani Oleh (Terapis/PIC)</Label>
                  <Select value={formData.handledById} onValueChange={(val) => {
                    const m = employees.find(x => x.user_id === val || x.id === val);
                    setFormData({ ...formData, handledById: val, handledByName: m?.user_name || '' });
                  }}>
                    <SelectTrigger><SelectValue placeholder="-- Pilih Penanggung Jawab --" /></SelectTrigger>
                    <SelectContent>
                      {employees.map(m => <SelectItem key={m.id} value={m.user_id || m.id}>{m.user_name || m.user_email} ({m.role})</SelectItem>)}
                    </SelectContent>
                  </Select>
                </div>

                {/* Kategori + Status */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1.5">
                    <Label className="text-sm">Kategori Keluhan</Label>
                    <Select value={formData.complaintType} onValueChange={(val) => setFormData({ ...formData, complaintType: val })}>
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        {Object.entries(COMPLAINT_TYPES).map(([val, cfg]) => (
                          <SelectItem key={val} value={val}>
                            {cfg.icon} {cfg.label} {cfg.desc && <span className="text-gray-400">({cfg.desc})</span>}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    {formData.complaintType && (() => {
                      const cfg = COMPLAINT_TYPES[formData.complaintType];
                      return cfg ? <span className="text-xs text-gray-500 dark:text-gray-400">{cfg.icon} {cfg.label}</span> : null;
                    })()}
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-sm">Status Penanganan</Label>
                    <Select value={formData.status} onValueChange={(val) => setFormData({ ...formData, status: val })}>
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        {Object.entries(STATUS_CONFIG).map(([val, cfg]) => (
                          <SelectItem key={val} value={val}>{cfg.icon} {cfg.label === 'Resolved' ? 'Resolved (Selesai)' : val === 'open' ? 'Open (Belum Ditangani)' : 'Menunggu Tindak Lanjut'}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    {formData.status && (
                      <span className={`inline-flex items-center gap-1 text-xs px-2.5 py-1 rounded-full font-medium ${STATUS_CONFIG[formData.status]?.color}`}>
                        {STATUS_CONFIG[formData.status]?.icon} {STATUS_CONFIG[formData.status]?.label}
                      </span>
                    )}
                  </div>
                </div>

                {/* Detail Keluhan */}
                <div className="space-y-1.5">
                  <Label className="text-sm">Deskripsi Keluhan <span className="text-red-500">*</span></Label>
                  <Textarea
                    className={`min-h-[100px] resize-none ${errors.complaintDetail ? 'border-red-500' : ''}`}
                    placeholder="Tuliskan secara lengkap detail keluhan dari pelanggan..."
                    value={formData.complaintDetail}
                    onChange={(e) => { setFormData({ ...formData, complaintDetail: e.target.value }); if (errors.complaintDetail) setErrors({ ...errors, complaintDetail: '' }); }}
                  />
                  {errors.complaintDetail && <p className="text-xs text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3" />{errors.complaintDetail}</p>}
                </div>

                {/* Solusi */}
                <div className="space-y-1.5">
                  <Label className="text-sm text-gray-600 dark:text-gray-400">Solusi / Tindakan yang Diberikan <span className="text-xs font-normal">(opsional)</span></Label>
                  <Textarea className="min-h-[80px] resize-none" placeholder="Solusi apa yang sudah/akan diberikan?" value={formData.solution} onChange={(e) => setFormData({ ...formData, solution: e.target.value })} />
                </div>

                <Button type="submit" disabled={loading} className="w-full bg-gradient-to-r from-amber-600 to-orange-600 hover:from-amber-700 hover:to-orange-700 text-white font-semibold h-11 shadow-md">
                  {loading ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Menyimpan...</> : <><Send className="w-4 h-4 mr-2" /> Simpan Data Komplain</>}
                </Button>
              </form>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="logs">
          <Card className="border dark:border-gray-700 shadow-sm">
            <CardHeader className="pb-3">
              <div className="flex flex-col sm:flex-row gap-3">
                <div className="relative flex-1">
                  <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-gray-400" />
                  <Input placeholder="Cari pelanggan..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="pl-8 text-sm h-9" />
                </div>
                <Select value={filterStatus} onValueChange={setFilterStatus}>
                  <SelectTrigger className="w-full sm:w-44 h-9 text-sm">
                    <Filter className="w-3.5 h-3.5 mr-1.5 text-gray-400" />
                    <SelectValue placeholder="Status" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">Semua Status</SelectItem>
                    <SelectItem value="open">≡ƒö┤ Open</SelectItem>
                    <SelectItem value="in_progress">≡ƒƒí Dalam Proses</SelectItem>
                    <SelectItem value="resolved">≡ƒƒó Resolved</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <p className="text-xs text-gray-500 mt-2">{loadingLogs ? 'Memuat...' : `Menampilkan ${filteredLogs.length} dari ${recentLogs.length} keluhan`}</p>
            </CardHeader>
            <CardContent className="space-y-3 pt-0">
              {loadingLogs ? (
                <div className="flex items-center justify-center py-10">
                  <Loader2 className="w-6 h-6 animate-spin text-amber-500 mr-2" />
                  <span className="text-sm text-gray-500">Memuat log...</span>
                </div>
              ) : filteredLogs.length === 0 ? (
                <div className="text-center py-10 text-gray-400 dark:text-gray-600">
                  <MessageSquareWarning className="w-10 h-10 mx-auto mb-2 opacity-40" />
                  <p className="text-sm font-medium">{recentLogs.length === 0 ? 'Belum ada log keluhan' : 'Tidak ada keluhan yang cocok'}</p>
                </div>
              ) : (
                filteredLogs.map(log => <LogCard key={log.id} log={log} />)
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { toast } from "sonner";
import { Loader2, Radio, Send, Users, Eye, ChevronDown, ChevronUp, Clock, DollarSign, RefreshCw, AlertCircle, Link as LinkIcon } from "lucide-react";
import { base44 } from '@/api/base44Client';
import { format, isToday } from 'date-fns';
import { id as localeId } from 'date-fns/locale';

const PLATFORMS = [
  { value: 'TikTok Live', icon: '≡ƒÄ╡', color: 'bg-black text-white' },
  { value: 'Shopee Live', icon: '≡ƒ¢Æ', color: 'bg-orange-500 text-white' },
  { value: 'Instagram Live', icon: '≡ƒô╕', color: 'bg-pink-500 text-white' },
  { value: 'YouTube Live', icon: 'Γû╢∩╕Å', color: 'bg-red-600 text-white' },
  { value: 'Facebook Live', icon: '≡ƒæÑ', color: 'bg-blue-600 text-white' },
  { value: 'Lazada Live', icon: '≡ƒ¢ì∩╕Å', color: 'bg-blue-700 text-white' },
];

function parseLog(content = '') {
  const lines = content.split('\n');
  const get = (p) => lines.find(l => l.startsWith(p))?.replace(p, '').trim() || '';
  const catatanIdx = lines.findIndex(l => l === 'Catatan:');
  const catatan = catatanIdx !== -1 ? lines.slice(catatanIdx + 1).join('\n').trim() : get('Catatan:');
  return { platform: get('Platform:'), host: get('Host:'), durasi: get('Durasi:'), penonton: get('Penonton:'), omset: get('Omset:'), link: get('Link Live:'), catatan };
}

function LogCard({ log }) {
  const [expanded, setExpanded] = useState(false);
  const parsed = useMemo(() => parseLog(log.content), [log.content]);
  const platformCfg = PLATFORMS.find(p => p.value === parsed.platform);

  return (
    <div className="border border-gray-200 dark:border-gray-700 rounded-xl overflow-hidden bg-white dark:bg-gray-800 shadow-sm hover:shadow-md transition-shadow">
      <div className="flex items-start gap-3 p-4">
        {platformCfg && (
          <div className={`w-9 h-9 rounded-xl flex items-center justify-center text-lg flex-shrink-0 ${platformCfg.color}`}>
            {platformCfg.icon}
          </div>
        )}
        <div className="flex-1 min-w-0">
          <p className="font-semibold text-sm text-gray-900 dark:text-gray-100">{log.title}</p>
          <div className="flex flex-wrap gap-3 mt-1 text-xs text-gray-500 dark:text-gray-400">
            {parsed.host && <span>≡ƒÄÖ∩╕Å {parsed.host}</span>}
            {parsed.durasi && <span>ΓÅ▒∩╕Å {parsed.durasi}</span>}
            {parsed.penonton && <span>≡ƒæÑ {parsed.penonton}</span>}
            {parsed.omset && <span className="font-semibold text-green-600 dark:text-green-400">≡ƒÆ░ {parsed.omset}</span>}
          </div>
          <span className="text-xs text-gray-400 dark:text-gray-500 mt-1 block">
            {log.created_date ? format(new Date(log.created_date), 'dd MMM yyyy ┬╖ HH:mm', { locale: localeId }) : ''}
          </span>
        </div>
        <button onClick={() => setExpanded(v => !v)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 p-1 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 flex-shrink-0">
          {expanded ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
        </button>
      </div>
      {expanded && parsed.catatan && (
        <div className="px-4 pb-4 border-t border-gray-100 dark:border-gray-700 pt-3">
          <p className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Evaluasi</p>
          <p className="text-sm text-gray-700 dark:text-gray-300 whitespace-pre-wrap bg-gray-50 dark:bg-gray-700/50 rounded-lg p-3">{parsed.catatan}</p>
          {parsed.link && parsed.link !== '-' && (
            <a href={parsed.link} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1.5 text-xs text-blue-500 hover:underline mt-2">
              <LinkIcon className="w-3 h-3" /> {parsed.link}
            </a>
          )}
        </div>
      )}
    </div>
  );
}

export default function FormLiveStreaming({ workspace, user }) {
  const [loading, setLoading] = useState(false);
  const [loadingLogs, setLoadingLogs] = useState(false);
  const [employees, setEmployees] = useState([]);
  const [recentLogs, setRecentLogs] = useState([]);
  const [activeTab, setActiveTab] = useState('form');
  const [errors, setErrors] = useState({});
  const [formData, setFormData] = useState({
    platform: '', hostId: '', hostName: '', liveLink: '',
    duration: '', viewers: '', turnover: '', notes: ''
  });

  useEffect(() => { loadData(); }, [workspace?.company_id]);

  const loadData = async () => {
    if (!workspace?.company_id) return;
    setLoadingLogs(true);
    try {
      const [members, tasks] = await Promise.all([
        base44.entities.CompanyMember.filter({ company_id: workspace.company_id, status: 'active' }),
        base44.entities.Task.filter({ workspace_id: workspace.id })
      ]);
      setEmployees(members || []);
      setRecentLogs((tasks || []).filter(t => t.task_type === 'live_streaming_log').sort((a, b) => new Date(b.created_date) - new Date(a.created_date)));
    } catch (e) { console.warn('load data error:', e); }
    finally { setLoadingLogs(false); }
  };

  const validate = () => {
    const errs = {};
    if (!formData.platform) errs.platform = 'Platform wajib dipilih';
    if (!formData.hostId) errs.hostId = 'Host wajib dipilih';
    if (!formData.duration) errs.duration = 'Durasi wajib diisi';
    setErrors(errs);
    return Object.keys(errs).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validate()) return;
    setLoading(true);
    try {
      const omsetFormatted = formData.turnover ? `Rp ${Number(formData.turnover).toLocaleString('id-ID')}` : 'Rp 0';
      const taskBody = `Platform: ${formData.platform}\nHost: ${formData.hostName}\nLink Live: ${formData.liveLink || '-'}\nDurasi: ${formData.duration} Jam\nPenonton: ${formData.viewers} Views\nOmset: ${omsetFormatted}\n\nCatatan:\n${formData.notes}`;
      await base44.entities.Task.create({
        title: `Live (${formData.platform}) - ${formData.hostName} - ${format(new Date(), 'dd/MM/yyyy', { locale: localeId })}`,
        content: taskBody, workspace_id: workspace.id, created_by: user?.email,
        company_id: workspace.company_id || null, assignee_id: formData.hostId || null,
        status: 'done', priority: 'medium', task_type: 'live_streaming_log'
      });
      toast.success('Data Live Streaming berhasil disimpan! ≡ƒö┤', { description: `${formData.platform} ┬╖ ${formData.hostName}` });
      setFormData({ platform: '', hostId: '', hostName: '', liveLink: '', duration: '', viewers: '', turnover: '', notes: '' });
      setErrors({});
      loadData();
      window.dispatchEvent(new CustomEvent('taskCreated', { detail: { workspaceId: workspace.id } }));
    } catch (error) {
      toast.error('Gagal menyimpan data live streaming');
    } finally { setLoading(false); }
  };

  // Stats
  const statsData = useMemo(() => {
    const totalOmset = recentLogs.reduce((sum, l) => {
      const p = parseLog(l.content);
      const cleaned = (p.omset || '').replace(/[^0-9]/g, '');
      return sum + (parseInt(cleaned) || 0);
    }, 0);
    return {
      total: recentLogs.length,
      today: recentLogs.filter(l => l.created_date && isToday(new Date(l.created_date))).length,
      totalOmset,
      avgViewers: recentLogs.length > 0 ? Math.round(recentLogs.reduce((sum, l) => {
        const p = parseLog(l.content);
        return sum + (parseInt(p.penonton) || 0);
      }, 0) / recentLogs.length) : 0,
    };
  }, [recentLogs]);

  return (
    <div className="max-w-4xl mx-auto space-y-5">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-gradient-to-br from-red-500 to-rose-600 text-white rounded-xl shadow-md">
            <div className="animate-pulse"><Radio className="w-5 h-5" /></div>
          </div>
          <div>
            <h2 className="text-lg font-bold text-gray-900 dark:text-white">Live Streaming</h2>
            <p className="text-xs text-gray-500 dark:text-gray-400">Rekap performa sesi live streaming</p>
          </div>
        </div>
        <Button variant="outline" size="sm" onClick={loadData} disabled={loadingLogs} className="gap-1.5">
          <RefreshCw className={`w-3.5 h-3.5 ${loadingLogs ? 'animate-spin' : ''}`} />
          Refresh
        </Button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        {[
          { label: 'Total Sesi', value: statsData.total, icon: Radio, color: 'text-red-500' },
          { label: 'Hari Ini', value: statsData.today, icon: Clock, color: 'text-indigo-500' },
          { label: 'Total Omset', value: statsData.totalOmset > 0 ? `Rp ${(statsData.totalOmset / 1000000).toFixed(1)}jt` : 'Rp 0', icon: DollarSign, color: 'text-green-500' },
          { label: 'Rata Penonton', value: statsData.avgViewers, icon: Users, color: 'text-blue-500' },
        ].map(({ label, value, icon: Icon, color }) => (
          <Card key={label} className="border dark:border-gray-700">
            <CardContent className="p-3 flex items-center gap-3">
              <div className={`p-2 rounded-lg bg-gray-100 dark:bg-gray-800 ${color}`}><Icon className="w-4 h-4" /></div>
              <div><p className="text-xs text-gray-500 dark:text-gray-400">{label}</p><p className="text-xl font-bold text-gray-900 dark:text-white">{value}</p></div>
            </CardContent>
          </Card>
        ))}
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="grid w-full grid-cols-2 mb-4">
          <TabsTrigger value="form" className="gap-2"><Send className="w-4 h-4" /> Input Laporan Live</TabsTrigger>
          <TabsTrigger value="logs" className="gap-2">
            <Eye className="w-4 h-4" /> Riwayat Log
            {recentLogs.length > 0 && <Badge className="ml-1 bg-red-600 text-white text-xs px-1.5 py-0">{recentLogs.length}</Badge>}
          </TabsTrigger>
        </TabsList>

        <TabsContent value="form">
          <Card className="border dark:border-gray-700 shadow-sm">
            <CardContent className="pt-6">
              <form onSubmit={handleSubmit} className="space-y-5">
                {/* Platform + Host */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1.5">
                    <Label className="text-sm">Platform <span className="text-red-500">*</span></Label>
                    <Select value={formData.platform} onValueChange={(val) => { setFormData({ ...formData, platform: val }); if (errors.platform) setErrors({ ...errors, platform: '' }); }}>
                      <SelectTrigger className={errors.platform ? 'border-red-500' : ''}><SelectValue placeholder="-- Pilih Platform --" /></SelectTrigger>
                      <SelectContent>
                        {PLATFORMS.map(p => <SelectItem key={p.value} value={p.value}>{p.icon} {p.value}</SelectItem>)}
                      </SelectContent>
                    </Select>
                    {errors.platform && <p className="text-xs text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3" />{errors.platform}</p>}
                    {/* Platform preview */}
                    {formData.platform && (() => {
                      const p = PLATFORMS.find(x => x.value === formData.platform);
                      return p ? (
                        <div className={`inline-flex items-center gap-1.5 text-xs px-2.5 py-1 rounded-full font-medium ${p.color}`}>
                          {p.icon} {p.value}
                        </div>
                      ) : null;
                    })()}
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-sm">Nama Host <span className="text-red-500">*</span></Label>
                    <Select value={formData.hostId} onValueChange={(val) => {
                      const m = employees.find(x => x.user_id === val || x.id === val);
                      setFormData({ ...formData, hostId: val, hostName: m?.user_name || val });
                      if (errors.hostId) setErrors({ ...errors, hostId: '' });
                    }}>
                      <SelectTrigger className={errors.hostId ? 'border-red-500' : ''}><SelectValue placeholder="-- Pilih Host --" /></SelectTrigger>
                      <SelectContent>
                        {employees.map(m => <SelectItem key={m.id} value={m.user_id || m.id}>{m.user_name || m.user_email}</SelectItem>)}
                      </SelectContent>
                    </Select>
                    {errors.hostId && <p className="text-xs text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3" />{errors.hostId}</p>}
                  </div>
                </div>

                {/* Link */}
                <div className="space-y-1.5">
                  <Label className="text-sm flex items-center gap-1.5"><LinkIcon className="w-3.5 h-3.5 text-blue-500" /> Link Live / Bukti Streaming</Label>
                  <Input placeholder="https://..." value={formData.liveLink} onChange={(e) => setFormData({ ...formData, liveLink: e.target.value })} />
                </div>

                {/* Metrics */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="space-y-1.5">
                    <Label className="text-sm">Durasi (Jam) <span className="text-red-500">*</span></Label>
                    <Input type="number" min="0" step="0.5" placeholder="Contoh: 2" value={formData.duration} onChange={(e) => { setFormData({ ...formData, duration: e.target.value }); if (errors.duration) setErrors({ ...errors, duration: '' }); }} className={errors.duration ? 'border-red-500' : ''} />
                    {errors.duration && <p className="text-xs text-red-500">{errors.duration}</p>}
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-sm flex items-center gap-1.5"><Users className="w-3.5 h-3.5 text-blue-500" /> Total Penonton</Label>
                    <Input type="number" min="0" placeholder="0" value={formData.viewers} onChange={(e) => setFormData({ ...formData, viewers: e.target.value })} />
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-sm flex items-center gap-1.5"><DollarSign className="w-3.5 h-3.5 text-green-500" /> Total Omset (Rp)</Label>
                    <Input type="number" min="0" placeholder="500000" value={formData.turnover} onChange={(e) => setFormData({ ...formData, turnover: e.target.value })} />
                    {formData.turnover && (
                      <p className="text-xs text-green-600 dark:text-green-400 font-medium">
                        Rp {Number(formData.turnover).toLocaleString('id-ID')}
                      </p>
                    )}
                  </div>
                </div>

                {/* Catatan */}
                <div className="space-y-1.5">
                  <Label className="text-sm">Catatan Performa / Evaluasi</Label>
                  <Textarea className="min-h-[90px] resize-none" placeholder="Evaluasi performa live (kendala, produk terlaris, masukan penonton)..." value={formData.notes} onChange={(e) => setFormData({ ...formData, notes: e.target.value })} />
                </div>

                <Button type="submit" disabled={loading} className="w-full bg-gradient-to-r from-red-600 to-rose-600 hover:from-red-700 hover:to-rose-700 text-white font-semibold h-11 shadow-md">
                  {loading ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Menyimpan...</> : <><Send className="w-4 h-4 mr-2" /> Simpan Laporan Live</>}
                </Button>
              </form>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="logs">
          <Card className="border dark:border-gray-700 shadow-sm">
            <CardHeader className="pb-3">
              <p className="text-xs text-gray-500">{loadingLogs ? 'Memuat...' : `${recentLogs.length} sesi live streaming`}</p>
            </CardHeader>
            <CardContent className="space-y-3 pt-0">
              {loadingLogs ? (
                <div className="flex items-center justify-center py-10">
                  <Loader2 className="w-6 h-6 animate-spin text-red-500 mr-2" />
                  <span className="text-sm text-gray-500">Memuat log...</span>
                </div>
              ) : recentLogs.length === 0 ? (
                <div className="text-center py-10 text-gray-400 dark:text-gray-600">
                  <Radio className="w-10 h-10 mx-auto mb-2 opacity-40" />
                  <p className="text-sm font-medium">Belum ada log live streaming</p>
                </div>
              ) : (
                recentLogs.map(log => <LogCard key={log.id} log={log} />)
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { toast } from "sonner";
import { Loader2, Send, Tag, Users, UserPlus, Package, Search, Filter, Eye, ChevronDown, ChevronUp, TrendingUp, CheckCircle2, Clock, RefreshCw, AlertCircle } from "lucide-react";
import { base44 } from '@/api/base44Client';
import { format, isToday } from 'date-fns';
import { id as localeId } from 'date-fns/locale';

const STATUS_CONFIG = {
  follow_up: { label: 'Perlu Follow Up', icon: '≡ƒöä', color: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/40 dark:text-yellow-300' },
  menunggu_jawaban: { label: 'Menunggu Jawaban', icon: 'ΓÅ│', color: 'bg-blue-100 text-blue-800 dark:bg-blue-900/40 dark:text-blue-300' },
  closing: { label: 'Closing', icon: 'Γ£à', color: 'bg-green-100 text-green-800 dark:bg-green-900/40 dark:text-green-300' },
  gagal: { label: 'Gagal/Ditolak', icon: 'Γ¥î', color: 'bg-red-100 text-red-800 dark:bg-red-900/40 dark:text-red-300' },
};

function parseLog(content = '') {
  const lines = content.split('\n');
  const get = (p) => lines.find(l => l.startsWith(p))?.replace(p, '').trim() || '';
  const catatanIdx = lines.findIndex(l => l === 'Catatan:');
  const catatan = catatanIdx !== -1 ? lines.slice(catatanIdx + 1).join('\n').trim() : get('Catatan:');
  return { klien: get('Nama Klien:'), wa: get('No Whatsapp:'), pic: get('PIC:'), produk: get('Produk Ditawarkan:'), status: get('Status:'), catatan };
}

function LogCard({ log }) {
  const [expanded, setExpanded] = useState(false);
  const parsed = useMemo(() => parseLog(log.content), [log.content]);
  const cfg = STATUS_CONFIG[parsed.status] || { label: parsed.status, icon: 'Γ¥ô', color: 'bg-gray-100 text-gray-700' };
  const isDone = log.status === 'done';

  return (
    <div className="border border-gray-200 dark:border-gray-700 rounded-xl overflow-hidden bg-white dark:bg-gray-800 shadow-sm hover:shadow-md transition-shadow">
      <div className="flex items-start justify-between gap-2 p-4">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap mb-1">
            <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${isDone ? 'bg-green-100 text-green-800 dark:bg-green-900/40 dark:text-green-300' : 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/40 dark:text-yellow-300'}`}>
              {isDone ? 'Γ£à Closing' : '≡ƒöä Proses'}
            </span>
            {parsed.status && <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${cfg.color}`}>{cfg.icon} {cfg.label}</span>}
          </div>
          <p className="font-semibold text-sm text-gray-900 dark:text-gray-100 truncate">{log.title}</p>
          <div className="flex flex-wrap gap-3 mt-1 text-xs text-gray-500 dark:text-gray-400">
            {parsed.klien && <span>≡ƒæñ {parsed.klien}</span>}
            {parsed.wa && parsed.wa !== '-' && <span>≡ƒô▒ {parsed.wa}</span>}
            {parsed.pic && parsed.pic !== '-' && <span>≡ƒÅ╖∩╕Å {parsed.pic}</span>}
            {parsed.produk && <span>≡ƒôª {parsed.produk}</span>}
          </div>
          <span className="text-xs text-gray-400 dark:text-gray-500 mt-1 block">
            {log.created_date ? format(new Date(log.created_date), 'dd MMM yyyy ┬╖ HH:mm', { locale: localeId }) : ''}
          </span>
        </div>
        <button onClick={() => setExpanded(v => !v)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 p-1 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 flex-shrink-0">
          {expanded ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
        </button>
      </div>
      {expanded && parsed.catatan && (
        <div className="px-4 pb-4 border-t border-gray-100 dark:border-gray-700 pt-3">
          <p className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-1">Catatan</p>
          <p className="text-sm text-gray-700 dark:text-gray-300 whitespace-pre-wrap bg-gray-50 dark:bg-gray-700/50 rounded-lg p-3">{parsed.catatan}</p>
        </div>
      )}
    </div>
  );
}

export default function FormPenawaran({ workspace, user }) {
  const [loading, setLoading] = useState(false);
  const [loadingLogs, setLoadingLogs] = useState(false);
  const [customers, setCustomers] = useState([]);
  const [products, setProducts] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [recentLogs, setRecentLogs] = useState([]);
  const [useExistingCustomer, setUseExistingCustomer] = useState(false);
  const [activeTab, setActiveTab] = useState('form');
  const [searchQuery, setSearchQuery] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');
  const [errors, setErrors] = useState({});
  const [formData, setFormData] = useState({
    customerId: '', clientName: '', phone: '', picId: '', picName: '',
    productOffered: '', productId: '', status: 'follow_up', notes: ''
  });

  useEffect(() => { loadData(); }, [workspace?.company_id]);

  const loadData = async () => {
    if (!workspace?.company_id) return;
    setLoadingLogs(true);
    try {
      const [custs, prods, members, tasks] = await Promise.all([
        base44.entities.Customer.filter({ company_id: workspace.company_id }),
        base44.entities.CompanyPOSProduct.filter({ company_id: workspace.company_id, is_active: true }),
        base44.entities.CompanyMember.filter({ company_id: workspace.company_id, status: 'active' }),
        base44.entities.Task.filter({ workspace_id: workspace.id })
      ]);
      setCustomers(custs || []);
      setProducts(prods || []);
      setEmployees(members || []);
      setRecentLogs((tasks || []).filter(t => t.task_type === 'penawaran_log').sort((a, b) => new Date(b.created_date) - new Date(a.created_date)));
    } catch (e) { console.warn('load data error:', e); }
    finally { setLoadingLogs(false); }
  };

  const validate = () => {
    const errs = {};
    if (!formData.clientName) errs.clientName = 'Nama klien wajib diisi';
    if (!formData.notes.trim()) errs.notes = 'Catatan hasil penawaran wajib diisi';
    setErrors(errs);
    return Object.keys(errs).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validate()) return;
    setLoading(true);
    try {
      if (!useExistingCustomer && formData.clientName && formData.phone) {
        const existing = customers.find(c => c.phone === formData.phone);
        if (!existing) {
          await base44.entities.Customer.create({ company_id: workspace.company_id, name: formData.clientName, phone: formData.phone, whatsapp_number: formData.phone, status: 'prospect', total_orders: 0 });
          toast.info(`${formData.clientName} ditambahkan ke database pelanggan`);
        }
      }
      const taskBody = `Nama Klien: ${formData.clientName}\nNo Whatsapp: ${formData.phone}\nPIC: ${formData.picName || '-'}\nProduk Ditawarkan: ${formData.productOffered}\nStatus: ${formData.status}\n\nCatatan:\n${formData.notes}`;
      await base44.entities.Task.create({
        title: `Penawaran: ${formData.clientName} - ${formData.productOffered || 'Produk'}`,
        content: taskBody, workspace_id: workspace.id, created_by: user?.email,
        company_id: workspace.company_id || null, assignee_id: formData.picId || null,
        status: formData.status === 'closing' ? 'done' : 'in_progress', priority: 'high', task_type: 'penawaran_log'
      });
      toast.success('Data penawaran berhasil disimpan! ≡ƒñ¥', { description: `${formData.clientName} - ${STATUS_CONFIG[formData.status]?.label}` });
      setFormData({ customerId: '', clientName: '', phone: '', picId: '', picName: '', productOffered: '', productId: '', status: 'follow_up', notes: '' });
      setErrors({});
      setUseExistingCustomer(false);
      loadData();
      window.dispatchEvent(new CustomEvent('taskCreated', { detail: { workspaceId: workspace.id } }));
    } catch (error) {
      toast.error('Gagal menyimpan data penawaran');
    } finally { setLoading(false); }
  };

  // Stats
  const statsData = useMemo(() => ({
    total: recentLogs.length,
    closing: recentLogs.filter(l => { const p = parseLog(l.content); return p.status === 'closing'; }).length,
    followUp: recentLogs.filter(l => { const p = parseLog(l.content); return p.status === 'follow_up'; }).length,
    today: recentLogs.filter(l => l.created_date && isToday(new Date(l.created_date))).length,
  }), [recentLogs]);

  // Filtered logs
  const filteredLogs = useMemo(() => {
    let result = recentLogs;
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      result = result.filter(l => { const p = parseLog(l.content); return (p.klien + p.produk + l.title).toLowerCase().includes(q); });
    }
    if (filterStatus !== 'all') {
      result = result.filter(l => { const p = parseLog(l.content); return p.status === filterStatus; });
    }
    return result;
  }, [recentLogs, searchQuery, filterStatus]);

  return (
    <div className="max-w-4xl mx-auto space-y-5">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-gradient-to-br from-emerald-500 to-teal-600 text-white rounded-xl shadow-md">
            <Tag className="w-5 h-5" />
          </div>
          <div>
            <h2 className="text-lg font-bold text-gray-900 dark:text-white">Penawaran Produk</h2>
            <p className="text-xs text-gray-500 dark:text-gray-400">Catat dan pantau penawaran ke klien</p>
          </div>
        </div>
        <Button variant="outline" size="sm" onClick={loadData} disabled={loadingLogs} className="gap-1.5">
          <RefreshCw className={`w-3.5 h-3.5 ${loadingLogs ? 'animate-spin' : ''}`} />
          Refresh
        </Button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        {[
          { label: 'Total Log', value: statsData.total, icon: Tag, color: 'text-emerald-500' },
          { label: 'Hari Ini', value: statsData.today, icon: Clock, color: 'text-indigo-500' },
          { label: 'Closing', value: statsData.closing, icon: CheckCircle2, color: 'text-green-500' },
          { label: 'Follow Up', value: statsData.followUp, icon: TrendingUp, color: 'text-yellow-500' },
        ].map(({ label, value, icon: Icon, color }) => (
          <Card key={label} className="border dark:border-gray-700">
            <CardContent className="p-3 flex items-center gap-3">
              <div className={`p-2 rounded-lg bg-gray-100 dark:bg-gray-800 ${color}`}><Icon className="w-4 h-4" /></div>
              <div><p className="text-xs text-gray-500 dark:text-gray-400">{label}</p><p className="text-xl font-bold text-gray-900 dark:text-white">{value}</p></div>
            </CardContent>
          </Card>
        ))}
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="grid w-full grid-cols-2 mb-4">
          <TabsTrigger value="form" className="gap-2"><Send className="w-4 h-4" /> Input Penawaran</TabsTrigger>
          <TabsTrigger value="logs" className="gap-2">
            <Eye className="w-4 h-4" /> Riwayat Log
            {recentLogs.length > 0 && <Badge className="ml-1 bg-emerald-600 text-white text-xs px-1.5 py-0">{recentLogs.length}</Badge>}
          </TabsTrigger>
        </TabsList>

        <TabsContent value="form">
          <Card className="border dark:border-gray-700 shadow-sm">
            <CardContent className="pt-6">
              <form onSubmit={handleSubmit} className="space-y-5">
                {/* Customer toggle */}
                <div className="p-4 bg-gray-50 dark:bg-gray-800/50 rounded-xl space-y-3 border border-gray-200 dark:border-gray-700">
                  <div className="flex gap-2">
                    <Button type="button" size="sm" variant={!useExistingCustomer ? 'default' : 'outline'} onClick={() => setUseExistingCustomer(false)} className="gap-1.5">
                      <UserPlus className="w-3.5 h-3.5" /> Klien Baru
                    </Button>
                    <Button type="button" size="sm" variant={useExistingCustomer ? 'default' : 'outline'} onClick={() => setUseExistingCustomer(true)} className="gap-1.5">
                      <Users className="w-3.5 h-3.5" /> Database ({customers.length})
                    </Button>
                  </div>
                  {useExistingCustomer ? (
                    <div className="space-y-1.5">
                      <Label className="text-sm">Pilih Klien dari Database</Label>
                      <Select value={formData.customerId} onValueChange={(val) => {
                        const c = customers.find(x => x.id === val);
                        setFormData({ ...formData, customerId: val, clientName: c?.name || '', phone: c?.phone || '' });
                      }}>
                        <SelectTrigger><SelectValue placeholder="-- Pilih Pelanggan --" /></SelectTrigger>
                        <SelectContent>
                          {customers.map(c => <SelectItem key={c.id} value={c.id}>{c.name} ({c.phone})</SelectItem>)}
                        </SelectContent>
                      </Select>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                      <div className="space-y-1.5">
                        <Label className="text-sm">Nama Klien <span className="text-red-500">*</span></Label>
                        <Input placeholder="Nama klien/target" value={formData.clientName} onChange={(e) => { setFormData({ ...formData, clientName: e.target.value }); if (errors.clientName) setErrors({ ...errors, clientName: '' }); }} className={errors.clientName ? 'border-red-500' : ''} />
                        {errors.clientName && <p className="text-xs text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3" />{errors.clientName}</p>}
                      </div>
                      <div className="space-y-1.5">
                        <Label className="text-sm">No. WA / Telepon</Label>
                        <Input placeholder="08xxxxxxxxxx" value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value })} />
                      </div>
                    </div>
                  )}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1.5">
                    <Label className="text-sm flex items-center gap-1.5"><Package className="w-3.5 h-3.5 text-teal-500" /> Produk Ditawarkan</Label>
                    <Select value={formData.productId} onValueChange={(val) => {
                      const p = products.find(x => x.id === val);
                      setFormData({ ...formData, productId: val, productOffered: p?.name || '' });
                    }}>
                      <SelectTrigger><SelectValue placeholder="-- Pilih Produk --" /></SelectTrigger>
                      <SelectContent>
                        {products.map(p => <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>)}
                        <SelectItem value="manual">+ Ketik Manual</SelectItem>
                      </SelectContent>
                    </Select>
                    {formData.productId === 'manual' && (
                      <Input placeholder="Nama produk..." value={formData.productOffered} onChange={(e) => setFormData({ ...formData, productOffered: e.target.value })} />
                    )}
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-sm">PIC / Petugas Penawaran</Label>
                    <Select value={formData.picId} onValueChange={(val) => {
                      const m = employees.find(x => x.user_id === val || x.id === val);
                      setFormData({ ...formData, picId: val, picName: m?.user_name || '' });
                    }}>
                      <SelectTrigger><SelectValue placeholder="-- Pilih PIC --" /></SelectTrigger>
                      <SelectContent>
                        {employees.map(m => <SelectItem key={m.id} value={m.user_id || m.id}>{m.user_name || m.user_email}</SelectItem>)}
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="space-y-1.5">
                  <Label className="text-sm">Status Penawaran</Label>
                  <Select value={formData.status} onValueChange={(val) => setFormData({ ...formData, status: val })}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>
                      {Object.entries(STATUS_CONFIG).map(([val, cfg]) => (
                        <SelectItem key={val} value={val}>{cfg.icon} {cfg.label}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {formData.status && (
                    <span className={`inline-flex items-center gap-1 text-xs px-2.5 py-1 rounded-full font-medium ${STATUS_CONFIG[formData.status]?.color}`}>
                      {STATUS_CONFIG[formData.status]?.icon} {STATUS_CONFIG[formData.status]?.label}
                    </span>
                  )}
                </div>

                <div className="space-y-1.5">
                  <Label className="text-sm">Catatan Hasil Penawaran <span className="text-red-500">*</span></Label>
                  <Textarea
                    className={`min-h-[100px] resize-none ${errors.notes ? 'border-red-500' : ''}`}
                    placeholder="Respon klien, alasan menolak, atau catatan keberhasilan..."
                    value={formData.notes}
                    onChange={(e) => { setFormData({ ...formData, notes: e.target.value }); if (errors.notes) setErrors({ ...errors, notes: '' }); }}
                  />
                  {errors.notes && <p className="text-xs text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3" />{errors.notes}</p>}
                </div>

                <Button type="submit" disabled={loading} className="w-full bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-700 hover:to-teal-700 text-white font-semibold h-11 shadow-md">
                  {loading ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Menyimpan...</> : <><Send className="w-4 h-4 mr-2" /> Simpan Data Penawaran</>}
                </Button>
              </form>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="logs">
          <Card className="border dark:border-gray-700 shadow-sm">
            <CardHeader className="pb-3">
              <div className="flex flex-col sm:flex-row gap-3">
                <div className="relative flex-1">
                  <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-gray-400" />
                  <Input placeholder="Cari klien atau produk..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="pl-8 text-sm h-9" />
                </div>
                <Select value={filterStatus} onValueChange={setFilterStatus}>
                  <SelectTrigger className="w-full sm:w-44 h-9 text-sm">
                    <Filter className="w-3.5 h-3.5 mr-1.5 text-gray-400" />
                    <SelectValue placeholder="Status" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">Semua Status</SelectItem>
                    {Object.entries(STATUS_CONFIG).map(([val, cfg]) => (
                      <SelectItem key={val} value={val}>{cfg.icon} {cfg.label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <p className="text-xs text-gray-500 mt-2">{loadingLogs ? 'Memuat...' : `Menampilkan ${filteredLogs.length} dari ${recentLogs.length} log`}</p>
            </CardHeader>
            <CardContent className="space-y-3 pt-0">
              {loadingLogs ? (
                <div className="flex items-center justify-center py-10">
                  <Loader2 className="w-6 h-6 animate-spin text-emerald-500 mr-2" />
                  <span className="text-sm text-gray-500">Memuat log...</span>
                </div>
              ) : filteredLogs.length === 0 ? (
                <div className="text-center py-10 text-gray-400 dark:text-gray-600">
                  <Tag className="w-10 h-10 mx-auto mb-2 opacity-40" />
                  <p className="text-sm font-medium">Belum ada log penawaran</p>
                </div>
              ) : (
                filteredLogs.map(log => <LogCard key={log.id} log={log} />)
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState } from 'react';
import { DragDropContext, Droppable, Draggable } from '@hello-pangea/dnd';
import TaskDetailModal from './TaskDetailModal';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { Plus, Calendar, GripVertical } from 'lucide-react';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';
import { Task } from '@/entities/Task';
import { User as UserEntity } from '@/entities/User';
import { toast } from 'sonner';
import { isPast } from 'date-fns';

const priorityConfig = {
  low: { color: 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-300', dot: 'bg-gray-400', label: 'Rendah' },
  medium: { color: 'bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-300', dot: 'bg-blue-400', label: 'Sedang' },
  high: { color: 'bg-orange-100 text-orange-700 dark:bg-orange-900/40 dark:text-orange-300', dot: 'bg-orange-400', label: 'Tinggi' },
  urgent: { color: 'bg-red-100 text-red-700 dark:bg-red-900/40 dark:text-red-300', dot: 'bg-red-500', label: 'Urgent' }
};

const columns = [
  { id: 'todo', title: 'Belum Mulai', color: '#64748b', bgClass: 'bg-slate-50 dark:bg-slate-900/30', borderClass: 'border-slate-200 dark:border-slate-700', dotClass: 'bg-slate-400' },
  { id: 'in_progress', title: 'Sedang Dikerjakan', color: '#3b82f6', bgClass: 'bg-blue-50 dark:bg-blue-950/30', borderClass: 'border-blue-200 dark:border-blue-800', dotClass: 'bg-blue-500' },
  { id: 'review', title: 'Review', color: '#f59e0b', bgClass: 'bg-amber-50 dark:bg-amber-950/30', borderClass: 'border-amber-200 dark:border-amber-800', dotClass: 'bg-amber-500' },
  { id: 'done', title: 'Selesai', color: '#10b981', bgClass: 'bg-green-50 dark:bg-green-950/30', borderClass: 'border-green-200 dark:border-green-800', dotClass: 'bg-green-500' }
];

function TaskCard({ task, onClick, companyMembers = [] }) {
  const priority = priorityConfig[task.priority] || priorityConfig.medium;
  const isOverdue = task.due_date && isPast(new Date(task.due_date)) && task.status !== 'done';
  const assignee = companyMembers.find(m => m.user_id === task.assignee_id || m.user_email === task.assignee_id);
  const assigneeName = assignee?.user_name || task.assignee_id?.split('@')[0] || '';

  return (
    <div
      className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-3.5 mb-2.5 hover:shadow-md hover:border-blue-300 dark:hover:border-blue-700 transition-all cursor-pointer group"
      onClick={() => onClick(task)}
    >
      {/* Priority + Overdue indicator */}
      <div className="flex items-center justify-between mb-2">
        <span className={`inline-flex items-center gap-1 text-[10px] font-semibold px-1.5 py-0.5 rounded-full ${priority.color}`}>
          <span className={`w-1.5 h-1.5 rounded-full ${priority.dot}`} />
          {priority.label}
        </span>
        <GripVertical className="w-3.5 h-3.5 text-gray-300 dark:text-gray-600 opacity-0 group-hover:opacity-100 transition-opacity" />
      </div>

      {/* Title */}
      <h4 className={`font-semibold text-sm leading-snug mb-2 ${task.status === 'done' ? 'line-through text-gray-400 dark:text-gray-500' : 'text-gray-900 dark:text-gray-100'}`}>
        {task.title}
      </h4>

      {/* Content preview */}
      {task.content && !['briefing_log', 'penawaran_log', 'live_streaming_log', 'complain_log'].includes(task.task_type) && (
        <p className="text-xs text-gray-500 dark:text-gray-400 mb-2.5 line-clamp-2 leading-relaxed">{task.content}</p>
      )}

      {/* Tags */}
      {task.tags && task.tags.length > 0 && (
        <div className="flex flex-wrap gap-1 mb-2.5">
          {task.tags.slice(0, 2).map(tag => (
            <span key={tag} className="text-[10px] bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-400 px-1.5 py-0.5 rounded-full">
              #{tag}
            </span>
          ))}
          {task.tags.length > 2 && <span className="text-[10px] text-gray-400">+{task.tags.length - 2}</span>}
        </div>
      )}

      {/* Footer: due date + assignee */}
      <div className="flex items-center justify-between mt-1 pt-2 border-t border-gray-100 dark:border-gray-700">
        {task.due_date ? (
          <div className={`flex items-center gap-1 text-xs ${isOverdue ? 'text-red-600 dark:text-red-400 font-medium' : 'text-gray-400 dark:text-gray-500'}`}>
            <Calendar className="w-3 h-3" />
            <span>{format(new Date(task.due_date), 'dd MMM', { locale: id })}</span>
            {isOverdue && <span className="text-[10px] bg-red-100 dark:bg-red-900/40 text-red-600 dark:text-red-400 px-1 rounded">Terlambat</span>}
          </div>
        ) : (
          <span />
        )}

        {task.assignee_id && (
          <div className="flex items-center gap-1">
            <Avatar className="w-5 h-5">
              <AvatarFallback className="text-[9px] bg-blue-100 dark:bg-blue-900 text-blue-700 dark:text-blue-300 font-bold">
                {assigneeName.charAt(0).toUpperCase()}
              </AvatarFallback>
            </Avatar>
            {assigneeName && (
              <span className="text-[10px] text-gray-500 dark:text-gray-400 max-w-[60px] truncate">{assigneeName.split(' ')[0]}</span>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default function KanbanBoard({ tasks, onTaskClick, onCreateTask, onTaskCompleted, onTaskUpdate, onUpdate, workspaceId, companyMembers = [], userRole }) {
  const [selectedTask, setSelectedTask] = useState(null);
  const handleUpdate = onTaskUpdate || onUpdate || (() => {});
  const canAdminEdit = userRole === 'owner' || userRole === 'admin';
  const handleTaskClick = onTaskClick || ((task) => setSelectedTask(task));
  const handleCreateTask = onCreateTask || (() => {});

  // Filter out special log tasks from kanban
  const regularTasks = (tasks || []).filter(t =>
    !['briefing_log', 'penawaran_log', 'live_streaming_log', 'complain_log'].includes(t.task_type)
  );

  const onDragEnd = async (result) => {
    const { destination, source, draggableId } = result;
    if (!destination) return;
    if (destination.droppableId === source.droppableId && destination.index === source.index) return;

    const newStatus = destination.droppableId;
    try {
      const taskToUpdate = regularTasks.find(t => t.id === draggableId);
      const updateData = {
        status: newStatus,
        completed_at: newStatus === 'done' ? new Date().toISOString() : null
      };
      await Task.update(draggableId, updateData);

      if (newStatus === 'done' && taskToUpdate && onTaskCompleted) {
        try {
          const currentUser = await UserEntity.me();
          if (currentUser?.email) await onTaskCompleted(currentUser.email, taskToUpdate);
        } catch (e) { console.error('Gamification error:', e); }
      }

      toast.success('Status tugas berhasil diubah');
      window.dispatchEvent(new CustomEvent('taskStatusChanged', { detail: { workspaceId, taskId: draggableId, newStatus } }));
      handleUpdate();
    } catch (error) {
      toast.error('Gagal mengubah status');
    }
  };

  const getTasksByStatus = (status) => regularTasks.filter(task => task.status === status);

  return (
    <div className="h-full">
      {selectedTask && (
        <TaskDetailModal
          task={selectedTask}
          onClose={() => setSelectedTask(null)}
          onUpdate={() => { setSelectedTask(null); handleUpdate(); }}
          canAdminEdit={canAdminEdit}
          companyMembers={companyMembers}
        />
      )}

      {/* Board summary */}
      <div className="flex items-center gap-4 mb-4 text-sm text-gray-500 dark:text-gray-400">
        <span>{regularTasks.length} total tugas</span>
        {columns.map(col => {
          const count = getTasksByStatus(col.id).length;
          if (count === 0) return null;
          return (
            <span key={col.id} className="flex items-center gap-1">
              <span className={`w-2 h-2 rounded-full ${col.dotClass}`} />
              {col.title}: <strong className="text-gray-700 dark:text-gray-300">{count}</strong>
            </span>
          );
        })}
      </div>

      <DragDropContext onDragEnd={onDragEnd}>
        <div className="flex gap-4 overflow-x-auto pb-6">
          {columns.map((column) => {
            const columnTasks = getTasksByStatus(column.id);
            return (
              <div key={column.id} className="flex-shrink-0 w-72 md:w-80">
                {/* Column Header */}
                <div className={`rounded-t-xl px-3.5 py-3 border-t border-x ${column.borderClass} ${column.bgClass} flex items-center justify-between`}>
                  <div className="flex items-center gap-2.5">
                    <div className={`w-2.5 h-2.5 rounded-full ${column.dotClass}`} />
                    <h3 className="font-semibold text-sm text-gray-800 dark:text-gray-200">{column.title}</h3>
                    <span className="text-xs bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-400 px-1.5 py-0 rounded-full font-semibold">
                      {columnTasks.length}
                    </span>
                  </div>
                  {canAdminEdit && (
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-7 w-7 hover:bg-white/60 dark:hover:bg-gray-700/60"
                      onClick={() => handleCreateTask(column.id)}
                      title="Tambah tugas"
                    >
                      <Plus className="w-3.5 h-3.5 text-gray-500" />
                    </Button>
                  )}
                </div>

                {/* Column Body */}
                <Droppable droppableId={column.id}>
                  {(provided, snapshot) => (
                    <div
                      ref={provided.innerRef}
                      {...provided.droppableProps}
                      className={`min-h-[300px] p-2.5 rounded-b-xl border-b border-x ${column.borderClass} transition-colors duration-150 ${
                        snapshot.isDraggingOver
                          ? `${column.bgClass} border-2 border-dashed`
                          : 'bg-gray-50 dark:bg-gray-900/20'
                      }`}
                    >
                      {columnTasks.map((task, index) => (
                        <Draggable key={task.id} draggableId={task.id} index={index}>
                          {(provided, snapshot) => (
                            <div
                              ref={provided.innerRef}
                              {...provided.draggableProps}
                              {...provided.dragHandleProps}
                              className={`transition-all ${snapshot.isDragging ? 'rotate-1 scale-105 shadow-2xl opacity-95 z-50' : ''}`}
                              style={provided.draggableProps.style}
                            >
                              <TaskCard task={task} onClick={handleTaskClick} companyMembers={companyMembers} />
                            </div>
                          )}
                        </Draggable>
                      ))}
                      {provided.placeholder}

                      {columnTasks.length === 0 && !snapshot.isDraggingOver && (
                        <div className="text-center py-10 px-4">
                          <div className={`w-10 h-10 rounded-full mx-auto mb-2 flex items-center justify-center ${column.bgClass} border ${column.borderClass}`}>
                            <span className="text-lg">≡ƒôï</span>
                          </div>
                          <p className="text-xs text-gray-400 dark:text-gray-500">Tidak ada tugas</p>
                          {canAdminEdit && (
                            <button
                              onClick={() => handleCreateTask(column.id)}
                              className="mt-2 text-xs text-blue-500 hover:text-blue-600 hover:underline"
                            >
                              + Tambah tugas
                            </button>
                          )}
                        </div>
                      )}

                      {snapshot.isDraggingOver && (
                        <div className={`border-2 border-dashed rounded-xl p-4 text-center text-xs text-gray-400 ${column.borderClass}`}>
                          Lepaskan di sini
                        </div>
                      )}
                    </div>
                  )}
                </Droppable>
              </div>
            );
          })}
        </div>
      </DragDropContext>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Task } from '@/entities/Task';
import { base44 } from '@/api/base44Client';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent } from '@/components/ui/dialog';
import {
  MapPin, User, Calendar, Save, X, ExternalLink, Navigation,
  Loader2, CheckCircle, RefreshCw, MessageSquare, Edit3,
  TrendingUp, Star, Hourglass
} from 'lucide-react';
import { format } from 'date-fns';
import { id as idLocale } from 'date-fns/locale';
import { toast } from 'sonner';

const priorityColors = {
  low: 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200',
  medium: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200',
  high: 'bg-orange-100 text-orange-800 dark:bg-orange-900 dark:text-orange-200',
  urgent: 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200 animate-pulse'
};
const statusColors = {
  todo: 'bg-gray-100 text-gray-700 dark:bg-gray-700 dark:text-gray-200',
  in_progress: 'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200',
  review: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200',
  completed: 'bg-teal-100 text-teal-800 dark:bg-teal-900 dark:text-teal-200',
  done: 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200'
};
const statusLabels = {
  todo: '≡ƒôï Belum Dikerjakan',
  in_progress: '≡ƒöä Sedang Dikerjakan',
  review: '≡ƒöì Menunggu Review',
  completed: 'Γ£à Selesai',
  done: '≡ƒÅü Tuntas'
};
const priorityLabels = { low: 'Rendah', medium: 'Sedang', high: 'Tinggi', urgent: '≡ƒÜ¿ Mendesak' };

export default function TaskDetailModal({ task, onClose, onUpdate, canAdminEdit = false, companyMembers = [], currentUser = null }) {
  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState({});
  const [locationInput, setLocationInput] = useState('');
  const [isSaving, setIsSaving] = useState(false);
  const [isSearchingLocation, setIsSearchingLocation] = useState(false);
  const [hrSyncStatus, setHrSyncStatus] = useState(null);
  const [employeeNote, setEmployeeNote] = useState('');
  const [isSavingNote, setIsSavingNote] = useState(false);
  const [activeMapTab, setActiveMapTab] = useState('map');

  // Determine if current user is the assignee (employee view)
  const isAssignee = currentUser && task &&
    (task.assignee_id === currentUser.email || task.assignee_id === currentUser.id);
  const canEmployeeUpdate = isAssignee; // employee can update status & add notes
  const canFullEdit = canAdminEdit; // only admin/owner can edit all fields

  useEffect(() => {
    if (task) {
      setEditData({
        title: task.title || '',
        content: task.content || '',
        location_pin: task.location_pin || null,
        status: task.status || 'todo',
        priority: task.priority || 'medium',
        assignee_id: task.assignee_id || '',
        due_date: task.due_date ? format(new Date(task.due_date), "yyyy-MM-dd'T'HH:mm") : '',
        estimated_time: task.estimated_time || ''
      });
      if (task.location_pin?.address) setLocationInput(task.location_pin.label || task.location_pin.address);
    }
  }, [task]);

  if (!task) return null;

  const assignee = companyMembers.find(m =>
    m.user_id === task.assignee_id || m.user_email === task.assignee_id
  );

  const handleSearchLocation = async () => {
    if (!locationInput.trim()) return;
    setIsSearchingLocation(true);
    try {
      const parts = locationInput.split(',');
      if (parts.length === 2 && !isNaN(parseFloat(parts[0])) && !isNaN(parseFloat(parts[1]))) {
        setEditData(prev => ({
          ...prev,
          location_pin: { latitude: parseFloat(parts[0].trim()), longitude: parseFloat(parts[1].trim()), address: locationInput, label: 'Pin Manual' }
        }));
        toast.success('Koordinat berhasil ditambahkan!');
        return;
      }
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(locationInput)}&limit=1`);
      const data = await response.json();
      if (data?.length > 0) {
        const { lat, lon, display_name } = data[0];
        setEditData(prev => ({
          ...prev,
          location_pin: { latitude: parseFloat(lat), longitude: parseFloat(lon), address: display_name, label: locationInput }
        }));
        toast.success('Lokasi ditemukan!');
      } else {
        toast.error('Lokasi tidak ditemukan. Coba lebih spesifik.');
      }
    } catch (e) {
      toast.error('Gagal mencari lokasi');
    } finally {
      setIsSearchingLocation(false);
    }
  };

  const triggerHRSync = async (taskData, newStatus) => {
    if (!task.workspace_id) return;
    setHrSyncStatus('syncing');

    try {
      // Update KPI for assignee
      if (task.assignee_id && (newStatus === 'done' || newStatus === 'completed')) {
        const today = new Date().toISOString().split('T')[0];
        const existingKPIs = await base44.entities.CompanyKPI.filter({
          user_id: task.assignee_id,
          date: today
        });

        if (existingKPIs?.length > 0) {
          const kpi = existingKPIs[0];
          await base44.entities.CompanyKPI.update(kpi.id, {
            tasks_completed: (kpi.tasks_completed || 0) + 1,
            performance_score: Math.min(100, (kpi.performance_score || 70) + 5)
          });
        } else {
          await base44.entities.CompanyKPI.create({
            user_id: task.assignee_id,
            company_id: task.company_id || '',
            date: today,
            tasks_completed: 1,
            performance_score: 75,
            notes: `Tugas selesai: ${task.title}`
          });
        }
      }

      // Mark task as hr_synced
      await Task.update(task.id, { hr_synced: true });

      window.dispatchEvent(new CustomEvent('taskStatusChanged', {
        detail: { workspaceId: task.workspace_id, taskId: task.id, newStatus }
      }));

      setTimeout(() => setHrSyncStatus('synced'), 1500);
    } catch (e) {
      console.warn('HR sync error:', e);
      setHrSyncStatus(null);
    }
  };

  const handleSave = async () => {
    setIsSaving(true);
    try {
      const saveData = { ...editData };
      if (saveData.due_date) saveData.due_date = new Date(saveData.due_date).toISOString();
      if (saveData.estimated_time) saveData.estimated_time = parseFloat(saveData.estimated_time);
      await Task.update(task.id, saveData);
      toast.success('Tugas berhasil diperbarui!');

      window.dispatchEvent(new CustomEvent('taskUpdated', { detail: { workspaceId: task.workspace_id, taskId: task.id } }));

      if (saveData.status !== task.status) {
        await triggerHRSync(saveData, saveData.status);
      }

      onUpdate();
      setIsEditing(false);
    } catch (e) {
      toast.error('Gagal menyimpan perubahan');
    } finally {
      setIsSaving(false);
    }
  };

  const handleQuickStatusChange = async (newStatus) => {
    try {
      const updateData = {
        status: newStatus,
        completed_at: (newStatus === 'done' || newStatus === 'completed') ? new Date().toISOString() : null,
        actual_time: (newStatus === 'done' || newStatus === 'completed') && task.estimated_time ? task.estimated_time : task.actual_time
      };
      await Task.update(task.id, updateData);
      toast.success(`Status diubah ke: ${statusLabels[newStatus]}`);
      await triggerHRSync(updateData, newStatus);
      onUpdate();
    } catch (e) {
      toast.error('Gagal mengubah status');
    }
  };

  const handleSaveEmployeeNote = async () => {
    if (!employeeNote.trim()) return;
    setIsSavingNote(true);
    try {
      const existingNotes = task.content || '';
      const timestamp = format(new Date(), "dd MMM yyyy HH:mm", { locale: idLocale });
      const noteEntry = `\n\n≡ƒô¥ [Update ${timestamp} - ${currentUser?.full_name || currentUser?.email || 'Karyawan'}]:\n${employeeNote}`;
      await Task.update(task.id, { content: existingNotes + noteEntry });
      toast.success('Catatan berhasil ditambahkan!');
      setEmployeeNote('');
      window.dispatchEvent(new CustomEvent('taskUpdated', { detail: { workspaceId: task.workspace_id, taskId: task.id } }));
      onUpdate();
    } catch (e) {
      toast.error('Gagal menyimpan catatan');
    } finally {
      setIsSavingNote(false);
    }
  };

  const pin = isEditing ? editData.location_pin : task.location_pin;
  const mapsEmbedUrl = pin
    ? `https://www.openstreetmap.org/export/embed.html?bbox=${pin.longitude - 0.008},${pin.latitude - 0.008},${pin.longitude + 0.008},${pin.latitude + 0.008}&layer=mapnik&marker=${pin.latitude},${pin.longitude}`
    : null;
  const mapsDirectUrl = pin ? `https://www.google.com/maps?q=${pin.latitude},${pin.longitude}` : null;
  const mapsNavUrl = pin ? `https://www.google.com/maps/dir/?api=1&destination=${pin.latitude},${pin.longitude}` : null;

  return (
    <Dialog open={!!task} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[95vh] overflow-y-auto p-0">

        {/* Header with gradient */}
        <div className="sticky top-0 z-10 bg-gradient-to-r from-blue-600 to-indigo-600 text-white px-6 py-4">
          <div className="flex items-start justify-between gap-3">
            <div className="flex-1 min-w-0">
              {isEditing && canFullEdit ? (
                <Input
                  value={editData.title}
                  onChange={e => setEditData(prev => ({ ...prev, title: e.target.value }))}
                  className="text-lg font-bold border-0 border-b border-white/50 rounded-none px-0 bg-transparent text-white placeholder-white/60 focus-visible:ring-0"
                  placeholder="Judul tugas..."
                />
              ) : (
                <h2 className="text-lg font-bold leading-tight">{task.title}</h2>
              )}
              {assignee && (
                <div className="flex items-center gap-1 mt-1 text-sm text-white/80">
                  <User className="w-3.5 h-3.5" />
                  <span>Ditugaskan ke: <strong>{assignee.user_name || assignee.user_email}</strong></span>
                  {assignee.position && <span>┬╖ {assignee.position}</span>}
                </div>
              )}
            </div>
            <button onClick={onClose} className="text-white/80 hover:text-white transition-colors p-1">
              <X className="w-5 h-5" />
            </button>
          </div>

          {/* HR Sync indicator */}
          {hrSyncStatus && (
            <div className={`mt-2 inline-flex items-center gap-2 text-xs px-3 py-1 rounded-full ${hrSyncStatus === 'syncing' ? 'bg-white/20 text-white' : 'bg-green-400/30 text-white'}`}>
              {hrSyncStatus === 'syncing' ? <Loader2 className="w-3 h-3 animate-spin" /> : <CheckCircle className="w-3 h-3" />}
              {hrSyncStatus === 'syncing' ? 'ΓÜí Sinkronisasi KPI & HR...' : 'Γ£à KPI & HR ter-update!'}
            </div>
          )}
        </div>

        <div className="p-5 space-y-5">
          {/* Status & Priority Badges */}
          <div className="flex flex-wrap gap-2 items-center">
            <Badge className={priorityColors[task.priority] || 'bg-gray-100 text-gray-800'}>
              {priorityLabels[task.priority] || task.priority}
            </Badge>
            <Badge className={statusColors[task.status] || 'bg-gray-100 text-gray-800'}>
              {statusLabels[task.status] || task.status}
            </Badge>
            {task.task_type && (
              <Badge variant="outline" className="capitalize text-xs">
                {task.task_type.replace('_log', '').replace(/_/g, ' ')}
              </Badge>
            )}
            {task.hr_synced && (
              <Badge className="bg-purple-100 text-purple-700 dark:bg-purple-900 dark:text-purple-200 text-xs">
                <RefreshCw className="w-3 h-3 mr-1" /> HR Synced
              </Badge>
            )}
          </div>

          {/* Γ£à QUICK STATUS CHANGE - For both admin and employee */}
          {(canFullEdit || canEmployeeUpdate) && (
            <div className="bg-gray-50 dark:bg-gray-800/50 rounded-xl p-4 space-y-2">
              <p className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-1">
                <TrendingUp className="w-3.5 h-3.5" /> Update Status Pekerjaan
              </p>
              <div className="flex flex-wrap gap-2">
                {Object.entries(statusLabels).map(([s, label]) => (
                  <button
                    key={s}
                    onClick={() => handleQuickStatusChange(s)}
                    className={`text-xs px-3 py-1.5 rounded-lg border-2 font-medium transition-all hover:scale-105 ${task.status === s
                      ? 'border-blue-500 bg-blue-500 text-white shadow-sm'
                      : 'border-gray-200 dark:border-gray-600 hover:border-blue-300 text-gray-600 dark:text-gray-300 bg-white dark:bg-gray-800'
                      }`}
                  >
                    {label}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Meta Info Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3 text-sm">
            {isEditing && canFullEdit ? (
              <>
                <div className="space-y-1">
                  <label className="text-xs font-medium text-gray-500">Prioritas</label>
                  <Select value={editData.priority} onValueChange={v => setEditData(prev => ({ ...prev, priority: v }))}>
                    <SelectTrigger className="h-9 text-sm"><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">Rendah</SelectItem>
                      <SelectItem value="medium">Sedang</SelectItem>
                      <SelectItem value="high">Tinggi</SelectItem>
                      <SelectItem value="urgent">≡ƒÜ¿ Mendesak</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-medium text-gray-500">Status</label>
                  <Select value={editData.status} onValueChange={v => setEditData(prev => ({ ...prev, status: v }))}>
                    <SelectTrigger className="h-9 text-sm"><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="todo">Belum Dikerjakan</SelectItem>
                      <SelectItem value="in_progress">Sedang Dikerjakan</SelectItem>
                      <SelectItem value="review">Menunggu Review</SelectItem>
                      <SelectItem value="done">Tuntas</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-medium text-gray-500">Ditugaskan kepada</label>
                  <Select value={editData.assignee_id} onValueChange={v => setEditData(prev => ({ ...prev, assignee_id: v }))}>
                    <SelectTrigger className="h-9 text-sm"><SelectValue placeholder="Pilih karyawan" /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value={null}>-- Tanpa Assignee --</SelectItem>
                      {companyMembers.map(m => (
                        <SelectItem key={m.id} value={m.user_id || m.user_email}>
                          {m.user_name || m.user_email} {m.position ? `(${m.position})` : ''}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-medium text-gray-500">Deadline</label>
                  <Input type="datetime-local" value={editData.due_date} onChange={e => setEditData(prev => ({ ...prev, due_date: e.target.value }))} className="h-9 text-sm" />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-medium text-gray-500">Estimasi Durasi (menit)</label>
                  <Input type="number" value={editData.estimated_time} onChange={e => setEditData(prev => ({ ...prev, estimated_time: e.target.value }))} className="h-9 text-sm" placeholder="Contoh: 120 (2 jam)" />
                </div>
              </>
            ) : (
              <div className="md:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-3 p-4 bg-gray-50 dark:bg-gray-800/50 rounded-xl border border-gray-100 dark:border-gray-700">
