                {task.due_date && (
                  <InfoRow icon={<Calendar className="w-4 h-4 text-orange-500" />} label="Deadline" value={format(new Date(task.due_date), 'd MMM yyyy HH:mm', { locale: idLocale })} />
                )}
                {task.estimated_time && (
                  <InfoRow icon={<Hourglass className="w-4 h-4 text-purple-500" />} label="Durasi" value={`${task.estimated_time} menit ${task.estimated_time >= 60 ? `(${Math.floor(task.estimated_time / 60)} jam${task.estimated_time % 60 ? ` ${task.estimated_time % 60} mnt` : ''})` : ''}`} />
                )}
                {task.completed_at && (
                  <InfoRow icon={<CheckCircle className="w-4 h-4 text-green-500" />} label="Selesai pada" value={format(new Date(task.completed_at), 'd MMM yyyy HH:mm', { locale: idLocale })} />
                )}
              </div>
            )}
          </div>

          {/* Description */}
          <div>
            <p className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2 flex items-center gap-1.5">
              <MessageSquare className="w-4 h-4 text-indigo-500" />
              Detail Tugas & Catatan
            </p>
            {isEditing && canFullEdit ? (
              <Textarea
                value={editData.content}
                onChange={e => setEditData(prev => ({ ...prev, content: e.target.value }))}
                rows={5}
                placeholder="Tambahkan deskripsi, instruksi detail, atau catatan tugas..."
                className="text-sm"
              />
            ) : (
              <div className="text-sm text-gray-600 dark:text-gray-400 bg-gray-50 dark:bg-gray-800 rounded-xl p-4 min-h-[80px] whitespace-pre-wrap border border-gray-100 dark:border-gray-700 font-mono text-xs leading-relaxed">
                {task.content || <span className="italic text-gray-400 font-sans">Belum ada deskripsi</span>}
              </div>
            )}
          </div>

          {/* Γ£à EMPLOYEE NOTE INPUT */}
          {(canEmployeeUpdate || canFullEdit) && !isEditing && (
            <div className="border border-blue-200 dark:border-blue-700 rounded-xl p-4 bg-blue-50 dark:bg-blue-950/20 space-y-3">
              <p className="text-sm font-semibold text-blue-700 dark:text-blue-300 flex items-center gap-1.5">
                <Edit3 className="w-4 h-4" /> Tambah Catatan / Laporan Progress
              </p>
              <Textarea
                value={employeeNote}
                onChange={e => setEmployeeNote(e.target.value)}
                rows={3}
                placeholder="Tulis laporan progress, kendala, atau catatan pekerjaan Anda..."
                className="text-sm bg-white dark:bg-gray-800"
              />
              <div className="flex justify-end">
                <Button
                  size="sm"
                  onClick={handleSaveEmployeeNote}
                  disabled={isSavingNote || !employeeNote.trim()}
                  className="bg-blue-600 hover:bg-blue-700 text-white"
                >
                  {isSavingNote ? <Loader2 className="w-4 h-4 mr-1 animate-spin" /> : <MessageSquare className="w-4 h-4 mr-1" />}
                  Kirim Laporan
                </Button>
              </div>
            </div>
          )}

          {/* Γ£à LOCATION MAP SECTION - Full Featured */}
          <div className="border border-gray-200 dark:border-gray-700 rounded-xl overflow-hidden">
            <div className="flex items-center justify-between px-4 py-3 bg-gray-50 dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700">
              <p className="text-sm font-semibold text-gray-700 dark:text-gray-300 flex items-center gap-2">
                <MapPin className="w-4 h-4 text-red-500" />
                Titik Lokasi Pelanggan
              </p>
              <div className="flex items-center gap-2">
                {mapsNavUrl && (
                  <a href={mapsNavUrl} target="_blank" rel="noopener noreferrer"
                    className="text-xs bg-green-600 text-white px-2 py-1 rounded flex items-center gap-1 hover:bg-green-700 transition-colors">
                    <Navigation className="w-3 h-3" /> Navigasi
                  </a>
                )}
                {mapsDirectUrl && (
                  <a href={mapsDirectUrl} target="_blank" rel="noopener noreferrer"
                    className="text-xs text-blue-600 hover:underline flex items-center gap-1">
                    <ExternalLink className="w-3 h-3" /> Google Maps
                  </a>
                )}
              </div>
            </div>

            <div className="p-4 space-y-3">
              {pin && mapsEmbedUrl && (
                <>
                  <div className="rounded-lg overflow-hidden border border-gray-200 dark:border-gray-600 shadow-sm">
                    <iframe
                      src={mapsEmbedUrl}
                      width="100%"
                      height="280"
                      style={{ border: 0 }}
                      loading="lazy"
                      title="Lokasi Tugas"
                    />
                  </div>
                  <div className="flex items-start gap-2 p-3 bg-red-50 dark:bg-red-950/20 rounded-lg border border-red-100 dark:border-red-800">
                    <Navigation className="w-4 h-4 text-red-500 flex-shrink-0 mt-0.5" />
                    <div>
                      <p className="text-xs font-semibold text-red-700 dark:text-red-300">{pin.label || 'Lokasi Tujuan'}</p>
                      <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5 line-clamp-2">{pin.address}</p>
                      <p className="text-xs text-gray-400 mt-0.5">Koordinat: {pin.latitude?.toFixed(5)}, {pin.longitude?.toFixed(5)}</p>
                    </div>
                  </div>
                </>
              )}

              {canFullEdit && isEditing && (
                <div className="space-y-2">
                  <p className="text-xs text-gray-500 dark:text-gray-400 flex items-center gap-1">
                    <MapPin className="w-3 h-3" /> Cari alamat atau masukkan koordinat (lat, lng):
                  </p>
                  <div className="flex gap-2">
                    <Input
                      value={locationInput}
                      onChange={e => setLocationInput(e.target.value)}
                      placeholder="Contoh: Jl. Sudirman Jakarta atau -6.2088, 106.8456"
                      className="text-sm"
                      onKeyDown={e => e.key === 'Enter' && handleSearchLocation()}
                    />
                    <Button size="sm" variant="outline" onClick={handleSearchLocation} disabled={isSearchingLocation}>
                      {isSearchingLocation ? <Loader2 className="w-4 h-4 animate-spin" /> : <MapPin className="w-4 h-4" />}
                    </Button>
                  </div>
                  {editData.location_pin && (
                    <div className="text-xs text-green-600 flex items-center gap-1">
                      <CheckCircle className="w-3 h-3" />
                      Lokasi: {editData.location_pin.latitude?.toFixed(4)}, {editData.location_pin.longitude?.toFixed(4)}
                      <button className="text-red-400 ml-2 hover:underline" onClick={() => setEditData(prev => ({ ...prev, location_pin: null }))}>hapus</button>
                    </div>
                  )}
                </div>
              )}

              {!pin && (
                <div className="text-center py-6 text-gray-400">
                  <MapPin className="w-10 h-10 mx-auto mb-2 opacity-30" />
                  <p className="text-sm">
                    {canFullEdit ? 'Belum ada titik lokasi. Klik Edit Detail untuk menambahkan.' : 'Belum ada titik lokasi yang ditandai.'}
                  </p>
                </div>
              )}
            </div>
          </div>

          {/* HR Integration Panel */}
          <div className={`rounded-xl p-4 text-sm flex items-start gap-3 ${task.hr_synced ? 'bg-purple-50 dark:bg-purple-950/30 border border-purple-200 dark:border-purple-700' : 'bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700'}`}>
            <div className={`w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0 ${task.hr_synced ? 'bg-purple-100 dark:bg-purple-900' : 'bg-gray-200 dark:bg-gray-700'}`}>
              <Star className={`w-4 h-4 ${task.hr_synced ? 'text-purple-600' : 'text-gray-400'}`} />
            </div>
            <div>
              <p className={`font-semibold text-xs uppercase tracking-wider ${task.hr_synced ? 'text-purple-700 dark:text-purple-300' : 'text-gray-500'}`}>
                {task.hr_synced ? 'Γ£à Terintegrasi HR & KPI' : 'ΓÅ│ Belum Tersinkron ke HR'}
              </p>
              <p className={`text-xs mt-1 ${task.hr_synced ? 'text-purple-600 dark:text-purple-400' : 'text-gray-400'}`}>
                {task.hr_synced
                  ? 'Data performa, KPI, dan kehadiran karyawan telah diperbarui otomatis. HR dapat memantau keaktifan karyawan ini.'
                  : 'Ketika status tugas diubah ke Selesai atau Tuntas, data KPI dan performa karyawan akan otomatis diperbarui ke modul HR.'}
              </p>
            </div>
          </div>

          {/* Action Buttons */}
          <div className="flex items-center justify-between pt-2 border-t border-gray-100 dark:border-gray-700">
            <div className="flex gap-2">
              {canFullEdit && !isEditing && (
                <Button size="sm" variant="outline" onClick={() => setIsEditing(true)} className="gap-1">
                  <Edit3 className="w-3.5 h-3.5" /> Edit Detail
                </Button>
              )}
              {isEditing && canFullEdit && (
                <>
                  <Button size="sm" variant="outline" onClick={() => setIsEditing(false)}>
                    <X className="w-4 h-4 mr-1" /> Batal
                  </Button>
                  <Button size="sm" onClick={handleSave} disabled={isSaving} className="bg-blue-600 hover:bg-blue-700">
                    {isSaving ? <Loader2 className="w-4 h-4 mr-1 animate-spin" /> : <Save className="w-4 h-4 mr-1" />}
                    {isSaving ? 'Menyimpan...' : 'Simpan Perubahan'}
                  </Button>
                </>
              )}
            </div>
            <Button size="sm" variant="ghost" onClick={onClose} className="text-gray-500">Tutup</Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

function InfoRow({ icon, label, value }) {
  return (
    <div className="flex items-start gap-2">
      <span className="mt-0.5 flex-shrink-0">{icon}</span>
      <div>
        <p className="text-xs text-gray-400 dark:text-gray-500">{label}</p>
        <p className="text-sm font-medium text-gray-800 dark:text-gray-200">{value}</p>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Task } from '@/entities/Task';
import { Bell, X, MapPin, Clock, ChevronRight } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { format } from 'date-fns';
import { id as idLocale } from 'date-fns/locale';

const priorityColors = {
  low: 'from-green-500 to-teal-500',
  medium: 'from-yellow-500 to-orange-400',
  high: 'from-orange-500 to-red-500',
  urgent: 'from-red-600 to-rose-700'
};

const priorityLabels = { low: 'Rendah', medium: 'Sedang', high: 'Tinggi', urgent: '≡ƒÜ¿ MENDESAK' };

export default function TaskNotificationPopup({ currentUser, onOpenTask }) {
  const [notifications, setNotifications] = useState([]);
  const [seenTaskIds, setSeenTaskIds] = useState(() => {
    try { return new Set(JSON.parse(localStorage.getItem('seen_task_notifs') || '[]')); }
    catch { return new Set(); }
  });

  const requestBrowserPermission = async () => {
    if ('Notification' in window && Notification.permission === 'default') {
      await Notification.requestPermission();
    }
  };

  const playNotificationSound = () => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const oscillator = ctx.createOscillator();
      const gainNode = ctx.createGain();
      oscillator.connect(gainNode);
      gainNode.connect(ctx.destination);
      oscillator.type = 'sine';
      oscillator.frequency.setValueAtTime(880, ctx.currentTime);
      oscillator.frequency.setValueAtTime(660, ctx.currentTime + 0.1);
      oscillator.frequency.setValueAtTime(880, ctx.currentTime + 0.2);
      gainNode.gain.setValueAtTime(0.3, ctx.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5);
      oscillator.start(ctx.currentTime);
      oscillator.stop(ctx.currentTime + 0.5);
    } catch (e) { /* audio not available */ }
  };

  const sendBrowserNotification = (task) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      const notif = new Notification('≡ƒôï Tugas Baru Ditugaskan!', {
        body: `${task.title}\n${task.due_date ? 'Deadline: ' + format(new Date(task.due_date), 'd MMM yyyy HH:mm', { locale: idLocale }) : ''}`,
        icon: '/favicon.ico',
        badge: '/favicon.ico',
        tag: task.id,
        requireInteraction: true
      });
      notif.onclick = () => {
        window.focus();
        onOpenTask && onOpenTask(task);
        notif.close();
      };
    }
  };

  const checkNewTasks = async () => {
    if (!currentUser) return;
    try {
      const assignedTasks = await Task.filter({
        assignee_id: currentUser.email,
        status: 'todo'
      });

      const newTasks = (assignedTasks || []).filter(t => {
        if (seenTaskIds.has(t.id)) return false;
        const createdAt = new Date(t.created_date || 0);
        const fiveMinutesAgo = new Date(Date.now() - 5 * 60 * 1000);
        return createdAt > fiveMinutesAgo;
      });

      if (newTasks.length > 0) {
        setNotifications(prev => [...newTasks, ...prev].slice(0, 5));
        newTasks.forEach(task => {
          sendBrowserNotification(task);
          setSeenTaskIds(prev => {
            const next = new Set(prev);
            next.add(task.id);
            localStorage.setItem('seen_task_notifs', JSON.stringify([...next].slice(-100)));
            return next;
          });
        });
        playNotificationSound();
      }
    } catch (e) { /* silent */ }
  };

  useEffect(() => {
    if (!currentUser) return;
    requestBrowserPermission();
    checkNewTasks();
    const interval = setInterval(checkNewTasks, 30000); // poll every 30s
    return () => clearInterval(interval);
  }, [currentUser]);

  // Also listen to taskAssigned events (real-time from same browser)
  useEffect(() => {
    const handler = async (e) => {
      const { taskId, assigneeEmail, taskTitle } = e.detail || {};
      if (!currentUser || assigneeEmail !== currentUser.email) return;
      try {
        const task = await Task.get(taskId);
        if (!task) return;
        setNotifications(prev => [task, ...prev].slice(0, 5));
        sendBrowserNotification(task);
        playNotificationSound();
      } catch (e) { /* silent */ }
    };
    window.addEventListener('taskAssigned', handler);
    return () => window.removeEventListener('taskAssigned', handler);
  }, [currentUser]);

  const dismiss = (taskId) => {
    setNotifications(prev => prev.filter(n => n.id !== taskId));
    setSeenTaskIds(prev => {
      const next = new Set(prev);
      next.add(taskId);
      localStorage.setItem('seen_task_notifs', JSON.stringify([...next].slice(-100)));
      return next;
    });
  };

  if (notifications.length === 0) return null;

  return (
    <div className="fixed top-4 right-4 z-[9999] space-y-2 max-w-sm w-full">
      <AnimatePresence>
        {notifications.map(task => (
          <motion.div
            key={task.id}
            initial={{ opacity: 0, x: 100, scale: 0.9 }}
            animate={{ opacity: 1, x: 0, scale: 1 }}
            exit={{ opacity: 0, x: 100, scale: 0.9 }}
            transition={{ type: 'spring', stiffness: 300, damping: 25 }}
            className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl border border-gray-100 dark:border-gray-700 overflow-hidden"
          >
            {/* Top gradient strip */}
            <div className={`h-1.5 bg-gradient-to-r ${priorityColors[task.priority] || 'from-blue-500 to-indigo-500'}`} />

            <div className="p-4">
              <div className="flex items-start gap-3">
                <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-xl flex items-center justify-center flex-shrink-0 shadow-md">
                  <Bell className="w-5 h-5 text-white" />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-0.5">
                    <p className="text-xs font-bold text-blue-600 dark:text-blue-400 uppercase tracking-wide">Tugas Baru!</p>
                    <Badge className={`text-[10px] px-1.5 py-0 ${task.priority === 'urgent' ? 'bg-red-100 text-red-700' : 'bg-gray-100 text-gray-600'}`}>
                      {priorityLabels[task.priority]}
                    </Badge>
                  </div>
                  <p className="text-sm font-bold text-gray-900 dark:text-gray-100 leading-tight line-clamp-2">
                    {task.title}
                  </p>
                  <div className="flex items-center gap-3 mt-1.5 text-xs text-gray-500 dark:text-gray-400">
                    {task.due_date && (
                      <span className="flex items-center gap-1">
                        <Clock className="w-3 h-3" />
                        {format(new Date(task.due_date), 'd MMM HH:mm', { locale: idLocale })}
                      </span>
                    )}
                    {task.location_pin && (
                      <span className="flex items-center gap-1 text-red-500">
                        <MapPin className="w-3 h-3" />
                        Ada Lokasi
                      </span>
                    )}
                    {task.estimated_time && (
                      <span className="flex items-center gap-1">
                        <Clock className="w-3 h-3" />
                        {task.estimated_time} mnt
                      </span>
                    )}
                  </div>
                </div>
                <button onClick={() => dismiss(task.id)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 flex-shrink-0">
                  <X className="w-4 h-4" />
                </button>
              </div>

              <div className="flex gap-2 mt-3">
                <Button
                  size="sm"
                  className="flex-1 h-8 text-xs bg-blue-600 hover:bg-blue-700 text-white gap-1"
                  onClick={() => { onOpenTask && onOpenTask(task); dismiss(task.id); }}
                >
                  Lihat Detail <ChevronRight className="w-3 h-3" />
                </Button>
                <Button
                  size="sm"
                  variant="outline"
                  className="h-8 text-xs"
                  onClick={() => dismiss(task.id)}
                >
                  Tutup
                </Button>
              </div>
            </div>
          </motion.div>
        ))}
      </AnimatePresence>
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { base44 } from '@/api/base44Client';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar } from '@/components/ui/calendar';
import { CalendarIcon, Download, Users, CheckSquare, XCircle, Clock, TrendingUp, RefreshCw, Loader2, Zap } from 'lucide-react';
import { format, subDays, isToday } from 'date-fns';
import { toast } from 'sonner';

const STATUS_CONFIG = {
  present: { label: 'Hadir', color: 'bg-green-100 text-green-800 dark:bg-green-900/40 dark:text-green-300', icon: 'Γ£à' },
  late: { label: 'Terlambat', color: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/40 dark:text-yellow-300', icon: 'ΓÅ░' },
  absent: { label: 'Tidak Hadir', color: 'bg-red-100 text-red-800 dark:bg-red-900/40 dark:text-red-300', icon: 'Γ¥î' },
  sick: { label: 'Sakit', color: 'bg-blue-100 text-blue-800 dark:bg-blue-900/40 dark:text-blue-300', icon: '≡ƒñÆ' },
  leave: { label: 'Izin', color: 'bg-purple-100 text-purple-800 dark:bg-purple-900/40 dark:text-purple-300', icon: '≡ƒôï' },
};

function getStatusConfig(status) {
  return STATUS_CONFIG[status] || { label: status, color: 'bg-gray-100 text-gray-700', icon: 'Γ¥ô' };
}

export default function WorkspaceAttendance({ workspace, user, members = [], companyMembers = [], companyId }) {
  const [records, setRecords] = useState([]);
  const [filters, setFilters] = useState({
    employeeId: 'all',
    status: 'all',
    dateRange: { from: subDays(new Date(), 7), to: new Date() }
  });
  const [isLoading, setIsLoading] = useState(true);

  // Γ£à FETCH FROM CompanyAttendance (REAL DATA from HR module)
  const fetchAttendanceData = async () => {
    if (!companyId) { setRecords([]); setIsLoading(false); return; }
    setIsLoading(true);
    try {
      const data = await base44.entities.CompanyAttendance.filter({
        company_id: companyId
      });
      setRecords(data || []);
    } catch (error) {
      console.error('Attendance load error:', error);
      toast.error('Gagal memuat data absensi.');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchAttendanceData();
  }, [companyId]);

  // Γ£à Listen for realtime attendance updates from WorkspaceHRSync
  useEffect(() => {
    if (!companyId) return;
    const handler = (e) => {
      if (e.detail?.companyId === companyId) {
        fetchAttendanceData();
      }
    };
    window.addEventListener('hrAttendanceUpdated', handler);
    return () => window.removeEventListener('hrAttendanceUpdated', handler);
  }, [companyId]);

  // Γ£à Resolve member name from CompanyAttendance record + companyMembers
  const getMemberName = (record) => {
    // First try the record's own employee_name
    if (record.employee_name) return record.employee_name;
    // Then try matching via companyMembers
    const member = companyMembers.find(m =>
      m.id === record.employee_id ||
      m.user_email === record.employee_email ||
      m.user_email === record.employee_id
    );
    return member?.user_name || record.employee_email || record.employee_id || '-';
  };

  // Γ£à Get member initial for avatar
  const getMemberInitial = (record) => {
    const name = getMemberName(record);
    return name.charAt(0).toUpperCase();
  };

  // Γ£à Filter records using CompanyAttendance fields
  const filteredRecords = useMemo(() => {
    let result = records;

    // Filter by employee
    if (filters.employeeId !== 'all') {
      result = result.filter(r =>
        r.employee_id === filters.employeeId ||
        r.employee_email === filters.employeeId
      );
    }

    // Filter by status
    if (filters.status !== 'all') {
      result = result.filter(r => r.status === filters.status);
    }

    // Filter by date range
    if (filters.dateRange.from && filters.dateRange.to) {
      const fromStr = format(filters.dateRange.from, 'yyyy-MM-dd');
      const toStr = format(filters.dateRange.to, 'yyyy-MM-dd');
      result = result.filter(r => {
        if (!r.date) return false;
        const dateStr = r.date.substring(0, 10);
        return dateStr >= fromStr && dateStr <= toStr;
      });
    }

    // Sort by date descending
    return [...result].sort((a, b) => {
      const da = a.date || '';
      const db = b.date || '';
      return db.localeCompare(da);
    });
  }, [records, filters]);

  // Stats
  const stats = useMemo(() => ({
    total: filteredRecords.length,
    present: filteredRecords.filter(r => r.status === 'present').length,
    late: filteredRecords.filter(r => r.status === 'late').length,
    absent: filteredRecords.filter(r => r.status === 'absent').length,
    sick: filteredRecords.filter(r => r.status === 'sick').length,
    leave: filteredRecords.filter(r => r.status === 'leave').length,
    avgHours: filteredRecords.filter(r => r.total_hours).length > 0
      ? (filteredRecords.reduce((sum, r) => sum + (r.total_hours || 0), 0) / filteredRecords.filter(r => r.total_hours).length).toFixed(1)
      : '0',
  }), [filteredRecords]);

  const attendanceRate = stats.total > 0 ? Math.round((stats.present + stats.late) / stats.total * 100) : 0;

  // Γ£à CSV Export with CompanyAttendance fields
  const handleExportCSV = () => {
    if (filteredRecords.length === 0) { toast.error('Tidak ada data untuk diekspor.'); return; }
    const escape = (f) => {
      if (f == null) return '';
      const s = String(f);
      return s.includes(',') || s.includes('"') || s.includes('\n') ? `"${s.replace(/"/g, '""')}"` : s;
    };
    const headers = ['Karyawan', 'Email', 'Tanggal', 'Clock In', 'Clock Out', 'Total Jam', 'Status', 'Catatan'];
    const csvContent = [
      headers.join(','),
      ...filteredRecords.map(r => [
        getMemberName(r),
        r.employee_email || '',
        r.date ? r.date.substring(0, 10) : '',
        r.clock_in_time ? (() => { try { return format(new Date(r.clock_in_time), 'HH:mm:ss'); } catch { return r.clock_in_time; } })() : '',
        r.clock_out_time ? (() => { try { return format(new Date(r.clock_out_time), 'HH:mm:ss'); } catch { return r.clock_out_time; } })() : '',
        r.total_hours ? r.total_hours.toFixed(2) : '',
        r.status || '',
        r.notes || ''
      ].map(escape).join(','))
    ].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.setAttribute('href', URL.createObjectURL(blob));
    link.setAttribute('download', `laporan-absensi-${companyId}-${format(new Date(), 'yyyy-MM-dd')}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    toast.success('Laporan berhasil diekspor!');
  };

  // Γ£à No company check
  if (!companyId) {
    return (
      <Card className="border-dashed border-2 dark:border-gray-700">
        <CardContent className="text-center py-12">
          <Clock className="w-12 h-12 mx-auto mb-3 text-gray-300 dark:text-gray-600" />
          <p className="text-sm font-medium text-gray-500">Absensi hanya tersedia untuk workspace yang terhubung dengan perusahaan</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
        <div>
          <h2 className="text-xl font-bold text-gray-900 dark:text-gray-100 flex items-center gap-2">
            <Clock className="w-5 h-5 text-teal-500" />
            Absensi Karyawan
          </h2>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-0.5">
            Data real dari HR ΓÇö {records.length} total catatan absensi
          </p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={fetchAttendanceData} disabled={isLoading} className="gap-1.5">
            <RefreshCw className={`w-3.5 h-3.5 ${isLoading ? 'animate-spin' : ''}`} />
            Refresh
          </Button>
          <Button variant="outline" size="sm" onClick={handleExportCSV} className="gap-1.5">
            <Download className="w-3.5 h-3.5" />
            Export CSV
          </Button>
        </div>
      </div>

      {/* Real data badge */}
      <div className="p-2.5 bg-teal-50 dark:bg-teal-950/30 rounded-lg border border-teal-200 dark:border-teal-800 flex items-center gap-2">
        <Zap className="w-4 h-4 text-teal-500 flex-shrink-0" />
        <p className="text-xs text-teal-700 dark:text-teal-300">
          <strong>Data Real</strong> ΓÇö Terintegrasi dengan modul HR & Payroll perusahaan. Absensi otomatis tercatat saat karyawan clock in/out.
        </p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3">
        {[
          { label: 'Total Record', value: stats.total, icon: Users, color: 'text-gray-500', bg: 'bg-gray-50 dark:bg-gray-900/40' },
          { label: 'Hadir', value: stats.present, icon: CheckSquare, color: 'text-green-500', bg: 'bg-green-50 dark:bg-green-950/30' },
          { label: 'Terlambat', value: stats.late, icon: Clock, color: 'text-yellow-500', bg: 'bg-yellow-50 dark:bg-yellow-950/30' },
          { label: 'Tidak Hadir', value: stats.absent, icon: XCircle, color: 'text-red-500', bg: 'bg-red-50 dark:bg-red-950/30' },
          { label: 'Kehadiran', value: `${attendanceRate}%`, icon: TrendingUp, color: 'text-teal-500', bg: 'bg-teal-50 dark:bg-teal-950/30' },
          { label: 'Rata-rata Jam', value: `${stats.avgHours}h`, icon: Clock, color: 'text-indigo-500', bg: 'bg-indigo-50 dark:bg-indigo-950/30' },
        ].map(({ label, value, icon: Icon, color, bg }) => (
          <Card key={label} className={`border dark:border-gray-700 ${bg}`}>
            <CardContent className="p-3">
              <div className="flex items-center justify-between mb-1">
                <p className="text-xs text-gray-500 dark:text-gray-400 font-medium">{label}</p>
                <Icon className={`w-3.5 h-3.5 ${color}`} />
              </div>
              <p className="text-xl font-bold text-gray-900 dark:text-white">{value}</p>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Attendance Rate Bar */}
      {stats.total > 0 && (
        <div className="space-y-1.5">
          <div className="flex justify-between text-xs text-gray-500 dark:text-gray-400">
            <span>Tingkat Kehadiran</span>
            <span className={`font-bold ${attendanceRate >= 80 ? 'text-green-600' : attendanceRate >= 60 ? 'text-yellow-600' : 'text-red-600'}`}>
              {attendanceRate}%
            </span>
          </div>
          <div className="h-2 bg-gray-100 dark:bg-gray-700 rounded-full overflow-hidden">
            <div
              className={`h-full rounded-full transition-all duration-700 ${attendanceRate >= 80 ? 'bg-green-500' : attendanceRate >= 60 ? 'bg-yellow-500' : 'bg-red-500'}`}
              style={{ width: `${attendanceRate}%` }}
            />
          </div>
        </div>
      )}

      {/* Filters */}
      <Card className="border dark:border-gray-700">
        <CardHeader className="pb-2">
          <CardTitle className="text-sm font-semibold">Filter Data</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            {/* Member filter ΓÇö uses companyMembers */}
            <div className="space-y-1">
              <label className="text-xs font-medium text-gray-600 dark:text-gray-400">Anggota</label>
              <Select value={filters.employeeId} onValueChange={(val) => setFilters(f => ({ ...f, employeeId: val }))}>
                <SelectTrigger className="h-9 text-sm">
                  <SelectValue placeholder="Semua Anggota" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Semua Anggota</SelectItem>
                  {companyMembers.map(m => (
                    <SelectItem key={m.id} value={m.id}>
                      {m.user_name || m.user_email}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Status filter */}
            <div className="space-y-1">
              <label className="text-xs font-medium text-gray-600 dark:text-gray-400">Status</label>
              <Select value={filters.status} onValueChange={(val) => setFilters(f => ({ ...f, status: val }))}>
                <SelectTrigger className="h-9 text-sm">
                  <SelectValue placeholder="Semua Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Semua Status</SelectItem>
                  {Object.entries(STATUS_CONFIG).map(([val, cfg]) => (
                    <SelectItem key={val} value={val}>{cfg.icon} {cfg.label}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Date range */}
            <div className="space-y-1">
              <label className="text-xs font-medium text-gray-600 dark:text-gray-400">Rentang Tanggal</label>
              <Popover>
                <PopoverTrigger asChild>
                  <Button variant="outline" className="w-full h-9 text-sm justify-start font-normal">
                    <CalendarIcon className="mr-2 h-3.5 w-3.5 text-gray-400" />
                    <span className="truncate text-xs">
                      {filters.dateRange.from && filters.dateRange.to
                        ? `${format(filters.dateRange.from, 'dd/MM/yy')} - ${format(filters.dateRange.to, 'dd/MM/yy')}`
                        : 'Pilih tanggal'}
                    </span>
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <Calendar
                    initialFocus
                    mode="range"
                    defaultMonth={filters.dateRange.from}
                    selected={filters.dateRange}
                    onSelect={(val) => val && setFilters(f => ({ ...f, dateRange: val }))}
                    numberOfMonths={1}
                  />
                  {/* Quick date presets */}
                  <div className="p-2 border-t flex flex-wrap gap-1">
                    {[
                      { label: 'Hari ini', from: new Date(), to: new Date() },
                      { label: '7 hari', from: subDays(new Date(), 7), to: new Date() },
                      { label: '30 hari', from: subDays(new Date(), 30), to: new Date() },
                      { label: 'Bulan ini', from: new Date(new Date().getFullYear(), new Date().getMonth(), 1), to: new Date() },
                    ].map(preset => (
                      <button
                        key={preset.label}
                        onClick={() => setFilters(f => ({ ...f, dateRange: { from: preset.from, to: preset.to } }))}
                        className="text-xs px-2 py-1 rounded bg-gray-100 dark:bg-gray-700 hover:bg-blue-100 dark:hover:bg-blue-900/40 text-gray-600 dark:text-gray-400 transition-colors"
                      >
                        {preset.label}
                      </button>
                    ))}
                  </div>
                </PopoverContent>
              </Popover>
            </div>
          </div>

          {/* Active filter summary */}
          {(filters.employeeId !== 'all' || filters.status !== 'all') && (
            <div className="mt-2 flex items-center gap-2 flex-wrap">
              <span className="text-xs text-gray-500">Filter aktif:</span>
              {filters.employeeId !== 'all' && (
                <Badge variant="outline" className="text-xs">
                  ≡ƒæñ {companyMembers.find(m => m.id === filters.employeeId)?.user_name || filters.employeeId}
                  <button onClick={() => setFilters(f => ({ ...f, employeeId: 'all' }))} className="ml-1 text-gray-400 hover:text-gray-600">├ù</button>
                </Badge>
              )}
              {filters.status !== 'all' && (
                <Badge variant="outline" className="text-xs">
                  {getStatusConfig(filters.status).icon} {getStatusConfig(filters.status).label}
                  <button onClick={() => setFilters(f => ({ ...f, status: 'all' }))} className="ml-1 text-gray-400 hover:text-gray-600">├ù</button>
                </Badge>
              )}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Data Table */}
      <Card className="border dark:border-gray-700">
        <CardHeader className="pb-3">
          <div className="flex items-center justify-between">
            <CardTitle className="text-base">Riwayat Kehadiran</CardTitle>
            <span className="text-xs text-gray-500 dark:text-gray-400">{filteredRecords.length} record</span>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow className="bg-gray-50 dark:bg-gray-800/50">
                  <TableHead className="text-xs font-semibold">Karyawan</TableHead>
                  <TableHead className="text-xs font-semibold">Tanggal</TableHead>
                  <TableHead className="text-xs font-semibold">Clock In</TableHead>
                  <TableHead className="text-xs font-semibold">Clock Out</TableHead>
                  <TableHead className="text-xs font-semibold hidden md:table-cell">Total Jam</TableHead>
                  <TableHead className="text-xs font-semibold">Status</TableHead>
                  <TableHead className="text-xs font-semibold hidden lg:table-cell">Catatan</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {isLoading ? (
                  <TableRow>
                    <TableCell colSpan={7} className="text-center py-10">
                      <Loader2 className="w-6 h-6 animate-spin mx-auto text-blue-500 mb-2" />
                      <p className="text-sm text-gray-500">Memuat data absensi dari HR...</p>
                    </TableCell>
                  </TableRow>
                ) : filteredRecords.length > 0 ? (
                  filteredRecords.map(record => {
                    const cfg = getStatusConfig(record.status);
                    const recordDate = record.date ? new Date(record.date + 'T00:00:00') : null;
                    const isRecordToday = recordDate ? isToday(recordDate) : false;
                    return (
                      <TableRow key={record.id} className={isRecordToday ? 'bg-blue-50/30 dark:bg-blue-950/10' : 'hover:bg-gray-50 dark:hover:bg-gray-800/30'}>
                        <TableCell className="text-xs md:text-sm">
                          <div className="flex items-center gap-2">
                            <div className="w-7 h-7 rounded-full bg-blue-100 dark:bg-blue-900/40 flex items-center justify-center text-blue-700 dark:text-blue-300 text-xs font-bold flex-shrink-0">
                              {getMemberInitial(record)}
                            </div>
                            <span className="truncate max-w-[100px] md:max-w-none font-medium">
                              {getMemberName(record)}
                            </span>
                          </div>
                        </TableCell>
                        <TableCell className="text-xs md:text-sm">
                          <div className="flex items-center gap-1">
                            {record.date ? record.date.substring(0, 10) : '-'}
                            {isRecordToday && <Badge className="text-[10px] bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-300 px-1 py-0">Hari ini</Badge>}
                          </div>
                        </TableCell>
                        <TableCell className="text-xs md:text-sm font-mono">
                          {record.clock_in_time ? (() => {
                            try { return format(new Date(record.clock_in_time), 'HH:mm'); }
                            catch { return record.clock_in_time; }
                          })() : '-'}
                        </TableCell>
                        <TableCell className="text-xs md:text-sm font-mono">
                          {record.clock_out_time ? (() => {
                            try { return format(new Date(record.clock_out_time), 'HH:mm'); }
                            catch { return record.clock_out_time; }
                          })() : <span className="text-gray-400">-</span>}
                        </TableCell>
                        <TableCell className="text-xs md:text-sm hidden md:table-cell">
                          {record.total_hours != null
                            ? <span className="font-semibold">{Number(record.total_hours).toFixed(1)}h</span>
                            : <span className="text-gray-400">-</span>
                          }
                        </TableCell>
                        <TableCell>
                          <Badge className={`text-xs ${cfg.color} whitespace-nowrap`}>
                            {cfg.icon} {cfg.label}
                          </Badge>
                        </TableCell>
                        <TableCell className="text-xs text-gray-500 hidden lg:table-cell max-w-[150px] truncate">
                          {record.notes || '-'}
                        </TableCell>
                      </TableRow>
                    );
                  })
                ) : (
                  <TableRow>
                    <TableCell colSpan={7} className="text-center py-12">
                      <Clock className="w-10 h-10 mx-auto mb-2 text-gray-300 dark:text-gray-600" />
                      <p className="text-sm font-medium text-gray-500 dark:text-gray-400">Tidak ada data kehadiran</p>
                      <p className="text-xs text-gray-400 dark:text-gray-500 mt-1">Coba ubah filter untuk melihat data lainnya</p>
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

/**
 * WorkspaceHRSync - Full real-time integration between Workspace tasks and HR modules
 * Triggers on: task completion, status change, briefing, penawaran, live, keluhan
 * Updates: CompanyKPI, CompanyAttendance, CompanyPayroll signals, AuditLog
 */
import { useEffect, useRef } from 'react';
import { base44 } from '@/api/base44Client';
import { Task } from '@/entities/Task';
import { format } from 'date-fns';
import { toast } from 'sonner';

const KPI_WEIGHTS = {
  task_completed:      { score: 10, metric: 'Task Completion',   label: 'Γ£à Tugas Selesai' },
  task_completed_late: { score: 5,  metric: 'Task Completion',   label: 'ΓÅ░ Tugas Selesai (Terlambat)' },
  briefing_log:        { score: 5,  metric: 'Briefing & Training', label: '≡ƒôï Briefing Dilakukan' },
  penawaran_log:       { score: 15, metric: 'Sales / Penawaran',  label: '≡ƒñ¥ Penawaran Dibuat' },
  penawaran_closing:   { score: 25, metric: 'Sales / Penawaran',  label: '≡ƒÅå Penawaran Closing' },
  live_streaming_log:  { score: 10, metric: 'Live Streaming',     label: '≡ƒö┤ Live Session' },
  complain_resolved:   { score: 12, metric: 'Customer Service',   label: '≡ƒÄ» Keluhan Diselesaikan' },
  task_in_progress:    { score: 2,  metric: 'Task Completion',    label: '≡ƒöä Mulai Mengerjakan Tugas' },
};

export default function WorkspaceHRSync({ workspace, currentUser, companyId }) {
  const syncedRef = useRef(new Set());

  // ΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const getMemberByEmail = async (email, compId) => {
    try {
      const members = await base44.entities.CompanyMember.filter({
        company_id: compId,
        user_email: email,
        status: 'active'
      });
      return members?.[0] || null;
    } catch { return null; }
  };

  // ΓöÇΓöÇ Auto Attendance ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const autoMarkAttendance = async (assigneeEmail, compId) => {
    if (!assigneeEmail || !compId) return;
    try {
      const today = format(new Date(), 'yyyy-MM-dd');
      const member = await getMemberByEmail(assigneeEmail, compId);
      if (!member) return;

      const existing = await base44.entities.CompanyAttendance.filter({
        company_id: compId,
        employee_id: member.id,
        date: today
      });

      if (!existing || existing.length === 0) {
        await base44.entities.CompanyAttendance.create({
          company_id: compId,
          employee_id: member.id,
          employee_name: member.user_name || member.user_email,
          employee_email: member.user_email,
          date: today,
          clock_in_time: new Date().toISOString(),
          status: 'present',
          notes: 'Auto-recorded dari Workspace task start',
          total_hours: 0
        });

        window.dispatchEvent(new CustomEvent('hrAttendanceUpdated', {
          detail: { employeeEmail: assigneeEmail, companyId: compId, date: today }
        }));
        console.log('Γ£à HR Sync: Attendance auto-recorded for', assigneeEmail);
      }
    } catch (e) {
      console.warn('HR Sync attendance error:', e);
    }
  };

  // ΓöÇΓöÇ KPI Update ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const updateKPI = async (assigneeEmail, compId, kpiType, taskTitle, taskId) => {
    if (!assigneeEmail || !compId) return;
    const config = KPI_WEIGHTS[kpiType];
    if (!config) return;

    try {
      const member = await getMemberByEmail(assigneeEmail, compId);
      if (!member) return;

      const period = format(new Date(), 'yyyy-MM');

      const existingKPIs = await base44.entities.CompanyKPI.filter({
        company_id: compId,
        employee_id: member.id,
        period
      });

      let kpi = existingKPIs?.[0];

      if (!kpi) {
        // Create fresh KPI record ΓÇö enrich with REAL data
        const period_start = `${period}-01`;
        const period_end = `${period}-31`;

        // Fetch real attendance for this employee in this period
        let attendanceRate = 0;
        let presentDays = 0;
        let workingDays = 1;
        try {
          const attendance = await base44.entities.CompanyAttendance.filter({
            company_id: compId,
            employee_id: member.id
          });
          const periodAtt = (attendance || []).filter(a => a.date >= period_start && a.date <= period_end);
          presentDays = periodAtt.filter(a => a.status === 'present' || a.status === 'late').length;
          // Calculate working days in period
          const [yr, mo] = period.split('-').map(Number);
          const daysInMonth = new Date(yr, mo, 0).getDate();
          workingDays = 0;
          for (let d = 1; d <= daysInMonth; d++) {
            const dow = new Date(yr, mo - 1, d).getDay();
            if (dow !== 0 && dow !== 6) workingDays++;
          }
          // Cap to today if current month
          const today = new Date();
          if (period === format(today, 'yyyy-MM')) {
            let passed = 0;
            for (let d = 1; d <= today.getDate(); d++) {
              const dow = new Date(yr, mo - 1, d).getDay();
              if (dow !== 0 && dow !== 6) passed++;
            }
            workingDays = passed || 1;
          }
          attendanceRate = workingDays > 0 ? Math.round((presentDays / workingDays) * 100) : 0;
        } catch (e) { /* silent */ }

        // Fetch real POS sales for this employee
        let totalSales = 0;
        try {
          const transactions = await base44.entities.CompanyPOSTransaction.filter({
            company_id: compId
          });
          const empTx = (transactions || []).filter(t => {
            const tDate = (t.transaction_date || t.created_date || '').substring(0, 10);
            const isInPeriod = tDate >= period_start && tDate <= period_end;
            const isEmp = t.cashier_id === member.id || t.cashier_id === member.user_email || t.cashier_name === (member.user_name || '');
            return isInPeriod && isEmp;
          });
          totalSales = empTx.reduce((s, t) => s + (t.total || t.total_amount || 0), 0);
        } catch (e) { /* silent */ }

        const omsetTarget = 10000000; // 10M default

        await base44.entities.CompanyKPI.create({
          company_id: compId,
          employee_id: member.id,
          employee_name: member.user_name || member.user_email,
          employee_email: member.user_email,
          period,
          overall_score: config.score,
          status: 'draft',
          workspace_activities: [{
            type: kpiType,
            task_id: taskId,
            task_title: taskTitle,
            score: config.score,
            label: config.label,
            recorded_at: new Date().toISOString()
          }],
          metrics: [
            { name: 'Absensi Harian', target: 100, actual: attendanceRate, unit: '%', weight: 25, description: `${presentDays} hadir dari ${workingDays} hari kerja` },
            { name: 'Omset Penjualan POS', target: omsetTarget, actual: totalSales, unit: 'Rp', weight: 25, description: 'Total penjualan POS bulan ini' },
            { name: 'Penyelesaian Tugas', target: 100, actual: kpiType.includes('task') ? config.score : 0, unit: 'poin', weight: 30 },
            { name: 'Aktivitas Workspace', target: 100, actual: config.score, unit: 'poin', weight: 20 },
          ]
        });
      } else {
        // Update existing KPI
        const activities = kpi.workspace_activities || [];
        activities.push({
          type: kpiType,
          task_id: taskId,
          task_title: taskTitle,
          score: config.score,
          label: config.label,
          recorded_at: new Date().toISOString()
        });

        // Update metrics ΓÇö use new metric names with fallback
        const metrics = kpi.metrics || [];
        // For task-related activities, update "Penyelesaian Tugas" or "Aktivitas Workspace"
        let targetMetricName = 'Aktivitas Workspace';
        if (kpiType.includes('task')) {
          targetMetricName = 'Penyelesaian Tugas';
        }
        
        // Try new metric name first, then fall back to old config.metric name
        let targetMetric = metrics.find(m => m.name === targetMetricName) || metrics.find(m => m.name === config.metric);
        if (targetMetric) {
          targetMetric.actual = Math.min(targetMetric.target, (targetMetric.actual || 0) + config.score);
        }

        // Also update Aktivitas Workspace score (cumulative activity points)
        const activityMetric = metrics.find(m => m.name === 'Aktivitas Workspace');
        if (activityMetric && targetMetricName !== 'Aktivitas Workspace') {
          activityMetric.actual = Math.min(activityMetric.target, (activityMetric.actual || 0) + config.score);
        }

        // Recalculate overall
        const totalWeight = metrics.reduce((s, m) => s + (m.weight || 0), 0);
        const newScore = totalWeight > 0
          ? Math.min(100, metrics.reduce((s, m) => s + Math.min(m.target, m.actual || 0) / m.target * 100 * ((m.weight || 0) / 100), 0))
          : Math.min(100, (kpi.overall_score || 0) + config.score);

        await base44.entities.CompanyKPI.update(kpi.id, {
          metrics,
          overall_score: Math.round(newScore),
          workspace_activities: activities
        });
      }

      console.log(`Γ£à HR Sync: KPI updated (${kpiType}) for`, assigneeEmail, '+ score', config.score);

      // Broadcast to KPI page for live reload
      window.dispatchEvent(new CustomEvent('hrKPIUpdated', {
        detail: { employeeEmail: assigneeEmail, companyId: compId, period, kpiType, score: config.score }
      }));

      // Payroll signal
      window.dispatchEvent(new CustomEvent('hrPayrollSignal', {
        detail: { employeeEmail: assigneeEmail, companyId: compId, reason: kpiType, taskId, period }
      }));

    } catch (e) {
      console.warn('HR Sync KPI error:', e);
    }
  };

  // ΓöÇΓöÇ Audit Log ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const logActivity = async (assigneeEmail, compId, action, taskTitle, detail) => {
    try {
      await base44.entities.AuditLog.create({
        company_id: compId,
        user_email: assigneeEmail,
        action,
        entity_type: 'Task',
        entity_name: taskTitle,
        detail,
        recorded_at: new Date().toISOString()
      });
    } catch (e) { /* silent - AuditLog is optional */ }
  };

  // ΓöÇΓöÇ Main Event Handler ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  const handleTaskStatusChanged = async (event) => {
    const { taskId, newStatus, workspaceId } = event.detail || {};
    if (!workspaceId || workspaceId !== workspace?.id) return;
    if (!companyId) return;

    const dedupKey = `${taskId}-${newStatus}`;
    if (syncedRef.current.has(dedupKey)) return;
    syncedRef.current.add(dedupKey);

    try {
      const task = await Task.get(taskId);
      if (!task || !task.assignee_id) return;

      const assigneeEmail = task.assignee_id;
      const taskType = task.task_type || '';
      const isLate = task.due_date && new Date() > new Date(task.due_date);

      // ΓöÇΓöÇ When task starts ΓåÆ auto attendance
      if (newStatus === 'in_progress') {
        await autoMarkAttendance(assigneeEmail, companyId);
        await updateKPI(assigneeEmail, companyId, 'task_in_progress', task.title, taskId);
        await logActivity(assigneeEmail, companyId, 'TASK_STARTED', task.title, `Status berubah ke In Progress`);
      }

      // ΓöÇΓöÇ When task completes
      if (newStatus === 'done' || newStatus === 'completed') {
        // Determine KPI type based on task type
        let kpiType = isLate ? 'task_completed_late' : 'task_completed';

        if (taskType === 'briefing_log') kpiType = 'briefing_log';
        else if (taskType === 'live_streaming_log') kpiType = 'live_streaming_log';
        else if (taskType === 'complain_log') kpiType = 'complain_resolved';
        else if (taskType === 'penawaran_log') {
          // Check if it's a closing (content contains "closing" or "deal")
          const content = (task.content || '').toLowerCase();
          kpiType = (content.includes('closing') || content.includes('deal') || content.includes('setuju'))
            ? 'penawaran_closing' : 'penawaran_log';
        }

        await updateKPI(assigneeEmail, companyId, kpiType, task.title, taskId);
        await logActivity(assigneeEmail, companyId, 'TASK_COMPLETED', task.title, `${KPI_WEIGHTS[kpiType]?.label} | +${KPI_WEIGHTS[kpiType]?.score} poin KPI`);

        // Mark task as HR synced
        await Task.update(taskId, { hr_synced: true });

        // Show toast confirmation if the current user is admin/owner
        if (currentUser && (currentUser.email !== assigneeEmail)) {
          toast.success(`Γ£à KPI ${task.assignee_id} diperbarui otomatis`, { duration: 3000 });
        }
      }

    } catch (e) {
      console.warn('HR Sync task status handler error:', e);
    }
  };

  const handleTaskCreated = async (event) => {
    const { taskId, assigneeId, workspaceId } = event.detail || {};
    if (!workspaceId || workspaceId !== workspace?.id) return;
    if (!companyId || !assigneeId) return;
    // Auto-mark attendance on task assignment
    await autoMarkAttendance(assigneeId, companyId);
  };

  // ΓöÇΓöÇ KPI Page live reload listener ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const handleHrKPIUpdated = (event) => {
    const { companyId: updatedCompId } = event.detail || {};
    if (updatedCompId !== companyId) return;
    // Trigger KPI page reload if open
    window.dispatchEvent(new CustomEvent('kpiPageReload', { detail: { companyId } }));
  };

  useEffect(() => {
    if (!workspace?.id || !companyId) return;

    window.addEventListener('taskStatusChanged', handleTaskStatusChanged);
    window.addEventListener('taskCreated', handleTaskCreated);
    window.addEventListener('hrKPIUpdated', handleHrKPIUpdated);

    return () => {
      window.removeEventListener('taskStatusChanged', handleTaskStatusChanged);
      window.removeEventListener('taskCreated', handleTaskCreated);
      window.removeEventListener('hrKPIUpdated', handleHrKPIUpdated);
    };
  }, [workspace?.id, companyId]);

  return null; // Headless sync component
}

import { Badge } from '@/components/ui/badge';
import { Crown, Star, Edit, Share2, ArrowLeft, CheckCircle2, Clock, FileText, Users, TrendingUp, AlertCircle } from 'lucide-react';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';
import { createPageUrl } from '@/utils';

const roleColors = {
  owner: 'bg-amber-100 text-amber-800 dark:bg-amber-900/60 dark:text-amber-200 border border-amber-300 dark:border-amber-700',
  admin: 'bg-red-100 text-red-800 dark:bg-red-900/60 dark:text-red-200 border border-red-300 dark:border-red-700',
  member: 'bg-blue-100 text-blue-800 dark:bg-blue-900/60 dark:text-blue-200 border border-blue-300 dark:border-blue-700',
  viewer: 'bg-gray-100 text-gray-800 dark:bg-gray-700/60 dark:text-gray-200 border border-gray-300 dark:border-gray-600'
};

const roleNames = { owner: 'Pemilik', admin: 'Admin', member: 'Anggota', viewer: 'Peninjau' };
const roleIcons = { owner: Crown, admin: Star, member: Edit, viewer: Share2 };

export default function WorkspaceHeader({ workspace, userRole, stats = { totalTasks: 0, completedTasks: 0, totalNotes: 0, totalMembers: 0, openComplaints: 0, pendingOffers: 0 }, onUpdate }) {
  const RoleIcon = roleIcons[userRole] || Edit;
  const completionRate = stats.totalTasks > 0 ? Math.round((stats.completedTasks / stats.totalTasks) * 100) : 0;

  const getProgressColor = () => {
    if (completionRate >= 75) return 'bg-green-500';
    if (completionRate >= 40) return 'bg-blue-500';
    return 'bg-amber-500';
  };

  return (
    <div className="space-y-0">
      {/* Breadcrumb */}
      <div className="flex items-center gap-2 mb-4 text-sm text-gray-500 dark:text-gray-400">
        <button
          onClick={() => window.location.href = createPageUrl("Workspaces")}
          className="flex items-center gap-1.5 hover:text-blue-600 dark:hover:text-blue-400 transition-colors font-medium"
        >
          <ArrowLeft className="w-4 h-4" />
          <span>Daftar Workspace</span>
        </button>
        <span className="text-gray-300 dark:text-gray-600">/</span>
        <span className="text-gray-900 dark:text-gray-100 font-semibold truncate max-w-[200px]">{workspace.name}</span>
      </div>

      {/* Main Header Card */}
      <div className="rounded-2xl overflow-hidden shadow-lg border border-gray-200 dark:border-gray-700">
        {/* Top Banner with gradient pattern */}
        <div
          className="relative h-28 md:h-36"
          style={{ background: `linear-gradient(135deg, ${workspace.color || '#2563eb'}, ${workspace.color || '#2563eb'}88, #1e1b4b55)` }}
        >
          <div className="absolute inset-0"
            style={{ backgroundImage: 'radial-gradient(circle at 20% 50%, rgba(255,255,255,0.08) 0%, transparent 50%), radial-gradient(circle at 80% 20%, rgba(255,255,255,0.05) 0%, transparent 40%)' }}
          />
          <div className="absolute inset-0 opacity-5"
            style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 20px, rgba(255,255,255,.3) 20px, rgba(255,255,255,.3) 21px)' }}
          />
        </div>

        {/* Profile Section */}
        <div className="bg-white dark:bg-gray-800 px-4 md:px-6 pb-5">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 -mt-12">
            <div className="flex items-end gap-4">
              {/* Workspace Icon */}
              <div
                className="w-20 h-20 rounded-2xl border-4 border-white dark:border-gray-800 shadow-xl flex items-center justify-center text-3xl font-bold text-white flex-shrink-0"
                style={{ backgroundColor: workspace.color || '#2563eb' }}
              >
                {workspace.icon || workspace.name?.charAt(0)}
              </div>
              <div className="mb-1 pb-1">
                <div className="flex items-center gap-2 flex-wrap">
                  <h1 className="text-xl md:text-2xl font-bold text-gray-900 dark:text-gray-100">{workspace.name}</h1>
                  <Badge className={`${roleColors[userRole]} text-xs font-semibold px-2 py-0.5`}>
                    <RoleIcon className="w-3 h-3 mr-1" />
                    {roleNames[userRole]}
                  </Badge>
                  {workspace.is_personal && (
                    <Badge variant="secondary" className="text-xs">Pribadi</Badge>
                  )}
                </div>
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-1 flex items-center gap-1.5 flex-wrap">
                  <span>{workspace.description || 'Workspace Operasional'}</span>
                  {workspace.created_date && (
                    <>
                      <span className="text-gray-300 dark:text-gray-600">┬╖</span>
                      <span>Dibuat {format(new Date(workspace.created_date), 'dd MMM yyyy', { locale: id })}</span>
                    </>
                  )}
                </p>
              </div>
            </div>

            <div className="flex items-center gap-2 pb-1 flex-shrink-0">
              <button
                onClick={() => window.location.href = createPageUrl("Workspaces")}
                className="flex items-center gap-1.5 px-4 py-2 rounded-xl border border-gray-200 dark:border-gray-600 text-sm text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 hover:border-gray-300 dark:hover:border-gray-500 transition-all font-medium shadow-sm"
              >
                <ArrowLeft className="w-4 h-4" />
                Kembali
              </button>
            </div>
          </div>

          {/* Progress bar with label */}
          <div className="mt-5 space-y-1.5">
            <div className="flex justify-between items-center text-xs">
              <span className="text-gray-500 dark:text-gray-400 font-medium">Progres Penyelesaian Tugas</span>
              <div className="flex items-center gap-2">
                <span className="text-gray-400 dark:text-gray-500">{stats.completedTasks}/{stats.totalTasks} tugas</span>
                <span className={`font-bold text-sm ${completionRate >= 75 ? 'text-green-600' : completionRate >= 40 ? 'text-blue-600' : 'text-amber-600'}`}>
                  {completionRate}%
                </span>
              </div>
            </div>
            <div className="h-2.5 bg-gray-100 dark:bg-gray-700 rounded-full overflow-hidden">
              <div
                className={`h-full rounded-full transition-all duration-700 ${getProgressColor()}`}
                style={{ width: `${completionRate}%` }}
              />
            </div>
          </div>

          {/* KPI Stats Row */}
          <div className="grid grid-cols-3 md:grid-cols-6 gap-2 md:gap-3 mt-5">
            <StatBox
              icon={<CheckCircle2 className="w-4 h-4" />}
              label="Total Tugas"
              value={stats.totalTasks}
              color="blue"
              onClick={() => {}}
            />
            <StatBox
              icon={<TrendingUp className="w-4 h-4" />}
              label="Selesai"
              value={stats.completedTasks}
              color="green"
            />
            <StatBox
              icon={<Clock className="w-4 h-4" />}
              label="Aktif"
              value={stats.totalTasks - stats.completedTasks}
              color="yellow"
            />
            <StatBox
              icon={<FileText className="w-4 h-4" />}
              label="Catatan"
              value={stats.totalNotes}
              color="purple"
            />
            <StatBox
              icon={<Users className="w-4 h-4" />}
              label="Anggota"
              value={stats.totalMembers}
              color="indigo"
            />
            <StatBox
              icon={<AlertCircle className="w-4 h-4" />}
              label="Keluhan"
              value={stats.openComplaints || 0}
              color="red"
              highlight={stats.openComplaints > 0}
            />
          </div>
        </div>
      </div>
    </div>
  );
}

function StatBox({ icon, label, value, color, highlight = false }) {
