export default function WorkspaceKPI({ workspace, companyId, currentUser, companyMembers = [] }) {
  const [kpis, setKpis] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [selectedPeriod, setSelectedPeriod] = useState(new Date().toISOString().slice(0, 7));
  const [filterEmployee, setFilterEmployee] = useState('all');
  const [sortBy, setSortBy] = useState('score_desc');
  const syncedPeriodRef = React.useRef(null);

  // ΓöÇΓöÇ Helper: Calculate rating from score ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const getRating = (score) => {
    if (score >= 90) return 'outstanding';
    if (score >= 80) return 'exceeds';
    if (score >= 70) return 'meets';
    if (score >= 50) return 'needs_improvement';
    return 'unsatisfactory';
  };

  // ΓöÇΓöÇ CORE: Sync KPI with REAL company data ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const syncKPIWithRealData = async () => {
    if (!companyId || companyMembers.length === 0) return;
    
    // Prevent duplicate syncs for the same period
    const syncKey = `${companyId}_${selectedPeriod}`;
    if (syncedPeriodRef.current === syncKey) return;
    
    setIsSyncing(true);
    try {
      const startDate = `${selectedPeriod}-01`;
      const endDate = `${selectedPeriod}-31`;

      // ≡ƒöä Batch fetch ALL real data for the company in this period
      const [allAttendance, allTransactions, allTasks, existingKPIs] = await Promise.all([
        base44.entities.CompanyAttendance.filter({
          company_id: companyId
        }).catch(() => []),
        base44.entities.CompanyPOSTransaction.filter({
          company_id: companyId
        }).catch(() => []),
        workspace?.id ? base44.entities.Task.filter({
          workspace_id: workspace.id
        }).catch(() => []) : Promise.resolve([]),
        base44.entities.CompanyKPI.filter({
          company_id: companyId,
          period: selectedPeriod
        }).catch(() => [])
      ]);

      // Filter attendance and transactions by period date range
      const periodAttendance = (allAttendance || []).filter(a => {
        if (!a.date) return false;
        return a.date >= startDate && a.date <= endDate;
      });
      const periodTransactions = (allTransactions || []).filter(t => {
        const tDate = t.transaction_date || t.created_date;
        if (!tDate) return false;
        const dateStr = tDate.substring(0, 10);
        return dateStr >= startDate && dateStr <= endDate;
      });

      // Count working days in the period (exclude weekends)
      const year = parseInt(selectedPeriod.split('-')[0]);
      const month = parseInt(selectedPeriod.split('-')[1]) - 1;
      const daysInMonth = new Date(year, month + 1, 0).getDate();
      let workingDays = 0;
      for (let d = 1; d <= daysInMonth; d++) {
        const dayOfWeek = new Date(year, month, d).getDay();
        if (dayOfWeek !== 0 && dayOfWeek !== 6) workingDays++;
      }
      // Cap working days to today if period is current month
      const today = new Date();
      const todayStr = today.toISOString().slice(0, 10);
      if (selectedPeriod === today.toISOString().slice(0, 7)) {
        let passedWorkingDays = 0;
        for (let d = 1; d <= today.getDate(); d++) {
          const dayOfWeek = new Date(year, month, d).getDay();
          if (dayOfWeek !== 0 && dayOfWeek !== 6) passedWorkingDays++;
        }
        workingDays = passedWorkingDays;
      }

      // Get total tasks in workspace
      const totalWorkspaceTasks = (allTasks || []).filter(t => 
        !t.task_type || t.task_type === '' // Only count regular tasks
      ).length;
      
      let updated = false;

      for (const member of companyMembers) {
        // ΓöÇΓöÇ Real Attendance Data ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
        const empAttendance = periodAttendance.filter(a => 
          a.employee_id === member.id || 
          a.employee_email === member.user_email
        );
        const presentDays = empAttendance.filter(a => 
          a.status === 'present' || a.status === 'late'
        ).length;
        const attendanceRate = workingDays > 0 ? Math.round((presentDays / workingDays) * 100) : 0;

        // ΓöÇΓöÇ Real POS Sales Data ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
        const empTransactions = periodTransactions.filter(t =>
          t.cashier_id === member.id || 
          t.cashier_id === member.user_email ||
          t.cashier_name === member.user_name ||
          t.assigned_to_id === member.id ||
          t.assigned_to_id === member.user_email
        );
        const totalSales = empTransactions.reduce((sum, t) => sum + (t.total || t.total_amount || 0), 0);

        // ΓöÇΓöÇ Real Task Completion ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
        const empTasks = (allTasks || []).filter(t => 
          (t.assignee_id === member.user_email || t.assignee_id === member.id) &&
          (!t.task_type || t.task_type === '')
        );
        const completedTasks = empTasks.filter(t => 
          t.status === 'done' || t.status === 'completed'
        ).length;
        const taskTotal = empTasks.length || totalWorkspaceTasks || 1; // Avoid division by zero
        const taskCompletionRate = Math.round((completedTasks / taskTotal) * 100);

        // ΓöÇΓöÇ Build enriched metrics ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
        const existingKPI = (existingKPIs || []).find(k => 
          k.employee_id === member.id || k.employee_email === member.user_email
        );

        // Preserve existing workspace activities
        const existingActivities = existingKPI?.workspace_activities || [];
        const activityScore = existingActivities.reduce((s, a) => s + (a.score || 0), 0);
        const activityMax = 100; // Max score from activities
        const activityRate = Math.min(100, Math.round((activityScore / activityMax) * 100));

        // Define the target omset (use company-level or default 10M)
        const omsetTarget = 10000000; // 10 juta default target

        const enrichedMetrics = [
          { 
            name: 'Absensi Harian', 
            target: 100, 
            actual: attendanceRate, 
            unit: '%', 
            weight: 25,
            description: `${presentDays} hadir dari ${workingDays} hari kerja`
          },
          { 
            name: 'Omset Penjualan POS', 
            target: omsetTarget, 
            actual: totalSales, 
            unit: 'Rp', 
            weight: 25,
            description: `Total penjualan POS bulan ini`
          },
          { 
            name: 'Penyelesaian Tugas', 
            target: taskTotal, 
            actual: completedTasks, 
            unit: 'tugas', 
            weight: 30,
            description: `${completedTasks} selesai dari ${taskTotal} tugas`
          },
          { 
            name: 'Aktivitas Workspace', 
            target: activityMax, 
            actual: Math.min(activityMax, activityScore), 
            unit: 'poin', 
            weight: 20,
            description: `${existingActivities.length} aktivitas tercatat`
          }
        ];

        // Calculate overall score (weighted average of achievement %)
        const overallScore = Math.min(100, enrichedMetrics.reduce((total, m) => {
          const achievement = m.target > 0 ? Math.min(100, (m.actual / m.target) * 100) : 0;
          return total + (achievement * (m.weight / 100));
        }, 0));

        const rating = getRating(overallScore);

        if (existingKPI) {
          // Update existing KPI with real data
          await base44.entities.CompanyKPI.update(existingKPI.id, {
            metrics: enrichedMetrics,
            overall_score: Math.round(overallScore),
            rating,
            employee_name: member.user_name || member.user_email,
            employee_email: member.user_email
          });
          updated = true;
        } else {
          // Create new KPI with real data for this member
          await base44.entities.CompanyKPI.create({
            company_id: companyId,
            employee_id: member.id,
            employee_name: member.user_name || member.user_email,
            employee_email: member.user_email,
            period: selectedPeriod,
            overall_score: Math.round(overallScore),
            rating,
            status: 'draft',
            metrics: enrichedMetrics,
            workspace_activities: existingActivities,
            auto_generated: true
          });
          updated = true;
        }
      }

      if (updated) {
        syncedPeriodRef.current = syncKey;
        // Reload KPIs to reflect changes
        const freshKPIs = await base44.entities.CompanyKPI.filter({
          company_id: companyId,
          period: selectedPeriod
        });
        setKpis(freshKPIs || []);
        console.log('Γ£à KPI synced with real data for', companyMembers.length, 'members');
      }
    } catch (e) {
      console.error('KPI sync error:', e);
    } finally {
      setIsSyncing(false);
    }
  };

  const loadKPIs = async () => {
    if (!companyId) return;
    setIsLoading(true);
    try {
      const data = await base44.entities.CompanyKPI.filter({
        company_id: companyId,
        period: selectedPeriod
      });
      setKpis(data || []);
    } catch (e) {
      toast.error('Gagal memuat data KPI');
    } finally {
      setIsLoading(false);
    }
  };

  // Load KPIs and then auto-sync with real data
  useEffect(() => {
    if (!companyId) return;
    syncedPeriodRef.current = null; // Reset sync flag on period change
    loadKPIs();
  }, [companyId, selectedPeriod]);

  // Auto-sync after KPIs are loaded and members are available
  useEffect(() => {
    if (companyMembers.length > 0 && companyId && !isSyncing) {
      syncKPIWithRealData();
    }
  }, [companyMembers, companyId, selectedPeriod]);

  // Listen to realtime KPI updates from WorkspaceHRSync
  useEffect(() => {
    const handler = (e) => {
      if (e.detail?.companyId === companyId) {
        syncedPeriodRef.current = null; // Allow re-sync
        loadKPIs().then(() => syncKPIWithRealData());
      }
    };
    window.addEventListener('hrKPIUpdated', handler);
    window.addEventListener('kpiPageReload', handler);
    return () => {
      window.removeEventListener('hrKPIUpdated', handler);
      window.removeEventListener('kpiPageReload', handler);
    };
  }, [companyId]);

  // Manual refresh handler
  const handleRefresh = async () => {
    syncedPeriodRef.current = null;
    await loadKPIs();
    await syncKPIWithRealData();
    toast.success('≡ƒöä KPI berhasil di-sync dengan data real!');
  };

  // Sorted & filtered KPIs
  const displayKPIs = useMemo(() => {
    let result = kpis;
    if (filterEmployee !== 'all') result = result.filter(k => k.employee_id === filterEmployee || k.employee_email === filterEmployee);

    switch (sortBy) {
      case 'score_desc': return [...result].sort((a, b) => (b.overall_score || 0) - (a.overall_score || 0));
      case 'score_asc': return [...result].sort((a, b) => (a.overall_score || 0) - (b.overall_score || 0));
      case 'name': return [...result].sort((a, b) => (a.employee_name || '').localeCompare(b.employee_name || ''));
      default: return result;
    }
  }, [kpis, filterEmployee, sortBy]);

  // Stats
  const stats = useMemo(() => ({
    total: kpis.length,
    avg: kpis.length > 0 ? kpis.reduce((s, k) => s + (k.overall_score || 0), 0) / kpis.length : 0,
    outstanding: kpis.filter(k => k.rating === 'outstanding').length,
    needsImprovement: kpis.filter(k => k.rating === 'needs_improvement' || k.rating === 'unsatisfactory').length,
    autoSynced: kpis.filter(k => (k.workspace_activities || []).length > 0).length,
  }), [kpis]);

  if (!companyId) {
    return (
      <Card className="border-dashed border-2 dark:border-gray-700">
        <CardContent className="text-center py-12">
          <Target className="w-12 h-12 mx-auto mb-3 text-gray-300 dark:text-gray-600" />
          <p className="text-sm font-medium text-gray-500">KPI hanya tersedia untuk workspace yang terhubung dengan perusahaan</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
        <div>
          <h2 className="text-xl font-bold text-gray-900 dark:text-gray-100 flex items-center gap-2">
            <Target className="w-5 h-5 text-blue-500" />
            KPI Tracking
          </h2>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-0.5">
            Real-time terintegrasi dengan aktivitas workspace ΓÇö otomatis update saat tugas selesai
          </p>
        </div>
        <div className="flex items-center gap-2 flex-shrink-0">
          <input
            type="month"
            value={selectedPeriod}
            onChange={(e) => setSelectedPeriod(e.target.value)}
            className="bg-gray-100 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 text-gray-900 dark:text-white rounded-lg px-3 py-1.5 text-sm"
          />
          <Button variant="outline" size="sm" onClick={handleRefresh} disabled={isLoading || isSyncing} className="gap-1.5">
            <RefreshCw className={`w-3.5 h-3.5 ${(isLoading || isSyncing) ? 'animate-spin' : ''}`} />
          </Button>
          <a href={createPageUrl('KPI')} target="_blank" rel="noopener noreferrer">
            <Button size="sm" className="bg-blue-600 hover:bg-blue-700 gap-1.5">
              <ExternalLink className="w-3.5 h-3.5" />
              KPI Full Page
            </Button>
          </a>
        </div>
      </div>

      {/* Auto-sync info banner */}
      <div className="p-3 bg-teal-50 dark:bg-teal-950/30 rounded-xl border border-teal-200 dark:border-teal-800 flex items-start gap-3">
        <Zap className="w-5 h-5 text-teal-500 flex-shrink-0 mt-0.5" />
        <div className="text-sm text-teal-800 dark:text-teal-300 flex-1">
          <p className="font-semibold">KPI Terintegrasi Data Real Perusahaan</p>
          <p className="text-xs mt-0.5 opacity-80">
            Data KPI otomatis sinkron dengan: Absensi Harian, Omset Penjualan POS, Penyelesaian Tugas, dan Aktivitas Workspace
          </p>
        </div>
        {isSyncing && (
          <div className="flex items-center gap-1.5 text-xs text-teal-600 dark:text-teal-400 flex-shrink-0">
            <RefreshCw className="w-3.5 h-3.5 animate-spin" />
            <span>Sync...</span>
          </div>
        )}
      </div>

      {/* Stats row */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
        {[
          { label: 'Total Review', value: stats.total, icon: Users, color: 'text-gray-500', bg: 'bg-gray-50 dark:bg-gray-900/40' },
          { label: 'Rata-rata Score', value: `${stats.avg.toFixed(1)}`, icon: BarChart2, color: 'text-blue-500', bg: 'bg-blue-50 dark:bg-blue-950/30' },
          { label: 'Outstanding', value: stats.outstanding, icon: Star, color: 'text-green-500', bg: 'bg-green-50 dark:bg-green-950/30' },
          { label: 'Perlu Perbaikan', value: stats.needsImprovement, icon: AlertCircle, color: 'text-yellow-500', bg: 'bg-yellow-50 dark:bg-yellow-950/30' },
          { label: 'Auto-Synced', value: stats.autoSynced, icon: Zap, color: 'text-teal-500', bg: 'bg-teal-50 dark:bg-teal-950/30' },
        ].map(({ label, value, icon: Icon, color, bg }) => (
          <Card key={label} className={`border dark:border-gray-700 ${bg}`}>
            <CardContent className="p-3 flex items-center gap-2">
              <div className={`p-1.5 rounded-lg bg-white/60 dark:bg-gray-800/60 ${color}`}><Icon className="w-4 h-4" /></div>
              <div><p className="text-[10px] text-gray-500 dark:text-gray-400 leading-tight">{label}</p><p className="text-xl font-bold text-gray-900 dark:text-white">{value}</p></div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Avg progress bar */}
      {stats.total > 0 && (
        <div className="space-y-1.5">
          <div className="flex justify-between text-xs text-gray-500">
            <span>Rata-rata Performa Tim</span>
            <span className={`font-bold ${stats.avg >= 80 ? 'text-green-600' : stats.avg >= 60 ? 'text-blue-600' : 'text-yellow-600'}`}>{stats.avg.toFixed(1)}/100</span>
          </div>
          <div className="h-2.5 bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
            <div
              className={`h-full rounded-full transition-all duration-700 ${stats.avg >= 80 ? 'bg-green-500' : stats.avg >= 60 ? 'bg-blue-500' : 'bg-yellow-500'}`}
              style={{ width: `${stats.avg}%` }}
            />
          </div>
        </div>
      )}

      {/* Filters */}
      <div className="flex flex-col sm:flex-row gap-2">
        <Select value={filterEmployee} onValueChange={setFilterEmployee}>
          <SelectTrigger className="w-full sm:w-52 h-9 text-sm">
            <Users className="w-3.5 h-3.5 mr-1.5 text-gray-400" />
            <SelectValue placeholder="Semua Karyawan" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">Semua Karyawan</SelectItem>
            {companyMembers.map(m => (
              <SelectItem key={m.id} value={m.id}>{m.user_name || m.user_email}</SelectItem>
            ))}
          </SelectContent>
        </Select>
        <Select value={sortBy} onValueChange={setSortBy}>
          <SelectTrigger className="w-full sm:w-44 h-9 text-sm">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="score_desc">Score Tertinggi</SelectItem>
            <SelectItem value="score_asc">Score Terendah</SelectItem>
            <SelectItem value="name">Nama A-Z</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* KPI Cards */}
      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <RefreshCw className="w-6 h-6 animate-spin text-blue-500 mr-2" />
          <span className="text-sm text-gray-500">Memuat data KPI...</span>
        </div>
      ) : displayKPIs.length === 0 ? (
        <Card className="border-dashed border-2 dark:border-gray-700">
          <CardContent className="text-center py-12">
            <Target className="w-12 h-12 mx-auto mb-3 text-gray-300 dark:text-gray-600" />
            <p className="text-base font-semibold text-gray-500 dark:text-gray-400 mb-1">Belum ada data KPI</p>
            <p className="text-sm text-gray-400 dark:text-gray-500 mb-4">
              KPI akan otomatis muncul saat anggota workspace menyelesaikan tugas, briefing, penawaran, atau live streaming
            </p>
            <a href={createPageUrl('KPI')} target="_blank" rel="noopener noreferrer">
              <Button size="sm" className="bg-blue-600 hover:bg-blue-700">
                <ExternalLink className="w-4 h-4 mr-2" />
                Buat KPI Manual di KPI Page
              </Button>
            </a>
          </CardContent>
        </Card>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
          {displayKPIs.map(kpi => (
            <KPICard key={kpi.id} kpi={kpi} companyMembers={companyMembers} />
          ))}
        </div>
      )}

      {/* Rating legend */}
      {displayKPIs.length > 0 && (
        <Card className="border dark:border-gray-700 bg-gray-50 dark:bg-gray-900/50">
          <CardContent className="p-3">
            <p className="text-xs font-semibold text-gray-500 dark:text-gray-400 mb-2 uppercase tracking-wider">Skala Penilaian</p>
            <div className="flex flex-wrap gap-2">
              {Object.entries(RATING_CONFIG).map(([key, cfg]) => (
                <span key={key} className={`text-xs px-2.5 py-1 rounded-full font-medium ${cfg.color}`}>
                  {cfg.icon} {cfg.label} ({cfg.min}+)
                </span>
              ))}
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState, useMemo } from 'react';
import { WorkspaceMember } from '@/entities/WorkspaceMember';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { UserPlus, Crown, Shield, User, Eye, Mail, MoreHorizontal, Trash2, Search, Users } from 'lucide-react';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuSeparator, DropdownMenuTrigger } from '@/components/ui/dropdown-menu';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';

const roleColors = {
  owner: 'bg-amber-100 text-amber-800 dark:bg-amber-900/60 dark:text-amber-200 border border-amber-300 dark:border-amber-700',
  admin: 'bg-red-100 text-red-800 dark:bg-red-900/60 dark:text-red-200 border border-red-300 dark:border-red-700',
  member: 'bg-blue-100 text-blue-800 dark:bg-blue-900/60 dark:text-blue-200 border border-blue-300 dark:border-blue-700',
  viewer: 'bg-gray-100 text-gray-800 dark:bg-gray-700/60 dark:text-gray-200 border border-gray-300 dark:border-gray-600'
};

const roleNames = { owner: 'Pemilik', admin: 'Admin', member: 'Anggota', viewer: 'Peninjau' };
const roleIcons = { owner: Crown, admin: Shield, member: User, viewer: Eye };
const roleDescriptions = {
  owner: 'Akses penuh, kontrol semua pengaturan',
  admin: 'Akses penuh kecuali pengaturan workspace',
  member: 'Dapat membuat dan mengedit tugas',
  viewer: 'Hanya dapat melihat konten'
};

const AVATAR_COLORS = [
  'bg-blue-500', 'bg-purple-500', 'bg-green-500', 'bg-amber-500', 'bg-rose-500', 'bg-teal-500', 'bg-indigo-500'
];

function getAvatarColor(str = '') {
  let hash = 0;
  for (let i = 0; i < str.length; i++) hash = str.charCodeAt(i) + ((hash << 5) - hash);
  return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
}

export default function WorkspaceMembers({ workspaceId, members, workspace, userRole, onUpdate, companyMembers = [] }) {
  const [showInviteForm, setShowInviteForm] = useState(false);
  const [inviteEmail, setInviteEmail] = useState('');
  const [inviteRole, setInviteRole] = useState('member');
  const [isInviting, setIsInviting] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterRole, setFilterRole] = useState('all');

  const canManageMembers = userRole === 'owner' || userRole === 'admin';

  const handleInviteMember = async () => {
    if (!inviteEmail.trim()) { toast.error('Email tidak boleh kosong'); return; }
    if (!canManageMembers) { toast.error('Anda tidak memiliki izin'); return; }

    setIsInviting(true);
    try {
      const existingMember = members.find(m => m.user_id === inviteEmail);
      if (existingMember) { toast.error('Pengguna sudah menjadi anggota'); setIsInviting(false); return; }

      const targetWorkspaceId = workspaceId || workspace?.id;
      if (!targetWorkspaceId) { toast.error('ID Workspace tidak ditemukan'); setIsInviting(false); return; }

      await WorkspaceMember.create({
        workspace_id: targetWorkspaceId,
        user_id: inviteEmail,
        role: inviteRole,
        invited_by: workspace.owner_id,
        joined_at: new Date().toISOString(),
        permissions: {
          can_create_tasks: true,
          can_edit_tasks: inviteRole !== 'viewer',
          can_delete_tasks: inviteRole === 'admin' || inviteRole === 'owner',
          can_invite_members: inviteRole === 'admin' || inviteRole === 'owner'
        }
      });

      window.dispatchEvent(new CustomEvent('workspaceMemberAdded', { detail: { workspaceId: targetWorkspaceId, memberEmail: inviteEmail, role: inviteRole } }));
      toast.success(`Undangan berhasil dikirim ke ${inviteEmail}!`);
      setShowInviteForm(false);
      setInviteEmail('');
      setInviteRole('member');
      onUpdate();
    } catch (error) {
      toast.error('Gagal mengundang anggota');
    }
    setIsInviting(false);
  };

  const handleRemoveMember = async (memberId, memberName) => {
    if (!canManageMembers) { toast.error('Anda tidak memiliki izin'); return; }
    if (confirm(`Hapus ${memberName} dari workspace ini?`)) {
      try {
        await WorkspaceMember.delete(memberId);
        toast.success('Anggota berhasil dihapus');
        onUpdate();
      } catch (error) { toast.error('Gagal menghapus anggota'); }
    }
  };

  const handleChangeRole = async (memberId, newRole) => {
    if (userRole !== 'owner') { toast.error('Hanya pemilik yang dapat mengubah peran'); return; }
    try {
      await WorkspaceMember.update(memberId, {
        role: newRole,
        permissions: {
          can_create_tasks: true,
          can_edit_tasks: newRole !== 'viewer',
          can_delete_tasks: newRole === 'admin' || newRole === 'owner',
          can_invite_members: newRole === 'admin' || newRole === 'owner'
        }
      });
      toast.success('Peran anggota berhasil diubah');
      onUpdate();
    } catch (error) { toast.error('Gagal mengubah peran'); }
  };

  // Build member list
  const ownerEntry = { id: 'owner', user_id: workspace.owner_id, role: 'owner', joined_at: workspace.created_date, isOwner: true };
  const seen = new Set([workspace.owner_id]);
  const dedupedMembers = members.filter(m => { if (seen.has(m.user_id)) return false; seen.add(m.user_id); return true; });
  const allMembers = [ownerEntry, ...dedupedMembers];

  // Filter & search
  const filteredMembers = useMemo(() => {
    return allMembers.filter(m => {
      const companyMember = companyMembers.find(cm => cm.user_email === m.user_id || cm.user_id === m.user_id);
      const displayName = companyMember?.user_name || m.user_id || '';
      const matchesSearch = displayName.toLowerCase().includes(searchQuery.toLowerCase()) ||
        m.user_id?.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesRole = filterRole === 'all' || m.role === filterRole;
      return matchesSearch && matchesRole;
    });
  }, [allMembers, searchQuery, filterRole, companyMembers]);

  const roleCounts = useMemo(() => {
    const counts = {};
    allMembers.forEach(m => { counts[m.role] = (counts[m.role] || 0) + 1; });
    return counts;
  }, [allMembers]);

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-bold text-gray-900 dark:text-gray-100 flex items-center gap-2">
            <Users className="w-5 h-5 text-indigo-500" />
            Anggota Workspace
          </h2>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-0.5">{allMembers.length} anggota terdaftar</p>
        </div>
        {canManageMembers && (
          <Button onClick={() => setShowInviteForm(!showInviteForm)} className="bg-indigo-600 hover:bg-indigo-700 gap-2 shadow-sm">
            <UserPlus className="w-4 h-4" />
            Undang Anggota
          </Button>
        )}
      </div>

      {/* Role Summary Pills */}
      <div className="flex flex-wrap gap-2">
        {['all', 'owner', 'admin', 'member', 'viewer'].map(role => {
          const count = role === 'all' ? allMembers.length : (roleCounts[role] || 0);
          if (role !== 'all' && count === 0) return null;
          const RoleIcon = role !== 'all' ? roleIcons[role] : Users;
          return (
            <button
              key={role}
              onClick={() => setFilterRole(role)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold border transition-all ${
                filterRole === role
                  ? 'bg-indigo-600 text-white border-indigo-600 shadow-sm'
                  : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-400 border-gray-200 dark:border-gray-600 hover:border-indigo-400'
              }`}
            >
              <RoleIcon className="w-3 h-3" />
              {role === 'all' ? 'Semua' : roleNames[role]}
              <span className={`rounded-full px-1.5 text-[10px] ${filterRole === role ? 'bg-white/20' : 'bg-gray-100 dark:bg-gray-700'}`}>{count}</span>
            </button>
          );
        })}
      </div>

      {/* Invite Form */}
      {showInviteForm && (
        <Card className="border-2 border-indigo-100 dark:border-indigo-900 shadow-sm">
          <CardHeader className="pb-3 bg-indigo-50 dark:bg-indigo-950/30 border-b border-indigo-100 dark:border-indigo-900">
            <CardTitle className="text-base flex items-center gap-2 text-indigo-900 dark:text-indigo-100">
              <UserPlus className="w-4 h-4" /> Undang Anggota Baru
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4 pt-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Email Pengguna</label>
                <div className="relative">
                  <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                  <Input
                    placeholder="email@contoh.com"
                    value={inviteEmail}
                    onChange={(e) => setInviteEmail(e.target.value)}
                    className="pl-9"
                    onKeyDown={(e) => e.key === 'Enter' && handleInviteMember()}
                  />
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Peran</label>
                <Select value={inviteRole} onValueChange={setInviteRole}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="viewer">
                      <div className="flex flex-col">
                        <span className="font-medium">≡ƒæü∩╕Å Peninjau</span>
                        <span className="text-xs text-gray-500">Hanya dapat melihat</span>
                      </div>
                    </SelectItem>
                    <SelectItem value="member">
                      <div className="flex flex-col">
                        <span className="font-medium">≡ƒæñ Anggota</span>
                        <span className="text-xs text-gray-500">Dapat membuat & mengedit tugas</span>
                      </div>
                    </SelectItem>
                    <SelectItem value="admin">
                      <div className="flex flex-col">
                        <span className="font-medium">≡ƒ¢í∩╕Å Admin</span>
                        <span className="text-xs text-gray-500">Akses penuh kecuali pengaturan</span>
                      </div>
                    </SelectItem>
                    {userRole === 'owner' && (
                      <SelectItem value="owner">
                        <div className="flex flex-col">
                          <span className="font-medium">≡ƒææ Pemilik</span>
                          <span className="text-xs text-gray-500">Akses penuh dan kontrol workspace</span>
                        </div>
                      </SelectItem>
                    )}
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div className="flex justify-end gap-2">
              <Button variant="outline" size="sm" onClick={() => { setShowInviteForm(false); setInviteEmail(''); }}>
                Batal
              </Button>
              <Button size="sm" onClick={handleInviteMember} disabled={isInviting} className="bg-indigo-600 hover:bg-indigo-700">
                {isInviting ? 'Mengundang...' : 'Kirim Undangan'}
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Search */}
      {allMembers.length > 5 && (
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <Input placeholder="Cari anggota..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="pl-9 h-9 text-sm" />
        </div>
      )}

      {/* Members Grid */}
      <div className="space-y-2">
        {filteredMembers.map((member) => {
          const RoleIcon = roleIcons[member.role] || User;
          const companyMember = companyMembers.find(cm => cm.user_email === member.user_id || cm.user_id === member.user_id);
          const displayName = companyMember?.user_name || member.user_id;
          const department = companyMember?.department;
          const position = companyMember?.position;
          const avatarColor = getAvatarColor(member.user_id || '');
          const joinedAt = member.joined_at && new Date(member.joined_at).getFullYear() > 1971
            ? format(new Date(member.joined_at), 'dd MMM yyyy', { locale: id })
            : companyMember?.joined_date
              ? format(new Date(companyMember.joined_date), 'dd MMM yyyy', { locale: id })
              : 'Tidak diketahui';

          return (
            <div
              key={member.id}
              className="flex items-center justify-between p-3.5 border border-gray-200 dark:border-gray-700 rounded-xl hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors group"
            >
              <div className="flex items-center gap-3 flex-1 min-w-0">
                <Avatar className="w-10 h-10 flex-shrink-0">
                  <AvatarFallback className={`${avatarColor} text-white font-bold text-sm`}>
                    {(displayName).charAt(0).toUpperCase()}
                  </AvatarFallback>
                </Avatar>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap">
                    <p className="font-semibold text-sm text-gray-900 dark:text-gray-100 truncate max-w-[160px]">
                      {displayName}
                    </p>
                    <Badge className={`${roleColors[member.role]} text-xs font-medium px-2 py-0`}>
                      <RoleIcon className="w-2.5 h-2.5 mr-1" />
                      {roleNames[member.role]}
                    </Badge>
                    {member.isOwner && (
                      <Badge className="bg-amber-50 text-amber-700 dark:bg-amber-950/40 dark:text-amber-300 border border-amber-200 dark:border-amber-700 text-xs">
                        ≡ƒææ Pemilik Workspace
                      </Badge>
                    )}
                  </div>
                  <div className="flex items-center gap-3 mt-0.5 flex-wrap">
                    <p className="text-xs text-gray-400 dark:text-gray-500 truncate max-w-[200px]">{member.user_id}</p>
                    {department && <Badge variant="outline" className="text-xs px-1.5 py-0">{department}</Badge>}
                    {position && <span className="text-xs text-gray-500 dark:text-gray-400">{position}</span>}
                  </div>
                  <p className="text-xs text-gray-400 dark:text-gray-600 mt-0.5">Bergabung {joinedAt}</p>
                </div>
              </div>

              {!member.isOwner && canManageMembers && (
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button variant="ghost" size="icon" className="h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity">
                      <MoreHorizontal className="w-4 h-4" />
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end" className="w-52">
                    {userRole === 'owner' && (
                      <>
                        <div className="px-2 py-1.5 text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase">Ubah Peran</div>
                        {['owner', 'admin', 'member', 'viewer'].filter(r => r !== member.role).map(role => {
                          const Icon = roleIcons[role];
                          return (
                            <DropdownMenuItem key={role} onClick={() => handleChangeRole(member.id, role)}>
                              <Icon className="w-4 h-4 mr-2" />
                              Jadikan {roleNames[role]}
                            </DropdownMenuItem>
                          );
                        })}
                        <DropdownMenuSeparator />
                      </>
                    )}
                    <DropdownMenuItem
                      onClick={() => handleRemoveMember(member.id, displayName)}
                      className="text-red-600 dark:text-red-400 focus:bg-red-50 dark:focus:bg-red-950/30"
                    >
                      <Trash2 className="w-4 h-4 mr-2" />
                      Hapus dari Workspace
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              )}
            </div>
          );
        })}

        {filteredMembers.length === 0 && (
          <div className="text-center py-10 text-gray-400 dark:text-gray-600">
            <Users className="w-10 h-10 mx-auto mb-2 opacity-40" />
            <p className="text-sm">Tidak ada anggota yang cocok</p>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Plus, FileText, Search, Pin, Clock, Tag } from 'lucide-react';
import { Note } from '@/entities/Note';
import { toast } from 'sonner';
import { motion } from 'framer-motion';
import { createPageUrl } from '@/utils';
import { format } from 'date-fns';
import { id } from 'date-fns/locale';

const NOTE_COLORS = [
  { bg: 'bg-blue-50 dark:bg-blue-950/30', border: 'border-blue-200 dark:border-blue-800', dot: 'bg-blue-400' },
  { bg: 'bg-green-50 dark:bg-green-950/30', border: 'border-green-200 dark:border-green-800', dot: 'bg-green-400' },
  { bg: 'bg-purple-50 dark:bg-purple-950/30', border: 'border-purple-200 dark:border-purple-800', dot: 'bg-purple-400' },
  { bg: 'bg-amber-50 dark:bg-amber-950/30', border: 'border-amber-200 dark:border-amber-800', dot: 'bg-amber-400' },
  { bg: 'bg-pink-50 dark:bg-pink-950/30', border: 'border-pink-200 dark:border-pink-800', dot: 'bg-pink-400' },
  { bg: 'bg-teal-50 dark:bg-teal-950/30', border: 'border-teal-200 dark:border-teal-800', dot: 'bg-teal-400' },
];

function getNoteColor(idx) {
  return NOTE_COLORS[idx % NOTE_COLORS.length];
}

function stripHtml(html = '') {
  return html.replace(/<[^>]*>/g, '').replace(/&nbsp;/g, ' ').trim();
}

export default function WorkspaceNotes({ notes, workspaceId, onUpdate, showCreateButton = true }) {
  const [isCreating, setIsCreating] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [viewMode, setViewMode] = useState('grid'); // grid | list

  const handleCreateNote = async () => {
    if (!workspaceId) { toast.error('Workspace ID tidak ditemukan'); return; }
    setIsCreating(true);
    try {
      const newNote = await Note.create({ title: 'Catatan Baru', content: '', workspace_id: workspaceId });
      toast.success('Catatan baru dibuat');
      window.dispatchEvent(new CustomEvent('noteCreated', { detail: { workspaceId, noteId: newNote.id } }));
      window.location.href = createPageUrl(`NoteEditor?id=${newNote.id}`);
      if (onUpdate) onUpdate();
    } catch (error) {
      toast.error('Gagal membuat catatan baru');
    } finally {
      setIsCreating(false);
    }
  };

  const handleNoteClick = (noteId) => {
    window.location.href = createPageUrl(`NoteEditor?id=${noteId}`);
  };

  const filteredNotes = (notes || []).filter(n =>
    n.title?.toLowerCase().includes(searchQuery.toLowerCase()) ||
    stripHtml(n.content).toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Separate pinned and regular notes
  const pinnedNotes = filteredNotes.filter(n => n.pinned);
  const regularNotes = filteredNotes.filter(n => !n.pinned);

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
        <div>
          <h2 className="text-xl font-bold text-gray-900 dark:text-gray-100 flex items-center gap-2">
            <FileText className="w-5 h-5 text-purple-500" />
            Catatan Workspace
          </h2>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-0.5">{(notes || []).length} catatan tersimpan</p>
        </div>
        <div className="flex items-center gap-2">
          {/* View toggle */}
          <div className="flex rounded-lg border border-gray-200 dark:border-gray-700 overflow-hidden">
            <button
              onClick={() => setViewMode('grid')}
              className={`px-2.5 py-1.5 text-xs font-medium transition-colors ${viewMode === 'grid' ? 'bg-blue-600 text-white' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800'}`}
            >
              Γûª Grid
            </button>
            <button
              onClick={() => setViewMode('list')}
              className={`px-2.5 py-1.5 text-xs font-medium border-l border-gray-200 dark:border-gray-700 transition-colors ${viewMode === 'list' ? 'bg-blue-600 text-white' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800'}`}
            >
              Γÿ░ List
            </button>
          </div>
          {showCreateButton && (
            <Button onClick={handleCreateNote} disabled={isCreating} size="sm" className="bg-purple-600 hover:bg-purple-700 gap-2 shadow-sm">
              <Plus className="w-4 h-4" />
              {isCreating ? 'Membuat...' : 'Tambah Catatan'}
            </Button>
          )}
        </div>
      </div>

      {/* Search */}
      {(notes || []).length > 3 && (
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <Input
            placeholder="Cari catatan..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-9 h-9 text-sm"
          />
        </div>
      )}

      {/* Notes Display */}
      {filteredNotes.length > 0 ? (
        <div className="space-y-4">
          {/* Pinned Notes */}
          {pinnedNotes.length > 0 && (
            <div>
              <p className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-2 flex items-center gap-1.5">
                <Pin className="w-3 h-3" /> Disematkan
              </p>
              <div className={viewMode === 'grid' ? 'grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3' : 'space-y-2'}>
                {pinnedNotes.map((note, idx) => (
                  <NoteCard key={note.id} note={note} idx={idx} onClick={() => handleNoteClick(note.id)} viewMode={viewMode} />
                ))}
              </div>
            </div>
          )}

          {/* Regular Notes */}
          {regularNotes.length > 0 && (
            <div>
              {pinnedNotes.length > 0 && (
                <p className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-2">Catatan Lainnya</p>
              )}
              <div className={viewMode === 'grid' ? 'grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3' : 'space-y-2'}>
                {regularNotes.map((note, idx) => (
                  <NoteCard key={note.id} note={note} idx={idx + pinnedNotes.length} onClick={() => handleNoteClick(note.id)} viewMode={viewMode} />
                ))}
              </div>
            </div>
          )}
        </div>
      ) : (
        <Card className="border-dashed border-2 dark:border-gray-700">
          <CardContent className="text-center py-14">
            <div className="w-16 h-16 bg-purple-50 dark:bg-purple-950/30 rounded-full flex items-center justify-center mx-auto mb-4">
              <FileText className="w-8 h-8 text-purple-400" />
            </div>
            <h3 className="text-base font-semibold text-gray-900 dark:text-gray-100 mb-1">
              {searchQuery ? 'Catatan tidak ditemukan' : 'Belum ada catatan'}
            </h3>
            <p className="text-sm text-gray-500 dark:text-gray-400 mb-5">
              {searchQuery ? 'Coba kata kunci pencarian yang berbeda' : 'Mulai buat catatan pertama di workspace ini'}
            </p>
            {showCreateButton && !searchQuery && (
              <Button onClick={handleCreateNote} disabled={isCreating} size="sm" className="bg-purple-600 hover:bg-purple-700">
                <Plus className="w-4 h-4 mr-2" /> Buat Catatan Pertama
              </Button>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

function NoteCard({ note, idx, onClick, viewMode }) {
  const colorStyle = getNoteColor(idx);
  const previewText = stripHtml(note.content || '');
  const wordCount = previewText.split(/\s+/).filter(Boolean).length;

  if (viewMode === 'list') {
    return (
      <motion.div
        initial={{ opacity: 0, x: -10 }}
        animate={{ opacity: 1, x: 0 }}
        className={`flex items-center gap-3 p-3 rounded-xl border cursor-pointer transition-all hover:shadow-sm ${colorStyle.bg} ${colorStyle.border}`}
        onClick={onClick}
      >
        <div className={`w-2.5 h-2.5 rounded-full flex-shrink-0 ${colorStyle.dot}`} />
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            {note.pinned && <Pin className="w-3 h-3 text-amber-500 flex-shrink-0" />}
            <p className="font-semibold text-sm text-gray-900 dark:text-gray-100 truncate">{note.title}</p>
          </div>
          {previewText && (
            <p className="text-xs text-gray-500 dark:text-gray-400 truncate mt-0.5">{previewText}</p>
          )}
        </div>
        <div className="flex items-center gap-2 flex-shrink-0 text-xs text-gray-400">
          {note.tags && note.tags.length > 0 && (
            <Badge variant="outline" className="text-xs">{note.tags[0]}</Badge>
          )}
          <span className="flex items-center gap-1">
            <Clock className="w-3 h-3" />
            {note.created_date ? format(new Date(note.created_date), 'dd MMM', { locale: id }) : ''}
          </span>
        </div>
      </motion.div>
    );
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      className={`p-4 rounded-xl border cursor-pointer transition-all hover:shadow-md hover:-translate-y-0.5 group ${colorStyle.bg} ${colorStyle.border}`}
      onClick={onClick}
    >
      <div className="flex items-start justify-between mb-2 gap-2">
        <div className="flex items-center gap-1.5 flex-1 min-w-0">
          {note.pinned && <Pin className="w-3 h-3 text-amber-500 flex-shrink-0" />}
          <h3 className="font-semibold text-sm text-gray-900 dark:text-gray-100 truncate">{note.title}</h3>
        </div>
        {note.archived && <Badge variant="secondary" className="text-xs flex-shrink-0">Arsip</Badge>}
      </div>

      {previewText && (
        <p className="text-xs text-gray-600 dark:text-gray-400 line-clamp-3 leading-relaxed mb-3">{previewText}</p>
      )}

      {/* Tags */}
      {note.tags && note.tags.length > 0 && (
        <div className="flex flex-wrap gap-1 mb-2">
          {note.tags.slice(0, 2).map(tag => (
            <span key={tag} className="flex items-center gap-0.5 text-[10px] bg-white/60 dark:bg-gray-800/60 px-1.5 py-0.5 rounded-full text-gray-600 dark:text-gray-400 border border-gray-200 dark:border-gray-700">
              <Tag className="w-2 h-2" />{tag}
            </span>
          ))}
          {note.tags.length > 2 && (
            <span className="text-[10px] text-gray-400">+{note.tags.length - 2}</span>
          )}
        </div>
      )}

      <div className="flex items-center justify-between text-[10px] text-gray-400 dark:text-gray-500 mt-auto pt-1 border-t border-gray-100 dark:border-gray-700/50">
        <span className="flex items-center gap-1">
          <Clock className="w-2.5 h-2.5" />
          {note.created_date ? format(new Date(note.created_date), 'dd MMM yyyy', { locale: id }) : ''}
        </span>
        {wordCount > 0 && <span>{wordCount} kata</span>}
      </div>
    </motion.div>
  );
}

import { useState } from 'react';
import { Workspace } from '@/entities/Workspace';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Trash2, Save, Settings, Globe, AlertTriangle, Palette, Lock } from 'lucide-react';
import { toast } from 'sonner';

const colors = [
  { hex: '#1f2937', name: 'Slate' },
  { hex: '#3b82f6', name: 'Biru' },
  { hex: '#8b5cf6', name: 'Ungu' },
  { hex: '#10b981', name: 'Hijau' },
  { hex: '#ef4444', name: 'Merah' },
  { hex: '#06b6d4', name: 'Cyan' },
  { hex: '#f97316', name: 'Orange' },
  { hex: '#ec4899', name: 'Pink' },
];

const icons = ['≡ƒÅá', '≡ƒÆ╝', '≡ƒÜÇ', '≡ƒôê', '≡ƒÄ»', '≡ƒÆí', '≡ƒöÑ', 'ΓÜí', '≡ƒîƒ', '≡ƒÅå', '≡ƒÄ¿', '≡ƒôè'];

export default function WorkspaceSettings({ workspace, userRole, onUpdate }) {
  const [formData, setFormData] = useState({
    name: workspace.name,
    description: workspace.description || '',
    icon: workspace.icon || '≡ƒÅá',
    color: workspace.color || '#3b82f6',
    settings: {
      allow_public_sharing: workspace.settings?.allow_public_sharing || false,
      default_task_priority: workspace.settings?.default_task_priority || 'medium'
    }
  });
  const [isSaving, setIsSaving] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteConfirmText, setDeleteConfirmText] = useState('');
  const [activeSection, setActiveSection] = useState('general');

  const canEdit = userRole === 'owner';

  const handleSave = async () => {
    if (!canEdit) { toast.error('Hanya pemilik yang dapat mengubah pengaturan workspace'); return; }
    if (!formData.name.trim()) { toast.error('Nama workspace tidak boleh kosong'); return; }

    setIsSaving(true);
    try {
      await Workspace.update(workspace.id, formData);
      toast.success('Pengaturan workspace berhasil disimpan!');
      onUpdate();
    } catch (error) {
      toast.error('Gagal menyimpan pengaturan workspace');
    }
    setIsSaving(false);
  };

  const handleDelete = async () => {
    if (!canEdit) { toast.error('Hanya pemilik yang dapat menghapus workspace'); return; }
    if (deleteConfirmText !== workspace.name) {
      toast.error(`Ketik nama workspace "${workspace.name}" dengan benar untuk konfirmasi`);
      return;
    }
    try {
      await Workspace.delete(workspace.id);
      toast.success('Workspace berhasil dihapus');
      window.location.href = '/workspaces';
    } catch (error) {
      toast.error('Gagal menghapus workspace');
    }
  };

  const sections = [
    { id: 'general', label: 'Umum', icon: Settings },
    { id: 'appearance', label: 'Tampilan', icon: Palette },
    { id: 'privacy', label: 'Privasi & Izin', icon: Lock },
    ...(canEdit ? [{ id: 'danger', label: 'Zona Bahaya', icon: AlertTriangle }] : []),
  ];

  return (
    <div className="space-y-5">
      {/* Header */}
      <div>
        <h2 className="text-xl font-bold text-gray-900 dark:text-gray-100 flex items-center gap-2">
          <Settings className="w-5 h-5 text-gray-500" />
          Pengaturan Workspace
        </h2>
        <p className="text-sm text-gray-500 dark:text-gray-400 mt-0.5">Kelola pengaturan dan preferensi workspace</p>
      </div>

      {!canEdit && (
        <div className="flex items-center gap-3 p-4 bg-amber-50 dark:bg-amber-950/30 rounded-xl border border-amber-200 dark:border-amber-800">
          <Lock className="w-5 h-5 text-amber-600 flex-shrink-0" />
          <p className="text-sm text-amber-800 dark:text-amber-300">
            Hanya pemilik workspace yang dapat mengubah pengaturan ini. Anda sedang melihat dalam mode read-only.
          </p>
        </div>
      )}

      {/* Section Navigation */}
      <div className="flex gap-1 bg-gray-100 dark:bg-gray-800 p-1 rounded-xl overflow-x-auto">
        {sections.map(({ id, label, icon: Icon }) => (
          <button
            key={id}
            onClick={() => setActiveSection(id)}
            className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
              activeSection === id
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 shadow-sm'
                : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
            } ${id === 'danger' ? 'text-red-600 dark:text-red-400' : ''}`}
          >
            <Icon className="w-4 h-4" />
            {label}
          </button>
        ))}
      </div>

      {/* General Section */}
      {activeSection === 'general' && (
        <Card className="border dark:border-gray-700">
          <CardHeader className="pb-3">
            <CardTitle className="text-base">Informasi Umum</CardTitle>
            <CardDescription>Nama dan deskripsi workspace Anda</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-1.5">
              <Label>Nama Workspace <span className="text-red-500">*</span></Label>
              <Input
                value={formData.name}
                onChange={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
                disabled={!canEdit}
                placeholder="Nama workspace..."
                className={!canEdit ? 'opacity-70 cursor-not-allowed' : ''}
              />
            </div>
            <div className="space-y-1.5">
              <Label>Deskripsi</Label>
              <Textarea
                value={formData.description}
                onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                placeholder="Deskripsi workspace (opsional)"
                disabled={!canEdit}
                className={`min-h-[80px] resize-none ${!canEdit ? 'opacity-70 cursor-not-allowed' : ''}`}
              />
              <p className="text-xs text-gray-400">{formData.description.length} karakter</p>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Appearance Section */}
      {activeSection === 'appearance' && (
        <Card className="border dark:border-gray-700">
          <CardHeader className="pb-3">
            <CardTitle className="text-base flex items-center gap-2"><Palette className="w-4 h-4" /> Tampilan</CardTitle>
            <CardDescription>Ikon dan warna tema workspace</CardDescription>
          </CardHeader>
          <CardContent className="space-y-5">
            {/* Icon picker */}
            <div className="space-y-2">
              <Label>Ikon Workspace</Label>
              <div className="flex flex-wrap gap-2">
                {icons.map(icon => (
                  <button
                    key={icon}
                    type="button"
                    disabled={!canEdit}
                    title={icon}
                    className={`w-10 h-10 text-xl rounded-xl border-2 transition-all hover:scale-110 ${
                      formData.icon === icon
                        ? 'border-blue-500 bg-blue-50 dark:bg-blue-950/40 shadow-md scale-110'
                        : 'border-gray-200 dark:border-gray-700 hover:border-gray-300 dark:hover:border-gray-600'
                    } ${!canEdit ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
                    onClick={() => canEdit && setFormData(prev => ({ ...prev, icon }))}
                  >
                    {icon}
                  </button>
                ))}
              </div>
            </div>

            {/* Color picker */}
            <div className="space-y-2">
              <Label>Warna Tema</Label>
              <div className="flex flex-wrap gap-3">
                {colors.map(({ hex, name }) => (
                  <button
                    key={hex}
                    type="button"
                    disabled={!canEdit}
                    title={name}
                    className={`relative w-9 h-9 rounded-xl border-3 transition-all hover:scale-110 ${
                      formData.color === hex
                        ? 'ring-2 ring-offset-2 ring-gray-600 dark:ring-gray-300 scale-110 shadow-lg'
                        : 'border-2 border-transparent hover:scale-105'
                    } ${!canEdit ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
                    style={{ backgroundColor: hex }}
                    onClick={() => canEdit && setFormData(prev => ({ ...prev, color: hex }))}
                  >
                    {formData.color === hex && (
                      <span className="absolute inset-0 flex items-center justify-center text-white text-xs font-bold">Γ£ô</span>
                    )}
                  </button>
                ))}
              </div>

              {/* Preview */}
              <div className="mt-3 p-3 rounded-xl flex items-center gap-3"
                style={{ backgroundColor: formData.color + '22', borderColor: formData.color + '44', border: '1px solid' }}>
                <div className="w-8 h-8 rounded-lg flex items-center justify-center text-lg font-bold text-white"
                  style={{ backgroundColor: formData.color }}>
                  {formData.icon}
                </div>
                <div>
                  <p className="font-semibold text-sm" style={{ color: formData.color }}>{formData.name || 'Nama Workspace'}</p>
                  <p className="text-xs text-gray-500">Preview tampilan workspace</p>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Privacy Section */}
      {activeSection === 'privacy' && (
        <Card className="border dark:border-gray-700">
          <CardHeader className="pb-3">
            <CardTitle className="text-base flex items-center gap-2"><Lock className="w-4 h-4" /> Privasi & Izin</CardTitle>
            <CardDescription>Kontrol akses dan visibilitas workspace</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex items-center justify-between p-3 rounded-xl border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50">
              <div className="flex items-start gap-3">
                <Globe className="w-5 h-5 text-blue-500 flex-shrink-0 mt-0.5" />
                <div>
                  <Label className="text-sm font-semibold">Berbagi Publik</Label>
                  <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
                    Izinkan anggota untuk membagikan konten workspace secara publik
                  </p>
                </div>
              </div>
              <Switch
                checked={formData.settings.allow_public_sharing}
                onCheckedChange={(checked) => setFormData(prev => ({
                  ...prev, settings: { ...prev.settings, allow_public_sharing: checked }
                }))}
                disabled={!canEdit}
              />
            </div>

            <div className="space-y-1.5">
              <Label>Prioritas Tugas Default</Label>
              <Select
                value={formData.settings.default_task_priority}
                onValueChange={(value) => setFormData(prev => ({
                  ...prev, settings: { ...prev.settings, default_task_priority: value }
                }))}
                disabled={!canEdit}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="low">≡ƒƒó Rendah</SelectItem>
                  <SelectItem value="medium">≡ƒƒí Sedang</SelectItem>
                  <SelectItem value="high">≡ƒƒá Tinggi</SelectItem>
                  <SelectItem value="urgent">≡ƒö┤ Mendesak</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Danger Zone */}
      {activeSection === 'danger' && canEdit && (
        <Card className="border-2 border-red-200 dark:border-red-900">
          <CardHeader className="pb-3 bg-red-50 dark:bg-red-950/30">
            <CardTitle className="text-base flex items-center gap-2 text-red-700 dark:text-red-300">
              <AlertTriangle className="w-4 h-4" /> Zona Bahaya
            </CardTitle>
            <CardDescription className="text-red-600/70 dark:text-red-400/70">
              Tindakan di bawah ini bersifat permanen dan tidak dapat dibatalkan
            </CardDescription>
          </CardHeader>
          <CardContent className="pt-4 space-y-4">
            <div className="p-4 rounded-xl border border-red-200 dark:border-red-900 bg-red-50/50 dark:bg-red-950/20 space-y-3">
              <div>
                <p className="text-sm font-semibold text-red-800 dark:text-red-300">Hapus Workspace</p>
                <p className="text-xs text-red-600/80 dark:text-red-400/80 mt-1">
                  Menghapus workspace akan menghapus semua tugas, catatan, dan data terkait secara permanen.
                </p>
              </div>
              {!showDeleteConfirm ? (
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setShowDeleteConfirm(true)}
                  className="border-red-300 text-red-700 hover:bg-red-50 dark:border-red-700 dark:text-red-400"
                >
                  <Trash2 className="w-4 h-4 mr-2" /> Hapus Workspace Ini
                </Button>
              ) : (
                <div className="space-y-2">
                  <p className="text-xs text-red-700 dark:text-red-300 font-medium">
                    Ketik <strong>"{workspace.name}"</strong> untuk konfirmasi:
                  </p>
                  <Input
                    placeholder={workspace.name}
                    value={deleteConfirmText}
                    onChange={(e) => setDeleteConfirmText(e.target.value)}
                    className="border-red-300 dark:border-red-700 text-sm"
                  />
                  <div className="flex gap-2">
                    <Button variant="outline" size="sm" onClick={() => { setShowDeleteConfirm(false); setDeleteConfirmText(''); }}>
                      Batal
                    </Button>
                    <Button
                      size="sm"
                      onClick={handleDelete}
                      disabled={deleteConfirmText !== workspace.name}
                      className="bg-red-600 hover:bg-red-700 text-white disabled:opacity-50"
                    >
                      <Trash2 className="w-4 h-4 mr-2" /> Hapus Sekarang
                    </Button>
                  </div>
                </div>
              )}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Save Button (not for danger zone) */}
      {canEdit && activeSection !== 'danger' && (
        <div className="flex justify-end pt-2">
          <Button onClick={handleSave} disabled={isSaving} className="bg-blue-600 hover:bg-blue-700 gap-2 shadow-sm">
            <Save className="w-4 h-4" />
            {isSaving ? 'Menyimpan...' : 'Simpan Perubahan'}
          </Button>
        </div>
      )}
    </div>
  );
}

import { useState, useMemo } from 'react';
import { Task } from '@/entities/Task';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Plus, Search, CheckSquare, ListFilter, SortAsc } from 'lucide-react';
import { Input } from '@/components/ui/input';
import TaskItem from '../tasks/TaskItem';
import TaskForm from '../tasks/TaskForm';
import TaskDetailModal from './TaskDetailModal';
import { AnimatePresence, motion } from 'framer-motion';
import { toast } from 'sonner';

const PRIORITY_ORDER = { urgent: 0, high: 1, medium: 2, low: 3 };

export default function WorkspaceTasks({ workspaceId, tasks, userRole, onUpdate, currentUser, companyMembers = [], filterByAssignee = false, showCreateButton = true }) {
  const [showForm, setShowForm] = useState(false);
  const [editingTask, setEditingTask] = useState(null);
  const [selectedTask, setSelectedTask] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');
  const [filterPriority, setFilterPriority] = useState('all');
  const [sortBy, setSortBy] = useState('created');

  const canEdit = userRole === 'owner' || userRole === 'admin' || userRole === 'member';
  const canAdminEdit = userRole === 'owner' || userRole === 'admin';

  const handleSubmit = async (taskData) => {
    try {
      const submitData = { ...taskData, workspace_id: workspaceId };
      if (editingTask) {
        await Task.update(editingTask.id, submitData);
        toast.success('Tugas berhasil diperbarui!');
        window.dispatchEvent(new CustomEvent('taskUpdated', { detail: { workspaceId, taskId: editingTask.id } }));
      } else {
        const newTask = await Task.create(submitData);
        toast.success('Tugas berhasil dibuat!');
        window.dispatchEvent(new CustomEvent('taskCreated', { detail: { workspaceId, taskId: newTask.id, assigneeId: submitData.assignee_id } }));
        if (submitData.assignee_id) {
          window.dispatchEvent(new CustomEvent('taskAssigned', { detail: { taskId: newTask.id, assigneeEmail: submitData.assignee_id, taskTitle: submitData.title, workspaceId } }));
        }
      }
      setShowForm(false);
      setEditingTask(null);
      onUpdate();
    } catch (error) {
      toast.error('Gagal menyimpan tugas');
    }
  };

  const handleStatusChange = async (task, newStatus) => {
    if (!canEdit) { toast.error('Anda tidak memiliki izin'); return; }
    try {
      await Task.update(task.id, { ...task, status: newStatus, completed_at: newStatus === 'done' ? new Date().toISOString() : null });
      toast.success('Status tugas berhasil diubah!');
      window.dispatchEvent(new CustomEvent('taskStatusChanged', { detail: { workspaceId, taskId: task.id, newStatus } }));
      onUpdate();
    } catch (error) { toast.error('Gagal mengubah status tugas'); }
  };

  const handleEdit = (task) => {
    if (!canEdit) { toast.error('Anda tidak memiliki izin'); return; }
    setEditingTask(task);
    setShowForm(true);
  };

  const handleDelete = async (taskId) => {
    if (!canEdit) { toast.error('Anda tidak memiliki izin'); return; }
    if (confirm('Apakah Anda yakin ingin menghapus tugas ini?')) {
      try {
        await Task.delete(taskId);
        toast.success('Tugas berhasil dihapus!');
        onUpdate();
      } catch (error) { toast.error('Gagal menghapus tugas'); }
    }
  };

  const visibleTasks = filterByAssignee && currentUser
    ? tasks.filter(t => t.assignee_id === currentUser.email || t.created_by === currentUser.email)
    : tasks;

  // Only show regular tasks (not log types)
  const regularTasks = visibleTasks.filter(t => !['briefing_log', 'penawaran_log', 'live_streaming_log', 'complain_log'].includes(t.task_type));

  const filteredTasks = useMemo(() => {
    let result = regularTasks.filter(task => {
      const matchesSearch = task.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        task.content?.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesStatus = filterStatus === 'all' || task.status === filterStatus;
      const matchesPriority = filterPriority === 'all' || task.priority === filterPriority;
      return matchesSearch && matchesStatus && matchesPriority;
    });

    if (sortBy === 'priority') result = [...result].sort((a, b) => (PRIORITY_ORDER[a.priority] ?? 2) - (PRIORITY_ORDER[b.priority] ?? 2));
    else if (sortBy === 'due_date') result = [...result].sort((a, b) => (a.due_date ? new Date(a.due_date) : Infinity) - (b.due_date ? new Date(b.due_date) : Infinity));
    else result = [...result].sort((a, b) => new Date(b.created_date || 0) - new Date(a.created_date || 0));

    return result;
  }, [regularTasks, searchQuery, filterStatus, filterPriority, sortBy]);

  // Counts for filter badges
  const counts = {
    todo: regularTasks.filter(t => t.status === 'todo').length,
    in_progress: regularTasks.filter(t => t.status === 'in_progress').length,
    done: regularTasks.filter(t => t.status === 'done' || t.status === 'completed').length,
  };

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-xl font-bold text-gray-900 dark:text-gray-100 flex items-center gap-2">
            <CheckSquare className="w-5 h-5 text-blue-500" />
            Tugas Workspace
          </h2>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-0.5">
            {regularTasks.length} total ┬╖ {counts.done} selesai ┬╖ {counts.in_progress} aktif
          </p>
        </div>
        {canEdit && showCreateButton !== false && (
          <Button onClick={() => setShowForm(true)} className="bg-blue-600 hover:bg-blue-700 shadow-sm gap-2">
            <Plus className="w-4 h-4" />
            Tugas Baru
          </Button>
        )}
      </div>

      {/* Status Quick Filter Pills */}
      <div className="flex flex-wrap gap-2">
        {[
          { val: 'all', label: 'Semua', count: regularTasks.length },
          { val: 'todo', label: 'Belum Mulai', count: counts.todo },
          { val: 'in_progress', label: 'Berlangsung', count: counts.in_progress },
          { val: 'done', label: 'Selesai', count: counts.done },
        ].map(f => (
          <button
            key={f.val}
            onClick={() => setFilterStatus(f.val)}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold border transition-all ${
              filterStatus === f.val
                ? 'bg-blue-600 text-white border-blue-600 shadow-sm'
                : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-400 border-gray-200 dark:border-gray-600 hover:border-blue-400'
            }`}
          >
            {f.label}
            <span className={`rounded-full px-1.5 py-0 text-[10px] ${filterStatus === f.val ? 'bg-white/20' : 'bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300'}`}>
              {f.count}
            </span>
          </button>
        ))}
      </div>

      {/* Search + Filters Row */}
      <div className="flex flex-col sm:flex-row gap-2">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
          <Input placeholder="Cari tugas..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="pl-9 h-9 text-sm" />
        </div>
        <Select value={filterPriority} onValueChange={setFilterPriority}>
          <SelectTrigger className="w-full sm:w-36 h-9 text-sm">
            <ListFilter className="w-3.5 h-3.5 mr-1.5 text-gray-400" />
            <SelectValue placeholder="Prioritas" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">Semua Prioritas</SelectItem>
            <SelectItem value="urgent">≡ƒö┤ Urgent</SelectItem>
            <SelectItem value="high">≡ƒƒá Tinggi</SelectItem>
            <SelectItem value="medium">≡ƒƒí Sedang</SelectItem>
            <SelectItem value="low">≡ƒƒó Rendah</SelectItem>
          </SelectContent>
        </Select>
        <Select value={sortBy} onValueChange={setSortBy}>
          <SelectTrigger className="w-full sm:w-36 h-9 text-sm">
            <SortAsc className="w-3.5 h-3.5 mr-1.5 text-gray-400" />
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="created">Terbaru</SelectItem>
            <SelectItem value="priority">Prioritas</SelectItem>
            <SelectItem value="due_date">Deadline</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Task Form */}
      <AnimatePresence>
        {showForm && (
          <TaskForm
            task={editingTask}
            workspaces={[{ id: workspaceId, name: 'Current Workspace' }]}
            onSubmit={handleSubmit}
            onCancel={() => { setShowForm(false); setEditingTask(null); }}
          />
        )}
      </AnimatePresence>

      {/* Task Detail Modal */}
      {selectedTask && (
        <TaskDetailModal
          task={selectedTask}
          onClose={() => setSelectedTask(null)}
          onUpdate={() => { setSelectedTask(null); onUpdate(); }}
          canAdminEdit={canAdminEdit}
          companyMembers={companyMembers}
          currentUser={currentUser}
        />
      )}

      {/* Tasks List */}
      <div className="space-y-3">
        {filteredTasks.length > 0 ? (
          filteredTasks.map(task => (
            <motion.div
              key={task.id}
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              className="cursor-pointer"
              onClick={() => setSelectedTask(task)}
            >
              <TaskItem
                task={task}
                workspaces={[]}
                onStatusChange={handleStatusChange}
                onEdit={handleEdit}
                onDelete={handleDelete}
              />
            </motion.div>
          ))
        ) : (
          <Card className="border-dashed border-2 dark:border-gray-700">
            <CardContent className="text-center py-14">
              <div className="w-16 h-16 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mx-auto mb-4">
                <CheckSquare className="w-8 h-8 text-gray-400" />
              </div>
              <h3 className="text-base font-semibold text-gray-900 dark:text-gray-100 mb-1">
                {searchQuery || filterStatus !== 'all' || filterPriority !== 'all' ? 'Tidak ada tugas yang cocok' : 'Belum ada tugas'}
              </h3>
              <p className="text-sm text-gray-500 dark:text-gray-400 mb-5">
                {searchQuery || filterStatus !== 'all' || filterPriority !== 'all'
                  ? 'Coba ubah filter atau kata kunci pencarian'
                  : 'Buat tugas pertama untuk workspace ini'}
              </p>
              {canEdit && !searchQuery && filterStatus === 'all' && filterPriority === 'all' && (
                <Button onClick={() => setShowForm(true)} size="sm" className="bg-blue-600 hover:bg-blue-700">
                  <Plus className="w-4 h-4 mr-2" /> Buat Tugas Baru
                </Button>
              )}
            </CardContent>
          </Card>
        )}
      </div>

      {/* Results summary */}
      {filteredTasks.length > 0 && (searchQuery || filterStatus !== 'all' || filterPriority !== 'all') && (
        <p className="text-xs text-center text-gray-400">
          Menampilkan {filteredTasks.length} dari {regularTasks.length} tugas
        </p>
      )}
    </div>
  );
}
